/**
 * Event Recorder - Captures all WebSocket broadcasts for simulation/debugging.
 *
 * Usage:
 *   import { eventRecorder } from './event-recorder';
 *
 *   // Start recording
 *   eventRecorder.start();
 *
 *   // ... events are automatically captured via broadcast wrapper ...
 *
 *   // Stop and get events
 *   const events = eventRecorder.stop();
 *
 *   // Export to scenario format
 *   const scenario = eventRecorder.exportScenario('my-scenario', 'Description');
 */

import type { WSMessageType } from './websocket.js';

export interface RecordedEvent {
  type: WSMessageType;
  payload: unknown;
  timestamp: number;
  /** Delay from previous event (calculated on export) */
  delay?: number;
}

export interface ExportedScenario {
  id: string;
  name: string;
  description: string;
  capturedAt: string;
  events: RecordedEvent[];
}

class EventRecorder {
  private events: RecordedEvent[] = [];
  private isRecording = false;
  private startTime = 0;

  /**
   * Start recording events.
   * Clears any previously recorded events.
   */
  start(): void {
    this.events = [];
    this.isRecording = true;
    this.startTime = Date.now();
    console.log('[EventRecorder] Recording started');
  }

  /**
   * Stop recording and return captured events.
   */
  stop(): RecordedEvent[] {
    this.isRecording = false;
    const duration = Date.now() - this.startTime;
    console.log(`[EventRecorder] Recording stopped. Captured ${this.events.length} events in ${duration}ms`);
    return this.events;
  }

  /**
   * Check if currently recording.
   */
  get recording(): boolean {
    return this.isRecording;
  }

  /**
   * Get event count.
   */
  get count(): number {
    return this.events.length;
  }

  /**
   * Record an event (called by broadcast wrapper).
   */
  record(type: WSMessageType, payload: unknown, timestamp: number): void {
    if (!this.isRecording) return;

    this.events.push({ type, payload, timestamp });
  }

  /**
   * Export recorded events as a scenario with delays calculated.
   */
  exportScenario(name: string, description: string): ExportedScenario {
    // Calculate delays between events
    const eventsWithDelays = this.events.map((event, index) => {
      const prevEvent = this.events[index - 1];
      const prevTimestamp = index > 0 && prevEvent ? prevEvent.timestamp : event.timestamp;
      const delay = event.timestamp - prevTimestamp;

      return {
        type: event.type,
        payload: event.payload,
        timestamp: event.timestamp,
        delay: Math.max(0, delay), // First event has delay 0
      };
    });

    return {
      id: name.toLowerCase().replace(/\s+/g, '-'),
      name,
      description,
      capturedAt: new Date().toISOString(),
      events: eventsWithDelays,
    };
  }

  /**
   * Export scenario as JSON string (for file saving).
   */
  exportScenarioJson(name: string, description: string): string {
    const scenario = this.exportScenario(name, description);
    return JSON.stringify(scenario, null, 2);
  }

  /**
   * Clear recorded events without stopping.
   */
  clear(): void {
    this.events = [];
    this.startTime = Date.now();
    console.log('[EventRecorder] Events cleared');
  }

  /**
   * Get current events (without stopping).
   */
  getEvents(): RecordedEvent[] {
    return [...this.events];
  }
}

// Singleton instance
export const eventRecorder = new EventRecorder();



/**
 * API module exports
 */

export * from './webhooks.js';
export * from './websocket.js';
export * from './static.js';



/**
 * API Types - Shared types for WebSocket and HTTP API communication.
 */

/**
 * WebSocket message types.
 */
export type WSMessageType =
  | 'state_change'
  | 'transcript'
  | 'audio_start'
  | 'audio_end'
  | 'error'
  | 'session_started'
  | 'session_ended'
  | 'tool_start'
  | 'tool_end'
  | 'item_pending'
  | 'item_completed'
  | 'cli_session_update'
  | 'cli_session_created'
  | 'cli_session_output'
  | 'subagent_activity'
  | 'welcome'
  | 'master_changed'
  | 'request_master';

/**
 * Payload for session handoff events.
 * Used when a voice session spawns a CLI session.
 */
export interface HandoffPayload {
  sessionId: string;
  parentId: string;
  threadId: string;
  mode: 'headless' | 'interactive';
  projectPath: string;
  goal: string;
}

/**
 * Payload for CLI session created events.
 */
export interface CliSessionCreatedPayload {
  id: string;
  goal: string;
  mode: 'headless' | 'interactive';
  projectPath: string;
  command: string;
  parentId?: string;
}

/**
 * Payload for CLI session update events.
 */
export interface CliSessionUpdatePayload {
  id: string;
  status: string;
  goal: string;
}

/**
 * Payload for CLI session output events.
 */
export interface CliSessionOutputPayload {
  sessionId: string;
  output: string;
}

/**
 * Payload for service state changed events.
 */
export interface ServiceStateChangedPayload {
  active: boolean;
  mode: 'web' | 'local';
}



/**
 * WebSocket Server - Real-time event broadcasting to web dashboard.
 *
 * Broadcasts:
 * - Agent state changes (idle, listening, thinking, speaking)
 * - Transcripts (user and assistant)
 * - Tool execution events
 * - Session lifecycle events
 * - Pending items (for delayed transcription handling)
 *
 * Master/Replica Pattern:
 * - Multiple clients can connect (no IP restriction)
 * - Only the "Master" client handles audio I/O (mic/speaker)
 * - All clients receive state and transcript updates
 * - Clients can request master control when agent is idle
 */

import { randomUUID } from 'crypto';
import { WebSocketServer, WebSocket } from 'ws';
import { CliSessionsRepository, SessionMessagesRepository } from '../db/index.js';
import { eventRecorder } from './event-recorder.js';
import { logStreamEvent } from '../logging/session-logger.js';

// Repository instance for persisting stream events
const messagesRepo = new SessionMessagesRepository();

const WS_PORT = parseInt(process.env.WS_PORT ?? '3001', 10);

// ═══════════════════════════════════════════════════════════════════════════
// Client State Management
// ═══════════════════════════════════════════════════════════════════════════

interface ClientState {
  id: string;
  isMaster: boolean;
  connectedAt: number;
  focusedSessionId: string | null;
}

// Track state per WebSocket client
const clientStates = new Map();

// Track current master client ID
let masterClientId: string | null = null;

// Track last agent state (to prevent master takeover during active turns)
let lastAgentState: string = 'idle';

// Track service state (for welcome message and soft power control)
let serviceActive: boolean = false;
let audioMode: 'web' | 'local' = 'web';

// Binary audio handler for WebSocketTransport
let binaryAudioHandler: ((data: Buffer, ws: WebSocket) => void) | null = null;

// Client command handler
let clientCommandHandler: ((command: ClientCommand, ws: WebSocket) => void) | null = null;

// Session input handler for direct text input to subagents
let sessionInputHandler: ((sessionId: string, text: string) => Promise) | null = null;

export interface ClientCommand {
  command: 'start_session' | 'stop_session' | 'start_service' | 'stop_service' | 'set_audio_mode';
  profile?: string;
  mode?: 'web' | 'local';
}

// ═══════════════════════════════════════════════════════════════════════════
// WebSocket Message Types (Phase 5: Simplified Protocol)
// ═══════════════════════════════════════════════════════════════════════════
//
// Core Types (7):
// - welcome            : Client identity + service state on connect
// - stream_chunk       : All agent message events (AI SDK format)
// - session_tree_update: Session hierarchy changes
// - state_change       : Voice UI state (listening/thinking/speaking)
// - master_changed     : Multi-client coordination
// - service_state_changed: Service active/dormant + audio mode
// - audio_control      : Audio playback control (start/stop/interrupt)
//
// Lifecycle Types (3):
// - session_started/ended: Voice session lifecycle
// - cli_session_deleted  : Terminal session cleanup
// - error                : Error messages
//
export type WSMessageType =
  // Core unified protocol
  | 'welcome'               // Client identity on connect
  | 'stream_chunk'          // All agent events (AI SDK format: text-delta, tool-call, etc.)
  | 'session_tree_update'   // Session hierarchy for ThreadRail
  | 'state_change'          // Voice UI state (listening/thinking/speaking/idle)
  | 'master_changed'        // Multi-client master coordination
  | 'service_state_changed' // Service active/dormant + audio mode
  | 'audio_control'         // Audio playback control (start/stop/interrupt)
  // Lifecycle events
  | 'session_started'       // Voice session activated
  | 'session_ended'         // Voice session deactivated
  | 'cli_session_deleted'   // Terminal session removed
  | 'error';                // Error messages

interface WSMessage {
  type: WSMessageType;
  payload: unknown;
  timestamp: number;
}

let wss: WebSocketServer | null = null;
const clients = new Set();

/**
 * Start the WebSocket server for real-time dashboard updates.
 */
export function startWebSocketServer(): Promise {
  return new Promise((resolve, reject) => {
    if (wss) {
      console.log('[WS] Server already running');
      resolve();
      return;
    }

    wss = new WebSocketServer({ port: WS_PORT, host: '0.0.0.0' });

    wss.on('listening', () => {
      console.log(`[WS] Server listening on port ${WS_PORT}`);
      resolve();
    });

    wss.on('error', (err) => {
      console.error('[WS] Server error:', err);
      wss = null;
      reject(err);
    });

    wss.on('connection', (ws, req) => {
      const clientAddr = req.socket.remoteAddress ?? 'unknown';
      const clientId = randomUUID();

      // First client becomes master
      const isMaster = masterClientId === null;
      if (isMaster) {
        masterClientId = clientId;
        console.log(`[WS] Client ${clientId.slice(0, 8)} assigned as Master (from ${clientAddr})`);
      } else {
        console.log(`[WS] Client ${clientId.slice(0, 8)} connected as Replica (from ${clientAddr})`);
      }

      // Store client state
      clientStates.set(ws, { id: clientId, isMaster, connectedAt: Date.now(), focusedSessionId: null });
      clients.add(ws);

      // Send welcome message with client identity and service state
      ws.send(JSON.stringify({
        type: 'welcome',
        payload: { clientId, isMaster, serviceActive, audioMode },
        timestamp: Date.now(),
      }));

      // Also send current agent state
      ws.send(JSON.stringify({
        type: 'state_change',
        payload: { state: lastAgentState, profile: null },
        timestamp: Date.now(),
      }));

      // Send recent session trees (for chat history persistence)
      // Includes both active and finished sessions from the last 24 hours
      const sessionsRepo = new CliSessionsRepository();
      const recentTrees = sessionsRepo.getRecentTrees(24, 50);
      if (recentTrees.length > 0) {
        ws.send(JSON.stringify({
          type: 'session_tree_update',
          payload: { trees: recentTrees },
          timestamp: Date.now(),
        }));
        console.log(`[WS] Sent ${recentTrees.length} recent session trees to ${clientId.slice(0, 8)}`);
      }

      // Handle disconnection
      ws.on('close', () => {
        const state = clientStates.get(ws);
        const shortId = state?.id.slice(0, 8) ?? 'unknown';
        console.log(`[WS] Client ${shortId} disconnected`);

        clients.delete(ws);
        clientStates.delete(ws);

        // If master disconnected, promote a new one
        if (state?.isMaster) {
          masterClientId = null;
          promoteNewMaster();
        }
      });

      ws.on('error', (err) => {
        const state = clientStates.get(ws);
        const shortId = state?.id.slice(0, 8) ?? 'unknown';
        console.error(`[WS] Client ${shortId} error: ${err.message}`);

        clients.delete(ws);
        clientStates.delete(ws);

        if (state?.isMaster) {
          masterClientId = null;
          promoteNewMaster();
        }
      });

      // Handle incoming messages from dashboard
      ws.on('message', (data, isBinary) => {
        const clientState = clientStates.get(ws);
        const shortId = clientState?.id.slice(0, 8) ?? 'unknown';

        // Handle binary audio data - only accept from Master
        // IMPORTANT: Only check isBinary flag, not Buffer.isBuffer(data)
        // because text messages in Node.js ws library also come as Buffers
        if (isBinary) {
          if (clientState?.isMaster && binaryAudioHandler) {
            binaryAudioHandler(data as Buffer, ws);
          } else if (!clientState?.isMaster) {
            // Log occasionally to help debug
            if (Math.random() < 0.01) {
              console.log(`[WS] Ignoring audio from non-master ${shortId}`);
            }
          }
          return;
        }

        // Handle JSON text messages
        try {
          const text = typeof data === 'string' ? data : data.toString();
          const msg = JSON.parse(text);
          console.log(`[WS] Message from ${shortId}:`, msg.type, msg.payload ? JSON.stringify(msg.payload).slice(0, 100) : '');
          handleClientMessage(ws, msg);
        } catch (err) {
          console.error('[WS] Invalid message:', err, 'data:', typeof data);
        }
      });
    });
  });
}

/**
 * Promote the oldest connected client to Master.
 */
function promoteNewMaster(): void {
  let newMasterWs: WebSocket | null = null;
  let oldestTime = Infinity;

  // Find the oldest remaining client
  for (const [candidateWs, candidateState] of clientStates.entries()) {
    if (candidateState.connectedAt < oldestTime && candidateWs.readyState === WebSocket.OPEN) {
      oldestTime = candidateState.connectedAt;
      newMasterWs = candidateWs;
    }
  }

  if (newMasterWs) {
    const newMasterState = clientStates.get(newMasterWs)!;
    newMasterState.isMaster = true;
    masterClientId = newMasterState.id;

    // Broadcast master change to all clients
    broadcast('master_changed', { masterId: newMasterState.id });
    console.log(`[WS] Promoted ${newMasterState.id.slice(0, 8)} to Master`);
  } else {
    console.log('[WS] No clients remaining to promote');
  }
}

/**
 * Stop the WebSocket server.
 */
export function stopWebSocketServer(): Promise {
  return new Promise((resolve) => {
    if (!wss) {
      resolve();
      return;
    }

    const wsServer = wss;
    wss = null;

    // Terminate client sockets immediately to avoid close-handshake stalls.
    for (const client of clients) {
      try {
        client.terminate();
      } catch {
        // Ignore close errors during shutdown.
      }
    }
    clients.clear();
    clientStates.clear();
    masterClientId = null;

    let settled = false;
    const finish = () => {
      if (settled) return;
      settled = true;
      console.log('[WS] Server stopped');
      resolve();
    };

    const timeout = setTimeout(() => {
      console.warn('[WS] Force shutdown after close timeout');
      finish();
    }, 2000);

    try {
      wsServer.close(() => {
        clearTimeout(timeout);
        finish();
      });
    } catch (error) {
      clearTimeout(timeout);
      console.warn('[WS] Error while closing server:', error);
      finish();
    }
  });
}

/**
 * Broadcast a message to all connected clients.
 * Also records the event if recording is active.
 */
export function broadcast(type: WSMessageType, payload: unknown): void {
  const timestamp = Date.now();

  // Record event if recording is active
  eventRecorder.record(type, payload, timestamp);

  if (clients.size === 0) return;

  const message: WSMessage = {
    type,
    payload,
    timestamp,
  };

  const data = JSON.stringify(message);

  for (const client of clients) {
    if (client.readyState === WebSocket.OPEN) {
      client.send(data);
    }
  }
}

/**
 * Broadcast binary data (audio) to Master client only.
 * Used by WebSocketTransport to send audio back to the browser handling I/O.
 */
export function broadcastBinary(data: Buffer | ArrayBuffer): void {
  if (clients.size === 0) return;

  const buffer = Buffer.isBuffer(data) ? data : Buffer.from(data);

  // Only send audio to Master client
  for (const [client, state] of clientStates.entries()) {
    if (state.isMaster && client.readyState === WebSocket.OPEN) {
      client.send(buffer);
      break; // Only one master
    }
  }
}

/**
 * Send a message to a specific client.
 */
export function sendTo(ws: WebSocket, type: WSMessageType, payload: unknown): void {
  if (ws.readyState !== WebSocket.OPEN) return;

  const message: WSMessage = {
    type,
    payload,
    timestamp: Date.now(),
  };

  ws.send(JSON.stringify(message));
}

/**
 * Handle messages from dashboard clients.
 */
function handleClientMessage(ws: WebSocket, msg: { type: string; payload?: unknown }): void {
  const clientState = clientStates.get(ws);
  const shortId = clientState?.id.slice(0, 8) ?? 'unknown';
  console.log(`[WS] Received from ${shortId}: ${msg.type}`);

  switch (msg.type) {
    case 'ping':
      sendTo(ws, 'state_change', { state: lastAgentState, profile: null });
      break;

    case 'client_command': {
      const command = msg.payload as ClientCommand;
      if (clientCommandHandler) {
        clientCommandHandler(command, ws);
      } else {
        console.warn('[WS] No command handler registered for client_command');
      }
      break;
    }

    case 'request_master': {
      if (!clientState) return;

      // Prevent takeover if agent is speaking/thinking to avoid audio glitches
      if (lastAgentState === 'thinking' || lastAgentState === 'speaking') {
        sendTo(ws, 'error', { message: 'Cannot take control while agent is active' });
        console.log(`[WS] ${shortId} request_master denied - agent is ${lastAgentState}`);
        return;
      }

      // Already master?
      if (clientState.isMaster) {
        console.log(`[WS] ${shortId} already master`);
        return;
      }

      // Demote current master
      for (const state of clientStates.values()) {
        state.isMaster = false;
      }

      // Promote requester
      clientState.isMaster = true;
      masterClientId = clientState.id;

      // Broadcast to all clients
      broadcast('master_changed', { masterId: clientState.id });
      console.log(`[WS] Control taken by ${shortId}`);
      break;
    }

    case 'focus_session': {
      // Track which session this client is focused on
      const { sessionId } = msg.payload as { sessionId: string | null };
      if (clientState) {
        clientState.focusedSessionId = sessionId;
        console.log(`[WS] ${shortId} focused on session: ${sessionId?.slice(0, 8) ?? 'none'}`);
      }
      break;
    }

    case 'session_input': {
      // Route text input to focused session
      const { text } = msg.payload as { text: string };
      const sessionId = clientState?.focusedSessionId;

      if (!sessionId) {
        sendTo(ws, 'error', { message: 'No session focused' });
        return;
      }

      if (!text?.trim()) {
        sendTo(ws, 'error', { message: 'Empty input' });
        return;
      }

      console.log(`[WS] ${shortId} input to session ${sessionId.slice(0, 8)}: "${text.slice(0, 50)}..."`);

      // Call the session input handler (async, don't await)
      if (sessionInputHandler) {
        sessionInputHandler(sessionId, text).catch((err) => {
          console.error(`[WS] Session input error:`, err);
          sendTo(ws, 'error', { message: `Input error: ${err.message}` });
        });
      } else {
        sendTo(ws, 'error', { message: 'Session input handler not registered' });
      }
      break;
    }

    default:
      console.log(`[WS] Unknown message type: ${msg.type}`);
  }
}

/**
 * Get number of connected clients.
 */
export function getClientCount(): number {
  return clients.size;
}

/**
 * Register a handler for incoming binary (audio) messages.
 * Used by WebSocketTransport to receive audio from browser clients.
 */
export function onBinaryMessage(handler: (data: Buffer, ws: WebSocket) => void): void {
  binaryAudioHandler = handler;
}

/**
 * Get reference to connected clients set.
 * Used by WebSocketTransport to send audio to browser clients.
 */
export function getClients(): Set {
  return clients;
}

/**
 * Register a handler for client commands (start_session, stop_session).
 * Used by index.ts to wire up agent activation in web mode.
 */
export function onClientCommand(handler: (command: ClientCommand, ws: WebSocket) => void): void {
  clientCommandHandler = handler;
}

/**
 * Register a handler for session input messages.
 * Called when a client sends text input to their focused session.
 */
export function onSessionInput(handler: (sessionId: string, text: string) => Promise): void {
  sessionInputHandler = handler;
}

// ═══════════════════════════════════════════════════════════════════════════
// Stream Chunk Types - AI SDK format events for all agents
// ═══════════════════════════════════════════════════════════════════════════

// Re-export types from stream-types.ts for convenience
export type { AISDKStreamEvent, StreamChunkMessage } from './stream-types.js';
import type { AISDKStreamEvent } from './stream-types.js';

// ═══════════════════════════════════════════════════════════════════════════
// Broadcast Helpers (Phase 5: Simplified)
// ═══════════════════════════════════════════════════════════════════════════
//
// Core broadcasts:
// - streamChunk        : All agent message content (voice + CLI + web-search)
// - sessionTreeUpdate  : Session hierarchy changes
// - stateChange        : Voice UI state
//
// Lifecycle broadcasts:
// - sessionStarted/Ended: Voice session lifecycle
// - cliSessionDeleted   : Terminal cleanup
// - error               : Error messages
//
export const wsBroadcast = {
  // Voice UI state (listening/thinking/speaking/idle)
  stateChange: (state: string, profile: string | null) => {
    lastAgentState = state; // Track state for master takeover logic
    broadcast('state_change', { state, profile });
  },

  // Service state (active/dormant + audio mode)
  serviceState: (active: boolean, mode: 'web' | 'local') =>
    broadcast('service_state_changed', { active, mode }),

  // Voice session lifecycle
  sessionStarted: (profile: string) =>
    broadcast('session_started', { profile }),

  sessionEnded: (profile: string | null) =>
    broadcast('session_ended', { profile }),

  // Error messages
  error: (message: string) =>
    broadcast('error', { message }),

  // Terminal session cleanup
  cliSessionDeleted: (sessionId: string) =>
    broadcast('cli_session_deleted', { sessionId }),

  cliAllSessionsDeleted: () =>
    broadcast('cli_session_deleted', { all: true }),

  // Unified stream chunk events (AI SDK format for all agents)
  // Also persists content-bearing events to database for history reconstruction
  streamChunk: (sessionId: string, event: AISDKStreamEvent) => {
    // Persist event (repository filters to content-bearing types only)
    const result = messagesRepo.create(sessionId, event);
    if (result) {
      console.log(`[WS] Persisted ${event.type} for session ${sessionId.slice(0, 8)}`);
    }

    // Log to JSONL file
    logStreamEvent(sessionId, event as { type: string; [key: string]: unknown });

    // Broadcast to all connected clients
    broadcast('stream_chunk', { sessionId, event });
  },

  // Session hierarchy tree update (for ThreadRail)
  sessionTreeUpdate: (rootId: string) => {
    const sessionsRepo = new CliSessionsRepository();
    const tree = sessionsRepo.getTree(rootId);
    if (tree) {
      broadcast('session_tree_update', { rootId, tree });
    }
  },

  // Broadcast all active trees (for initial load)
  allActiveTreesUpdate: () => {
    const sessionsRepo = new CliSessionsRepository();
    const trees = sessionsRepo.getActiveTrees();
    broadcast('session_tree_update', { trees });
  },
};

/**
 * Update the tracked service state and broadcast to all clients.
 * Called by index.ts when service state changes.
 */
export function setServiceState(active: boolean, mode: 'web' | 'local'): void {
  serviceActive = active;
  audioMode = mode;
  wsBroadcast.serviceState(active, mode);
}

/**
 * Get current service state.
 */
export function getServiceState(): { active: boolean; mode: 'web' | 'local' } {
  return { active: serviceActive, mode: audioMode };
}



/**
 * Audio Capture - Captures microphone input via PipeWire
 *
 * Uses pw-cat to capture audio at 24kHz (Realtime API format).
 * PipeWire handles the resampling from device's native rate.
 */

import { spawn, ChildProcess } from 'child_process';
import { EventEmitter } from 'events';

const API_SAMPLE_RATE = 24000;

export class AudioCapture extends EventEmitter {
  private recorder: ChildProcess | null = null;
  private isRunning = false;

  start(): void {
    if (this.isRunning) {
      return;
    }

    // Use pw-cat to capture audio at 24kHz - PipeWire handles resampling
    this.recorder = spawn('pw-cat', [
      '--record',
      '--raw',
      '--channels', '1',
      '--rate', String(API_SAMPLE_RATE),
      '--format', 's16',
      '-',
    ], {
      stdio: ['ignore', 'pipe', 'pipe'],
    });

    this.recorder.stderr?.on('data', (data: Buffer) => {
      const msg = data.toString().trim();
      if (msg && !msg.includes('opened')) {
        console.error('[AudioCapture] pw-cat:', msg);
      }
    });

    this.recorder.on('error', (err) => {
      console.error('[AudioCapture] Error:', err.message);
      this.emit('error', err);
    });

    this.recorder.on('exit', (code) => {
      if (this.isRunning && code !== 0) {
        console.error(`[AudioCapture] pw-cat exited with code ${code}`);
      }
      this.isRunning = false;
    });

    this.recorder.stdout?.on('data', (data: Buffer) => {
      // Convert Buffer to ArrayBuffer and emit
      const arrayBuffer = data.buffer.slice(
        data.byteOffset,
        data.byteOffset + data.byteLength
      );
      this.emit('audio', arrayBuffer);
    });

    this.isRunning = true;
    console.log(`[AudioCapture] Started (${API_SAMPLE_RATE}Hz pcm16)`);
  }

  stop(): void {
    if (!this.isRunning) {
      return;
    }

    this.isRunning = false;

    if (this.recorder) {
      this.recorder.kill('SIGTERM');
      this.recorder = null;
    }

    console.log('[AudioCapture] Stopped');
  }

  isCapturing(): boolean {
    return this.isRunning;
  }
}



export { AudioCapture } from './capture.js';
export { AudioPlayback } from './playback.js';
export { speak } from './tts.js';



/**
 * Audio Playback - Plays audio via PipeWire
 *
 * Uses pw-cat to play audio at 24kHz (Realtime API format).
 * PipeWire handles the resampling to device's native rate.
 */

import { spawn, ChildProcess } from 'child_process';
import { EventEmitter } from 'events';

const API_SAMPLE_RATE = 24000;

export class AudioPlayback extends EventEmitter {
  private player: ChildProcess | null = null;
  private isPlaying = false;

  start(): void {
    if (this.player) {
      return;
    }

    // Use pw-cat at 24kHz - PipeWire handles resampling to device
    this.player = spawn('pw-cat', [
      '--playback',
      '--raw',
      '--channels', '1',
      '--rate', String(API_SAMPLE_RATE),
      '--format', 's16',
      '-',
    ], {
      stdio: ['pipe', 'pipe', 'pipe'],
    });

    this.player.stderr?.on('data', (data: Buffer) => {
      const msg = data.toString().trim();
      if (msg) {
        console.error('[AudioPlayback] pw-cat:', msg);
      }
    });

    this.player.on('error', (err) => {
      console.error('[AudioPlayback] Error:', err.message);
      this.player = null;
      this.isPlaying = false;
    });

    this.player.on('exit', (code) => {
      if (this.isPlaying && code !== 0 && code !== null) {
        console.error(`[AudioPlayback] pw-cat exited with code ${code}`);
      }
      this.player = null;
      this.isPlaying = false;
    });

    this.player.stdin?.on('error', () => {
      // Ignore EPIPE errors
    });

    this.isPlaying = true;
    console.log(`[AudioPlayback] Started (${API_SAMPLE_RATE}Hz pcm16)`);
  }

  play(data: ArrayBuffer | Buffer): void {
    const buffer = Buffer.isBuffer(data) ? data : Buffer.from(data);

    if (!this.player) {
      this.start();
    }

    if (this.player?.stdin?.writable) {
      this.player.stdin.write(buffer);
    }
  }

  stop(): void {
    this.isPlaying = false;

    if (this.player) {
      try {
        this.player.stdin?.end();
      } catch {
        // Ignore
      }
      try {
        this.player.kill('SIGTERM');
      } catch {
        // Ignore
      }
      this.player = null;
    }
    console.log('[AudioPlayback] Stopped');
  }

  interrupt(): void {
    this.stop();
    this.emit('interrupted');
  }

  isActive(): boolean {
    return this.isPlaying;
  }
}



/**
 * Audio Resampling - Convert between sample rates
 *
 * Uses linear interpolation for simple resampling.
 * Converts 16kHz (Jabra device) ↔ 24kHz (Realtime API)
 */

/**
 * Resample PCM16 audio data from one sample rate to another.
 * @param audioData PCM16 audio as Buffer
 * @param fromRate Source sample rate
 * @param toRate Target sample rate
 * @returns Resampled PCM16 audio as Buffer
 */
export function resampleAudio(audioData: Buffer, fromRate: number, toRate: number): Buffer {
  if (fromRate === toRate) {
    return audioData;
  }

  // Convert Buffer to Int16Array
  const numSamples = audioData.length / 2;
  const samples = new Float32Array(numSamples);
  for (let i = 0; i < numSamples; i++) {
    samples[i] = audioData.readInt16LE(i * 2);
  }

  // Calculate new length
  const newLength = Math.floor(numSamples * toRate / fromRate);

  // Linear interpolation resampling
  const resampled = new Float32Array(newLength);
  for (let i = 0; i < newLength; i++) {
    const srcIndex = i * fromRate / toRate;
    const srcIndexFloor = Math.floor(srcIndex);
    const srcIndexCeil = Math.min(srcIndexFloor + 1, numSamples - 1);
    const fraction = srcIndex - srcIndexFloor;

    // Linear interpolation
    resampled[i] = samples[srcIndexFloor]! * (1 - fraction) + samples[srcIndexCeil]! * fraction;
  }

  // Convert back to Buffer with Int16
  const result = Buffer.alloc(newLength * 2);
  for (let i = 0; i < newLength; i++) {
    // Clamp to Int16 range
    const value = Math.max(-32768, Math.min(32767, Math.round(resampled[i]!)));
    result.writeInt16LE(value, i * 2);
  }

  return result;
}

// Common sample rates
export const DEVICE_SAMPLE_RATE = 16000;  // Jabra Speak2 55 MS
export const API_SAMPLE_RATE = 24000;      // OpenAI Realtime API

/**
 * Resample from device rate (16kHz) to API rate (24kHz)
 */
export function resampleForApi(audioData: Buffer): Buffer {
  return resampleAudio(audioData, DEVICE_SAMPLE_RATE, API_SAMPLE_RATE);
}

/**
 * Resample from API rate (24kHz) to device rate (16kHz)
 */
export function resampleForDevice(audioData: Buffer): Buffer {
  return resampleAudio(audioData, API_SAMPLE_RATE, DEVICE_SAMPLE_RATE);
}



/**
 * Text-to-Speech - Generate speech using OpenAI TTS API
 *
 * Streams PCM audio directly to PipeWire for playback.
 */

import OpenAI from 'openai';
import { spawn } from 'child_process';
import { config } from '../config.js';

const openai = new OpenAI({
  apiKey: config.openai.apiKey,
});

const TTS_SAMPLE_RATE = 24000; // OpenAI TTS outputs 24kHz

export interface TTSOptions {
  voice?: 'alloy' | 'ash' | 'coral' | 'echo' | 'fable' | 'onyx' | 'nova' | 'shimmer';
  speed?: number;
}

/**
 * Speak text using OpenAI TTS API, streaming PCM directly to PipeWire.
 */
export async function speak(text: string, options: TTSOptions = {}): Promise {
  const voice = options.voice ?? 'echo';
  const speed = options.speed ?? 1.0;

  console.log(`[TTS] Speaking: "${text.substring(0, 50)}${text.length > 50 ? '...' : ''}"`);

  // Start pw-cat for PCM playback
  const player = spawn('pw-cat', [
    '--playback',
    '--raw',
    '--channels', '1',
    '--rate', String(TTS_SAMPLE_RATE),
    '--format', 's16',
    '-',
  ], {
    stdio: ['pipe', 'pipe', 'pipe'],
  });

  let playerError: Error | null = null;

  player.stderr?.on('data', (data: Buffer) => {
    const msg = data.toString().trim();
    if (msg && !msg.includes('opening stream')) {
      console.error('[TTS] pw-cat:', msg);
    }
  });

  player.on('error', (err) => {
    playerError = err;
  });

  const playerDone = new Promise((resolve, reject) => {
    player.on('exit', (code) => {
      if (code === 0 || code === null) {
        resolve();
      } else if (playerError) {
        reject(playerError);
      } else {
        reject(new Error(`pw-cat exited with code ${code}`));
      }
    });
  });

  try {
    // Request PCM audio from OpenAI
    const response = await openai.audio.speech.create({
      model: 'gpt-4o-mini-tts',
      voice,
      input: text,
      speed,
      response_format: 'pcm', // 24kHz 16-bit mono PCM
    });

    // Stream the audio data to pw-cat
    const arrayBuffer = await response.arrayBuffer();
    const buffer = Buffer.from(arrayBuffer);

    player.stdin?.write(buffer);
    player.stdin?.end();

    // Wait for playback to complete
    await playerDone;
    console.log('[TTS] Done');
  } catch (error) {
    // Kill the player on error
    player.kill();
    console.error('[TTS] Error:', error);
    throw error;
  }
}



/**
 * HandoffPacket - Structured context transfer from voice to subagents.
 *
 * Solves the "telephone effect" where context is lost at each handoff boundary:
 *   Voice (10 turns about Kireon auth bug)
 *     → developer_session("fix the auth endpoint bug")  ← only last turn
 *       → CLI Agent gets: tool args + poorly formatted history
 *
 * With HandoffPacket:
 *   Voice (10 turns about Kireon auth bug)
 *     → developer_session builds HandoffPacket with full context
 *       → CLI Agent gets: request + 20 recent voice entries + active processes
 */

import { generateId } from '../db/index.js';
import type { ManagedProcess } from '../processes/manager.js';

export interface HandoffPacket {
  /** Unique ID for this handoff */
  id: string;

  /** When the handoff was created */
  timestamp: number;

  /** The user's explicit request (from tool args) */
  request: string;

  /** Recent voice conversation (last N turns, properly formatted) */
  voiceContext: VoiceContextEntry[];

  /** Active/recent background tasks and their status */
  activeProcesses: ProcessSummary[];

  /** Metadata about the source */
  source: {
    sessionId: string;
    profile: string; // 'jarvis' | 'marvin'
  };
}

export interface VoiceContextEntry {
  role: 'user' | 'assistant' | 'system';
  content: string;
  timestamp: number;
  /** Whether this was a tool call/result (provides extra context) */
  toolInfo?: { name: string; args?: unknown; result?: string };
}

export interface ProcessSummary {
  name: string;
  status: 'running' | 'finished' | 'error';
  goal: string;
  startedAt: number;
  result?: string;
}

/**
 * Build a HandoffPacket from voice agent state.
 */
export function buildHandoffPacket(params: {
  request: string;
  voiceContext: VoiceContextEntry[];
  activeProcesses: ManagedProcess[];
  sessionId: string;
  profile: string;
}): HandoffPacket {
  return {
    id: generateId(),
    timestamp: Date.now(),
    request: params.request,
    voiceContext: params.voiceContext.slice(-20), // last 20 entries
    activeProcesses: params.activeProcesses.map(p => ({
      name: p.name,
      status: p.status === 'finished' ? 'finished' : p.status === 'error' ? 'error' : 'running',
      goal: p.name, // process name serves as goal
      startedAt: p.startedAt,
      result: p.result,
    })),
    source: {
      sessionId: params.sessionId,
      profile: params.profile,
    },
  };
}

/**
 * Format a HandoffPacket's voice context into a readable text block.
 * Used by subagents to include in their system prompt.
 */
export function formatVoiceContext(packet: HandoffPacket): string {
  if (packet.voiceContext.length === 0) {
    return '(direct request, no voice context)';
  }

  return packet.voiceContext
    .map(entry => {
      if (entry.toolInfo) {
        return `[tool:${entry.toolInfo.name}] ${entry.toolInfo.result || entry.content}`;
      }
      return `[${entry.role}] ${entry.content}`;
    })
    .join('\n');
}

/**
 * Format active processes into a readable text block.
 */
export function formatActiveProcesses(packet: HandoffPacket): string {
  if (packet.activeProcesses.length === 0) {
    return 'None';
  }

  return packet.activeProcesses
    .map(p => `- ${p.name} (${p.status}): ${p.goal}${p.result ? ` → ${p.result.substring(0, 100)}` : ''}`)
    .join('\n');
}



/**
 * Agent Runs Repository
 *
 * Optional history of agent interactions for debugging and analytics.
 */

import type { Database } from 'bun:sqlite';
import { getDatabase } from '../database.js';

export interface AgentRun {
  id: number;
  profile: string | null;
  transcript: string | null;
  tool_calls: string | null;
  created_at: string;
}

export interface CreateAgentRunInput {
  profile?: string;
  transcript?: string;
  tool_calls?: string | object[];
}

export class AgentRunsRepository {
  private db: Database;

  constructor(db?: Database) {
    this.db = db ?? getDatabase();
  }

  /**
   * Log a new agent run.
   */
  create(input: CreateAgentRunInput): AgentRun {
    const toolCalls =
      input.tool_calls === undefined
        ? null
        : typeof input.tool_calls === 'string'
          ? input.tool_calls
          : JSON.stringify(input.tool_calls);

    const result = this.db
      .query(
        `INSERT INTO agent_runs (profile, transcript, tool_calls)
         VALUES (?, ?, ?)`
      )
      .run(input.profile ?? null, input.transcript ?? null, toolCalls);

    return this.findById(result.lastInsertRowid as number)!;
  }

  /**
   * Find a run by ID.
   */
  findById(id: number): AgentRun | null {
    return (this.db.query('SELECT * FROM agent_runs WHERE id = ?').get(id) as AgentRun) ?? null;
  }

  /**
   * Get recent runs.
   */
  getRecent(limit: number = 50): AgentRun[] {
    return this.db
      .query(
        `SELECT * FROM agent_runs
         ORDER BY created_at DESC
         LIMIT ?`
      )
      .all(limit) as AgentRun[];
  }

  /**
   * Get runs by profile.
   */
  getByProfile(profile: string, limit?: number): AgentRun[] {
    if (limit) {
      return this.db
        .query(
          `SELECT * FROM agent_runs
           WHERE profile = ?
           ORDER BY created_at DESC
           LIMIT ?`
        )
        .all(profile, limit) as AgentRun[];
    }
    return this.db
      .query(
        `SELECT * FROM agent_runs
         WHERE profile = ?
         ORDER BY created_at DESC`
      )
      .all(profile) as AgentRun[];
  }

  /**
   * Delete old runs (older than days).
   */
  cleanup(days: number = 30): number {
    const result = this.db
      .query(
        `DELETE FROM agent_runs
         WHERE created_at < datetime('now', '-' || ? || ' days')`
      )
      .run(days);
    return result.changes;
  }

  /**
   * Get run count statistics.
   */
  getStats(): { total: number; by_profile: Record } {
    const total = (
      this.db.query('SELECT COUNT(*) as count FROM agent_runs').get() as { count: number }
    ).count;

    const byProfile = this.db
      .query(
        `SELECT profile, COUNT(*) as count FROM agent_runs
         WHERE profile IS NOT NULL
         GROUP BY profile`
      )
      .all() as { profile: string; count: number }[];

    const profileMap: Record = {};
    for (const row of byProfile) {
      profileMap[row.profile] = row.count;
    }

    return { total, by_profile: profileMap };
  }
}



/**
 * CLI Events Repository
 *
 * Event log for CLI session activities.
 */

import type { Database } from 'bun:sqlite';
import { getDatabase } from '../database.js';
import { logCliEvent } from '../../logging/session-logger.js';

export type EventType =
  | 'created'
  | 'started'
  | 'input'
  | 'output'
  | 'status_change'
  | 'error'
  | 'finished';

export interface CliEvent {
  id: number;
  session_id: string;
  event_type: EventType;
  payload: string | null;
  created_at: string;
}

export interface CreateEventInput {
  session_id: string;
  event_type: EventType;
  payload?: string | object;
}

export class CliEventsRepository {
  private db: Database;

  constructor(db?: Database) {
    this.db = db ?? getDatabase();
  }

  /**
   * Log a new event for a session.
   */
  create(input: CreateEventInput): CliEvent {
    const payload =
      input.payload === undefined
        ? null
        : typeof input.payload === 'string'
          ? input.payload
          : JSON.stringify(input.payload);

    const result = this.db
      .query(
        `INSERT INTO cli_events (session_id, event_type, payload)
         VALUES (?, ?, ?)`
      )
      .run(input.session_id, input.event_type, payload);

    // Mirror DB event into per-session JSONL debug log.
    let parsedPayload: unknown = null;
    if (payload !== null) {
      try {
        parsedPayload = JSON.parse(payload);
      } catch {
        parsedPayload = payload;
      }
    }
    logCliEvent(input.session_id, input.event_type, parsedPayload);

    return this.findById(result.lastInsertRowid as number)!;
  }

  /**
   * Find an event by ID.
   */
  findById(id: number): CliEvent | null {
    return (this.db.query('SELECT * FROM cli_events WHERE id = ?').get(id) as CliEvent) ?? null;
  }

  /**
   * Get all events for a session.
   */
  getBySession(sessionId: string, limit?: number): CliEvent[] {
    if (limit) {
      return this.db
        .query(
          `SELECT * FROM cli_events
           WHERE session_id = ?
           ORDER BY created_at DESC
           LIMIT ?`
        )
        .all(sessionId, limit) as CliEvent[];
    }
    return this.db
      .query(
        `SELECT * FROM cli_events
         WHERE session_id = ?
         ORDER BY created_at ASC`
      )
      .all(sessionId) as CliEvent[];
  }

  /**
   * Get recent events across all sessions.
   */
  getRecent(limit: number = 100): CliEvent[] {
    return this.db
      .query(
        `SELECT * FROM cli_events
         ORDER BY created_at DESC
         LIMIT ?`
      )
      .all(limit) as CliEvent[];
  }

  /**
   * Get events by type for a session.
   */
  getByType(sessionId: string, eventType: EventType): CliEvent[] {
    return this.db
      .query(
        `SELECT * FROM cli_events
         WHERE session_id = ? AND event_type = ?
         ORDER BY created_at ASC`
      )
      .all(sessionId, eventType) as CliEvent[];
  }

  /**
   * Delete all events for a session.
   */
  deleteBySession(sessionId: string): number {
    const result = this.db
      .query('DELETE FROM cli_events WHERE session_id = ?')
      .run(sessionId);
    return result.changes;
  }
}



/**
 * Handoffs Repository
 *
 * Persists HandoffPackets for debugging and replay.
 * Each packet captures the full context transferred from voice to a subagent.
 */

import type { Database } from 'bun:sqlite';
import { getDatabase } from '../database.js';
import type { HandoffPacket } from '../../context/handoff.js';

export interface HandoffRow {
  id: string;
  source_session_id: string;
  target_session_id: string | null;
  request: string;
  voice_context: string;
  active_processes: string | null;
  created_at: string;
}

export class HandoffsRepository {
  private db: Database;

  constructor(db?: Database) {
    this.db = db ?? getDatabase();
  }

  /**
   * Save a handoff packet to the database.
   */
  save(packet: HandoffPacket, targetSessionId?: string): void {
    this.db.query(
      `INSERT INTO handoff_packets (id, source_session_id, target_session_id, request, voice_context, active_processes)
       VALUES (?, ?, ?, ?, ?, ?)`
    ).run(
      packet.id,
      packet.source.sessionId,
      targetSessionId ?? null,
      packet.request,
      JSON.stringify(packet.voiceContext),
      JSON.stringify(packet.activeProcesses),
    );
  }

  /**
   * Update the target session ID after the subagent session is created.
   */
  setTargetSession(handoffId: string, targetSessionId: string): void {
    this.db.query(
      `UPDATE handoff_packets SET target_session_id = ? WHERE id = ?`
    ).run(targetSessionId, handoffId);
  }

  /**
   * Get a handoff packet by ID.
   */
  findById(id: string): HandoffRow | null {
    return this.db.query(
      `SELECT * FROM handoff_packets WHERE id = ?`
    ).get(id) as HandoffRow | null;
  }

  /**
   * Get all handoffs for a source session (voice session).
   */
  findBySourceSession(sourceSessionId: string): HandoffRow[] {
    return this.db.query(
      `SELECT * FROM handoff_packets WHERE source_session_id = ? ORDER BY created_at DESC`
    ).all(sourceSessionId) as HandoffRow[];
  }

  /**
   * Delete handoffs that reference a session as source or target.
   * Returns number of rows deleted.
   */
  deleteBySession(sessionId: string): number {
    const result = this.db.query(
      `DELETE FROM handoff_packets
       WHERE source_session_id = ? OR target_session_id = ?`
    ).run(sessionId, sessionId);
    return result.changes;
  }

  /**
   * Delete all handoff packets.
   * Returns number of rows deleted.
   */
  deleteAll(): number {
    const result = this.db.query('DELETE FROM handoff_packets').run();
    return result.changes;
  }
}



/**
 * Session Messages Repository
 *
 * Stores AI SDK stream events for chat history persistence.
 * Enables UI reconstruction with tool calls, reasoning, and full message structure.
 */

import type { Database } from 'bun:sqlite';
import { getDatabase } from '../database.js';
import type { AISDKStreamEvent } from '../../api/stream-types.js';

/**
 * Events worth persisting (content-bearing).
 * Lifecycle events (start, finish, etc.) are skipped as they're reconstructable.
 */
export const PERSISTABLE_EVENT_TYPES = new Set([
  'text-delta',
  'user-transcript',
  'tool-call',
  'tool-result',
  'reasoning-delta',
  'reasoning-end',
  'error',
]);

export interface SessionMessage {
  id: number;
  session_id: string;
  event_type: string;
  payload: string; // JSON blob of AISDKStreamEvent
  created_at: string;
}

export class SessionMessagesRepository {
  private db: Database;

  constructor(db?: Database) {
    this.db = db ?? getDatabase();
  }

  /**
   * Persist an AI SDK stream event for a session.
   * Only persists content-bearing events (text, tools, reasoning, errors).
   *
   * @returns The created message, or null if event type is not persistable
   */
  create(sessionId: string, event: AISDKStreamEvent): SessionMessage | null {
    if (!PERSISTABLE_EVENT_TYPES.has(event.type)) {
      return null;
    }

    const payload = JSON.stringify(event);

    const result = this.db
      .query(
        `INSERT INTO session_messages (session_id, event_type, payload)
         VALUES (?, ?, ?)`
      )
      .run(sessionId, event.type, payload);

    return this.findById(result.lastInsertRowid as number)!;
  }

  /**
   * Find a message by ID.
   */
  findById(id: number): SessionMessage | null {
    return (
      (this.db
        .query('SELECT * FROM session_messages WHERE id = ?')
        .get(id) as SessionMessage) ?? null
    );
  }

  /**
   * Get all messages for a session, ordered by creation time.
   */
  getBySession(sessionId: string): SessionMessage[] {
    return this.db
      .query(
        `SELECT * FROM session_messages
         WHERE session_id = ?
         ORDER BY id ASC`
      )
      .all(sessionId) as SessionMessage[];
  }

  /**
   * Get messages for a session with parsed events.
   * Convenience method for replaying events.
   */
  getEventsForSession(sessionId: string): AISDKStreamEvent[] {
    const messages = this.getBySession(sessionId);
    return messages.map((msg) => JSON.parse(msg.payload) as AISDKStreamEvent);
  }

  /**
   * Delete all messages for a session.
   */
  deleteBySession(sessionId: string): number {
    const result = this.db
      .query('DELETE FROM session_messages WHERE session_id = ?')
      .run(sessionId);
    return result.changes;
  }

  /**
   * Get message count for a session.
   */
  countBySession(sessionId: string): number {
    const result = this.db
      .query('SELECT COUNT(*) as count FROM session_messages WHERE session_id = ?')
      .get(sessionId) as { count: number };
    return result.count;
  }
}



/**
 * Timers Repository
 *
 * CRUD operations for timers and reminders.
 */

import type { Database } from 'bun:sqlite';
import { getDatabase } from '../database.js';

export type TimerMode = 'tts' | 'agent';
export type TimerStatus = 'pending' | 'fired' | 'cancelled';

export interface Timer {
  id: number;
  fire_at: string;
  mode: TimerMode;
  message: string;
  status: TimerStatus;
  created_at: string;
}

export interface CreateTimerInput {
  fire_at: Date | string;
  message: string;
  mode?: TimerMode;
}

export class TimersRepository {
  private db: Database;

  constructor(db?: Database) {
    this.db = db ?? getDatabase();
  }

  /**
   * Create a new timer.
   */
  create(input: CreateTimerInput): Timer {
    const fireAt =
      input.fire_at instanceof Date ? input.fire_at.toISOString() : input.fire_at;
    const mode = input.mode ?? 'tts';

    const result = this.db
      .query(
        `INSERT INTO timers (fire_at, mode, message, status)
         VALUES (?, ?, ?, 'pending')`
      )
      .run(fireAt, mode, input.message);

    return this.findById(result.lastInsertRowid as number)!;
  }

  /**
   * Find a timer by ID.
   */
  findById(id: number): Timer | null {
    return (this.db.query('SELECT * FROM timers WHERE id = ?').get(id) as Timer) ?? null;
  }

  /**
   * List all timers, optionally filtered by status.
   */
  list(status?: TimerStatus): Timer[] {
    if (status) {
      return this.db
        .query('SELECT * FROM timers WHERE status = ? ORDER BY fire_at ASC')
        .all(status) as Timer[];
    }
    return this.db.query('SELECT * FROM timers ORDER BY fire_at ASC').all() as Timer[];
  }

  /**
   * Get pending timers that are due (fire_at <= now).
   */
  getDue(): Timer[] {
    // Compare against current ISO timestamp to handle both ISO and SQLite datetime formats
    const now = new Date().toISOString();
    return this.db
      .query(
        `SELECT * FROM timers
         WHERE status = 'pending' AND fire_at <= ?
         ORDER BY fire_at ASC`
      )
      .all(now) as Timer[];
  }

  /**
   * Get the next pending timer.
   */
  getNext(): Timer | null {
    return (
      (this.db
        .query(
          `SELECT * FROM timers
           WHERE status = 'pending'
           ORDER BY fire_at ASC
           LIMIT 1`
        )
        .get() as Timer) ?? null
    );
  }

  /**
   * Mark a timer as fired.
   */
  markFired(id: number): boolean {
    const result = this.db
      .query(`UPDATE timers SET status = 'fired' WHERE id = ?`)
      .run(id);
    return result.changes > 0;
  }

  /**
   * Cancel a timer.
   */
  cancel(id: number): boolean {
    const result = this.db
      .query(`UPDATE timers SET status = 'cancelled' WHERE id = ? AND status = 'pending'`)
      .run(id);
    return result.changes > 0;
  }

  /**
   * Delete a timer.
   */
  delete(id: number): boolean {
    const result = this.db.query('DELETE FROM timers WHERE id = ?').run(id);
    return result.changes > 0;
  }

  /**
   * Get all pending timers.
   */
  getPending(): Timer[] {
    return this.db
      .query(
        `SELECT * FROM timers
         WHERE status = 'pending'
         ORDER BY fire_at ASC`
      )
      .all() as Timer[];
  }

  /**
   * Clean up old fired/cancelled timers (older than days).
   */
  cleanup(days: number = 7): number {
    const result = this.db
      .query(
        `DELETE FROM timers
         WHERE status IN ('fired', 'cancelled')
         AND created_at < datetime('now', '-' || ? || ' days')`
      )
      .run(days);
    return result.changes;
  }
}



/**
 * Database Connection Manager
 *
 * Singleton pattern for SQLite database connection.
 * Uses bun:sqlite for synchronous, high-performance operations.
 */

import { Database } from 'bun:sqlite';
import { join } from 'path';
import { homedir } from 'os';
import { runMigrations } from './schema.js';

const DEFAULT_DB_PATH = join(homedir(), 'voice-agent.db');

let dbInstance: Database | null = null;

/**
 * Get the database instance (singleton).
 * Creates the database and runs migrations if needed.
 */
export function getDatabase(dbPath: string = DEFAULT_DB_PATH): Database {
  if (!dbInstance) {
    console.log(`[DB] Opening database at ${dbPath}`);
    dbInstance = new Database(dbPath);

    // Enable WAL mode for better concurrent access
    dbInstance.exec('PRAGMA journal_mode = WAL');

    // Enable foreign keys
    dbInstance.exec('PRAGMA foreign_keys = ON');

    // Run migrations
    runMigrations(dbInstance);

    console.log('[DB] Database initialized');
  }

  return dbInstance;
}

/**
 * Close the database connection.
 */
export function closeDatabase(): void {
  if (dbInstance) {
    console.log('[DB] Closing database');
    dbInstance.close();
    dbInstance = null;
  }
}

/**
 * Generate a unique ID for sessions.
 * Format: 8 character hex string
 */
export function generateId(): string {
  return Math.random().toString(16).substring(2, 10);
}



