/**
 * Demo API Module - Provides streaming demo data for component development.
 *
 * Routes:
 * - GET /api/demo/health - Health check
 * - GET /api/demo/streams - List available demo streams
 * - GET /api/demo/streams/:id - SSE stream for a specific demo
 * - POST /api/demo/capture/start - Start capturing real agent output
 * - POST /api/demo/capture/stop - Stop capture and save
 * - GET /api/demo/captured - List captured sessions
 */

import type { IncomingMessage, ServerResponse } from 'http';
import { streams, type DemoStream } from './streams/index.js';

export { type DemoStream } from './streams/index.js';

/**
 * Handle demo API requests.
 * Returns true if the request was handled, false otherwise.
 */
export async function handleDemoRequest(
  req: IncomingMessage,
  res: ServerResponse
): Promise {
  const url = req.url ?? '';

  // Health check
  if (req.method === 'GET' && url === '/api/demo/health') {
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ status: 'ok', module: 'demo' }));
    return true;
  }

  // HEAD for health check (used by frontend to check availability)
  if (req.method === 'HEAD' && url === '/api/demo/health') {
    res.writeHead(200);
    res.end();
    return true;
  }

  // List available streams
  if (req.method === 'GET' && url === '/api/demo/streams') {
    const list = Array.from(streams.entries()).map(([id, stream]) => ({
      id,
      name: stream.name,
      description: stream.description,
      agent: stream.agent,
      eventCount: stream.events.length,
    }));
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify(list));
    return true;
  }

  // Stream a specific demo via SSE
  const streamMatch = url.match(/^\/api\/demo\/streams\/([a-zA-Z0-9_-]+)$/);
  if (req.method === 'GET' && streamMatch) {
    const streamId = streamMatch[1]!;
    const stream = streams.get(streamId);

    if (!stream) {
      res.writeHead(404, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: `Stream '${streamId}' not found` }));
      return true;
    }

    // Set up SSE
    res.writeHead(200, {
      'Content-Type': 'text/event-stream',
      'Cache-Control': 'no-cache',
      'Connection': 'keep-alive',
      'Access-Control-Allow-Origin': '*',
    });

    // Stream events with delays
    streamEvents(res, stream);
    return true;
  }

  return false;
}

/**
 * Stream demo events via SSE with realistic timing.
 */
async function streamEvents(res: ServerResponse, stream: DemoStream): Promise {
  for (const event of stream.events) {
    // Wait for the delay
    if (event.delay && event.delay > 0) {
      await sleep(event.delay);
    }

    // Check if connection is still open
    if (res.writableEnded) {
      return;
    }

    // Send the event
    const data = JSON.stringify({
      type: event.type,
      payload: event.payload,
    });
    res.write(`data: ${data}\n\n`);
  }

  // Send done event
  res.write('event: done\ndata: {}\n\n');
  res.end();
}

function sleep(ms: number): Promise {
  return new Promise((resolve) => setTimeout(resolve, ms));
}



/**
 * Library utilities for the voice agent.
 *
 * Note: Agent streaming is now handled directly in each subagent using
 * AI SDK's streamText with stream_chunk events. See:
 * - src/subagents/cli/index.ts
 * - src/subagents/web-search/index.ts
 * - src/api/stream-types.ts
 */

// Re-export stream types for convenience
export type { AISDKStreamEvent, StreamChunkMessage } from '../api/stream-types.js';
export { createStreamChunk } from '../api/stream-types.js';



import { EventEmitter } from 'events';

// Module-level singleton
let instance: ProcessManager | null = null;

/**
 * Get the singleton ProcessManager instance.
 * Created on first call, reused thereafter.
 */
export function getProcessManager(): ProcessManager {
  if (!instance) {
    instance = new ProcessManager();
  }
  return instance;
}

export interface ManagedProcess {
  id: string;
  name: string;              // Human-readable ("swift-falcon")
  sessionId: string;          // DB session ID
  type: 'headless' | 'interactive' | 'web_search' | 'deep_thinking';
  notifyVoiceOnCompletion: boolean;
  status: 'running' | 'finished' | 'error';
  startedAt: number;
  finishedAt?: number;
  result?: string;
  error?: string;
}

export interface SpawnConfig {
  name: string;
  sessionId: string;
  type: ManagedProcess['type'];
  notifyVoiceOnCompletion?: boolean;
  execute: () => Promise;
}

export class ProcessManager extends EventEmitter {
  private processes = new Map();

  spawn(config: SpawnConfig): ManagedProcess {
    const process: ManagedProcess = {
      id: config.sessionId,
      name: config.name,
      sessionId: config.sessionId,
      type: config.type,
      notifyVoiceOnCompletion: config.notifyVoiceOnCompletion ?? false,
      status: 'running',
      startedAt: Date.now(),
    };

    this.processes.set(process.id, process);

    // Fire-and-forget: run in background
    config.execute()
      .then((result) => {
        process.status = 'finished';
        process.finishedAt = Date.now();
        process.result = result;
        this.emit('process:completed', process);
      })
      .catch((err) => {
        process.status = 'error';
        process.finishedAt = Date.now();
        process.error = err?.message || String(err);
        this.emit('process:error', process);
      });

    return process;
  }

  getRunning(): ManagedProcess[] {
    return [...this.processes.values()].filter(p => p.status === 'running');
  }

  getByName(name: string): ManagedProcess | undefined {
    return [...this.processes.values()].find(p => p.name === name);
  }

  getBySessionId(id: string): ManagedProcess | undefined {
    return this.processes.get(id);
  }

  cancel(nameOrId: string): boolean {
    const process = this.getByName(nameOrId) || this.processes.get(nameOrId);
    if (!process || process.status !== 'running') return false;
    process.status = 'error';
    process.finishedAt = Date.now();
    process.error = 'Cancelled by user';
    this.emit('process:error', process);
    return true;
  }

  getSummary(): string {
    const running = this.getRunning().length;
    const finished = [...this.processes.values()].filter(p => p.status === 'finished').length;
    const errors = [...this.processes.values()].filter(p => p.status === 'error').length;
    const parts: string[] = [];
    if (running > 0) parts.push(`${running} running`);
    if (finished > 0) parts.push(`${finished} completed`);
    if (errors > 0) parts.push(`${errors} failed`);
    return parts.join(', ') || 'No processes';
  }
}



/**
 * Prompt Variable Interpolation
 *
 * Uses double brackets {{variable}} syntax to avoid conflicts with JSON examples in prompts.
 * Single curly braces {} in prompts are preserved (for JSON examples, etc.).
 */

export interface InterpolationContext {
  agent_name?: string;
  session_id?: string;
  user_locale?: string;
  [key: string]: string | undefined;
}

/**
 * Interpolate variables in a prompt template.
 *
 * Replaces {{variable}} patterns with values from context or built-in variables.
 * Unknown variables are preserved unchanged.
 *
 * Built-in variables:
 * - {{date}} - Current date (YYYY-MM-DD)
 * - {{datetime}} - Current ISO datetime
 * - {{weekday}} - Current weekday name (English)
 * - {{timestamp}} - Unix timestamp in ms
 *
 * @param template - The prompt template with {{variable}} placeholders
 * @param context - Variables to substitute (agent_name, session_id, etc.)
 * @returns The interpolated prompt string
 *
 * @example
 * ```typescript
 * const prompt = interpolatePrompt(
 *   "Hello {{agent_name}}, today is {{date}}",
 *   { agent_name: "Jarvis" }
 * );
 * // => "Hello Jarvis, today is 2025-01-15"
 * ```
 */
export function interpolatePrompt(
  template: string,
  context: InterpolationContext = {}
): string {
  const now = new Date();

  // Built-in variables (can be overridden by context)
  const builtins: Record = {
    date: now.toISOString().split('T')[0] ?? '',
    datetime: now.toISOString(),
    weekday: now.toLocaleDateString('en-US', { weekday: 'long' }),
    timestamp: now.getTime().toString(),
  };

  // Merge built-ins with context (context takes precedence)
  const vars: Record = { ...builtins, ...context };

  // Replace {{variable}} patterns
  // Regex matches {{ followed by word characters, followed by }}
  return template.replace(/\{\{(\w+)\}\}/g, (match, key: string) => {
    const value = vars[key];
    // If variable not found, keep the original {{variable}} unchanged
    return value !== undefined ? value : match;
  });
}

/**
 * Extract all variable names from a prompt template.
 *
 * @param template - The prompt template
 * @returns Array of unique variable names found in the template
 *
 * @example
 * ```typescript
 * const vars = extractVariables("Hello {{name}}, date: {{date}}");
 * // => ["name", "date"]
 * ```
 */
export function extractVariables(template: string): string[] {
  const matches = template.matchAll(/\{\{(\w+)\}\}/g);
  const variables = new Set();

  for (const match of matches) {
    if (match[1]) variables.add(match[1]);
  }

  return Array.from(variables);
}



/**
 * Timer Scheduler
 *
 * Background service that checks for due timers and fires them.
 * Supports two modes:
 *   - 'tts': Direct TTS output for the message
 *   - 'agent': Inject as synthetic user message to the agent
 */

import { TimersRepository, type Timer } from '../db/index.js';
import { EventEmitter } from 'events';

export interface SchedulerEvents {
  timerFired: (timer: Timer) => void;
  error: (error: Error) => void;
}

export class Scheduler extends EventEmitter {
  private timersRepo: TimersRepository;
  private intervalId: NodeJS.Timeout | null = null;
  private checkIntervalMs: number;

  constructor(checkIntervalMs: number = 1000) {
    super();
    this.timersRepo = new TimersRepository();
    this.checkIntervalMs = checkIntervalMs;
  }

  /**
   * Start the scheduler background loop.
   */
  start(): void {
    if (this.intervalId) {
      return; // Already running
    }

    console.log('[Scheduler] Starting timer scheduler');
    this.intervalId = setInterval(() => this.checkTimers(), this.checkIntervalMs);

    // Check immediately on start
    this.checkTimers();
  }

  /**
   * Stop the scheduler.
   */
  stop(): void {
    if (this.intervalId) {
      console.log('[Scheduler] Stopping timer scheduler');
      clearInterval(this.intervalId);
      this.intervalId = null;
    }
  }

  /**
   * Check for due timers and fire them.
   */
  private checkTimers(): void {
    try {
      const dueTimers = this.timersRepo.getDue();

      for (const timer of dueTimers) {
        console.log(`[Scheduler] Firing timer #${timer.id}: ${timer.message}`);

        // Mark as fired first to prevent double-firing
        this.timersRepo.markFired(timer.id);

        // Emit event for the main app to handle
        this.emit('timerFired', timer);
      }
    } catch (error) {
      console.error('[Scheduler] Error checking timers:', error);
      this.emit('error', error as Error);
    }
  }

  /**
   * Get the next pending timer.
   */
  getNextTimer(): Timer | null {
    return this.timersRepo.getNext();
  }

  /**
   * Get all pending timers.
   */
  getPendingTimers(): Timer[] {
    return this.timersRepo.getPending();
  }

  /**
   * Check if scheduler is running.
   */
  isRunning(): boolean {
    return this.intervalId !== null;
  }
}

// Re-export time parsing utilities
export { parseTimeExpression, formatTimerResponse } from './time-parser.js';



/**
 * Natural Language Time Parser
 *
 * Parses time expressions like:
 *   - "in 5 minutes"
 *   - "in einer Stunde"
 *   - "at 3pm" / "um 15 Uhr"
 *   - "tomorrow at 9am"
 *
 * Uses Europe/Berlin timezone for German locale.
 */

// Set timezone for consistent parsing
const TIMEZONE = 'Europe/Berlin';

interface ParsedTime {
  date: Date;
  description: string;
}


/**
 * Format date for German timezone display.
 */
function formatTimeDE(date: Date): string {
  return date.toLocaleTimeString('de-DE', {
    hour: '2-digit',
    minute: '2-digit',
    timeZone: TIMEZONE,
  });
}

/**
 * Format date for German timezone display.
 */
function formatDateDE(date: Date): string {
  return date.toLocaleDateString('de-DE', {
    timeZone: TIMEZONE,
  });
}

/**
 * Get today's date string in German timezone.
 */
function getTodayDE(): string {
  return new Date().toLocaleDateString('de-DE', { timeZone: TIMEZONE });
}

/**
 * Get tomorrow's date string in German timezone.
 */
function getTomorrowDE(): string {
  const tomorrow = new Date();
  tomorrow.setDate(tomorrow.getDate() + 1);
  return tomorrow.toLocaleDateString('de-DE', { timeZone: TIMEZONE });
}

/**
 * Parse a natural language time expression into a Date.
 * Supports English and German.
 */
export function parseTimeExpression(expression: string): ParsedTime | null {
  const now = new Date();
  const lower = expression.toLowerCase().trim();

  // Try relative time first ("in X minutes/hours")
  const relativeResult = parseRelativeTime(lower, now);
  if (relativeResult) return relativeResult;

  // Try absolute time ("at 3pm", "um 15 Uhr")
  const absoluteResult = parseAbsoluteTime(lower, now);
  if (absoluteResult) return absoluteResult;

  return null;
}

/**
 * Parse relative time expressions like "in 5 minutes".
 */
function parseRelativeTime(expr: string, now: Date): ParsedTime | null {
  // English patterns
  const enPatterns: [RegExp, (n: number) => number][] = [
    [/in (\d+) seconds?/, (n) => n * 1000],
    [/in (\d+) minutes?/, (n) => n * 60 * 1000],
    [/in (\d+) hours?/, (n) => n * 60 * 60 * 1000],
    [/in half an hour/, () => 30 * 60 * 1000],
    [/in an hour/, () => 60 * 60 * 1000],
    [/in a minute/, () => 60 * 1000],
  ];

  // German patterns
  const dePatterns: [RegExp, (n: number) => number][] = [
    [/in (\d+) sekunden?/, (n) => n * 1000],
    [/in (\d+) minuten?/, (n) => n * 60 * 1000],
    [/in (\d+) stunden?/, (n) => n * 60 * 60 * 1000],
    [/in einer halben stunde/, () => 30 * 60 * 1000],
    [/in einer stunde/, () => 60 * 60 * 1000],
    [/in einer minute/, () => 60 * 1000],
  ];

  const allPatterns = [...enPatterns, ...dePatterns];

  for (const [pattern, getMs] of allPatterns) {
    const match = expr.match(pattern);
    if (match) {
      const num = match[1] ? parseInt(match[1], 10) : 1;
      const ms = getMs(num);
      const date = new Date(now.getTime() + ms);
      return {
        date,
        description: formatRelativeDescription(ms),
      };
    }
  }

  return null;
}

/**
 * Parse absolute time expressions like "at 3pm" or "um 15 Uhr".
 */
function parseAbsoluteTime(expr: string, now: Date): ParsedTime | null {
  let hours: number | null = null;
  let minutes = 0;
  let addDay = false;

  // English: "at 3pm", "at 3:30pm", "at 15:30"
  const enMatch = expr.match(/at (\d{1,2})(?::(\d{2}))?\s*(am|pm)?/);
  if (enMatch && enMatch[1]) {
    hours = parseInt(enMatch[1], 10);
    minutes = enMatch[2] ? parseInt(enMatch[2], 10) : 0;
    const ampm = enMatch[3];
    if (ampm === 'pm' && hours < 12) hours += 12;
    if (ampm === 'am' && hours === 12) hours = 0;
  }

  // German: "um 15 Uhr", "um 15:30 Uhr", "um 3 Uhr"
  const deMatch = expr.match(/um (\d{1,2})(?::(\d{2}))?\s*uhr/);
  if (deMatch && deMatch[1]) {
    hours = parseInt(deMatch[1], 10);
    minutes = deMatch[2] ? parseInt(deMatch[2], 10) : 0;
  }

  // Check for "tomorrow" / "morgen"
  if (expr.includes('tomorrow') || expr.includes('morgen')) {
    addDay = true;
  }

  if (hours === null) {
    return null;
  }

  const date = new Date(now);
  date.setHours(hours, minutes, 0, 0);

  // If time is in the past today, move to tomorrow
  if (date <= now && !addDay) {
    date.setDate(date.getDate() + 1);
  } else if (addDay) {
    date.setDate(date.getDate() + 1);
  }

  return {
    date,
    description: formatAbsoluteDescription(date),
  };
}

/**
 * Format a relative time description.
 */
function formatRelativeDescription(ms: number): string {
  const minutes = Math.round(ms / 60000);
  if (minutes < 60) {
    return `in ${minutes} minute${minutes !== 1 ? 's' : ''}`;
  }
  const hours = Math.round(minutes / 60);
  return `in ${hours} hour${hours !== 1 ? 's' : ''}`;
}

/**
 * Format an absolute time description.
 */
function formatAbsoluteDescription(date: Date): string {
  const dateStr = formatDateDE(date);
  const isToday = dateStr === getTodayDE();
  const isTomorrow = dateStr === getTomorrowDE();
  const timeStr = formatTimeDE(date);

  if (isToday) {
    return `heute um ${timeStr} Uhr`;
  } else if (isTomorrow) {
    return `morgen um ${timeStr} Uhr`;
  } else {
    return `am ${dateStr} um ${timeStr} Uhr`;
  }
}

/**
 * Format a timer response for TTS.
 */
export function formatTimerResponse(message: string, fireAt: Date): string {
  const now = new Date();
  const diffMs = fireAt.getTime() - now.getTime();
  const diffMinutes = Math.round(diffMs / 60000);

  let timeDesc: string;
  if (diffMinutes < 60) {
    timeDesc = `in ${diffMinutes} Minuten`;
  } else {
    const hours = Math.floor(diffMinutes / 60);
    const mins = diffMinutes % 60;
    if (mins === 0) {
      timeDesc = `in ${hours} Stunde${hours !== 1 ? 'n' : ''}`;
    } else {
      timeDesc = `in ${hours} Stunde${hours !== 1 ? 'n' : ''} und ${mins} Minuten`;
    }
  }

  return `Timer gesetzt ${timeDesc}: ${message}`;
}



import { createLlmRuntime } from '@voiceclaw/llm-runtime';

export const llmRuntime = createLlmRuntime();



/**
 * Subagent Loader - Utility to load agent configuration and prompts from disk.
 *
 * Each subagent lives in a directory with:
 * - config.json: Agent settings (model, name, maxSteps, etc.)
 * - PROMPT.md: System instructions (fallback)
 *
 * Prompts are now primarily loaded from the centralized ./prompts/ directory
 * with version support and variable interpolation.
 */

import { readFile } from 'fs/promises';
import { join, basename } from 'path';
import {
  getActivePrompt,
  getPromptConfig,
  getPromptIdForSubagent,
  type InterpolationContext,
} from '../prompts/index.js';

export interface SubagentConfig {
  name: string;
  model: string;
  description?: string;
  maxSteps?: number;
}

export interface LoadedSubagent {
  config: SubagentConfig;
  prompt: string;
}

/**
 * Load agent configuration and prompt from a subagent directory.
 *
 * Prompts are loaded from the centralized ./prompts/ directory first,
 * with fallback to local PROMPT.md if not found.
 *
 * @param dirPath - Absolute path to the subagent directory (use import.meta.dirname)
 * @param context - Optional interpolation context for variables
 * @returns The loaded config and prompt
 */
export async function loadAgentConfig(
  dirPath: string,
  context: InterpolationContext = {}
): Promise {
  const configPath = join(dirPath, 'config.json');

  // Load config from local directory
  const configStr = await readFile(configPath, 'utf-8');
  const config = JSON.parse(configStr) as SubagentConfig;

  // Determine prompt ID from directory name
  const dirName = basename(dirPath);
  const promptId = getPromptIdForSubagent(dirName);

  // Add agent_name to context if not provided
  const fullContext: InterpolationContext = {
    agent_name: config.name,
    ...context,
  };

  // Override model/maxSteps from centralized prompts config (JIT — no restart needed)
  const promptConfig = await getPromptConfig(promptId);
  if (promptConfig?.metadata?.model) {
    config.model = promptConfig.metadata.model;
  }
  if (promptConfig?.metadata?.maxSteps) {
    config.maxSteps = promptConfig.metadata.maxSteps;
  }

  // Try centralized prompts first, fall back to local PROMPT.md
  let prompt = await getActivePrompt(promptId, fullContext);

  if (!prompt) {
    // Fallback to local file
    const promptPath = join(dirPath, 'PROMPT.md');
    try {
      prompt = (await readFile(promptPath, 'utf-8')).trim();
    } catch {
      throw new Error(`No prompt found for ${dirName} (checked prompts/${promptId} and ${promptPath})`);
    }
  }

  return { config, prompt };
}

/**
 * Synchronously load agent config (for use in module initialization).
 * Prefer async loadAgentConfig when possible.
 *
 * Note: This does NOT use the centralized prompts system (sync I/O limitation).
 * Use only for initialization where async is not possible.
 */
export function loadAgentConfigSync(dirPath: string): LoadedSubagent {
  const { readFileSync } = require('fs');
  const configPath = join(dirPath, 'config.json');
  const promptPath = join(dirPath, 'PROMPT.md');

  const configStr = readFileSync(configPath, 'utf-8');
  const prompt = readFileSync(promptPath, 'utf-8');

  return {
    config: JSON.parse(configStr) as SubagentConfig,
    prompt: prompt.trim(),
  };
}



import type { LlmEvent } from '@voiceclaw/llm-runtime';
import { wsBroadcast } from '../api/websocket.js';

interface StreamBridgeOptions {
  sessionId?: string;
  onToolCall?: (event: {
    toolName: string;
    toolCallId: string;
    input?: unknown;
  }) => void;
  onToolResult?: (event: {
    toolName: string;
    toolCallId: string;
    output?: unknown;
    isError?: boolean;
  }) => void;
}

export async function forwardLlmStreamToSession(
  events: AsyncIterable,
  options: StreamBridgeOptions
): Promise<{ text: string; eventCount: number }> {
  let text = '';
  let eventCount = 0;

  for await (const event of events) {
    eventCount++;

    if (event.type === 'start') {
      if (options.sessionId) {
        wsBroadcast.streamChunk(options.sessionId, { type: 'start' });
      }
      continue;
    }

    if (event.type === 'start-step') {
      if (options.sessionId) {
        wsBroadcast.streamChunk(options.sessionId, { type: 'start-step' });
      }
      continue;
    }

    if (event.type === 'text-delta') {
      text += event.textDelta;
      if (options.sessionId) {
        wsBroadcast.streamChunk(options.sessionId, {
          type: 'text-delta',
          textDelta: event.textDelta,
        });
      }
      continue;
    }

    if (event.type === 'reasoning-delta') {
      if (options.sessionId) {
        wsBroadcast.streamChunk(options.sessionId, {
          type: 'reasoning-delta',
          text: event.text,
        });
      }
      continue;
    }

    if (event.type === 'tool-call') {
      options.onToolCall?.({
        toolName: event.toolName,
        toolCallId: event.toolCallId,
        input: event.input,
      });

      if (options.sessionId) {
        wsBroadcast.streamChunk(options.sessionId, {
          type: 'tool-call',
          toolName: event.toolName,
          toolCallId: event.toolCallId,
          input: event.input,
        });
      }
      continue;
    }

    if (event.type === 'tool-result') {
      options.onToolResult?.({
        toolName: event.toolName,
        toolCallId: event.toolCallId,
        output: event.output,
        isError: event.isError,
      });

      if (options.sessionId) {
        const outputStr =
          typeof event.output === 'string' ? event.output : JSON.stringify(event.output);
        wsBroadcast.streamChunk(options.sessionId, {
          type: 'tool-result',
          toolName: event.toolName,
          toolCallId: event.toolCallId,
          output: outputStr,
          ...(event.isError ? { isError: true } : {}),
        });
      }
      continue;
    }

    if (event.type === 'finish') {
      if (options.sessionId) {
        wsBroadcast.streamChunk(options.sessionId, {
          type: 'finish',
          finishReason: event.finishReason ?? 'stop',
        });
      }
      continue;
    }

    if (event.type === 'error') {
      if (options.sessionId) {
        wsBroadcast.streamChunk(options.sessionId, {
          type: 'error',
          error: event.error,
        });
      }
      throw new Error(event.error);
    }
  }

  return { text, eventCount };
}



/**
 * Background Task Tool - Spawns detached subagent sessions that don't block voice input.
 *
 * This tool demonstrates the background session pattern:
 * - Returns immediately without waiting for the task to complete
 * - The voice agent can continue listening for new commands
 * - When the background task completes, it notifies the voice agent (if still active)
 *
 * Use cases:
 * - Long-running code reviews
 * - Feature implementations
 * - Any task where the user wants to queue work and continue talking
 */

import { tool, RealtimeContextData } from '@openai/agents/realtime';
import { z } from 'zod';
import { spawnBackgroundSubagent } from '../subagents/background.js';
import type { VoiceAgent } from '../agent/voice-agent.js';

const backgroundTaskParameters = z.object({
  task: z
    .string()
    .describe(
      'The task to run in the background. Be specific about what needs to be done.'
    ),
  notify_on_completion: z
    .boolean()
    .optional()
    .default(true)
    .describe('Whether to notify the user when the task completes (default: true)'),
});

/**
 * Factory function to create the background_task tool with injected dependencies.
 *
 * @param voiceAgent - Reference to the voice agent for completion notifications
 * @param sessionId - Current voice session ID for parent-child tracking
 */
export function createBackgroundTaskTool(voiceAgent: VoiceAgent, sessionId: string) {
  return tool({
    name: 'background_task',
    description: `Start a task in the background without blocking the conversation.
Use this when:
- The user wants to queue a task and continue with other things
- The task might take a while (code reviews, implementations)
- The user explicitly says "in the background" or "while I do other things"

The task will run independently and notify the user when complete.
Examples:
- "Review the kireon backend code in the background"
- "Start implementing dark mode while I think about the API"
- "Run the tests in the background and tell me when done"`,
    parameters: backgroundTaskParameters,
    async execute({ task, notify_on_completion }) {
      console.log('[BackgroundTask] Spawning background task:', task);

      // Build HandoffPacket with full voice context (anti-telephone)
      const handoff = voiceAgent?.createHandoffPacket(task);

      // Spawn the background subagent
      const { sessionId: bgSessionId } = spawnBackgroundSubagent({
        task,
        voiceSessionId: sessionId,
        handoff,
        voiceAgent: notify_on_completion ? voiceAgent : undefined,
        completionMessage: (result) =>
          `Deine Hintergrund-Aufgabe ist fertig: ${result.substring(0, 200)}${result.length > 200 ? '...' : ''}`,
      });

      // Return immediately - don't await the completion
      return `Ich habe die Aufgabe im Hintergrund gestartet (Session: ${bgSessionId.substring(0, 8)}). Du kannst weiter mit mir sprechen - ich sage dir Bescheid wenn es fertig ist.`;
    },
  });
}



/**
 * CLI Agent Tools - Tools for managing Mac CLI sessions.
 *
 * These tools create TERMINAL sessions as children of the CLI orchestrator.
 * Session Hierarchy:
 *   Orchestrator (stateful, created in index.ts)
 *     → Terminal 1 (long-running Claude Code CLI)
 *     → Terminal 2
 */

import { tool } from 'ai';
import { z } from 'zod';
import type {
  ToolCallContext,
  ToolCallResult,
  ToolDefinition,
} from '@voiceclaw/ai-core/tools';
import {
  generateId,
  CliSessionsRepository,
  CliEventsRepository,
} from '../db/index.js';
import * as macClient from './mac-client.js';
import { waitForSessionCompletion } from '../api/webhooks.js';
import { wsBroadcast } from '../api/websocket.js';
import { getCurrentOrchestratorId, consumePendingToolCall } from '../subagents/cli/index.js';

/**
 * Check if the Mac daemon is available.
 */
export async function isMacDaemonAvailable(): Promise {
  const health = await macClient.checkHealth();
  return health !== null;
}

const ACTIVE_SESSION_STATUSES = new Set(['pending', 'running', 'waiting_for_input']);

function isActiveSessionStatus(status: string): boolean {
  return ACTIVE_SESSION_STATUSES.has(status);
}

function clipText(value: string, maxLength: number): string {
  if (value.length <= maxLength) return value;
  return `${value.slice(0, maxLength - 3)}...`;
}

function normalizeOutputLine(line: string): string {
  const trimmed = line.trimEnd();

  if (/^[\-\u2500\s]+$/.test(trimmed) && trimmed.length > 30) {
    return '----------------------------------------';
  }

  return clipText(trimmed, 160);
}

function formatOutputBlock(lines: string[]): string {
  if (lines.length === 0) {
    return '| (keine Ausgabe - interaktive Session wartet eventuell auf Eingabe)';
  }

  return lines.map((line) => `| ${normalizeOutputLine(line)}`).join('\n');
}

interface ResolvedTerminalTarget {
  terminalId: string | null;
  resolutionNote: string | null;
  error: string | null;
}

function resolveTerminalTarget(
  sessionsRepo: CliSessionsRepository,
  targetId: string,
  orchestratorId?: string
): ResolvedTerminalTarget {
  const target = sessionsRepo.findById(targetId);

  if (!target) {
    return {
      terminalId: null,
      resolutionNote: null,
      error: `Terminal/Session "${targetId}" nicht gefunden.`,
    };
  }

  if (target.type === 'terminal') {
    return {
      terminalId: target.id,
      resolutionNote: null,
      error: null,
    };
  }

  if (target.type === 'subagent') {
    const activeChildren = sessionsRepo
      .getChildren(target.id)
      .filter((child) => child.type === 'terminal' && isActiveSessionStatus(child.status));

    if (activeChildren.length === 1) {
      const resolved = activeChildren[0]!;
      return {
        terminalId: resolved.id,
        resolutionNote: `Orchestrator-ID ${target.id} wurde auf Terminal ${resolved.id} aufgelöst.`,
        error: null,
      };
    }

    if (activeChildren.length > 1) {
      const choices = activeChildren.map((child) => `- ${child.id} (${child.status})`).join('\n');
      return {
        terminalId: null,
        resolutionNote: null,
        error: `Orchestrator ${target.id} hat mehrere aktive Terminals. Nutze terminal_id explizit:\n${choices}`,
      };
    }

    return {
      terminalId: null,
      resolutionNote: null,
      error: `Orchestrator ${target.id} hat kein aktives Terminal.`,
    };
  }

  if (target.type === 'voice' && orchestratorId) {
    const orchestrator = sessionsRepo.findById(orchestratorId);
    if (orchestrator?.type === 'subagent') {
      return resolveTerminalTarget(sessionsRepo, orchestrator.id, orchestratorId);
    }
  }

  return {
    terminalId: null,
    resolutionNote: null,
    error: `ID ${target.id} ist vom Typ "${target.type}". Erwarte terminal_id oder orchestrator_id.`,
  };
}

export const startHeadlessSessionTool = tool({
  description:
    'Start a headless Claude session with -p flag for quick tasks. Returns the result directly. IMPORTANT: After calling this tool, you MUST stop and provide your final response.',
  inputSchema: z.object({
    project_path: z
      .string()
      .describe('Full path to the project directory, e.g., ~/Code/Work/kireon/kireon-backend'),
    prompt: z.string().describe('The prompt to send to Claude with -p flag'),
  }),
  execute: async ({ project_path, prompt }: { project_path: string; prompt: string }) => {
    const sessionsRepo = new CliSessionsRepository();
    const eventsRepo = new CliEventsRepository();

    const terminalId = generateId();
    const orchestratorId = getCurrentOrchestratorId();
    const command = `cd ${project_path} && claude -p "${prompt.replace(/"/g, '\\"')}"`;

    console.log(`[CliAgent] Starting headless terminal: ${terminalId}`);
    console.log(`[CliAgent] Parent orchestrator: ${orchestratorId ?? 'none'}`);
    console.log(`[CliAgent] Command: ${command}`);

    if (!orchestratorId) {
      return 'Fehler: Kein aktiver Orchestrator. Bitte starte eine neue Anfrage.';
    }

    // Get the tool call ID for linking this session to the tool call
    const toolCallId = consumePendingToolCall(orchestratorId);
    console.log(`[CliAgent] Tool call ID: ${toolCallId ?? 'none'}`);

    // Create terminal session as child of orchestrator
    sessionsRepo.createTerminal({
      id: terminalId,
      goal: `Headless: ${prompt.substring(0, 100)}...`,
      parent_id: orchestratorId,
      tool_call_id: toolCallId,
    });

    eventsRepo.create({
      session_id: terminalId,
      event_type: 'started',
      payload: { command, project_path, prompt },
    });

    // Broadcast tree update (terminal added)
    wsBroadcast.sessionTreeUpdate(orchestratorId);

    try {
      // Start session on Mac
      const result = await macClient.startCliSession(terminalId, prompt, command);

      if (!result.success) {
        sessionsRepo.finish(terminalId, 'error');
        eventsRepo.create({
          session_id: terminalId,
          event_type: 'error',
          payload: result.message,
        });
        wsBroadcast.sessionTreeUpdate(orchestratorId);
        return `Fehler beim Starten der Session: ${result.message}`;
      }

      // Wait for completion via webhook (no polling!)
      const completion = await waitForSessionCompletion(terminalId, 120_000);

      if (completion) {
        sessionsRepo.finish(
          terminalId,
          completion.status === 'finished' ? 'finished' : 'error'
        );
        eventsRepo.create({
          session_id: terminalId,
          event_type: 'finished',
          payload: { message: completion.message },
        });

        // Cleanup: terminate the tmux session since headless is done
        try {
          await macClient.terminateSession(terminalId);
          console.log(`[CliAgent] Terminated tmux session for ${terminalId}`);
        } catch (cleanupError) {
          console.warn(`[CliAgent] Failed to cleanup tmux session ${terminalId}:`, cleanupError);
        }

        wsBroadcast.sessionTreeUpdate(orchestratorId);
        return `Headless-Session ${terminalId} abgeschlossen.\n${completion.message || 'Aufgabe abgeschlossen, keine Ausgabe.'}`;
      } else {
        sessionsRepo.finish(terminalId, 'error');
        wsBroadcast.sessionTreeUpdate(orchestratorId);
        return 'Die Aufgabe hat zu lange gedauert. Bitte prüfe die Session manuell.';
      }
    } catch (error) {
      sessionsRepo.finish(terminalId, 'error');
      eventsRepo.create({
        session_id: terminalId,
        event_type: 'error',
        payload: String(error),
      });
      wsBroadcast.sessionTreeUpdate(orchestratorId);
      return `Fehler: ${error instanceof Error ? error.message : String(error)}`;
    }
  },
});

export const startInteractiveSessionTool = tool({
  description:
    'Start an interactive Claude session for complex tasks that need iteration. Returns immediately with "Session gestartet". IMPORTANT: After calling this tool, you MUST stop and provide your final response.',
  inputSchema: z.object({
    project_path: z.string().describe('Full path to the project directory'),
    initial_prompt: z.string().describe('Initial prompt/goal to send after session starts'),
  }),
  execute: async ({ project_path, initial_prompt }: { project_path: string; initial_prompt: string }) => {
    const sessionsRepo = new CliSessionsRepository();
    const eventsRepo = new CliEventsRepository();

    const terminalId = generateId();
    const orchestratorId = getCurrentOrchestratorId();

    // Escape the prompt for shell
    const escapedPrompt = initial_prompt
      .replace(/\\/g, '\\\\')
      .replace(/"/g, '\\"')
      .replace(/\$/g, '\\$');

    // Start Claude with the initial prompt - stays interactive after first response
    const command = `cd ${project_path} && claude --dangerously-skip-permissions "${escapedPrompt}"`;

    console.log(`[CliAgent] Starting interactive terminal: ${terminalId}`);
    console.log(`[CliAgent] Parent orchestrator: ${orchestratorId ?? 'none'}`);
    console.log(`[CliAgent] Command: ${command}`);
    console.log(`[CliAgent] Initial prompt: ${initial_prompt}`);

    if (!orchestratorId) {
      return 'Fehler: Kein aktiver Orchestrator. Bitte starte eine neue Anfrage.';
    }

    // Get the tool call ID for linking this session to the tool call
    const toolCallId = consumePendingToolCall(orchestratorId);
    console.log(`[CliAgent] Tool call ID: ${toolCallId ?? 'none'}`);

    // Create terminal session as child of orchestrator
    sessionsRepo.createTerminal({
      id: terminalId,
      goal: initial_prompt.substring(0, 200),
      parent_id: orchestratorId,
      tool_call_id: toolCallId,
    });

    eventsRepo.create({
      session_id: terminalId,
      event_type: 'started',
      payload: { command, project_path, initial_prompt },
    });

    // Broadcast tree update (terminal added)
    wsBroadcast.sessionTreeUpdate(orchestratorId);

    try {
      const result = await macClient.startCliSession(terminalId, initial_prompt, command);

      if (!result.success) {
        sessionsRepo.finish(terminalId, 'error');
        wsBroadcast.sessionTreeUpdate(orchestratorId);
        return `Fehler beim Starten: ${result.message}`;
      }

      sessionsRepo.update(terminalId, { mac_session_id: result.tmuxSession });

      eventsRepo.create({
        session_id: terminalId,
        event_type: 'input',
        payload: { input: initial_prompt },
      });

      wsBroadcast.sessionTreeUpdate(orchestratorId);
      return `Interaktive Session gestartet in ${project_path}. Terminal-ID: ${terminalId}. Claude arbeitet jetzt an der Aufgabe.`;
    } catch (error) {
      sessionsRepo.finish(terminalId, 'error');
      wsBroadcast.sessionTreeUpdate(orchestratorId);
      return `Fehler: ${error instanceof Error ? error.message : String(error)}`;
    }
  },
});

export const sendSessionInputTool = tool({
  description:
    'Send input/feedback to a running interactive terminal. Use terminal_id. ' +
    'If an orchestrator session_id is provided and has exactly one active terminal, it is auto-resolved.',
  inputSchema: z.object({
    terminal_id: z
      .string()
      .optional()
      .describe('Terminal session ID (preferred)'),
    session_id: z
      .string()
      .optional()
      .describe('Deprecated alias. Can be terminal ID or orchestrator ID'),
    input: z.string().describe('The input to send'),
  }),
  execute: async (
    { terminal_id, session_id, input }: { terminal_id?: string; session_id?: string; input: string }
  ) => {
    const eventsRepo = new CliEventsRepository();
    const sessionsRepo = new CliSessionsRepository();
    const requestedId = terminal_id ?? session_id;
    const orchestratorId = getCurrentOrchestratorId();

    if (!requestedId) {
      return 'Fehler: terminal_id fehlt. Nutze list_active_sessions für gültige Terminal-IDs.';
    }

    const resolved = resolveTerminalTarget(sessionsRepo, requestedId, orchestratorId);
    if (!resolved.terminalId) {
      return `Fehler: ${resolved.error}`;
    }

    console.log(`[CliAgent] Sending input to terminal ${resolved.terminalId}: ${input}`);

    try {
      const result = await macClient.sendCliInput(resolved.terminalId, input);

      eventsRepo.create({
        session_id: resolved.terminalId,
        event_type: 'input',
        payload: {
          input,
          requested_id: requestedId,
          resolved_terminal_id: resolved.terminalId,
        },
      });

      const resolutionPrefix = resolved.resolutionNote ? `${resolved.resolutionNote}\n` : '';
      return result.success
        ? [
            resolutionPrefix.trim(),
            '=== INPUT GESENDET ===',
            `Terminal : ${resolved.terminalId}`,
            `Text     : ${clipText(input, 140)}`,
          ]
            .filter(Boolean)
            .join('\n')
        : `Fehler: ${result.message}`;
    } catch (error) {
      return `Fehler: ${error instanceof Error ? error.message : String(error)}`;
    }
  },
});

export const checkSessionStatusTool = tool({
  description:
    'Check the status and recent output of a terminal session. Use terminal_id (or session_id alias).',
  inputSchema: z.object({
    terminal_id: z.string().optional().describe('Terminal session ID (preferred)'),
    session_id: z.string().optional().describe('Deprecated alias for terminal_id/orchestrator_id'),
  }),
  execute: async ({ terminal_id, session_id }: { terminal_id?: string; session_id?: string }) => {
    const sessionsRepo = new CliSessionsRepository();
    const requestedId = terminal_id ?? session_id;
    const orchestratorId = getCurrentOrchestratorId();

    if (!requestedId) {
      return 'Fehler: terminal_id fehlt. Nutze list_active_sessions für gültige Terminal-IDs.';
    }

    const resolved = resolveTerminalTarget(sessionsRepo, requestedId, orchestratorId);
    if (!resolved.terminalId) {
      return `Fehler: ${resolved.error}`;
    }

    console.log(`[CliAgent] Checking status for terminal ${resolved.terminalId}`);

    try {
      const result = await macClient.readCliOutput(resolved.terminalId);
      const details = await macClient.getSessionDetails(resolved.terminalId);
      const runtimeStatus = details?.status || result.status;

      const recentOutput = formatOutputBlock(result.output.slice(-10));
      const waitingHint =
        runtimeStatus === 'waiting_for_input'
          ? '\n[Hint]\nSession wartet auf Input. Nutze send_session_input.'
          : '';

      const resolutionPrefix = resolved.resolutionNote ? `${resolved.resolutionNote}\n` : '';
      return [
        resolutionPrefix.trim(),
        '=== TERMINAL STATUS ===',
        '',
        '[Terminal]',
        `ID     : ${resolved.terminalId}`,
        `Status : ${runtimeStatus}`,
        '',
        '[Snapshot]',
        '--- BEGIN SNAPSHOT ---',
        recentOutput,
        '--- END SNAPSHOT ---',
        waitingHint.trim(),
      ]
        .filter(Boolean)
        .join('\n');
    } catch (error) {
      return `Fehler: ${error instanceof Error ? error.message : String(error)}`;
    }
  },
});

export const listActiveSessionsTool = tool({
  description:
    'List active terminal sessions. By default this returns only terminals for the current orchestrator.',
  inputSchema: z.object({}),
  execute: async () => {
    console.log(`[CliAgent] Listing active sessions`);

    try {
      const sessionsRepo = new CliSessionsRepository();
      const dbSessions = sessionsRepo.getActive();
      const orchestratorId = getCurrentOrchestratorId();
      const activeTerminals = dbSessions.filter(
        (s) =>
          s.type === 'terminal' &&
          isActiveSessionStatus(s.status) &&
          (orchestratorId ? s.parent_id === orchestratorId : true)
      );

      if (activeTerminals.length === 0) {
        return orchestratorId
          ? `Keine aktiven Terminals für Orchestrator ${orchestratorId}.`
          : 'Keine aktiven Terminals.';
      }

      const summaries = activeTerminals.map(
        (terminal) => {
          const parent = terminal.parent_id ?? '-';
          return [
            `- ${terminal.id}`,
            `  status : ${terminal.status}`,
            `  parent : ${parent}`,
            `  goal   : ${clipText(terminal.goal, 100)}`,
          ].join('\n');
        }
      );

      return [
        '=== AKTIVE TERMINALS ===',
        `Scope: ${orchestratorId ? `orchestrator ${orchestratorId}` : 'global'}`,
        `Count: ${activeTerminals.length}`,
        '',
        ...summaries,
        '',
        'Nutze diese IDs als terminal_id in send_session_input/check_session_status/terminate_session.',
      ].join('\n');
    } catch (error) {
      return `Fehler: ${error instanceof Error ? error.message : String(error)}`;
    }
  },
});

export const terminateSessionTool = tool({
  description:
    'Terminate/cancel a running terminal and delete it from the database. Use terminal_id (or session_id alias).',
  inputSchema: z.object({
    terminal_id: z.string().optional().describe('Terminal session ID (preferred)'),
    session_id: z.string().optional().describe('Deprecated alias for terminal_id/orchestrator_id'),
  }),
  execute: async ({ terminal_id, session_id }: { terminal_id?: string; session_id?: string }) => {
    const requestedId = terminal_id ?? session_id;
    const orchestratorId = getCurrentOrchestratorId();
    const sessionsRepo = new CliSessionsRepository();

    if (!requestedId) {
      return 'Fehler: terminal_id fehlt. Nutze list_active_sessions für gültige Terminal-IDs.';
    }

    const resolved = resolveTerminalTarget(sessionsRepo, requestedId, orchestratorId);
    if (!resolved.terminalId) {
      return `Fehler: ${resolved.error}`;
    }

    console.log(`[CliAgent] Terminating terminal ${resolved.terminalId}`);

    try {
      // Get session to find parent for tree update
      const session = sessionsRepo.findById(resolved.terminalId);
      const parentId = session?.parent_id;

      // Terminate on Mac daemon
      await macClient.terminateSession(resolved.terminalId);

      // Delete from database (cascade deletes events too)
      sessionsRepo.delete(resolved.terminalId);
      console.log(`[CliAgent] Deleted terminal ${resolved.terminalId} from database`);

      // Broadcast deletion to connected clients
      wsBroadcast.cliSessionDeleted(resolved.terminalId);

      // Broadcast tree update if we have a parent
      if (parentId) {
        wsBroadcast.sessionTreeUpdate(parentId);
      }

      const resolutionPrefix = resolved.resolutionNote ? `${resolved.resolutionNote}\n` : '';
      return `${resolutionPrefix}Terminal ${resolved.terminalId} beendet und gelöscht.`;
    } catch (error) {
      return `Fehler: ${error instanceof Error ? error.message : String(error)}`;
    }
  },
});

export const terminateAllSessionsTool = tool({
  description: 'Terminate all active sessions and delete them from the database',
  inputSchema: z.object({}),
  execute: async () => {
    console.log(`[CliAgent] Terminating all sessions`);

    const sessionsRepo = new CliSessionsRepository();

    try {
      // Get all active sessions
      const activeSessions = sessionsRepo.getActive();

      if (activeSessions.length === 0) {
        return 'Keine aktiven Sessions zum Beenden.';
      }

      let terminatedCount = 0;
      const errors: string[] = [];

      for (const session of activeSessions) {
        try {
          // Terminate on Mac daemon (skip if no mac_session_id - might be orchestrator)
          if (session.mac_session_id || session.type === 'terminal') {
            await macClient.terminateSession(session.id);
          }

          // Delete from database
          sessionsRepo.delete(session.id);
          terminatedCount++;
          console.log(`[CliAgent] Deleted session ${session.id}`);
        } catch (error) {
          const msg = error instanceof Error ? error.message : String(error);
          errors.push(`${session.id.substring(0, 8)}: ${msg}`);
          console.error(`[CliAgent] Failed to terminate session ${session.id}:`, error);
        }
      }

      // Broadcast that all sessions have been deleted
      wsBroadcast.cliAllSessionsDeleted();

      if (errors.length > 0) {
        return `${terminatedCount} Sessions beendet. Fehler bei: ${errors.join(', ')}`;
      }

      return `${terminatedCount} Sessions beendet und gelöscht.`;
    } catch (error) {
      return `Fehler: ${error instanceof Error ? error.message : String(error)}`;
    }
  },
});

/**
 * Tool registry for the CLI orchestration agent.
 */
export const cliAgentTools = {
  start_headless_session: startHeadlessSessionTool,
  start_interactive_session: startInteractiveSessionTool,
  send_session_input: sendSessionInputTool,
  check_session_status: checkSessionStatusTool,
  list_active_sessions: listActiveSessionsTool,
  terminate_session: terminateSessionTool,
  terminate_all_sessions: terminateAllSessionsTool,
};

type CliAgentToolName =
  | 'start_headless_session'
  | 'start_interactive_session'
  | 'send_session_input'
  | 'check_session_status'
  | 'list_active_sessions'
  | 'terminate_session'
  | 'terminate_all_sessions';

const CLI_AGENT_TOOL_DEFINITION_BY_NAME: Record = {
  start_headless_session: {
    name: 'start_headless_session',
    description: startHeadlessSessionTool.description ?? '',
    parameters: {
      type: 'object',
      properties: {
