export const cliAgentToolDefinitions: ToolDefinition[] = Object.values(
  CLI_AGENT_TOOL_DEFINITION_BY_NAME
);

async function invokeAiTool(
  toolRegistration: any,
  input: Record
): Promise {
  if (!toolRegistration.execute) {
    return 'Tool execute handler is not available.';
  }

  const rawResult = await toolRegistration.execute(input, {
    toolCallId: `manual_${Date.now().toString(36)}`,
    messages: [],
  });

  if (typeof rawResult === 'string') {
    return rawResult;
  }

  if (
    typeof rawResult === 'object' &&
    rawResult !== null &&
    Symbol.asyncIterator in rawResult
  ) {
    let text = '';
    for await (const chunk of rawResult as AsyncIterable) {
      if (typeof chunk === 'string') {
        text += chunk;
      } else {
        text += JSON.stringify(chunk);
      }
    }
    return text;
  }

  if (rawResult === undefined || rawResult === null) {
    return '';
  }

  return typeof rawResult === 'string'
    ? rawResult
    : JSON.stringify(rawResult);
}

const CLI_AGENT_TOOL_EXECUTOR_BY_NAME: Record<
  CliAgentToolName,
  (input: Record) => Promise
> = {
  start_headless_session: (input) =>
    invokeAiTool(startHeadlessSessionTool, {
      project_path: String(input.project_path ?? ''),
      prompt: String(input.prompt ?? ''),
    }),
  start_interactive_session: (input) =>
    invokeAiTool(startInteractiveSessionTool, {
      project_path: String(input.project_path ?? ''),
      initial_prompt: String(input.initial_prompt ?? ''),
    }),
  send_session_input: (input) =>
    invokeAiTool(sendSessionInputTool, {
      terminal_id:
        typeof input.terminal_id === 'string' ? input.terminal_id : undefined,
      session_id:
        typeof input.session_id === 'string' ? input.session_id : undefined,
      input: String(input.input ?? ''),
    }),
  check_session_status: (input) =>
    invokeAiTool(checkSessionStatusTool, {
      terminal_id:
        typeof input.terminal_id === 'string' ? input.terminal_id : undefined,
      session_id:
        typeof input.session_id === 'string' ? input.session_id : undefined,
    }),
  list_active_sessions: () => invokeAiTool(listActiveSessionsTool, {}),
  terminate_session: (input) =>
    invokeAiTool(terminateSessionTool, {
      terminal_id:
        typeof input.terminal_id === 'string' ? input.terminal_id : undefined,
      session_id:
        typeof input.session_id === 'string' ? input.session_id : undefined,
    }),
  terminate_all_sessions: () => invokeAiTool(terminateAllSessionsTool, {}),
};

export async function executeCliAgentTool(
  name: string,
  input: Record,
  context: ToolCallContext
): Promise {
  const executor = CLI_AGENT_TOOL_EXECUTOR_BY_NAME[name as CliAgentToolName];
  if (!executor) {
    return {
      invocationId: context.invocationId,
      result: `Unknown CLI tool: ${name}`,
      isError: true,
    };
  }

  const result = await executor(input);
  return {
    invocationId: context.invocationId,
    result,
    isError: false,
  };
}



/**
 * Developer Session Tool - Delegates coding tasks to the CLI orchestration agent.
 *
 * This tool is called by the realtime voice agent when the user requests:
 * - Code reviews
 * - Feature implementation
 * - Bug fixes
 * - Any coding-related tasks
 *
 * It passes the conversation history and delegates to a GPT-5 text-based agent
 * that manages Mac CLI sessions.
 */

import { tool, RealtimeContextData } from '@openai/agents/realtime';
import { z } from 'zod';
import { handleDeveloperRequest, isMacDaemonAvailable } from '../subagents/cli/index.js';
import { handleDirectInput } from '../subagents/direct-input.js';
import { getProcessManager } from '../processes/manager.js';
import { generateSessionName, resolveSessionName } from '../utils/session-names.js';
import { CliSessionsRepository, HandoffsRepository, CliEventsRepository } from '../db/index.js';
import type { Session } from '../db/repositories/cli-sessions.js';
import type { VoiceAgent } from '../agent/voice-agent.js';
import * as macClient from './mac-client.js';

/**
 * Resolve a named coding session (subagent) by exact or fuzzy name.
 * Only named subagent sessions are considered.
 */
function resolveNamedSession(sessionName: string, includeFinished = false): Session | null {
  const repo = new CliSessionsRepository();
  const query = sessionName.trim();
  if (!query) return null;

  const subagents = repo.list({ type: 'subagent' });
  const candidates = subagents.filter((s) => {
    if (!s.name) return false;
    if (includeFinished) return true;
    return ['pending', 'running', 'waiting_for_input'].includes(s.status);
  });

  const exact = candidates.find((s) => s.name === query);
  if (exact) return exact;

  const resolved = resolveSessionName(
    query,
    candidates.map((s) => ({ name: s.name!, id: s.id }))
  );
  if (!resolved) return null;

  return candidates.find((s) => s.id === resolved.id) ?? null;
}

function isSessionStartIntent(request: string): boolean {
  const normalized = request.toLowerCase();
  const startWords = ['start', 'starte', 'starte bitte', 'öffne', 'open', 'create', 'erstelle', 'launch', 'begin'];
  const sessionWords = ['session', 'coding-session', 'cli', 'interaktiv', 'interactive', 'terminal', 'claude'];
  return startWords.some((word) => normalized.includes(word)) &&
    sessionWords.some((word) => normalized.includes(word));
}

function isExplicitNewSessionIntent(request: string): boolean {
  const normalized = request.toLowerCase();
  return normalized.includes('neue session') ||
    normalized.includes('new session') ||
    normalized.includes('another session') ||
    normalized.includes('weitere session') ||
    normalized.includes('zweite session');
}

function isActiveSessionStatus(status: Session['status']): boolean {
  return status === 'pending' || status === 'running' || status === 'waiting_for_input';
}

function getTerminalChildren(repo: CliSessionsRepository, subagentId: string): Session[] {
  return repo.getChildren(subagentId).filter((child) => child.type === 'terminal');
}

function getActiveTerminalChildren(repo: CliSessionsRepository, subagentId: string): Session[] {
  return getTerminalChildren(repo, subagentId).filter((child) => isActiveSessionStatus(child.status));
}

function getPrimaryTerminal(repo: CliSessionsRepository, subagentId: string): Session | null {
  const activeTerminals = getActiveTerminalChildren(repo, subagentId);
  if (activeTerminals.length > 0) {
    // Oldest active terminal is treated as the primary thread for direct feedback/checks.
    return activeTerminals[0] ?? null;
  }

  const allTerminals = getTerminalChildren(repo, subagentId);
  if (allTerminals.length === 0) return null;

  return allTerminals.sort((a, b) => b.created_at.localeCompare(a.created_at))[0] ?? null;
}

function clipText(value: string, maxLength: number): string {
  if (value.length <= maxLength) return value;
  return `${value.slice(0, maxLength - 3)}...`;
}

function normalizeOutputLine(line: string): string {
  const trimmed = line.trimEnd();

  // Collapse very long visual separators from terminal UIs.
  if (/^[\-\u2500\s]+$/.test(trimmed) && trimmed.length > 30) {
    return '----------------------------------------';
  }

  return clipText(trimmed, 160);
}

function formatOutputBlock(lines: string[]): string {
  if (lines.length === 0) {
    return '| (keine Ausgabe - interaktive Session wartet eventuell auf Eingabe)';
  }

  return lines.map((line) => `| ${normalizeOutputLine(line)}`).join('\n');
}

function parseEventPayload(payload: string | null): string {
  if (!payload) return '(keine Nachricht)';

  try {
    const parsed = JSON.parse(payload) as {
      message?: unknown;
      status?: unknown;
      input?: unknown;
      reason?: unknown;
    };

    if (typeof parsed.message === 'string' && parsed.message.length > 0) {
      return parsed.message;
    }
    if (typeof parsed.status === 'string' && parsed.status.length > 0) {
      return `Status: ${parsed.status}`;
    }
    if (typeof parsed.input === 'string' && parsed.input.length > 0) {
      return `Input: ${parsed.input}`;
    }
    if (typeof parsed.reason === 'string' && parsed.reason.length > 0) {
      return `Grund: ${parsed.reason}`;
    }
  } catch {
    // Payload might already be plain text
  }

  return payload;
}

async function getTerminalRuntimeState(
  terminal: Session
): Promise<{ runtimeStatus: string; recentOutput: string[] }> {
  let runtimeStatus: string = terminal.status;
  let recentOutput: string[] = [];

  try {
    const details = await macClient.getSessionDetails(terminal.id);
    if (details?.status) {
      runtimeStatus = details.status;
    }
  } catch (error) {
    console.warn(`[DeveloperSession] Failed to load terminal details ${terminal.id}:`, error);
  }

  try {
    const output = await macClient.readCliOutput(terminal.id);
    if (output.status) {
      runtimeStatus = output.status;
    }
    recentOutput = output.output.slice(-8);
  } catch (error) {
    console.warn(`[DeveloperSession] Failed to read terminal output ${terminal.id}:`, error);
  }

  return { runtimeStatus, recentOutput };
}

async function buildFeedbackRoutingMessage(
  session: Session,
  feedback: string,
  sessionsRepo: CliSessionsRepository,
  eventsRepo: CliEventsRepository
): Promise {
  const allTerminals = getTerminalChildren(sessionsRepo, session.id);
  const activeTerminals = getActiveTerminalChildren(sessionsRepo, session.id);
  const primaryTerminal = getPrimaryTerminal(sessionsRepo, session.id);

  let primaryStatus = '(kein Terminal)';
  let primaryOutput = '(keine Ausgabe erfasst)';
  let primaryEvent = '(kein Event)';

  if (primaryTerminal) {
    const { runtimeStatus, recentOutput } = await getTerminalRuntimeState(primaryTerminal);
    primaryStatus = runtimeStatus;
    primaryOutput = formatOutputBlock(recentOutput);

    const recentEvents = eventsRepo.getBySession(primaryTerminal.id, 1);
    const lastEvent = recentEvents[0];
    if (lastEvent) {
      primaryEvent = `[${lastEvent.event_type}] ${parseEventPayload(lastEvent.payload)}`;
    }
  }

  const activeTerminalLines =
    activeTerminals.length > 0
      ? activeTerminals
          .map((terminal) => `- ${terminal.id} [${terminal.status}]`)
      : ['- keine aktiven Terminals'];

  return [
    '=== ROUTED VOICE FEEDBACK ===',
    '',
    '[Session]',
    `Name             : ${session.name ?? '(unbenannt)'}`,
    `ID               : ${session.id}`,
    `Status           : ${session.status}`,
    '',
    '[Terminals]',
    `Active           : ${activeTerminals.length}/${allTerminals.length}`,
    `Primary Terminal : ${primaryTerminal?.id ?? 'keins'}`,
    `Primary Status   : ${primaryStatus}`,
    'Terminal List    :',
    ...activeTerminalLines.map((line) => `  ${line}`),
    '',
    '[Last Event]',
    primaryEvent,
    '',
    '[Primary Terminal Snapshot]',
    '--- BEGIN SNAPSHOT ---',
    primaryOutput,
    '--- END SNAPSHOT ---',
    '',
    '[User Feedback]',
    feedback.trim(),
    '',
    '[Orchestration Rules]',
    '1) Reuse existing session/terminals.',
    '2) Do NOT start a new session for the same project unless user explicitly asks.',
    '3) If terminal is waiting_for_input, forward feedback via send_session_input with terminal_id.',
    '4) If no usable terminal exists, explain why before starting a new session.',
  ].join('\n');
}

const developerSessionParameters = z.object({
  request: z
    .string()
    .describe(
      'The coding task or request from the user. Include project name if mentioned.'
    ),
});

/**
 * Factory function to create the developer_session tool with injected context.
 * Uses the VoiceAgent to build a HandoffPacket with full conversation context,
 * solving the "telephone effect" where subagents lose context.
 *
 * The tool is NON-BLOCKING: it spawns the work via ProcessManager and returns
 * immediately with the session name so the voice agent can continue the conversation.
 */
export function createDeveloperSessionTool(sessionId: string, voiceAgent?: VoiceAgent) {
  return tool({
    name: 'developer_session',
    description: `Start or manage a coding session on the Mac. Use this when the user wants to:
- Review code in a project
- Implement a new feature
- Fix a bug
- Refactor code
- Get information about a project
- Start Claude Code to work on something

Examples:
- "Review the code in kireon backend"
- "Implement dark mode in the frontend"
- "Fix the authentication bug in weka"
- "Start a session for the BEGA project"`,
    parameters: developerSessionParameters,
    async execute({ request }) {
      console.log('[DeveloperSession] Tool called with request:', request);

      // Check if Mac daemon is available
      const macAvailable = await isMacDaemonAvailable();
      if (!macAvailable) {
        console.log('[DeveloperSession] Mac daemon not available');
        return 'Der Mac ist gerade nicht erreichbar. Bitte stelle sicher, dass der Mac Daemon läuft.';
      }

      // Use the injected sessionId directly (no need to extract from history)
      console.log('[DeveloperSession] Using injected voice session ID:', sessionId);

      // Build HandoffPacket with full voice context (anti-telephone)
      // Falls back to minimal packet if voiceAgent not available
      const handoff = voiceAgent
        ? voiceAgent.createHandoffPacket(request)
        : {
            id: `hp-${Date.now()}`,
            timestamp: Date.now(),
            request,
            voiceContext: [],
            activeProcesses: [],
            source: { sessionId, profile: 'unknown' },
          };

      console.log(`[DeveloperSession] HandoffPacket: ${handoff.voiceContext.length} context entries, ${handoff.activeProcesses.length} active processes`);

      // Persist handoff for debugging/replay
      const handoffsRepo = new HandoffsRepository();
      handoffsRepo.save(handoff);

      const sessionsRepo = new CliSessionsRepository();
      const processManager = getProcessManager();

      // Check if there's already a running CLI subagent for this voice session
      const existingSubagent = sessionsRepo.findRunningSubagent('cli', sessionId);

      if (existingSubagent?.name) {
        const activeTerminals = getActiveTerminalChildren(sessionsRepo, existingSubagent.id);

        // Guard against accidental session-start loops when one session is already running.
        if (
          activeTerminals.length > 0 &&
          isSessionStartIntent(request) &&
          !isExplicitNewSessionIntent(request)
        ) {
          console.log(`[DeveloperSession] Session "${existingSubagent.name}" already active, skipping duplicate start intent`);
          return `Session "${existingSubagent.name}" läuft bereits. Sag mir stattdessen die nächste Aufgabe für diese Session.`;
        }

        // Reuse existing session — announce its name, not a new one
        processManager.spawn({
          name: existingSubagent.name,
          sessionId: `dev-${Date.now()}`,
          type: 'headless',
          notifyVoiceOnCompletion: false,
          execute: async () => {
            return await handleDeveloperRequest(handoff, sessionId);
          },
        });
        console.log(`[DeveloperSession] Reusing existing subagent "${existingSubagent.name}"`);
        return `Sende an "${existingSubagent.name}": ${request.substring(0, 80)}`;
      }

      // No existing session — generate new name
      const activeNames = sessionsRepo.getActiveSessionNames();
      const name = generateSessionName(activeNames);

      // Spawn as background process via ProcessManager - returns immediately
      processManager.spawn({
        name,
        sessionId: `dev-${Date.now()}`, // Unique process ID
        type: 'headless',
        notifyVoiceOnCompletion: false,
        execute: async () => {
          return await handleDeveloperRequest(handoff, sessionId, name);
        },
      });

      console.log(`[DeveloperSession] Spawned non-blocking process "${name}"`);
      return `Starte "${name}" für: ${request.substring(0, 100)}`;
    },
  });
}

// Additional tools for session management from voice

const checkSessionParameters = z.object({
  session_name: z
    .string()
    .optional()
    .describe('Name der Session (z.B. "terra-comet"). Ohne Angabe werden alle aktiven Sessions gezeigt.'),
});

export const checkSessionTool = tool<
  typeof checkSessionParameters,
  RealtimeContextData
>({
  name: 'check_coding_session',
  description:
    'Check the status of a coding session or list all active sessions. ' +
    'Use when the user asks "how is the session going" or "what sessions are running". ' +
    'Use session names, not IDs.',
  parameters: checkSessionParameters,
  async execute({ session_name }) {
    console.log('[CheckSession] Checking session:', session_name ?? 'all');

    const macAvailable = await isMacDaemonAvailable();
    if (!macAvailable) {
      return 'Der Mac ist gerade nicht erreichbar.';
    }

    const sessionsRepo = new CliSessionsRepository();
    const eventsRepo = new CliEventsRepository();

    if (session_name) {
      // Resolve by exact or fuzzy session name
      const session = resolveNamedSession(session_name);
      if (!session) {
        return `Session "${session_name}" nicht gefunden.`;
      }

      const terminal = getPrimaryTerminal(sessionsRepo, session.id);
      if (!terminal) {
        const displayName = session.name!;
        return `Session "${displayName}": ${session.status}\nZiel: ${session.goal}\n\nEs wurde noch kein Terminal gestartet.`;
      }

      const allTerminals = getTerminalChildren(sessionsRepo, session.id);
      const activeTerminals = getActiveTerminalChildren(sessionsRepo, session.id);
      const { runtimeStatus, recentOutput } = await getTerminalRuntimeState(terminal);
      const recentLines = formatOutputBlock(recentOutput);

      // Get last webhook event for this session
      const recentEvents = eventsRepo.getBySession(terminal.id, 1);
      const lastEvent = recentEvents[0];
      let lastWebhookInfo = '';
      if (lastEvent) {
        const eventMessage = parseEventPayload(lastEvent.payload);
        lastWebhookInfo = `\n[Last Event]\n[${lastEvent.event_type}] ${eventMessage}`;
      }

      const waitingHint =
        runtimeStatus === 'waiting_for_input' || terminal.status === 'waiting_for_input'
          ? '\n[Hint]\nClaude wartet auf Eingabe. Nutze send_session_feedback, um die Session weiterzuführen.'
          : '';

      const displayName = session.name!;
      return [
        '=== SESSION STATUS ===',
        '',
        '[Session]',
        `Name             : ${displayName}`,
        `Status           : ${session.status}`,
        `Goal             : ${clipText(session.goal, 140)}`,
        '',
        '[Terminals]',
        `Active           : ${activeTerminals.length}/${allTerminals.length}`,
        `Primary Terminal : ${terminal.id}`,
        `Primary Status   : ${runtimeStatus}`,
        '',
        '[Primary Terminal Snapshot]',
        '--- BEGIN SNAPSHOT ---',
        recentLines,
        '--- END SNAPSHOT ---',
        `${lastWebhookInfo}${waitingHint}`.trim(),
      ]
        .filter(Boolean)
        .join('\n');
    } else {
      // List all active named coding sessions
      const sessions = sessionsRepo
        .getActive()
        .filter((s) => s.type === 'subagent' && Boolean(s.name));

      if (sessions.length === 0) {
        return 'Keine aktiven Coding-Sessions.';
      }

      const summaries = sessions.map((s) => {
        const primaryTerminal = getPrimaryTerminal(sessionsRepo, s.id);
        const eventSessionId = primaryTerminal?.id ?? s.id;
        const recentEvents = eventsRepo.getBySession(eventSessionId, 1);
        const lastEvent = recentEvents[0];
        let lastMessage = '';
        if (lastEvent?.payload) {
          try {
            const payload = JSON.parse(lastEvent.payload);
            if (payload.message) {
              lastMessage = ` - ${payload.message.substring(0, 40)}`;
            }
          } catch {
            // Ignore parse errors
          }
        }
        const displayName = s.name!;
        const terminalStatus = primaryTerminal
          ? `, terminal=${primaryTerminal.status}`
          : ', terminal=none';
        const waitingHint =
          primaryTerminal?.status === 'waiting_for_input' ? ' (wartet auf Eingabe)' : '';
        const primaryId = primaryTerminal?.id ?? '-';
        return `- ${displayName} | status=${s.status}${terminalStatus}${waitingHint} | primary=${primaryId} | goal="${clipText(s.goal ?? 'kein Ziel', 70)}"${lastMessage}`;
      });

      return [
        '=== AKTIVE CODING-SESSIONS ===',
        `Anzahl: ${sessions.length}`,
        '',
        ...summaries,
        '',
        'Tipp: Nutze check_coding_session mit session_name für Details.',
      ].join('\n');
    }
  },
});

const sendFeedbackParameters = z.object({
  session_name: z.string().describe('Name der Session (z.B. "terra-comet")'),
  feedback: z.string().describe('The feedback or input to send to the session'),
});

export const sendFeedbackTool = tool<
  typeof sendFeedbackParameters,
  RealtimeContextData
>({
  name: 'send_session_feedback',
  description:
    'Send feedback or input to an active coding session. ' +
    'Use when the user wants to guide or correct what Claude is doing in a session. ' +
    'Use session names, not IDs.',
  parameters: sendFeedbackParameters,
  async execute({ session_name, feedback }) {
    console.log(`[SendFeedback] Sending to ${session_name}: ${feedback}`);

    const macAvailable = await isMacDaemonAvailable();
    if (!macAvailable) {
      return 'Der Mac ist gerade nicht erreichbar.';
    }

    // Resolve by exact or fuzzy session name
    const session = resolveNamedSession(session_name);
    if (!session) {
      return `Session "${session_name}" nicht gefunden.`;
    }

    const sessionsRepo = new CliSessionsRepository();
    const eventsRepo = new CliEventsRepository();
    const processManager = getProcessManager();

    try {
      const routedFeedback = await buildFeedbackRoutingMessage(
        session,
        feedback,
        sessionsRepo,
        eventsRepo
      );

      // Option 2 routing: always feed follow-up input through the CLI orchestrator.
      processManager.spawn({
        name: session.name ?? `cli-${session.id.slice(0, 8)}`,
        sessionId: `feedback-${Date.now()}`,
        type: 'headless',
        notifyVoiceOnCompletion: false,
        execute: async () => {
          await handleDirectInput(session.id, routedFeedback);
          return 'Feedback verarbeitet.';
        },
      });

      eventsRepo.create({
        session_id: session.id,
        event_type: 'input',
        payload: {
          input: feedback,
          routed_via: 'orchestrator',
        },
      });

      const displayName = session.name!;
      return `Feedback an "${displayName}" wurde an den Orchestrator übergeben.`;
    } catch (error) {
      return `Fehler beim Senden: ${error instanceof Error ? error.message : String(error)}`;
    }
  },
});

const stopSessionParameters = z.object({
  session_name: z.string().describe('Name der Session (z.B. "terra-comet")'),
});

export const stopSessionTool = tool<
  typeof stopSessionParameters,
  RealtimeContextData
>({
  name: 'stop_coding_session',
  description:
    'Stop/terminate a coding session. Use when the user wants to cancel or end a session. ' +
    'Use session names, not IDs.',
  parameters: stopSessionParameters,
  async execute({ session_name }) {
    console.log(`[StopSession] Stopping session ${session_name}`);

    const macAvailable = await isMacDaemonAvailable();
    if (!macAvailable) {
      return 'Der Mac ist gerade nicht erreichbar.';
    }

    // Resolve by exact or fuzzy session name
    const session = resolveNamedSession(session_name);
    if (!session) {
      return `Session "${session_name}" nicht gefunden.`;
    }

    const macClient = await import('./mac-client.js');
    const { CliEventsRepository } = await import('../db/index.js');

    const sessionsRepo = new CliSessionsRepository();
    const eventsRepo = new CliEventsRepository();

    try {
      const activeTerminals = getActiveTerminalChildren(sessionsRepo, session.id);
      const terminationErrors: string[] = [];
      let terminatedCount = 0;

      for (const terminal of activeTerminals) {
        try {
          const result = await macClient.terminateSession(terminal.id);
          if (!result.success) {
            terminationErrors.push(`${terminal.id.slice(0, 8)}: ${result.message}`);
            continue;
          }

          sessionsRepo.updateStatus(terminal.id, 'cancelled');
          eventsRepo.create({
            session_id: terminal.id,
            event_type: 'finished',
            payload: { reason: 'user_cancelled' },
          });
          terminatedCount += 1;
        } catch (error) {
          const message = error instanceof Error ? error.message : String(error);
          terminationErrors.push(`${terminal.id.slice(0, 8)}: ${message}`);
        }
      }

      if (terminationErrors.length === 0 || terminatedCount > 0) {
        sessionsRepo.updateStatus(session.id, 'cancelled');
      }

      const displayName = session.name!;
      if (terminationErrors.length === 0) {
        if (activeTerminals.length === 0) {
          return `Session "${displayName}" beendet (kein aktives Terminal mehr).`;
        }
        return `Session "${displayName}" beendet (${terminatedCount} Terminal${terminatedCount === 1 ? '' : 'e'} gestoppt).`;
      }
      return `Session "${displayName}" teilweise beendet (${terminatedCount}/${activeTerminals.length} Terminals gestoppt). Fehler: ${terminationErrors.join('; ')}`;
    } catch (error) {
      return `Fehler: ${error instanceof Error ? error.message : String(error)}`;
    }
  },
});

const viewPastSessionsParameters = z.object({
  limit: z
    .number()
    .optional()
    .describe('Number of sessions to show (default: 5)'),
  session_name: z
    .string()
    .optional()
    .describe('Name einer bestimmten Session für Detailansicht (z.B. "terra-comet")'),
});

export const viewPastSessionsTool = tool<
  typeof viewPastSessionsParameters,
  RealtimeContextData
>({
  name: 'view_past_sessions',
  description:
    'View completed/past coding sessions and their results. ' +
    'Use when the user asks about previous sessions, what was done, or session history. ' +
    'Can show a list of recent sessions or details for a specific session name.',
  parameters: viewPastSessionsParameters,
  async execute({ limit = 5, session_name }) {
    console.log('[ViewPastSessions] Viewing past sessions, limit:', limit, 'session_name:', session_name);

    const { CliEventsRepository } = await import('../db/index.js');
    const sessionsRepo = new CliSessionsRepository();
    const eventsRepo = new CliEventsRepository();

    if (session_name) {
      // Resolve by exact or fuzzy session name (include finished)
      const session = resolveNamedSession(session_name, true);
      if (!session) {
        return `Session "${session_name}" nicht gefunden.`;
      }

      // Get all events for this session
      const events = eventsRepo.getBySession(session.id);

      // Find the result message (from finished or status_change events)
      let resultMessage = '';
      for (const event of events.reverse()) {
        if (event.payload) {
          try {
            const payload = JSON.parse(event.payload);
            if (payload.message) {
              resultMessage = payload.message;
              break;
            }
          } catch {
            // Skip parse errors
          }
        }
      }

      const createdAt = new Date(session.created_at).toLocaleString('de-DE');
      const displayName = session.name!;

      return `Session "${displayName}"
Status: ${session.status}
Erstellt: ${createdAt}
Ziel: ${session.goal}

Ergebnis:
${resultMessage || '(kein Ergebnis gespeichert)'}`;
    } else {
      // List recent sessions
      const allSessions = sessionsRepo
        .list({ type: 'subagent' })
        .filter((s) => Boolean(s.name));
      const recentSessions = allSessions.slice(0, limit);

      if (recentSessions.length === 0) {
        return 'Keine vergangenen Sessions gefunden.';
      }

      const summaries = recentSessions.map((s) => {
        // Get last event with a message
        const events = eventsRepo.getBySession(s.id, 1);
        const lastEvent = events[0];
        let shortResult = '';
        if (lastEvent?.payload) {
          try {
            const payload = JSON.parse(lastEvent.payload);
            if (payload.message) {
              shortResult = payload.message.substring(0, 60).replace(/\n/g, ' ');
              if (payload.message.length > 60) shortResult += '...';
            }
          } catch {
            // Skip
          }
        }

        const createdAt = new Date(s.created_at).toLocaleTimeString('de-DE', {
          hour: '2-digit',
          minute: '2-digit'
        });

        const displayName = s.name!;
        return `${displayName} [${createdAt}] (${s.status}): ${s.goal?.substring(0, 40) || 'kein Ziel'}${shortResult ? `\n  → ${shortResult}` : ''}`;
      });

      return `Letzte ${recentSessions.length} Sessions:\n\n${summaries.join('\n\n')}`;
    }
  },
});



import { tool, RealtimeContextData } from '@openai/agents/realtime';
import { z } from 'zod';
import { wsBroadcast } from '../api/websocket.js';
import { CliEventsRepository, CliSessionsRepository, type Session } from '../db/index.js';
import { generateSessionName, resolveSessionName } from '../utils/session-names.js';
import * as macClient from './mac-client.js';

export type DirectTerminalToolName =
  | 'open_claude'
  | 'open_codex'
  | 'dictate_to_session'
  | 'read_session'
  | 'close_session'
  | 'arrange_window';

type CliKind = 'claude' | 'codex';

const ACTIVE_STATUSES = new Set([
  'pending',
  'running',
  'waiting_for_input',
]);

function shellQuote(value: string): string {
  return `'${value.replace(/'/g, `'\\''`)}'`;
}

function isActiveSession(session: Session): boolean {
  return ACTIVE_STATUSES.has(session.status);
}

function clip(value: string, maxLength: number): string {
  if (value.length <= maxLength) return value;
  return `${value.slice(0, maxLength - 3)}...`;
}

function normalizeSessionQuery(value: string): string {
  return value.trim().toLowerCase().replace(/\s+/g, '-');
}

function gatherVoiceScopedTerminalSessions(
  sessionsRepo: CliSessionsRepository,
  voiceSessionId: string,
  includeFinished: boolean
): Session[] {
  const allSessions = sessionsRepo.list();
  const byId = new Map(allSessions.map((session) => [session.id, session]));

  const belongsToVoiceTree = (session: Session): boolean => {
    let current: Session | undefined = session;
    const seen = new Set();

    while (current?.parent_id) {
      if (current.parent_id === voiceSessionId) {
        return true;
      }

      if (seen.has(current.parent_id)) {
        return false;
      }
      seen.add(current.parent_id);
      current = byId.get(current.parent_id);
    }

    return false;
  };

  return allSessions.filter((session) => {
    if (session.type !== 'terminal') return false;
    if (!belongsToVoiceTree(session)) return false;
    if (includeFinished) return true;
    return isActiveSession(session);
  });
}

function resolveTerminalByNameOrRecency(
  sessionsRepo: CliSessionsRepository,
  voiceSessionId: string,
  sessionName?: string,
  includeFinished = false
): { session: Session | null; error?: string } {
  const candidates = gatherVoiceScopedTerminalSessions(
    sessionsRepo,
    voiceSessionId,
    includeFinished
  );

  if (candidates.length === 0) {
    return {
      session: null,
      error:
        "No active session found. Say 'open Claude in ' first.",
    };
  }

  if (sessionName && sessionName.trim().length > 0) {
    const query = normalizeSessionQuery(sessionName);
    const namedCandidates = candidates.filter((candidate) => candidate.name);

    const exact = namedCandidates.find((candidate) => candidate.name === query);
    if (exact) {
      return { session: exact };
    }

    const fuzzy = resolveSessionName(
      query,
      namedCandidates.map((candidate) => ({
        id: candidate.id,
        name: candidate.name!,
      }))
    );

    if (!fuzzy) {
      return {
        session: null,
        error: `Session "${sessionName}" was not found in this voice conversation.`,
      };
    }

    const resolved = namedCandidates.find((candidate) => candidate.id === fuzzy.id);
    if (!resolved) {
      return {
        session: null,
        error: `Session "${sessionName}" was not found in this voice conversation.`,
      };
    }
    return { session: resolved };
  }

  // list() is sorted DESC by created_at, so first active terminal is the most recent.
  const mostRecent = candidates.find((candidate) => isActiveSession(candidate));
  if (!mostRecent) {
    return {
      session: null,
      error:
        "No active session found. Say 'open Claude in ' first.",
    };
  }

  return { session: mostRecent };
}

function getDisplayName(session: Session): string {
  if (session.name) return session.name;
  return session.id.slice(0, 8);
}

function buildCliCommand(
  cli: CliKind,
  projectPath: string,
  prompt?: string | null
): string {
  const cdPrefix = `cd ${shellQuote(projectPath)}`;
  const normalizedPrompt = prompt?.trim();

  if (cli === 'claude') {
    if (normalizedPrompt) {
      return `${cdPrefix} && claude -p ${shellQuote(normalizedPrompt)}`;
    }
    return `${cdPrefix} && claude --dangerously-skip-permissions`;
  }

  if (normalizedPrompt) {
    return `${cdPrefix} && codex ${shellQuote(normalizedPrompt)}`;
  }
  return `${cdPrefix} && codex`;
}

function generateTerminalName(sessionsRepo: CliSessionsRepository): string {
  const allKnownNames = new Set(
    sessionsRepo
      .list()
      .map((session) => session.name)
      .filter((name): name is string => Boolean(name))
  );

  return generateSessionName(allKnownNames);
}

function normalizeRuntimeStatus(status: string): Session['status'] | null {
  if (status === 'running') return 'running';
  if (status === 'waiting_for_input') return 'waiting_for_input';
  if (status === 'finished') return 'finished';
  if (status === 'error') return 'error';
  return null;
}

interface OpenSessionInput {
  project_path: string;
  prompt?: string | null;
  open_gui?: boolean | null;
}

function createOpenCliTool(
  voiceSessionId: string,
  cli: CliKind
) {
  const toolName = cli === 'claude' ? 'open_claude' : 'open_codex';
  const cliLabel = cli === 'claude' ? 'Claude' : 'Codex';
  const openToolSchema = z.object({
    project_path: z.string().describe('Project directory path on the Mac'),
    prompt: z
      .string()
      .nullable()
      .optional()
      .describe('Optional first prompt to pass directly to the CLI'),
    open_gui: z
      .boolean()
      .nullable()
      .optional()
      .describe('Whether to open a GUI terminal window (default: true)'),
  });

  return tool({
    name: toolName,
    description:
      `Open a direct ${cliLabel} terminal session in a project directory. ` +
      `Creates a named tmux session and can open a GUI terminal window.`,
    parameters: openToolSchema,
    async execute({ project_path, prompt, open_gui }: OpenSessionInput) {
      const projectPath = project_path.trim();
      if (!projectPath) {
        return 'Project path is required.';
      }

      const health = await macClient.checkHealth();
      if (!health) {
        return 'Der Mac-Daemon ist nicht erreichbar.';
      }

      const sessionsRepo = new CliSessionsRepository();
      const eventsRepo = new CliEventsRepository();
      const sessionName = generateTerminalName(sessionsRepo);
      const command = buildCliCommand(cli, projectPath, prompt);
      const shouldOpenGui = open_gui !== false;

      const terminal = sessionsRepo.createTerminal({
        goal: `${cliLabel} in ${projectPath}`,
        parent_id: voiceSessionId,
        name: sessionName,
      });
      wsBroadcast.sessionTreeUpdate(voiceSessionId);

      eventsRepo.create({
        session_id: terminal.id,
        event_type: 'created',
        payload: {
          source: toolName,
          cli,
          name: sessionName,
          project_path: projectPath,
        },
      });

      try {
        const startResult = await macClient.startCliSession(
          terminal.id,
          `${cliLabel} in ${projectPath}`,
          command
        );

        if (!startResult.success) {
          sessionsRepo.finish(terminal.id, 'error');
          eventsRepo.create({
            session_id: terminal.id,
            event_type: 'error',
            payload: {
              message: startResult.message,
            },
          });
          wsBroadcast.sessionTreeUpdate(voiceSessionId);
          return `Failed to start ${cliLabel} session "${sessionName}": ${startResult.message}`;
        }

        sessionsRepo.update(terminal.id, {
          status: 'running',
          mac_session_id: startResult.tmuxSession,
        });

        eventsRepo.create({
          session_id: terminal.id,
          event_type: 'started',
          payload: {
            command,
            prompt: prompt?.trim() || null,
            open_gui: shouldOpenGui,
          },
        });

        if (shouldOpenGui) {
          const guiResult = await macClient.openGuiTerminal(terminal.id);
          if (!guiResult.success) {
            eventsRepo.create({
              session_id: terminal.id,
              event_type: 'error',
              payload: { message: `GUI open failed: ${guiResult.message}` },
            });

            wsBroadcast.sessionTreeUpdate(voiceSessionId);
            return `Opened ${cliLabel} session "${sessionName}" in ${projectPath}, but GUI failed: ${guiResult.message}`;
          }
        }

        wsBroadcast.sessionTreeUpdate(voiceSessionId);
        return `Opened ${cliLabel} session "${sessionName}" in ${projectPath}.`;
      } catch (error) {
        const errorMessage =
          error instanceof Error ? error.message : String(error);
        sessionsRepo.finish(terminal.id, 'error');
        eventsRepo.create({
          session_id: terminal.id,
          event_type: 'error',
          payload: { message: errorMessage },
        });
        wsBroadcast.sessionTreeUpdate(voiceSessionId);
        return `Failed to open ${cliLabel}: ${errorMessage}`;
      }
    },
  });
}

export function createDirectTerminalTools(
  voiceSessionId: string
) {
  const dictateSchema = z.object({
    text: z.string().describe('Text to type into the terminal and submit'),
    session_name: z
      .string()
      .nullable()
      .optional()
      .describe('Optional named terminal session (e.g. "swift-fox")'),
  });

  const readSchema = z.object({
    session_name: z
      .string()
      .nullable()
      .optional()
      .describe('Optional named terminal session (e.g. "swift-fox")'),
    lines: z.coerce
      .number()
      .int()
      .min(1)
      .max(200)
      .nullable()
      .optional()
      .describe('How many recent lines to return (default: 20)'),
  });

  const closeSchema = z.object({
    session_name: z
      .string()
      .nullable()
      .optional()
      .describe('Optional named terminal session (e.g. "swift-fox")'),
  });

  const arrangeSchema = z.object({
    arrangement: z.enum([
      'left_half',
      'right_half',
      'fullscreen',
      'top_half',
      'bottom_half',
      'center',
    ]),
    session_name: z
      .string()
      .nullable()
      .optional()
      .describe('Optional named terminal session (e.g. "swift-fox")'),
  });

  return {
    open_claude: createOpenCliTool(voiceSessionId, 'claude'),
    open_codex: createOpenCliTool(voiceSessionId, 'codex'),
    dictate_to_session: tool({
      name: 'dictate_to_session',
      description:
        'Send dictated text to a named terminal session (or the most recent active one).',
      parameters: dictateSchema,
      async execute({ text, session_name }) {
        const inputText = text.trim();
        if (!inputText) {
          return 'Text cannot be empty.';
        }

        const sessionsRepo = new CliSessionsRepository();
        const eventsRepo = new CliEventsRepository();
        const resolved = resolveTerminalByNameOrRecency(
          sessionsRepo,
          voiceSessionId,
          session_name ?? undefined,
          false
        );

        if (!resolved.session) {
          return resolved.error ?? 'No matching session found.';
        }

        const target = resolved.session;
        const response = await macClient.sendCliInput(target.id, inputText);
        if (!response.success) {
          return `Failed to send to "${getDisplayName(target)}": ${response.message}`;
        }

        eventsRepo.create({
          session_id: target.id,
          event_type: 'input',
          payload: {
            input: inputText,
            source: 'dictate_to_session',
          },
        });

        return `Sent to "${getDisplayName(target)}".`;
      },
    }),
    read_session: tool({
      name: 'read_session',
      description:
        'Read recent terminal output from a named session (or the most recent active one).',
      parameters: readSchema,
      async execute({ session_name, lines }) {
        const maxLines = lines ?? 20;
        const sessionsRepo = new CliSessionsRepository();

        const resolved = resolveTerminalByNameOrRecency(
          sessionsRepo,
          voiceSessionId,
          session_name ?? undefined,
          false
        );

        if (!resolved.session) {
          return resolved.error ?? 'No matching session found.';
        }

        const target = resolved.session;
        const response = await macClient.readCliOutput(target.id);
        if (!response.success) {
          return `Failed to read "${getDisplayName(target)}".`;
        }

        const runtimeStatus = normalizeRuntimeStatus(response.status);
        if (runtimeStatus && runtimeStatus !== target.status) {
          sessionsRepo.update(target.id, { status: runtimeStatus });
          wsBroadcast.sessionTreeUpdate(voiceSessionId);
        }

        const recent = response.output.slice(-maxLines);
        if (recent.length === 0) {
          return `Session "${getDisplayName(target)}" has no recent output.`;
        }

        return [
          `Session "${getDisplayName(target)}" (${response.status || target.status})`,
          ...recent.map((line) => clip(line, 240)),
        ].join('\n');
      },
    }),
    close_session: tool({
      name: 'close_session',
      description:
        'Close a running terminal session by name (or the most recent active one).',
      parameters: closeSchema,
      async execute({ session_name }) {
        const sessionsRepo = new CliSessionsRepository();
        const eventsRepo = new CliEventsRepository();

        const resolved = resolveTerminalByNameOrRecency(
          sessionsRepo,
          voiceSessionId,
          session_name ?? undefined,
          false
        );

        if (!resolved.session) {
          if (session_name) {
            const maybeFinished = resolveTerminalByNameOrRecency(
              sessionsRepo,
              voiceSessionId,
              session_name,
              true
            );
            if (maybeFinished.session && !isActiveSession(maybeFinished.session)) {
              return `Session "${getDisplayName(maybeFinished.session)}" is already closed.`;
            }
          }
          return resolved.error ?? 'No matching session found.';
        }

        const target = resolved.session;
        const terminateResult = await macClient.terminateSession(target.id);
        const closeGuiResult = await macClient.closeGuiTerminal(target.id);

        if (!terminateResult.success) {
          return `Failed to close "${getDisplayName(target)}": ${terminateResult.message}`;
        }

        sessionsRepo.finish(target.id, 'finished');
        eventsRepo.create({
          session_id: target.id,
          event_type: 'finished',
          payload: {
            reason: 'user_closed',
            gui: closeGuiResult.success ? 'closed' : closeGuiResult.message,
          },
        });
        wsBroadcast.sessionTreeUpdate(voiceSessionId);

        if (!closeGuiResult.success) {
          return `Closed session "${getDisplayName(target)}", but GUI close failed: ${closeGuiResult.message}`;
        }

        return `Closed session "${getDisplayName(target)}".`;
      },
    }),
    arrange_window: tool({
      name: 'arrange_window',
      description:
        'Arrange a terminal GUI window (left/right/fullscreen/top/bottom/center).',
      parameters: arrangeSchema,
      async execute({ arrangement, session_name }) {
        const sessionsRepo = new CliSessionsRepository();
        const resolved = resolveTerminalByNameOrRecency(
          sessionsRepo,
          voiceSessionId,
          session_name ?? undefined,
          false
        );

        if (!resolved.session) {
          return resolved.error ?? 'No matching session found.';
        }

        const target = resolved.session;
        const result = await macClient.arrangeWindow(target.id, arrangement);
        if (!result.success) {
          return `Failed to arrange "${getDisplayName(target)}": ${result.message}`;
        }

        return `Arranged "${getDisplayName(target)}" on ${arrangement}.`;
      },
    }),
  };
}



/**
 * Govee Smart Light Control Tool
 *
 * Controls Govee smart lights via their API.
 * Supports: on/off, brightness, color (RGB), color temperature
 *
 * Uses raw JSON schema (not Zod) to allow optional parameters without strict mode.
 */

import { tool } from '@openai/agents/realtime';

const GOVEE_API_BASE = 'https://openapi.api.govee.com';

// Device mapping
const DEVICES: Record = {
  'stehlampe 1': { sku: 'H6008', deviceId: '25:96:D0:C9:07:30:23:60' },
  'stehlampe 2': { sku: 'H6008', deviceId: 'ED:12:D0:C9:07:30:3B:92' },
  'wandleuchte': { sku: 'H600D', deviceId: '69:84:CC:8D:A2:B3:1F:78' },
};

function getApiKey(): string {
  const key = process.env.GOVEE_API_KEY;
  if (!key) {
    throw new Error('GOVEE_API_KEY not set in environment');
  }
  return key;
}

const DEFAULT_DEVICE = { displayName: 'Stehlampe 1', sku: 'H6008', deviceId: '25:96:D0:C9:07:30:23:60' };

function findDevice(name: string | undefined | null): { displayName: string; sku: string; deviceId: string } {
  // Default to Stehlampe 1
  if (!name) {
    return DEFAULT_DEVICE;
  }

  const nameLower = name.toLowerCase().trim();

  // Direct match
  const direct = DEVICES[nameLower];
  if (direct) {
    return { displayName: name, sku: direct.sku, deviceId: direct.deviceId };
  }

  // Partial match
  for (const [key, device] of Object.entries(DEVICES)) {
    if (nameLower.includes(key) || key.includes(nameLower)) {
      return { displayName: key, sku: device.sku, deviceId: device.deviceId };
    }
  }

  // Default fallback
  return DEFAULT_DEVICE;
}

async function sendCommand(
  sku: string,
  deviceId: string,
  capabilityType: string,
  instance: string,
  value: number
): Promise {
  const payload = {
    requestId: 'voice-agent',
    payload: {
      sku,
      device: deviceId,
      capability: {
        type: capabilityType,
        instance,
        value,
      },
    },
  };

  console.log(`[Govee] Sending command to ${deviceId}: ${instance}=${value}`);

  const response = await fetch(`${GOVEE_API_BASE}/router/api/v1/device/control`, {
    method: 'POST',
    headers: {
      'Govee-API-Key': getApiKey(),
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(payload),
  });

  if (!response.ok) {
    const text = await response.text();
    throw new Error(`Govee API error: ${response.status} - ${text}`);
  }
}

interface ControlLightParams {
  action: 'on' | 'off' | 'brightness' | 'color' | 'temperature';
  device_name?: string;
  brightness?: number;
  r?: number;
  g?: number;
  b?: number;
  temperature?: number;
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export const controlLightTool = tool({
  name: 'control_light',
  description:
    'Control smart lights in the home. Can turn lights on/off, ' +
    'adjust brightness (1-100), set colors via RGB values (0-255 each), ' +
    'or set color temperature in Kelvin (2000-9000). ' +
    'Available devices: Stehlampe 1, Stehlampe 2, Wandleuchte.',
  strict: false,
  parameters: {
    type: 'object',
    properties: {
      action: { type: 'string', description: 'The action: on, off, brightness, color, or temperature.' },
      device_name: { type: 'string', description: "Device: 'Stehlampe 1', 'Stehlampe 2', or 'Wandleuchte'. Defaults to Stehlampe 1." },
      brightness: { type: 'number', description: 'Brightness 1-100. For brightness action.' },
      r: { type: 'number', description: 'Red 0-255. For color action.' },
      g: { type: 'number', description: 'Green 0-255. For color action.' },
      b: { type: 'number', description: 'Blue 0-255. For color action.' },
      temperature: { type: 'number', description: 'Temperature 2000-9000K. For temperature action.' },
    },
    required: ['action'],
    additionalProperties: true,
  },
  execute: async (input: unknown) => {
    const { action, device_name, brightness, r, g, b, temperature } = input as ControlLightParams;
    console.log(`[Govee] Action: ${action} on ${device_name || 'default'}, brightness=${brightness}, rgb=${r},${g},${b}, temp=${temperature}`);

    try {
      const { displayName, sku, deviceId } = findDevice(device_name);

      switch (action) {
        case 'on':
        case 'off': {
          const value = action === 'on' ? 1 : 0;
          await sendCommand(sku, deviceId, 'devices.capabilities.on_off', 'powerSwitch', value);
          const status = action === 'on' ? 'eingeschaltet' : 'ausgeschaltet';
          return `${displayName} wurde ${status}.`;
        }

        case 'brightness': {
          if (brightness == null) {
            return 'Helligkeit nicht angegeben.';
          }
          await sendCommand(sku, deviceId, 'devices.capabilities.range', 'brightness', brightness);
          return `${displayName} Helligkeit auf ${brightness} Prozent gesetzt.`;
        }

        case 'color': {
          if (r == null || g == null || b == null) {
            return 'RGB Werte (r, g, b) nicht vollständig angegeben.';
          }
          // Govee uses RGB as integer: (r << 16) + (g << 8) + b
          const colorValue = (r << 16) + (g << 8) + b;
          await sendCommand(sku, deviceId, 'devices.capabilities.color_setting', 'colorRgb', colorValue);
          return `${displayName} Farbe auf RGB ${r}, ${g}, ${b} gesetzt.`;
        }

        case 'temperature': {
          if (temperature == null) {
            return 'Farbtemperatur nicht angegeben.';
          }
          await sendCommand(sku, deviceId, 'devices.capabilities.color_setting', 'colorTemperatureK', temperature);
          return `${displayName} Farbtemperatur auf ${temperature} Kelvin gesetzt.`;
        }

        default:
          return `Unbekannte Aktion: ${action}. Verfügbar: on, off, brightness, color, temperature`;
      }
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      console.error(`[Govee] Error: ${message}`);
      return `Fehler bei der Lichtsteuerung: ${message}`;
    }
  },
});



/**
 * Reasoning Delegation Tool - Hands off to a reasoning model for complex tasks.
 *
 * This demonstrates delegation through tools (from the docs):
 * - Realtime model handles voice interaction
 * - Complex reasoning is delegated to gpt-5-mini (or similar)
 * - Result is returned for Realtime to speak
 *
 * Use cases:
 * - Multi-step planning
 * - Code analysis
 * - Complex calculations
 * - Decision making with multiple factors
 */

import { tool, type RealtimeContextData } from '@openai/agents/realtime';
import OpenAI from 'openai';
import { z } from 'zod';

let _client: OpenAI | null = null;
function getClient(): OpenAI {
  if (!_client) _client = new OpenAI();
  return _client;
}

export const reasoningTool = tool<
  z.ZodObject<{
    task: z.ZodString;
    context: z.ZodNullable;
  }>,
  RealtimeContextData
>({
  name: 'deep_thinking',
  description:
    'Delegate complex reasoning tasks to a more capable model. Use this for: ' +
    'multi-step planning, analyzing complex problems, making decisions with ' +
    'multiple factors, code review, or any task requiring deeper thought. ' +
    'The result will be spoken back to the user.',
  parameters: z.object({
    task: z.string().describe('The task or question that requires deep reasoning.'),
    context: z
      .string()
      .nullable()
      .describe('Additional context about what the user needs. Pass null if none.'),
  }),
  async execute({ task, context }, details) {
    console.log(`[Reasoning] Task: ${task}`);

    // Access conversation history from the Realtime session
    const history = details?.context?.history ?? [];

    // Build context from recent conversation
    const recentMessages = history
      .filter((item) => item.type === 'message')
      .slice(-5) // Last 5 messages for context
      .map((item) => {
        if ('content' in item && Array.isArray(item.content)) {
          const content = item.content as Array<{ type?: string; text?: string }>;
          const text = content
            .filter((c) => c.text)
            .map((c) => c.text)
            .join(' ');
          const role = 'role' in item ? (item as { role: string }).role : 'unknown';
          return `${role}: ${text}`;
        }
        return null;
      })
      .filter(Boolean)
      .join('\n');

    try {
      const response = await getClient().chat.completions.create({
        model: 'gpt-4o', // Use gpt-5-mini when available
        messages: [
          {
            role: 'system',
            content: `Du bist ein intelligenter Assistent, der bei komplexen Aufgaben hilft.
Du erhältst eine Aufgabe und den Kontext aus einem Voice-Gespräch.
Deine Antwort wird vorgelesen, also:
- Halte dich kurz und prägnant (max 3-4 Sätze)
- Verwende natürliche Sprache, keine Aufzählungen
- Strukturiere komplexe Antworten in sprechbare Abschnitte`,
          },
          {
            role: 'user',
            content: `Aufgabe: ${task}
${context ? `\nZusätzlicher Kontext: ${context}` : ''}
${recentMessages ? `\nLetzter Gesprächsverlauf:\n${recentMessages}` : ''}`,
          },
        ],
        temperature: 0.7,
        max_tokens: 500,
      });

      const result = response.choices[0]?.message?.content || 'Ich konnte keine Antwort generieren.';
      console.log(`[Reasoning] Result: ${result.substring(0, 100)}...`);

      return result;
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      console.error(`[Reasoning] Error: ${message}`);
      return `Bei der Analyse ist ein Fehler aufgetreten: ${message}`;
    }
  },
});



/**
 * Timer Tools - Set, list, and cancel timers.
 *
 * Uses SQLite database for persistence and the scheduler for firing.
 */

import { tool } from '@openai/agents/realtime';
import { z } from 'zod';
import { TimersRepository, type TimerMode } from '../db/index.js';
import { parseTimeExpression, formatTimerResponse } from '../scheduler/index.js';

const timersRepo = new TimersRepository();

export const setTimerTool = tool({
  name: 'set_timer',
  description:
    'Set a timer or reminder. Use this when the user wants to be reminded of something ' +
    'or wants a timer. Supports natural language time expressions like "in 5 minutes", ' +
    '"in einer Stunde", "um 15 Uhr", "at 3pm", "morgen um 9 Uhr".',
  parameters: z.object({
    time: z
      .string()
      .describe(
        'When the timer should fire. Natural language like "in 5 minutes", ' +
          '"in einer Stunde", "um 15 Uhr", "tomorrow at 9am".'
      ),
    message: z
      .string()
      .nullable()
      .describe('The reminder message to speak when the timer fires. If not specified, defaults to "Timer abgelaufen".'),
    mode: z
      .enum(['tts', 'agent'])
      .nullable()
      .describe(
        'How to deliver the reminder. "tts" speaks the message directly (default), ' +
          '"agent" triggers a new agent conversation.'
      ),
  }),
  async execute({ time, message: rawMessage, mode }) {
    const message = rawMessage ?? 'Timer abgelaufen';
    // Parse the time expression
    const parsed = parseTimeExpression(time);
    if (!parsed) {
      return `Ich konnte die Zeit "${time}" nicht verstehen. Bitte sage zum Beispiel "in 5 Minuten" oder "um 15 Uhr".`;
    }

    // Don't allow timers in the past
    if (parsed.date <= new Date()) {
      return 'Die angegebene Zeit liegt in der Vergangenheit. Bitte gib eine Zeit in der Zukunft an.';
    }

    // Create the timer
    const timer = timersRepo.create({
      fire_at: parsed.date,
      message: message.trim(),
      mode: (mode ?? 'tts') as TimerMode,
    });

    console.log(`[Timer] Created #${timer.id}: "${message}" at ${parsed.date.toISOString()}`);

    return formatTimerResponse(message, parsed.date);
  },
});

export const listTimersTool = tool({
  name: 'list_timers',
  description:
    'List all pending timers and reminders. Use this when the user wants to see ' +
    'their active timers or asks "what timers do I have?".',
  parameters: z.object({}),
  async execute() {
    const pending = timersRepo.getPending();

    if (pending.length === 0) {
      return 'Du hast keine aktiven Timer.';
    }

    const now = new Date();
    const lines = pending.map((t) => {
      const fireAt = new Date(t.fire_at);
      const diffMs = fireAt.getTime() - now.getTime();
      const diffMinutes = Math.round(diffMs / 60000);

      let timeDesc: string;
      if (diffMinutes < 1) {
        timeDesc = 'gleich';
      } else if (diffMinutes < 60) {
        timeDesc = `in ${diffMinutes} Minuten`;
      } else {
        const hours = Math.floor(diffMinutes / 60);
        const mins = diffMinutes % 60;
        if (mins === 0) {
          timeDesc = `in ${hours} Stunde${hours !== 1 ? 'n' : ''}`;
        } else {
          timeDesc = `in ${hours} Stunde${hours !== 1 ? 'n' : ''} und ${mins} Minuten`;
        }
      }

      return `Timer ${t.id}: "${t.message}" ${timeDesc}`;
    });

    console.log(`[Timer] Listed ${pending.length} timers`);

    return `Du hast ${pending.length} aktive Timer: ${lines.join('. ')}.`;
  },
});

export const cancelTimerTool = tool({
  name: 'cancel_timer',
  description:
    'Cancel a timer by its ID. Use this when the user wants to delete or cancel ' +
    'a specific timer.',
  parameters: z.object({
    id: z.number().describe('The ID of the timer to cancel.'),
  }),
  async execute({ id }) {
    const timer = timersRepo.findById(id);

    if (!timer) {
      return `Timer ${id} wurde nicht gefunden.`;
    }

    if (timer.status !== 'pending') {
      return `Timer ${id} ist bereits ${timer.status === 'fired' ? 'abgelaufen' : 'abgebrochen'}.`;
    }

    const success = timersRepo.cancel(id);

    if (success) {
      console.log(`[Timer] Cancelled #${id}: "${timer.message}"`);
      return `Timer ${id} wurde abgebrochen: "${timer.message}"`;
    } else {
      return `Timer ${id} konnte nicht abgebrochen werden.`;
    }
  },
});



/**
 * Todo List Tools - JSON-based task management.
 *
 * Data stored in ~/todos.json
 * Each task has: id, task, assignee, created_at, due_date (optional)
 */

import { tool } from '@openai/agents/realtime';
import { z } from 'zod';
import { readFileSync, writeFileSync, existsSync } from 'fs';
import { homedir } from 'os';
import { join } from 'path';

const TODO_FILE = join(homedir(), 'todos.json');

interface Todo {
  id: number;
  task: string;
  assignee: string;
  created_at: string;
  due_date?: string;
}

function loadTodos(): Todo[] {
  if (!existsSync(TODO_FILE)) {
    return [];
  }
  try {
    const data = readFileSync(TODO_FILE, 'utf-8');
    return JSON.parse(data) as Todo[];
  } catch {
    return [];
  }
}

function saveTodos(todos: Todo[]): void {
  writeFileSync(TODO_FILE, JSON.stringify(todos, null, 2), 'utf-8');
}

function getNextId(todos: Todo[]): number {
  if (todos.length === 0) return 1;
  return Math.max(...todos.map((t) => t.id)) + 1;
}

export const addTodoTool = tool({
  name: 'add_todo',
  description:
    'Add a new task to the todo list. Use this when the user wants to create ' +
    'a new task, reminder, or todo item.',
  parameters: z.object({
    task: z.string().describe('The task description or name.'),
    due_date: z
      .string()
      .nullable()
      .describe('Optional due date in format YYYY-MM-DD. Pass null if not specified.'),
    assignee: z
      .enum(['Lukasz', 'Hannah'])
      .nullable()
      .describe('Who is assigned to this task. Defaults to Lukasz if null.'),
  }),
  async execute({ task, due_date, assignee }) {
    if (!task.trim()) {
      return 'Keine Aufgabe angegeben.';
    }

    // Use defaults for null values
    const actualAssignee = assignee ?? 'Lukasz';
    let actualDueDate = due_date;

    // Validate due_date format if provided
    if (actualDueDate && !/^\d{4}-\d{2}-\d{2}$/.test(actualDueDate)) {
      actualDueDate = null;
    }

    const todos = loadTodos();
    const newId = getNextId(todos);

    const newTodo: Todo = {
      id: newId,
      task: task.trim(),
      assignee: actualAssignee,
      created_at: new Date().toISOString(),
    };
    if (actualDueDate) {
      newTodo.due_date = actualDueDate;
    }

    todos.push(newTodo);
    saveTodos(todos);

    console.log(`[Todo] Added #${newId}: ${task}`);

    let response = `Aufgabe Nummer ${newId} erstellt: ${task}`;
    if (actualDueDate) {
      response += `, fällig am ${actualDueDate}`;
    }
    response += `, zugewiesen an ${actualAssignee}.`;

    return response;
  },
});

export const viewTodosTool = tool({
  name: 'view_todos',
  description:
    'View or query the todo list. Use this when the user wants to see their ' +
    'tasks, check what is due, or filter by assignee.',
  parameters: z.object({
    assignee: z
      .enum(['Lukasz', 'Hannah'])
      .nullable()
      .describe('Filter by assignee. Pass null to show all tasks.'),
  }),
  async execute({ assignee }) {
    let todos = loadTodos();

    if (todos.length === 0) {
      return 'Die Todo-Liste ist leer. Keine Aufgaben vorhanden.';
    }

    // Filter by assignee if specified
    if (assignee) {
      todos = todos.filter((t) => t.assignee === assignee);
      if (todos.length === 0) {
        return `Keine Aufgaben für ${assignee} gefunden.`;
      }
    }

    console.log(`[Todo] Found ${todos.length} todos`);

    // Build response for speech
    const lines = todos.map((t) => {
      let line = `Nummer ${t.id}: ${t.task}, zugewiesen an ${t.assignee}`;
      if (t.due_date) {
        line += `, fällig am ${t.due_date}`;
      }
      return line;
    });

    const header = assignee ? `Aufgaben für ${assignee}:` : 'Alle Aufgaben:';
    return `${header} ${lines.join('. ')}.`;
  },
});

export const deleteTodoTool = tool({
  name: 'delete_todo',
  description:
    'Delete a task from the todo list by its ID. Use this when the user wants ' +
    'to remove or complete a task.',
  parameters: z.object({
    id: z.number().describe('The ID of the task to delete.'),
  }),
  async execute({ id }) {
    const todos = loadTodos();

    const todoToDelete = todos.find((t) => t.id === id);
    if (!todoToDelete) {
      return `Aufgabe Nummer ${id} nicht gefunden.`;
    }

    const remaining = todos.filter((t) => t.id !== id);
    saveTodos(remaining);

    console.log(`[Todo] Deleted #${id}: ${todoToDelete.task}`);

    return `Aufgabe Nummer ${id} gelöscht: ${todoToDelete.task}`;
  },
});



/**
 * Audio Transport Layer - Abstracts audio I/O for different platforms.
 *
 * Exports:
 * - IAudioTransport: Interface for audio transport implementations
 * - LocalTransport: Hardware audio (Pi via PipeWire, Mac via sox)
 * - WebSocketTransport: Browser-based audio via WebSocket
 */

export { type IAudioTransport, type AudioTransportEvents, AUDIO_CONFIG } from './types.js';
export { LocalTransport } from './local.js';
export { WebSocketTransport, type WSAudioMessage } from './websocket.js';



/**
 * Audio Transport Interface - Abstract audio I/O for different platforms.
 *
 * Implementations:
 * - LocalTransport: Hardware audio (Pi via PipeWire, Mac via sox)
 * - WebSocketTransport: Browser-based audio via WebSocket
 */

import { EventEmitter } from 'events';

export interface IAudioTransport extends EventEmitter {
  /**
   * Start capturing/handling audio.
   * For local transport: starts microphone recording.
   * For WebSocket transport: signals UI to start recording.
   */
  start(): void;

  /**
   * Stop capturing/handling audio.
   * For local transport: stops microphone recording.
   * For WebSocket transport: signals UI to stop recording.
   */
  stop(): void;

  /**
   * Play raw PCM16 24kHz mono audio.
   * For local transport: outputs to speakers.
   * For WebSocket transport: sends to connected browser clients.
   */
  play(audio: ArrayBuffer): void;

  /**
   * Check if transport is actively capturing audio.
   */
  isActive(): boolean;

  /**
   * Interrupt any currently playing audio.
   */
  interrupt(): void;
}

/**
 * Events emitted by IAudioTransport:
 * - 'audio': (chunk: ArrayBuffer) => void - Incoming audio from user (Mic/Browser)
 * - 'error': (error: Error) => void - Transport error
 * - 'interrupted': () => void - Audio playback was interrupted
 */
export interface AudioTransportEvents {
  audio: (chunk: ArrayBuffer) => void;
  error: (error: Error) => void;
  interrupted: () => void;
}

/**
 * Audio configuration constants.
 */
export const AUDIO_CONFIG = {
  /** OpenAI Realtime API sample rate */
  API_SAMPLE_RATE: 24000,
  /** Channels (mono) */
  CHANNELS: 1,
  /** Bit depth */
  BIT_DEPTH: 16,
  /** Format identifier */
  FORMAT: 's16' as const,
} as const;



/**
 * WebSocket Audio Transport - Browser-based audio via WebSocket.
 *
 * Routes audio to/from connected browser clients:
 * - Incoming audio from browser microphone → 'audio' event
 * - Outgoing audio for playback → send binary to clients
 *
 * This allows running the agent on a Mac (or any server) while using
 * the browser as the microphone and speaker.
 */

import { EventEmitter } from 'events';
import { WebSocket } from 'ws';
import { type IAudioTransport, AUDIO_CONFIG } from './types.js';
import { broadcastBinary } from '../api/websocket.js';

// Message types for WebSocket communication (follows WSMessage format)
export interface WSAudioControlPayload {
  action: 'start' | 'stop' | 'interrupt';
}

export interface WSAudioMessage {
  type: 'audio_control';
  payload: WSAudioControlPayload;
  timestamp: number;
}

export class WebSocketTransport extends EventEmitter implements IAudioTransport {
  private active = false;
  private clients: Set;

  /**
   * Create a WebSocket transport.
   * @param clients - Reference to the set of connected WebSocket clients
   */
  constructor(clients: Set) {
    super();
    this.clients = clients;
  }

  /**
   * Start capturing audio from browser clients.
   * Sends a 'start' control message to all connected clients.
   */
  start(): void {
    if (this.active) {
      return;
    }

    this.active = true;

    // Notify browser clients to start recording
    this.sendControlMessage('start');

    console.log(`[WebSocketTransport] Started (expecting ${AUDIO_CONFIG.API_SAMPLE_RATE}Hz pcm16)`);
  }

  /**
   * Stop capturing audio from browser clients.
   * Sends a 'stop' control message to all connected clients.
   */
  stop(): void {
    if (!this.active) {
      return;
    }

    this.active = false;

    // Notify browser clients to stop recording
    this.sendControlMessage('stop');

    console.log('[WebSocketTransport] Stopped');
  }

  /**
   * Play audio by sending it to browser clients for playback.
   * Sends binary PCM16 24kHz data.
   */
  play(audio: ArrayBuffer): void {
    const buffer = Buffer.isBuffer(audio) ? audio : Buffer.from(audio);
    broadcastBinary(buffer);
  }

  /**
   * Interrupt playback on browser clients.
   */
  interrupt(): void {
    this.sendControlMessage('interrupt');
    this.emit('interrupted');
  }

  /**
   * Check if transport is active.
   */
  isActive(): boolean {
    return this.active;
  }

  /**
   * Handle incoming audio data from a browser client.
   * This should be called by the WebSocket server when it receives binary data.
   */
  handleClientAudio(data: Buffer): void {
    if (!this.active) {
      // Log occasionally to help debug (not every frame to avoid spam)
      if (Math.random() < 0.01) {
        console.log('[WebSocketTransport] Dropping audio - transport not active');
      }
      return;
    }

    // Convert Buffer to ArrayBuffer and emit
    const arrayBuffer = data.buffer.slice(
      data.byteOffset,
      data.byteOffset + data.byteLength
    );
    this.emit('audio', arrayBuffer);
  }

  /**
   * Register a handler for incoming client audio.
   * Used for wiring up the WebSocket server's binary message handler.
   */
  getAudioHandler(): (data: Buffer) => void {
    return (data: Buffer) => this.handleClientAudio(data);
  }

  /**
   * Send a control message to all connected clients.
   * Uses WSMessage format for consistency with other WebSocket messages.
   */
  private sendControlMessage(action: 'start' | 'stop' | 'interrupt'): void {
    if (this.clients.size === 0) {
      return;
    }

    const message: WSAudioMessage = {
      type: 'audio_control',
      payload: { action },
      timestamp: Date.now(),
    };

    const data = JSON.stringify(message);

    for (const client of this.clients) {
      if (client.readyState === WebSocket.OPEN) {
        client.send(data);
      }
    }
  }

  /**
   * Get the number of connected clients.
   */
  getClientCount(): number {
    return this.clients.size;
  }
}



/**
 * Hook for audio transport lifecycle in the inspector.
 *
 * Primary path: attach LocalTransport directly to VoiceRuntime
 * (`runtime.attachAudioTransport`) so playback/interruption flow is managed
 * by the unified runtime layer.
 */

import { useRef, useCallback, useEffect } from 'react';
import { LocalTransport } from '../../../transport/local.js';
import type { VoiceRuntime } from '../../../voice/types.js';
import type { EventMux } from '../util/event-mux.js';
import { useInspector } from '../state.js';

export interface AudioHandle {
  start: (runtime: VoiceRuntime, mux: EventMux) => Promise;
  stop: () => void;
  toggleMute: () => void;
  cycleInputDevice: () => void;
  cycleOutputDevice: () => void;
}

export function useAudio(): AudioHandle {
  const { state, dispatch } = useInspector();
  const transportRef = useRef(null);
  const runtimeRef = useRef(null);
  const mutedRef = useRef(false);
  const runtimeManagedTransportRef = useRef(false);
  const inputDevicesRef = useRef(['default']);
  const outputDevicesRef = useRef(['default']);
  const selectedInputDeviceRef = useRef('default');
  const selectedOutputDeviceRef = useRef('default');
  const defaultInputDeviceRef = useRef('default');
  const defaultOutputDeviceRef = useRef('default');

  function resolveSelectedDevice(preferred: string, available: string[], fallback: string): string {
    if (available.includes(preferred)) return preferred;
    if (available.includes(fallback)) return fallback;
    return available[0] ?? 'default';
  }

  const refreshAudioDevices = useCallback(() => {
    const devices = LocalTransport.listAudioDevices();
    inputDevicesRef.current = devices.inputDevices.length > 0 ? devices.inputDevices : ['default'];
    outputDevicesRef.current = devices.outputDevices.length > 0 ? devices.outputDevices : ['default'];
    defaultInputDeviceRef.current = devices.defaultInputDevice || 'default';
    defaultOutputDeviceRef.current = devices.defaultOutputDevice || 'default';

    const selectedInput = resolveSelectedDevice(
      state.audioDevices.inputDevice,
      inputDevicesRef.current,
      devices.defaultInputDevice
    );
    const selectedOutput = resolveSelectedDevice(
      state.audioDevices.outputDevice,
      outputDevicesRef.current,
      devices.defaultOutputDevice
    );

    selectedInputDeviceRef.current = selectedInput;
    selectedOutputDeviceRef.current = selectedOutput;

    dispatch({
      type: 'AUDIO_DEVICES_LOADED',
      inputDevices: inputDevicesRef.current,
      outputDevices: outputDevicesRef.current,
      inputDevice: selectedInput,
      outputDevice: selectedOutput,
    });
  }, [dispatch, state.audioDevices.inputDevice, state.audioDevices.outputDevice]);

  function toTransportDevice(selected: string, defaultDevice: string): string {
    if (!selected || selected === 'default') return 'default';
    if (selected === defaultDevice) return 'default';
    return selected;
  }

  useEffect(() => {
    mutedRef.current = state.muted;
    transportRef.current?.setCaptureEnabled(!state.muted);
  }, [state.muted]);

  const start = useCallback(async (runtime: VoiceRuntime, mux: EventMux) => {
    // Clean up previous transport/runtime attachment.
    const previousRuntime = runtimeRef.current;
    if (runtimeManagedTransportRef.current && previousRuntime?.detachAudioTransport) {
      await previousRuntime.detachAudioTransport().catch(() => {});
    }
    if (transportRef.current) {
      transportRef.current.stop();
      transportRef.current = null;
    }

    refreshAudioDevices();
    const transport = new LocalTransport({
      inputDevice: toTransportDevice(
        selectedInputDeviceRef.current,
        defaultInputDeviceRef.current
      ),
      outputDevice: toTransportDevice(
        selectedOutputDeviceRef.current,
        defaultOutputDeviceRef.current
      ),
    });
    transportRef.current = transport;
    runtimeRef.current = runtime;
    runtimeManagedTransportRef.current =
      typeof runtime.attachAudioTransport === 'function' &&
      typeof runtime.detachAudioTransport === 'function';

    transport.setCaptureEnabled(!mutedRef.current);
    transport.on('error', (error: Error) => {
      dispatch({ type: 'ERROR', message: `Audio transport: ${error.message}` });
    });

    const startFallbackTransport = () => {
      runtimeManagedTransportRef.current = false;
      transport.on('audio', (chunk: ArrayBuffer) => {
        if (!mutedRef.current) {
          runtime.sendAudio(chunk);
        }
      });
      transport.start();
    };

    if (runtimeManagedTransportRef.current) {
      try {
        await runtime.attachAudioTransport!(transport);
      } catch (error) {
        dispatch({
          type: 'ERROR',
          message: `Attach audio transport failed: ${(error as Error).message}`,
        });
        startFallbackTransport();
      }
    } else {
      // Back-compat fallback for runtimes without attachAudioTransport.
      startFallbackTransport();
    }

    // Runtime audio events are still observed for metrics/diagnostics.
    let audioChunkCount = 0;
    mux.on('audio', (audio) => {
      audioChunkCount++;
      if (audioChunkCount <= 3) {
        console.error(
          `[TUI Audio] chunk #${audioChunkCount}: ${audio.data.byteLength}B rate=${audio.sampleRate ?? 'undefined'}`
        );
      }

      if (!runtimeManagedTransportRef.current) {
        transport.play(audio.data, audio.sampleRate);
      }

      dispatch({ type: 'AUDIO_CHUNK', timestamp: Date.now() });
    });

    mux.on('audioInterrupted', () => {
      dispatch({ type: 'AUDIO_INTERRUPTED' });
      // Runtime-managed mode already interrupts playback in VoiceSession.
      if (!runtimeManagedTransportRef.current && transport.isPlayingAudio()) {
        transport.interrupt();
      }
    });
  }, [dispatch, refreshAudioDevices]);

  const stop = useCallback(() => {
    if (runtimeManagedTransportRef.current && runtimeRef.current?.detachAudioTransport) {
      void runtimeRef.current.detachAudioTransport().catch(() => {});
    }
    if (transportRef.current) {
      transportRef.current.stop();
      transportRef.current = null;
    }
    runtimeManagedTransportRef.current = false;
    runtimeRef.current = null;
  }, []);

  const toggleMute = useCallback(() => {
    dispatch({ type: 'TOGGLE_MUTE' });
  }, [dispatch]);

  const cycleInputDevice = useCallback(() => {
    const devices = inputDevicesRef.current;
    if (devices.length === 0) return;
    const current = selectedInputDeviceRef.current;
    const currentIndex = Math.max(0, devices.indexOf(current));
    const next = devices[(currentIndex + 1) % devices.length] ?? devices[0]!;
    selectedInputDeviceRef.current = next;
    transportRef.current?.setInputDevice(toTransportDevice(next, defaultInputDeviceRef.current));
    dispatch({ type: 'AUDIO_INPUT_DEVICE_SET', device: next });
  }, [dispatch]);

  const cycleOutputDevice = useCallback(() => {
    const devices = outputDevicesRef.current;
    if (devices.length === 0) return;
    const current = selectedOutputDeviceRef.current;
    const currentIndex = Math.max(0, devices.indexOf(current));
    const next = devices[(currentIndex + 1) % devices.length] ?? devices[0]!;
    selectedOutputDeviceRef.current = next;
    transportRef.current?.setOutputDevice(toTransportDevice(next, defaultOutputDeviceRef.current));
    dispatch({ type: 'AUDIO_OUTPUT_DEVICE_SET', device: next });
  }, [dispatch]);

  // Cleanup on unmount
  useEffect(() => {
    return stop;
  }, [stop]);

  return { start, stop, toggleMute, cycleInputDevice, cycleOutputDevice };
}



/**
 * Hook for VoiceSessionBenchmark wiring.
 *
 * Always enabled in the inspector (bypasses VOICE_BENCHMARK_ENABLED env check).
 * Wires runtime events to the benchmark recorder for live metric capture.
 */

import { useRef, useCallback, useEffect } from 'react';
import {
  VoiceSessionBenchmark,
  mergeThresholds,
  parseThresholdOverridesFromEnv,
  resolveOutputDir,
} from '../../../voice/benchmark-recorder.js';
import type { VoiceProviderName } from '../../../voice/types.js';
import type { EventMux } from '../util/event-mux.js';
import { useInspector } from '../state.js';

export interface BenchmarkHandle {
  attach: (mux: EventMux, provider: VoiceProviderName, profile: string, sessionId: string) => void;
  finalize: (reason: 'disconnected' | 'deactivate' | 'connect-failed') => void;
}

export function useBenchmark(): BenchmarkHandle {
  const { dispatch } = useInspector();
  const benchRef = useRef(null);

  const attach = useCallback((
    mux: EventMux,
    provider: VoiceProviderName,
    profile: string,
    sessionId: string,
  ) => {
    const thresholds = mergeThresholds(provider, parseThresholdOverridesFromEnv());
    const benchmark = new VoiceSessionBenchmark({
      sessionId,
      profile,
      provider,
      enabled: true, // Always enabled in inspector
      outputDir: resolveOutputDir(),
      thresholds,
    });
    benchRef.current = benchmark;

    // Wire runtime events to benchmark via mux (not runtime.on directly!)
    mux.on('stateChange', (state) => {
      benchmark.onStateChange(state);
    });

    mux.on('audio', (audio) => {
      benchmark.onAudio(audio);
    });

    mux.on('transcript', (text, role, itemId) => {
      benchmark.onTranscriptFinal(text, role, itemId);
    });

    mux.on('transcriptDelta', (delta, role, itemId) => {
      benchmark.onTranscriptDelta(delta, role, itemId);
    });

    mux.on('assistantItemCreated', (itemId) => {
      benchmark.onAssistantItemCreated(itemId);
    });

    mux.on('audioInterrupted', () => {
      benchmark.markInterruptionRequested();
    });
  }, []);

  const finalize = useCallback((reason: 'disconnected' | 'deactivate' | 'connect-failed') => {
    if (!benchRef.current) return;

    const result = benchRef.current.finalize(reason);
    benchRef.current = null;

    if (result?.report) {
      dispatch({
        type: 'BENCHMARK_FINALIZED',
        report: result.report,
        outputPath: result.outputPath,
      });
    }
  }, [dispatch]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (benchRef.current) {
        benchRef.current.finalize('disconnected');
      }
    };
  }, []);

  return { attach, finalize };
}



/**
 * Hook for keyboard bindings in the inspector TUI.
 */

import { useState } from 'react';
import { useInput } from 'ink';

export interface KeyboardHandlers {
  onQuit: () => void;
  onToggleMute: () => void;
  onReconnect: () => void;
  onSwitchProfile: () => void;
  onCycleInputDevice: () => void;
  onCycleOutputDevice: () => void;
  onTextInput: () => void;
  onSendText: (text: string) => void;
  onDismiss: () => void;
  /** Whether text input mode is active (disables other bindings) */
  textInputActive: boolean;
}

export function useKeyboard(handlers: KeyboardHandlers): string {
  const [textBuffer, setTextBuffer] = useState('');

  useInput((input, key) => {
    // When text input is active, capture keystrokes
    if (handlers.textInputActive) {
      if (key.escape) {
        setTextBuffer('');
        handlers.onDismiss();
      } else if (key.return) {
        if (textBuffer.trim()) {
          handlers.onSendText(textBuffer.trim());
        }
        setTextBuffer('');
        handlers.onDismiss();
      } else if (key.backspace || key.delete) {
        setTextBuffer((prev) => prev.slice(0, -1));
      } else if (input && !key.ctrl && !key.meta) {
        setTextBuffer((prev) => prev + input);
      }
      return;
    }

    if (input === 'q') handlers.onQuit();
    if (input === ' ') handlers.onToggleMute();
    if (input === 'r') handlers.onReconnect();
    if (input === 'p') handlers.onSwitchProfile();
    if (input === 'i') handlers.onCycleInputDevice();
    if (input === 'o') handlers.onCycleOutputDevice();
    if (key.return) handlers.onTextInput();
  });

  return textBuffer;
}



/**
 * Event multiplexer for VoiceRuntime.
 *
 * PackageBackedVoiceRuntime only supports one handler per event type
 * (this.handlers[event] = handler). This utility fans out a single
 * runtime handler to multiple listeners so that use-runtime, use-audio,
 * and use-benchmark can all subscribe without overwriting each other.
 */

import type { VoiceRuntime, VoiceRuntimeEvents } from '../../../voice/types.js';

export type EventMux = {
  on(event: K, handler: VoiceRuntimeEvents[K]): void;
};

export function createEventMux(runtime: VoiceRuntime): EventMux {
  const registered = new Map();

  return {
    on(event: K, handler: VoiceRuntimeEvents[K]): void {
      const key = event as string;
      if (!registered.has(key)) {
        registered.set(key, []);
        // Register a single fan-out handler on the actual runtime.
        // All subsequent listeners for this event go through the fan-out.
        runtime.on(event, ((...args: unknown[]) => {
          for (const h of registered.get(key)!) {
            h(...args);
          }
        }) as VoiceRuntimeEvents[K]);
      }
      registered.get(key)!.push(handler as Function);
    },
  };
}



/**
 * Formatting and calculation utilities for the inspector TUI.
 */

/** Format milliseconds as human-readable string. */
export function fmtMs(ms: number | undefined | null): string {
  if (ms == null) return 'n/a';
  if (ms < 1000) return `${Math.round(ms)}ms`;
  return `${(ms / 1000).toFixed(1)}s`;
}

/** Format duration in seconds as MM:SS. */
export function fmtDuration(startedAt: number | null): string {
  if (!startedAt) return '00:00';
  const elapsed = Math.floor((Date.now() - startedAt) / 1000);
  const mins = Math.floor(elapsed / 60);
  const secs = elapsed % 60;
  return `${String(mins).padStart(2, '0')}:${String(secs).padStart(2, '0')}`;
}

/** Calculate P95 from a sorted array of samples. */
export function p95(samples: number[]): number | null {
  if (samples.length === 0) return null;
  const sorted = [...samples].sort((a, b) => a - b);
  const idx = Math.ceil(sorted.length * 0.95) - 1;
  return sorted[Math.max(0, idx)]!;
}

/** Calculate median from samples. */
export function median(samples: number[]): number | null {
  if (samples.length === 0) return null;
  const sorted = [...samples].sort((a, b) => a - b);
  const mid = Math.floor(sorted.length / 2);
  if (sorted.length % 2 === 0) {
    return (sorted[mid - 1]! + sorted[mid]!) / 2;
  }
  return sorted[mid]!;
}

/** Truncate string to max length with ellipsis. */
export function truncate(str: string, max: number): string {
  if (str.length <= max) return str;
  return str.slice(0, max - 1) + '\u2026';
}

/** Color name for agent state. */
export function stateColor(state: string): string {
  switch (state) {
    case 'idle': return 'gray';
    case 'listening': return 'green';
    case 'thinking': return 'yellow';
    case 'speaking': return 'cyan';
    default: return 'white';
  }
}

/** Whether a metric value exceeds a threshold. */
export function exceedsThreshold(value: number | null, threshold: number | undefined): boolean {
  if (value == null || threshold == null) return false;
  return value > threshold;
}



// 100 adjectives x 100 nouns = 10,000 unique combinations
const ADJECTIVES = ['swift', 'iron', 'amber', 'blue', 'quiet', 'bright', 'bold', 'calm', 'dark', 'deep',
  'eager', 'fair', 'gold', 'green', 'keen', 'light', 'lunar', 'noble', 'prime', 'rapid',
  'sharp', 'silver', 'solar', 'stark', 'steel', 'stone', 'warm', 'wild', 'wise', 'vivid',
  'arctic', 'astral', 'binary', 'blazing', 'carbon', 'chrome', 'cipher', 'cobalt', 'coral', 'cosmic',
  'crimson', 'crystal', 'cyber', 'delta', 'digital', 'drift', 'dusk', 'echo', 'ember', 'flux',
  'forge', 'frost', 'gamma', 'ghost', 'glass', 'granite', 'haze', 'helix', 'hollow', 'hyper',
  'jade', 'laser', 'lava', 'mist', 'neon', 'nova', 'onyx', 'orbit', 'oxide', 'pale',
  'phantom', 'plasma', 'polar', 'pulse', 'quartz', 'raven', 'ruby', 'rust', 'sable', 'sage',
  'scarlet', 'shadow', 'silent', 'slate', 'smoke', 'sonic', 'spark', 'spectrum', 'storm', 'terra',
  'thunder', 'titan', 'ultra', 'vapor', 'velvet', 'vertex', 'violet', 'volt', 'zero', 'zinc'];

const NOUNS = ['falcon', 'drone', 'spark', 'beacon', 'circuit', 'prism', 'matrix', 'forge', 'nexus', 'pulse',
  'arrow', 'atlas', 'blade', 'bolt', 'bridge', 'cache', 'claw', 'comet', 'core', 'crown',
  'cube', 'dagger', 'dawn', 'flame', 'flare', 'gate', 'glyph', 'grid', 'hawk', 'helix',
  'horn', 'lance', 'lens', 'link', 'lotus', 'lynx', 'mesa', 'mirror', 'node', 'orbit',
  'peak', 'pike', 'pixel', 'plume', 'probe', 'quasar', 'rail', 'ramp', 'reef', 'ridge',
  'ring', 'rover', 'rune', 'saber', 'scale', 'scope', 'shard', 'shell', 'shield', 'shore',
  'sigma', 'skull', 'slate', 'spear', 'sphere', 'spike', 'spine', 'stone', 'surge', 'sword',
  'thorn', 'tide', 'tower', 'trail', 'vault', 'veil', 'viper', 'wave', 'weave', 'wing',
  'anvil', 'badge', 'bison', 'cedar', 'chain', 'cliff', 'crane', 'drift', 'eagle', 'frost',
  'grove', 'hound', 'ivory', 'jewel', 'knot', 'latch', 'marsh', 'otter', 'pine', 'quill'];

export function generateSessionName(existingNames: Set): string {
  // Try random combo, append -2, -3 on collision
  for (let attempt = 0; attempt < 100; attempt++) {
    const adj = ADJECTIVES[Math.floor(Math.random() * ADJECTIVES.length)];
    const noun = NOUNS[Math.floor(Math.random() * NOUNS.length)];
    const name = `${adj}-${noun}`;
    if (!existingNames.has(name)) return name;
  }
  // Fallback: append number
  const adj = ADJECTIVES[Math.floor(Math.random() * ADJECTIVES.length)];
  const noun = NOUNS[Math.floor(Math.random() * NOUNS.length)];
  let suffix = 2;
  while (existingNames.has(`${adj}-${noun}-${suffix}`)) suffix++;
  return `${adj}-${noun}-${suffix}`;
}

export function resolveSessionName(
  spoken: string,
  sessions: Array<{ name: string; id: string }>
): { id: string; name: string } | null {
  const normalized = spoken.toLowerCase().trim().replace(/\s+/g, '-');

  // 1. Exact match
  const exact = sessions.find(s => s.name === normalized);
  if (exact) return exact;

  // 2. Partial match (spoken is substring)
  const partial = sessions.filter(s => s.name.includes(normalized) || normalized.includes(s.name));
  if (partial.length === 1 && partial[0]) return partial[0];

  // 3. Word match (any word in name matches)
  const words = normalized.split('-');
  const wordMatch = sessions.filter(s => words.some(w => s.name.includes(w)));
  if (wordMatch.length === 1 && wordMatch[0]) return wordMatch[0];

  // 4. Fuzzy (Levenshtein distance <= 2)
  const fuzzy = sessions
    .map(s => ({ ...s, distance: levenshtein(normalized, s.name) }))
    .filter(s => s.distance <= 2)
    .sort((a, b) => a.distance - b.distance);
  const best = fuzzy[0];
  if (best) return { id: best.id, name: best.name };

  return null;
}

function levenshtein(a: string, b: string): number {
  const matrix: number[][] = [];
  for (let i = 0; i <= a.length; i++) matrix[i] = [i];
  for (let j = 0; j <= b.length; j++) matrix[0]![j] = j;
  for (let i = 1; i <= a.length; i++) {
    for (let j = 1; j <= b.length; j++) {
      matrix[i]![j] = Math.min(
        matrix[i - 1]![j]! + 1,
        matrix[i]![j - 1]! + 1,
        matrix[i - 1]![j - 1]! + (a[i - 1] === b[j - 1] ? 0 : 1)
      );
    }
  }
  return matrix[a.length]![b.length]!;
}



export { createVoiceRuntime } from './factory.js';
export type {
