  timersRepo.delete(timer.id);
  console.log('Cleaned up test data');

  // Close database
  closeDatabase();
  console.log('\nDatabase test complete!');
}

main().catch(console.error);



/**
 * Test script for text-based interaction with the voice agent.
 * This allows testing the agent without audio hardware.
 *
 * Usage: npx tsx src/test-text.ts
 */

import * as readline from 'readline';
import { validateConfig } from './config.js';
import { VoiceAgent } from './agent/voice-agent.js';

async function main() {
  console.log('Voice Agent Text Test');
  console.log('======================');
  console.log('This test uses text input/output to verify the agent works.');
  console.log('');

  // Validate configuration
  try {
    validateConfig();
  } catch (error) {
    console.error('Configuration error:', error);
    process.exit(1);
  }

  const agent = new VoiceAgent();

  // Set up event handlers
  agent.on('stateChange', (state, profile) => {
    console.log(`\n[State] ${state}${profile ? ` (${profile})` : ''}`);
  });

  agent.on('transcript', (text, role) => {
    if (role === 'assistant') {
      console.log(`\n[Assistant] ${text}`);
    } else {
      console.log(`\n[User] ${text}`);
    }
  });

  agent.on('audio', (audio) => {
    if (audio.data) {
      console.log(`[Audio] Received ${audio.data.byteLength} bytes (not playing in text mode)`);
    }
  });

  agent.on('error', (error) => {
    console.error('\n[Error]', error.message);
  });

  // Activate with default profile
  console.log('Connecting to Jarvis profile...');
  const success = await agent.activate('jarvis');

  if (!success) {
    console.error('Failed to activate agent');
    process.exit(1);
  }

  console.log('\nAgent activated! Type your messages below.');
  console.log('Commands: /quit to exit, /interrupt to interrupt the agent\n');

  // Set up readline for text input
  const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout,
  });

  const prompt = () => {
    rl.question('You: ', (input) => {
      const trimmed = input.trim();

      if (trimmed === '/quit') {
        console.log('Disconnecting...');
        agent.deactivate();
        rl.close();
        process.exit(0);
      }

      if (trimmed === '/interrupt') {
        agent.interrupt();
        prompt();
        return;
      }

      if (trimmed) {
        agent.sendMessage(trimmed);
      }

      // Give some time for response before prompting again
      setTimeout(prompt, 100);
    });
  };

  prompt();

  // Handle Ctrl+C
  process.on('SIGINT', () => {
    console.log('\nDisconnecting...');
    agent.deactivate();
    rl.close();
    process.exit(0);
  });
}

main().catch((error) => {
  console.error('Fatal error:', error);
  process.exit(1);
});



/**
 * Test script for timer functionality.
 * Run with: npm run test:timer
 */

import { TimersRepository } from './db/index.js';
import { Scheduler, parseTimeExpression, formatTimerResponse } from './scheduler/index.js';
import { speak } from './audio/tts.js';

async function testTimeParser() {
  console.log('\n=== Testing Time Parser ===\n');

  const testCases = [
    'in 5 minutes',
    'in einer Stunde',
    'in 30 Sekunden',
    'at 3pm',
    'um 15 Uhr',
    'um 9:30 Uhr',
    'tomorrow at 9am',
    'morgen um 8 Uhr',
  ];

  for (const expr of testCases) {
    const result = parseTimeExpression(expr);
    if (result) {
      console.log(`"${expr}" → ${result.date.toISOString()} (${result.description})`);
    } else {
      console.log(`"${expr}" → COULD NOT PARSE`);
    }
  }
}

async function testScheduler() {
  console.log('\n=== Testing Scheduler ===\n');

  const timersRepo = new TimersRepository();
  const scheduler = new Scheduler(500); // Check every 500ms for testing

  // Clean up any existing test timers
  const pending = timersRepo.getPending();
  for (const t of pending) {
    if (t.message.startsWith('Test:')) {
      timersRepo.delete(t.id);
    }
  }

  // Create a test timer that fires in 3 seconds
  const timer = timersRepo.create({
    fire_at: new Date(Date.now() + 3000),
    message: 'Test: Drei Sekunden sind vergangen!',
    mode: 'tts',
  });
  console.log(`Created timer #${timer.id}: fires in 3 seconds`);

  // Set up event handler
  scheduler.on('timerFired', async (firedTimer) => {
    console.log(`\n>>> Timer #${firedTimer.id} FIRED: "${firedTimer.message}"`);

    // Speak the message
    try {
      console.log('Speaking message via TTS...');
      await speak(firedTimer.message);
      console.log('TTS complete!');
    } catch (error) {
      console.error('TTS error:', error);
    }

    // Clean up and exit
    scheduler.stop();
    console.log('\nTest complete!');
    process.exit(0);
  });

  // Start scheduler
  scheduler.start();
  console.log('Scheduler started, waiting for timer to fire...\n');

  // Timeout after 10 seconds
  setTimeout(() => {
    console.error('Test timed out!');
    scheduler.stop();
    process.exit(1);
  }, 10000);
}

async function testTimerResponse() {
  console.log('\n=== Testing Timer Response Format ===\n');

  const testCases = [
    { message: 'Pizza aus dem Ofen', minutes: 5 },
    { message: 'Meeting', minutes: 60 },
    { message: 'Wäsche aufhängen', minutes: 90 },
  ];

  for (const { message, minutes } of testCases) {
    const fireAt = new Date(Date.now() + minutes * 60 * 1000);
    const response = formatTimerResponse(message, fireAt);
    console.log(`${minutes}min: "${response}"`);
  }
}

async function main() {
  const args = process.argv.slice(2);

  if (args.includes('--parser')) {
    await testTimeParser();
  } else if (args.includes('--scheduler')) {
    await testScheduler();
  } else if (args.includes('--response')) {
    await testTimerResponse();
  } else {
    // Run all tests
    await testTimeParser();
    await testTimerResponse();
    console.log('\nTo test scheduler with TTS, run: npm run test:timer -- --scheduler');
  }
}

main().catch(console.error);



# OpenAI Realtime Provider Notes

Wraps the `@openai/agents` Realtime SDK for voice-to-voice interaction.

## 1. Code Location

- Adapter: `packages/voice-runtime/src/adapters/openai-sdk-adapter.ts`
- Config parser: `parseOpenAIProviderConfig()` in `provider-config.ts`

## 2. Architecture

The adapter delegates transport management entirely to the OpenAI Realtime SDK (`RealtimeSession` from `@openai/agents/realtime`). The SDK manages WebSocket or WebRTC connections underneath.

```
SessionInput --> RealtimeAgent + RealtimeSession --> OpenAI Realtime API
                      |
                 SDK events --> normalized VoiceSessionEvents
```

## 3. Session Flow

1. `connect()` creates a `RealtimeAgent` with instructions, voice, and tools.
2. Creates a `RealtimeSession` with model, API key, and session config.
3. Calls `session.connect({ apiKey })` to establish the connection.
4. SDK handles the WebSocket handshake and session negotiation.
5. Session events are bound and normalized to `VoiceSessionEvents`.

## 4. Transport

| Property | Value |
|----------|-------|
| Transport kind | SDK-managed (WebSocket default) |
| Input format | PCM16 @ 24kHz |
| Output format | PCM16 @ 24kHz (negotiable via session config) |
| Audio encoding | `pcm16` (also supports `g711_ulaw`, `g711_alaw`) |

The adapter sends GA-style audio config with explicit PCM rate to avoid playback-speed mismatches:

```typescript
audio: {
  input: { format: { type: 'audio/pcm', rate: 24000 } },
  output: { format: { type: 'audio/pcm', rate: 24000 } },
}
```

Output sample rate is updated dynamically from `session.created` / `session.updated` transport events.

## 5. Capabilities

| Capability | Supported | Notes |
|------------|-----------|-------|
| Tool calling | Yes | Via SDK `tool()` wrapper |
| Transcript deltas | Yes | `response.output_audio_transcript.delta` events |
| Interruption | Yes | `session.interrupt()` |
| Usage metrics | Yes | From SDK events |
| Native truncation | Yes | SDK handles on interrupt |
| Tool approval | Yes | `tool_approval_requested` event |
| MCP tools | Yes | Via SDK |
| Ephemeral tokens | Yes | Key passed as ephemeral-compatible value |
| VAD modes | `server`, `semantic`, `manual`, `disabled` |
| Mid-session config update | Yes | `updateConfig()` supported |
| Session resumption | No | |
| Context compression | No | |
| Proactivity | No | |

## 6. VAD / Turn Detection

Turn detection is configured from `SessionInput.vad`:

| VAD Mode | Turn Detection Type | Description |
|----------|-------------------|-------------|
| `semantic` | `semantic_vad` | Context-aware silence detection (default) |
| `server` | `server_vad` | Standard server VAD |
| `manual` | `null` | No automatic turn detection |
| (default) | From `providerConfig.turnDetection` or `semantic_vad` | |

Configurable parameters:
- `silence_duration_ms` -- how long silence triggers a turn
- `threshold` -- VAD sensitivity

## 7. Event Normalization

### SDK Events to VoiceSessionEvents

| SDK Event | Emitted As | Notes |
|-----------|-----------|-------|
| `audio` | `audio` | PCM frames with resolved sample rate |
| `audio_interrupted` | `audioInterrupted` | Barge-in while speaking |
| `audio_stopped` | state -> `listening` | |
| `agent_start` | `turnStarted`, state -> `thinking` | |
| `agent_end` | `turnComplete`, `transcript` (final) | |
| `agent_tool_start` | `toolStart` | Parses callId and args |
| `agent_tool_end` | `toolEnd` | |
| `tool_approval_requested` | Auto-approved | Calls `approve()` |
| `history_updated` | `historyUpdated` | Maps `RealtimeItem[]` to `VoiceHistoryItem[]` |
| `error` | `error` | |

### Transport Events (raw)

| Transport Event | Handling |
|----------------|----------|
| `session.created` / `session.updated` | Updates output sample rate |
| `input_audio_buffer.speech_started` | Emits `audioInterrupted` if speaking, sets state to `listening` |
| `conversation.item.added` | Emits `userItemCreated` or `assistantItemCreated` |
| `response.output_audio_transcript.delta` | Emits `transcriptDelta` for assistant |
| `conversation.item.input_audio_transcription.completed` | Emits `transcript` for user |

## 8. Tools

Tools are wrapped using the SDK's `tool()` helper:

```typescript
tool({
  name: definition.name,
  description: definition.description,
  strict: false,
  parameters: definition.parameters,
  execute: async (rawInput, _context, details) => {
    // calls input.toolHandler(name, args, context)
    return resultString;
  },
});
```

Tool results are returned as strings directly to the SDK, which feeds them back into the conversation.

## 9. Configuration

`OpenAIProviderConfig` fields:

| Field | Default | Description |
|-------|---------|-------------|
| `apiKey` | (required) | OpenAI API key |
| `turnDetection` | `'semantic_vad'` | Turn detection type |
| `transcriptionModel` | `'gpt-4o-mini-transcribe'` | Input audio transcription model |
| `language` | (from `SessionInput`) | Language for transcription |

## 10. Text Input

`sendText()` sends a user message via:

```typescript
session.sendMessage({
  type: 'message',
  role: 'user',
  content: [{ type: 'input_text', text }],
});
```

The `defer` option is logged as a latency event but does not change SDK behavior.



# Ultravox Provider Notes

Ultravox is a voice-to-voice provider using a REST create-call + WebSocket join protocol.

## 1. Code Location

- Adapter: `packages/voice-runtime/src/adapters/ultravox-ws-adapter.ts`
- Config parser: `parseUltravoxProviderConfig()` in `provider-config.ts`

## 2. Session Flow

### REST Create Call

1. `POST {apiBaseUrl}/api/calls` with `X-API-Key` header.
2. Request body includes: model, systemPrompt, voice, medium (sample rates), and selectedTools.
3. Response contains `joinUrl` (or `websocketUrl`) and negotiated sample rates.

### WebSocket Join

4. Open WebSocket to `joinUrl` with `?apiVersion=1`.
5. Set `binaryType = 'arraybuffer'` (audio is raw binary).
6. Wait for `open` event.
7. Bind message handlers and emit `connected`.

### Disconnect

Sends `{ type: 'hang_up' }` before closing the socket.

## 3. Audio Format

| Direction | Default Rate | Negotiable |
|-----------|-------------|------------|
| Input (mic -> Ultravox) | 48kHz | Yes, via `inputSampleRate` |
| Output (Ultravox -> speaker) | 48kHz | Yes, via `outputSampleRate` |
| Preferred client rate | 24kHz | Adapter resamples automatically |

The adapter uses `resamplePcm16Mono()` to convert between client preferred rate (24kHz) and provider rates (typically 48kHz) in both directions.

Binary WebSocket messages are raw PCM16 audio -- no framing or headers.

## 4. Capabilities

| Capability | Supported | Notes |
|------------|-----------|-------|
| Tool calling | Yes | Client-side via `client_tool_invocation` / `client_tool_result` |
| Transcript deltas | Yes | Via ordinal-based accumulation |
| Interruption | Yes | `playback_clear_buffer` messages |
| Server-side tools | Yes | Via `temporaryTool` definitions |
| Precomputable tools | Yes | `precomputable: true` on tool definition |
| Tool reaction | Yes | `SPEAKS` / `LISTENS` / `SPEAKS_ONCE` |
| Tool timeout | Yes | Specified as duration string (e.g., `"5000ms"`) |
| Session resumption | Yes | (not yet implemented in adapter) |
| Force agent message | Yes | `forced_agent_message` with urgency |
| Output medium switch | Yes | `set_output_medium` voice/text |
| Call state | Yes | Via `updateCallState` in tool results |
| Deferred text | Yes | `deferred_text_message` type |
| Call stages | Yes | `new-stage` response type in tool results |
| Ordered transcripts | Yes | Via ordinal numbers |
| VAD | Server-only | |
| Proactivity | No | |
| Usage metrics | No | |
| Ephemeral tokens | No | |

## 5. Server-Side Tools

Tools are sent as `selectedTools` in the create-call payload using the `temporaryTool` format:

```typescript
{
  temporaryTool: {
    modelToolName: 'tool_name',
    description: 'What the tool does',
    dynamicParameters: [{
      name: 'param',
      location: 'PARAMETER_LOCATION_BODY',
      schema: { type: 'string' },
      required: true,
    }],
    client: {},                          // marks as client-executed
    precomputable: true,                 // optional
    timeout: '5000ms',                   // optional
    defaultReaction: 'SPEAKS',           // optional: SPEAKS | LISTENS | SPEAKS_ONCE
  }
}
```

### Tool Reactions

Control what the agent does while waiting for the tool result:

| Reaction | Ultravox Value | Description |
|----------|---------------|-------------|
| `speaks` | `SPEAKS` | Agent continues speaking (default) |
| `listens` | `LISTENS` | Agent waits silently |
| `speaks-once` | `SPEAKS_ONCE` | Agent speaks once then waits |

### Tool Result Protocol

```
Ultravox sends:  { type: 'client_tool_invocation', toolName, invocationId, parameters }
Adapter calls:   toolHandler(toolName, args, context)
Adapter sends:   { type: 'client_tool_result', invocationId, result, responseType, ... }
```

`responseType` values:
- `tool-response` -- normal result
- `tool-error` -- error result
- `new-stage` -- triggers a stage transition

Optional fields in result: `updateCallState`, `errorMessage`, `agentReaction`.

## 6. Ordinal Transcript Normalization

Ultravox uses ordinal numbers to identify transcript turns. The adapter maintains a `transcriptsByOrdinal` map to:

1. Accumulate partial transcripts (deltas or full-text updates).
2. Compute deltas when only full text is provided (not delta).
3. Defer assistant item creation until meaningful text arrives (avoids empty bubbles).
4. Emit user items immediately (even before text, for "You: ..." UI feedback).
5. Emit final `transcript` event with accumulated text when `final: true`.

### Role Mapping

Ultravox may use `role: 'agent'` or `speaker: 'agent'` for assistant messages. The adapter normalizes both to `'assistant'`.

## 7. WebSocket Message Types

### Incoming (Ultravox -> Adapter)

| Type | Description |
|------|-------------|
| `state` | Voice state: listening/thinking/speaking |
| `transcript` | Text transcript with ordinal, delta/text, final flag |
| `playback_clear_buffer` | Interruption -- clear audio buffer |
| `client_tool_invocation` | Tool call request |
| (binary) | Raw PCM16 audio data |

### Outgoing (Adapter -> Ultravox)

| Type | Description |
|------|-------------|
| `input_text_message` | Text input from user |
| `deferred_text_message` | Deferred text (context, not immediate) |
| `client_tool_result` | Tool execution result |
| `set_output_medium` | Switch between voice and text output |
| `forced_agent_message` | Force agent to speak specific text |
| `hang_up` | End the call |
| (binary) | Raw PCM16 audio input |

## 8. Configuration

`UltravoxProviderConfig` fields:

| Field | Default | Description |
|-------|---------|-------------|
| `apiKey` | (required) | Ultravox API key (`X-API-Key` header) |
| `apiBaseUrl` | `'https://api.ultravox.ai'` | API base URL |
| `model` | From `SessionInput.model` | Ultravox model name |
| `voice` | From `SessionInput.voice` | Voice identifier |
| `inputSampleRate` | 48000 | Audio input sample rate |
| `outputSampleRate` | 48000 | Audio output sample rate |
| `clientBufferSizeMs` | 30000 | Client-side audio buffer size |



import { encodeWavPcm16Mono } from '../decomposed-utils.js';
import type { SttTranscriptionInput } from './types.js';

export interface DeepgramListenResponse {
  results?: {
    channels?: Array<{
      alternatives?: Array<{
        transcript?: string;
      }>;
    }>;
  };
}

export async function transcribeWithDeepgram(input: SttTranscriptionInput): Promise {
  const { pcm, context } = input;
  if (!context.deepgramApiKey) {
    throw new Error('Deepgram API key is missing for decomposed STT');
  }

  const wav = encodeWavPcm16Mono(pcm, context.sampleRate);
  const url = new URL('https://api.deepgram.com/v1/listen');
  url.searchParams.set('model', context.model || 'nova-3');
  url.searchParams.set('language', context.language);
  url.searchParams.set('smart_format', 'true');

  const response = await fetch(url, {
    method: 'POST',
    headers: {
      Authorization: `Token ${context.deepgramApiKey}`,
      'Content-Type': 'audio/wav',
    },
    body: wav,
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`Deepgram STT failed (${response.status}): ${errorText}`);
  }

  const payload = (await response.json()) as DeepgramListenResponse;
  return payload.results?.channels?.[0]?.alternatives?.[0]?.transcript?.trim() ?? '';
}



import { transcribeWithDeepgram } from './deepgram-stt.js';
import { transcribeWithLocal } from './local-stt.js';
import { transcribeWithOpenAI } from './openai-stt.js';
import type {
  DecomposedSttProvider,
  SttProviderDefinition,
  SttTranscriptionInput,
} from './types.js';

const PROVIDERS: Record = {
  openai: {
    id: 'openai',
    transcribe: transcribeWithOpenAI,
  },
  deepgram: {
    id: 'deepgram',
    transcribe: transcribeWithDeepgram,
  },
  local: {
    id: 'local',
    transcribe: transcribeWithLocal,
  },
};

export function getSttProviderDefinition(provider: DecomposedSttProvider): SttProviderDefinition {
  return PROVIDERS[provider];
}

export async function transcribeStt(input: SttTranscriptionInput): Promise {
  const provider = getSttProviderDefinition(input.context.provider);
  return provider.transcribe(input);
}



import { encodeWavPcm16Mono } from '../decomposed-utils.js';
import type { SttTranscriptionInput } from './types.js';

export async function transcribeWithLocal(input: SttTranscriptionInput): Promise {
  const { pcm, context } = input;
  const wav = encodeWavPcm16Mono(pcm, context.sampleRate);
  const endpoint = new URL('/v1/audio/transcriptions', context.localEndpoint);
  endpoint.searchParams.set('model', context.model);
  endpoint.searchParams.set('language', context.language);

  const response = await fetch(endpoint, {
    method: 'POST',
    headers: {
      'Content-Type': 'audio/wav',
    },
    body: wav,
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`Local STT failed (${response.status}): ${errorText}`);
  }

  const payload = (await response.json()) as { text?: string };
  return payload.text?.trim() ?? '';
}



import { encodeWavPcm16Mono } from '../decomposed-utils.js';
import type { SttTranscriptionInput } from './types.js';

export async function transcribeWithOpenAI(input: SttTranscriptionInput): Promise {
  const { pcm, context } = input;
  if (!context.openaiApiKey) {
    throw new Error('OpenAI API key is missing for decomposed STT');
  }

  const wav = encodeWavPcm16Mono(pcm, context.sampleRate);
  const form = new FormData();
  form.append('file', new File([wav], 'speech.wav', { type: 'audio/wav' }));
  form.append('model', context.model);
  if (context.language) {
    form.append('language', context.language);
  }

  const response = await fetch('https://api.openai.com/v1/audio/transcriptions', {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${context.openaiApiKey}`,
    },
    body: form,
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`OpenAI STT failed (${response.status}): ${errorText}`);
  }

  const payload = (await response.json()) as { text?: string };
  return payload.text?.trim() ?? '';
}



export const DECOMPOSED_STT_PROVIDERS = ['openai', 'deepgram', 'local'] as const;

export type DecomposedSttProvider = (typeof DECOMPOSED_STT_PROVIDERS)[number];

export interface SttProviderContext {
  provider: DecomposedSttProvider;
  model: string;
  language: string;
  sampleRate: number;
  openaiApiKey?: string;
  deepgramApiKey?: string;
  localEndpoint: string;
}

export interface SttTranscriptionInput {
  pcm: Uint8Array;
  context: SttProviderContext;
}

export type SttTranscriber = (input: SttTranscriptionInput) => Promise;

export interface SttProviderDefinition {
  id: DecomposedSttProvider;
  transcribe: SttTranscriber;
}



import { clampNumber, roundTo } from '../decomposed-utils.js';

const LOCAL_QWEN_ADAPTIVE_START_BUFFER_MIN_MS = 120;
const LOCAL_QWEN_ADAPTIVE_START_BUFFER_MAX_MS = 4000;
const LOCAL_QWEN_ADAPTIVE_START_BUFFER_DEFAULT_MS = 220;
const LOCAL_QWEN_ADAPTIVE_START_BUFFER_WAIT_CAP_MS = 4500;
const LOCAL_QWEN_ADAPTIVE_LEAD_TARGET_MS = 220;
const LOCAL_QWEN_ADAPTIVE_INTERVAL_MIN = 0.6;
const LOCAL_QWEN_ADAPTIVE_INTERVAL_MAX = 4.0;
const LOCAL_QWEN_ADAPTIVE_INTERVAL_STEP = 0.1;
export const LOCAL_QWEN_ADAPTIVE_UNDERRUN_THRESHOLD_MS = -40;
const LOCAL_QWEN_ADAPTIVE_BOOTSTRAP_INTERVAL_MULTIPLIER = 2.0;
const LOCAL_QWEN_ADAPTIVE_RTF_EMA_ALPHA = 0.35;
const LOCAL_QWEN_ADAPTIVE_AUDIO_MS_PER_CHAR_DEFAULT = 60;
const LOCAL_QWEN_ADAPTIVE_AUDIO_MS_PER_CHAR_MIN = 16;
const LOCAL_QWEN_ADAPTIVE_AUDIO_MS_PER_CHAR_MAX = 220;
const LOCAL_QWEN_ADAPTIVE_AUDIO_MS_PER_CHAR_EMA_ALPHA = 0.25;

export interface AdaptiveSegmentState {
  startupBufferMs: number;
  intervalSec: number;
  released: boolean;
  releaseAtMs: number | null;
  emittedSinceReleaseMs: number;
  startupBufferedAudioMs: number;
  predictedSegmentAudioMs: number;
  queuedChunks: Array<{ chunk: ArrayBuffer; audioMs: number; arrivedAtMs: number }>;
}

export interface AdaptiveChunkArrivalMetrics {
  producerAudioMs: number;
  producerElapsedMs: number;
  elapsedSinceFirstChunkMs: number;
}

export interface AdaptiveSegmentCompletionMetrics {
  state: AdaptiveSegmentState;
  text: string;
  emittedPlaybackMs: number;
  producerAudioMs: number;
  producerElapsedMs: number;
  cumulativeGapDeficitMs: number;
  finalPlayoutLeadMs: number;
  chunksWithGapDeficit: number;
}

export interface AdaptiveSegmentUpdate {
  producerRtf: number;
  suggestedStartupBufferMs: number;
  requiredBufferFromRtfEma: number;
  nextStreamingIntervalSec: number;
  nextStartupBufferMs: number;
  adaptiveProducerRtfEma: number;
  adaptiveAudioMsPerChar: number;
}

export class AdaptiveUnderrunController {
  private startBufferMs = LOCAL_QWEN_ADAPTIVE_START_BUFFER_DEFAULT_MS;
  private intervalSec = 1.0;
  private producerRtfEma = 1.0;
  private audioMsPerChar = LOCAL_QWEN_ADAPTIVE_AUDIO_MS_PER_CHAR_DEFAULT;

  reset(configuredIntervalSec: number): void {
    this.startBufferMs = LOCAL_QWEN_ADAPTIVE_START_BUFFER_DEFAULT_MS;
    this.intervalSec = configuredIntervalSec;
    this.producerRtfEma = 1.0;
    this.audioMsPerChar = LOCAL_QWEN_ADAPTIVE_AUDIO_MS_PER_CHAR_DEFAULT;
  }

  getStreamingIntervalSec(): number {
    return this.intervalSec;
  }

  createSegmentState(input: {
    enabled: boolean;
    text: string;
    configuredIntervalSec: number;
  }): AdaptiveSegmentState | null {
    if (!input.enabled) {
      return null;
    }

    const configuredIntervalMs =
      clampNumber(
        input.configuredIntervalSec,
        LOCAL_QWEN_ADAPTIVE_INTERVAL_MIN,
        LOCAL_QWEN_ADAPTIVE_INTERVAL_MAX
      ) * 1000;
    const predictedSegmentAudioMs = Math.max(
      LOCAL_QWEN_ADAPTIVE_START_BUFFER_DEFAULT_MS * 2,
      Math.round(input.text.length * this.audioMsPerChar)
    );
    const predictedDeficitMsFromEma =
      Math.max(0, this.producerRtfEma - 1) * predictedSegmentAudioMs;
    const startupFloorFromIntervalMs = Math.round(
      configuredIntervalMs * LOCAL_QWEN_ADAPTIVE_BOOTSTRAP_INTERVAL_MULTIPLIER
    );

    return {
      startupBufferMs: clampNumber(
        Math.max(
          this.startBufferMs,
          startupFloorFromIntervalMs,
          Math.round(LOCAL_QWEN_ADAPTIVE_LEAD_TARGET_MS + predictedDeficitMsFromEma)
        ),
        LOCAL_QWEN_ADAPTIVE_START_BUFFER_MIN_MS,
        LOCAL_QWEN_ADAPTIVE_START_BUFFER_MAX_MS
      ),
      intervalSec: clampNumber(
        this.intervalSec,
        LOCAL_QWEN_ADAPTIVE_INTERVAL_MIN,
        LOCAL_QWEN_ADAPTIVE_INTERVAL_MAX
      ),
      released: false,
      releaseAtMs: null,
      emittedSinceReleaseMs: 0,
      startupBufferedAudioMs: 0,
      predictedSegmentAudioMs,
      queuedChunks: [],
    };
  }

  handleChunkArrival(
    state: AdaptiveSegmentState,
    metrics: AdaptiveChunkArrivalMetrics
  ): { shouldRelease: boolean; startupWaitCapMs: number } {
    const producerRtf =
      metrics.producerAudioMs > 0 ? metrics.producerElapsedMs / metrics.producerAudioMs : 0;
    const projectedDeficitMs =
      Math.max(0, producerRtf - 1) * state.predictedSegmentAudioMs;
    const targetFromRtf = LOCAL_QWEN_ADAPTIVE_LEAD_TARGET_MS + projectedDeficitMs;

    state.startupBufferMs = clampNumber(
      Math.round(state.startupBufferMs * 0.6 + targetFromRtf * 0.4),
      LOCAL_QWEN_ADAPTIVE_START_BUFFER_MIN_MS,
      LOCAL_QWEN_ADAPTIVE_START_BUFFER_MAX_MS
    );

    const startupWaitCapMs = Math.min(
      LOCAL_QWEN_ADAPTIVE_START_BUFFER_WAIT_CAP_MS,
      Math.max(1200, Math.round(state.startupBufferMs + 400))
    );

    const shouldRelease =
      state.startupBufferedAudioMs >= state.startupBufferMs ||
      metrics.elapsedSinceFirstChunkMs >= startupWaitCapMs;

    return {
      shouldRelease,
      startupWaitCapMs,
    };
  }

  updateAfterSegment(metrics: AdaptiveSegmentCompletionMetrics): AdaptiveSegmentUpdate {
    const producerRtf =
      metrics.producerAudioMs > 0 ? metrics.producerElapsedMs / metrics.producerAudioMs : 0;

    this.producerRtfEma = roundTo(
      clampNumber(
        this.producerRtfEma * (1 - LOCAL_QWEN_ADAPTIVE_RTF_EMA_ALPHA) +
          producerRtf * LOCAL_QWEN_ADAPTIVE_RTF_EMA_ALPHA,
        0.7,
        3.0
      ),
      3
    );

    if (metrics.text.length > 0 && metrics.emittedPlaybackMs > 0) {
      const observedAudioMsPerChar = metrics.emittedPlaybackMs / metrics.text.length;
      this.audioMsPerChar = roundTo(
        clampNumber(
          this.audioMsPerChar * (1 - LOCAL_QWEN_ADAPTIVE_AUDIO_MS_PER_CHAR_EMA_ALPHA) +
            observedAudioMsPerChar * LOCAL_QWEN_ADAPTIVE_AUDIO_MS_PER_CHAR_EMA_ALPHA,
          LOCAL_QWEN_ADAPTIVE_AUDIO_MS_PER_CHAR_MIN,
          LOCAL_QWEN_ADAPTIVE_AUDIO_MS_PER_CHAR_MAX
        ),
        2
      );
    }

    const requiredBufferFromDeficit =
      metrics.cumulativeGapDeficitMs + LOCAL_QWEN_ADAPTIVE_LEAD_TARGET_MS;
    const requiredBufferFromRtf =
      producerRtf > 1
        ? (producerRtf - 1) * metrics.emittedPlaybackMs + LOCAL_QWEN_ADAPTIVE_LEAD_TARGET_MS
        : LOCAL_QWEN_ADAPTIVE_LEAD_TARGET_MS;
    const projectedNextAudioMs = Math.max(
      LOCAL_QWEN_ADAPTIVE_START_BUFFER_DEFAULT_MS * 2,
      Math.round(metrics.text.length * this.audioMsPerChar)
    );
    const requiredBufferFromRtfEma =
      Math.max(0, this.producerRtfEma - 1) * projectedNextAudioMs +
      LOCAL_QWEN_ADAPTIVE_LEAD_TARGET_MS;
    const suggestedStartupBufferMs = Math.max(
      LOCAL_QWEN_ADAPTIVE_START_BUFFER_MIN_MS,
      requiredBufferFromDeficit,
      requiredBufferFromRtf,
      requiredBufferFromRtfEma
    );

    this.startBufferMs = clampNumber(
      Math.round(this.startBufferMs * 0.25 + suggestedStartupBufferMs * 0.75),
      LOCAL_QWEN_ADAPTIVE_START_BUFFER_MIN_MS,
      LOCAL_QWEN_ADAPTIVE_START_BUFFER_MAX_MS
    );

    if (
      metrics.chunksWithGapDeficit === 0 &&
      producerRtf < 0.95 &&
      metrics.finalPlayoutLeadMs > LOCAL_QWEN_ADAPTIVE_LEAD_TARGET_MS * 2
    ) {
      this.startBufferMs = clampNumber(
        this.startBufferMs - 40,
        LOCAL_QWEN_ADAPTIVE_START_BUFFER_MIN_MS,
        LOCAL_QWEN_ADAPTIVE_START_BUFFER_MAX_MS
      );
    }

    const baseInterval = clampNumber(
      metrics.state.intervalSec,
      LOCAL_QWEN_ADAPTIVE_INTERVAL_MIN,
      LOCAL_QWEN_ADAPTIVE_INTERVAL_MAX
    );
    const intervalMin = Math.max(
      LOCAL_QWEN_ADAPTIVE_INTERVAL_MIN,
      roundTo(baseInterval - 0.25, 2)
    );
    const intervalMax = Math.min(
      LOCAL_QWEN_ADAPTIVE_INTERVAL_MAX,
      roundTo(baseInterval + 2.0, 2)
    );

    const gapPressure =
      metrics.emittedPlaybackMs > 0 ? metrics.cumulativeGapDeficitMs / metrics.emittedPlaybackMs : 0;
    const rtfPressure = Math.max(0, producerRtf - 1);
    const increaseBy = Math.min(
      0.45,
      Math.max(LOCAL_QWEN_ADAPTIVE_INTERVAL_STEP, rtfPressure * 0.9 + gapPressure * 0.8)
    );
    const adjustedInterval =
      metrics.chunksWithGapDeficit > 0 || producerRtf > 1.01
        ? metrics.state.intervalSec + increaseBy
        : metrics.chunksWithGapDeficit === 0 && producerRtf < 0.9
          ? metrics.state.intervalSec - LOCAL_QWEN_ADAPTIVE_INTERVAL_STEP
          : metrics.state.intervalSec;

    this.intervalSec = roundTo(clampNumber(adjustedInterval, intervalMin, intervalMax), 2);

    return {
      producerRtf,
      suggestedStartupBufferMs,
      requiredBufferFromRtfEma,
      nextStreamingIntervalSec: this.intervalSec,
      nextStartupBufferMs: Math.round(this.startBufferMs),
      adaptiveProducerRtfEma: this.producerRtfEma,
      adaptiveAudioMsPerChar: this.audioMsPerChar,
    };
  }
}



export const AUDIO_SAMPLE_RATE = 24000;
export const PCM_BYTES_PER_100MS = (AUDIO_SAMPLE_RATE * 2) / 10;

interface StreamPcmResponseOptions {
  passthroughChunks?: boolean;
  minChunkBytes?: number;
}

export function chunkArrayBuffer(input: ArrayBuffer, chunkSize: number): ArrayBuffer[] {
  const bytes = new Uint8Array(input);
  const chunks: ArrayBuffer[] = [];
  for (let offset = 0; offset < bytes.byteLength; offset += chunkSize) {
    const end = Math.min(offset + chunkSize, bytes.byteLength);
    chunks.push(bytes.slice(offset, end).buffer);
  }
  return chunks;
}

export async function streamPcmResponse(
  response: Response,
  emitChunk: (chunk: ArrayBuffer) => Promise,
  options?: StreamPcmResponseOptions
): Promise {
  const passthroughChunks = options?.passthroughChunks === true;
  const minChunkBytes = Math.max(2, options?.minChunkBytes ?? PCM_BYTES_PER_100MS);
  const evenMinChunkBytes = minChunkBytes % 2 === 0 ? minChunkBytes : minChunkBytes + 1;

  if (!response.body) {
    let audio = await response.arrayBuffer();
    if (audio.byteLength % 2 !== 0) {
      // PCM16 requires an even number of bytes; drop trailing partial sample.
      audio = audio.slice(0, audio.byteLength - 1);
    }
    const chunks = passthroughChunks
      ? [audio]
      : chunkArrayBuffer(audio, evenMinChunkBytes);
    for (const chunk of chunks) {
      const keepGoing = await emitChunk(chunk);
      if (!keepGoing) {
        break;
      }
    }
    return;
  }

  const reader = response.body.getReader();
  let pending = new Uint8Array(0);

  const appendPending = (value: Uint8Array): void => {
    if (value.byteLength === 0) return;
    if (pending.byteLength === 0) {
      pending = value.slice();
      return;
    }
    const merged = new Uint8Array(pending.byteLength + value.byteLength);
    merged.set(pending, 0);
    merged.set(value, pending.byteLength);
    pending = merged;
  };

  const flushPending = async (force: boolean): Promise => {
    if (passthroughChunks) {
      const emitBytes = pending.byteLength - (pending.byteLength % 2);
      if (emitBytes > 0) {
        const chunk = pending.slice(0, emitBytes);
        pending = pending.slice(emitBytes);
        const keepGoing = await emitChunk(chunk.buffer);
        if (!keepGoing) {
          return false;
        }
      }
      if (force && pending.byteLength > 0) {
        // Keep transport resilient: discard trailing partial PCM16 sample.
        pending = new Uint8Array(0);
      }
      return true;
    }

    while (pending.byteLength >= evenMinChunkBytes || (force && pending.byteLength > 0)) {
      const chunkSize =
        pending.byteLength >= evenMinChunkBytes ? evenMinChunkBytes : pending.byteLength;
      const evenChunkSize = chunkSize - (chunkSize % 2);
      if (evenChunkSize <= 0) {
        break;
      }
      const chunk = pending.slice(0, evenChunkSize);
      pending = pending.slice(evenChunkSize);
      const keepGoing = await emitChunk(chunk.buffer);
      if (!keepGoing) {
        return false;
      }
    }
    if (force && pending.byteLength > 0) {
      // Keep transport resilient: discard trailing partial PCM16 sample.
      pending = new Uint8Array(0);
    }
    return true;
  };

  try {
    while (true) {
      const { done, value } = await reader.read();
      if (done) {
        break;
      }
      if (!value || value.byteLength === 0) {
        continue;
      }
      if (passthroughChunks) {
        appendPending(value);
        const keepGoing = await flushPending(false);
        if (!keepGoing) {
          await reader.cancel();
          break;
        }
        continue;
      }
      appendPending(value);
      const keepGoing = await flushPending(false);
      if (!keepGoing) {
        await reader.cancel();
        break;
      }
    }
    await flushPending(true);
  } finally {
    reader.releaseLock();
  }
}

export function decodeBase64ToArrayBuffer(value: string): ArrayBuffer {
  const bytes = Buffer.from(value, 'base64');
  const output = new Uint8Array(bytes.byteLength);
  output.set(bytes);
  return output.buffer;
}

export function stripWavHeader(audio: ArrayBuffer): ArrayBuffer {
  const bytes = new Uint8Array(audio);
  if (bytes.byteLength < 44) {
    return audio;
  }

  const riff = String.fromCharCode(bytes[0] ?? 0, bytes[1] ?? 0, bytes[2] ?? 0, bytes[3] ?? 0);
  const wave = String.fromCharCode(
    bytes[8] ?? 0,
    bytes[9] ?? 0,
    bytes[10] ?? 0,
    bytes[11] ?? 0
  );
  if (riff !== 'RIFF' || wave !== 'WAVE') {
    return audio;
  }

  const dataOffset = findWavDataOffset(bytes);
  if (dataOffset < 0 || dataOffset >= bytes.byteLength) {
    return audio;
  }

  return bytes.slice(dataOffset).buffer;
}

function findWavDataOffset(bytes: Uint8Array): number {
  let offset = 12;
  while (offset + 8 <= bytes.byteLength) {
    const chunkId = String.fromCharCode(
      bytes[offset] ?? 0,
      bytes[offset + 1] ?? 0,
      bytes[offset + 2] ?? 0,
      bytes[offset + 3] ?? 0
    );
    const sizeView = new DataView(bytes.buffer, bytes.byteOffset + offset + 4, 4);
    const chunkSize = sizeView.getUint32(0, true);
    if (chunkId === 'data') {
      return offset + 8;
    }

    const paddedSize = chunkSize + (chunkSize % 2);
    offset += 8 + paddedSize;
  }

  return -1;
}



import WebSocket from 'ws';
import type { SpokenWordTimestamp } from '../../types.js';
import { decodeBase64ToArrayBuffer } from './audio-utils.js';
import type { SegmentSynthesisInput, SegmentSynthesisResult } from './types.js';

const CARTESIA_DEFAULT_VERSION = '2025-04-16';
const CARTESIA_REQUIRED_PATH = '/tts/websocket';

interface CartesiaEnvelope {
  type?: unknown;
  data?: unknown;
  error?: unknown;
  message?: unknown;
  word_timestamps?: unknown;
}

interface CartesiaWordTimestampsPayload {
  words?: unknown;
  start?: unknown;
  end?: unknown;
}

export async function synthesizeCartesiaSegment(
  input: SegmentSynthesisInput
): Promise {
  const { context, text, emitChunk, signal } = input;
  if (!context.cartesiaApiKey) {
    throw new Error('Cartesia API key is missing for decomposed TTS provider cartesia');
  }
  if (signal.aborted) {
    throw createAbortError();
  }

  const endpoint = normalizeCartesiaWsEndpoint(context.cartesiaTtsWsUrl);
  const cartesiaVersion = resolveCartesiaVersion(endpoint);
  const contextId = randomContextId();
  const wordTimestamps: SpokenWordTimestamp[] = [];
  const dedupeWordTimestamps = new Set();

  await new Promise((resolve, reject) => {
    let settled = false;
    let doneReceived = false;
    let stopRequested = false;
    let requestSent = false;
    let audioPipeline: Promise = Promise.resolve();

    const socket = new WebSocket(endpoint.toString(), {
      headers: {
        Authorization: `Bearer ${context.cartesiaApiKey}`,
        'cartesia-version': cartesiaVersion,
      },
    });

    const closeSocket = (): void => {
      if (
        socket.readyState === WebSocket.CLOSING
        || socket.readyState === WebSocket.CLOSED
      ) {
        return;
      }
      try {
        socket.close();
      } catch {
        // ignore close failures
      }
    };

    const cleanup = (): void => {
      signal.removeEventListener('abort', onAbort);
      socket.off('open', onOpen);
      socket.off('message', onMessage);
      socket.off('error', onError);
      socket.off('close', onClose);
    };

    const resolveOnce = (): void => {
      if (settled) return;
      settled = true;
      cleanup();
      resolve();
    };

    const rejectOnce = (error: unknown): void => {
      if (settled) return;
      settled = true;
      cleanup();
      reject(toError(error, 'Cartesia websocket TTS failed'));
    };

    const resolveAfterAudioDrain = (): void => {
      void audioPipeline.then(resolveOnce).catch((error) => {
        closeSocket();
        rejectOnce(error);
      });
    };

    const onAbort = (): void => {
      stopRequested = true;
      closeSocket();
      rejectOnce(createAbortError());
    };

    const onOpen = (): void => {
      if (signal.aborted) {
        onAbort();
        return;
      }

      const request = {
        model_id: context.model,
        voice: {
          mode: 'id',
          id: context.voice,
        },
        output_format: {
          container: 'raw',
          encoding: 'pcm_s16le',
          sample_rate: 24000,
        },
        transcript: text,
        context_id: contextId,
        continue: false,
        add_timestamps: true,
      };

      try {
        socket.send(JSON.stringify(request));
        requestSent = true;
      } catch (error) {
        closeSocket();
        rejectOnce(error);
      }
    };

    const onMessage = (raw: WebSocket.RawData): void => {
      if (settled || stopRequested) {
        return;
      }

      const payload = rawDataToString(raw);
      if (!payload) {
        return;
      }

      let message: CartesiaEnvelope;
      try {
        message = JSON.parse(payload) as CartesiaEnvelope;
      } catch (error) {
        closeSocket();
        rejectOnce(
          toError(
            error,
            `Cartesia websocket returned a non-JSON message: ${payload.slice(0, 120)}`
          )
        );
        return;
      }

      const eventType = typeof message.type === 'string' ? message.type : '';
      if (eventType === 'chunk') {
        if (typeof message.data !== 'string' || message.data.length === 0) {
          return;
        }
        let chunk: ArrayBuffer;
        try {
          chunk = decodeBase64ToArrayBuffer(message.data);
        } catch (error) {
          closeSocket();
          rejectOnce(toError(error, 'Cartesia websocket chunk decode failed'));
          return;
        }

        audioPipeline = audioPipeline
          .then(async () => {
            if (settled || stopRequested || signal.aborted) {
              return;
            }
            const keepGoing = await emitChunk(chunk);
            if (!keepGoing) {
              stopRequested = true;
              closeSocket();
              resolveOnce();
            }
          })
          .catch((error) => {
            stopRequested = true;
            closeSocket();
            rejectOnce(toError(error, 'Cartesia websocket chunk emit failed'));
          });
        return;
      }

      if (eventType === 'timestamps') {
        appendProviderWordTimestamps(
          message.word_timestamps,
          wordTimestamps,
          dedupeWordTimestamps
        );
        return;
      }

      if (eventType === 'error') {
        closeSocket();
        rejectOnce(new Error(resolveCartesiaErrorMessage(message)));
        return;
      }

      if (eventType === 'done') {
        doneReceived = true;
        closeSocket();
        resolveAfterAudioDrain();
      }
    };

    const onError = (event: Error): void => {
      closeSocket();
      rejectOnce(toError(event, 'Cartesia websocket TTS connection error'));
    };

    const onClose = (code: number, reason: Buffer): void => {
      if (settled) {
        return;
      }
      if (stopRequested || signal.aborted) {
        return;
      }
      if (doneReceived) {
        resolveAfterAudioDrain();
        return;
      }

      const reasonText = normalizeCloseReason(reason);
      const phase = requestSent ? 'before completion' : 'before request send';
      rejectOnce(
        new Error(
          `Cartesia websocket closed ${phase} (code ${code})${reasonText ? `: ${reasonText}` : ''}`
        )
      );
    };

    signal.addEventListener('abort', onAbort, { once: true });
    socket.on('open', onOpen);
    socket.on('message', onMessage);
    socket.on('error', onError);
    socket.on('close', onClose);
  });

  if (wordTimestamps.length === 0) {
    return { precision: 'segment' };
  }

  return {
    precision: 'provider-word-timestamps',
    wordTimestamps,
    wordTimestampsTimeBase: 'segment',
  };
}

function normalizeCartesiaWsEndpoint(rawUrl: string): URL {
  const endpoint = new URL(rawUrl);
  if (endpoint.protocol === 'https:') {
    endpoint.protocol = 'wss:';
  } else if (endpoint.protocol === 'http:') {
    endpoint.protocol = 'ws:';
  }

  const normalizedPath = endpoint.pathname.replace(/\/+$/, '');
  if (normalizedPath.endsWith(CARTESIA_REQUIRED_PATH)) {
    endpoint.pathname = normalizedPath;
    return endpoint;
  }
  endpoint.pathname = `${normalizedPath}${CARTESIA_REQUIRED_PATH}`;
  return endpoint;
}

function resolveCartesiaVersion(endpoint: URL): string {
  const versionFromQuery =
    endpoint.searchParams.get('cartesia_version')
    ?? endpoint.searchParams.get('cartesia-version');
  return versionFromQuery || CARTESIA_DEFAULT_VERSION;
}

function randomContextId(): string {
  if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
    return crypto.randomUUID();
  }
  return `ctx-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 10)}`;
}

function rawDataToString(raw: WebSocket.RawData): string {
  if (typeof raw === 'string') {
    return raw;
  }
  if (raw instanceof ArrayBuffer) {
    return Buffer.from(raw).toString('utf8');
  }
  if (ArrayBuffer.isView(raw)) {
    return Buffer.from(raw.buffer, raw.byteOffset, raw.byteLength).toString('utf8');
  }
  if (Array.isArray(raw)) {
    const buffers: Buffer[] = [];
    for (const chunk of raw) {
      if (chunk instanceof ArrayBuffer) {
        buffers.push(Buffer.from(chunk));
        continue;
      }
      if (ArrayBuffer.isView(chunk)) {
        buffers.push(Buffer.from(chunk.buffer, chunk.byteOffset, chunk.byteLength));
      }
    }
    return Buffer.concat(buffers).toString('utf8');
  }
  return '';
}

function appendProviderWordTimestamps(
  payload: unknown,
  target: SpokenWordTimestamp[],
  dedupe: Set
): void {
  if (!payload || typeof payload !== 'object') {
    return;
  }

  const wordTimestamps = payload as CartesiaWordTimestampsPayload;
  if (
    !Array.isArray(wordTimestamps.words)
    || !Array.isArray(wordTimestamps.start)
    || !Array.isArray(wordTimestamps.end)
  ) {
    return;
  }

  const count = Math.min(
    wordTimestamps.words.length,
    wordTimestamps.start.length,
    wordTimestamps.end.length
  );

  for (let index = 0; index < count; index += 1) {
    const rawWord = wordTimestamps.words[index];
    if (typeof rawWord !== 'string') {
      continue;
    }
    const word = rawWord.trim();
    if (!word) {
      continue;
    }

    const startMs = toMilliseconds(wordTimestamps.start[index]);
    if (startMs === null) {
      continue;
    }
    const endRawMs = toMilliseconds(wordTimestamps.end[index]);
    const endMs = Math.max(startMs, endRawMs ?? startMs);
    const key = `${word}|${startMs}|${endMs}`;
    if (dedupe.has(key)) {
      continue;
    }

    dedupe.add(key);
    target.push({
      word,
      startMs,
      endMs,
    });
  }
}

function toMilliseconds(value: unknown): number | null {
  if (typeof value !== 'number' || !Number.isFinite(value)) {
    return null;
  }
  return Math.max(0, value * 1000);
}

function resolveCartesiaErrorMessage(message: CartesiaEnvelope): string {
  if (typeof message.error === 'string' && message.error) {
    return `Cartesia websocket TTS error: ${message.error}`;
  }
  if (typeof message.message === 'string' && message.message) {
    return `Cartesia websocket TTS error: ${message.message}`;
  }
  if (message.error && typeof message.error === 'object') {
    const nested = message.error as { message?: unknown; error?: unknown };
    if (typeof nested.message === 'string' && nested.message) {
      return `Cartesia websocket TTS error: ${nested.message}`;
    }
    if (typeof nested.error === 'string' && nested.error) {
      return `Cartesia websocket TTS error: ${nested.error}`;
    }
  }
  return 'Cartesia websocket TTS returned an unknown error event';
}

function normalizeCloseReason(reason: Buffer): string {
  if (!reason || reason.byteLength === 0) {
    return '';
  }
  return reason.toString('utf8').trim();
}

function toError(error: unknown, fallback: string): Error {
  if (error instanceof Error) {
    return error;
  }
  if (typeof error === 'string' && error) {
    return new Error(error);
  }
  return new Error(fallback);
}

function createAbortError(): Error {
  if (typeof DOMException !== 'undefined') {
    return new DOMException('The operation was aborted', 'AbortError');
  }
  const error = new Error('The operation was aborted');
  error.name = 'AbortError';
  return error;
}



import { createClient, LiveTTSEvents, type SpeakLiveClient } from '@deepgram/sdk';
import { DecomposedSpokenWordBuffer } from '../decomposed-spoken-buffer.js';
import {
  DEEPGRAM_FLUSH_FALLBACK_FORCE_MS,
  DEEPGRAM_FLUSH_FALLBACK_IDLE_MS,
  DEEPGRAM_FLUSH_FALLBACK_POLL_MS,
  countWords,
  detectSpeechOnsetInChunk,
  shouldFlushDeepgramStream,
  sleep,
  toRawDataUint8Array,
} from '../decomposed-utils.js';
import { AUDIO_SAMPLE_RATE, PCM_BYTES_PER_100MS, chunkArrayBuffer } from './audio-utils.js';

export interface DeepgramTtsConnectionOptions {
  apiKey?: string;
  model: string;
  endpoint: string;
}

export interface DeepgramStreamingOptions extends DeepgramTtsConnectionOptions {
  ttsProvider: string;
  punctuationChunkingEnabled: boolean;
  spokenStreamEnabled: boolean;
}

export interface DeepgramStreamingLatencyMetric {
  stage: 'stt' | 'llm' | 'tts' | 'turn' | 'tool';
  durationMs: number;
  provider?: string;
  model?: string;
  details?: Record;
}

export interface DeepgramStreamingSpokenMeta {
  spokenChars?: number;
  spokenWords?: number;
  playbackMs?: number;
  speechOnsetMs?: number;
  precision?: 'segment';
  wordTimestamps?: Array<{ word: string; startMs: number; endMs: number }>;
  wordTimestampsTimeBase?: 'segment' | 'utterance';
}

export interface DeepgramStreamingContext {
  connectionManager: DeepgramConnectionManager;
  options: DeepgramStreamingOptions;
  isTurnCurrent: () => boolean;
  setSpeaking: () => void;
  setListening: () => void;
  trackAssistantOutput: (chunk: ArrayBuffer) => void;
  emitAudio: (chunk: ArrayBuffer) => void;
  emitError: (error: Error) => void;
  emitLatency: (metric: DeepgramStreamingLatencyMetric) => void;
  emitTranscriptDelta: (delta: string) => void;
  emitSpokenDelta: (delta: string, meta: DeepgramStreamingSpokenMeta) => void;
  emitSpokenProgress: (progress: {
    spokenChars: number;
    spokenWords: number;
    playbackMs: number;
    precision: 'segment';
  }) => void;
  emitSpokenFinal: (text: string, meta: DeepgramStreamingSpokenMeta) => void;
}

export interface DeepgramStreamingResult {
  text: string;
  spokenText: string;
  spokeAudio: boolean;
  llmDurationMs: number;
  interrupted: boolean;
}

export class DeepgramTtsConnectionManager implements DeepgramConnectionManager {
  private connection: SpeakLiveClient | null = null;
  private connectionReady: Promise | null = null;
  private requestQueue: Promise = Promise.resolve();

  resetQueue(): void {
    this.requestQueue = Promise.resolve();
  }

  enqueueRequest(fn: () => Promise): Promise {
    const request = this.requestQueue.then(() => fn());
    this.requestQueue = request.then(() => undefined).catch(() => undefined);
    return request;
  }

  async ensure(options: DeepgramTtsConnectionOptions): Promise {
    if (!options.apiKey) {
      throw new Error('Deepgram API key is missing for decomposed TTS');
    }

    if (this.connection && this.connection.isConnected()) {
      return this.connection;
    }

    if (this.connectionReady) {
      return this.connectionReady;
    }

    const connectPromise = new Promise((resolve, reject) => {
      if (!options.apiKey) {
        reject(new Error('Deepgram API key is missing for decomposed TTS'));
        return;
      }

      const connectionTimeout = setTimeout(() => {
        this.close();
        rejectOnce(new Error('Deepgram websocket TTS connect timed out'));
      }, 10000);

      const connection = this.createConnection(options.apiKey, options.model, options.endpoint);

      let settled = false;
      const cleanup = (): void => {
        clearTimeout(connectionTimeout);
        connection.off(LiveTTSEvents.Open, onOpen);
        connection.off(LiveTTSEvents.Error, onError);
        connection.off(LiveTTSEvents.Close, onCloseBeforeOpen);
      };

      const resolveOnce = (client: SpeakLiveClient): void => {
        if (settled) return;
        settled = true;
        cleanup();
        resolve(client);
      };

      const rejectOnce = (error: Error): void => {
        if (settled) return;
        settled = true;
        cleanup();
        reject(error);
      };

      const onOpen = (): void => {
        this.connection = connection;

        connection.on(LiveTTSEvents.Close, () => {
          if (this.connection === connection) {
            this.connection = null;
          }
        });

        resolveOnce(connection);
      };

      const onError = (event: unknown): void => {
        rejectOnce(toDeepgramLiveError(event, 'Deepgram websocket TTS connect failed'));
      };

      const onCloseBeforeOpen = (): void => {
        rejectOnce(new Error('Deepgram websocket TTS closed before open'));
      };

      connection.once(LiveTTSEvents.Open, onOpen);
      connection.once(LiveTTSEvents.Error, onError);
      connection.once(LiveTTSEvents.Close, onCloseBeforeOpen);
    });

    this.connectionReady = connectPromise;
    try {
      return await connectPromise;
    } finally {
      if (this.connectionReady === connectPromise) {
        this.connectionReady = null;
      }
    }
  }

  close(): void {
    const connection = this.connection;
    this.connection = null;
    this.connectionReady = null;
    if (!connection) return;
    try {
      connection.requestClose();
    } catch {
      // ignore close-send failures
    }
    try {
      connection.disconnect();
    } catch {
      // ignore close failures
    }
  }

  private createConnection(apiKey: string, model: string, endpoint: string): SpeakLiveClient {
    const deepgram = createClient({
      key: apiKey,
    });
    return deepgram.speak.live(
      {
        model,
        encoding: 'linear16',
        sample_rate: AUDIO_SAMPLE_RATE,
        container: 'none',
      },
      endpoint
    );
  }
}

export interface DeepgramConnectionManager {
  ensure(options: DeepgramTtsConnectionOptions): Promise;
  close(): void;
}

export function toDeepgramLiveError(event: unknown, fallback: string): Error {
  if (event instanceof Error) {
    return event;
  }

  const object = event as { message?: unknown; description?: unknown; code?: unknown } | null;
  if (object && typeof object === 'object') {
    const message =
      typeof object.message === 'string'
        ? object.message
        : typeof object.description === 'string'
          ? object.description
          : null;
    const code = typeof object.code === 'string' ? object.code : null;
    if (message && code) {
      return new Error(`${message} (code: ${code})`);
    }
    if (message) {
      return new Error(message);
    }
  }

  return new Error(fallback);
}

export async function speakWithDeepgramLiveSegment(input: {
  text: string;
  emitChunk: (chunk: ArrayBuffer) => Promise;
  context: DeepgramStreamingContext;
}): Promise {
  const { text, emitChunk, context } = input;
  const { options } = context;

  if (!options.apiKey) {
    throw new Error('Deepgram API key is missing for decomposed TTS');
  }

  const connection = await context.connectionManager.ensure(options);
  if (!context.isTurnCurrent()) {
    return;
  }

  await new Promise((resolve, reject) => {
    let settled = false;
    let flushReceived = false;
    let aborted = false;
    let audioPipeline: Promise = Promise.resolve();
    const segmentTimeout = setTimeout(() => {
      context.connectionManager.close();
      rejectOnce(new Error('Deepgram websocket TTS segment timed out waiting for flush'));
    }, 10000);

    const cleanup = (): void => {
      clearTimeout(segmentTimeout);
      connection.off(LiveTTSEvents.Audio, onAudio);
      connection.off(LiveTTSEvents.Flushed, onFlushed);
      connection.off(LiveTTSEvents.Warning, onWarning);
      connection.off(LiveTTSEvents.Close, onClose);
      connection.off(LiveTTSEvents.Error, onError);
    };

    const resolveOnce = (): void => {
      if (settled) return;
      settled = true;
      cleanup();
      resolve();
    };

    const rejectOnce = (error: Error): void => {
      if (settled) return;
      settled = true;
      cleanup();
      reject(error);
    };

    const maybeResolve = (): void => {
      if (settled) return;
      if (aborted) {
        resolveOnce();
        return;
      }
      if (!flushReceived) {
        return;
      }
      void audioPipeline.then(() => resolveOnce()).catch((error) => {
        rejectOnce(error as Error);
      });
    };

    const enqueueAudio = (payload: ArrayBuffer | Uint8Array): void => {
      audioPipeline = audioPipeline.then(async () => {
        const bytes =
          payload instanceof ArrayBuffer
            ? new Uint8Array(payload)
            : new Uint8Array(payload.buffer, payload.byteOffset, payload.byteLength);
        const copied = new Uint8Array(bytes.byteLength);
        copied.set(bytes);
        const audioBuffer = copied.buffer;

        const chunks = chunkArrayBuffer(audioBuffer, PCM_BYTES_PER_100MS);
        for (const chunk of chunks) {
          if (aborted) return;
          const keepGoing = await emitChunk(chunk);
          if (!keepGoing) {
            aborted = true;
            context.connectionManager.close();
            return;
          }
        }
      });
    };

    const onAudio = (payload: unknown): void => {
      const binary = toRawDataUint8Array(payload);
      if (binary) {
        enqueueAudio(binary);
      }
    };

    const onFlushed = (): void => {
      flushReceived = true;
      maybeResolve();
    };

    const onWarning = (event: unknown): void => {
      if (settled) return;
      const error = toDeepgramLiveError(event, 'Deepgram websocket TTS warning');
      context.connectionManager.close();
      rejectOnce(error);
    };

    const onClose = (): void => {
      if (settled) return;
      if (!context.isTurnCurrent()) {
        resolveOnce();
        return;
      }
      rejectOnce(new Error('Deepgram websocket TTS closed before flush completed'));
    };

    const onError = (event: unknown): void => {
      if (settled) return;
      if (!context.isTurnCurrent()) {
        resolveOnce();
        return;
      }
      const error = toDeepgramLiveError(event, 'Deepgram websocket TTS error');
      context.connectionManager.close();
      rejectOnce(error);
    };

    connection.on(LiveTTSEvents.Audio, onAudio);
    connection.on(LiveTTSEvents.Flushed, onFlushed);
    connection.on(LiveTTSEvents.Warning, onWarning);
    connection.on(LiveTTSEvents.Close, onClose);
    connection.on(LiveTTSEvents.Error, onError);

    try {
      connection.sendText(text);
      connection.flush();
    } catch (error) {
      context.connectionManager.close();
      rejectOnce(toDeepgramLiveError(error, 'Deepgram websocket TTS send failed'));
      return;
    }
  });
}

export async function streamTextWithDeepgramTts(input: {
  textStream: AsyncIterable;
  llmStartedAtMs: number;
  context: DeepgramStreamingContext;
}): Promise {
  const { textStream, llmStartedAtMs, context } = input;
  const { options } = context;

  if (!options.apiKey) {
    throw new Error('Deepgram API key is missing for decomposed TTS');
  }

  if (!context.isTurnCurrent()) {
    return { text: '', spokenText: '', spokeAudio: false, llmDurationMs: 0, interrupted: true };
  }

  const connection = await context.connectionManager.ensure(options);
  if (!context.isTurnCurrent()) {
    return { text: '', spokenText: '', spokeAudio: false, llmDurationMs: 0, interrupted: true };
  }

  const ttsStartedAtMs = Date.now();
  const punctuationChunkingEnabled = options.punctuationChunkingEnabled;
  let llmDurationMs = 0;
  let assistantText = '';
  let pendingText = '';
  let speaking = false;
  let spokeAudio = false;
  let pendingChars = 0;
  let expectedFlushes = 0;
  let receivedFlushes = 0;
  let sendingComplete = false;
  let sendingCompleteAtMs: number | null = null;
  let settled = false;
  let aborted = false;
  let emittedAudioBytes = 0;
  let emittedChunks = 0;
  let firstAudioAtMs: number | null = null;
  let lastAudioAtMs: number | null = null;
  let forceReconnectAfterTurn = false;
  let audioPipeline: Promise = Promise.resolve();
  const spokenStreamEnabled = options.spokenStreamEnabled === true;

  let speechOnsetBytes = 0;
  let speechOnsetDetected = false;
  const flushTextQueue: string[] = [];
  let spokenText = '';
  let spokenChars = 0;
  let spokenWords = 0;
  let spokenPlaybackMs = 0;
  const spokenWordBuffer = new DecomposedSpokenWordBuffer();

  const emitSpokenWord = (word: string): void => {
    if (!word || !spokenStreamEnabled || !context.isTurnCurrent()) return;
    spokenText += word;
    spokenChars = spokenText.length;
    spokenWords = countWords(spokenText);
    const playbackMs = Math.floor((emittedAudioBytes / 2 / AUDIO_SAMPLE_RATE) * 1000);
    const onsetMs = speechOnsetDetected
      ? Math.floor((speechOnsetBytes / 2 / AUDIO_SAMPLE_RATE) * 1000)
      : 0;
    spokenPlaybackMs = playbackMs;
    context.emitSpokenDelta(word, {
      spokenChars,
      spokenWords,
      playbackMs,
      speechOnsetMs: onsetMs,
      precision: 'segment',
    });
    context.emitSpokenProgress({
      spokenChars,
      spokenWords,
      playbackMs,
      precision: 'segment',
    });
  };

  const drainSpokenWordBuffer = (): void => {
    const buffered = spokenWordBuffer.markAudioStarted();
    if (buffered) {
      emitSpokenWord(buffered);
    }
  };

  await new Promise((resolve, reject) => {
    let flushFallbackTimer: ReturnType | null = null;
    const streamingTimeout = setTimeout(() => {
      context.connectionManager.close();
      rejectOnce(new Error('Deepgram websocket TTS streaming turn timed out'));
    }, 30000);

    const cleanup = (): void => {
      clearTimeout(streamingTimeout);
      if (flushFallbackTimer) {
        clearTimeout(flushFallbackTimer);
        flushFallbackTimer = null;
      }
      connection.off(LiveTTSEvents.Audio, onAudio);
      connection.off(LiveTTSEvents.Flushed, onFlushed);
      connection.off(LiveTTSEvents.Warning, onWarning);
      connection.off(LiveTTSEvents.Close, onClose);
      connection.off(LiveTTSEvents.Error, onError);
    };

    const resolveOnce = (): void => {
      if (settled) return;
      settled = true;
      cleanup();
      resolve();
    };

    const rejectOnce = (error: Error): void => {
      if (settled) return;
      settled = true;
      cleanup();
      reject(error);
    };

    const updatePlaybackOnFlush = (flushedText: string): void => {
      if (!flushedText || !context.isTurnCurrent()) {
        return;
      }
      const playbackMs = Math.floor((emittedAudioBytes / 2 / AUDIO_SAMPLE_RATE) * 1000);
      spokenPlaybackMs = playbackMs;
    };

    const drainPendingFlushQueue = (): void => {
      while (flushTextQueue.length > 0) {
        const flushedText = flushTextQueue.shift() ?? '';
        updatePlaybackOnFlush(flushedText);
        receivedFlushes += 1;
      }
    };

    const armFlushFallback = (): void => {
      if (settled || !sendingComplete) {
        return;
      }
      if (receivedFlushes >= expectedFlushes) {
        return;
      }
      if (flushFallbackTimer) {
        clearTimeout(flushFallbackTimer);
        flushFallbackTimer = null;
      }

      flushFallbackTimer = setTimeout(() => {
        flushFallbackTimer = null;
        if (settled) return;
        if (!context.isTurnCurrent()) {
          resolveOnce();
          return;
        }

        const idleMs =
          lastAudioAtMs === null ? Number.POSITIVE_INFINITY : Date.now() - lastAudioAtMs;
        if (idleMs < DEEPGRAM_FLUSH_FALLBACK_IDLE_MS) {
          armFlushFallback();
          return;
        }

        if (receivedFlushes < expectedFlushes) {
          const connectionAlive =
            typeof connection.isConnected === 'function' ? connection.isConnected() : true;
          const stalledSinceCompleteMs =
            sendingCompleteAtMs === null ? 0 : Date.now() - sendingCompleteAtMs;
          if (
            connectionAlive &&
            stalledSinceCompleteMs < DEEPGRAM_FLUSH_FALLBACK_FORCE_MS
          ) {
            armFlushFallback();
            return;
          }
          drainPendingFlushQueue();
          if (receivedFlushes < expectedFlushes) {
            receivedFlushes = expectedFlushes;
          }
          forceReconnectAfterTurn = true;
        }

        maybeResolve();
      }, DEEPGRAM_FLUSH_FALLBACK_POLL_MS);
    };

    const maybeResolve = (): void => {
      if (settled) return;
      if (aborted) {
        resolveOnce();
        return;
      }
      if (!context.isTurnCurrent()) {
        resolveOnce();
        return;
      }
      if (!sendingComplete) {
        return;
      }
      if (receivedFlushes < expectedFlushes) {
        return;
      }
      void audioPipeline.then(() => resolveOnce()).catch((error) => {
        rejectOnce(error as Error);
      });
    };

    const emitChunk = async (chunk: ArrayBuffer): Promise => {
      if (!context.isTurnCurrent()) {
        return false;
      }

      let onsetDetectedInChunk = false;
      if (!speechOnsetDetected) {
        const onsetByteInChunk = detectSpeechOnsetInChunk(chunk);
        if (onsetByteInChunk >= 0) {
          speechOnsetBytes = emittedAudioBytes + onsetByteInChunk;
          speechOnsetDetected = true;
          onsetDetectedInChunk = true;
        }
      }

      emittedAudioBytes += chunk.byteLength;
      emittedChunks += 1;
      const isFirstAudio = firstAudioAtMs === null;
      if (isFirstAudio) {
        firstAudioAtMs = Date.now();
        if (!speaking) {
          context.setSpeaking();
          speaking = true;
        }
      }

      context.trackAssistantOutput(chunk);
      context.emitAudio(chunk);

      if (onsetDetectedInChunk) {
        drainSpokenWordBuffer();
      }

      await sleep(20);
      return true;
    };

    const enqueueAudio = (payload: Uint8Array | ArrayBuffer): void => {
      audioPipeline = audioPipeline.then(async () => {
        const bytes =
          payload instanceof ArrayBuffer
            ? new Uint8Array(payload)
            : new Uint8Array(payload.buffer, payload.byteOffset, payload.byteLength);
        const copied = new Uint8Array(bytes.byteLength);
        copied.set(bytes);
        const chunks = chunkArrayBuffer(copied.buffer, PCM_BYTES_PER_100MS);
        for (const chunk of chunks) {
          if (aborted) return;
          const keepGoing = await emitChunk(chunk);
          if (!keepGoing) {
            aborted = true;
            context.connectionManager.close();
            return;
          }
        }
      });
    };

    const requestFlush = (): void => {
      if (!context.isTurnCurrent() || pendingChars <= 0) return;
      const flushText = pendingText;
      connection.sendText(flushText);
      flushTextQueue.push(flushText);
      pendingText = '';
      pendingChars = 0;
      expectedFlushes += 1;
      spokeAudio = true;
      connection.flush();
    };

    const onAudio = (payload: unknown): void => {
      const binary = toRawDataUint8Array(payload);
      if (!binary || binary.byteLength === 0) return;
      lastAudioAtMs = Date.now();
      enqueueAudio(binary);
      if (sendingComplete) {
        armFlushFallback();
      }
    };

    const onFlushed = (): void => {
      const flushedText = flushTextQueue.shift() ?? '';
      updatePlaybackOnFlush(flushedText);
      receivedFlushes += 1;
      maybeResolve();
    };

    const onWarning = (event: unknown): void => {
      const warning = toDeepgramLiveError(event, 'Deepgram websocket TTS warning');
      context.emitError(warning);
    };

    const onClose = (): void => {
      if (settled) return;
      if (!context.isTurnCurrent()) {
        resolveOnce();
        return;
      }
      if (sendingComplete) {
        drainPendingFlushQueue();
        if (receivedFlushes < expectedFlushes) {
          receivedFlushes = expectedFlushes;
          forceReconnectAfterTurn = true;
        }
        maybeResolve();
        return;
      }
      rejectOnce(new Error('Deepgram websocket TTS closed before flush completed'));
    };

    const onError = (event: unknown): void => {
      if (settled) return;
      if (!context.isTurnCurrent()) {
        resolveOnce();
        return;
      }
      const error = toDeepgramLiveError(event, 'Deepgram websocket TTS error');
      context.connectionManager.close();
      rejectOnce(error);
    };

    connection.on(LiveTTSEvents.Audio, onAudio);
    connection.on(LiveTTSEvents.Flushed, onFlushed);
    connection.on(LiveTTSEvents.Warning, onWarning);
    connection.on(LiveTTSEvents.Close, onClose);
    connection.on(LiveTTSEvents.Error, onError);

    void (async () => {
      try {
        for await (const delta of textStream) {
          if (!context.isTurnCurrent()) {
            aborted = true;
            context.connectionManager.close();
            break;
          }
          if (!delta) continue;
          assistantText += delta;
          context.emitTranscriptDelta(delta);

          if (spokenStreamEnabled) {
            const completeWords = spokenWordBuffer.ingestDelta(delta);
            if (completeWords) {
              emitSpokenWord(completeWords);
            }
          }

          pendingText += delta;
          pendingChars += delta.length;

          if (punctuationChunkingEnabled) {
            if (
              shouldFlushDeepgramStream(
                delta,
                pendingChars,
                expectedFlushes,
                true
              )
            ) {
              requestFlush();
            }
          } else {
            connection.sendText(delta);
          }
        }

        llmDurationMs = Date.now() - llmStartedAtMs;
        sendingComplete = true;
        sendingCompleteAtMs = Date.now();

        if (!aborted && (pendingChars > 0 || expectedFlushes === 0)) {
          if (!punctuationChunkingEnabled) {
            flushTextQueue.push(pendingText);
            pendingText = '';
            pendingChars = 0;
            expectedFlushes += 1;
            spokeAudio = true;
            connection.flush();
          } else {
            requestFlush();
          }
        }

        maybeResolve();
        armFlushFallback();
      } catch (error) {
        context.connectionManager.close();
        if (!context.isTurnCurrent()) {
          aborted = true;
          resolveOnce();
          return;
        }
        rejectOnce(toDeepgramLiveError(error, 'Deepgram websocket TTS stream failed'));
      }
    })();
  });

  context.emitLatency({
    stage: 'tts',
    durationMs: Date.now() - ttsStartedAtMs,
    provider: options.ttsProvider,
    model: options.model,
    details: {
      textChars: assistantText.length,
      audioBytes: emittedAudioBytes,
      chunks: emittedChunks,
      firstAudioLatencyMs:
        firstAudioAtMs === null ? null : Math.max(0, firstAudioAtMs - ttsStartedAtMs),
      streaming: true,
      flushes: expectedFlushes,
      flushMode: punctuationChunkingEnabled ? 'punctuation' : 'size-threshold',
    },
  });

  if (context.isTurnCurrent()) {
    context.setListening();
  }

  if (!speechOnsetDetected && emittedAudioBytes > 0) {
    drainSpokenWordBuffer();
  }

  const trailingWords = spokenWordBuffer.flushRemainder();
  if (trailingWords) {
    emitSpokenWord(trailingWords);
  }

  if (spokenStreamEnabled && spokenText && context.isTurnCurrent()) {
    spokenPlaybackMs = Math.floor((emittedAudioBytes / 2 / AUDIO_SAMPLE_RATE) * 1000);
    context.emitSpokenFinal(spokenText, {
      spokenChars,
      spokenWords,
      playbackMs: spokenPlaybackMs,
      precision: 'segment',
    });
  }

  if (forceReconnectAfterTurn) {
    context.connectionManager.close();
  }

  return {
    text: assistantText,
    spokenText,
    spokeAudio,
    llmDurationMs,
    interrupted: !context.isTurnCurrent(),
  };
}



import type { SegmentSynthesisInput, SegmentSynthesisResult } from './types.js';

export async function synthesizeDeepgramSegment(
  _input: SegmentSynthesisInput
): Promise {
  throw new Error(
    'Deepgram segment synthesis is handled by DecomposedAdapter streaming transport. '
      + 'Use the adapter deepgram websocket path.'
  );
}



import { decode, encode } from '@msgpack/msgpack';
import WebSocket, { type RawData } from 'ws';
import { chunkArrayBuffer, PCM_BYTES_PER_100MS } from './audio-utils.js';
import type { SegmentSynthesisInput, SegmentSynthesisResult } from './types.js';

const FISH_SAMPLE_RATE = 24_000;
const FISH_MAX_TEXT_CHUNK_CHARS = 180;
const FISH_MIN_SPLIT_INDEX = 60;

export async function synthesizeFishSegment(
  input: SegmentSynthesisInput
): Promise {
  const { context, text, emitChunk, signal } = input;
  if (!context.fishAudioApiKey) {
    throw new Error('Fish Audio API key is missing for decomposed TTS provider fish');
  }

  if (signal.aborted) {
    throw createAbortError();
  }

  const textChunks = chunkFishText(text);
  if (textChunks.length === 0) {
    return { precision: 'segment' };
  }

  const socket = new WebSocket(context.fishTtsWsUrl, {
    headers: {
      Authorization: `Bearer ${context.fishAudioApiKey}`,
      model: context.model,
    },
  });

  await waitForSocketOpen(socket, signal);

  let finishReceived = false;
  let abortedByConsumer = false;
  let settled = false;
  let stopSent = false;
  let audioPipeline: Promise = Promise.resolve();

  const synthesisComplete = new Promise((resolve, reject) => {
    const cleanup = (): void => {
      socket.off('message', onMessage);
      socket.off('error', onError);
      socket.off('close', onClose);
      signal.removeEventListener('abort', onAbort);
    };

    const resolveOnce = (): void => {
      if (settled) return;
      settled = true;
      cleanup();
      resolve({ precision: 'segment' });
    };

    const rejectOnce = (error: Error): void => {
      if (settled) return;
      settled = true;
      cleanup();
      reject(error);
    };

    const maybeResolve = (): void => {
      if (settled) return;
      if (!finishReceived && !abortedByConsumer) return;
      void audioPipeline.then(resolveOnce).catch((error) => {
        rejectOnce(toError(error, 'Fish websocket audio pipeline failed'));
      });
    };

    const enqueueAudio = (audio: ArrayBuffer): void => {
      audioPipeline = audioPipeline.then(async () => {
        if (abortedByConsumer || settled) {
          return;
        }

        const chunks = chunkArrayBuffer(audio, PCM_BYTES_PER_100MS);
        for (const chunk of chunks) {
          if (abortedByConsumer || settled) {
            return;
          }

          const keepGoing = await emitChunk(chunk);
          if (!keepGoing) {
            abortedByConsumer = true;
            safeCloseSocket(socket);
            maybeResolve();
            return;
          }
        }
      });

      void audioPipeline.catch((error) => {
        rejectOnce(toError(error, 'Fish websocket audio pipeline failed'));
      });
    };

    const onMessage = (raw: RawData, isBinary: boolean): void => {
      if (!isBinary || settled) return;

      let decoded: unknown;
      try {
        decoded = decode(rawDataToUint8Array(raw));
      } catch (error) {
        rejectOnce(toError(error, 'Failed to decode Fish websocket message'));
        return;
      }

      const decodedMessage = coerceDecodedMessage(decoded);
      if (!decodedMessage) {
        return;
      }

      const event = decodedMessage.event;
      if (event === 'audio') {
        const audio = toArrayBufferCopy(decodedMessage.audio);
        if (audio) {
          enqueueAudio(audio);
        }
        return;
      }

      if (event === 'finish') {
        const reason = typeof decodedMessage.reason === 'string' ? decodedMessage.reason : '';
        if (reason === 'error') {
          const errorMessage =
            typeof decodedMessage.message === 'string' && decodedMessage.message.trim().length > 0
              ? decodedMessage.message
              : 'Fish websocket TTS returned finish=error';
          rejectOnce(new Error(errorMessage));
          return;
        }
        if (reason === 'stop') {
          finishReceived = true;
          maybeResolve();
        }
      }
    };

    const onError = (error: Error): void => {
      if (signal.aborted) {
        rejectOnce(createAbortError());
        return;
      }
      rejectOnce(toError(error, 'Fish websocket TTS error'));
    };

    const onClose = (): void => {
      if (settled) return;
      if (signal.aborted) {
        rejectOnce(createAbortError());
        return;
      }
      if (abortedByConsumer || finishReceived) {
        maybeResolve();
        return;
      }
      if (stopSent) {
        rejectOnce(new Error('Fish websocket closed before finish event was received'));
        return;
      }
      rejectOnce(new Error('Fish websocket closed unexpectedly'));
    };

    const onAbort = (): void => {
      safeCloseSocket(socket);
      rejectOnce(createAbortError());
    };

    socket.on('message', onMessage);
    socket.on('error', onError);
    socket.on('close', onClose);
    signal.addEventListener('abort', onAbort, { once: true });
  });

  try {
    const startRequest = createFishStartRequest(context.voice);
    await sendFishEvent(socket, { event: 'start', request: startRequest });

    for (const chunk of textChunks) {
      if (signal.aborted) {
        throw createAbortError();
      }
      await sendFishEvent(socket, { event: 'text', text: chunk });
    }

    await sendFishEvent(socket, { event: 'flush' });
    stopSent = true;
    await sendFishEvent(socket, { event: 'stop' });
  } catch (error) {
    safeCloseSocket(socket);
    void synthesisComplete.catch(() => {});
    throw toError(error, 'Fish websocket TTS send failed');
  }

  return synthesisComplete;
}

async function waitForSocketOpen(socket: WebSocket, signal: AbortSignal): Promise {
  if (signal.aborted) {
    safeCloseSocket(socket);
    throw createAbortError();
  }

  await new Promise((resolve, reject) => {
    let settled = false;

    const cleanup = (): void => {
      socket.off('open', onOpen);
      socket.off('error', onError);
      socket.off('close', onClose);
      signal.removeEventListener('abort', onAbort);
    };

    const resolveOnce = (): void => {
      if (settled) return;
      settled = true;
      cleanup();
      resolve();
    };

    const rejectOnce = (error: Error): void => {
      if (settled) return;
      settled = true;
      cleanup();
      reject(error);
    };

    const onOpen = (): void => {
      resolveOnce();
    };

    const onError = (error: Error): void => {
      rejectOnce(toError(error, 'Fish websocket connect failed'));
    };

    const onClose = (): void => {
      rejectOnce(new Error('Fish websocket closed before opening'));
    };

    const onAbort = (): void => {
      safeCloseSocket(socket);
      rejectOnce(createAbortError());
    };

    socket.on('open', onOpen);
    socket.on('error', onError);
    socket.on('close', onClose);
    signal.addEventListener('abort', onAbort, { once: true });
  });
}

async function sendFishEvent(
  socket: WebSocket,
  payload: Record
): Promise {
  if (socket.readyState !== WebSocket.OPEN) {
    throw new Error('Fish websocket is not open');
  }

  const encoded = encode(payload);
  await new Promise((resolve, reject) => {
    socket.send(encoded, (error) => {
      if (error) {
        reject(toError(error, 'Fish websocket send failed'));
        return;
      }
      resolve();
    });
  });
}

function createFishStartRequest(voice: string): Record {
  const request: Record = {
    text: '',
    format: 'pcm',
    sample_rate: FISH_SAMPLE_RATE,
  };

  const trimmedVoice = voice.trim();
  if (trimmedVoice) {
    request.reference_id = trimmedVoice;
  }

  return request;
}

function chunkFishText(text: string): string[] {
  const normalized = text.replace(/\s+/g, ' ').trim();
  if (!normalized) {
    return [];
  }

  const phraseMatches = normalized.match(/[^.!?;:,\n]+[.!?;:,\n]*\s*/g) ?? [normalized];
  const chunks: string[] = [];
  let current = '';

  const flushCurrent = (): void => {
    const trimmed = current.trim();
    if (trimmed) {
      chunks.push(trimmed);
    }
    current = '';
  };

  for (const phraseRaw of phraseMatches) {
    const phrase = phraseRaw.trim();
    if (!phrase) continue;

    if (phrase.length > FISH_MAX_TEXT_CHUNK_CHARS) {
      flushCurrent();
      chunks.push(...splitLongFishChunk(phrase));
      continue;
    }

    if (!current) {
      current = phrase;
      continue;
    }

    if (current.length + 1 + phrase.length <= FISH_MAX_TEXT_CHUNK_CHARS) {
      current = `${current} ${phrase}`;
      continue;
    }

    flushCurrent();
    current = phrase;
  }

  flushCurrent();
  return chunks;
}

function splitLongFishChunk(text: string): string[] {
  const chunks: string[] = [];
  let remaining = text.trim();

  while (remaining.length > FISH_MAX_TEXT_CHUNK_CHARS) {
    let splitAt = remaining.lastIndexOf(' ', FISH_MAX_TEXT_CHUNK_CHARS);
    if (splitAt < FISH_MIN_SPLIT_INDEX) {
      splitAt = remaining.lastIndexOf(',', FISH_MAX_TEXT_CHUNK_CHARS);
    }
    if (splitAt < FISH_MIN_SPLIT_INDEX) {
      splitAt = FISH_MAX_TEXT_CHUNK_CHARS;
    }

    const chunk = remaining.slice(0, splitAt).trim();
    if (chunk) {
      chunks.push(chunk);
    }
    remaining = remaining.slice(splitAt).trimStart();
  }

  if (remaining) {
    chunks.push(remaining);
  }

  return chunks;
}

function rawDataToUint8Array(data: RawData): Uint8Array {
  if (Array.isArray(data)) {
    return Buffer.concat(data);
  }
  if (Buffer.isBuffer(data)) {
    return data;
  }
  if (data instanceof ArrayBuffer) {
    return new Uint8Array(data);
  }
  const maybeView: unknown = data;
  if (isArrayBufferView(maybeView)) {
    return new Uint8Array(maybeView.buffer, maybeView.byteOffset, maybeView.byteLength);
  }
  throw new Error('Unsupported Fish websocket message payload type');
}

function coerceDecodedMessage(value: unknown): Record | null {
  if (isRecord(value)) {
    return value;
  }
  if (value instanceof Map) {
    const mapped: Record = {};
    for (const [key, entry] of value.entries()) {
      if (typeof key === 'string') {
        mapped[key] = entry;
      }
    }
    return mapped;
  }
  return null;
}

function toArrayBufferCopy(value: unknown): ArrayBuffer | null {
  if (value instanceof ArrayBuffer) {
    const bytes = new Uint8Array(value);
    const copied = new Uint8Array(bytes.byteLength);
    copied.set(bytes);
    return copied.buffer;
  }
  if (Buffer.isBuffer(value)) {
    const copied = new Uint8Array(value.byteLength);
    copied.set(value);
    return copied.buffer;
  }
  if (value instanceof Uint8Array) {
    const copied = new Uint8Array(value.byteLength);
    copied.set(value);
    return copied.buffer;
  }
  if (ArrayBuffer.isView(value)) {
    const bytes = new Uint8Array(value.buffer, value.byteOffset, value.byteLength);
    const copied = new Uint8Array(bytes.byteLength);
    copied.set(bytes);
    return copied.buffer;
  }
  return null;
}

function safeCloseSocket(socket: WebSocket): void {
  if (socket.readyState === WebSocket.CLOSING || socket.readyState === WebSocket.CLOSED) {
    return;
  }
  try {
    socket.close();
  } catch {
    // ignore close errors on teardown
  }
}

function isRecord(value: unknown): value is Record {
  return typeof value === 'object' && value !== null;
}

function isArrayBufferView(value: unknown): value is ArrayBufferView {
  return ArrayBuffer.isView(value);
}

function toError(error: unknown, fallback: string): Error {
  if (error instanceof Error) {
    return error;
  }
  return new Error(fallback);
}

function createAbortError(): Error {
  if (typeof DOMException !== 'undefined') {
    return new DOMException('The operation was aborted', 'AbortError');
  }
  const error = new Error('The operation was aborted');
  error.name = 'AbortError';
  return error;
}



import {
  chunkArrayBuffer,
  decodeBase64ToArrayBuffer,
  PCM_BYTES_PER_100MS,
  stripWavHeader,
} from './audio-utils.js';
import type { SegmentSynthesisInput, SegmentSynthesisResult } from './types.js';

interface GoogleSynthesizeResponse {
  audioContent?: string;
}

export async function synthesizeGoogleChirpSegment(
  input: SegmentSynthesisInput
): Promise {
  const { context, text, emitChunk, signal } = input;
  if (!context.googleApiKey) {
    throw new Error('Google API key is missing for decomposed TTS provider google-chirp');
  }

  const endpoint = new URL(context.googleChirpEndpoint);
  if (!endpoint.searchParams.has('key')) {
    endpoint.searchParams.set('key', context.googleApiKey);
  }

  const response = await fetch(endpoint, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      input: { text },
      voice: {
        name: context.voice,
        languageCode: inferGoogleLanguageCode(context.language, context.voice),
      },
      audioConfig: {
        audioEncoding: 'LINEAR16',
        sampleRateHertz: 24000,
      },
    }),
    signal,
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`Google Chirp TTS failed (${response.status}): ${errorText}`);
  }

  const payload = (await response.json()) as GoogleSynthesizeResponse;
  if (!payload.audioContent) {
    throw new Error('Google Chirp TTS response is missing audioContent');
  }

  const wavOrPcm = decodeBase64ToArrayBuffer(payload.audioContent);
  const pcm = stripWavHeader(wavOrPcm);
  const chunks = chunkArrayBuffer(pcm, PCM_BYTES_PER_100MS);
  for (const chunk of chunks) {
    const keepGoing = await emitChunk(chunk);
    if (!keepGoing) {
      break;
    }
  }

  return { precision: 'segment' };
}

function inferGoogleLanguageCode(language: string, voice: string): string {
  const voiceMatch = voice.match(/^[a-z]{2}-[a-z]{2}/i);
  if (voiceMatch?.[0]) {
    return voiceMatch[0];
  }

  const normalized = language.trim().toLowerCase();
  if (!normalized) {
    return 'en-US';
  }
  if (/^[a-z]{2}-[a-z]{2}$/i.test(normalized)) {
    return normalized;
  }

  if (normalized === 'en') return 'en-US';
  if (normalized === 'de') return 'de-DE';
  if (normalized === 'fr') return 'fr-FR';
  if (normalized === 'es') return 'es-ES';
  if (normalized === 'it') return 'it-IT';
  if (normalized === 'pt') return 'pt-BR';
  if (normalized === 'ja') return 'ja-JP';
  if (normalized === 'ko') return 'ko-KR';
  if (normalized === 'zh') return 'cmn-CN';

  return 'en-US';
}



import { synthesizeCartesiaSegment } from './cartesia-tts.js';
import { synthesizeDeepgramSegment } from './deepgram-tts.js';
