  },
  'google-chirp': {
    id: 'google-chirp',
    defaultModel: 'chirp-3-hd',
    supportsRealtimeStreaming: false,
    supportsProviderWordTimestamps: false,
    synthesizeSegment: synthesizeGoogleChirpSegment,
  },
  kokoro: {
    id: 'kokoro',
