import {
  chunkArrayBuffer,
  PCM_BYTES_PER_100MS,
  stripWavHeader,
} from './audio-utils.js';
import type { SegmentSynthesisInput, SegmentSynthesisResult } from './types.js';

export async function synthesizePocketTtsSegment(
  input: SegmentSynthesisInput
): Promise {
  const { context, text, emitChunk, signal } = input;
  const response = await fetch(context.pocketTtsEndpoint, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      text,
      voice: context.voice,
      model: context.model,
    }),
    signal,
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`Pocket TTS failed (${response.status}): ${errorText}`);
  }

  const wavOrPcm = await response.arrayBuffer();
  const pcm = stripWavHeader(wavOrPcm);
  const chunks = chunkArrayBuffer(pcm, PCM_BYTES_PER_100MS);
  for (const chunk of chunks) {
    const keepGoing = await emitChunk(chunk);
    if (!keepGoing) {
      break;
    }
  }

  return { precision: 'segment' };
}



import WebSocket, { type RawData } from 'ws';
import type { SpokenWordTimestamp } from '../../types.js';
import { decodeBase64ToArrayBuffer } from './audio-utils.js';
import type { SegmentSynthesisInput, SegmentSynthesisResult } from './types.js';

const RIME_SAMPLE_RATE = 24000;
const RIME_TEXT_CHUNK_MAX_CHARS = 220;

export async function synthesizeRimeSegment(
  input: SegmentSynthesisInput
): Promise {
  const { context, text, emitChunk, signal } = input;
  if (!context.rimeApiKey) {
    throw new Error('Rime API key is missing for decomposed TTS');
  }

  const trimmed = text.trim();
  if (!trimmed) {
    return { precision: 'segment' };
  }

  const endpoint = normalizeRimeWsEndpoint(context.rimeTtsWsUrl);
  endpoint.searchParams.set('speaker', context.voice);
  endpoint.searchParams.set('modelId', context.model);
  endpoint.searchParams.set('audioFormat', 'pcm');
  endpoint.searchParams.set('samplingRate', String(RIME_SAMPLE_RATE));
  if (!endpoint.searchParams.has('segment')) {
    endpoint.searchParams.set('segment', 'never');
  }

  const textChunks = chunkTextNaturally(trimmed, RIME_TEXT_CHUNK_MAX_CHARS);
  const contextId = createContextId();
  let providerWordTimestamps: SpokenWordTimestamp[] | undefined;

  await new Promise((resolve, reject) => {
    if (signal.aborted) {
      reject(createAbortError());
      return;
    }

    const socket = new WebSocket(endpoint.toString(), {
      headers: {
        Authorization: `Bearer ${context.rimeApiKey}`,
      },
    });

    let settled = false;
    let opened = false;
    let sentFlushAndEos = false;
    let consumerStopped = false;
    let audioPipeline: Promise = Promise.resolve();

    const cleanup = (): void => {
      signal.removeEventListener('abort', onAbort);
      socket.off('open', onOpen);
      socket.off('message', onMessage);
      socket.off('close', onClose);
      socket.off('error', onSocketError);
    };

    const resolveOnce = (): void => {
      if (settled) return;
      settled = true;
      cleanup();
      resolve();
    };

    const rejectOnce = (error: Error): void => {
      if (settled) return;
      settled = true;
      cleanup();
      try {
        if (
          socket.readyState === WebSocket.CONNECTING
          || socket.readyState === WebSocket.OPEN
        ) {
          socket.close();
        }
      } catch {
        // ignore close race
      }
      reject(error);
    };

    const onAbort = (): void => {
      rejectOnce(createAbortError());
    };

    const onOpen = (): void => {
      opened = true;
      void (async () => {
        for (const chunk of textChunks) {
          await sendJson(socket, { text: chunk, contextId });
        }

        // One flush/eos sequence after all text preserves continuous provider buffering.
        await sendJson(socket, { operation: 'flush' });
        await sendJson(socket, { operation: 'eos' });
        sentFlushAndEos = true;
      })().catch((error: unknown) => {
        rejectOnce(toError(error, 'Failed to send Rime websocket payload'));
      });
    };

    const onSocketError = (error: Error): void => {
      rejectOnce(toError(error, 'Rime websocket TTS failed'));
    };

    const onMessage = (data: RawData, isBinary: boolean): void => {
      if (settled || isBinary) {
        return;
      }

      const parsed = parseJsonMessage(data);
      if (!parsed.ok) {
        rejectOnce(parsed.error);
        return;
      }

      const payload = parsed.value;
      const eventType = typeof payload.type === 'string' ? payload.type : '';

      if (eventType === 'error') {
        rejectOnce(new Error(readRimeErrorMessage(payload)));
        return;
      }

      if (eventType === 'chunk') {
        const base64 = typeof payload.data === 'string' ? payload.data : '';
        if (!base64) {
          return;
        }
        audioPipeline = audioPipeline
          .then(async () => {
            if (settled || consumerStopped) {
              return;
            }
            const keepGoing = await emitChunk(decodeBase64ToArrayBuffer(base64));
            if (!keepGoing) {
              consumerStopped = true;
              resolveOnce();
              try {
                if (
                  socket.readyState === WebSocket.CONNECTING
                  || socket.readyState === WebSocket.OPEN
                ) {
                  socket.close();
                }
              } catch {
                // ignore close race
              }
            }
          })
          .catch((error: unknown) => {
            rejectOnce(toError(error, 'Failed while streaming Rime audio chunk'));
          });
        return;
      }

      if (eventType === 'timestamps') {
        const mapped = mapRimeWordTimestamps(payload.word_timestamps);
        if (mapped.length > 0) {
          providerWordTimestamps = mapped;
        }
        return;
      }

      if (eventType === 'done' || eventType === 'complete' || eventType === 'eos') {
        void audioPipeline.then(() => resolveOnce()).catch((error: unknown) => {
          rejectOnce(toError(error, 'Failed while finalizing Rime audio stream'));
        });
      }
    };

    const onClose = (): void => {
      if (settled) {
        return;
      }
      if (consumerStopped) {
        resolveOnce();
        return;
      }
      if (signal.aborted) {
        rejectOnce(createAbortError());
        return;
      }
      if (!opened) {
        rejectOnce(new Error('Rime websocket closed before opening'));
        return;
      }
      if (!sentFlushAndEos) {
        rejectOnce(new Error('Rime websocket closed before flush/eos were sent'));
        return;
      }
      void audioPipeline.then(() => resolveOnce()).catch((error: unknown) => {
        rejectOnce(toError(error, 'Failed while completing Rime audio stream'));
      });
    };

    signal.addEventListener('abort', onAbort, { once: true });
    socket.on('open', onOpen);
    socket.on('message', onMessage);
    socket.on('close', onClose);
    socket.on('error', onSocketError);
  });

  if (providerWordTimestamps && providerWordTimestamps.length > 0) {
    return {
      precision: 'provider-word-timestamps',
      wordTimestamps: providerWordTimestamps,
      wordTimestampsTimeBase: 'segment',
    };
  }

  return { precision: 'segment' };
}

function sendJson(
  socket: WebSocket,
  payload: Record
): Promise {
  return new Promise((resolve, reject) => {
    if (socket.readyState !== WebSocket.OPEN) {
      reject(new Error('Rime websocket is not open'));
      return;
    }
    socket.send(JSON.stringify(payload), (error) => {
      if (error) {
        reject(error);
        return;
      }
      resolve();
    });
  });
}

function chunkTextNaturally(text: string, maxChars: number): string[] {
  const trimmed = text.trim();
  if (!trimmed) {
    return [];
  }

  const words = trimmed.split(/\s+/);
  const chunks: string[] = [];
  let current = '';

  for (const word of words) {
    const candidate = current ? `${current} ${word}` : word;
    if (candidate.length <= maxChars) {
      current = candidate;
      continue;
    }

    if (current) {
      chunks.push(current);
      current = '';
    }

    if (word.length <= maxChars) {
      current = word;
      continue;
    }

    for (let index = 0; index < word.length; index += maxChars) {
      chunks.push(word.slice(index, index + maxChars));
    }
  }

  if (current) {
    chunks.push(current);
  }

  return chunks;
}

function normalizeRimeWsEndpoint(rawUrl: string): URL {
  const endpoint = new URL(rawUrl);
  if (endpoint.protocol === 'https:') {
    endpoint.protocol = 'wss:';
  } else if (endpoint.protocol === 'http:') {
    endpoint.protocol = 'ws:';
  }

  const normalizedPath = endpoint.pathname.replace(/\/+$/, '');
  if (normalizedPath.endsWith('/ws')) {
    endpoint.pathname = `${normalizedPath}2`;
  } else {
    endpoint.pathname = normalizedPath;
  }
  return endpoint;
}

function createContextId(): string {
  return `segment-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 10)}`;
}

function parseJsonMessage(
  data: RawData
): { ok: true; value: Record } | { ok: false; error: Error } {
  const raw = rawDataToUtf8(data);
  try {
    const parsed = JSON.parse(raw) as unknown;
    if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
      return { ok: false, error: new Error('Rime websocket sent non-object JSON payload') };
    }
    return { ok: true, value: parsed as Record };
  } catch (error) {
    return {
      ok: false,
      error: new Error(`Rime websocket JSON parse failed: ${toError(error).message}`),
    };
  }
}

function rawDataToUtf8(data: RawData): string {
  if (typeof data === 'string') {
    return data;
  }
  if (Array.isArray(data)) {
    return Buffer.concat(data).toString('utf8');
  }
  if (data instanceof ArrayBuffer) {
    return Buffer.from(data).toString('utf8');
  }
  return Buffer.from(data).toString('utf8');
}

function readRimeErrorMessage(payload: Record): string {
  const message = toStringValue(payload.message);
  if (message) {
    return `Rime websocket error: ${message}`;
  }

  const errorString = toStringValue(payload.error);
  if (errorString) {
    return `Rime websocket error: ${errorString}`;
  }

  if (payload.error && typeof payload.error === 'object' && !Array.isArray(payload.error)) {
    const nested = payload.error as Record;
    const nestedMessage = toStringValue(nested.message);
    if (nestedMessage) {
      return `Rime websocket error: ${nestedMessage}`;
    }
    const nestedCode = toStringValue(nested.code);
    if (nestedCode) {
      return `Rime websocket error (${nestedCode})`;
    }
  }

  const code = toStringValue(payload.code);
  if (code) {
    return `Rime websocket error (${code})`;
  }

  return 'Rime websocket error';
}

function mapRimeWordTimestamps(value: unknown): SpokenWordTimestamp[] {
  if (!value || typeof value !== 'object' || Array.isArray(value)) {
    return [];
  }

  const payload = value as Record;
  const words = Array.isArray(payload.words) ? payload.words : [];
  const starts = Array.isArray(payload.start) ? payload.start : [];
  const ends = Array.isArray(payload.end) ? payload.end : [];
  const count = Math.min(words.length, starts.length, ends.length);
  if (count === 0) {
    return [];
  }

  const numericValues: number[] = [];
  for (let index = 0; index < count; index += 1) {
    const start = toFiniteNumber(starts[index]);
    const end = toFiniteNumber(ends[index]);
    if (start !== null) numericValues.push(start);
    if (end !== null) numericValues.push(end);
  }
  const useSeconds = shouldTreatAsSeconds(numericValues);

  const mapped: SpokenWordTimestamp[] = [];
  for (let index = 0; index < count; index += 1) {
    const word = toStringValue(words[index]);
    const start = toFiniteNumber(starts[index]);
    const end = toFiniteNumber(ends[index]);
    if (!word || start === null || end === null) {
      continue;
    }

    const startMs = toMilliseconds(start, useSeconds);
    const endMs = Math.max(startMs, toMilliseconds(end, useSeconds));
    mapped.push({ word, startMs, endMs });
  }

  return mapped;
}

function shouldTreatAsSeconds(values: number[]): boolean {
  if (values.length === 0) {
    return false;
  }
  if (values.some((value) => !Number.isInteger(value))) {
    return true;
  }
  const maxValue = Math.max(...values.map((value) => Math.abs(value)));
  return maxValue <= 300;
}

function toMilliseconds(value: number, useSeconds: boolean): number {
  return useSeconds ? Math.round(value * 1000) : Math.round(value);
}

function toFiniteNumber(value: unknown): number | null {
  if (typeof value !== 'number' || !Number.isFinite(value)) {
    return null;
  }
  return value;
}

function toStringValue(value: unknown): string | null {
  if (typeof value === 'string') {
    const trimmed = value.trim();
    return trimmed.length > 0 ? trimmed : null;
  }
  if (typeof value === 'number' && Number.isFinite(value)) {
    return String(value);
  }
  return null;
}

function createAbortError(): Error {
  try {
    return new DOMException('Rime websocket TTS request aborted', 'AbortError');
  } catch {
    const fallback = new Error('Rime websocket TTS request aborted');
    fallback.name = 'AbortError';
    return fallback;
  }
}

function toError(error: unknown, fallback = 'Unknown error'): Error {
  if (error instanceof Error) {
    return error;
  }
  if (typeof error === 'string' && error.trim().length > 0) {
    return new Error(error);
  }
  return new Error(fallback);
}



export abstract class BaseWebSocketAdapter {
  protected disconnecting = false;
  protected reconnectInProgress = false;
  protected consecutiveFailures = 0;

  protected readonly maxReconnectRetries: number;
  protected readonly reconnectBaseDelayMs: number;
  protected readonly reconnectMaxDelayMs: number;

  constructor(options?: {
    maxReconnectRetries?: number;
    reconnectBaseDelayMs?: number;
    reconnectMaxDelayMs?: number;
  }) {
    this.maxReconnectRetries = options?.maxReconnectRetries ?? 3;
    this.reconnectBaseDelayMs = options?.reconnectBaseDelayMs ?? 250;
    this.reconnectMaxDelayMs = options?.reconnectMaxDelayMs ?? 4000;
  }

  protected markDisconnecting(disconnecting: boolean): void {
    this.disconnecting = disconnecting;
  }

  protected resetFailureState(): void {
    this.consecutiveFailures = 0;
    this.reconnectInProgress = false;
  }

  protected markFailure(): void {
    this.consecutiveFailures += 1;
  }

  protected async tryReconnect(connectFn: () => Promise): Promise {
    if (this.disconnecting) return false;
    if (this.reconnectInProgress) return false;

    this.reconnectInProgress = true;
    try {
      for (let attempt = 0; attempt < this.maxReconnectRetries; attempt++) {
        if (this.disconnecting) return false;

        const delayMs = this.computeBackoffMs(attempt);
        await this.sleep(delayMs);

        try {
          await connectFn();
          this.resetFailureState();
          return true;
        } catch {
          this.markFailure();
        }
      }
      return false;
    } finally {
      this.reconnectInProgress = false;
    }
  }

  protected computeBackoffMs(attempt: number): number {
    const exponential = this.reconnectBaseDelayMs * Math.pow(2, attempt);
    return Math.min(exponential, this.reconnectMaxDelayMs);
  }

  protected sleep(ms: number): Promise {
    return new Promise((resolve) => setTimeout(resolve, ms));
  }
}



/**
 * Buffers LLM token deltas into speakable word chunks for Deepgram streaming.
 *
 * Responsibilities:
 * - keep token parsing state (`tokenBuffer`) separate from pre-audio buffering
 * - preserve original word order while audio hasn't started yet
 * - emit trailing non-space remainder on explicit flush
 */
export class DecomposedSpokenWordBuffer {
  private tokenBuffer = '';
  private preAudioBuffer = '';
  private audioStarted = false;

  ingestDelta(delta: string): string | null {
    if (!delta) {
      return null;
    }
    this.tokenBuffer += delta;
    const lastSpaceIdx = this.tokenBuffer.lastIndexOf(' ');
    if (lastSpaceIdx <= 0) {
      return null;
    }
    const completeWords = this.tokenBuffer.slice(0, lastSpaceIdx + 1);
    this.tokenBuffer = this.tokenBuffer.slice(lastSpaceIdx + 1);
    return this.bufferOrEmit(completeWords);
  }

  markAudioStarted(): string | null {
    if (this.audioStarted) {
      return null;
    }
    this.audioStarted = true;
    if (!this.preAudioBuffer) {
      return null;
    }
    const buffered = this.preAudioBuffer;
    this.preAudioBuffer = '';
    return buffered;
  }

  flushRemainder(): string | null {
    const remainder = this.tokenBuffer;
    this.tokenBuffer = '';
    if (!remainder.trim()) {
      return null;
    }
    return this.bufferOrEmit(remainder);
  }

  private bufferOrEmit(value: string): string | null {
    if (!value) {
      return null;
    }
    if (!this.audioStarted) {
      this.preAudioBuffer += value;
      return null;
    }
    return value;
  }
}



import type { DecomposedTtsProvider } from './tts/types.js';

/**
 * RMS threshold for detecting speech onset in PCM16 audio.
 * Values below this are considered silence (Deepgram TTS preamble).
 * PCM16 range is [-32768, 32767]; a typical quiet signal has RMS < 200.
 */
export const SPEECH_ONSET_RMS_THRESHOLD = 300;

export const DEEPGRAM_FLUSH_FALLBACK_POLL_MS = 500;
export const DEEPGRAM_FLUSH_FALLBACK_IDLE_MS = 1200;
export const DEEPGRAM_FLUSH_FALLBACK_FORCE_MS = 1400;

export const TURN_MARKERS = ['✓', '○', '◐'] as const;

export type TurnMarker = (typeof TURN_MARKERS)[number];

export interface ChatCompletionResponse {
  choices?: Array<{
    message?: ChatCompletionMessage;
    finish_reason?: string | null;
  }>;
}

export interface ChatCompletionStreamChunk {
  choices?: Array<{
    delta?: {
      content?: string | Array<{ type?: string; text?: string }>;
    };
  }>;
}

export interface ChatCompletionMessage {
  role?: 'system' | 'user' | 'assistant' | 'tool';
  content?: string | Array<{ type?: string; text?: string }> | null;
  tool_calls?: ChatCompletionToolCall[];
  tool_call_id?: string;
}

export interface ChatCompletionToolCall {
  id?: string;
  type?: string;
  function?: {
    name?: string;
    arguments?: string;
  };
}

export interface LlmRequestTool {
  type: 'function';
  function: {
    name: string;
    description: string;
    parameters: Record;
  };
}

export type LlmMessage =
  | { role: 'system' | 'user' | 'assistant'; content: string; tool_calls?: ChatCompletionToolCall[] }
  | { role: 'tool'; content: string; tool_call_id: string };

/**
 * Detect the sample offset within a PCM16 chunk where speech begins.
 * Returns the byte offset relative to the chunk start, or -1 if the
 * entire chunk is silence. Uses a small sliding window (128 samples ≈ 5ms)
 * to avoid triggering on isolated clicks/pops.
 */
export function detectSpeechOnsetInChunk(chunk: ArrayBuffer): number {
  const samples = new Int16Array(chunk);
  const windowSize = Math.min(128, samples.length);
  if (windowSize === 0) return -1;

  let sumSquares = 0;
  for (let i = 0; i < windowSize; i++) {
    const s = samples[i]!;
    sumSquares += s * s;
  }
  if (Math.sqrt(sumSquares / windowSize) >= SPEECH_ONSET_RMS_THRESHOLD) {
    return 0;
  }

  for (let i = windowSize; i < samples.length; i++) {
    const entering = samples[i]!;
    const leaving = samples[i - windowSize]!;
    sumSquares += entering * entering - leaving * leaving;
    const rms = Math.sqrt(Math.max(0, sumSquares) / windowSize);
    if (rms >= SPEECH_ONSET_RMS_THRESHOLD) {
      const onsetSample = i - windowSize + 1;
      return onsetSample * 2;
    }
  }

  return -1;
}

export function toRawDataUint8Array(value: unknown): Uint8Array | null {
  if (value instanceof Uint8Array) {
    return value;
  }
  if (ArrayBuffer.isView(value)) {
    return new Uint8Array(value.buffer, value.byteOffset, value.byteLength);
  }
  if (Array.isArray(value)) {
    const views: Uint8Array[] = [];
    let total = 0;
    for (const part of value) {
      if (part instanceof Uint8Array) {
        views.push(part);
        total += part.byteLength;
      } else if (ArrayBuffer.isView(part)) {
        const view = new Uint8Array(part.buffer, part.byteOffset, part.byteLength);
        views.push(view);
        total += view.byteLength;
      } else if (part instanceof ArrayBuffer) {
        const view = new Uint8Array(part);
        views.push(view);
        total += view.byteLength;
      }
    }
    if (views.length === 0) return null;
    const merged = new Uint8Array(total);
    let offset = 0;
    for (const view of views) {
      merged.set(view, offset);
      offset += view.byteLength;
    }
    return merged;
  }
  return null;
}

export function parseJsonObject(raw: string): Record | null {
  try {
    const parsed = JSON.parse(raw) as unknown;
    if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
      return null;
    }
    return parsed as Record;
  } catch {
    return null;
  }
}

export function parseToolArgs(raw: string): Record {
  if (!raw.trim()) return {};
  const parsed = parseJsonObject(raw);
  if (parsed) return parsed;
  return { raw };
}

export function sanitizeToolCalls(
  value: ChatCompletionToolCall[] | undefined
): ChatCompletionToolCall[] {
  if (!Array.isArray(value)) return [];
  const calls: ChatCompletionToolCall[] = [];
  for (const call of value) {
    if (!call || typeof call !== 'object') continue;
    const name = call.function?.name;
    if (typeof name !== 'string' || !name.trim()) continue;
    calls.push(call);
  }
  return calls;
}

export function safeStringify(value: unknown): string {
  if (typeof value === 'string') return value;
  try {
    const serialized = JSON.stringify(value);
    if (typeof serialized === 'string') {
      return serialized;
    }
    return String(value);
  } catch {
    return String(value);
  }
}

export async function* emptyAsyncGenerator(): AsyncGenerator {
  // yields nothing
}

export async function* singleValueGenerator(value: string): AsyncGenerator {
  if (value) yield value;
}

export async function* prependToAsyncGenerator(
  prefix: string,
  source: AsyncIterable
): AsyncGenerator {
  if (prefix) yield prefix;
  yield* source;
}

export function clampNumber(value: number, min: number, max: number): number {
  if (!Number.isFinite(value)) {
    return min;
  }
  return Math.min(max, Math.max(min, value));
}

export function roundTo(value: number, digits: number): number {
  const factor = 10 ** digits;
  return Math.round(value * factor) / factor;
}

export function parseMarker(
  text: string,
  markerMode: boolean
): { marker: TurnMarker; text: string } {
  const trimmed = text.trim();
  if (!markerMode || trimmed.length === 0) {
    return {
      marker: '✓',
      text: trimmed,
    };
  }

  const marker = trimmed[0] as TurnMarker;
  if (!TURN_MARKERS.includes(marker)) {
    return {
      marker: '✓',
      text: trimmed,
    };
  }

  return {
    marker,
    text: trimmed.slice(1).trimStart(),
  };
}

export function makeItemId(prefix: string): string {
  const random = Math.random().toString(36).slice(2, 10);
  return `${prefix}-${Date.now()}-${random}`;
}

export function computeRmsPcm16(input: ArrayBuffer): number {
  const bytes = new DataView(input);
  const sampleCount = Math.floor(bytes.byteLength / 2);
  if (sampleCount <= 0) return 0;

  let sumSquares = 0;
  for (let i = 0; i < sampleCount; i += 1) {
    const sample = bytes.getInt16(i * 2, true) / 32768;
    sumSquares += sample * sample;
  }

  return Math.sqrt(sumSquares / sampleCount);
}

export function concatUint8Arrays(parts: Uint8Array[]): Uint8Array {
  const total = parts.reduce((sum, part) => sum + part.byteLength, 0);
  const output = new Uint8Array(total);
  let offset = 0;
  for (const part of parts) {
    output.set(part, offset);
    offset += part.byteLength;
  }
  return output;
}

export function encodeWavPcm16Mono(pcm: Uint8Array, sampleRate: number): ArrayBuffer {
  const headerSize = 44;
  const wav = new ArrayBuffer(headerSize + pcm.byteLength);
  const view = new DataView(wav);
  const bytes = new Uint8Array(wav);

  writeAscii(bytes, 0, 'RIFF');
  view.setUint32(4, 36 + pcm.byteLength, true);
  writeAscii(bytes, 8, 'WAVE');
  writeAscii(bytes, 12, 'fmt ');
  view.setUint32(16, 16, true);
  view.setUint16(20, 1, true);
  view.setUint16(22, 1, true);
  view.setUint32(24, sampleRate, true);
  view.setUint32(28, sampleRate * 2, true);
  view.setUint16(32, 2, true);
  view.setUint16(34, 16, true);
  writeAscii(bytes, 36, 'data');
  view.setUint32(40, pcm.byteLength, true);
  bytes.set(pcm, headerSize);

  return wav;
}

export function writeAscii(target: Uint8Array, offset: number, value: string): void {
  for (let i = 0; i < value.length; i += 1) {
    target[offset + i] = value.charCodeAt(i);
  }
}

export function sleep(ms: number): Promise {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

export function extractChatCompletionText(payload: ChatCompletionResponse): string {
  const content = payload.choices?.[0]?.message?.content;
  if (typeof content === 'string') {
    return content.trim();
  }
  if (!Array.isArray(content)) {
    return '';
  }
  return content
    .map((part) => (typeof part?.text === 'string' ? part.text : ''))
    .join('')
    .trim();
}

export function extractChatCompletionMessageText(message: ChatCompletionMessage): string {
  const content = message.content;
  if (typeof content === 'string') {
    return content.trim();
  }
  if (!Array.isArray(content)) {
    return '';
  }
  return content
    .map((part) => (typeof part?.text === 'string' ? part.text : ''))
    .join('')
    .trim();
}

export function extractChatCompletionDeltaText(chunk: ChatCompletionStreamChunk): string {
  const content = chunk.choices?.[0]?.delta?.content;
  if (typeof content === 'string') {
    return content;
  }
  if (!Array.isArray(content)) {
    return '';
  }
  return content
    .map((part) => (typeof part?.text === 'string' ? part.text : ''))
    .join('');
}

export function splitSpeakableText(buffer: string): { segments: string[]; remainder: string } {
  if (!buffer) {
    return { segments: [], remainder: '' };
  }

  const segments: string[] = [];
  let start = 0;
  let candidate = -1;
  const minSegmentChars = 16;
  const earlySegmentChars = 8;
  const whitespaceSegmentChars = 18;
  const forceFlushChars = 72;
  const firstSegmentForceFlushChars = 28;

  const pushSegment = (endExclusive: number): void => {
    const raw = buffer.slice(start, endExclusive).trim();
    if (raw.length > 0) {
      segments.push(raw);
    }
    start = endExclusive;
    candidate = -1;
  };

  for (let i = 0; i < buffer.length; i += 1) {
    const char = buffer[i];
    if (char === '.' || char === '!' || char === '?' || char === ';' || char === '\n') {
      candidate = i + 1;
    } else if ((char === ',' || char === ':') && i + 1 - start >= 28) {
      candidate = i + 1;
    } else if (char === ' ' && i + 1 - start >= whitespaceSegmentChars) {
      candidate = i + 1;
    }

    const minCharsForSplit = segments.length === 0 ? earlySegmentChars : minSegmentChars;
    if (candidate > start && candidate - start >= minCharsForSplit) {
      pushSegment(candidate);
      continue;
    }

    const forceLimit = segments.length === 0 ? firstSegmentForceFlushChars : forceFlushChars;
    if (i + 1 - start >= forceLimit) {
      let splitAt = buffer.lastIndexOf(' ', i);
      if (splitAt <= start) {
        splitAt = i;
      }
      pushSegment(splitAt + 1);
    }
  }

  const remainder = buffer.slice(start);
  return { segments, remainder };
}

export function shouldFlushDeepgramStream(
  delta: string,
  pendingChars: number,
  completedFlushes: number,
  punctuationChunkingEnabled: boolean
): boolean {
  if (pendingChars <= 0) return false;

  if (!punctuationChunkingEnabled) {
    const baseThreshold = completedFlushes === 0 ? 140 : 220;
    const overflowThreshold = baseThreshold + 72;
    const hasSentenceBoundary = /[.!?;\n]/.test(delta);
    if (pendingChars < baseThreshold) return false;

    if (hasSentenceBoundary) return true;
    if (/\s/.test(delta) && pendingChars >= baseThreshold + 12) return true;
    return pendingChars >= overflowThreshold;
  }

  const hasSentenceBoundary = /[.!?;\n]/.test(delta);
  const hasMinorBoundary = /[,]/.test(delta);
  const boundaryThreshold = completedFlushes === 0 ? 24 : 64;
  const hasWhitespaceBoundary = /\s/.test(delta);

  if (hasSentenceBoundary && pendingChars >= boundaryThreshold) {
    return true;
  }
  if (completedFlushes === 0 && hasWhitespaceBoundary && pendingChars >= 32) {
    return true;
  }
  if (hasMinorBoundary && pendingChars >= 96) {
    return true;
  }
  if (completedFlushes === 0 && pendingChars >= 64) {
    return true;
  }
  if (pendingChars >= 180) {
    return true;
  }

  return false;
}

export function isQwenTtsModelId(model: string): boolean {
  const normalized = model.toLowerCase();
  return normalized.includes('qwen3') || normalized.includes('qwen-tts');
}

export function defaultInlineTtsChunkingEnabled(
  ttsProvider: DecomposedTtsProvider,
  ttsModel: string
): boolean {
  if (ttsProvider === 'local' && isQwenTtsModelId(ttsModel)) {
    return false;
  }
  return true;
}

export function countWords(text: string): number {
  const trimmed = text.trim();
  if (!trimmed) {
    return 0;
  }
  return trimmed.split(/\s+/).length;
}



import type { AudioFrame } from '../types.js';

/**
 * Lightweight PCM16 mono resampler for runtime boundary adaptation.
 * Uses linear interpolation and preserves mono PCM16 framing.
 */
export function resamplePcm16Mono(frame: AudioFrame, targetSampleRate: number): AudioFrame {
  if (frame.format !== 'pcm16') {
    throw new Error(`Unsupported audio format: ${frame.format}`);
  }
  if (frame.sampleRate <= 0 || targetSampleRate <= 0) {
    throw new Error(
      `Invalid sample rate conversion: ${frame.sampleRate} -> ${targetSampleRate}`
    );
  }
  if (frame.sampleRate === targetSampleRate) {
    return frame;
  }
  if (frame.data.byteLength % 2 !== 0) {
    throw new Error(`PCM16 payload must be 2-byte aligned, got ${frame.data.byteLength} bytes`);
  }

  const source = new Int16Array(frame.data);
  if (source.length === 0) {
    return { ...frame, sampleRate: targetSampleRate };
  }

  const ratio = frame.sampleRate / targetSampleRate;
  const targetLength = Math.max(1, Math.round(source.length / ratio));
  const target = new Int16Array(targetLength);

  if (targetLength === 1) {
    target[0] = source[0] ?? 0;
  } else {
    for (let i = 0; i < targetLength; i++) {
      const position = i * ratio;
      const index = Math.floor(position);
      const fractional = position - index;
      const nextIndex = Math.min(index + 1, source.length - 1);
      const s1 = source[index] ?? source[source.length - 1] ?? 0;
      const s2 = source[nextIndex] ?? s1;
      target[i] = Math.round(s1 + (s2 - s1) * fractional);
    }
  }

  return {
    data: target.buffer,
    sampleRate: targetSampleRate,
    format: 'pcm16',
  };
}



import type { EventHandler } from '../types.js';

type EventKey = {
  [K in keyof Events]-?: NonNullable extends (...args: any[]) => void ? K : never;
}[keyof Events];

export class TypedEventEmitter {
  private handlers: Partial<Record<keyof Events, Set<(...args: any[]) => void>>> = {};

  on<K extends EventKey>(event: K, handler: EventHandler): void {
    const set = this.handlers[event] ?? new Set<(...args: any[]) => void>();
    set.add(handler as (...args: any[]) => void);
    this.handlers[event] = set;
  }

  off<K extends EventKey>(event: K, handler: EventHandler): void {
    const set = this.handlers[event];
    if (!set) return;
    set.delete(handler as (...args: any[]) => void);
    if (set.size === 0) {
      delete this.handlers[event];
    }
  }

  emit<K extends EventKey>(event: K, ...args: Parameters<EventHandler>): void {
    const set = this.handlers[event];
    if (!set || set.size === 0) return;

    for (const handler of set) {
      (handler as (...eventArgs: Parameters<EventHandler>) => void)(...args);
    }
  }

  removeAllListeners(): void {
    this.handlers = {};
  }
}



import type {
  ProviderAdapter,
  ProviderCapabilities,
  ProviderDescriptor,
  SessionInput,
  VoiceProviderId,
  VoiceRuntime,
  VoiceSession,
} from '../types.js';
import { VoiceSessionImpl } from './voice-session.js';

export interface ProviderRegistration {
  id: VoiceProviderId;
  label: string;
  createAdapter: () => ProviderAdapter;
  capabilities?: ProviderCapabilities;
}

interface ResolvedProviderRegistration {
  id: VoiceProviderId;
  label: string;
  createAdapter: () => ProviderAdapter;
  capabilities: ProviderCapabilities;
}

export class VoiceRuntimeImpl implements VoiceRuntime {
  private readonly providers = new Map();

  constructor(registrations: ProviderRegistration[]) {
    for (const registration of registrations) {
      this.register(registration);
    }
  }

  listProviders(): ProviderDescriptor[] {
    return [...this.providers.values()].map((provider) => ({
      id: provider.id,
      label: provider.label,
      capabilities: provider.capabilities,
    }));
  }

  async createSession(input: SessionInput): Promise {
    const provider = this.providers.get(input.provider);
    if (!provider) {
      throw new Error(`Provider not registered: ${input.provider}`);
    }

    const adapter = provider.createAdapter();
    if (adapter.id !== input.provider) {
      throw new Error(
        `Adapter id mismatch: expected ${input.provider}, got ${adapter.id}`
      );
    }

    return new VoiceSessionImpl(adapter, input);
  }

  private register(registration: ProviderRegistration): void {
    const capabilities =
      registration.capabilities ?? registration.createAdapter().capabilities();

    this.providers.set(registration.id, {
      id: registration.id,
      label: registration.label,
      createAdapter: registration.createAdapter,
      capabilities,
    });
  }
}

export function createVoiceRuntime(registrations: ProviderRegistration[]): VoiceRuntime {
  return new VoiceRuntimeImpl(registrations);
}



import type { SpokenWordTimestamp } from '../types.js';

interface CumulativeWordTimestamp {
  id: string;
  word: string;
  startMs: number;
  endMs: number;
  segmentIndex: number;
}

export class WordTimeline {
  private readonly words: CumulativeWordTimestamp[] = [];
  private readonly dedupeKeys = new Set();
  private segmentIndex = -1;
  private segmentOffsetMs = 0;
  private wordCounter = 0;

  get length(): number {
    return this.words.length;
  }

  hasWords(): boolean {
    return this.words.length > 0;
  }

  beginSegment(offsetMs: number): void {
    this.segmentIndex += 1;
    this.segmentOffsetMs = Number.isFinite(offsetMs) ? Math.max(0, offsetMs) : 0;
  }

  addWords(wordTimestamps: SpokenWordTimestamp[]): void {
    if (!Array.isArray(wordTimestamps) || wordTimestamps.length === 0) {
      return;
    }
    if (this.segmentIndex < 0) {
      this.beginSegment(0);
    }

    let added = false;
    for (const timestamp of wordTimestamps) {
      const normalized = normalizeWordTimestamp(timestamp);
      if (!normalized) {
        continue;
      }

      const absoluteStartMs = this.segmentOffsetMs + normalized.startMs;
      const absoluteEndMs = this.segmentOffsetMs + normalized.endMs;
      const dedupeKey = `${normalized.word}|${toDedupeMs(absoluteStartMs)}|${toDedupeMs(absoluteEndMs)}`;
      if (this.dedupeKeys.has(dedupeKey)) {
        continue;
      }

      this.wordCounter += 1;
      this.words.push({
        id: `word-${this.wordCounter}`,
        word: normalized.word,
        startMs: absoluteStartMs,
        endMs: absoluteEndMs,
        segmentIndex: this.segmentIndex,
      });
      this.dedupeKeys.add(dedupeKey);
      added = true;
    }

    if (added && this.words.length > 1) {
      this.words.sort((left, right) => {
        if (left.startMs !== right.startMs) {
          return left.startMs - right.startMs;
        }
        if (left.endMs !== right.endMs) {
          return left.endMs - right.endMs;
        }
        return left.segmentIndex - right.segmentIndex;
      });
    }
  }

  getSpokenTextAt(playbackMs: number): {
    text: string;
    wordCount: number;
    wordIndex?: number;
  } {
    if (this.words.length === 0) {
      return { text: '', wordCount: 0 };
    }

    const clampedPlaybackMs = Number.isFinite(playbackMs) ? Math.max(0, playbackMs) : 0;
    const lastWordIndex = findLastStartedWordIndex(this.words, clampedPlaybackMs);
    if (lastWordIndex < 0) {
      return { text: '', wordCount: 0 };
    }

    const spokenWords = this.words.slice(0, lastWordIndex + 1).map((word) => word.word);
    const text = spokenWords.join(' ');
    const wordCount = spokenWords.length;
    return {
      text,
      wordCount,
      wordIndex: wordCount > 0 ? wordCount - 1 : undefined,
    };
  }

  getWordSpans(): Array<{
    id: string;
    text: string;
    startMs: number;
    endMs: number;
    type: 'word';
  }> {
    return this.words.map((word) => ({
      id: word.id,
      text: word.word,
      startMs: word.startMs,
      endMs: word.endMs,
      type: 'word',
    }));
  }

  reset(): void {
    this.words.length = 0;
    this.dedupeKeys.clear();
    this.segmentIndex = -1;
    this.segmentOffsetMs = 0;
    this.wordCounter = 0;
  }
}

function normalizeWordTimestamp(
  value: SpokenWordTimestamp
): { word: string; startMs: number; endMs: number } | null {
  if (!value || typeof value.word !== 'string') {
    return null;
  }

  const word = value.word.trim();
  if (!word) {
    return null;
  }
  if (!Number.isFinite(value.startMs) || !Number.isFinite(value.endMs)) {
    return null;
  }

  const startMs = Math.max(0, value.startMs);
  const endMs = Math.max(startMs, value.endMs);
  return { word, startMs, endMs };
}

function findLastStartedWordIndex(
  words: CumulativeWordTimestamp[],
  playbackMs: number
): number {
  let low = 0;
  let high = words.length - 1;
  let found = -1;

  while (low <= high) {
    const middle = (low + high) >> 1;
    const candidate = words[middle];
    if (!candidate) {
      break;
    }
    if (candidate.startMs < playbackMs) {
      found = middle;
      low = middle + 1;
    } else {
      high = middle - 1;
    }
  }

  return found;
}

function toDedupeMs(value: number): number {
  return Math.round(value * 1000);
}



declare module '@echogarden/fvad-wasm' {
  interface FvadModule {
    HEAP16: Int16Array;
    _fvad_new(): number;
    _fvad_free(instancePtr: number): void;
    _fvad_set_mode(instancePtr: number, mode: number): number;
    _fvad_set_sample_rate(instancePtr: number, sampleRate: number): number;
    _fvad_process(instancePtr: number, framePtr: number, frameLengthSamples: number): number;
    _malloc(size: number): number;
    _free(ptr: number): void;
  }

  type FvadFactory = (moduleArg?: Record) => Promise;

  const createFvadModule: FvadFactory;
  export default createFvadModule;
}



import { createRequire } from 'module';
import { resamplePcm16Mono } from '../media/resample-pcm16.js';
import type { AudioFrame } from '../types.js';

interface RnnoiseWasmModule {
  HEAPF32: Float32Array;
  _malloc(size: number): number;
  _free(ptr: number): void;
  _rnnoise_create(modelPtr: number): number;
  _rnnoise_destroy(statePtr: number): void;
  _rnnoise_process_frame(statePtr: number, outPtr: number, inPtr: number): number;
}

export interface RnnoiseProcessResult {
  filtered: ArrayBuffer;
  speechProbability: number;
}

const RNNOISE_SAMPLE_RATE = 48_000;
const RNNOISE_FRAME_SAMPLES = 480; // 10ms at 48kHz
const FLOAT32_BYTES = Float32Array.BYTES_PER_ELEMENT;
const require = createRequire(import.meta.url);

/**
 * Lightweight RNNoise wrapper used as an optional pre-VAD neural filter.
 * Falls back cleanly if initialization fails.
 */
export class RnnoiseProcessor {
  private readonly module: RnnoiseWasmModule | null;
  private readonly statePtr: number;
  private readonly inPtr: number;
  private readonly outPtr: number;

  constructor() {
    try {
      const rnnoisePackage = require('@jitsi/rnnoise-wasm') as {
        createRNNWasmModuleSync?: () => unknown;
      };
      const moduleFactory = rnnoisePackage.createRNNWasmModuleSync;
      if (typeof moduleFactory !== 'function') {
        throw new Error('createRNNWasmModuleSync is unavailable');
      }
      const module = moduleFactory() as RnnoiseWasmModule;
      const statePtr = module._rnnoise_create(0);
      if (!statePtr) {
        throw new Error('rnnoise_create returned null pointer');
      }
      const inPtr = module._malloc(RNNOISE_FRAME_SAMPLES * FLOAT32_BYTES);
      const outPtr = module._malloc(RNNOISE_FRAME_SAMPLES * FLOAT32_BYTES);
      if (!inPtr || !outPtr) {
        if (inPtr) module._free(inPtr);
        if (outPtr) module._free(outPtr);
        module._rnnoise_destroy(statePtr);
        throw new Error('rnnoise malloc failed');
      }

      this.module = module;
      this.statePtr = statePtr;
      this.inPtr = inPtr;
      this.outPtr = outPtr;
    } catch {
      this.module = null;
      this.statePtr = 0;
      this.inPtr = 0;
      this.outPtr = 0;
    }
  }

  isAvailable(): boolean {
    return this.module !== null;
  }

  process(input: ArrayBuffer, sampleRate: number): RnnoiseProcessResult | null {
    if (!this.module || sampleRate <= 0 || input.byteLength === 0) {
      return null;
    }
    if (input.byteLength % 2 !== 0) {
      return null;
    }

    const frame: AudioFrame = {
      data: input,
      sampleRate,
      format: 'pcm16',
    };
    const at48k = sampleRate === RNNOISE_SAMPLE_RATE
      ? frame
      : resamplePcm16Mono(frame, RNNOISE_SAMPLE_RATE);

    const inputPcm = new Int16Array(at48k.data);
    if (inputPcm.length === 0) {
      return null;
    }

    const denoised = new Float32Array(inputPcm.length);
    let speechProbabilitySum = 0;
    let speechProbabilityFrames = 0;

    for (let offset = 0; offset < inputPcm.length; offset += RNNOISE_FRAME_SAMPLES) {
      const size = Math.min(RNNOISE_FRAME_SAMPLES, inputPcm.length - offset);
      const heapOffsetIn = this.inPtr >> 2;
      const heapOffsetOut = this.outPtr >> 2;

      for (let i = 0; i < RNNOISE_FRAME_SAMPLES; i += 1) {
        const sample =
          i < size
            ? (inputPcm[offset + i] ?? 0) / 32768
            : 0;
        this.module.HEAPF32[heapOffsetIn + i] = sample;
      }

      const speechProbability = this.module._rnnoise_process_frame(
        this.statePtr,
        this.outPtr,
        this.inPtr
      );
      if (Number.isFinite(speechProbability)) {
        speechProbabilitySum += speechProbability;
        speechProbabilityFrames += 1;
      }

      for (let i = 0; i < size; i += 1) {
        denoised[offset + i] = this.module.HEAPF32[heapOffsetOut + i] ?? 0;
      }
    }

    const denoisedPcm48k = float32ToPcm16ArrayBuffer(denoised);
    const backToInputRate = sampleRate === RNNOISE_SAMPLE_RATE
      ? denoisedPcm48k
      : resamplePcm16Mono(
          { data: denoisedPcm48k, sampleRate: RNNOISE_SAMPLE_RATE, format: 'pcm16' },
          sampleRate
        ).data;

    const averageSpeechProbability =
      speechProbabilityFrames > 0
        ? speechProbabilitySum / speechProbabilityFrames
        : 0;

    return {
      filtered: backToInputRate,
      speechProbability: clamp01(averageSpeechProbability),
    };
  }

  destroy(): void {
    if (!this.module) {
      return;
    }
    this.module._free(this.inPtr);
    this.module._free(this.outPtr);
    this.module._rnnoise_destroy(this.statePtr);
  }
}

function float32ToPcm16ArrayBuffer(input: Float32Array): ArrayBuffer {
  const pcm = new Int16Array(input.length);
  for (let i = 0; i < input.length; i += 1) {
    const sample = Math.max(-1, Math.min(1, input[i] ?? 0));
    pcm[i] = sample < 0 ? Math.round(sample * 0x8000) : Math.round(sample * 0x7fff);
  }
  return pcm.buffer;
}

function clamp01(value: number): number {
  if (!Number.isFinite(value)) {
    return 0;
  }
  return Math.max(0, Math.min(1, value));
}



import { RnnoiseProcessor } from './rnnoise-processor.js';
import { WebRtcVadProcessor } from './webrtc-vad-processor.js';

export type DecomposedVadEngine = 'rms' | 'rnnoise' | 'webrtc-vad';

const DEFAULT_RMS_ECHO_MULTIPLIER = 3.8;
const DEFAULT_ASSISTANT_RMS_MULTIPLIER = 3.0;
const DEFAULT_ASSISTANT_RMS_OFFSET = 0.02;
const RNNOISE_ECHO_ASSISTANT_RMS_MULTIPLIER = 1.7;
const RNNOISE_ECHO_ASSISTANT_RMS_OFFSET = 0.008;

export interface TurnDetectorInput {
  frameData: ArrayBuffer;
  frameSampleRate: number;
  minRms: number;
  assistantRms: number;
  echoSensitivePhase: boolean;
}

export interface TurnDetectorResult {
  hasSpeech: boolean;
  processedFrameData: ArrayBuffer;
  rms: number;
  speechThreshold: number;
  speechProbability?: number;
}

export interface TurnDetector {
  detect(input: TurnDetectorInput): TurnDetectorResult;
  destroy(): void;
}

export interface RmsDetectorOptions {
  echoRmsMultiplier?: number;
  assistantRmsMultiplier?: number;
  assistantRmsOffset?: number;
}

export interface RnnoiseDetectorOptions extends RmsDetectorOptions {
  speechThreshold: number;
  echoSpeechThresholdBoost: number;
  applyNeuralFilter: boolean;
}

export interface WebRtcVadDetectorOptions extends RmsDetectorOptions {
  mode: 0 | 1 | 2 | 3;
  speechRatioThreshold: number;
  echoSpeechRatioBoost: number;
  applyNeuralFilter: boolean;
  frameMs?: 10 | 20 | 30;
  sampleRate?: 8_000 | 16_000 | 32_000 | 48_000;
}

export async function createTurnDetector(
  engine: DecomposedVadEngine,
  options: {
    rmsOptions?: RmsDetectorOptions;
    rnnoiseOptions?: RnnoiseDetectorOptions;
    webrtcVadOptions?: WebRtcVadDetectorOptions;
  }
): Promise {
  if (engine === 'webrtc-vad' && options.webrtcVadOptions) {
    return WebRtcVadTurnDetector.create(options.webrtcVadOptions);
  }
  if (engine === 'rnnoise' && options.rnnoiseOptions) {
    return new RnnoiseTurnDetector(options.rnnoiseOptions);
  }
  return new RmsTurnDetector(options.rmsOptions ?? {});
}

export class RmsTurnDetector implements TurnDetector {
  private readonly echoRmsMultiplier: number;
  private readonly assistantRmsMultiplier: number;
  private readonly assistantRmsOffset: number;

  constructor(options: RmsDetectorOptions) {
    this.echoRmsMultiplier = options.echoRmsMultiplier ?? DEFAULT_RMS_ECHO_MULTIPLIER;
    this.assistantRmsMultiplier =
      options.assistantRmsMultiplier ?? DEFAULT_ASSISTANT_RMS_MULTIPLIER;
    this.assistantRmsOffset = options.assistantRmsOffset ?? DEFAULT_ASSISTANT_RMS_OFFSET;
  }

  detect(input: TurnDetectorInput): TurnDetectorResult {
    const rms = computeRmsPcm16(input.frameData);
    const speechThreshold = input.echoSensitivePhase
      ? Math.max(
          input.minRms * this.echoRmsMultiplier,
          input.assistantRms * this.assistantRmsMultiplier + this.assistantRmsOffset
        )
      : input.minRms;

    return {
      hasSpeech: rms >= speechThreshold,
      processedFrameData: input.frameData,
      rms,
      speechThreshold,
    };
  }

  destroy(): void {
    // no-op
  }
}

export class RnnoiseTurnDetector implements TurnDetector {
  private readonly fallbackRmsDetector: RmsTurnDetector;
  private readonly rnnoise: RnnoiseProcessor;
  private readonly speechThreshold: number;
  private readonly echoSpeechThresholdBoost: number;
  private readonly applyNeuralFilter: boolean;
  private disabled = false;
  private warnedFrameFallback = false;

  constructor(options: RnnoiseDetectorOptions) {
    this.fallbackRmsDetector = new RmsTurnDetector(options);
    this.speechThreshold = options.speechThreshold;
    this.echoSpeechThresholdBoost = options.echoSpeechThresholdBoost;
    this.applyNeuralFilter = options.applyNeuralFilter;
    this.rnnoise = new RnnoiseProcessor();

    if (!this.rnnoise.isAvailable()) {
      this.disabled = true;
      console.warn(
        '[RnnoiseTurnDetector] RNNoise runtime unavailable; using RMS fallback detector.'
      );
    }
  }

  isUsingRmsFallback(): boolean {
    return this.disabled;
  }

  detect(input: TurnDetectorInput): TurnDetectorResult {
    if (this.disabled) {
      return this.fallbackRmsDetector.detect(input);
    }

    const filtered = this.rnnoise.process(input.frameData, input.frameSampleRate);
    if (!filtered) {
      if (!this.warnedFrameFallback) {
        this.warnedFrameFallback = true;
        console.warn(
          '[RnnoiseTurnDetector] RNNoise frame processing unavailable; falling back to RMS for current session.'
        );
      }
      return this.fallbackRmsDetector.detect(input);
    }

    const processedFrameData = this.applyNeuralFilter ? filtered.filtered : input.frameData;
    const rms = computeRmsPcm16(processedFrameData);
    const rmsFallback = this.fallbackRmsDetector.detect({
      ...input,
      frameData: processedFrameData,
    });

    const threshold = input.echoSensitivePhase
      ? Math.min(0.99, this.speechThreshold + this.echoSpeechThresholdBoost)
      : this.speechThreshold;

    const probabilityPass = filtered.speechProbability >= threshold;
    const minRmsGate = input.echoSensitivePhase
      ? Math.max(input.minRms * 0.75, 0.006)
      : Math.max(input.minRms * 0.6, 0.004);
    const assistantEchoGate = input.echoSensitivePhase
      ? Math.max(
          minRmsGate,
          input.assistantRms * RNNOISE_ECHO_ASSISTANT_RMS_MULTIPLIER +
            RNNOISE_ECHO_ASSISTANT_RMS_OFFSET
        )
      : minRmsGate;

    const hasSpeech = input.echoSensitivePhase
      ? probabilityPass && rms >= assistantEchoGate
      : probabilityPass || rmsFallback.hasSpeech;

    return {
      hasSpeech,
      processedFrameData,
      rms,
      speechThreshold: threshold,
      speechProbability: filtered.speechProbability,
    };
  }

  destroy(): void {
    this.rnnoise.destroy();
  }
}

export class WebRtcVadTurnDetector implements TurnDetector {
  private readonly fallbackRmsDetector: RmsTurnDetector;
  private readonly webrtcVad: WebRtcVadProcessor;
  private readonly rnnoiseFilter: RnnoiseProcessor | null;
  private readonly speechRatioThreshold: number;
  private readonly echoSpeechRatioBoost: number;
  private disabled = false;
  private warnedFrameFallback = false;

  private constructor(
    options: WebRtcVadDetectorOptions,
    processor: WebRtcVadProcessor
  ) {
    this.fallbackRmsDetector = new RmsTurnDetector(options);
    this.speechRatioThreshold = options.speechRatioThreshold;
    this.echoSpeechRatioBoost = options.echoSpeechRatioBoost;
    this.rnnoiseFilter = options.applyNeuralFilter ? new RnnoiseProcessor() : null;
    this.webrtcVad = processor;

    if (!this.webrtcVad.isAvailable()) {
      this.disabled = true;
      console.warn(
        '[WebRtcVadTurnDetector] WebRTC VAD runtime unavailable; using RMS fallback detector.'
      );
    }

    if (this.rnnoiseFilter && !this.rnnoiseFilter.isAvailable()) {
      console.warn(
        '[WebRtcVadTurnDetector] RNNoise prefilter unavailable; using raw input frames for VAD.'
      );
    }
  }

  static async create(options: WebRtcVadDetectorOptions): Promise {
    const processor = await WebRtcVadProcessor.create({
      mode: options.mode,
      frameMs: options.frameMs ?? 20,
      sampleRate: options.sampleRate ?? 16_000,
    });
    return new WebRtcVadTurnDetector(options, processor);
  }

  isUsingRmsFallback(): boolean {
    return this.disabled;
  }

  detect(input: TurnDetectorInput): TurnDetectorResult {
    if (this.disabled) {
      return this.fallbackRmsDetector.detect(input);
    }

    let processedFrameData = input.frameData;
    if (this.rnnoiseFilter?.isAvailable()) {
      const filtered = this.rnnoiseFilter.process(input.frameData, input.frameSampleRate);
      if (filtered) {
        processedFrameData = filtered.filtered;
      }
    }

    const vadResult = this.webrtcVad.process(processedFrameData, input.frameSampleRate);
    if (!vadResult) {
      if (!this.warnedFrameFallback) {
        this.warnedFrameFallback = true;
        console.warn(
          '[WebRtcVadTurnDetector] WebRTC VAD frame processing unavailable; falling back to RMS for current session.'
        );
      }
      return this.fallbackRmsDetector.detect({
        ...input,
        frameData: processedFrameData,
      });
    }

    const threshold = input.echoSensitivePhase
      ? Math.min(0.99, this.speechRatioThreshold + this.echoSpeechRatioBoost)
      : this.speechRatioThreshold;
    const hasSpeech = vadResult.totalFrames > 0 && vadResult.speechProbability >= threshold;
    const rms = computeRmsPcm16(processedFrameData);

    return {
      hasSpeech,
      processedFrameData,
      rms,
      speechThreshold: threshold,
      speechProbability: vadResult.speechProbability,
    };
  }

  destroy(): void {
    this.webrtcVad.destroy();
    this.rnnoiseFilter?.destroy();
  }
}

function computeRmsPcm16(input: ArrayBuffer): number {
  const bytes = new DataView(input);
  const sampleCount = Math.floor(bytes.byteLength / 2);
  if (sampleCount <= 0) return 0;

  let sumSquares = 0;
  for (let i = 0; i < sampleCount; i += 1) {
    const sample = bytes.getInt16(i * 2, true) / 32768;
    sumSquares += sample * sample;
  }

  return Math.sqrt(sumSquares / sampleCount);
}



import { createRequire } from 'module';
import { resamplePcm16Mono } from '../media/resample-pcm16.js';
import type { AudioFrame } from '../types.js';

export interface WebRtcVadProcessResult {
  speechProbability: number;
  voicedFrames: number;
  totalFrames: number;
}

export interface WebRtcVadProcessorOptions {
  mode: 0 | 1 | 2 | 3;
  sampleRate: 8_000 | 16_000 | 32_000 | 48_000;
  frameMs: 10 | 20 | 30;
}

const DEFAULT_OPTIONS: WebRtcVadProcessorOptions = {
  mode: 3,
  sampleRate: 16_000,
  frameMs: 20,
};
const require = createRequire(import.meta.url);

interface FvadModule {
  HEAP16: Int16Array;
  _fvad_new(): number;
  _fvad_free(instancePtr: number): void;
  _fvad_set_mode(instancePtr: number, mode: number): number;
  _fvad_set_sample_rate(instancePtr: number, sampleRate: number): number;
  _fvad_process(instancePtr: number, framePtr: number, frameLengthSamples: number): number;
  _malloc(size: number): number;
  _free(ptr: number): void;
}

export class WebRtcVadProcessor {
  private readonly module: FvadModule | null;
  private readonly instancePtr: number;
  private readonly framePtr: number;
  private readonly options: WebRtcVadProcessorOptions;
  private pendingBytes = new Uint8Array(0);

  private constructor(
    module: FvadModule | null,
    options: WebRtcVadProcessorOptions,
    instancePtr = 0,
    framePtr = 0
  ) {
    this.module = module;
    this.options = options;
    this.instancePtr = instancePtr;
    this.framePtr = framePtr;
  }

  static async create(
    inputOptions: Partial = {}
  ): Promise {
    const options: WebRtcVadProcessorOptions = {
      ...DEFAULT_OPTIONS,
      ...inputOptions,
    };

    try {
      const modulePath = require.resolve('@echogarden/fvad-wasm/fvad.js');
      const imported = (await import(modulePath)) as {
        default?: (moduleArg?: Record) => Promise;
      };
      const createFvadModule = imported.default;
      if (typeof createFvadModule !== 'function') {
        return new WebRtcVadProcessor(null, options);
      }
      const module = (await createFvadModule()) as FvadModule;
      const instancePtr = module._fvad_new();
      if (!instancePtr) {
        return new WebRtcVadProcessor(null, options);
      }

      const modeResult = module._fvad_set_mode(instancePtr, options.mode);
      const sampleRateResult = module._fvad_set_sample_rate(instancePtr, options.sampleRate);
      const frameSamples = Math.floor((options.sampleRate * options.frameMs) / 1000);
      const framePtr = module._malloc(frameSamples * Int16Array.BYTES_PER_ELEMENT);

      if (modeResult !== 0 || sampleRateResult !== 0 || !framePtr) {
        if (framePtr) {
          module._free(framePtr);
        }
        module._fvad_free(instancePtr);
        return new WebRtcVadProcessor(null, options);
      }

      return new WebRtcVadProcessor(module, options, instancePtr, framePtr);
    } catch {
      return new WebRtcVadProcessor(null, options);
    }
  }

  isAvailable(): boolean {
    return this.module !== null && this.instancePtr !== 0 && this.framePtr !== 0;
  }

  process(input: ArrayBuffer, sampleRate: number): WebRtcVadProcessResult | null {
    if (!this.module || sampleRate <= 0 || input.byteLength === 0 || input.byteLength % 2 !== 0) {
      return null;
    }

    const frame: AudioFrame = {
      data: input,
      sampleRate,
      format: 'pcm16',
    };
    const vadRate = this.options.sampleRate;
    const normalized = sampleRate === vadRate ? frame : resamplePcm16Mono(frame, vadRate);
    const normalizedBytes = new Uint8Array(normalized.data);
    if (normalizedBytes.byteLength === 0) {
      return null;
    }

    const merged = new Uint8Array(this.pendingBytes.length + normalizedBytes.length);
    merged.set(this.pendingBytes, 0);
    merged.set(normalizedBytes, this.pendingBytes.length);

    const frameSamples = Math.floor((vadRate * this.options.frameMs) / 1000);
    const frameBytes = frameSamples * Int16Array.BYTES_PER_ELEMENT;
    const totalFrames = Math.floor(merged.byteLength / frameBytes);
    if (totalFrames <= 0) {
      this.pendingBytes = merged;
      return {
        speechProbability: 0,
        voicedFrames: 0,
        totalFrames: 0,
      };
    }

    let voicedFrames = 0;
    for (let frameIndex = 0; frameIndex < totalFrames; frameIndex += 1) {
      const byteOffset = frameIndex * frameBytes;
      const samples = new Int16Array(
        merged.buffer,
        merged.byteOffset + byteOffset,
        frameSamples
      );
      this.module.HEAP16.set(samples, this.framePtr >> 1);
      const vadResult = this.module._fvad_process(this.instancePtr, this.framePtr, frameSamples);
      if (vadResult === 1) {
        voicedFrames += 1;
      }
    }

    const remainderOffset = totalFrames * frameBytes;
    this.pendingBytes = merged.slice(remainderOffset);

    return {
      speechProbability: voicedFrames / totalFrames,
      voicedFrames,
      totalFrames,
    };
  }

  destroy(): void {
    if (!this.module) {
      return;
    }
    if (this.framePtr) {
      this.module._free(this.framePtr);
    }
    if (this.instancePtr) {
      this.module._fvad_free(this.instancePtr);
    }
    this.pendingBytes = new Uint8Array(0);
  }
}



