import { navigateToSession } from '../../hooks/useRouter';
import type { SessionTreeNode } from '../../types';

function formatTime(dateStr: string): string {
  const date = new Date(dateStr);
  const now = new Date();
  const diffMs = now.getTime() - date.getTime();
  const diffMins = Math.floor(diffMs / 60000);
  const diffHours = Math.floor(diffMs / 3600000);
  const diffDays = Math.floor(diffMs / 86400000);

  if (diffMins < 1) return 'now';
  if (diffMins < 60) return `${diffMins}m`;
  if (diffHours < 24) return `${diffHours}h`;
  if (diffDays < 7) return `${diffDays}d`;
  return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
}

function hasRunningDescendant(node: SessionTreeNode): boolean {
  if (['pending', 'running', 'waiting_for_input'].includes(node.status)) return true;
  return node.children.some(hasRunningDescendant);
}

export function HistoryPanel() {
  const allTrees = useUnifiedSessionsStore((s) => s.allTrees);
  const sessionTree = useUnifiedSessionsStore((s) => s.sessionTree);
  const toggleHistoryPanel = useUnifiedSessionsStore((s) => s.toggleHistoryPanel);

  const rootSessions = useMemo(() => {
    return Array.from(allTrees.values())
      .filter((s) => s.type === 'voice')
      .sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime());
  }, [allTrees]);

  const currentRootId = sessionTree?.id ?? null;

  return (




        Sessions









        {rootSessions.length > 0 ? (
          rootSessions.map((session) => {
            const isActive = hasRunningDescendant(session);
            const isCurrent = session.id === currentRootId;
            const preview = session.name || 'Voice session';
            const time = formatTime(session.created_at);

            return (
               {
                  navigateToSession(session.id);
                  toggleHistoryPanel();
                }}
              >

                {preview}
                {time}

            );
          })
        ) : (


            No sessions yet

        )}


  );
}



import { useMemo } from 'react';
import { useVoiceState, useUnifiedSessionsStore } from '../../stores';
import type { AgentState } from '../../types';

const stateLabels: Record = {
  idle: 'Ready',
  listening: 'Listening',
  thinking: 'Processing',
  speaking: 'Speaking',
};

const stateColors: Record = {
  idle: 'var(--muted-foreground)',
  listening: 'var(--color-blue)',
  thinking: 'var(--color-purple)',
  speaking: 'var(--color-green)',
};

/**
 * Generate a smooth closed blob path from control points.
 * Uses cubic bezier curves for organic feel.
 */
function blobPath(points: Array<{ x: number; y: number }>, tension = 0.3): string {
  const n = points.length;
  if (n < 3) return '';

  const parts: string[] = [`M ${points[0]!.x} ${points[0]!.y}`];

  for (let i = 0; i < n; i++) {
    const p0 = points[(i - 1 + n) % n]!;
    const p1 = points[i]!;
    const p2 = points[(i + 1) % n]!;
    const p3 = points[(i + 2) % n]!;

    const cp1x = p1.x + (p2.x - p0.x) * tension;
    const cp1y = p1.y + (p2.y - p0.y) * tension;
    const cp2x = p2.x - (p3.x - p1.x) * tension;
    const cp2y = p2.y - (p3.y - p1.y) * tension;

    parts.push(`C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${p2.x} ${p2.y}`);
  }

  parts.push('Z');
  return parts.join(' ');
}

function VoiceBlob({ state }: { state: AgentState }) {
  const color = stateColors[state];
  const isActive = state !== 'idle';
  const isSpeaking = state === 'speaking';
  const isListening = state === 'listening';
  const isThinking = state === 'thinking';

  // Base blob radius and number of control points
  const cx = 75;
  const cy = 75;
  const baseR = 40;
  const pointCount = 8;

  // Generate multiple blob paths for animation layers
  const blobs = useMemo(() => {
    const configs = [
      { offset: 0, rVariance: 6, name: 'a' },
      { offset: Math.PI / pointCount, rVariance: 8, name: 'b' },
    ];

    return configs.map(({ offset, rVariance, name }) => {
      const points = Array.from({ length: pointCount }, (_, i) => {
        const angle = (i / pointCount) * Math.PI * 2 + offset;
        const r = baseR + (i % 2 === 0 ? rVariance : -rVariance * 0.5);
        return {
          x: cx + Math.cos(angle) * r,
          y: cy + Math.sin(angle) * r,
        };
      });
      return { name, d: blobPath(points) };
    });
  }, []);

  // Animation speed and scale per state
  const animDuration = isSpeaking ? '1.2s' : isListening ? '2.5s' : isThinking ? '1.8s' : '6s';
  const animDuration2 = isSpeaking ? '0.9s' : isListening ? '2s' : isThinking ? '1.5s' : '5s';

  return (










        {/* Ambient glow */}


        {/* Blob layer 1 — main shape */}


        {/* Blob layer 2 — offset, counter-rotated */}


        {/* Center dot */}





  );
}

