// ─── Voice Card ─────────────────────────────────────────────────────────────

interface VoiceCardProps {
  voice: VoiceMeta;
  isActive: boolean;
  onActivate: (label: string) => void;
  onDelete: (label: string) => void;
  deleting: string | null;
}

function VoiceCard({ voice, isActive, onActivate, onDelete, deleting }: VoiceCardProps) {
  const audioRef = useRef(null);
  const [playing, setPlaying] = useState(false);

  const togglePlay = useCallback(() => {
    if (playing && audioRef.current) {
      audioRef.current.pause();
      audioRef.current.currentTime = 0;
      setPlaying(false);
      return;
    }
    const audio = new Audio(voiceAudioUrl(voice.label));
    audioRef.current = audio;
    audio.onended = () => setPlaying(false);
    audio.onerror = () => setPlaying(false);
    audio.play();
    setPlaying(true);
  }, [playing, voice.label]);

  useEffect(() => {
    return () => {
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current = null;
      }
    };
  }, []);

  const isDeleting = deleting === voice.label;

  return (





{voice.label}


          {voice.language}
          {isActive && active}



      {voice.instruct && (

{voice.instruct}
      )}



        ref: {voice.refText.length > 60 ? voice.refText.slice(0, 60) + '...' : voice.refText}






            {playing ? (
              <></>
            ) : (

            )}


        {!isActive && (
           onActivate(voice.label)}
          >
            Set Active

        )}
         onDelete(voice.label)}
          disabled={isDeleting}
        >
          {isDeleting ? '...' : 'Delete'}



  );
}

// ─── Voice Design Form ──────────────────────────────────────────────────────

interface DesignFormState {
  label: string;
  instruct: string;
  text: string;
  language: string;
  seed: string;
}

const INITIAL_DESIGN_FORM: DesignFormState = {
  label: '',
  instruct: '',
  text: '',
  language: 'German',
  seed: '42',
};

// ─── Main Component ─────────────────────────────────────────────────────────

export function SettingsVoices() {
  const [voices, setVoices] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [deleting, setDeleting] = useState(null);

  // Design form
  const [form, setForm] = useState(INITIAL_DESIGN_FORM);
  const [designing, setDesigning] = useState(false);
  const [designError, setDesignError] = useState(null);

  const loadVoices = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const list = await fetchVoices();
      setVoices(list);
    } catch (err) {
      setError((err as Error).message);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    void loadVoices();
  }, [loadVoices]);

  const handleDelete = useCallback(
    async (label: string) => {
      setDeleting(label);
      try {
        await deleteVoiceApi(label);
        await loadVoices();
      } catch (err) {
        setError((err as Error).message);
      } finally {
        setDeleting(null);
      }
    },
    [loadVoices]
  );

  const handleDesign = useCallback(async () => {
    if (!form.label.trim() || !form.instruct.trim() || !form.text.trim()) {
      setDesignError('Label, instruct description, and reference text are required.');
      return;
    }
    setDesigning(true);
    setDesignError(null);
    try {
      await designVoice({
        label: form.label.trim(),
        instruct: form.instruct.trim(),
        text: form.text.trim(),
        language: form.language || 'German',
        seed: parseInt(form.seed, 10) || 42,
      });
      setForm(INITIAL_DESIGN_FORM);
      await loadVoices();
    } catch (err) {
      setDesignError((err as Error).message);
    } finally {
      setDesigning(false);
    }
  }, [form, loadVoices]);

  const updateField = (key: keyof DesignFormState, value: string) => {
    setForm((prev) => ({ ...prev, [key]: value }));
  };

  return (




      {/* Voice Library */}



          {loading ? (

Loading voices...
          ) : error ? (

{error}
          ) : voices.length === 0 ? (

No voices yet. Use Voice Design below to create one.
          ) : (
            voices.map((v) => (
               {}}
                onDelete={handleDelete}
                deleting={deleting}
              />
            ))
          )}



      {/* Voice Design */}


           updateField('label', e.target.value)}
            placeholder="cheerful-aria"
          />



           updateField('language', e.target.value)}
          >
            German
            English
            French
            Spanish
            Chinese
            Japanese
            Korean




           updateField('instruct', e.target.value)}
            placeholder="A cheerful and energetic female voice with a warm, friendly tone..."
            rows={3}
          />



           updateField('text', e.target.value)}
            placeholder="Hallo, ich bin dein neuer Sprachassistent..."
            rows={2}
          />



           updateField('seed', e.target.value)}
          />







              {designing ? 'Generating...' : 'Generate Voice'}

            {designing && (
              This may take 10-30 seconds...
            )}
            {designError && {designError}}




  );
}



