// ═══════════════════════════════════════════════════════════════════════════
// Stream Event Types
// ═══════════════════════════════════════════════════════════════════════════

/**
 * A single event in a demo stream.
 * Uses the same format as WebSocket messages for consistency.
 */
export interface StreamEvent {
  type: WSMessageType;
  payload: unknown;
  /** Delay in ms before emitting this event (for realistic timing) */
  delay?: number;
}

/**
 * A complete stream scenario with metadata.
 */
export interface StreamScenario {
  id: string;
  name: string;
  description: string;
  events: StreamEvent[];
}

// ═══════════════════════════════════════════════════════════════════════════
// Demo Configuration Types
// ═══════════════════════════════════════════════════════════════════════════

export type DemoCategory = 'subagent' | 'session' | 'conversation' | 'status';

/**
 * Props passed to demo wrapper components.
 */
export interface DemoProps {
  /** Events emitted so far in the stream */
  events: StreamEvent[];
  /** Whether the stream is currently playing */
  isPlaying: boolean;
  /** Reset the demo to initial state */
  onReset: () => void;
}

/**
 * Configuration for a single component demo.
 */
export interface DemoConfig {
  /** Unique identifier (kebab-case, e.g., 'activity-feed') */
  id: string;
  /** Display name */
  name: string;
  /** Short description */
  description: string;
  /** Category for sidebar grouping */
  category: DemoCategory;
  /** Component that renders the demo */
  component: ComponentType;
  /** Available stream scenarios */
  scenarios: StreamScenario[];
  /** Backend route for real streaming (optional) */
  backendRoute?: string;
}

// ═══════════════════════════════════════════════════════════════════════════
// Demo Registry
// ═══════════════════════════════════════════════════════════════════════════

const registry = new Map();

/**
 * Register a component demo.
 */
export function registerDemo(config: DemoConfig): void {
  if (registry.has(config.id)) {
    console.warn(`[DemoRegistry] Overwriting existing demo: ${config.id}`);
  }
  registry.set(config.id, config);
}

/**
 * Get a demo by ID.
 */
export function getDemo(id: string): DemoConfig | undefined {
  return registry.get(id);
}

/**
 * Get all registered demos.
 */
export function getAllDemos(): DemoConfig[] {
  return Array.from(registry.values());
}

/**
 * Get demos grouped by category.
 */
export function getDemosByCategory(): Map {
  const grouped = new Map();

  for (const demo of registry.values()) {
    const list = grouped.get(demo.category) || [];
    list.push(demo);
    grouped.set(demo.category, list);
  }

  return grouped;
}

/**
 * Category display names and order.
 */
export const categoryMeta: Record = {
  subagent: { name: 'Subagent Components', order: 1 },
  session: { name: 'Session Components', order: 2 },
  conversation: { name: 'Conversation Components', order: 3 },
  status: { name: 'Status Components', order: 4 },
};



import { useCallback, useEffect, useState } from 'react';
import {
  fetchVoiceConfig,
  saveVoiceConfig,
  type VoiceConfigDocument,
} from '../lib/voice-config-api';

export interface VoiceRuntimeConfigState {
  config: VoiceConfigDocument | null;
  setConfig: (next: VoiceConfigDocument) => void;
  loading: boolean;
  saving: boolean;
  error: string | null;
  reload: () => Promise;
  save: () => Promise;
}

export function useVoiceRuntimeConfig(): VoiceRuntimeConfigState {
  const [config, setConfig] = useState(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState(null);

  const load = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const next = await fetchVoiceConfig();
      setConfig(next);
    } catch (err) {
      setError((err as Error).message);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    void load();
  }, [load]);

  const save = useCallback(async () => {
    if (!config) return;

    setSaving(true);
    setError(null);
    try {
      const next = await saveVoiceConfig(config);
      setConfig(next);
    } catch (err) {
      setError((err as Error).message);
      throw err;
    } finally {
      setSaving(false);
    }
  }, [config]);

  return {
    config,
    setConfig,
    loading,
    saving,
    error,
    reload: load,
    save,
  };
}



// ═══════════════════════════════════════════════════════════════════════════
// Activity Utilities - Shared helpers for activity block rendering
// ═══════════════════════════════════════════════════════════════════════════

/**
 * Extract the last sentence from text for preview display.
 * Truncates to specified max length.
 */
export function getLastSentence(text: string, maxLength = 60): string {
  const sentences = text.split(/[.!?]\s+/);
  const last = sentences[sentences.length - 1] || '';
  return last.slice(0, maxLength) + (last.length > maxLength ? '...' : '');
}

/**
 * Format duration in milliseconds to seconds with one decimal.
 */
export function formatDuration(ms: number): string {
  return (ms / 1000).toFixed(1);
}

/**
 * Check if reasoning content is meaningful (not empty or placeholder).
 * Filters out known placeholder patterns from models that hide reasoning.
 */
export function hasUsefulReasoning(content: string): boolean {
  const trimmed = content.trim();
  if (!trimmed) return false;

  const placeholders = [
    '[REDACTED]',
    '[redacted]',
    'Redacted',
    '[Web search in progress...]',
  ];

  return !placeholders.some(
    (p) => trimmed === p || trimmed.startsWith(p)
  );
}

/**
 * Truncate text to specified length with ellipsis.
 */
export function truncateText(text: string, maxLength: number): string {
  if (text.length <= maxLength) return text;
  return text.slice(0, maxLength) + '...';
}

