/**
 * Static File Server - Serves the web dashboard from the Pi.
 *
 * Serves the built web dashboard on port 8080.
 * Access from any device on the local network: http://marlon.local:8080
 */

import http from 'http';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';
import type { Socket } from 'net';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const STATIC_PORT = parseInt(process.env.STATIC_PORT ?? '8080', 10);

// Path to the built web dashboard (sibling package: packages/web-ui)
const STATIC_DIR = path.resolve(__dirname, '../../../web-ui/dist');

let server: http.Server | null = null;
const openConnections = new Set();

const MIME_TYPES: Record = {
  '.html': 'text/html',
  '.js': 'application/javascript',
  '.css': 'text/css',
  '.json': 'application/json',
  '.png': 'image/png',
  '.jpg': 'image/jpeg',
  '.gif': 'image/gif',
  '.svg': 'image/svg+xml',
  '.ico': 'image/x-icon',
  '.woff': 'font/woff',
  '.woff2': 'font/woff2',
  '.ttf': 'font/ttf',
};

/**
 * Serve static files from the web/dist directory.
 */
function handleRequest(req: http.IncomingMessage, res: http.ServerResponse): void {
  // Only handle GET requests
  if (req.method !== 'GET') {
    res.writeHead(405);
    res.end('Method Not Allowed');
    return;
  }

  let urlPath = req.url ?? '/';

  // Remove query string
  const queryIndex = urlPath.indexOf('?');
  if (queryIndex !== -1) {
    urlPath = urlPath.substring(0, queryIndex);
  }

  // Default to index.html for root or SPA routes
  if (urlPath === '/' || !path.extname(urlPath)) {
    urlPath = '/index.html';
  }

  const filePath = path.join(STATIC_DIR, urlPath);

  // Security: Prevent directory traversal
  if (!filePath.startsWith(STATIC_DIR)) {
    res.writeHead(403);
    res.end('Forbidden');
    return;
  }

  // Check if file exists
  fs.stat(filePath, (err, stats) => {
    if (err || !stats.isFile()) {
      // For SPA, serve index.html for missing routes
      const indexPath = path.join(STATIC_DIR, 'index.html');
      fs.readFile(indexPath, (indexErr, data) => {
        if (indexErr) {
          res.writeHead(404);
          res.end('Not Found');
          return;
        }
        res.writeHead(200, { 'Content-Type': 'text/html' });
        res.end(data);
      });
      return;
    }

    // Serve the file
    const ext = path.extname(filePath).toLowerCase();
    const contentType = MIME_TYPES[ext] || 'application/octet-stream';

    fs.readFile(filePath, (readErr, data) => {
      if (readErr) {
        res.writeHead(500);
        res.end('Internal Server Error');
        return;
      }

      // Set cache headers for assets
      const cacheControl = ext === '.html' ? 'no-cache' : 'public, max-age=31536000';

      res.writeHead(200, {
        'Content-Type': contentType,
        'Cache-Control': cacheControl,
      });
      res.end(data);
    });
  });
}

/**
 * Start the static file server.
 */
export function startStaticServer(): Promise {
  return new Promise((resolve, reject) => {
    if (server) {
      console.log('[Static] Server already running');
      resolve();
      return;
    }

    // Check if dist directory exists
    if (!fs.existsSync(STATIC_DIR)) {
      console.log(`[Static] Warning: ${STATIC_DIR} not found. Build the web dashboard first.`);
      console.log('[Static] Run: cd ../web-ui && bun run build');
      resolve(); // Don't fail, just warn
      return;
    }

    server = http.createServer(handleRequest);
    openConnections.clear();

    server.on('connection', (socket) => {
      openConnections.add(socket);
      socket.on('close', () => {
        openConnections.delete(socket);
      });
    });

    server.on('error', (err) => {
      console.error('[Static] Server error:', err);
      server = null;
      openConnections.clear();
      reject(err);
    });

    server.listen(STATIC_PORT, '0.0.0.0', () => {
      console.log(`[Static] Dashboard server listening on port ${STATIC_PORT}`);
      console.log(`[Static] Access from local network: http://marlon.local:${STATIC_PORT}`);
      resolve();
    });
  });
}

/**
 * Stop the static file server.
 */
export function stopStaticServer(): Promise {
  return new Promise((resolve) => {
    if (!server) {
      resolve();
      return;
    }

    const currentServer = server;
    server = null;

    let settled = false;
    const finish = () => {
      if (settled) return;
      settled = true;
      openConnections.clear();
      resolve();
    };

    const timeout = setTimeout(() => {
      for (const socket of openConnections) {
        socket.destroy();
      }
      openConnections.clear();
      console.warn('[Static] Force shutdown after close timeout');
      finish();
    }, 2000);

    try {
      currentServer.close(() => {
        clearTimeout(timeout);
        console.log('[Static] Server stopped');
        finish();
      });
    } catch (error) {
      clearTimeout(timeout);
      console.warn('[Static] Error while closing server:', error);
      finish();
    }
  });
}



/**
 * Sessions Repository
 *
 * Unified CRUD operations for voice sessions, subagents, and terminals.
 * All session types are persisted with parent-child relationships.
 */

import type { Database } from 'bun:sqlite';
import { getDatabase, generateId } from '../database.js';

export type SessionStatus =
  | 'pending'
  | 'running'
  | 'waiting_for_input'
  | 'finished'
  | 'error'
  | 'cancelled';

export type SessionType = 'voice' | 'subagent' | 'terminal';

/** @deprecated Use 'subagent' instead */
export type OrchestratorType = 'orchestrator';

export type AgentName = 'cli' | 'web_search' | 'deep_thinking';

export type VoiceProfile = 'jarvis' | 'marvin';

export interface Session {
  id: string;
  type: SessionType;
  name: string | null; // Human-readable name (e.g., "swift-falcon")
  goal: string;
  status: SessionStatus;
  // Hierarchy
  parent_id: string | null;
  // Voice-specific
  profile: VoiceProfile | null; // 'jarvis' | 'marvin' - for voice sessions
  // Subagent-specific (formerly orchestrator)
  agent_name: AgentName | null;
  model: string | null;
  conversation_history: string | null; // JSON array
  background: boolean; // true = detached/fire-and-forget, doesn't block voice agent
  // Terminal-specific
  mac_session_id: string | null;
  tool_call_id: string | null; // Links to the tool call that created this session
  // Timestamps
  created_at: string;
  updated_at: string;
  finished_at: string | null;
}

/** @deprecated Use Session instead */
export type CliSession = Session;

export interface CreateVoiceInput {
  id: string; // Voice session ID is generated by VoiceAgent
  profile: VoiceProfile;
  goal?: string; // Optional goal, defaults to "Voice conversation"
  name?: string; // Human-readable session name
}

export interface CreateSubagentInput {
  id?: string;
  goal: string;
  agent_name: AgentName;
  model: string;
  parent_id?: string; // Voice session ID - links subagent to voice session
  background?: boolean; // If true, runs detached without blocking voice agent
  name?: string; // Human-readable session name
}

/** @deprecated Use CreateSubagentInput instead */
export interface CreateOrchestratorInput {
  id?: string;
  goal: string;
  agent_name: AgentName;
  model: string;
  parent_id?: string;
}

export interface CreateTerminalInput {
  id?: string;
  goal: string;
  parent_id: string; // Parent can be a voice or subagent session
  mac_session_id?: string;
  tool_call_id?: string; // Links to the tool call that created this session
  name?: string; // Human-readable session name (e.g. "swift-fox")
}

/** @deprecated Use CreateOrchestratorInput or CreateTerminalInput instead */
export interface CreateSessionInput {
  goal: string;
  id?: string;
  parent_id?: string;
  thread_id?: string;
}

/**
 * Session tree node for UI rendering
 */
export interface SessionTreeNode {
  id: string;
  type: SessionType;
  name: string | null; // Human-readable session name
  status: SessionStatus;
  goal: string;
  profile: VoiceProfile | null; // For voice sessions
  agent_name: AgentName | null; // For subagent sessions
  tool_call_id: string | null; // For terminals: links to the tool call that created them
  background: boolean; // For subagents: true if running detached from voice agent
  created_at: string;
  children: SessionTreeNode[];
}

export class CliSessionsRepository {
  private db: Database;

  constructor(db?: Database) {
    this.db = db ?? getDatabase();
  }

  // ============================================================================
  // CREATE METHODS
  // ============================================================================

  /**
   * Create a new voice session (persisted root of session tree).
   * Voice sessions are the root of all subagent and terminal sessions.
   */
  createVoice(input: CreateVoiceInput): Session {
    const now = new Date().toISOString();
    const goal = input.goal ?? `Voice conversation (${input.profile})`;

    this.db
      .query(
        `INSERT INTO cli_sessions
         (id, type, goal, status, profile, name, created_at, updated_at)
         VALUES (?, 'voice', ?, 'running', ?, ?, ?, ?)`
      )
      .run(input.id, goal, input.profile, input.name ?? null, now, now);

    return this.findById(input.id)!;
  }

  /**
   * Create a new subagent session (stateful LLM agent).
   * Subagents are typically children of voice sessions.
   *
   * @param input.background - If true, creates a detached session that runs independently
   *                           without blocking the voice agent. Background sessions can
   *                           notify the voice agent upon completion via callback.
   */
  createSubagent(input: CreateSubagentInput): Session {
    const id = input.id ?? generateId();
    const now = new Date().toISOString();
    const background = input.background ? 1 : 0;

    this.db
      .query(
        `INSERT INTO cli_sessions
         (id, type, goal, status, parent_id, agent_name, model, conversation_history, background, name, created_at, updated_at)
         VALUES (?, 'subagent', ?, 'running', ?, ?, ?, '[]', ?, ?, ?, ?)`
      )
      .run(id, input.goal, input.parent_id ?? null, input.agent_name, input.model, background, input.name ?? null, now, now);

    return this.findById(id)!;
  }

  /**
   * @deprecated Use createSubagent instead.
   */
  createOrchestrator(input: CreateOrchestratorInput): Session {
    return this.createSubagent(input);
  }

  /**
   * Create a new terminal session (Claude Code CLI).
   */
  createTerminal(input: CreateTerminalInput): Session {
    const id = input.id ?? generateId();
    const now = new Date().toISOString();

    this.db
      .query(
        `INSERT INTO cli_sessions
         (id, type, goal, status, parent_id, mac_session_id, tool_call_id, name, created_at, updated_at)
         VALUES (?, 'terminal', ?, 'running', ?, ?, ?, ?, ?, ?)`
      )
      .run(
        id,
        input.goal,
        input.parent_id,
        input.mac_session_id ?? null,
        input.tool_call_id ?? null,
        input.name ?? null,
        now,
        now
      );

    return this.findById(id)!;
  }

  /**
   * @deprecated Use createOrchestrator or createTerminal instead.
   */
  create(input: CreateSessionInput): Session {
    const id = input.id ?? generateId();
    const now = new Date().toISOString();

    this.db
      .query(
        `INSERT INTO cli_sessions (id, type, goal, status, parent_id, thread_id, created_at, updated_at)
         VALUES (?, 'terminal', ?, 'pending', ?, ?, ?, ?)`
      )
      .run(id, input.goal, input.parent_id ?? null, input.thread_id ?? null, now, now);

    return this.findById(id)!;
  }

  // ============================================================================
  // READ METHODS
  // ============================================================================

  /**
   * Find a session by ID.
   */
  findById(id: string): Session | null {
    return (
      (this.db.query('SELECT * FROM cli_sessions WHERE id = ?').get(id) as Session) ?? null
    );
  }

  /**
   * Find a running voice session by profile name.
   * Used to get the current voice session for parent tracking.
   */
  findRunningVoice(profile?: VoiceProfile): Session | null {
    if (profile) {
      return (
        (this.db
          .query(
            `SELECT * FROM cli_sessions
             WHERE type = 'voice'
             AND profile = ?
             AND status = 'running'
             ORDER BY created_at DESC
             LIMIT 1`
          )
          .get(profile) as Session) ?? null
      );
    }

    // Find any running voice session
    return (
      (this.db
        .query(
          `SELECT * FROM cli_sessions
           WHERE type = 'voice'
           AND status = 'running'
           ORDER BY created_at DESC
           LIMIT 1`
        )
        .get() as Session) ?? null
    );
  }

  /**
   * Find a running subagent by agent name.
   * Used to resume existing subagents instead of creating new ones.
   *
   * @param agentName - The agent name to search for
   * @param parentId - Optional parent session ID to scope the search (e.g., voice session)
   *                   If provided, only returns subagents that are children of this parent.
   *                   If not provided, returns ANY running subagent with this name.
   */
  findRunningSubagent(agentName: AgentName, parentId?: string): Session | null {
    if (parentId) {
      // Scoped search: only find subagents belonging to this parent
      return (
        (this.db
          .query(
            `SELECT * FROM cli_sessions
             WHERE type = 'subagent'
             AND agent_name = ?
             AND parent_id = ?
             AND status = 'running'
             ORDER BY created_at DESC
             LIMIT 1`
          )
          .get(agentName, parentId) as Session) ?? null
      );
    }

    // Unscoped search: find any running subagent (legacy behavior)
    return (
      (this.db
        .query(
          `SELECT * FROM cli_sessions
           WHERE type = 'subagent'
           AND agent_name = ?
           AND status = 'running'
           ORDER BY created_at DESC
           LIMIT 1`
        )
        .get(agentName) as Session) ?? null
    );
  }

  /**
   * @deprecated Use findRunningSubagent instead.
   */
  findRunningOrchestrator(agentName: AgentName): Session | null {
    return this.findRunningSubagent(agentName);
  }

  /**
   * Find a session by its human-readable name.
   */
  findByName(name: string): Session | null {
    return (
      (this.db.query('SELECT * FROM cli_sessions WHERE name = ?').get(name) as Session) ?? null
    );
  }

  /**
   * Get the set of names currently in use by active sessions.
   * Used by generateSessionName to avoid collisions.
   */
  getActiveSessionNames(): Set {
    const rows = this.db
      .query(
        `SELECT name FROM cli_sessions
         WHERE name IS NOT NULL
         AND status IN ('pending', 'running', 'waiting_for_input')`
      )
      .all() as Array<{ name: string }>;
    return new Set(rows.map((r) => r.name));
  }

  /**
   * List all sessions, optionally filtered by status and/or type.
   */
  list(options?: { status?: SessionStatus; type?: SessionType }): Session[] {
    let query = 'SELECT * FROM cli_sessions WHERE 1=1';
    const params: (string | null)[] = [];

    if (options?.status) {
      query += ' AND status = ?';
      params.push(options.status);
    }
    if (options?.type) {
      query += ' AND type = ?';
      params.push(options.type);
    }

    query += ' ORDER BY created_at DESC';

    return this.db.query(query).all(...params) as Session[];
  }

  /**
   * Get active sessions (pending, running, or waiting_for_input).
   */
  getActive(): Session[] {
    return this.db
      .query(
        `SELECT * FROM cli_sessions
         WHERE status IN ('pending', 'running', 'waiting_for_input')
         ORDER BY created_at DESC`
      )
      .all() as Session[];
  }

  /**
   * Get all root sessions (voice or subagent with no parent) that are active OR have active descendants.
   * This ensures we can navigate to running terminals even if their parent has finished.
   */
  getActiveRoots(): Session[] {
    // Use recursive CTE to find all roots with any active descendants
    return this.db
      .query(
        `WITH RECURSIVE ancestry AS (
           -- Start with all active sessions
           SELECT id, parent_id FROM cli_sessions
           WHERE status IN ('pending', 'running', 'waiting_for_input')

           UNION

           -- Walk up to parents
           SELECT p.id, p.parent_id FROM cli_sessions p
           INNER JOIN ancestry a ON a.parent_id = p.id
         )
         SELECT DISTINCT r.* FROM cli_sessions r
         WHERE r.type IN ('voice', 'subagent')
         AND r.parent_id IS NULL
         AND r.id IN (SELECT id FROM ancestry)
         ORDER BY r.created_at DESC`
      )
      .all() as Session[];
  }

  /**
   * Get direct children of a session.
   */
  getChildren(parentId: string): Session[] {
    return this.db
      .query('SELECT * FROM cli_sessions WHERE parent_id = ? ORDER BY created_at ASC')
      .all(parentId) as Session[];
  }

  /**
   * Get running children of a session.
   */
  getRunningChildren(parentId: string): Session[] {
    return this.db
      .query(
        `SELECT * FROM cli_sessions
         WHERE parent_id = ?
         AND status IN ('pending', 'running', 'waiting_for_input')
         ORDER BY created_at ASC`
      )
      .all(parentId) as Session[];
  }

  /**
   * Build a tree structure starting from a root session.
   */
  getTree(rootId: string): SessionTreeNode | null {
    const session = this.findById(rootId);
    if (!session) return null;

    const buildNode = (s: Session): SessionTreeNode => {
      const children = this.getChildren(s.id);
      return {
        id: s.id,
        type: s.type,
        name: s.name,
        status: s.status,
        goal: s.goal,
        profile: s.profile,
        agent_name: s.agent_name,
        tool_call_id: s.tool_call_id,
        background: Boolean(s.background),
        created_at: s.created_at,
        children: children.map(buildNode),
      };
    };

    return buildNode(session);
  }

  /**
   * Get all active trees (roots with their children).
   */
  getActiveTrees(): SessionTreeNode[] {
    const roots = this.getActiveRoots();
    return roots.map((root) => this.getTree(root.id)!).filter(Boolean);
  }

  /**
   * Get recent root sessions (for chat history persistence).
   * Returns roots from the last N hours, regardless of status.
   */
  getRecentRoots(hoursAgo: number = 24, limit: number = 50): Session[] {
    return this.db
      .query(
        `SELECT * FROM cli_sessions
         WHERE type IN ('voice', 'subagent')
         AND parent_id IS NULL
         AND created_at >= datetime('now', '-' || ? || ' hours')
         ORDER BY created_at DESC
         LIMIT ?`
      )
      .all(hoursAgo, limit) as Session[];
  }

  /**
   * Get recent session trees (for chat history persistence).
   * Returns all trees from the last N hours, including finished ones.
   */
  getRecentTrees(hoursAgo: number = 24, limit: number = 50): SessionTreeNode[] {
    const roots = this.getRecentRoots(hoursAgo, limit);
    return roots.map((root) => this.getTree(root.id)!).filter(Boolean);
  }

  /**
   * Get a session with its direct children.
   * @deprecated Use getTree for full hierarchy.
   */
  getWithChildren(id: string): { session: Session; children: Session[] } | null {
    const session = this.findById(id);
    if (!session) return null;

    const children = this.getChildren(id);
    return { session, children };
  }

  /**
   * Get all sessions belonging to a thread.
   * @deprecated thread_id is no longer used; use getTree instead.
   */
  getByThread(threadId: string): Session[] {
    return this.db
      .query('SELECT * FROM cli_sessions WHERE thread_id = ? ORDER BY created_at ASC')
      .all(threadId) as Session[];
  }

  /**
   * Get all session IDs in a tree (root + descendants), depth-first.
   */
  getTreeSessionIds(rootId: string): string[] {
    const root = this.findById(rootId);
    if (!root) return [];

    const ids: string[] = [];
    const collect = (sessionId: string): void => {
      ids.push(sessionId);
      const children = this.getChildren(sessionId);
      for (const child of children) {
        collect(child.id);
      }
    };

    collect(rootId);
    return ids;
  }

  // ============================================================================
  // UPDATE METHODS
  // ============================================================================

  /**
   * Update session fields.
   */
  update(
    id: string,
    fields: Partial<{
      status: SessionStatus;
      goal: string;
      mac_session_id: string;
      conversation_history: string;
      finished_at: string;
    }>
  ): boolean {
    const updates: string[] = [];
    const params: (string | null)[] = [];

    if (fields.status !== undefined) {
      updates.push('status = ?');
      params.push(fields.status);
    }
    if (fields.goal !== undefined) {
      updates.push('goal = ?');
      params.push(fields.goal);
    }
    if (fields.mac_session_id !== undefined) {
      updates.push('mac_session_id = ?');
      params.push(fields.mac_session_id);
    }
    if (fields.conversation_history !== undefined) {
      updates.push('conversation_history = ?');
      params.push(fields.conversation_history);
    }
    if (fields.finished_at !== undefined) {
      updates.push('finished_at = ?');
      params.push(fields.finished_at);
    }

    if (updates.length === 0) return false;

    updates.push("updated_at = datetime('now')");
    params.push(id);

    const result = this.db
      .query(`UPDATE cli_sessions SET ${updates.join(', ')} WHERE id = ?`)
      .run(...params);

    return result.changes > 0;
  }

  /**
   * Update session status.
   * @deprecated Use update({ status }) instead.
   */
  updateStatus(id: string, status: SessionStatus): boolean {
    return this.update(id, { status });
  }

  /**
   * Set the Mac daemon session ID.
   * @deprecated Use update({ mac_session_id }) instead.
   */
  setMacSessionId(id: string, macSessionId: string): boolean {
    return this.update(id, { mac_session_id: macSessionId });
  }

  /**
   * Append to conversation history (for subagents).
   */
  appendToHistory(id: string, messages: Array<{ role: string; content: string }>): boolean {
    const session = this.findById(id);
    if (!session || session.type !== 'subagent') return false;

    const history = JSON.parse(session.conversation_history || '[]');
    history.push(...messages);

    return this.update(id, { conversation_history: JSON.stringify(history) });
  }

  /**
   * Mark session as finished.
   */
  finish(id: string, status: 'finished' | 'cancelled' | 'error' = 'finished'): boolean {
    return this.update(id, {
      status,
      finished_at: new Date().toISOString(),
    });
  }

  // ============================================================================
  // DELETE METHODS
  // ============================================================================

  /**
   * Delete a session and its related data.
   * - session_messages + cli_events are removed via ON DELETE CASCADE
   * - handoff_packets are removed explicitly (schema has no cascade)
   */
  delete(id: string): boolean {
    this.db
      .query(
        `DELETE FROM handoff_packets
         WHERE source_session_id = ? OR target_session_id = ?`
      )
      .run(id, id);

    const result = this.db.query('DELETE FROM cli_sessions WHERE id = ?').run(id);
    return result.changes > 0;
  }

  /**
   * Delete all sessions and related data.
   * - handoff_packets are removed first to avoid FK violations
   * - cli_events + session_messages are removed via ON DELETE CASCADE
   * Returns the number of sessions deleted.
   */
  deleteAll(): number {
    this.db.query('DELETE FROM handoff_packets').run();

    const result = this.db.query('DELETE FROM cli_sessions').run();
    return result.changes;
  }

  /**
   * Delete a subtree rooted at the given session ID.
   * Returns the list of successfully deleted session IDs.
   */
  deleteTree(rootId: string): string[] {
    const ids = this.getTreeSessionIds(rootId);
    if (ids.length === 0) return [];

    // Delete children first, then root.
    const deletedIds: string[] = [];
    for (const id of [...ids].reverse()) {
      if (this.delete(id)) {
        deletedIds.push(id);
      }
    }

    return deletedIds;
  }

  /**
   * Cancel a session and all its descendants (cascading cancel).
   * Returns the number of sessions cancelled.
   */
  cancelTree(rootId: string): number {
    const session = this.findById(rootId);
    if (!session) return 0;

    let count = 0;

    // Recursively cancel children first
    const children = this.getChildren(rootId);
    for (const child of children) {
      count += this.cancelTree(child.id);
    }

    // Cancel this session if running
    if (['pending', 'running', 'waiting_for_input'].includes(session.status)) {
      this.finish(rootId, 'cancelled');
      count++;
    }

    return count;
  }

  /**
   * Cleanup old sessions based on retention policy.
   * - Leaf subagents/voice sessions without children: 24 hours
   * - All other finished sessions: 10 days
   */
  cleanup(): { deleted: number } {
    // Delete leaf subagents and voice sessions after 24h
    const leafResult = this.db
      .query(
        `DELETE FROM cli_sessions
         WHERE type IN ('subagent', 'voice')
         AND status IN ('finished', 'cancelled', 'error')
         AND id NOT IN (SELECT DISTINCT parent_id FROM cli_sessions WHERE parent_id IS NOT NULL)
         AND finished_at < datetime('now', '-24 hours')`
      )
      .run();

    // Delete all finished sessions after 10 days
    const oldResult = this.db
      .query(
        `DELETE FROM cli_sessions
         WHERE status IN ('finished', 'cancelled', 'error')
         AND finished_at < datetime('now', '-10 days')`
      )
      .run();

    return { deleted: leafResult.changes + oldResult.changes };
  }
}

// Also export as SessionsRepository for new code
export { CliSessionsRepository as SessionsRepository };



/**
 * JSONL Session Logger - Append-only file-based session logging for debugging.
 *
 * Each session gets a `.jsonl` file in `.voiceclaw/.sessions/` with one JSON object per line.
 * Inspired by pi-mono's session persistence pattern.
 */

import { appendFileSync, mkdirSync, existsSync, readdirSync, unlinkSync } from 'fs';
import { join } from 'path';
import { CliSessionsRepository } from '../db/repositories/cli-sessions.js';

// Session log directory at project root
const SESSIONS_DIR = join(import.meta.dirname, '..', '..', '..', '..', '.voiceclaw', '.sessions');
type LoggerSessionType = 'voice' | 'subagent' | 'terminal';

export interface SessionLogEntry {
  type: string;
  id: string;
  timestamp: string;
  [key: string]: unknown;
}

/**
 * Logger instance for a single session. Appends JSONL entries to a file.
 * Uses lazy flush: buffers until first content event, then flushes all at once.
 */
export class SessionLogger {
  private filePath: string;
  private buffer: SessionLogEntry[] = [];
  private flushed = false;

  constructor(
    sessionId: string,
    sessionName: string | null,
    sessionType: LoggerSessionType,
    parentId: string | null = null,
    meta: Record = {}
  ) {
    // Ensure .voiceclaw/.sessions/ directory exists
    if (!existsSync(SESSIONS_DIR)) {
      mkdirSync(SESSIONS_DIR, { recursive: true });
    }

    // Filename: use session name if available, else UUID prefix
    const rawName = sessionName ?? sessionId.slice(0, 12);
    const filename = rawName.replace(/[^a-zA-Z0-9._-]/g, '_');
    this.filePath = join(SESSIONS_DIR, `${filename}.jsonl`);

    // Write session header
    this.append({
      type: 'session',
      version: 1,
      id: sessionId,
      sessionType,
      name: sessionName,
      parentId,
      ...meta,
      timestamp: new Date().toISOString(),
    });
  }

  /**
   * Append an entry to the session log.
   * Buffers until first content event (text-delta, tool-call, user-transcript),
   * then flushes all buffered entries and switches to immediate append.
   */
  append(entry: SessionLogEntry): void {
    if (!this.flushed) {
      this.buffer.push(entry);
      // Flush on first content-bearing event
      const contentTypes = [
        'text-delta',
        'user-transcript',
        'tool-call',
        'tool-result',
        'reasoning-delta',
        'state-change',
        'cli-event',
        'webhook-status',
        'error',
      ];
      if (contentTypes.includes(entry.type)) {
        this.flush();
      }
      return;
    }
    this.writeLine(entry);
  }

  private flush(): void {
    for (const entry of this.buffer) {
      this.writeLine(entry);
    }
    this.buffer = [];
    this.flushed = true;
  }

  private writeLine(entry: SessionLogEntry): void {
    try {
      appendFileSync(this.filePath, JSON.stringify(entry) + '\n');
    } catch (err) {
      console.error(`[SessionLogger] Failed to write to ${this.filePath}:`, err);
    }
  }

  /** Get the file path for this session log */
  getFilePath(): string {
    return this.filePath;
  }
}

// ============================================================================
// Global logger registry - one logger per session
// ============================================================================

const loggers = new Map();
let logCounter = 0;

function createLogEntryId(prefix = 'evt'): string {
  logCounter += 1;
  return `${prefix}-${Date.now()}-${logCounter.toString(36)}`;
}

function mapSessionType(type: string | null): LoggerSessionType {
  if (type === 'voice' || type === 'terminal') return type;
  return 'subagent';
}

function ensureSessionLogger(sessionId: string): SessionLogger | null {
  const existing = loggers.get(sessionId);
  if (existing) return existing;

  const sessionsRepo = new CliSessionsRepository();
  const session = sessionsRepo.findById(sessionId);
  if (!session) return null;

  const logger = new SessionLogger(
    session.id,
    session.name,
    mapSessionType(session.type),
    session.parent_id,
    {
      profile: session.profile,
      agent_name: session.agent_name,
      goal: session.goal,
      status: session.status,
      created_at: session.created_at,
    }
  );
  loggers.set(sessionId, logger);
  return logger;
}

/**
 * Get or create a logger for a session.
 * Call this from wsBroadcast.streamChunk or voice-agent event handlers.
 */
export function getSessionLogger(
  sessionId: string,
  sessionName?: string | null,
  sessionType: LoggerSessionType = 'subagent',
  parentId?: string | null,
  meta?: Record
): SessionLogger {
  let logger = loggers.get(sessionId);
  if (!logger) {
    logger = new SessionLogger(sessionId, sessionName ?? null, sessionType, parentId ?? null, meta ?? {});
    loggers.set(sessionId, logger);
  }
  return logger;
}

/**
 * Remove a logger from the registry (on session end).
 */
export function removeSessionLogger(sessionId: string): void {
  loggers.delete(sessionId);
}

/**
 * Clear all persisted session JSONL logs.
 * Returns number of deleted files.
 */
export function clearAllSessionLogs(): number {
  loggers.clear();

  if (!existsSync(SESSIONS_DIR)) {
    return 0;
  }

  let deleted = 0;
  const entries = readdirSync(SESSIONS_DIR, { withFileTypes: true });

  for (const entry of entries) {
    if (!entry.isFile() || !entry.name.endsWith('.jsonl')) {
      continue;
    }

    const filePath = join(SESSIONS_DIR, entry.name);
    try {
      unlinkSync(filePath);
      deleted += 1;
    } catch (err) {
      console.error(`[SessionLogger] Failed to delete ${filePath}:`, err);
    }
  }

  return deleted;
}

/**
 * Clear session JSONL logs for specific sessions.
 * Returns number of deleted files.
 */
export function clearSessionLogsForSessions(
  sessions: Array<{ id: string; name: string | null }>
): number {
  if (!existsSync(SESSIONS_DIR) || sessions.length === 0) {
    return 0;
  }

  let deleted = 0;
  const filenames = new Set();

  for (const session of sessions) {
    const rawName = session.name ?? session.id.slice(0, 12);
    const sanitized = rawName.replace(/[^a-zA-Z0-9._-]/g, '_');
    filenames.add(`${sanitized}.jsonl`);
  }

  for (const filename of filenames) {
    const filePath = join(SESSIONS_DIR, filename);
    if (!existsSync(filePath)) {
      continue;
    }

    try {
      unlinkSync(filePath);
      deleted += 1;
    } catch (err) {
      console.error(`[SessionLogger] Failed to delete ${filePath}:`, err);
    }
  }

  return deleted;
}

/**
 * Log an AI SDK stream event for a session.
 * Converts the event to a JSONL entry and appends it.
 */
export function logStreamEvent(sessionId: string, event: { type: string; [key: string]: unknown }): void {
  const logger = ensureSessionLogger(sessionId);
  if (!logger) return;

  const entry: SessionLogEntry = {
    ...event,
    id: createLogEntryId('stream'),
    timestamp: new Date().toISOString(),
  };
  logger.append(entry);
}

/**
 * Log CLI event repository writes to session JSONL logs.
 */
export function logCliEvent(
  sessionId: string,
  eventType: string,
  payload: unknown
): void {
  const logger = ensureSessionLogger(sessionId);
  if (!logger) return;

  logger.append({
    type: 'cli-event',
    id: createLogEntryId('cli'),
    timestamp: new Date().toISOString(),
    eventType,
    payload,
  });
}

/**
 * Log webhook status updates to session JSONL logs.
 */
export function logWebhookStatus(
  sessionId: string,
  status: string,
  message?: string,
  output?: unknown
): void {
  const logger = ensureSessionLogger(sessionId);
  if (!logger) return;

  logger.append({
    type: 'webhook-status',
    id: createLogEntryId('wh'),
    timestamp: new Date().toISOString(),
    status,
    message: message ?? null,
    output: output ?? null,
  });
}



/**
 * Centralized Prompt Management Service
 *
 * Manages prompts stored in ./prompts// directories with:
 * - Version tracking (v1.md, v2.md, ...)
 * - Active version selection via config.json
 * - Variable interpolation with {{variable}} syntax
 */

import { readdir, readFile, writeFile, mkdir, stat } from 'fs/promises';
import path from 'path';
import { interpolatePrompt, type InterpolationContext } from './interpolate.js';

export { interpolatePrompt, type InterpolationContext } from './interpolate.js';

// Prompts directory inside the voice-agent package
const PROMPTS_DIR = path.join(process.cwd(), 'prompts');

/**
 * Prompt configuration stored in config.json
 */
export interface PromptConfig {
  name: string;
  description: string;
  type: 'voice' | 'subagent';
  activeVersion: string;
  metadata?: {
    voice?: string;
    wakeWord?: string;
    tools?: string[];
    model?: string;
    maxSteps?: number;
  };
}

/**
 * Prompt info returned by list operations
 */
export interface PromptInfo extends PromptConfig {
  /** Directory name (e.g., "jarvis", "cli-orchestrator") */
  id: string;
  /** Available versions (e.g., ["v1", "v2", "v3"]) */
  versions: string[];
}

/**
 * Version content with metadata
 */
export interface PromptVersion {
  version: string;
  content: string;
  createdAt: number;
}

/**
 * Get the prompts directory path
 */
export function getPromptsDir(): string {
  return PROMPTS_DIR;
}

/**
 * Check if the prompts directory exists
 */
export async function promptsDirExists(): Promise {
  try {
    const stats = await stat(PROMPTS_DIR);
    return stats.isDirectory();
  } catch {
    return false;
  }
}

/**
 * List all available prompts with their metadata
 */
export async function listPrompts(): Promise {
  const exists = await promptsDirExists();
  if (!exists) {
    return [];
  }

  const entries = await readdir(PROMPTS_DIR, { withFileTypes: true });
  const prompts: PromptInfo[] = [];

  for (const entry of entries) {
    if (!entry.isDirectory()) continue;

    try {
      const promptDir = path.join(PROMPTS_DIR, entry.name);
      const configPath = path.join(promptDir, 'config.json');

      const configStr = await readFile(configPath, 'utf-8');
      const config = JSON.parse(configStr) as PromptConfig;

      const versions = await listVersions(entry.name);

      prompts.push({
        id: entry.name,
        ...config,
        versions,
      });
    } catch (error) {
      // Skip directories without valid config.json
      console.warn(`[Prompts] Skipping ${entry.name}: ${error}`);
    }
  }

  // Sort by type (voice first) then by name
  return prompts.sort((a, b) => {
    if (a.type !== b.type) {
      return a.type === 'voice' ? -1 : 1;
    }
    return a.name.localeCompare(b.name);
  });
}

/**
 * Get prompt configuration by ID (directory name)
 */
export async function getPromptConfig(id: string): Promise {
  try {
    const configPath = path.join(PROMPTS_DIR, id, 'config.json');
    const configStr = await readFile(configPath, 'utf-8');
    return JSON.parse(configStr) as PromptConfig;
  } catch {
    return null;
  }
}

/**
 * Get prompt info with versions
 */
export async function getPromptInfo(id: string): Promise {
  const config = await getPromptConfig(id);
  if (!config) return null;

  const versions = await listVersions(id);

  return {
    id,
    ...config,
    versions,
  };
}

/**
 * List all versions for a prompt (e.g., ["v1", "v2", "v3"])
 */
export async function listVersions(id: string): Promise {
  try {
    const promptDir = path.join(PROMPTS_DIR, id);
    const entries = await readdir(promptDir);

    const versions = entries
      .filter((f) => /^v\d+\.md$/.test(f))
      .map((f) => f.replace('.md', ''))
      .sort((a, b) => {
        const numA = parseInt(a.slice(1), 10);
        const numB = parseInt(b.slice(1), 10);
        return numA - numB;
      });

    return versions;
  } catch {
    return [];
  }
}

/**
 * Get the next version number for a prompt
 */
async function getNextVersion(id: string): Promise {
  const versions = await listVersions(id);

  if (versions.length === 0) {
    return 'v1';
  }

  const lastVersion = versions[versions.length - 1]!;
  const lastNum = parseInt(lastVersion.slice(1), 10);
  return `v${lastNum + 1}`;
}

/**
 * Get a specific version's content (raw, without interpolation)
 */
export async function getPromptVersion(
  id: string,
  version: string
): Promise {
  try {
    const versionPath = path.join(PROMPTS_DIR, id, `${version}.md`);
    const stats = await stat(versionPath);
    const content = await readFile(versionPath, 'utf-8');

    return {
      version,
      content,
      createdAt: stats.mtimeMs,
    };
  } catch {
    return null;
  }
}

/**
 * Get the active prompt content with variable interpolation
 *
 * This is the main function used by agents to load their prompts.
 *
 * @param id - Prompt directory name (e.g., "jarvis", "cli-orchestrator")
 * @param context - Variables to interpolate (agent_name, session_id, etc.)
 * @returns Interpolated prompt content, or null if not found
 *
 * @example
 * ```typescript
 * const prompt = await getActivePrompt('jarvis', {
 *   agent_name: 'Jarvis',
 *   session_id: 'sess_abc123'
 * });
 * ```
 */
export async function getActivePrompt(
  id: string,
  context: InterpolationContext = {}
): Promise {
  const config = await getPromptConfig(id);
  if (!config) return null;

  const version = await getPromptVersion(id, config.activeVersion);
  if (!version) return null;

  return interpolatePrompt(version.content, context);
}

/**
 * Get the active prompt content without interpolation (raw)
 */
export async function getActivePromptRaw(id: string): Promise {
  const config = await getPromptConfig(id);
  if (!config) return null;

  const version = await getPromptVersion(id, config.activeVersion);
  return version?.content ?? null;
}

/**
 * Create a new version of a prompt
 *
 * @param id - Prompt directory name
 * @param content - New prompt content
 * @returns The new version name (e.g., "v2")
 */
export async function createPromptVersion(
  id: string,
  content: string
): Promise {
  const promptDir = path.join(PROMPTS_DIR, id);

  // Ensure directory exists
  await mkdir(promptDir, { recursive: true });

  const version = await getNextVersion(id);
  const versionPath = path.join(promptDir, `${version}.md`);

  await writeFile(versionPath, content, 'utf-8');

  return version;
}

/**
 * Set the active version for a prompt
 *
 * @param id - Prompt directory name
 * @param version - Version to activate (e.g., "v2")
 */
export async function setActiveVersion(
  id: string,
  version: string
): Promise {
  const config = await getPromptConfig(id);
  if (!config) {
    throw new Error(`Prompt not found: ${id}`);
  }

  // Verify version exists
  const versionData = await getPromptVersion(id, version);
  if (!versionData) {
    throw new Error(`Version not found: ${version}`);
  }

  // Update config
  const configPath = path.join(PROMPTS_DIR, id, 'config.json');
  const updatedConfig = { ...config, activeVersion: version };
  await writeFile(configPath, JSON.stringify(updatedConfig, null, 2), 'utf-8');
}

/**
 * Create a new prompt with initial content
 *
 * @param id - Directory name (e.g., "my-agent")
 * @param config - Prompt configuration (without activeVersion)
 * @param content - Initial prompt content
 */
export async function createPrompt(
  id: string,
  config: Omit,
  content: string
): Promise {
  const promptDir = path.join(PROMPTS_DIR, id);

  // Create directory
  await mkdir(promptDir, { recursive: true });

  // Write initial version
  await writeFile(path.join(promptDir, 'v1.md'), content, 'utf-8');

  // Write config
  const fullConfig: PromptConfig = { ...config, activeVersion: 'v1' };
  await writeFile(
    path.join(promptDir, 'config.json'),
    JSON.stringify(fullConfig, null, 2),
    'utf-8'
  );
}

/**
 * Update prompt configuration (metadata only, not content)
 */
export async function updatePromptConfig(
  id: string,
  updates: Partial<Omit>
): Promise {
  const config = await getPromptConfig(id);
  if (!config) {
    throw new Error(`Prompt not found: ${id}`);
  }

  const configPath = path.join(PROMPTS_DIR, id, 'config.json');
  const updatedConfig = { ...config, ...updates };
  await writeFile(configPath, JSON.stringify(updatedConfig, null, 2), 'utf-8');
}

/**
 * Mapping from subagent directory names to prompt IDs
 *
 * This allows subagent loaders to find their prompts in the centralized directory.
 */
export const SUBAGENT_PROMPT_MAPPING: Record = {
  cli: 'cli-orchestrator',
  'web-search': 'web-search',
};

/**
 * Get prompt ID for a subagent directory
 */
export function getPromptIdForSubagent(dirName: string): string {
  return SUBAGENT_PROMPT_MAPPING[dirName] ?? dirName;
}



/**
 * CLI Orchestration Agent - Uses Vercel AI SDK with grok-code-fast-1 via OpenRouter.
 *
 * This agent is a STATEFUL orchestrator that:
 * - Persists conversation history in the database
 * - Can be resumed by subsequent voice commands
 * - Manages multiple terminal sessions as children
 * - Emits AI SDK format events via stream_chunk for frontend
 *
 * Session Hierarchy:
 *   Voice (persisted in DB)
 *     → Subagent/Orchestrator (stateful, conversation history)
 *       → Terminal 1 (long-running Claude Code CLI)
 *       → Terminal 2
 */

import { wsBroadcast } from '../../api/websocket.js';
import { loadAgentConfig } from '../loader.js';
import {
  cliAgentToolDefinitions,
  executeCliAgentTool,
  isMacDaemonAvailable,
} from '../../tools/cli-agent-tools.js';
import { CliSessionsRepository, HandoffsRepository } from '../../db/index.js';
import { generateSessionName } from '../../utils/session-names.js';
import { formatVoiceContext, formatActiveProcesses, type HandoffPacket } from '../../context/handoff.js';
import { llmRuntime } from '../llm-runtime.js';
import { forwardLlmStreamToSession } from '../stream-events.js';

// Re-export for use by developer-session.ts
export { isMacDaemonAvailable };

// Module-level context for orchestrator session tracking
// Set before running the agent, accessed by tools during execution
let currentOrchestratorId: string | undefined;

// Track pending tool calls for session-creating tools
// Maps orchestratorId → toolCallId
// Set when tool-call event fires, consumed by tools when creating sessions
const pendingSessionToolCalls = new Map();

// Tools that create terminal sessions - need to track their tool call IDs
const SESSION_CREATING_TOOLS = ['start_headless_session', 'start_interactive_session'];

/**
 * Get the current orchestrator session ID for terminal tracking.
 * Called by CLI tools when creating new terminal sessions.
 */
export function getCurrentOrchestratorId(): string | undefined {
  return currentOrchestratorId;
}

/**
 * Set or clear the current orchestrator session ID.
 * Used by direct input routing so CLI tools can resolve the active orchestrator context.
 */
export function setCurrentOrchestratorId(orchestratorId: string | undefined): void {
  currentOrchestratorId = orchestratorId;
}

/**
 * Set a pending tool call ID for session-creating tools.
 * Called internally when we see a tool-call event for session-creating tools.
 */
export function setPendingToolCall(orchestratorId: string, toolCallId: string): void {
  pendingSessionToolCalls.set(orchestratorId, toolCallId);
}

/**
 * Consume the pending tool call ID for the given orchestrator.
 * Called by CLI tools when creating terminal sessions.
 * Returns the toolCallId and removes it from the map.
 */
export function consumePendingToolCall(orchestratorId: string): string | undefined {
  const toolCallId = pendingSessionToolCalls.get(orchestratorId);
  pendingSessionToolCalls.delete(orchestratorId);
  return toolCallId;
}

/**
 * Handle a developer request by delegating to the CLI orchestration agent.
 *
 * This function:
 * 1. Finds an existing running CLI subagent OR creates a new one
 * 2. Loads the subagent's conversation history from the database
 * 3. Runs the agent with full context from the HandoffPacket
 * 4. Emits stream_chunk events in AI SDK format
 * 5. Saves the updated conversation history back to the database
 *
 * @param handoff - HandoffPacket with full voice context (anti-telephone)
 * @param voiceSessionId - Voice session ID to establish parent-child relationship
 * @param sessionName - Optional pre-generated session name (used by ProcessManager for non-blocking tools)
 */
export async function handleDeveloperRequest(
  handoff: HandoffPacket,
  voiceSessionId?: string,
  sessionName?: string
): Promise {
  const sessionsRepo = new CliSessionsRepository();
  const request = handoff.request;

  console.log('\n========================================');
  console.log('[CliAgent] Handling developer request');
  console.log(`[CliAgent] Request: ${request}`);
  console.log(`[CliAgent] Voice context entries: ${handoff.voiceContext.length}`);
  console.log(`[CliAgent] Active processes: ${handoff.activeProcesses.length}`);
  console.log(`[CliAgent] Voice session ID: ${voiceSessionId ?? 'none'}`);

  // Load config and prompt from disk
  const { config, prompt: systemPrompt } = await loadAgentConfig(import.meta.dirname);

  // Find or create the CLI subagent session
  // IMPORTANT: Scope to current voice session to avoid reusing subagents from old sessions
  let subagent = sessionsRepo.findRunningSubagent('cli', voiceSessionId);

  if (subagent) {
    console.log(`[CliAgent] Resuming existing subagent: ${subagent.id} (parent: ${voiceSessionId ?? 'none'})`);
  } else {
    const activeNames = sessionsRepo.getActiveSessionNames();
    const name = sessionName ?? generateSessionName(activeNames);
    subagent = sessionsRepo.createSubagent({
      goal: request.substring(0, 100),
      agent_name: 'cli',
      model: config.model,
      parent_id: voiceSessionId, // Link to voice session for hierarchy
      name,
    });
    console.log(`[CliAgent] Created new subagent: ${subagent.id} "${name}" (parent: ${voiceSessionId ?? 'none'})`);

    // Broadcast tree update - use voice session as root if available, otherwise subagent
    wsBroadcast.sessionTreeUpdate(voiceSessionId ?? subagent.id);
  }

  // Set subagent ID for tools to access during this request
  setCurrentOrchestratorId(subagent.id);
  const sessionId = subagent.id;

  console.log(`[CliAgent] Using model: ${config.model} via llm-runtime/openrouter`);

  // Load subagent's conversation history from database
  const subagentHistory: Array<{ role: string; content: string }> = JSON.parse(
    subagent.conversation_history || '[]'
  );

  // Format voice context from HandoffPacket (anti-telephone: lossless context transfer)
  const voiceContextText = formatVoiceContext(handoff);
  const activeProcessesText = formatActiveProcesses(handoff);

  // Update handoff packet with target session ID
  const handoffsRepo = new HandoffsRepository();
  handoffsRepo.setTargetSession(handoff.id, subagent.id);

  // Build messages array from subagent history + new request
  const messages: Array<{ role: 'user' | 'assistant'; content: string }> = [];

  // Restore previous conversation turns as proper messages
  for (const msg of subagentHistory) {
    messages.push({
      role: msg.role as 'user' | 'assistant',
      content: msg.content,
    });
  }

  // New user message with voice context
  const userMessage = [
    voiceContextText ? `## Voice Context\n${voiceContextText}` : '',
    activeProcessesText ? `## Active Background Tasks\n${activeProcessesText}` : '',
    `## Request\n${request}`,
    '',
    'Analyze this request and take appropriate action. Remember:',
    '- For quick tasks (reviews, simple fixes): use headless mode with claude -p',
    '- For complex tasks (implementation, refactoring): use interactive mode',
    '- For feature implementation, prefix with "use the \'feature planner fast\' skill to implement..."',
    '- Navigate to the correct project directory first',
  ].filter(Boolean).join('\n\n');

  messages.push({ role: 'user', content: userMessage });

  console.log(`[CliAgent] Messages count: ${messages.length} (${subagentHistory.length} history + 1 new)`);

  try {
    // Emit user message for frontend display before starting stream
    wsBroadcast.streamChunk(sessionId, { type: 'user-transcript', text: request });

    console.log(`[CliAgent] Starting llm-runtime stream processing...`);
    const { text: fullText, eventCount: updateCount } = await forwardLlmStreamToSession(
      llmRuntime.streamOpenRouter({
        model: {
          provider: 'openrouter',
          model: config.model,
          modality: 'llm',
        },
        context: {
          systemPrompt,
          messages,
          tools: cliAgentToolDefinitions,
        },
        options: {
          maxSteps: config.maxSteps ?? 3,
        },
        toolHandler: executeCliAgentTool,
      }),
      {
        sessionId,
        onToolCall: ({ toolName, toolCallId }) => {
          console.log(`[CliAgent] Tool called: ${toolName}`);
          if (SESSION_CREATING_TOOLS.includes(toolName) && currentOrchestratorId) {
            setPendingToolCall(currentOrchestratorId, toolCallId);
          }
        },
        onToolResult: ({ toolName }) => {
          console.log(`[CliAgent] Tool result: ${toolName}`);
        },
      }
    );

    console.log('[CliAgent] Stream processing complete:');
    console.log(`[CliAgent] Total updates: ${updateCount}`);
    console.log(`[CliAgent] Final text length: ${fullText.length}`);
    console.log(`[CliAgent] Final text: ${fullText || '(empty)'}`);
    console.log('========================================\n');

    // Determine final response
    let finalResponse = fullText;

    // Save conversation to history
    sessionsRepo.appendToHistory(subagent.id, [
      { role: 'user', content: request },
      { role: 'assistant', content: finalResponse || 'No response' },
    ]);

    // Check if subagent should finish (no running children)
    const runningChildren = sessionsRepo.getRunningChildren(subagent.id);
    if (runningChildren.length === 0) {
      console.log('[CliAgent] No active terminals, subagent stays running for follow-ups');
    } else {
      console.log(`[CliAgent] Subagent has ${runningChildren.length} active terminal(s)`);
    }

    // Broadcast tree update - use voice session as root if available
    wsBroadcast.sessionTreeUpdate(voiceSessionId ?? subagent.id);

    return finalResponse || 'Keine Antwort erhalten.';
  } catch (error) {
    const errorMsg = error instanceof Error ? error.message : String(error);
    console.error('[CliAgent] Error:', errorMsg);
    wsBroadcast.streamChunk(sessionId, { type: 'error', error: errorMsg });
    wsBroadcast.error(`CLI Agent error: ${errorMsg}`);
    return `Es gab einen Fehler bei der Verarbeitung: ${errorMsg}`;
  } finally {
    // Clear subagent ID to avoid leaking to subsequent requests
    setCurrentOrchestratorId(undefined);
  }
}



/**
 * Web Search Subagent - Uses llm-runtime with OpenRouter model configured in agent config.
 *
 * This demonstrates the handoff pattern with OpenRouter's :online suffix:
 * 1. Realtime model calls this tool with a query
 * 2. Tool delegates to configured OpenRouter model via llm-runtime
 * 3. Model performs web search and returns grounded result
 * 4. Realtime model SPEAKS the result to the user
 */

import { tool } from '@openai/agents/realtime';
import { z } from 'zod';
import { loadAgentConfig } from '../loader.js';
import { llmRuntime } from '../llm-runtime.js';
import { forwardLlmStreamToSession } from '../stream-events.js';

// Track current voice session for event emission (set by voice-agent before tool call)
let currentVoiceSessionId: string | undefined;

/**
 * Set the current voice session ID for stream event emission.
 * Called by VoiceSession before tool execution.
 */
export function setVoiceSessionId(sessionId: string | undefined): void {
  currentVoiceSessionId = sessionId;
}

export const webSearchTool = tool({
  name: 'web_search',
  description:
    'Search the web for current information. Use this when the user asks about ' +
    'recent news, current events, live data, weather, or anything that requires ' +
    'up-to-date information from the internet.',
  parameters: z.object({
    query: z.string().describe('The search query to look up on the web.'),
  }),
  async execute({ query }) {
    if (!query.trim()) {
      return 'Keine Suchanfrage angegeben.';
    }

    console.log(`[WebSearch] Searching with configured model for: ${query}`);

    try {
      const { config, prompt: systemPrompt } = await loadAgentConfig(import.meta.dirname);

      const { text: fullText, eventCount } = await forwardLlmStreamToSession(
        llmRuntime.streamOpenRouter({
          model: {
            provider: 'openrouter',
            model: config.model,
            modality: 'llm',
          },
          context: {
            systemPrompt,
            messages: [{ role: 'user', content: query }],
          },
        }),
        {
          sessionId: currentVoiceSessionId,
        }
      );

      console.log(`[WebSearch] Result (${eventCount} events): ${fullText.substring(0, 100)}...`);
      return fullText || 'Keine Ergebnisse gefunden.';
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      console.error(`[WebSearch] Error: ${message}`);
      return `Die Websuche ist fehlgeschlagen: ${message}`;
    }
  },
});



/**
 * Background Subagent Spawner
 *
 * Provides utilities for spawning subagents that run independently in the background
 * without blocking the voice agent. Background sessions:
 * - Don't block the voice agent's tool execution
 * - Can notify the voice agent upon completion via callback
 * - Are tracked in the session tree with background=true
 * - Stream events to the frontend via WebSocket like normal subagents
 */

import { wsBroadcast } from '../api/websocket.js';
import { loadAgentConfig } from './loader.js';
import { cliAgentToolDefinitions, executeCliAgentTool } from '../tools/cli-agent-tools.js';
import { CliSessionsRepository } from '../db/index.js';
import { generateSessionName } from '../utils/session-names.js';
import type { VoiceAgent } from '../agent/voice-agent.js';
import { formatVoiceContext, type HandoffPacket } from '../context/handoff.js';
import { llmRuntime } from './llm-runtime.js';
import { forwardLlmStreamToSession } from './stream-events.js';

export interface BackgroundTaskOptions {
  /** The task description/request */
  task: string;
  /** Voice session ID for parent-child relationship */
  voiceSessionId: string;
  /** HandoffPacket with structured voice context (anti-telephone) */
  handoff?: HandoffPacket;
  /** Reference to voice agent for completion notification */
  voiceAgent?: VoiceAgent;
  /** Custom completion message (default: summarizes result) */
  completionMessage?: (result: string) => string;
}

export interface BackgroundTaskResult {
  /** The spawned session ID */
  sessionId: string;
  /** Promise that resolves when the task completes */
  completion: Promise;
}

/**
 * Spawn a background subagent that runs independently without blocking.
 *
 * The function returns immediately with the session ID. The subagent runs
 * asynchronously and can optionally notify the voice agent when done.
 *
 * @example
 * ```typescript
 * // In a tool's execute function:
 * const { sessionId } = spawnBackgroundSubagent({
 *   task: "Review the code in project X",
 *   voiceSessionId: currentVoiceSessionId,
 *   voiceAgent: agent,  // For completion notification
 * });
 * return `Started background task ${sessionId}. I'll let you know when it's done.`;
 * ```
 */
export function spawnBackgroundSubagent(options: BackgroundTaskOptions): BackgroundTaskResult {
  const { task, voiceSessionId, handoff, voiceAgent, completionMessage } = options;

  const sessionsRepo = new CliSessionsRepository();

  // Create subagent session with background=true
  const activeNames = sessionsRepo.getActiveSessionNames();
  const sessionName = generateSessionName(activeNames);
  const subagent = sessionsRepo.createSubagent({
    goal: task.substring(0, 100),
    agent_name: 'cli',
    model: 'x-ai/grok-code-fast-1', // Will be overridden by config
    parent_id: voiceSessionId,
    background: true,
    name: sessionName,
  });

  console.log(`[Background] Spawned background subagent: ${subagent.id} "${sessionName}" (parent: ${voiceSessionId})`);

  // Broadcast tree update immediately so UI shows the new session
  wsBroadcast.sessionTreeUpdate(voiceSessionId);

  // Start the async execution (fire-and-forget)
  const completion = runBackgroundAgent(subagent.id, task, handoff).then((result) => {
    // Notify voice agent if still active and callback provided
    if (voiceAgent?.isActive()) {
      const message = completionMessage
        ? completionMessage(result)
        : `[Background task completed] ${result.substring(0, 300)}`;
      voiceAgent.sendMessage(message);
      console.log(`[Background] Notified voice agent of completion: ${subagent.id}`);
    } else {
      console.log(`[Background] Task completed but voice agent inactive: ${subagent.id}`);
    }
    return result;
  });

  return {
    sessionId: subagent.id,
    completion,
  };
}

/**
 * Run the background agent's main loop.
 * This is similar to handleDeveloperRequest but designed for background execution.
 */
async function runBackgroundAgent(
  sessionId: string,
  task: string,
  handoff?: HandoffPacket
): Promise {
  const sessionsRepo = new CliSessionsRepository();

  try {
    // Load config from CLI agent (reuse same config)
    const cliAgentDir = new URL('./cli', import.meta.url).pathname;
    const { config, prompt: systemPrompt } = await loadAgentConfig(cliAgentDir);

    // Format voice context from HandoffPacket (anti-telephone: lossless context transfer)
    const voiceContextText = handoff ? formatVoiceContext(handoff) : '(no voice context)';

    const userMessage = `
## Background Task
This is a BACKGROUND task running independently. Complete it thoroughly.

## Voice Context (for reference)
${voiceContextText}

## Task
${task}

Complete this task. When done, provide a concise summary of what was accomplished.
`.trim();

    console.log(`[Background] Starting agent for session ${sessionId}`);
    const { text: fullText } = await forwardLlmStreamToSession(
      llmRuntime.streamOpenRouter({
        model: {
          provider: 'openrouter',
          model: config.model,
          modality: 'llm',
        },
        context: {
          systemPrompt,
          messages: [{ role: 'user', content: userMessage }],
          tools: cliAgentToolDefinitions,
        },
        options: {
          maxSteps: config.maxSteps ?? 5,
        },
        toolHandler: executeCliAgentTool,
      }),
      { sessionId }
    );

    // Update session status
    sessionsRepo.finish(sessionId, 'finished');

    // Broadcast tree update
    const session = sessionsRepo.findById(sessionId);
    if (session?.parent_id) {
      wsBroadcast.sessionTreeUpdate(session.parent_id);
    }

    console.log(`[Background] Completed session ${sessionId}`);
    return fullText || 'Task completed.';
  } catch (error) {
    const errorMsg = error instanceof Error ? error.message : String(error);
    console.error(`[Background] Error in session ${sessionId}:`, errorMsg);
    wsBroadcast.streamChunk(sessionId, { type: 'error', error: errorMsg });
    sessionsRepo.finish(sessionId, 'error');
    return `Error: ${errorMsg}`;
  }
}



/**
 * Direct Input Handler - Routes text input to subagent sessions.
 *
 * Enables "chatable subagents" where users can type directly to a focused
 * subagent session instead of going through voice.
 */

import { wsBroadcast } from '../api/websocket.js';
import { CliSessionsRepository } from '../db/index.js';
import { loadAgentConfig } from './loader.js';
import { cliAgentToolDefinitions, executeCliAgentTool } from '../tools/cli-agent-tools.js';
import { getCurrentOrchestratorId, setCurrentOrchestratorId } from './cli/index.js';
import { llmRuntime } from './llm-runtime.js';
import { forwardLlmStreamToSession } from './stream-events.js';

/**
 * Handle direct text input to a subagent session.
 * Resumes the session's conversation and streams the response.
 */
export async function handleDirectInput(sessionId: string, text: string): Promise {
  const sessionsRepo = new CliSessionsRepository();
  const session = sessionsRepo.findById(sessionId);

  if (!session) {
    throw new Error(`Session not found: ${sessionId}`);
  }

  if (session.type !== 'subagent') {
    throw new Error(`Cannot send input to ${session.type} session`);
  }

  if (session.status === 'finished' || session.status === 'cancelled') {
    throw new Error(`Session is ${session.status}`);
  }

  console.log(`[DirectInput] Processing input for session ${sessionId.slice(0, 8)} (${session.agent_name})`);

  // Route based on agent type
  switch (session.agent_name) {
    case 'cli':
      await handleCliInput(session, text, sessionsRepo);
      break;
    default:
      throw new Error(`Unsupported agent type: ${session.agent_name}`);
  }
}

/**
 * Handle input to a CLI subagent session.
 */
async function handleCliInput(
  session: ReturnType & object,
  text: string,
  sessionsRepo: CliSessionsRepository
): Promise {
  const sessionId = session.id;

  // Load agent config
  const configPath = new URL('./cli', import.meta.url).pathname;
  const { config, prompt: systemPrompt } = await loadAgentConfig(configPath);

  // Load conversation history
  const history: Array<{ role: string; content: string }> = JSON.parse(
    session.conversation_history || '[]'
  );

  // Add user message
  history.push({ role: 'user', content: text });

  // Format for AI SDK
  const messages = history.map((msg) => ({
    role: msg.role as 'user' | 'assistant',
    content: msg.content,
  }));

  console.log(`[DirectInput] CLI session ${sessionId.slice(0, 8)}: ${history.length} messages in history`);

  const previousOrchestratorId = getCurrentOrchestratorId();
  setCurrentOrchestratorId(sessionId);

  try {
    // For direct input, we DO want to show the user's message
    // This is actual user input, not a tool invocation
    wsBroadcast.streamChunk(sessionId, { type: 'user-transcript', text });
    console.log('[DirectInput] Starting llm-runtime stream processing...');
    const { text: fullText, eventCount: updateCount } = await forwardLlmStreamToSession(
      llmRuntime.streamOpenRouter({
        model: {
          provider: 'openrouter',
          model: config.model,
          modality: 'llm',
        },
        context: {
          systemPrompt,
          messages,
          tools: cliAgentToolDefinitions,
        },
        options: {
          maxSteps: config.maxSteps ?? 3,
        },
        toolHandler: executeCliAgentTool,
      }),
      { sessionId }
    );

    console.log(`[DirectInput] Stream complete: ${updateCount} events, ${fullText.length} chars`);

    // Save updated history
    history.push({ role: 'assistant', content: fullText || 'No response' });
    sessionsRepo.update(session.id, {
      conversation_history: JSON.stringify(history),
    });

    console.log(`[DirectInput] Response saved to session ${sessionId.slice(0, 8)}`);

    // Broadcast tree update
    const parentId = session.parent_id;
    wsBroadcast.sessionTreeUpdate(parentId ?? sessionId);
  } catch (error) {
    const errorMsg = error instanceof Error ? error.message : String(error);
    console.error(`[DirectInput] Error:`, errorMsg);
    wsBroadcast.streamChunk(sessionId, { type: 'error', error: errorMsg });
    throw error;
  } finally {
    setCurrentOrchestratorId(previousOrchestratorId);
  }
}



/**
 * Tools Index - Export all available tools for the voice agent.
 */

export { webSearchTool } from '../subagents/web-search/index.js';
export { addTodoTool, viewTodosTool, deleteTodoTool } from './todo.js';
export { controlLightTool } from './govee.js';
export { reasoningTool } from './reasoning.js';
export { setTimerTool, listTimersTool, cancelTimerTool } from './timer.js';
export {
  createDeveloperSessionTool,
  checkSessionTool,
  sendFeedbackTool,
  stopSessionTool,
  viewPastSessionsTool,
} from './developer-session.js';
export { createBackgroundTaskTool } from './background-task.js';
export { createDirectTerminalTools } from './direct-terminal.js';

// Tool registry by name for easy lookup
import { webSearchTool } from '../subagents/web-search/index.js';
import { addTodoTool, viewTodosTool, deleteTodoTool } from './todo.js';
import { controlLightTool } from './govee.js';
import { reasoningTool } from './reasoning.js';
import { setTimerTool, listTimersTool, cancelTimerTool } from './timer.js';
import {
  createDeveloperSessionTool,
  checkSessionTool,
  sendFeedbackTool,
  stopSessionTool,
  viewPastSessionsTool,
} from './developer-session.js';
import { createBackgroundTaskTool } from './background-task.js';
import { createDirectTerminalTools, type DirectTerminalToolName } from './direct-terminal.js';
import type { VoiceAgent } from '../agent/voice-agent.js';

// Static tools that don't need session context
const staticToolsByName = {
  web_search: webSearchTool,
  add_todo: addTodoTool,
  view_todos: viewTodosTool,
  delete_todo: deleteTodoTool,
  control_light: controlLightTool,
  deep_thinking: reasoningTool,
  set_timer: setTimerTool,
  list_timers: listTimersTool,
  cancel_timer: cancelTimerTool,
  // Session management tools (these don't need the voice session ID)
  check_coding_session: checkSessionTool,
  send_session_feedback: sendFeedbackTool,
  stop_coding_session: stopSessionTool,
  view_past_sessions: viewPastSessionsTool,
} as const;

// Type includes both static tools and factory-created tools
export type ToolName =
  | keyof typeof staticToolsByName
  | 'developer_session'
  | 'background_task'
  | DirectTerminalToolName;

/**
 * Options for creating tools with injected dependencies.
 */
export interface ToolCreationOptions {
  /** Voice session ID for parent-child tracking */
  sessionId: string;
  /** Voice agent reference for completion notifications (needed by background_task) */
  voiceAgent?: VoiceAgent;
}

/**
 * Get tools for a session, instantiating factory tools with the session ID.
 * This allows tools like developer_session to access the voice session ID
 * without polluting the conversation context.
 *
 * @param names - Tool names to instantiate
 * @param options - Session ID and optional voice agent reference
 */
export function getToolsForSession(names: ToolName[], options: ToolCreationOptions | string) {
  // Support legacy signature (sessionId string) for backwards compatibility
  const { sessionId, voiceAgent } = typeof options === 'string'
    ? { sessionId: options, voiceAgent: undefined }
    : options;
  const directToolsByName = createDirectTerminalTools(sessionId);

  return names.map((name) => {
    // Factory tool: developer_session needs sessionId + voiceAgent for HandoffPacket
    if (name === 'developer_session') {
      return createDeveloperSessionTool(sessionId, voiceAgent);
    }
    // Factory tool: background_task needs sessionId AND voiceAgent
    if (name === 'background_task') {
      if (!voiceAgent) {
        console.warn('[Tools] background_task requires voiceAgent - tool may not notify on completion');
      }
      return createBackgroundTaskTool(voiceAgent!, sessionId);
    }
    // Factory tools: direct voice-to-terminal tools need voice session ID scoping
    if (name in directToolsByName) {
      return directToolsByName[name as DirectTerminalToolName];
    }
    // Static tools
    if (name in staticToolsByName) {
      return staticToolsByName[name as keyof typeof staticToolsByName];
    }
    throw new Error(`Unknown tool: ${name}`);
  });
}



/**
 * Mac Daemon Client - HTTP client for communicating with the Mac CLI daemon.
 *
 * The Mac daemon runs on the MacBook and manages tmux sessions for Claude Code.
 * This client provides a typed interface for all daemon API endpoints.
 */

// Mac daemon URL from environment or default to mDNS hostname
const MAC_DAEMON_URL =
  process.env.MAC_DAEMON_URL || 'http://MacBook-Pro-von-Lukasz.local:3100';

export interface MacSession {
  sessionId: string;
  tmuxSession: string;
  command: string;
  status: 'running' | 'waiting_for_input' | 'finished' | 'error';
  outputBuffer: string[];
  createdAt: string;
  goal?: string;
}

export interface StartSessionResponse {
  success: boolean;
  sessionId: string;
  tmuxSession: string;
  message: string;
}

export interface SessionOutputResponse {
  success: boolean;
  sessionId: string;
  status: string;
  output: string[];
  hasMore: boolean;
}

export interface SessionInputResponse {
  success: boolean;
  message: string;
}

export interface ListSessionsResponse {
  success: boolean;
  sessions: MacSession[];
}

export interface TerminateSessionResponse {
  success: boolean;
  message: string;
}

export type GuiTerminal = 'ghostty' | 'iterm2' | 'terminal';
export type WindowArrangement =
  | 'left_half'
  | 'right_half'
  | 'fullscreen'
  | 'top_half'
  | 'bottom_half'
  | 'center';

export interface GuiActionResponse {
  success: boolean;
  message: string;
}

export interface HealthResponse {
  status: string;
  uptime: number;
  sessions: number;
}

interface ApiEnvelope {
  success?: boolean;
  data?: T;
  message?: string;
  error?: string;
}

function isObject(value: unknown): value is Record {
  return value !== null && typeof value === 'object';
}

function getEnvelopeData(raw: unknown): T | null {
  if (!isObject(raw)) return null;
  if (!('data' in raw)) return null;
  return (raw as ApiEnvelope).data ?? null;
}

function getEnvelopeSuccess(raw: unknown, fallback: boolean): boolean {
  if (!isObject(raw)) return fallback;
  const success = (raw as ApiEnvelope).success;
  return typeof success === 'boolean' ? success : fallback;
}

function getEnvelopeMessage(raw: unknown, fallback: string): string {
  if (!isObject(raw)) return fallback;
  const envelope = raw as ApiEnvelope;
  if (typeof envelope.message === 'string' && envelope.message.length > 0) return envelope.message;
  if (typeof envelope.error === 'string' && envelope.error.length > 0) return envelope.error;
  return fallback;
}

/**
 * Check if the Mac daemon is reachable.
 */
export async function checkHealth(): Promise {
  try {
    const res = await fetch(`${MAC_DAEMON_URL}/health`, {
      method: 'GET',
      signal: AbortSignal.timeout(5000),
    });
    if (!res.ok) return null;
    return (await res.json()) as HealthResponse;
  } catch (error) {
    console.error('[MacClient] Health check failed:', error);
    return null;
  }
}

/**
 * Start a new CLI session on the Mac daemon.
 *
 * @param sessionId - Unique session ID (generated by Pi)
 * @param goal - Description of what this session should accomplish
 * @param command - CLI command to run (default: 'claude --dangerously-skip-permissions')
 */
export async function startCliSession(
  sessionId: string,
  goal: string,
  command = 'claude --dangerously-skip-permissions'
): Promise {
  console.log(`[MacClient] Starting session ${sessionId}: ${goal}`);
  console.log(`[MacClient] Command: ${command}`);

  const res = await fetch(`${MAC_DAEMON_URL}/sessions`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ sessionId, goal, command }),
  });

  const raw = (await res.json()) as unknown;
  const wrappedData = getEnvelopeData<{
    sessionId?: string;
    tmuxSession?: string;
  }>(raw);

  const success = getEnvelopeSuccess(raw, res.ok);
  const normalized: StartSessionResponse = wrappedData
    ? {
        success,
        sessionId: wrappedData.sessionId ?? sessionId,
        tmuxSession: wrappedData.tmuxSession ?? '',
        message: getEnvelopeMessage(raw, success ? 'Session gestartet.' : 'Fehler beim Starten der Session.'),
      }
    : {
        success,
        sessionId: (raw as Partial)?.sessionId ?? sessionId,
        tmuxSession: (raw as Partial)?.tmuxSession ?? '',
        message: getEnvelopeMessage(raw, success ? 'Session gestartet.' : 'Fehler beim Starten der Session.'),
      };

  console.log(`[MacClient] Start response:`, normalized);
  return normalized;
}

/**
 * Send input to a running CLI session.
 *
 * @param sessionId - The session ID
 * @param input - Text input to send (will be followed by Enter)
 */
export async function sendCliInput(
  sessionId: string,
  input: string
): Promise {
  console.log(`[MacClient] Sending input to ${sessionId}: ${input.substring(0, 100)}...`);

  const res = await fetch(`${MAC_DAEMON_URL}/sessions/${sessionId}/input`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ input }),
  });

  const raw = (await res.json()) as unknown;
  const normalized: SessionInputResponse = {
    success: getEnvelopeSuccess(raw, res.ok),
    message: getEnvelopeMessage(raw, res.ok ? 'Input gesendet.' : 'Fehler beim Senden von Input.'),
  };
  console.log(`[MacClient] Input response:`, normalized);
  return normalized;
}

/**
 * Read current output from a CLI session.
 *
 * @param sessionId - The session ID
 */
export async function readCliOutput(
  sessionId: string
): Promise {
  const res = await fetch(`${MAC_DAEMON_URL}/sessions/${sessionId}/output`, {
    method: 'GET',
  });

  const raw = (await res.json()) as unknown;
  const wrappedData = getEnvelopeData<{
    sessionId?: string;
    status?: string;
    output?: unknown;
    hasMore?: unknown;
  }>(raw);
  const source = wrappedData ?? (isObject(raw) ? raw : {});

  const data: SessionOutputResponse = {
    success: getEnvelopeSuccess(raw, res.ok),
    sessionId: typeof source.sessionId === 'string' ? source.sessionId : sessionId,
    status: typeof source.status === 'string' ? source.status : '',
    output: Array.isArray(source.output)
      ? source.output.filter((line): line is string => typeof line === 'string')
      : [],
    hasMore: Boolean(source.hasMore),
  };

  // Don't log full output - too noisy
  console.log(`[MacClient] Output status: ${data.status}, lines: ${data.output?.length ?? 0}`);
  return data;
}

/**
 * List all active sessions on the Mac daemon.
 */
export async function listCliSessions(): Promise {
  const res = await fetch(`${MAC_DAEMON_URL}/sessions`, {
    method: 'GET',
  });

  const raw = (await res.json()) as unknown;
  const wrappedData = getEnvelopeData(raw);
  const flatSessions = isObject(raw) ? raw.sessions : undefined;
  const candidate = wrappedData ?? flatSessions;
  const sessions = Array.isArray(candidate) ? (candidate as MacSession[]) : [];
  const normalized: ListSessionsResponse = {
    success: getEnvelopeSuccess(raw, res.ok),
    sessions,
  };

  console.log(`[MacClient] Listed ${normalized.sessions?.length ?? 0} sessions`);
  return normalized;
}

/**
 * Get details of a specific session.
 *
 * @param sessionId - The session ID
 */
export async function getSessionDetails(
  sessionId: string
): Promise {
  try {
    const res = await fetch(`${MAC_DAEMON_URL}/sessions/${sessionId}`, {
      method: 'GET',
    });

  if (!res.ok) return null;
    const raw = (await res.json()) as unknown;
    const wrappedData = getEnvelopeData(raw);
    if (wrappedData) return wrappedData;
    if (isObject(raw) && typeof raw.sessionId === 'string') return raw as unknown as MacSession;
    return null;
  } catch (error) {
    console.error(`[MacClient] Failed to get session ${sessionId}:`, error);
    return null;
  }
}

/**
 * Terminate a CLI session.
 *
 * @param sessionId - The session ID to terminate
 */
export async function terminateSession(
  sessionId: string
): Promise {
  console.log(`[MacClient] Terminating session ${sessionId}`);

  const res = await fetch(`${MAC_DAEMON_URL}/sessions/${sessionId}`, {
    method: 'DELETE',
  });

  const raw = (await res.json()) as unknown;
  const normalized: TerminateSessionResponse = {
    success: getEnvelopeSuccess(raw, res.ok),
    message: getEnvelopeMessage(raw, res.ok ? 'Session beendet.' : 'Fehler beim Beenden der Session.'),
  };
  console.log(`[MacClient] Terminate response:`, normalized);
  return normalized;
}

/**
 * Open a GUI terminal attached to an existing tmux session.
 */
export async function openGuiTerminal(
  sessionId: string,
  terminal: GuiTerminal = 'ghostty'
): Promise {
  console.log(`[MacClient] Opening ${terminal} GUI for session ${sessionId}`);

  const res = await fetch(`${MAC_DAEMON_URL}/sessions/${sessionId}/open-gui`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ terminal }),
  });

  const raw = (await res.json()) as unknown;
  const normalized: GuiActionResponse = {
    success: getEnvelopeSuccess(raw, res.ok),
    message: getEnvelopeMessage(
      raw,
      res.ok
        ? `${terminal} window opened.`
        : `Failed to open ${terminal} window.`
    ),
  };

  console.log('[MacClient] Open GUI response:', normalized);
  return normalized;
}

/**
 * Close the GUI terminal window for a tmux session.
 */
export async function closeGuiTerminal(
  sessionId: string
): Promise {
  console.log(`[MacClient] Closing GUI for session ${sessionId}`);

  const res = await fetch(`${MAC_DAEMON_URL}/sessions/${sessionId}/close-gui`, {
    method: 'POST',
  });

  const raw = (await res.json()) as unknown;
  const normalized: GuiActionResponse = {
    success: getEnvelopeSuccess(raw, res.ok),
    message: getEnvelopeMessage(
      raw,
      res.ok ? 'GUI window closed.' : 'Failed to close GUI window.'
    ),
  };

  console.log('[MacClient] Close GUI response:', normalized);
  return normalized;
}

/**
 * Arrange/resize a GUI terminal window for a tmux session.
 */
export async function arrangeWindow(
  sessionId: string,
  arrangement: WindowArrangement
): Promise {
  console.log(
    `[MacClient] Arranging GUI for ${sessionId} -> ${arrangement}`
  );

  const res = await fetch(`${MAC_DAEMON_URL}/sessions/${sessionId}/arrange`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ arrangement }),
  });

  const raw = (await res.json()) as unknown;
  const normalized: GuiActionResponse = {
    success: getEnvelopeSuccess(raw, res.ok),
    message: getEnvelopeMessage(
      raw,
      res.ok ? `Window arranged as ${arrangement}.` : 'Failed to arrange window.'
    ),
  };

  console.log('[MacClient] Arrange window response:', normalized);
  return normalized;
}

/**
 * Wait for a session to complete (polling).
 *
 * @param sessionId - The session ID
 * @param timeoutMs - Maximum time to wait (default: 5 minutes)
 * @param pollIntervalMs - How often to check (default: 2 seconds)
 */
export async function waitForCompletion(
  sessionId: string,
  timeoutMs = 300_000,
  pollIntervalMs = 2000
): Promise<{ completed: boolean; output: string[]; status: string }> {
  const startTime = Date.now();
  let consecutiveUndefined = 0;
  const maxUndefinedRetries = 3;

  while (Date.now() - startTime < timeoutMs) {
    try {
      const result = await readCliOutput(sessionId);

      // Handle terminal states
      if (result.status === 'finished' || result.status === 'error') {
        return {
          completed: true,
          output: result.output ?? [],
          status: result.status,
        };
      }

      // Handle undefined/missing status - likely session doesn't exist or daemon issue
      if (!result.status) {
        consecutiveUndefined++;
        console.warn(
          `[MacClient] Received undefined status for session ${sessionId} (attempt ${consecutiveUndefined}/${maxUndefinedRetries})`
        );

        if (consecutiveUndefined >= maxUndefinedRetries) {
          console.error(
            `[MacClient] Session ${sessionId} returned undefined status ${maxUndefinedRetries} times, aborting poll`
          );
          return {
            completed: false,
            output: result.output ?? [],
            status: 'unknown',
          };
        }
      } else {
        // Reset counter on valid status
        consecutiveUndefined = 0;
      }

      // Wait before next poll
      await new Promise((resolve) => setTimeout(resolve, pollIntervalMs));
    } catch (error) {
      console.error(`[MacClient] Error polling session ${sessionId}:`, error);
      return {
        completed: false,
        output: [],
        status: 'error',
      };
    }
  }

  return {
    completed: false,
    output: [],
    status: 'timeout',
  };
}



/**
 * Local Audio Transport - Hardware audio via PipeWire (Linux) or sox (macOS).
 *
 * Handles both microphone capture and speaker playback using native tools:
 * - Linux (Pi): pw-cat for PipeWire
 * - macOS: sox (rec/play commands)
 */

import { execSync, spawn, ChildProcess } from 'child_process';
import { EventEmitter } from 'events';
import { AUDIO_CONFIG, type IAudioTransport } from './types.js';

const isLinux = process.platform === 'linux';
const isMac = process.platform === 'darwin';

export interface LocalAudioDeviceInfo {
  inputDevices: string[];
  outputDevices: string[];
  defaultInputDevice: string;
  defaultOutputDevice: string;
}

export interface LocalTransportOptions {
  inputDevice?: string;
  outputDevice?: string;
  preferEchoCancelSource?: boolean;
}

export interface LocalRoutingDiagnostics {
  inputDevice: string;
  outputDevice: string;
  echoCancelSourceSelected: boolean;
  samePhysicalDeviceLikely: boolean;
}

const ECHO_CANCEL_SOURCE_PATTERNS = [/echo[-_. ]?cancel/i, /\baec\b/i, /webrtc/i];
const DEVICE_IDENTITY_STOPWORDS = new Set([
  'alsa',
  'analog',
  'audio',
  'builtin',
  'card',
  'coreaudio',
  'default',
  'hdmi',
  'iec958',
  'input',
  'mic',
  'microphone',
  'monitor',
  'mono',
  'output',
  'pcm',
  'sink',
  'source',
  'speaker',
  'speakers',
  'stereo',
  'usb',
]);

export function isEchoCancelSourceName(deviceName: string): boolean {
  const normalized = deviceName.trim().toLowerCase();
  if (!normalized || normalized === 'default') {
    return false;
  }
  return ECHO_CANCEL_SOURCE_PATTERNS.some((pattern) => pattern.test(normalized));
}

export function selectPreferredLinuxInputDevice(options: {
  requestedInputDevice: string;
  inventory: LocalAudioDeviceInfo;
  preferEchoCancelSource: boolean;
}): string {
  const requestedInput = options.requestedInputDevice.trim() || 'default';
  if (requestedInput !== 'default') {
    return requestedInput;
  }

  const fallbackDefault =
    options.inventory.defaultInputDevice || options.inventory.inputDevices[0] || 'default';
  if (!options.preferEchoCancelSource) {
    return fallbackDefault;
  }

  const candidates = options.inventory.inputDevices
    .filter((device) => isEchoCancelSourceName(device))
    .sort((left, right) => {
      const scoreDiff = scoreEchoCancelCandidate(right) - scoreEchoCancelCandidate(left);
      if (scoreDiff !== 0) return scoreDiff;
      return left.localeCompare(right);
    });

  return candidates[0] ?? fallbackDefault;
}

export function areLikelySamePhysicalAudioDevice(
  inputDevice: string,
  outputDevice: string
): boolean {
  const inputNormalized = inputDevice.trim().toLowerCase() || 'default';
  const outputNormalized = outputDevice.trim().toLowerCase() || 'default';

  if (inputNormalized === 'default' && outputNormalized === 'default') {
    return true;
  }
  if (inputNormalized === outputNormalized) {
    return true;
  }

  const inputBackendCanonical = canonicalBackendNode(inputNormalized);
  const outputBackendCanonical = canonicalBackendNode(outputNormalized);
  if (inputBackendCanonical && inputBackendCanonical === outputBackendCanonical) {
    return true;
  }

  const inputTokens = tokenizeDeviceIdentity(inputNormalized);
  const outputTokens = tokenizeDeviceIdentity(outputNormalized);
  if (inputTokens.length === 0 || outputTokens.length === 0) {
    return false;
  }

  const outputSet = new Set(outputTokens);
  let overlap = 0;
  for (const token of inputTokens) {
    if (outputSet.has(token)) {
      overlap += 1;
    }
  }

  const minSize = Math.min(inputTokens.length, outputTokens.length);
  return overlap >= 2 && overlap / minSize >= 0.6;
}

function scoreEchoCancelCandidate(deviceName: string): number {
  const normalized = deviceName.toLowerCase();
  let score = 0;
  if (/echo[-_. ]?cancel/.test(normalized)) score += 10;
  if (/\baec\b/.test(normalized)) score += 6;
  if (/webrtc/.test(normalized)) score += 4;
  if (/\bsource\b/.test(normalized)) score += 1;
  return score;
}

function canonicalBackendNode(deviceName: string): string {
  if (!deviceName) return '';
  return deviceName
    .replace(/^(alsa|bluez|coreaudio|pipewire)_(input|output)\./, '')
    .replace(/^(input|output)\./, '')
    .replace(/\.monitor$/, '')
    .replace(/\.analog-(stereo|mono)$/, '')
    .replace(/\.iec958-stereo$/, '');
}

function tokenizeDeviceIdentity(deviceName: string): string[] {
  return deviceName
    .split(/[^a-z0-9]+/)
    .map((token) => token.trim())
    .filter((token) => {
      if (!token || token.length < 2) return false;
      if (DEVICE_IDENTITY_STOPWORDS.has(token)) return false;
      return true;
    });
}

export function parseMacAudioDevices(systemProfilerOutput: string): LocalAudioDeviceInfo {
  const inputSet = new Set();
  const outputSet = new Set();
  let currentDevice: string | null = null;
  let defaultInput: string | null = null;
  let defaultOutput: string | null = null;

  for (const line of systemProfilerOutput.split('\n')) {
    const deviceLine = line.match(/^ {8}(.+):$/);
    if (deviceLine?.[1]) {
      currentDevice = deviceLine[1].trim();
      continue;
    }

    const trimmed = line.trim();
    if (!currentDevice || !trimmed) continue;

    if (trimmed === 'Default Input Device: Yes') {
      defaultInput = currentDevice;
      inputSet.add(currentDevice);
      continue;
    }
    if (trimmed === 'Default Output Device: Yes') {
      defaultOutput = currentDevice;
      outputSet.add(currentDevice);
      continue;
    }
    if (trimmed.startsWith('Input Channels:')) {
      inputSet.add(currentDevice);
      continue;
    }
    if (trimmed.startsWith('Output Channels:')) {
      outputSet.add(currentDevice);
    }
  }

  const inputDevices = [...inputSet];
  const outputDevices = [...outputSet];
  const defaultInputDevice = defaultInput ?? inputDevices[0] ?? 'default';
  const defaultOutputDevice = defaultOutput ?? outputDevices[0] ?? 'default';

  return {
    inputDevices: inputDevices.length > 0 ? inputDevices : ['default'],
    outputDevices: outputDevices.length > 0 ? outputDevices : ['default'],
    defaultInputDevice,
    defaultOutputDevice,
  };
}

function parseLinuxAudioDevices(): LocalAudioDeviceInfo {
  try {
    const sourcesRaw = execSync('pactl list short sources', { encoding: 'utf8', stdio: ['ignore', 'pipe', 'ignore'] });
    const sinksRaw = execSync('pactl list short sinks', { encoding: 'utf8', stdio: ['ignore', 'pipe', 'ignore'] });
    const infoRaw = execSync('pactl info', { encoding: 'utf8', stdio: ['ignore', 'pipe', 'ignore'] });

    const inputDevices = sourcesRaw
      .split('\n')
      .map((line) => line.split('\t')[1]?.trim())
      .filter((name): name is string => Boolean(name));
    const outputDevices = sinksRaw
      .split('\n')
      .map((line) => line.split('\t')[1]?.trim())
      .filter((name): name is string => Boolean(name));

    const defaultInputDevice =
      infoRaw.match(/^Default Source:\s*(.+)$/m)?.[1]?.trim() ??
      inputDevices[0] ??
      'default';
    const defaultOutputDevice =
      infoRaw.match(/^Default Sink:\s*(.+)$/m)?.[1]?.trim() ??
      outputDevices[0] ??
      'default';

    return {
      inputDevices: inputDevices.length > 0 ? inputDevices : ['default'],
      outputDevices: outputDevices.length > 0 ? outputDevices : ['default'],
      defaultInputDevice,
      defaultOutputDevice,
    };
  } catch {
    return {
      inputDevices: ['default'],
      outputDevices: ['default'],
      defaultInputDevice: 'default',
      defaultOutputDevice: 'default',
    };
  }
}

export class LocalTransport extends EventEmitter implements IAudioTransport {
  private static readonly PLAYBACK_WARMUP_MS = 80;
  private static readonly MAX_QUEUE_BYTES = 1024 * 1024; // 1MB safety cap

  private recorder: ChildProcess | null = null;
  private player: ChildProcess | null = null;
  private isRecording = false;
  private isPlaying = false;
  private captureEnabled = true;
  private playbackSampleRate: number = AUDIO_CONFIG.API_SAMPLE_RATE;
  private inputDevice: string;
  private outputDevice: string;
  private readonly preferEchoCancelSource: boolean;
  private captureFallbackAttempted = false;
  private playbackFallbackAttempted = false;
  private playbackReady = false;
  private playbackWarmupTimer: NodeJS.Timeout | null = null;
  private playbackQueue: Buffer[] = [];
  private queuedPlaybackBytes = 0;
  private flushScheduled = false;

  constructor(options?: LocalTransportOptions) {
    super();
    const requestedInputDevice = options?.inputDevice?.trim() || 'default';
    const requestedOutputDevice = options?.outputDevice?.trim() || 'default';
    this.preferEchoCancelSource = options?.preferEchoCancelSource ?? false;

    this.inputDevice = requestedInputDevice;
    this.outputDevice = requestedOutputDevice;

    if (isLinux) {
      const inventory = parseLinuxAudioDevices();
      this.inputDevice = selectPreferredLinuxInputDevice({
        requestedInputDevice,
        inventory,
        preferEchoCancelSource: this.preferEchoCancelSource,
      });
      this.outputDevice =
        requestedOutputDevice === 'default'
          ? inventory.defaultOutputDevice || 'default'
          : requestedOutputDevice;

      if (
        this.preferEchoCancelSource &&
        requestedInputDevice === 'default' &&
        this.inputDevice !== inventory.defaultInputDevice &&
        this.inputDevice !== 'default'
      ) {
        console.log(
          `[LocalTransport] Using echo-cancel input source: ${this.inputDevice} (default source: ${inventory.defaultInputDevice})`
        );
      }
    }

    if (!isLinux && !isMac) {
      console.warn(`[LocalTransport] Unsupported platform: ${process.platform}`);
    }
  }

  static listAudioDevices(): LocalAudioDeviceInfo {
    if (isMac) {
      try {
        const output = execSync('system_profiler SPAudioDataType 2>/dev/null', {
          encoding: 'utf8',
          stdio: ['ignore', 'pipe', 'ignore'],
        });
        return parseMacAudioDevices(output);
      } catch {
        return {
          inputDevices: ['default'],
          outputDevices: ['default'],
          defaultInputDevice: 'default',
          defaultOutputDevice: 'default',
        };
      }
    }

    if (isLinux) {
      return parseLinuxAudioDevices();
    }

    return {
      inputDevices: ['default'],
      outputDevices: ['default'],
      defaultInputDevice: 'default',
      defaultOutputDevice: 'default',
    };
  }

  /**
   * Start capturing microphone audio.
   */
  start(): void {
    if (this.isRecording) {
      return;
    }
    this.captureFallbackAttempted = false;

    if (isLinux) {
      this.startLinuxCapture();
    } else if (isMac) {
      this.startMacCapture();
    } else {
      this.emit('error', new Error(`Unsupported platform: ${process.platform}`));
      return;
    }

    this.isRecording = true;
    console.log(
      `[LocalTransport] Capture started (${AUDIO_CONFIG.API_SAMPLE_RATE}Hz pcm16, input=${this.inputDevice})`
    );
  }

  /**
   * Start Linux capture using pw-cat (PipeWire).
   */
  private startLinuxCapture(): void {
    const args = [
      '--record',
      '--raw',
      '--channels', String(AUDIO_CONFIG.CHANNELS),
      '--rate', String(AUDIO_CONFIG.API_SAMPLE_RATE),
      '--format', AUDIO_CONFIG.FORMAT,
    ];
    if (this.inputDevice !== 'default') {
      args.push('--target', this.inputDevice);
    }
    args.push('-');

    this.recorder = spawn('pw-cat', args, {
      stdio: ['ignore', 'pipe', 'pipe'],
    });

    this.setupRecorderHandlers('pw-cat');
  }

  /**
   * Start macOS capture using sox (rec command).
   * Requires: brew install sox
   *
   * We omit -r from rec options so sox captures at the device's native rate
   * (Bluetooth devices like Bose QC45 may not support 24kHz natively).
   * The `rate` effect then resamples to the target sample rate.
   */
  private startMacCapture(): void {
    if (this.inputDevice === 'default') {
      this.recorder = spawn('rec', [
        '-t', 'raw',           // Raw PCM output
        '-e', 'signed',        // Signed integers
        '-b', String(AUDIO_CONFIG.BIT_DEPTH),
        '-c', String(AUDIO_CONFIG.CHANNELS),
        '-q',                  // Quiet mode (suppress progress)
        '-',                   // Output to stdout
        'rate', String(AUDIO_CONFIG.API_SAMPLE_RATE),  // Resample to target rate
      ], {
        stdio: ['ignore', 'pipe', 'pipe'],
      });
    } else {
      this.recorder = spawn('sox', [
        '-q',
        '-t', 'coreaudio',
        this.inputDevice,
        '-t', 'raw',
        '-e', 'signed',
        '-b', String(AUDIO_CONFIG.BIT_DEPTH),
        '-c', String(AUDIO_CONFIG.CHANNELS),
        '-',
        'rate', String(AUDIO_CONFIG.API_SAMPLE_RATE),
      ], {
        stdio: ['ignore', 'pipe', 'pipe'],
      });
    }

    this.setupRecorderHandlers('sox rec');
  }

  /**
   * Set up event handlers for the recorder process.
   */
  private setupRecorderHandlers(name: string): void {
    if (!this.recorder) return;

    this.recorder.stderr?.on('data', (data: Buffer) => {
      const msg = data.toString().trim();
      if (msg && !msg.includes('opened') && !msg.includes('In:')) {
        console.error(`[LocalTransport] ${name}:`, msg);
      }
    });

    this.recorder.on('error', (err) => {
      console.error(`[LocalTransport] ${name} error:`, err.message);
      this.emit('error', err);
    });

    this.recorder.on('exit', (code) => {
      if (
        this.isRecording &&
        code !== 0 &&
        this.inputDevice !== 'default' &&
        !this.captureFallbackAttempted
      ) {
        const failedDevice = this.inputDevice;
        this.captureFallbackAttempted = true;
        this.inputDevice = 'default';
        console.error(
          `[LocalTransport] input device "${failedDevice}" failed; retrying with default input`
        );
        this.emit(
          'error',
          new Error(`Input device "${failedDevice}" unavailable; switched to default input`)
        );
        if (isLinux) {
          this.startLinuxCapture();
        } else if (isMac) {
          this.startMacCapture();
        }
        this.isRecording = true;
        return;
      }

      if (this.isRecording && code !== 0) {
        console.error(`[LocalTransport] ${name} exited with code ${code}`);
      }
      this.isRecording = false;
    });

    this.recorder.stdout?.on('data', (data: Buffer) => {
      if (!this.captureEnabled) {
        return;
      }
      // Convert Buffer to ArrayBuffer and emit
      const arrayBuffer = data.buffer.slice(
        data.byteOffset,
        data.byteOffset + data.byteLength
      );
      this.emit('audio', arrayBuffer);
    });
  }

  /**
   * Stop capturing audio.
   */
  stop(): void {
    const hadCaptureOrPlayback = this.isRecording || this.isPlaying;

    this.isRecording = false;

    if (this.recorder) {
      this.recorder.kill('SIGTERM');
      this.recorder = null;
    }

    // Also stop playback when capture stops
    this.stopPlayback();

    if (hadCaptureOrPlayback) {
      console.log('[LocalTransport] Stopped');
    }
  }

  /**
   * Play PCM16 mono audio. Accepts an optional sample rate from the provider;
   * defaults to AUDIO_CONFIG.API_SAMPLE_RATE (24kHz).
   */
  play(audio: ArrayBuffer, sampleRate?: number): void {
    const buffer = Buffer.isBuffer(audio) ? audio : Buffer.from(audio);

    if (!this.player) {
      this.startPlayback(sampleRate);
    }

    this.enqueuePlaybackBuffer(buffer);
    this.schedulePlaybackFlush();
  }

  /**
   * Start the playback process.
   */
  private startPlayback(sampleRate?: number): void {
    if (this.player) {
      return;
    }

    this.playbackSampleRate = sampleRate ?? AUDIO_CONFIG.API_SAMPLE_RATE;
    this.playbackFallbackAttempted = false;

    if (isLinux) {
      this.startLinuxPlayback();
    } else if (isMac) {
      this.startMacPlayback();
    } else {
      this.emit('error', new Error(`Unsupported platform: ${process.platform}`));
      return;
    }

    this.isPlaying = true;
    this.playbackReady = false;
    console.log(
      `[LocalTransport] Playback started (${this.playbackSampleRate}Hz pcm16, output=${this.outputDevice})`
    );

    // CoreAudio sinks can exit prematurely if stdin is written immediately
    // after spawn. Buffer initial chunks and flush after a short warmup.
    this.clearPlaybackWarmupTimer();
    this.playbackWarmupTimer = setTimeout(() => {
      this.playbackReady = true;
      this.schedulePlaybackFlush();
    }, LocalTransport.PLAYBACK_WARMUP_MS);
  }

  /**
   * Start Linux playback using pw-cat (PipeWire).
   */
  private startLinuxPlayback(): void {
    const args = [
      '--playback',
      '--raw',
      '--channels', String(AUDIO_CONFIG.CHANNELS),
      '--rate', String(this.playbackSampleRate),
      '--format', AUDIO_CONFIG.FORMAT,
    ];
    if (this.outputDevice !== 'default') {
      args.push('--target', this.outputDevice);
    }
    args.push('-');

    this.player = spawn('pw-cat', args, {
      stdio: ['pipe', 'pipe', 'pipe'],
    });

    this.setupPlayerHandlers('pw-cat');
  }

  /**
   * Start macOS playback using a direct SoX CoreAudio sink.
   *
   * We intentionally avoid the `play` wrapper because under Bun + realtime
   * chunked stdin it can exit early, which truncates assistant utterances.
   */
  private startMacPlayback(): void {
    this.player = spawn('sox', [
      '-q',
      '-t', 'raw',
      '-r', String(this.playbackSampleRate),
      '-e', 'signed',
      '-b', String(AUDIO_CONFIG.BIT_DEPTH),
      '-c', String(AUDIO_CONFIG.CHANNELS),
      '-',
      '-t', 'coreaudio',
      this.outputDevice,
    ], {
      stdio: ['pipe', 'pipe', 'pipe'],
    });

    this.setupPlayerHandlers('sox coreaudio');
  }

  /**
   * Set up event handlers for the player process.
   */
  private setupPlayerHandlers(name: string): void {
    if (!this.player) return;

    const fallbackToDefaultOutput = (trigger: string): boolean => {
      if (
        !(isLinux || isMac) ||
        !this.isPlaying ||
        this.outputDevice === 'default' ||
        this.playbackFallbackAttempted
      ) {
        return false;
      }

      const failedDevice = this.outputDevice;
      this.playbackFallbackAttempted = true;
      this.outputDevice = 'default';
      console.error(
        `[LocalTransport] output device "${failedDevice}" ${trigger}; falling back to default output`
      );
      this.emit(
        'error',
        new Error(`Output device "${failedDevice}" unavailable; switched to default output`)
      );
      this.player = null;
      this.startPlayback(this.playbackSampleRate);
      return true;
    };

    this.player.stderr?.on('data', (data: Buffer) => {
      const msg = data.toString().trim();
      if (msg) {
        console.error(`[LocalTransport] ${name} stderr:`, msg);
      }
    });

    this.player.on('error', (err) => {
      console.error(`[LocalTransport] ${name} error:`, err.message);
      if (fallbackToDefaultOutput('failed')) {
        return;
      }
      this.player = null;
      this.isPlaying = false;
      this.playbackReady = false;
      this.clearPlaybackWarmupTimer();
    });

    this.player.on('exit', (code, signal) => {
      if (code !== 0 && fallbackToDefaultOutput(`exited with code ${code}`)) {
        return;
      }
      console.error(`[LocalTransport] ${name} exited: code=${code} signal=${signal} (wasPlaying=${this.isPlaying})`);
      this.player = null;
      this.isPlaying = false;
      this.playbackReady = false;
      this.clearPlaybackWarmupTimer();
    });

    this.player.stdin?.on('error', () => {
      // Ignore EPIPE errors
    });
  }

  /**
   * Stop playback.
   */
  private stopPlayback(): void {
    this.isPlaying = false;
    this.playbackReady = false;
    this.clearPlaybackWarmupTimer();
    this.playbackQueue = [];
    this.queuedPlaybackBytes = 0;
    this.flushScheduled = false;

    if (this.player) {
      try {
        this.player.stdin?.end();
      } catch {
        // Ignore
      }
      try {
        this.player.kill('SIGTERM');
      } catch {
        // Ignore
      }
      this.player = null;
    }
  }

  /**
   * Interrupt any currently playing audio.
   */
  interrupt(): void {
    this.stopPlayback();
    this.emit('interrupted');
  }

  /**
   * Check if transport is actively capturing audio.
   */
  isActive(): boolean {
    return this.isRecording;
  }

  /**
   * Enable/disable forwarding captured mic audio to listeners.
   * Capture process remains running; this only gates emitted chunks.
   */
  setCaptureEnabled(enabled: boolean): void {
    this.captureEnabled = enabled;
  }

  setInputDevice(device: string): void {
    const normalized = this.resolveInputDevice(device.trim() || 'default');
    if (normalized === this.inputDevice) return;
    this.inputDevice = normalized;
    if (this.isRecording) {
      this.restartCapture();
    }
  }

  setOutputDevice(device: string): void {
    const normalized = this.resolveOutputDevice(device.trim() || 'default');
    if (normalized === this.outputDevice) return;
    this.outputDevice = normalized;
    // Restart playback pipe; next chunk continues on selected output.
    this.stopPlayback();
  }

  getSelectedDevices(): { inputDevice: string; outputDevice: string } {
    return { inputDevice: this.inputDevice, outputDevice: this.outputDevice };
  }

  getRoutingDiagnostics(): LocalRoutingDiagnostics {
    return {
      inputDevice: this.inputDevice,
      outputDevice: this.outputDevice,
      echoCancelSourceSelected: isEchoCancelSourceName(this.inputDevice),
      samePhysicalDeviceLikely: areLikelySamePhysicalAudioDevice(
        this.inputDevice,
        this.outputDevice
      ),
    };
  }

  /**
   * Check if transport is currently playing audio.
   */
  isPlayingAudio(): boolean {
    return this.isPlaying;
  }

  private resolveInputDevice(requested: string): string {
    if (!isLinux) {
      return requested;
    }

    const inventory = parseLinuxAudioDevices();
    return selectPreferredLinuxInputDevice({
      requestedInputDevice: requested,
      inventory,
      preferEchoCancelSource: this.preferEchoCancelSource,
    });
  }

  private resolveOutputDevice(requested: string): string {
    if (!isLinux || requested !== 'default') {
      return requested;
    }
    const inventory = parseLinuxAudioDevices();
    return inventory.defaultOutputDevice || 'default';
  }

  private restartCapture(): void {
    if (this.recorder) {
      try {
        this.recorder.kill('SIGTERM');
      } catch {
        // Ignore
      }
      this.recorder = null;
    }

    if (isLinux) {
      this.startLinuxCapture();
    } else if (isMac) {
      this.captureFallbackAttempted = false;
      this.startMacCapture();
    } else {
      this.emit('error', new Error(`Unsupported platform: ${process.platform}`));
      return;
    }

    this.isRecording = true;
    console.log(`[LocalTransport] Capture input switched to ${this.inputDevice}`);
  }

  private enqueuePlaybackBuffer(buffer: Buffer): void {
    this.playbackQueue.push(buffer);
    this.queuedPlaybackBytes += buffer.byteLength;

    // Keep most-recent audio if writer stalls.
    while (this.queuedPlaybackBytes > LocalTransport.MAX_QUEUE_BYTES && this.playbackQueue.length > 0) {
      const dropped = this.playbackQueue.shift();
      if (!dropped) break;
      this.queuedPlaybackBytes -= dropped.byteLength;
    }
  }

  private schedulePlaybackFlush(): void {
    if (this.flushScheduled) return;
    this.flushScheduled = true;
    queueMicrotask(() => {
      this.flushScheduled = false;
      this.flushPlaybackQueue();
    });
  }

  private flushPlaybackQueue(): void {
    if (!this.player || !this.playbackReady || !this.player.stdin?.writable) {
      return;
    }

    while (this.playbackQueue.length > 0) {
      const chunk = this.playbackQueue[0];
      if (!chunk) break;
      const writable = this.player.stdin.write(chunk);
      this.playbackQueue.shift();
      this.queuedPlaybackBytes -= chunk.byteLength;

      if (!writable) {
        this.player.stdin.once('drain', () => this.flushPlaybackQueue());
        break;
      }
    }
  }

  private clearPlaybackWarmupTimer(): void {
    if (!this.playbackWarmupTimer) return;
    clearTimeout(this.playbackWarmupTimer);
    this.playbackWarmupTimer = null;
  }
}



/**
 * Hook for loading and managing benchmark report files.
 */

import { useEffect, useCallback } from 'react';
import fs from 'fs';
import path from 'path';
import { useInspector } from '../state.js';
import type { ReportListEntry, BenchmarkReportFile } from '../types.js';

function resolveBenchmarkDir(): string {
  if (process.env.VOICE_BENCH_OUTPUT_DIR) {
    return path.resolve(process.cwd(), process.env.VOICE_BENCH_OUTPUT_DIR);
  }
  const cwdBase = path.basename(process.cwd());
  if (cwdBase === 'voice-agent') {
    return path.resolve(process.cwd(), '..', '..', '.benchmarks', 'voice');
  }
  return path.resolve(process.cwd(), '.benchmarks', 'voice');
}

function loadReportList(directory: string): ReportListEntry[] {
  if (!fs.existsSync(directory)) return [];

  return fs
    .readdirSync(directory)
    .filter((name) => name.endsWith('.json'))
    .sort((a, b) => b.localeCompare(a)) // newest first
    .map((filename) => {
      const filePath = path.join(directory, filename);
      try {
        const raw = fs.readFileSync(filePath, 'utf8');
        const data = JSON.parse(raw) as BenchmarkReportFile;
        return {
          filename,
          path: filePath,
          provider: data.meta?.provider ?? 'unknown',
          profile: data.meta?.profile ?? 'unknown',
          pass: data.report?.pass ?? false,
          date: data.meta?.startedAt ?? filename,
        };
      } catch {
        return {
          filename,
          path: filePath,
          provider: 'unknown',
          profile: 'unknown',
          pass: false,
          date: filename,
        };
      }
    });
}

export function useReports() {
  const { state, dispatch } = useInspector();
  const dir = resolveBenchmarkDir();

  // Load report list on mount
  useEffect(() => {
    const reports = loadReportList(dir);
    dispatch({ type: 'REPORTS_LOADED', reports });
  }, [dir, dispatch]);

  // Load selected report detail
  useEffect(() => {
    const entry = state.reportFiles[state.selectedReportIndex];
    if (!entry) return;
    // Skip if already loaded
    if (state.selectedReport && state.selectedReport.meta?.provider === entry.provider) return;

    try {
      const raw = fs.readFileSync(entry.path, 'utf8');
      const detail = JSON.parse(raw) as BenchmarkReportFile;
      dispatch({ type: 'REPORT_DETAIL_LOADED', detail });
    } catch {
      dispatch({ type: 'ERROR', message: `Failed to load report: ${entry.filename}` });
    }
  }, [state.selectedReportIndex, state.reportFiles, dispatch]);

  const selectNext = useCallback(() => {
    const next = Math.min(state.selectedReportIndex + 1, state.reportFiles.length - 1);
    dispatch({ type: 'SELECT_REPORT', index: next });
  }, [state.selectedReportIndex, state.reportFiles.length, dispatch]);

  const selectPrev = useCallback(() => {
    const prev = Math.max(state.selectedReportIndex - 1, 0);
    dispatch({ type: 'SELECT_REPORT', index: prev });
  }, [state.selectedReportIndex, dispatch]);

  return {
    reports: state.reportFiles,
    selectedIndex: state.selectedReportIndex,
    selectedReport: state.selectedReport,
    benchmarkDir: dir,
    selectNext,
    selectPrev,
  };
}



/**
 * Hook for VoiceRuntime lifecycle and event wiring.
 *
 * Creates a VoiceRuntime via the factory, creates an EventMux for
 * fan-out (PackageBackedVoiceRuntime only supports one handler per event),
 * and dispatches state actions through the mux.
 */

import { useRef, useCallback, useEffect } from 'react';
import { randomUUID } from 'crypto';
import { createVoiceRuntime, type VoiceRuntime } from '../../../voice/index.js';
import { resolveVoiceRuntimeConfig } from '../../../voice/config.js';
import { profiles, loadProfilePrompts, type AgentProfile } from '../../../agent/profiles.js';
import type { VoiceProviderName } from '../../../voice/types.js';
import { useInspector } from '../state.js';
import { createEventMux, type EventMux } from '../util/event-mux.js';
import type { ResolvedConfigDisplay, LatencyStage } from '../types.js';

function getProfile(name: string): AgentProfile {
  const profile = profiles[name.toLowerCase()];
  if (!profile) {
    const available = Object.keys(profiles).join(', ');
    throw new Error(`Unknown profile "${name}". Available: ${available}`);
  }
  return profile;
}

function buildConfigDisplay(profile: AgentProfile, providerOverride?: string): ResolvedConfigDisplay {
  const config = resolveVoiceRuntimeConfig(profile);
  return {
    provider: (providerOverride ?? config.provider) as VoiceProviderName,
    mode: config.mode,
    model: config.model,
    voice: config.voice ?? profile.voice,
    language: config.language,
    sttProvider: config.mode === 'decomposed' ? config.decomposedSttProvider : undefined,
    sttModel: config.mode === 'decomposed' ? config.decomposedSttModel : undefined,
    llmProvider: config.mode === 'decomposed' ? config.decomposedLlmProvider : undefined,
    llmModel: config.mode === 'decomposed' ? config.decomposedLlmModel : undefined,
    ttsProvider: config.mode === 'decomposed' ? config.decomposedTtsProvider : undefined,
    ttsModel: config.mode === 'decomposed' ? config.decomposedTtsModel : undefined,
  };
}

export interface ConnectResult {
  runtime: VoiceRuntime;
  mux: EventMux;
}

export interface RuntimeHandle {
  connect: () => Promise;
  disconnect: () => void;
  sendMessage: (text: string) => void;
  interrupt: () => void;
}

export function useRuntime(profileName: string, providerOverride?: string): RuntimeHandle {
  const { dispatch } = useInspector();
  const runtimeRef = useRef(null);
  const profileRef = useRef(null);

  const connect = useCallback(async (): Promise => {
    // Disconnect previous if any
    if (runtimeRef.current?.isConnected()) {
      runtimeRef.current.disconnect();
    }

    // Load prompts if needed
    await loadProfilePrompts();

    const profile = getProfile(profileName);
    profileRef.current = profile;

    // Apply provider override via env (factory reads it)
    if (providerOverride) {
      process.env.VOICE_PROVIDER = providerOverride;
    }

    const sessionId = randomUUID();
    const configDisplay = buildConfigDisplay(profile, providerOverride);

    dispatch({
      type: 'CONNECT_START',
      provider: configDisplay.provider,
      voiceMode: configDisplay.mode,
      config: configDisplay,
    });

    const runtime = createVoiceRuntime(profile, sessionId);
    runtimeRef.current = runtime;

    // Create event mux — all hooks must use this instead of runtime.on()
    // because PackageBackedVoiceRuntime only supports one handler per event.
    const mux = createEventMux(runtime);

    // Wire state dispatch handlers via mux
    mux.on('connected', () => {
      dispatch({ type: 'CONNECTED' });
    });

    mux.on('disconnected', () => {
      dispatch({ type: 'DISCONNECTED' });
    });

    mux.on('stateChange', (state) => {
      dispatch({ type: 'STATE_CHANGE', state });
    });

    mux.on('transcript', (text, role, itemId, order) => {
      dispatch({ type: 'TRANSCRIPT', role, text, itemId, order });
    });

    mux.on('transcriptDelta', (delta, role, itemId, order) => {
      dispatch({ type: 'TRANSCRIPT_DELTA', role, delta, itemId, order });
    });

    mux.on('userItemCreated', (itemId, order) => {
      dispatch({ type: 'USER_ITEM_CREATED', itemId, order });
    });

    mux.on('assistantItemCreated', (itemId, previousItemId, order) => {
      dispatch({ type: 'ASSISTANT_ITEM_CREATED', itemId, previousItemId, order });
    });

    mux.on('latency', (metric) => {
      dispatch({
        type: 'LATENCY',
        stage: metric.stage as LatencyStage,
        durationMs: metric.durationMs,
      });
    });

    mux.on('toolStart', (name, args, callId) => {
      dispatch({ type: 'TOOL_START', name, args, callId });
    });

    mux.on('toolEnd', (name, result, callId) => {
      dispatch({ type: 'TOOL_END', name, result, callId });
    });

    mux.on('error', (error) => {
      dispatch({ type: 'ERROR', message: error.message });
    });

    // Connect
    try {
      await runtime.connect();
      return { runtime, mux };
    } catch (error) {
      dispatch({ type: 'ERROR', message: `Connection failed: ${(error as Error).message}` });
      dispatch({ type: 'DISCONNECTED' });
      return null;
    }
  }, [profileName, providerOverride, dispatch]);

  const disconnect = useCallback(() => {
    if (runtimeRef.current?.isConnected()) {
      runtimeRef.current.disconnect();
    }
    runtimeRef.current = null;
  }, []);

  const sendMessage = useCallback((text: string) => {
    runtimeRef.current?.sendMessage(text);
  }, []);

  const interrupt = useCallback(() => {
    runtimeRef.current?.interrupt();
  }, []);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (runtimeRef.current?.isConnected()) {
        runtimeRef.current.disconnect();
      }
    };
  }, []);

  return {
    connect,
    disconnect,
    sendMessage,
    interrupt,
  };
}



/**
 * Voice Runtime Inspector TUI — State management (reducer + context).
 */

import { createContext, useContext } from 'react';
import type {
  InspectorState,
  InspectorAction,
  LatencyStage,
  LatencyEntry,
  TranscriptEntry,
} from './types.js';

// ── Initial State ────────────────────────────────────────────

export function createInitialState(mode: 'live' | 'report', profileName: string): InspectorState {
  return {
    mode,
    connectionStatus: 'disconnected',
    provider: null,
    voiceMode: null,
    agentState: 'idle',
    profileName,
    sessionStartedAt: null,

    muted: false,
    audio: {
      chunkCount: 0,
      lastChunkAt: null,
      chunkGaps: [],
      interruptionCount: 0,
    },
    audioDevices: {
      inputDevices: ['default'],
      outputDevices: ['default'],
      inputDevice: 'default',
      outputDevice: 'default',
    },

    latency: new Map(),
    thinkingStartedAt: null,

    transcripts: [],
    activeTools: [],

    benchmarkReport: null,
    benchmarkOutputPath: null,

    config: null,

    reportFiles: [],
    selectedReportIndex: 0,
    selectedReport: null,

    errors: [],

    textInputActive: false,
    showBenchmarkResult: false,
  };
}

// ── Helpers ──────────────────────────────────────────────────

function updateLatency(
  map: Map,
  stage: LatencyStage,
  durationMs: number,
): Map {
  const next = new Map(map);
  const existing = next.get(stage);
  if (existing) {
    next.set(stage, {
      current: durationMs,
      samples: [...existing.samples, durationMs],
    });
  } else {
    next.set(stage, { current: durationMs, samples: [durationMs] });
  }
  return next;
}

function findTranscriptByItemId(
  transcripts: TranscriptEntry[],
  itemId: string,
  role?: 'user' | 'assistant',
): number {
  for (let i = transcripts.length - 1; i >= 0; i--) {
    const item = transcripts[i];
    if (!item || item.id !== itemId) continue;
    if (role && item.role !== role) continue;
    return i;
  }
  return -1;
}

function toOrderValue(order?: number): number | null {
  return typeof order === 'number' && Number.isFinite(order) ? order : null;
}

function findTranscriptInsertIndex(
  transcripts: TranscriptEntry[],
  order?: number,
  previousItemId?: string,
): number | undefined {
  const targetOrder = toOrderValue(order);

  if (previousItemId) {
    for (let idx = transcripts.length - 1; idx >= 0; idx--) {
      const item = transcripts[idx];
      if (!item || item.id !== previousItemId) continue;

      let insertIdx = idx + 1;
      if (targetOrder !== null) {
        while (insertIdx < transcripts.length) {
          const current = transcripts[insertIdx];
          if (!current) {
            insertIdx++;
            continue;
          }
          const currentOrder = toOrderValue(current.order);
          if (currentOrder === null) {
            insertIdx++;
            continue;
          }
          if (currentOrder >= targetOrder) break;
          insertIdx++;
        }
      }
      return insertIdx;
    }
  }

  if (targetOrder === null) return undefined;

  for (let idx = 0; idx < transcripts.length; idx++) {
    const item = transcripts[idx];
    if (!item) continue;
    const currentOrder = toOrderValue(item.order);
    if (currentOrder === null) continue;
    if (currentOrder > targetOrder) return idx;
  }

  return transcripts.length;
}

function insertTranscriptAt(
  transcripts: TranscriptEntry[],
  entry: TranscriptEntry,
  insertIndex?: number,
): TranscriptEntry[] {
  if (insertIndex === undefined || insertIndex < 0 || insertIndex >= transcripts.length) {
    return [...transcripts, entry];
  }
  return [
    ...transcripts.slice(0, insertIndex),
    entry,
    ...transcripts.slice(insertIndex),
  ];
}

function ensurePlaceholder(
  transcripts: TranscriptEntry[],
  role: 'user' | 'assistant',
  itemId: string,
  order?: number,
  previousItemId?: string,
): TranscriptEntry[] {
  const existingIdx = findTranscriptByItemId(transcripts, itemId, role);
  if (existingIdx >= 0) {
    if (order == null) return transcripts;
    const existing = transcripts[existingIdx];
    if (!existing || existing.order === order) return transcripts;
    return [
      ...transcripts.slice(0, existingIdx),
      { ...existing, order },
      ...transcripts.slice(existingIdx + 1),
    ];
  }

  const newEntry: TranscriptEntry = {
    id: itemId,
    role,
    text: '',
    isStreaming: true,
    timestamp: Date.now(),
    order,
  };
  const insertIndex = findTranscriptInsertIndex(transcripts, order, previousItemId);
  return insertTranscriptAt(transcripts, newEntry, insertIndex);
}

function updateTranscriptDelta(
  transcripts: TranscriptEntry[],
  role: 'user' | 'assistant',
  delta: string,
  itemId?: string,
  order?: number,
): TranscriptEntry[] {
  if (itemId) {
    const existingIdx = findTranscriptByItemId(transcripts, itemId, role);
    if (existingIdx >= 0) {
      const existing = transcripts[existingIdx];
      if (!existing) return transcripts;
      return [
        ...transcripts.slice(0, existingIdx),
        {
          ...existing,
          text: existing.text + delta,
          isStreaming: true,
          order: order ?? existing.order,
        },
        ...transcripts.slice(existingIdx + 1),
      ];
    }

    // Ignore scaffold-only deltas before a concrete item exists.
    if (delta.trim().length === 0) {
      return transcripts;
    }

    const created: TranscriptEntry = {
      id: itemId,
      role,
      text: delta,
      isStreaming: true,
      timestamp: Date.now(),
      order,
    };
    const insertIndex = findTranscriptInsertIndex(transcripts, order);
    return insertTranscriptAt(transcripts, created, insertIndex);
  }

  for (let i = transcripts.length - 1; i >= 0; i--) {
    const current = transcripts[i];
    if (!current || !current.isStreaming || current.role !== role) continue;
    return [
      ...transcripts.slice(0, i),
      {
        ...current,
        text: current.text + delta,
        isStreaming: true,
        order: order ?? current.order,
      },
      ...transcripts.slice(i + 1),
    ];
  }

  if (delta.trim().length === 0) {
    return transcripts;
  }

  return [
    ...transcripts,
    {
      id: `${role}-stream-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
      role,
      text: delta,
      isStreaming: true,
      timestamp: Date.now(),
      order,
    },
  ];
}

function finalizeTranscript(
  transcripts: TranscriptEntry[],
  role: 'user' | 'assistant',
  text: string,
  itemId?: string,
  order?: number,
): TranscriptEntry[] {
  if (itemId) {
    const existingIdx = findTranscriptByItemId(transcripts, itemId, role);
    if (existingIdx >= 0) {
      const current = transcripts[existingIdx];
      if (!current) return transcripts;
      return [
        ...transcripts.slice(0, existingIdx),
        {
          ...current,
          role,
          text,
          isStreaming: false,
          timestamp: current.timestamp,
          order: order ?? current.order,
        },
        ...transcripts.slice(existingIdx + 1),
      ];
    }

    const created: TranscriptEntry = {
      id: itemId,
      role,
      text,
      isStreaming: false,
      timestamp: Date.now(),
      order,
    };
    const insertIndex = findTranscriptInsertIndex(transcripts, order);
    return insertTranscriptAt(transcripts, created, insertIndex);
  }

  for (let i = transcripts.length - 1; i >= 0; i--) {
    const current = transcripts[i];
    if (!current || !current.isStreaming || current.role !== role) continue;
    return [
      ...transcripts.slice(0, i),
      {
        ...current,
        role,
        text,
        isStreaming: false,
        timestamp: current.timestamp,
        order: order ?? current.order,
      },
      ...transcripts.slice(i + 1),
    ];
  }

  return [
    ...transcripts,
    {
      id: itemId ?? `${role}-final-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
      role,
      text,
      isStreaming: false,
      timestamp: Date.now(),
      order,
    },
  ];
}

function finalizeStreamingRole(
  transcripts: TranscriptEntry[],
  role: 'user' | 'assistant',
): TranscriptEntry[] {
  let changed = false;
  const next = transcripts.map((entry) => {
    if (entry.role !== role || !entry.isStreaming) return entry;
    changed = true;
    return { ...entry, isStreaming: false };
  });
  return changed ? next : transcripts;
}

// ── Reducer ──────────────────────────────────────────────────

export function inspectorReducer(state: InspectorState, action: InspectorAction): InspectorState {
  switch (action.type) {
    // ── Connection ─────────────────────────────────────────
    case 'CONNECT_START':
      return {
        ...state,
        connectionStatus: 'connecting',
        provider: action.provider,
        voiceMode: action.voiceMode,
        config: action.config,
        sessionStartedAt: Date.now(),
        // Reset live state
        agentState: 'idle',
        latency: new Map(),
        thinkingStartedAt: null,
        transcripts: [],
        activeTools: [],
        audio: { chunkCount: 0, lastChunkAt: null, chunkGaps: [], interruptionCount: 0 },
        benchmarkReport: null,
        benchmarkOutputPath: null,
        showBenchmarkResult: false,
        errors: [],
      };

    case 'CONNECTED':
      return { ...state, connectionStatus: 'connected' };

    case 'DISCONNECTED':
      return { ...state, connectionStatus: 'disconnected', agentState: 'idle' };

    // ── Runtime Events ─────────────────────────────────────
    case 'STATE_CHANGE': {
      const next: Partial = { agentState: action.state };
      // Track thinking start for synthetic turn latency
      if (action.state === 'thinking') {
        next.thinkingStartedAt = Date.now();
      }
      // Synthetic turn latency: first audio after thinking
      if (action.state === 'speaking' && state.thinkingStartedAt) {
        const syntheticTurn = Date.now() - state.thinkingStartedAt;
        next.latency = updateLatency(state.latency, 'turn', syntheticTurn);
        next.thinkingStartedAt = null;
      }
      if (action.state !== 'speaking') {
        next.transcripts = finalizeStreamingRole(state.transcripts, 'assistant');
      }
      return { ...state, ...next };
    }

    case 'AUDIO_CHUNK': {
      const { lastChunkAt, chunkGaps } = state.audio;
      const gap = lastChunkAt ? action.timestamp - lastChunkAt : null;
      return {
        ...state,
        audio: {
          ...state.audio,
          chunkCount: state.audio.chunkCount + 1,
          lastChunkAt: action.timestamp,
          chunkGaps: gap !== null ? [...chunkGaps, gap] : chunkGaps,
        },
        // Clear synthetic turn latency — first audio received
        thinkingStartedAt: null,
      };
    }

    case 'AUDIO_INTERRUPTED':
      return {
        ...state,
        audio: {
          ...state.audio,
          interruptionCount: state.audio.interruptionCount + 1,
        },
      };

    case 'AUDIO_DEVICES_LOADED':
      return {
        ...state,
        audioDevices: {
          inputDevices: action.inputDevices.length > 0 ? action.inputDevices : ['default'],
          outputDevices: action.outputDevices.length > 0 ? action.outputDevices : ['default'],
          inputDevice: action.inputDevice || 'default',
          outputDevice: action.outputDevice || 'default',
        },
      };

    case 'AUDIO_INPUT_DEVICE_SET':
      return {
        ...state,
        audioDevices: {
          ...state.audioDevices,
          inputDevice: action.device,
        },
      };

    case 'AUDIO_OUTPUT_DEVICE_SET':
      return {
        ...state,
        audioDevices: {
          ...state.audioDevices,
          outputDevice: action.device,
        },
      };

    case 'LATENCY':
      return {
        ...state,
        latency: updateLatency(state.latency, action.stage, action.durationMs),
      };

    case 'USER_ITEM_CREATED':
      return {
        ...state,
        transcripts: ensurePlaceholder(state.transcripts, 'user', action.itemId, action.order),
      };

    case 'ASSISTANT_ITEM_CREATED':
      return {
        ...state,
        transcripts: ensurePlaceholder(
          state.transcripts,
          'assistant',
          action.itemId,
          action.order,
          action.previousItemId
        ),
      };

    case 'TRANSCRIPT':
      return {
        ...state,
        transcripts: finalizeTranscript(
          state.transcripts,
          action.role,
          action.text,
          action.itemId,
          action.order
        ),
      };

    case 'TRANSCRIPT_DELTA':
      return {
        ...state,
        transcripts: updateTranscriptDelta(
          state.transcripts,
          action.role,
          action.delta,
          action.itemId,
          action.order
        ),
      };

    case 'TOOL_START':
      return {
        ...state,
        activeTools: [
          ...state.activeTools,
          {
            name: action.name,
            args: action.args,
            callId: action.callId,
            startedAt: Date.now(),
          },
        ],
      };

    case 'TOOL_END': {
      const tools = state.activeTools.map((t) =>
        t.callId === action.callId || t.name === action.name
          ? { ...t, result: action.result, finishedAt: Date.now() }
          : t,
      );
      return { ...state, activeTools: tools };
    }

    case 'ERROR':
      return { ...state, errors: [...state.errors, action.message] };

    // ── Audio ──────────────────────────────────────────────
    case 'TOGGLE_MUTE':
      return { ...state, muted: !state.muted };

    // ── Benchmark ──────────────────────────────────────────
    case 'BENCHMARK_FINALIZED':
      return {
        ...state,
        benchmarkReport: action.report,
        benchmarkOutputPath: action.outputPath ?? null,
        showBenchmarkResult: true,
      };

    // ── UI ─────────────────────────────────────────────────
    case 'SET_TEXT_INPUT':
      return { ...state, textInputActive: action.active };

    case 'DISMISS_BENCHMARK':
      return { ...state, showBenchmarkResult: false };

    // ── Report Mode ────────────────────────────────────────
    case 'REPORTS_LOADED':
      return { ...state, reportFiles: action.reports, selectedReportIndex: 0, selectedReport: null };

    case 'SELECT_REPORT':
      return { ...state, selectedReportIndex: action.index, selectedReport: null };

    case 'REPORT_DETAIL_LOADED':
      return { ...state, selectedReport: action.detail };

    case 'FILTER_REPORTS':
      // Filtering is handled at the component level; this just resets selection
      return { ...state, selectedReportIndex: 0, selectedReport: null };

    default:
      return state;
  }
}

// ── Context ──────────────────────────────────────────────────

export interface InspectorContextValue {
  state: InspectorState;
  dispatch: React.Dispatch;
}

export const InspectorContext = createContext(null);

export function useInspector(): InspectorContextValue {
  const ctx = useContext(InspectorContext);
  if (!ctx) {
    throw new Error('useInspector must be used within InspectorContext.Provider');
  }
  return ctx;
}



/**
 * Voice Runtime Inspector TUI — Type definitions.
 */

import type { VoiceProviderName, VoiceMode, AgentState } from '../../voice/types.js';

// ── Latency ──────────────────────────────────────────────────

export type LatencyStage = 'stt' | 'llm' | 'tts' | 'turn' | 'tool' | 'connection';

export interface LatencyEntry {
  current: number;
  samples: number[];
}

// ── Transcripts ──────────────────────────────────────────────

export interface TranscriptEntry {
  id: string;
  role: 'user' | 'assistant';
  text: string;
  isStreaming: boolean;
  timestamp: number;
  order?: number;
}

// ── Tool Calls ───────────────────────────────────────────────

export interface ToolEntry {
  name: string;
  args: Record;
  callId?: string;
  result?: string;
  startedAt: number;
  finishedAt?: number;
}

// ── Audio Metrics ────────────────────────────────────────────

export interface AudioMetrics {
  chunkCount: number;
  lastChunkAt: number | null;
  chunkGaps: number[];
  interruptionCount: number;
}

export interface AudioDeviceState {
  inputDevices: string[];
  outputDevices: string[];
  inputDevice: string;
  outputDevice: string;
}

// ── Benchmark Report (from voice-runtime package) ────────────

export interface BenchmarkReportFile {
  meta: {
    sessionId: string;
    profile: string;
    provider: VoiceProviderName;
    startedAt: string;
    finishedAt: string;
    reason: string;
  };
  thresholds: Record;
  report: {
    pass: boolean;
    violations: string[];
    firstAudioLatencyMs?: number;
    chunkCadence: {
      medianGapMs: number;
      p95GapMs: number;
      maxGapMs: number;
      p95JitterMs: number;
    };
    realtimeFactor?: number;
    transcriptOrdering: {
      duplicateAssistantFinals: number;
      outOfOrderAssistantItems: number;
    };
    interruption: {
      count: number;
      medianMs: number;
      p95Ms: number;
      maxMs: number;
    };
  };
}

// ── Resolved Config (subset for display) ─────────────────────

export interface ResolvedConfigDisplay {
  provider: VoiceProviderName;
  mode: VoiceMode;
  model: string;
  voice: string;
  language: string;
  // Decomposed sub-providers (only if mode === 'decomposed')
  sttProvider?: string;
  sttModel?: string;
  llmProvider?: string;
  llmModel?: string;
  ttsProvider?: string;
  ttsModel?: string;
}

// ── Inspector State ──────────────────────────────────────────

export interface InspectorState {
  // Mode
  mode: 'live' | 'report';

  // Connection (live mode)
  connectionStatus: 'disconnected' | 'connecting' | 'connected';
  provider: VoiceProviderName | null;
  voiceMode: VoiceMode | null;
  agentState: AgentState;
  profileName: string;
  sessionStartedAt: number | null;

  // Audio
  muted: boolean;
  audio: AudioMetrics;
  audioDevices: AudioDeviceState;

  // Latency
  latency: Map;
  /** Timestamp when state changed to 'thinking' — for synthetic turn latency */
  thinkingStartedAt: number | null;

  // Transcripts
  transcripts: TranscriptEntry[];

  // Tools
  activeTools: ToolEntry[];

  // Benchmark
  benchmarkReport: BenchmarkReportFile['report'] | null;
  benchmarkOutputPath: string | null;

  // Config
  config: ResolvedConfigDisplay | null;

  // Report mode
  reportFiles: ReportListEntry[];
  selectedReportIndex: number;
  selectedReport: BenchmarkReportFile | null;

  // Errors
  errors: string[];

  // UI
  textInputActive: boolean;
  showBenchmarkResult: boolean;
}

// ── Report List ──────────────────────────────────────────────

export interface ReportListEntry {
  filename: string;
  path: string;
  provider: string;
  profile: string;
  pass: boolean;
  date: string;
}

// ── Actions ──────────────────────────────────────────────────

export type InspectorAction =
  // Connection lifecycle
  | { type: 'CONNECT_START'; provider: VoiceProviderName; voiceMode: VoiceMode; config: ResolvedConfigDisplay }
  | { type: 'CONNECTED' }
  | { type: 'DISCONNECTED' }

  // Runtime events
  | { type: 'STATE_CHANGE'; state: AgentState }
  | { type: 'AUDIO_CHUNK'; timestamp: number }
  | { type: 'AUDIO_INTERRUPTED' }
  | {
      type: 'AUDIO_DEVICES_LOADED';
      inputDevices: string[];
      outputDevices: string[];
      inputDevice: string;
      outputDevice: string;
    }
  | { type: 'AUDIO_INPUT_DEVICE_SET'; device: string }
  | { type: 'AUDIO_OUTPUT_DEVICE_SET'; device: string }
  | { type: 'LATENCY'; stage: LatencyStage; durationMs: number }
  | { type: 'USER_ITEM_CREATED'; itemId: string; order?: number }
  | { type: 'ASSISTANT_ITEM_CREATED'; itemId: string; previousItemId?: string; order?: number }
  | {
      type: 'TRANSCRIPT';
      role: 'user' | 'assistant';
      text: string;
      itemId?: string;
      order?: number;
    }
  | {
      type: 'TRANSCRIPT_DELTA';
      role: 'user' | 'assistant';
      delta: string;
      itemId?: string;
      order?: number;
    }
  | { type: 'TOOL_START'; name: string; args: Record; callId?: string }
  | { type: 'TOOL_END'; name: string; result: string; callId?: string }
  | { type: 'ERROR'; message: string }

  // Audio
  | { type: 'TOGGLE_MUTE' }

  // Benchmark
  | { type: 'BENCHMARK_FINALIZED'; report: BenchmarkReportFile['report']; outputPath?: string }

  // UI
  | { type: 'SET_TEXT_INPUT'; active: boolean }
  | { type: 'DISMISS_BENCHMARK' }

  // Report mode
  | { type: 'REPORTS_LOADED'; reports: ReportListEntry[] }
  | { type: 'SELECT_REPORT'; index: number }
  | { type: 'REPORT_DETAIL_LOADED'; detail: BenchmarkReportFile }
  | { type: 'FILTER_REPORTS'; provider?: string };

// ── CLI Args ─────────────────────────────────────────────────

export interface InspectorArgs {
  mode: 'live' | 'report';
  profile: string;
  provider?: string;
}



import type { AgentProfile } from '../agent/profiles.js';
import type { VoiceAgent } from '../agent/voice-agent.js';
import {
  createVoiceRuntime as createPackageVoiceRuntime,
  getBuiltInProviderRegistry,
  resolveRuntimeSessionInput,
  type ToolCallHandler as PackageToolCallHandler,
  type ToolDefinition as PackageToolDefinition,
} from '@voiceclaw/voice-runtime';
import type { FunctionTool } from '@openai/agents-core';
import { RunContext } from '@openai/agents-core';
import { resolveVoiceRuntimeConfig } from './config.js';
import { PackageBackedVoiceRuntime } from './package-backed-runtime.js';
import { getToolsForSession } from '../tools/index.js';
import type { VoiceRuntime } from './types.js';

function normalizeToolOutput(output: unknown): string {
  if (typeof output === 'string') return output;
  if (typeof output === 'number' || typeof output === 'boolean') {
    return String(output);
  }
  try {
    return JSON.stringify(output);
  } catch {
    return String(output);
  }
}

function buildTooling(
  profile: AgentProfile,
  sessionId: string,
  voiceAgent?: VoiceAgent
): {
  tools: PackageToolDefinition[];
  toolHandler: PackageToolCallHandler;
} {
  const functionTools = getToolsForSession(profile.tools, {
    sessionId,
    voiceAgent,
  }).filter((tool): tool is FunctionTool => tool.type === 'function');

  const toolMap = new Map(functionTools.map((tool) => [tool.name, tool]));

  return {
    tools: functionTools.map((tool) => ({
      name: tool.name,
      description: tool.description,
      parameters: (tool.parameters ?? {}) as Record,
    })),
    toolHandler: async (name, args, context) => {
      const tool = toolMap.get(name);
      if (!tool) {
        return {
          invocationId: context.invocationId,
          result: `Tool ${name} is not available in this profile.`,
          isError: true,
        };
      }

      const output = await tool.invoke(
        new RunContext({
          history: context.history as unknown as never[],
        }),
        JSON.stringify(args)
      );
      return {
        invocationId: context.invocationId,
        result: normalizeToolOutput(output),
      };
    },
  };
}

export function createVoiceRuntime(
  profile: AgentProfile,
  sessionId: string,
  voiceAgent?: VoiceAgent
): VoiceRuntime {
  const runtimeConfig = resolveVoiceRuntimeConfig(profile);
  console.log(
    `[VoiceRuntime] profile=${profile.name} mode=${runtimeConfig.mode} provider=${runtimeConfig.provider}` +
      ` stt=${runtimeConfig.decomposedSttProvider}/${runtimeConfig.decomposedSttModel}` +
      ` llm=${runtimeConfig.decomposedLlmProvider}/${runtimeConfig.decomposedLlmModel}` +
      ` tts=${runtimeConfig.decomposedTtsProvider}/${runtimeConfig.decomposedTtsModel}`
  );

  const { tools, toolHandler } = buildTooling(profile, sessionId, voiceAgent);
  const runtimeHost = createPackageVoiceRuntime(getBuiltInProviderRegistry());

  const sessionInput = resolveRuntimeSessionInput({
    instructions: profile.instructions,
    language: runtimeConfig.language,
    voice: runtimeConfig.voice,
    provider: runtimeConfig.provider,
    model: runtimeConfig.model,
    geminiModel: runtimeConfig.geminiModel,
    ultravoxModel: runtimeConfig.ultravoxModel,
    pipecatServerUrl: runtimeConfig.pipecatServerUrl,
    pipecatTransport: runtimeConfig.pipecatTransport,
    pipecatBotId: runtimeConfig.pipecatBotId,
    decomposedSttProvider: runtimeConfig.decomposedSttProvider,
    decomposedSttModel: runtimeConfig.decomposedSttModel,
    decomposedLlmProvider: runtimeConfig.decomposedLlmProvider,
    decomposedLlmModel: runtimeConfig.decomposedLlmModel,
    decomposedTtsProvider: runtimeConfig.decomposedTtsProvider,
    decomposedTtsModel: runtimeConfig.decomposedTtsModel,
    decomposedTtsVoice: runtimeConfig.decomposedTtsVoice,
    turn: runtimeConfig.turn,
    providerSettings: runtimeConfig.providerSettings,
    auth: runtimeConfig.auth,
    tools,
    toolHandler,
  });

  return new PackageBackedVoiceRuntime({
    mode: runtimeConfig.mode,
    provider: runtimeConfig.provider,
    inputSampleRateHz: 24000,
    sessionFactory: () => runtimeHost.createSession(sessionInput),
  });
}



import {
  resamplePcm16Mono,
  type AudioFrame,
  type ClientTransport,
  type ClientTransportKind,
  type ClientTransportStartConfig,
} from '@voiceclaw/voice-runtime';
import { AUDIO_CONFIG, type IAudioTransport } from '../transport/types.js';

export class LegacyAudioTransportBridge implements ClientTransport {
  readonly kind: ClientTransportKind;

  private readonly transport: IAudioTransport;
  private readonly frameHandlers = new Set<(frame: AudioFrame) => void>();
  private inputRateHz: number = AUDIO_CONFIG.API_SAMPLE_RATE;
  private audioListener: ((chunk: ArrayBuffer) => void) | null = null;
  private playedMs = 0;
  private pendingMs = 0;
  private lastClockMs = Date.now();

  constructor(transport: IAudioTransport, kind?: ClientTransportKind) {
    this.transport = transport;
    this.kind = kind ?? inferTransportKind(transport);
  }

  async start(config: ClientTransportStartConfig): Promise {
    this.inputRateHz = config.inputRate;
    this.resetPlaybackClock();

    if (this.audioListener) {
      this.transport.off('audio', this.audioListener);
      this.audioListener = null;
    }

    this.audioListener = (chunk: ArrayBuffer) => {
      const frame: AudioFrame = {
        data: chunk,
        sampleRate: this.inputRateHz,
        format: 'pcm16',
      };
      for (const handler of this.frameHandlers) {
        handler(frame);
      }
    };

    this.transport.on('audio', this.audioListener);
    if (!this.transport.isActive()) {
      this.transport.start();
    }
  }

  async stop(): Promise {
    if (this.audioListener) {
      this.transport.off('audio', this.audioListener);
      this.audioListener = null;
    }
    if (this.transport.isActive()) {
      this.transport.stop();
    }
    this.resetPlaybackClock();
  }

  onAudioFrame(handler: (frame: AudioFrame) => void): void {
    this.frameHandlers.add(handler);
  }

  offAudioFrame(handler: (frame: AudioFrame) => void): void {
    this.frameHandlers.delete(handler);
  }

  playAudioFrame(frame: AudioFrame): void {
    this.advancePlaybackClock();
    const playbackFrame =
      frame.sampleRate === AUDIO_CONFIG.API_SAMPLE_RATE
        ? frame
        : resamplePcm16Mono(frame, AUDIO_CONFIG.API_SAMPLE_RATE);
    this.pendingMs += frameDurationMs(playbackFrame);
    this.transport.play(playbackFrame.data);
  }

  interruptPlayback(): void {
    this.advancePlaybackClock();
    this.pendingMs = 0;
    this.transport.interrupt();
  }

  getPlaybackPositionMs(): number {
    this.advancePlaybackClock();
    return this.playedMs;
  }

  private resetPlaybackClock(): void {
    this.playedMs = 0;
    this.pendingMs = 0;
    this.lastClockMs = Date.now();
  }

  private advancePlaybackClock(): void {
    const now = Date.now();
    const elapsedMs = Math.max(0, now - this.lastClockMs);
    const clampedElapsedMs = Math.min(elapsedMs, 500);
    const consumedMs = Math.min(clampedElapsedMs, this.pendingMs);
    this.pendingMs -= consumedMs;
    this.playedMs += consumedMs;
    this.lastClockMs = now;
  }
}

function frameDurationMs(frame: AudioFrame): number {
  if (frame.sampleRate <= 0) return 0;
  return (frame.data.byteLength / 2 / frame.sampleRate) * 1000;
}

function inferTransportKind(transport: IAudioTransport): ClientTransportKind {
  const name = transport.constructor.name.toLowerCase();
  if (name.includes('websocket')) return 'ws-pcm';
  return 'local-pcm';
}



import { config, validateConfig } from './config.js';
import { VoiceAgent } from './agent/voice-agent.js';
import { WakewordDetector } from './wakeword/index.js';
import { speak } from './audio/index.js';
import { closeDatabase } from './db/index.js';
import { Scheduler } from './scheduler/index.js';
import { startWebhookServer, stopWebhookServer, onWebhookEvent } from './api/webhooks.js';
import {
  startWebSocketServer,
  stopWebSocketServer,
  wsBroadcast,
  onBinaryMessage,
  getClients,
  onClientCommand,
  onSessionInput,
  setServiceState,
} from './api/websocket.js';
import { handleDirectInput } from './subagents/direct-input.js';
import { startStaticServer, stopStaticServer } from './api/static.js';
import { LocalTransport, WebSocketTransport } from './transport/index.js';
import { getProcessManager, type ManagedProcess } from './processes/manager.js';
import { CliSessionsRepository } from './db/index.js';

// ═══════════════════════════════════════════════════════════════════════════
// Service State Machine
// ═══════════════════════════════════════════════════════════════════════════
//
// States:
// - DORMANT: Service is off. No audio capture, no wakeword, no agent sessions.
// - RUNNING: Service is active. Audio/wakeword based on audioMode.
//
// Audio Modes:
// - 'web': Browser handles audio I/O via WebSocket
// - 'local': Device handles audio via hardware (PipeWire/sox)
//

let isServiceActive = false;
let audioMode: 'web' | 'local' = 'web';

// Components initialized at startup
let agent: VoiceAgent;
let wakeword: WakewordDetector | null = null;
let scheduler: Scheduler;
let localTransport: LocalTransport;
let wsTransport: WebSocketTransport;
const SHUTDOWN_TIMEOUT_MS = parseInt(process.env.SHUTDOWN_TIMEOUT_MS ?? '8000', 10);
let lastLocalRoutingDiagnosticsKey = '';

function logLocalRoutingDiagnostics(): void {
  const diagnostics = localTransport.getRoutingDiagnostics();
  const key = [
    diagnostics.inputDevice,
    diagnostics.outputDevice,
    diagnostics.echoCancelSourceSelected ? 'echo' : 'raw',
    diagnostics.samePhysicalDeviceLikely ? 'shared' : 'separate',
  ].join('|');

  if (key === lastLocalRoutingDiagnosticsKey) {
    return;
  }
  lastLocalRoutingDiagnosticsKey = key;

  console.log(
    `[LocalAudio] Routing input=${diagnostics.inputDevice} output=${diagnostics.outputDevice} echoCancel=${diagnostics.echoCancelSourceSelected ? 'on' : 'off'}`
  );

  if (
    process.platform === 'linux' &&
    !diagnostics.echoCancelSourceSelected &&
    diagnostics.samePhysicalDeviceLikely
  ) {
    console.warn(
      '[LocalAudio] Echo-risk routing detected: input/output appear to be the same device and no echo-cancel source is selected. Configure PipeWire echo-cancel or set LOCAL_AUDIO_INPUT_DEVICE / LOCAL_PREFER_ECHO_CANCEL_SOURCE.'
    );
  }
}

/**
 * Update service state and coordinate all components.
 * This is the central state machine that controls wakeword, transport, and agent.
 */
async function updateServiceState(): Promise {
  console.log(`[Service] State update: active=${isServiceActive}, mode=${audioMode}`);

  if (!isServiceActive) {
    // === DORMANT STATE ===
    // Stop everything

    // Stop wakeword detection
    if (wakeword?.isListening()) {
      wakeword.stop();
      console.log('[Service] Wakeword stopped (dormant)');
    }

    // Deactivate agent if active
    if (agent.isActive()) {
      agent.deactivate();
      console.log('[Service] Agent deactivated (dormant)');
    }

    // Stop both transports
    localTransport.stop();
    wsTransport.stop();

  } else {
    // === RUNNING STATE ===
    // Activate based on audio mode

    // Select and configure transport based on mode
    const selectedTransport = audioMode === 'local' ? localTransport : wsTransport;
    agent.setTransport(selectedTransport);
    console.log(`[Service] Transport set to ${audioMode}`);

    if (audioMode === 'local') {
      // LOCAL MODE: Use wakeword detection when agent is idle
      wsTransport.stop(); // Ensure web transport is stopped
      logLocalRoutingDiagnostics();

      if (!agent.isActive() && wakeword && !wakeword.isListening()) {
        try {
          await wakeword.start();
          console.log('[Service] Wakeword started (local mode)');
        } catch (err) {
          console.error('[Service] Failed to start wakeword:', err);
        }
      }
    } else {
      // WEB MODE: Stop wakeword, browser handles activation
      if (wakeword?.isListening()) {
        wakeword.stop();
        console.log('[Service] Wakeword stopped (web mode)');
      }
      localTransport.stop(); // Ensure local transport is stopped
    }
  }

  // Broadcast state to all connected clients
  setServiceState(isServiceActive, audioMode);
}

async function main() {
  console.log('Starting Pi Voice Agent (TypeScript)...');

  // Validate configuration
  try {
    validateConfig();
  } catch (error) {
    console.error('Configuration error:', error);
    process.exit(1);
  }

  // Start WebSocket server first (needed for dashboard)
  try {
    await startWebSocketServer();
    console.log('WebSocket server started');
  } catch (error) {
    console.error('Failed to start WebSocket server:', error);
    process.exit(1);
  }

  // Initialize both transports (but don't start them yet)
  localTransport = new LocalTransport({
    inputDevice: config.localAudio.inputDevice,
    outputDevice: config.localAudio.outputDevice,
    preferEchoCancelSource: config.localAudio.preferEchoCancelSource,
  });
  wsTransport = new WebSocketTransport(getClients());

  // Wire up binary message handler to route browser audio to WebSocket transport
  onBinaryMessage((data) => {
    wsTransport.handleClientAudio(data);
  });

  console.log('[Transport] Initialized LocalTransport and WebSocketTransport');

  // Initialize agent WITHOUT a transport (will be set via updateServiceState)
  agent = new VoiceAgent();

  // Initialize ProcessManager for background task tracking
  const processManager = getProcessManager();

  processManager.on('process:completed', (process: ManagedProcess) => {
    console.log(`[ProcessManager] Process "${process.name}" completed`);

    const sessionsRepo = new CliSessionsRepository();
    const session = sessionsRepo.findById(process.sessionId);
    if (!session) {
      // Detached process without DB session linkage (e.g. developer_session fire-and-forget).
      return;
    }
    const voiceSessionId = session.type === 'voice' ? session.id : session.parent_id ?? session.id;

    wsBroadcast.streamChunk(voiceSessionId, {
      type: 'process-status',
      processName: process.name,
      sessionId: process.sessionId,
      status: 'completed',
      summary: process.result?.substring(0, 200),
    });

    if (!process.notifyVoiceOnCompletion) {
      return;
    }

    // Notify voice agent or queue for next session
    if (agent.isActive()) {
      agent.sendMessage(
        `[Background task "${process.name}" completed] ${process.result?.substring(0, 500) || 'Task finished.'}`
      );
    } else {
      agent.addPendingNotification(process);
    }
  });

  processManager.on('process:error', (process: ManagedProcess) => {
    console.error(`[ProcessManager] Process "${process.name}" failed: ${process.error}`);

    const sessionsRepo = new CliSessionsRepository();
    const session = sessionsRepo.findById(process.sessionId);
    if (!session) {
      // Detached process without DB session linkage (e.g. developer_session fire-and-forget).
      return;
    }
    const voiceSessionId = session.type === 'voice' ? session.id : session.parent_id ?? session.id;

    wsBroadcast.streamChunk(voiceSessionId, {
      type: 'process-status',
      processName: process.name,
      sessionId: process.sessionId,
      status: 'error',
      summary: process.error,
    });

    if (!process.notifyVoiceOnCompletion) {
      return;
    }

    if (agent.isActive()) {
      agent.sendMessage(
        `[Background task "${process.name}" failed] ${process.error || 'Unknown error'}`
      );
    } else {
      agent.addPendingNotification(process);
    }
  });

  // Initialize wakeword detector (but don't start yet)
  try {
    wakeword = new WakewordDetector(['jarvis', 'computer']);
    console.log('[Wakeword] Detector initialized');
  } catch (error) {
    console.warn('[Wakeword] Failed to initialize (may not be available on this platform):', error);
    wakeword = null;
  }

  // Initialize scheduler
  scheduler = new Scheduler(1000);

  // Set up scheduler event handlers
  scheduler.on('timerFired', async (timer) => {
    console.log(`[Timer] Fired #${timer.id}: ${timer.message}`);

    if (agent.isActive()) {
      agent.sendMessage(`[TIMER ERINNERUNG] Sag dem Nutzer: "${timer.message}"`);
    } else {
      if (timer.mode === 'tts') {
        try {
          await speak(timer.message);
        } catch (error) {
          console.error('[Timer] TTS error:', error);
        }
      } else if (timer.mode === 'agent') {
        const success = await agent.activate('jarvis');
        if (success) {
          setTimeout(() => {
            agent.sendMessage(`[TIMER ERINNERUNG] Sag dem Nutzer: "${timer.message}"`);
          }, 500);
        }
      }
    }
  });

  scheduler.on('error', (error) => {
    console.error('[Scheduler] Error:', error);
  });

  // Set up agent event handlers
  agent.on('stateChange', async (state, profile) => {
    console.log(`[State] ${state}${profile ? ` (${profile})` : ''}`);
    wsBroadcast.stateChange(state, profile);

    // Resume wakeword detection when idle (only in local mode with service active)
    if (state === 'idle' && isServiceActive && audioMode === 'local') {
      if (wakeword && !wakeword.isListening()) {
        try {
          await wakeword.start();
          console.log('[Service] Wakeword resumed after idle');
        } catch (err) {
          console.error('[Wakeword] Failed to restart:', err);
        }
      }
    }

    // Stop wakeword during active agent states
    if ((state === 'listening' || state === 'thinking' || state === 'speaking') && wakeword?.isListening()) {
      wakeword.stop();
    }
  });

  agent.on('error', (error) => {
    console.error('[Error]', error.message);
  });

  // Set up wakeword detection handlers (if available)
  if (wakeword) {
    wakeword.onWakeword(async (keyword, confidence) => {
      console.log(`[Wakeword] Detected: ${keyword} (confidence: ${confidence})`);

      if (!agent.isActive()) {
        wakeword!.stop();

        const success = await agent.activateWithWakeword(keyword);
        if (success) {
          console.log('[Agent] Session activated, listening...');
        } else {
          // Restart wakeword if activation failed and service is still active
          if (isServiceActive && audioMode === 'local') {
            wakeword!.start().catch((err) => {
              console.error('[Wakeword] Failed to restart:', err);
            });
          }
        }
      } else {
        console.log('[Agent] Already active, ignoring wakeword');
      }
    });
  }

  // Register client command handler
  onClientCommand(async (command) => {
    console.log(`[WS] Client command: ${command.command}`, command.profile ? `(profile: ${command.profile})` : '', command.mode ? `(mode: ${command.mode})` : '');

    switch (command.command) {
      case 'start_service': {
        if (!isServiceActive) {
          isServiceActive = true;
          await updateServiceState();
          console.log('[Service] Started');
        }
        break;
      }

      case 'stop_service': {
        if (isServiceActive) {
          isServiceActive = false;
          await updateServiceState();
          console.log('[Service] Stopped');
        }
        break;
      }

      case 'set_audio_mode': {
        const newMode = command.mode;
        if (newMode && (newMode === 'web' || newMode === 'local') && newMode !== audioMode) {
          audioMode = newMode;
          await updateServiceState();
          console.log(`[Service] Audio mode changed to ${audioMode}`);
        }
        break;
      }

      case 'start_session': {
        if (!isServiceActive) {
          console.log('[WS] Cannot start session - service is dormant');
          wsBroadcast.error('Service is not active');
          return;
        }

        if (agent.isActive()) {
          console.log('[WS] Session already active, ignoring start_session');
          return;
        }

        // Stop wakeword detection if active (local mode)
        if (wakeword?.isListening()) {
          wakeword.stop();
        }

        const profile = command.profile || 'jarvis';
        const success = await agent.activate(profile);
        if (success) {
          console.log(`[WS] Session activated for ${profile}`);
          wsBroadcast.sessionStarted(profile);
        } else {
          console.error('[WS] Failed to activate session');
          wsBroadcast.error('Failed to activate session');
          // Restart wakeword if in local mode and service is active
          if (isServiceActive && audioMode === 'local' && wakeword) {
            wakeword.start().catch((err) => {
              console.error('[Wakeword] Failed to restart:', err);
            });
          }
        }
        break;
      }

      case 'stop_session': {
        if (agent.isActive()) {
          const profile = agent.getCurrentProfile()?.name || null;
          agent.deactivate();
          console.log('[WS] Session stopped');
          wsBroadcast.sessionEnded(profile);
        }
        break;
      }
    }
  });

  // Register session input handler for direct text input to subagents
  onSessionInput(handleDirectInput);

  // Start the timer scheduler
  scheduler.start();
  console.log('Timer scheduler started');

  // Start static file server for web dashboard (skip in dev when using Vite)
  if (process.env.SKIP_STATIC_SERVER !== 'true') {
    try {
      await startStaticServer();
      console.log('Static dashboard server started');
    } catch (error) {
      console.warn('Failed to start static server:', error);
    }
  } else {
    console.log('[Static] Skipped (SKIP_STATIC_SERVER=true, use Vite dev server instead)');
  }

  let shutdownPromise: Promise | null = null;
  const shutdown = async (signal: NodeJS.Signals | 'startup_failure'): Promise => {
    if (shutdownPromise) {
      return shutdownPromise;
    }

    shutdownPromise = (async () => {
      console.log(`\nShutting down... (${signal})`);

      const forceExitTimer = setTimeout(() => {
        console.error(`[Shutdown] Timed out after ${SHUTDOWN_TIMEOUT_MS}ms, forcing exit`);
        process.exit(1);
      }, SHUTDOWN_TIMEOUT_MS);
      forceExitTimer.unref?.();

      try {
        scheduler.stop();
      } catch (error) {
        console.warn('[Shutdown] Failed to stop scheduler:', error);
      }

      await Promise.allSettled([
        stopStaticServer(),
        stopWebSocketServer(),
        stopWebhookServer(),
      ]);

      try {
        agent.deactivate();
      } catch (error) {
        console.warn('[Shutdown] Failed to deactivate agent:', error);
      }

      if (wakeword) {
        try {
          wakeword.stop();
        } catch (error) {
          console.warn('[Shutdown] Failed to stop wakeword:', error);
        }
      }

      closeDatabase();
      clearTimeout(forceExitTimer);
      process.exit(signal === 'startup_failure' ? 1 : 0);
    })();

    return shutdownPromise;
  };

  // Start webhook server for Mac daemon callbacks
  try {
    await startWebhookServer();

    onWebhookEvent(async (payload) => {
      console.log(`[Webhook] Session ${payload.sessionId} status: ${payload.status}`);

      if (payload.status === 'finished' || payload.status === 'error') {
        const statusText =
          payload.status === 'finished'
            ? 'Die Coding-Session ist fertig.'
            : 'Die Coding-Session hat einen Fehler.';

        if (agent.isActive()) {
          agent.sendMessage(`[SESSION UPDATE] ${statusText}`);
        } else {
          await speak(statusText);
        }
      }
    });
  } catch (error) {
    console.error('Failed to start webhook server:', error);
    await shutdown('startup_failure');
    return;
  }

  process.on('SIGINT', () => {
    if (shutdownPromise) {
      console.log('[Shutdown] SIGINT received while shutdown is already in progress');
      return;
    }
    void shutdown('SIGINT');
  });
  process.on('SIGTERM', () => {
    if (shutdownPromise) {
      console.log('[Shutdown] SIGTERM received while shutdown is already in progress');
      return;
    }
    void shutdown('SIGTERM');
  });

  // Broadcast initial service state (dormant by default)
  setServiceState(isServiceActive, audioMode);

  console.log('Agent ready. Service is DORMANT - use dashboard to activate.');
  console.log('Connect a browser client and click the power button to start...');
}

main().catch((error) => {
  console.error('Fatal error:', error);
  process.exit(1);
});



/**
 * Convert a real recorded voice session (.voiceclaw/.sessions/*.jsonl) into a provider-contract fixture.
 *
 * Usage:
 * - bun run src/scratch-contract-fixture.ts 
 * - bun run src/scratch-contract-fixture.ts  
 * - bun run src/scratch-contract-fixture.ts  --case-id=
 * - bun run src/scratch-contract-fixture.ts .voiceclaw/.sessions/.jsonl --case-id=live_multiturn_ultravox
 */

import fs from 'fs';
import path from 'path';

type VoiceState = 'idle' | 'listening' | 'thinking' | 'speaking';

interface SessionLogEntry {
  type?: string;
  timestamp?: string;
  [key: string]: unknown;
}

type ReplayFixtureEvent =
  | {
      atMs: number;
      type: 'state';
      state: VoiceState;
    }
  | {
      atMs: number;
      type: 'turn_started' | 'turn_complete' | 'audio_interrupted';
    }
  | {
      atMs: number;
      type: 'assistant_item' | 'user_item';
      itemId: string;
      previousItemId?: string;
    }
  | {
      atMs: number;
      type: 'transcript_delta' | 'transcript_final';
      role: 'user' | 'assistant';
      text: string;
      itemId?: string;
    }
  | {
      atMs: number;
      type: 'tool_start';
      name: string;
      callId: string;
      args?: Record;
    }
  | {
      atMs: number;
      type: 'tool_end';
      name: string;
      callId: string;
      result: string;
    };

interface ParsedArgs {
  input: string;
  outPath?: string;
  caseId?: string;
}

const VALID_STATES = new Set(['idle', 'listening', 'thinking', 'speaking']);

function parseArgs(argv: string[]): ParsedArgs {
  const positional: string[] = [];
  let caseId: string | undefined;

  for (const arg of argv) {
    if (arg.startsWith('--case-id=')) {
      caseId = arg.slice('--case-id='.length).trim() || undefined;
      continue;
    }
    positional.push(arg);
  }

  const input = positional[0]?.trim();
  if (!input) {
    throw new Error(
      'Missing input. Usage: bun run src/scratch-contract-fixture.ts  [output-file] [--case-id=]'
    );
  }

  const outPath = positional[1]?.trim() || undefined;
  return { input, outPath, caseId };
}

function resolveRepoRoot(): string {
  const cwd = process.cwd();
  return path.basename(cwd) === 'voice-agent' ? path.resolve(cwd, '..', '..') : cwd;
}

function parseJsonl(filePath: string): SessionLogEntry[] {
  const raw = fs.readFileSync(filePath, 'utf8');
  return raw
    .split('\n')
    .map((line) => line.trim())
    .filter((line) => line.length > 0)
    .map((line, index) => {
      try {
        return JSON.parse(line) as SessionLogEntry;
      } catch (error) {
        throw new Error(`Invalid JSON at ${filePath}:${index + 1}: ${(error as Error).message}`);
      }
    });
}

function findSessionLogById(sessionId: string, sessionsDir: string): string {
  if (!fs.existsSync(sessionsDir)) {
    throw new Error(`Sessions directory not found: ${sessionsDir}`);
  }

  const candidates = fs
    .readdirSync(sessionsDir)
    .filter((name) => name.endsWith('.jsonl'))
    .map((name) => path.join(sessionsDir, name));

  for (const filePath of candidates) {
    const lines = fs
      .readFileSync(filePath, 'utf8')
      .split('\n')
      .map((line) => line.trim())
      .filter((line) => line.length > 0);
    if (lines.length === 0) continue;

    let first: SessionLogEntry;
    try {
      first = JSON.parse(lines[0] ?? '{}') as SessionLogEntry;
    } catch {
      continue;
    }

    if (first.type === 'session' && first.id === sessionId) {
      return filePath;
    }
  }

  const shortPrefix = sessionId.slice(0, 12);
  const byPrefix = candidates.find((filePath) =>
    path.basename(filePath).startsWith(shortPrefix)
  );
  if (byPrefix) {
    return byPrefix;
  }

  throw new Error(`Could not find .voiceclaw/.sessions log for session id: ${sessionId}`);
}

function resolveInputLogPath(input: string, repoRoot: string): string {
  const direct = path.resolve(process.cwd(), input);
  if (fs.existsSync(direct)) return direct;

  const sessionsDir = path.join(repoRoot, '.voiceclaw', '.sessions');
  return findSessionLogById(input, sessionsDir);
}

function toAtMs(isoTimestamp: string, baseMs: number): number {
  const parsed = Date.parse(isoTimestamp);
  if (!Number.isFinite(parsed)) return 0;
  return Math.max(0, parsed - baseMs);
}

function isRecord(value: unknown): value is Record {
  return !!value && typeof value === 'object' && !Array.isArray(value);
}

function toResultText(value: unknown): string {
  if (typeof value === 'string') return value;
  try {
    return JSON.stringify(value);
  } catch {
    return String(value);
  }
}

function buildFixture(entries: SessionLogEntry[]): ReplayFixtureEvent[] {
  const timedEntries = entries.filter(
    (entry) => typeof entry.timestamp === 'string' && entry.type !== 'session'
  );
  if (timedEntries.length === 0) {
    throw new Error('No timestamped stream events found in session log');
  }

  const baseMs = Date.parse((timedEntries[0]?.timestamp as string) ?? '');
  if (!Number.isFinite(baseMs)) {
    throw new Error('Unable to parse first event timestamp');
  }

  const fixture: ReplayFixtureEvent[] = [];
  const assistantOrder: string[] = [];
  const assistantTextByItem = new Map();
  const finalizedAssistantItems = new Set();

  const ensureAssistantItem = (itemId: string): void => {
    if (!assistantTextByItem.has(itemId)) {
      assistantTextByItem.set(itemId, '');
      assistantOrder.push(itemId);
    }
  };

  const appendAssistantText = (itemId: string, delta: string): void => {
    ensureAssistantItem(itemId);
    assistantTextByItem.set(itemId, (assistantTextByItem.get(itemId) ?? '') + delta);
  };

  const emitPendingAssistantFinals = (atMs: number): void => {
    for (const itemId of assistantOrder) {
      if (finalizedAssistantItems.has(itemId)) continue;
      const text = (assistantTextByItem.get(itemId) ?? '').trim();
      if (!text) continue;
      fixture.push({
        atMs,
        type: 'transcript_final',
        role: 'assistant',
        text,
        itemId,
      });
      finalizedAssistantItems.add(itemId);
    }
  };

  for (const entry of timedEntries) {
    const eventType = typeof entry.type === 'string' ? entry.type : '';
    const timestamp = entry.timestamp as string;
    const atMs = toAtMs(timestamp, baseMs);

    switch (eventType) {
      case 'state-change': {
        const state = entry.state;
        if (typeof state === 'string' && VALID_STATES.has(state as VoiceState)) {
          fixture.push({
            atMs,
            type: 'state',
            state: state as VoiceState,
          });
        }
        break;
      }
      case 'start-step': {
        fixture.push({ atMs, type: 'turn_started' });
        break;
      }
      case 'finish': {
        emitPendingAssistantFinals(atMs);
        fixture.push({ atMs, type: 'turn_complete' });
        break;
      }
      case 'audio_interrupted': {
        fixture.push({ atMs, type: 'audio_interrupted' });
        break;
      }
      case 'assistant-placeholder': {
        const itemId = typeof entry.itemId === 'string' ? entry.itemId : undefined;
        if (!itemId) break;
        const previousItemId =
          typeof entry.previousItemId === 'string' ? entry.previousItemId : undefined;
        ensureAssistantItem(itemId);
        fixture.push({
          atMs,
          type: 'assistant_item',
          itemId,
          ...(previousItemId ? { previousItemId } : {}),
        });
        break;
      }
      case 'user-placeholder': {
        const itemId = typeof entry.itemId === 'string' ? entry.itemId : undefined;
        if (!itemId) break;
        const previousItemId =
          typeof entry.previousItemId === 'string' ? entry.previousItemId : undefined;
        fixture.push({
          atMs,
          type: 'user_item',
          itemId,
          ...(previousItemId ? { previousItemId } : {}),
        });
        break;
      }
      case 'text-delta': {
        const text = typeof entry.textDelta === 'string' ? entry.textDelta : '';
        const itemId = typeof entry.itemId === 'string' ? entry.itemId : undefined;
        const role = entry.role === 'user' ? 'user' : 'assistant';
        fixture.push({
          atMs,
          type: 'transcript_delta',
          role,
          text,
          ...(itemId ? { itemId } : {}),
        });
        if (role === 'assistant' && itemId) {
          appendAssistantText(itemId, text);
        }
        break;
      }
      case 'user-transcript': {
        const text = typeof entry.text === 'string' ? entry.text : '';
        const itemId = typeof entry.itemId === 'string' ? entry.itemId : undefined;
        fixture.push({
          atMs,
          type: 'transcript_final',
          role: 'user',
          text,
          ...(itemId ? { itemId } : {}),
        });
        break;
      }
      case 'transcript': {
        const text = typeof entry.text === 'string' ? entry.text : '';
        const role = entry.role === 'user' ? 'user' : 'assistant';
        const itemId = typeof entry.itemId === 'string' ? entry.itemId : undefined;
        fixture.push({
          atMs,
          type: 'transcript_final',
          role,
          text,
          ...(itemId ? { itemId } : {}),
        });
        if (role === 'assistant' && itemId) {
          ensureAssistantItem(itemId);
          assistantTextByItem.set(itemId, text);
          finalizedAssistantItems.add(itemId);
        }
        break;
      }
      case 'tool-call': {
        const name = typeof entry.toolName === 'string' ? entry.toolName : 'tool';
        const callId = typeof entry.toolCallId === 'string' ? entry.toolCallId : `tool-${atMs}`;
        const args = isRecord(entry.input) ? entry.input : undefined;
        fixture.push({
          atMs,
          type: 'tool_start',
          name,
          callId,
          ...(args ? { args } : {}),
        });
        break;
      }
      case 'tool-result': {
        const name = typeof entry.toolName === 'string' ? entry.toolName : 'tool';
        const callId = typeof entry.toolCallId === 'string' ? entry.toolCallId : `tool-${atMs}`;
        const result = toResultText(entry.output);
        fixture.push({
          atMs,
          type: 'tool_end',
          name,
          callId,
          result,
        });
        break;
      }
      default:
        break;
    }
  }

  if (fixture.length === 0) {
    throw new Error('No fixture events could be generated from session log');
  }

  // Ensure no assistant text is dropped if the session ended without a finish event.
  const lastAtMs = fixture[fixture.length - 1]?.atMs ?? 0;
  emitPendingAssistantFinals(lastAtMs);

  return fixture.sort((a, b) => a.atMs - b.atMs);
}

function defaultOutputPath(repoRoot: string, inputLogPath: string): string {
  const baseName = path.basename(inputLogPath, '.jsonl');
  return path.join(
    repoRoot,
    'packages',
    'voice-runtime',
    'tests',
    'contracts',
    'fixtures',
    `${baseName}-live-multiturn.jsonl`
  );
}

function summarizeFixture(events: ReplayFixtureEvent[]): {
  turnStarted: number;
  turnComplete: number;
  toolStarts: number;
  toolEnds: number;
  assistantFinals: string[];
} {
  const assistantFinals: string[] = [];
  let turnStarted = 0;
  let turnComplete = 0;
  let toolStarts = 0;
  let toolEnds = 0;

  for (const event of events) {
    if (event.type === 'turn_started') turnStarted += 1;
    if (event.type === 'turn_complete') turnComplete += 1;
    if (event.type === 'tool_start') toolStarts += 1;
    if (event.type === 'tool_end') toolEnds += 1;
    if (event.type === 'transcript_final' && event.role === 'assistant') {
      assistantFinals.push(event.text);
    }
  }

  return { turnStarted, turnComplete, toolStarts, toolEnds, assistantFinals };
}

function writeFixture(outPath: string, events: ReplayFixtureEvent[]): void {
  fs.mkdirSync(path.dirname(outPath), { recursive: true });
  const lines = events.map((event) => JSON.stringify(event));
  fs.writeFileSync(outPath, `${lines.join('\n')}\n`, 'utf8');
}

function printCaseStub(caseId: string, fixtureFileName: string, summary: ReturnType): void {
  const assistantFinalsJson = JSON.stringify(summary.assistantFinals, null, 2)
    .split('\n')
    .map((line) => `      ${line}`)
    .join('\n');
  console.log('\nCase stub:');
  console.log('{');
  console.log(`  id: '${caseId}',`);
  console.log(`  fixtureFile: '${fixtureFileName}',`);
  console.log('  expected: {');
  console.log(`    turnStarted: ${summary.turnStarted},`);
  console.log(`    turnComplete: ${summary.turnComplete},`);
  console.log(`    toolStarts: ${summary.toolStarts},`);
  console.log(`    toolEnds: ${summary.toolEnds},`);
  console.log('    assistantFinals:');
  console.log(assistantFinalsJson);
  console.log('  },');
  console.log('  thresholds: RELAXED_BENCH_THRESHOLDS,');
  console.log('  timeoutMs: 2_000,');
  console.log('},');
}

async function main(): Promise {
  const args = parseArgs(process.argv.slice(2));
  const repoRoot = resolveRepoRoot();
  const inputLogPath = resolveInputLogPath(args.input, repoRoot);
  const events = buildFixture(parseJsonl(inputLogPath));

  const outputPath = args.outPath
    ? path.resolve(process.cwd(), args.outPath)
    : defaultOutputPath(repoRoot, inputLogPath);
  writeFixture(outputPath, events);

  const summary = summarizeFixture(events);
  console.log(`[contract-fixture] input=${inputLogPath}`);
  console.log(`[contract-fixture] output=${outputPath}`);
  console.log(
    `[contract-fixture] events=${events.length} turns=${summary.turnStarted}/${summary.turnComplete} tools=${summary.toolStarts}/${summary.toolEnds}`
  );

  if (args.caseId) {
    printCaseStub(args.caseId, path.basename(outputPath), summary);
  }
}

main().catch((error) => {
  console.error('[contract-fixture] failed:', error);
  process.exit(1);
});



/**
 * Provider contract check for onboarding new voice/STT/TTS/LLM providers.
 *
 * Usage:
 * - bun run src/scratch-provider-contract.ts deepgram
 * - bun run src/scratch-provider-contract.ts ultravox
 * - bun run src/scratch-provider-contract.ts openai
 */

import { config as loadEnv } from 'dotenv';
import { resolve } from 'path';
import {
  loadAuthProfiles,
  loadVoiceConfig,
  resolveApiKey,
  type AuthProvider,
} from './voice/settings.js';

loadEnv({ path: resolve(process.cwd(), '../../.env') });

interface ProviderContract {
  provider: AuthProvider;
  endpoint: string;
  method: 'GET' | 'POST';
  auth: 'bearer' | 'token' | 'x-api-key' | 'query-key';
  body?: unknown;
  notes: string;
}

const CONTRACTS: Record = {
  openai: {
    provider: 'openai',
    endpoint: 'https://api.openai.com/v1/models',
    method: 'GET',
    auth: 'bearer',
    notes: 'LLM + TTS + STT provider; used in openai-realtime and decomposed LLM/TTS/STT.',
  },
  openrouter: {
    provider: 'openrouter',
    endpoint: 'https://openrouter.ai/api/v1/models',
    method: 'GET',
    auth: 'bearer',
    notes: 'LLM aggregator provider; used for decomposed LLM fallback.',
  },
  google: {
    provider: 'google',
    endpoint: 'https://generativelanguage.googleapis.com/v1beta/models',
    method: 'GET',
    auth: 'query-key',
    notes: 'Gemini Live + text model provider.',
  },
  deepgram: {
    provider: 'deepgram',
    endpoint: 'https://api.deepgram.com/v1/projects',
    method: 'GET',
    auth: 'token',
    notes: 'Decomposed STT/TTS provider. STT endpoint: /v1/listen, TTS endpoint: /v1/speak.',
  },
  ultravox: {
    provider: 'ultravox',
    endpoint: 'https://api.ultravox.ai/api/models',
    method: 'GET',
    auth: 'x-api-key',
    notes: 'Voice-to-voice provider. Call creation endpoint: /api/calls.',
  },
};

async function runContractCheck(provider: AuthProvider): Promise {
  const contract = CONTRACTS[provider];
  const voiceConfig = loadVoiceConfig();
  const authProfiles = loadAuthProfiles();
  const key = resolveApiKey(provider, { authProfiles });

  console.log(`\n[contract] provider=${provider}`);
  console.log(`[contract] endpoint=${contract.endpoint}`);
  console.log(`[contract] notes=${contract.notes}`);

  if (!key) {
    throw new Error(
      `No API key resolved for ${provider}. Set env var or defaults.${provider} in auth-profiles.json`
    );
  }

  const headers: Record = {};
  let endpoint = contract.endpoint;

  switch (contract.auth) {
    case 'bearer':
      headers.Authorization = `Bearer ${key}`;
      break;
    case 'token':
      headers.Authorization = `Token ${key}`;
      break;
    case 'x-api-key':
      headers['X-API-Key'] = key;
      break;
    case 'query-key': {
      const url = new URL(endpoint);
      url.searchParams.set('key', key);
      endpoint = url.toString();
      break;
    }
  }

  const response = await fetch(endpoint, {
    method: contract.method,
    headers,
    ...(contract.body ? { body: JSON.stringify(contract.body) } : {}),
  });

  if (!response.ok) {
    throw new Error(`Contract request failed (${response.status}): ${await response.text()}`);
  }

  const body = await response.text();
  console.log(`[contract] success status=${response.status} bodySize=${body.length}`);

  console.log('[contract] current configured runtime:');
  console.log(`- mode=${voiceConfig.voice.mode}`);
  console.log(`- voice-to-voice provider=${voiceConfig.voice.voiceToVoice.provider}`);
  console.log(`- decomposed stt=${voiceConfig.voice.decomposed.stt.provider}/${voiceConfig.voice.decomposed.stt.model}`);
  console.log(`- decomposed llm=${voiceConfig.voice.decomposed.llm.provider}/${voiceConfig.voice.decomposed.llm.model}`);
  console.log(`- decomposed tts=${voiceConfig.voice.decomposed.tts.provider}/${voiceConfig.voice.decomposed.tts.model}`);
}

async function main(): Promise {
  const arg = (process.argv[2] ?? '').trim();
  if (!arg) {
    console.log('Usage: bun run src/scratch-provider-contract.ts ');
    process.exit(1);
  }

  if (!(arg in CONTRACTS)) {
    throw new Error(`Unsupported provider: ${arg}`);
  }

  await runContractCheck(arg as AuthProvider);
  console.log('\n[contract] done');
}

main().catch((error) => {
  console.error('[contract] failed:', error);
  process.exit(1);
});



/**
 * Scratch file to explore Vercel AI SDK v5 streaming events with OpenRouter
 *
 * Testing:
 * 1. Which events are emitted during streaming
 * 2. Tool call events
 * 3. Reasoning/thinking events (if model supports extended thinking)
 * 4. Text delta events
 *
 * Run: npx tsx src/scratch-stream-test.ts [1|2|3|4]
 */

import dotenv from 'dotenv';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
dotenv.config({ path: path.resolve(__dirname, '../../../.env') });

import { streamText, generateText, tool } from 'ai';
import { createOpenRouter } from '@openrouter/ai-sdk-provider';
import { z } from 'zod';

const OPENROUTER_API_KEY = process.env.OPEN_ROUTER_API || process.env.OPEN_ROUTER_API_KEY;

if (!OPENROUTER_API_KEY) {
  console.error('OPEN_ROUTER_API or OPEN_ROUTER_API_KEY not found in .env');
  process.exit(1);
}

const openrouter = createOpenRouter({
  apiKey: OPENROUTER_API_KEY,
});

// ==================== TOOLS ====================
// Using tool() helper with inputSchema as per AI SDK v5

const weatherTool = tool({
  description: 'Get the current weather for a location',
  inputSchema: z.object({
    location: z.string().describe('The city and country'),
  }),
  execute: async ({ location }) => {
    console.log(`\n  ========================================`);
    console.log(`  [TOOL EXECUTE] weather called with:`);
    console.log(`    location = "${location}"`);
    console.log(`    type = ${typeof location}`);
    console.log(`  ========================================\n`);
    const result = { temperature: 22, condition: 'sunny', location };
    console.log(`  [TOOL EXECUTE] returning:`, JSON.stringify(result));
    return result;
  },
});

const calculatorTool = tool({
  description: 'Perform a math calculation',
  inputSchema: z.object({
    expression: z.string().describe('The math expression to evaluate, e.g. "25 * 4"'),
  }),
  execute: async ({ expression }) => {
    console.log(`  [TOOL EXECUTING] calculator: ${expression}`);
    try {
      const result = eval(expression);
      return { expression, result };
    } catch {
      return { expression, error: 'Invalid expression' };
    }
  },
});

// ==================== MODELS (Limited set) ====================
const MODELS = {
  // Primary: grok-code-fast-1 (already used in cli-agent.ts)
  grok: openrouter.chat('x-ai/grok-code-fast-1'),
  // Reasoning model
  deepseek: openrouter.chat('deepseek/deepseek-r1'),
  // Claude
  claude: openrouter.chat('anthropic/claude-sonnet-4'),
};

// ==================== STREAM TEST ====================
async function testStreamText(
  modelKey: keyof typeof MODELS,
  prompt: string,
  withTools = false
) {
  console.log('\n' + '='.repeat(60));
  console.log(`streamText | Model: ${modelKey} | Tools: ${withTools}`);
  console.log(`Prompt: "${prompt}"`);
  console.log('='.repeat(60));

  const model = MODELS[modelKey];

  try {
    const result = streamText({
      model,
      prompt,
      ...(withTools && {
        tools: { weather: weatherTool, calculator: calculatorTool },
        maxSteps: 3,
      }),
    });

    console.log('\n--- Streaming events ---\n');

    for await (const event of result.fullStream) {
      switch (event.type) {
        // Stream lifecycle
        case 'start':
          console.log('[start] Stream started');
          break;
        case 'start-step':
          console.log('[start-step] New step beginning');
          break;

        // Reasoning events (for thinking models)
        case 'reasoning-start':
          console.log(`[reasoning-start] id: ${(event as any).id}`);
          break;
        case 'reasoning-delta':
          process.stdout.write(`[reasoning] ${(event as any).text}`);
          break;
        case 'reasoning-end':
          console.log('\n[reasoning-end]');
          break;

        // Text generation events
        case 'text-start':
          console.log('[text-start]');
          break;
        case 'text-delta':
          process.stdout.write((event as any).textDelta || '');
          break;
        case 'text-end':
          console.log('\n[text-end]');
          break;

        // Tool calling events
        case 'tool-input-start':
          console.log(`[tool-input-start] ${(event as any).toolName} (id: ${(event as any).id})`);
          break;
        case 'tool-input-delta':
          console.log(`[tool-input-delta] args: ${(event as any).delta}`);
          break;
        case 'tool-input-end':
          console.log('[tool-input-end]');
          break;
        case 'tool-call':
          console.log(`[tool-call] toolName: ${event.toolName}`);
          console.log(`  event.args: ${JSON.stringify(event.args)}`);
          console.log(`  event keys: ${Object.keys(event).join(', ')}`);
          console.log(`  full event:`, event);
          break;
        case 'tool-result':
          console.log(`[tool-result] toolName: ${event.toolName}`);
          console.log(`  event.result: ${JSON.stringify(event.result)}`);
          console.log(`  event keys: ${Object.keys(event).join(', ')}`);
          console.log(`  full event:`, event);
          break;

        // Step/stream finish
        case 'finish-step':
          console.log(`[finish-step] reason: ${(event as any).finishReason}`);
          console.log(`  usage: ${JSON.stringify((event as any).usage)}`);
          break;
        case 'finish':
          console.log(`[finish] reason: ${event.finishReason}`);
          break;

        case 'error':
          console.log(`[error] ${JSON.stringify(event.error)}`);
          break;

        default:
          console.log(`[${event.type}]`, event);
      }
    }

    const finalText = await result.text;
    console.log(`\n--- Final text (${finalText.length} chars) ---`);
    console.log(finalText.substring(0, 300) + (finalText.length > 300 ? '...' : ''));

  } catch (error) {
    console.error('Error:', error);
  }
}

// ==================== GENERATE TEXT TEST ====================
async function testGenerateText(
  modelKey: keyof typeof MODELS,
  prompt: string,
  withTools = false
) {
  console.log('\n' + '='.repeat(60));
  console.log(`generateText | Model: ${modelKey} | Tools: ${withTools}`);
  console.log(`Prompt: "${prompt}"`);
  console.log('='.repeat(60));

  const model = MODELS[modelKey];

  try {
    const result = await generateText({
      model,
      prompt,
      ...(withTools && {
        tools: { weather: weatherTool, calculator: calculatorTool },
        maxSteps: 3,
        onStepFinish: ({ stepType, text, toolCalls, toolResults, finishReason, usage }) => {
          console.log(`\n[onStepFinish] stepType: ${stepType}, reason: ${finishReason}`);
          console.log(`  usage: ${JSON.stringify(usage)}`);
          if (toolCalls?.length) {
            toolCalls.forEach((tc) =>
              console.log(`  toolCall: ${tc.toolName}(${JSON.stringify(tc.args)})`)
            );
          }
          if (toolResults?.length) {
            toolResults.forEach((tr) =>
              console.log(`  toolResult: ${tr.toolName} => ${JSON.stringify(tr.result)}`)
            );
          }
          if (text) console.log(`  text: "${text.substring(0, 100)}..."`);
        },
      }),
    });

    console.log('\n--- Result ---');
    console.log(`text: "${result.text.substring(0, 300)}${result.text.length > 300 ? '...' : ''}"`);
    console.log(`steps: ${result.steps.length}`);
    console.log(`finishReason: ${result.finishReason}`);
    console.log(`usage: ${JSON.stringify(result.usage)}`);

    // Check for reasoning content
    const reasoning = (result as any).reasoning;
    if (reasoning) {
      const reasoningText = typeof reasoning === 'string' ? reasoning : JSON.stringify(reasoning);
      console.log(`reasoning: ${reasoningText.substring(0, 200)}...`);
    }

  } catch (error) {
    console.error('Error:', error);
  }
}

// ==================== MAIN ====================
async function main() {
  console.log('Vercel AI SDK v5 - Stream Events Explorer');
  console.log('==========================================\n');
  console.log('Available tests:');
  console.log('  1 - grok simple streaming (no tools)');
  console.log('  2 - grok streaming WITH tools');
  console.log('  3 - deepseek-r1 reasoning model');
  console.log('  4 - generateText with tools + onStepFinish');
  console.log('  5 - Claude streaming WITH tools');
  console.log('');

  const testNum = process.argv[2] || '1';

  switch (testNum) {
    case '1':
      await testStreamText('grok', 'Say hello in 3 languages, one per line. Be brief.');
      break;

    case '2':
      await testStreamText(
        'grok',
        'What is the weather in Berlin? Also calculate 25 * 4 for me.',
        true
      );
      break;

    case '3':
      await testStreamText(
        'deepseek',
        'Think step by step: If I have 3 boxes with 4 apples each and give away 5, how many left?'
      );
      break;

    case '4':
      await testGenerateText(
        'grok',
        'What is the weather in Tokyo? Also calculate 15 * 7.',
        true
      );
      break;

    case '5':
      await testStreamText(
        'claude',
        'What is the weather in Paris? Also calculate 12 * 8 for me.',
        true
      );
      break;

    default:
      console.log('Usage: npx tsx src/scratch-stream-test.ts [1|2|3|4|5]');
  }
}

main().catch(console.error);



/**
 * Voice benchmark report inspector.
 *
 * Usage:
 * - bun run src/scratch-voice-benchmark.ts list
 * - bun run src/scratch-voice-benchmark.ts latest
 * - bun run src/scratch-voice-benchmark.ts /absolute/or/relative/report.json
 */

import fs from 'fs';
import path from 'path';

interface BenchmarkReportFile {
  meta?: {
    sessionId?: string;
    profile?: string;
    provider?: string;
    startedAt?: string;
    finishedAt?: string;
    reason?: string;
  };
  report?: {
    pass?: boolean;
    violations?: string[];
    firstAudioLatencyMs?: number;
    chunkCadence?: {
      p95GapMs?: number;
      maxGapMs?: number;
    };
    interruption?: {
      p95Ms?: number;
    };
    transcriptOrdering?: {
      duplicateAssistantFinals?: number;
      outOfOrderAssistantItems?: number;
    };
  };
}

function resolveBenchmarkDir(): string {
  if (process.env.VOICE_BENCH_OUTPUT_DIR) {
    return path.resolve(process.cwd(), process.env.VOICE_BENCH_OUTPUT_DIR);
  }

  const cwdBase = path.basename(process.cwd());
  if (cwdBase === 'voice-agent') {
    return path.resolve(process.cwd(), '..', '..', '.benchmarks', 'voice');
  }
  return path.resolve(process.cwd(), '.benchmarks', 'voice');
}

function listReports(directory: string): string[] {
  if (!fs.existsSync(directory)) return [];
  return fs
    .readdirSync(directory)
    .filter((name) => name.endsWith('.json'))
    .sort((a, b) => a.localeCompare(b));
}

function loadReport(filePath: string): BenchmarkReportFile {
  const raw = fs.readFileSync(filePath, 'utf8');
  return JSON.parse(raw) as BenchmarkReportFile;
}

function printReport(filePath: string, report: BenchmarkReportFile): void {
  const meta = report.meta ?? {};
  const metrics = report.report ?? {};
  const status = metrics.pass ? 'PASS' : 'FAIL';
  console.log(`\n[voice-benchmark] ${status}`);
  console.log(`file=${filePath}`);
  console.log(`provider=${meta.provider ?? '(unknown)'} profile=${meta.profile ?? '(unknown)'}`);
  console.log(`session=${meta.sessionId ?? '(unknown)'} reason=${meta.reason ?? '(unknown)'}`);
  console.log(`firstAudioMs=${metrics.firstAudioLatencyMs ?? '(n/a)'}`);
  console.log(
    `chunkP95Ms=${metrics.chunkCadence?.p95GapMs ?? '(n/a)'} chunkMaxMs=${metrics.chunkCadence?.maxGapMs ?? '(n/a)'}`
  );
  console.log(`interruptP95Ms=${metrics.interruption?.p95Ms ?? '(n/a)'}`);
  console.log(
    `duplicates=${metrics.transcriptOrdering?.duplicateAssistantFinals ?? '(n/a)'} outOfOrder=${metrics.transcriptOrdering?.outOfOrderAssistantItems ?? '(n/a)'}`
  );
  const violations = metrics.violations ?? [];
  if (violations.length > 0) {
    console.log('violations:');
    for (const violation of violations) {
      console.log(`- ${violation}`);
    }
  }
}

async function main(): Promise {
  const arg = (process.argv[2] ?? 'latest').trim();
  const directory = resolveBenchmarkDir();

  if (arg === 'list') {
    const files = listReports(directory);
    if (files.length === 0) {
      console.log(`[voice-benchmark] no reports at ${directory}`);
      return;
    }
    console.log(`[voice-benchmark] reports at ${directory}`);
    for (const name of files) {
      console.log(`- ${name}`);
    }
    return;
  }

  let targetPath: string;
  if (arg === 'latest') {
    const files = listReports(directory);
    if (files.length === 0) {
      console.log(`[voice-benchmark] no reports at ${directory}`);
      return;
    }
    const latest = files[files.length - 1];
    if (!latest) {
      console.log(`[voice-benchmark] no reports at ${directory}`);
      return;
    }
    targetPath = path.join(directory, latest);
  } else {
    targetPath = path.resolve(process.cwd(), arg);
  }

  if (!fs.existsSync(targetPath)) {
    throw new Error(`Report not found: ${targetPath}`);
  }

  const report = loadReport(targetPath);
  printReport(targetPath, report);
}

main().catch((error) => {
  console.error('[voice-benchmark] failed:', error);
  process.exit(1);
});



#!/usr/bin/env bun
/**
 * Voice Runtime Inspector TUI — Entrypoint.
 *
 * Prerequisites (macOS):
 *   brew install sox
 *
 * Usage:
 *   bun run tui:inspect                           # Live mode, default profile
 *   bun run tui:inspect --profile=marvin           # Live mode, marvin profile
 *   bun run tui:inspect --provider=decomposed      # Force provider
 *   bun run tui:inspect --mode=report              # Browse benchmark reports
 *   bun run tui:inspect --check                    # Check audio setup
 */

import { config as loadEnv } from 'dotenv';
import { resolve } from 'path';
import { execSync } from 'child_process';
import type { InspectorArgs } from './tui/inspector/types.js';

// Load .env from repo root
loadEnv({ path: resolve(import.meta.dirname, '../../.env') });

// ── Audio Prerequisites Check ────────────────────────────────

function checkAudioSetup(): { ok: boolean; issues: string[] } {
  const issues: string[] = [];
  const isMac = process.platform === 'darwin';
  const isLinux = process.platform === 'linux';

  if (isMac) {
    // Check sox
    try {
      execSync('which rec', { stdio: 'pipe' });
    } catch {
      issues.push('sox is not installed. Install with: brew install sox');
    }
    try {
      execSync('which play', { stdio: 'pipe' });
    } catch {
      if (!issues.some((i) => i.includes('sox'))) {
        issues.push('sox play command not found. Install with: brew install sox');
      }
    }
  } else if (isLinux) {
    try {
      execSync('which pw-cat', { stdio: 'pipe' });
    } catch {
      issues.push('pw-cat not found. Install PipeWire: sudo apt install pipewire pipewire-audio-client-libraries');
    }
  } else {
    issues.push(`Unsupported platform: ${process.platform}. Supported: macOS, Linux`);
  }

  return { ok: issues.length === 0, issues };
}

function printAudioDevices(): void {
  const isMac = process.platform === 'darwin';
  if (isMac) {
    console.log('\n  Audio Devices (macOS):');
    try {
      const output = execSync('system_profiler SPAudioDataType 2>/dev/null', { encoding: 'utf8' });
      const lines = output.split('\n');
      let currentDevice = '';
      let isDefault = false;
      for (const line of lines) {
        const trimmed = line.trim();
        if (trimmed.endsWith(':') && !trimmed.startsWith('Devices') && !trimmed.startsWith('Audio')) {
          currentDevice = trimmed.replace(':', '');
        } else if (trimmed.startsWith('Default Input Device: Yes')) {
          console.log(`    [INPUT]  ${currentDevice} (default)`);
          isDefault = true;
        } else if (trimmed.startsWith('Default Output Device: Yes')) {
          console.log(`    [OUTPUT] ${currentDevice} (default)`);
          isDefault = true;
        } else if (trimmed.startsWith('Input Channels') && !isDefault) {
          console.log(`    [INPUT]  ${currentDevice}`);
        } else if (trimmed.startsWith('Output Channels') && !isDefault) {
          console.log(`    [OUTPUT] ${currentDevice}`);
        }
        if (trimmed === '') isDefault = false;
      }
    } catch {
      console.log('    (unable to list devices)');
    }
    console.log('\n  In live mode, press i/o to cycle input/output devices in the TUI.');
    console.log('  Device names match System Settings > Sound.');
  }
}

// ── CLI Arg Parsing ──────────────────────────────────────────

function parseArgs(): InspectorArgs & { check?: boolean } {
  const args = process.argv.slice(2);
  let mode: 'live' | 'report' = 'live';
  let profile = 'jarvis';
  let provider: string | undefined;
  let check = false;

  for (const arg of args) {
    if (arg === '--check') {
      check = true;
    } else if (arg === '--mode=report' || arg === '-r' || arg === 'report') {
      mode = 'report';
    } else if (arg.startsWith('--mode=')) {
      mode = arg.slice('--mode='.length) as 'live' | 'report';
    } else if (arg.startsWith('--profile=') || arg.startsWith('-p=')) {
      profile = arg.split('=')[1]!;
    } else if (arg.startsWith('--provider=')) {
      provider = arg.split('=')[1]!;
    } else if (arg === '--help' || arg === '-h') {
      console.log(`
Voice Runtime Inspector TUI

Prerequisites (macOS):
  brew install sox

Usage:
  bun run tui:inspect [options]

Options:
  --mode=live|report   Inspector mode (default: live)
  --profile=NAME       Agent profile: jarvis, marvin (default: jarvis)
  --provider=NAME      Force voice provider (default: from config)
  --check              Check audio prerequisites and list devices
  -r, report           Shorthand for --mode=report
  -h, --help           Show this help

Audio:
  The inspector detects available input/output devices.
  In live mode, press i/o to cycle them.
  Device labels come from your OS audio settings.

Keyboard (live mode):
  Space    Toggle mic mute
  i        Cycle input device
  o        Cycle output device
  q        Quit (shows benchmark result)
  r        Reconnect to provider
  p        Switch profile
  Enter    Text input mode
      `);
      process.exit(0);
    }
  }

  return { mode, profile, provider, check };
}

// ── Main ─────────────────────────────────────────────────────

const args = parseArgs();

// Handle --check
if (args.check) {
  console.log('\nVoice Runtime Inspector — Audio Setup Check\n');
  const { ok, issues } = checkAudioSetup();
  if (ok) {
    console.log('  ✓ Audio tools installed');
  } else {
    for (const issue of issues) {
      console.log(`  ✗ ${issue}`);
    }
  }
  printAudioDevices();

  // Check .env
  console.log('\n  API Keys:');
  const keys = ['OPENAI_API_KEY', 'OPEN_ROUTER_API_KEY', 'DEEPGRAM_API_KEY', 'ULTRAVOX_API_KEY'];
  for (const key of keys) {
    const val = process.env[key];
    console.log(`    ${key}: ${val ? '✓ set' : '✗ missing'}`);
  }

  console.log('');
  process.exit(ok ? 0 : 1);
}

// Pre-flight check for live mode
if (args.mode === 'live') {
  const { ok, issues } = checkAudioSetup();
  if (!ok) {
    console.error('\nAudio setup issues found:');
    for (const issue of issues) {
      console.error(`  ✗ ${issue}`);
    }
    console.error('\nRun with --check for full diagnostics.\n');
    process.exit(1);
  }
}

// Dynamic import to avoid loading React/Ink if --help/--check was shown
const { run } = await import('./tui/inspector/index.js');
run(args);



/**
 * Voice pipeline scratch lab for provider/auth integration.
 *
 * Scenarios:
 * - `bun run src/scratch-voice-pipeline.ts auth`
 * - `bun run src/scratch-voice-pipeline.ts ultravox`
 * - `bun run src/scratch-voice-pipeline.ts deepgram`
 * - `bun run src/scratch-voice-pipeline.ts decomposed`
 * - `bun run src/scratch-voice-pipeline.ts all`
 */

import { config as loadEnv } from 'dotenv';
import { resolve } from 'path';
import WebSocket from 'ws';
import OpenAI from 'openai';
import {
  loadVoiceConfig,
  loadAuthProfiles,
  resolveApiKey,
  type AuthProvider,
} from './voice/settings.js';

loadEnv({ path: resolve(process.cwd(), '../../.env') });

const TURN_COMPLETION_PROMPT = [
  'You must start every response with exactly one marker character:',
  '✓ when the user turn is complete and you should answer now.',
  '○ when the user seems to have paused mid-thought and likely continues soon.',
  '◐ when the user seems to be thinking and may continue after a longer pause.',
  'If marker is ○ or ◐ output only that single marker.',
].join('\n');

interface DeepgramListenResponse {
  results?: {
    channels?: Array<{
      alternatives?: Array<{
        transcript?: string;
      }>;
    }>;
  };
}

function maskSecret(value: string): string {
  if (!value) return '(missing)';
  if (value.length <= 8) return '********';
  return `${value.slice(0, 4)}...${value.slice(-4)}`;
}

async function runAuthDiagnostics(): Promise {
  const authProfiles = loadAuthProfiles();

  const providers: AuthProvider[] = ['openai', 'openrouter', 'google', 'deepgram', 'ultravox'];
  console.log('\n[auth] resolved API keys');
  for (const provider of providers) {
    const key = resolveApiKey(provider, { authProfiles });
    const defaultProfile = authProfiles.defaults[provider] ?? '(none)';
    console.log(`- ${provider.padEnd(10)} profile=${defaultProfile.padEnd(20)} key=${maskSecret(key)}`);
  }
}

async function deepgramTts(text: string, model: string, apiKey: string): Promise {
  const url = new URL('https://api.deepgram.com/v1/speak');
  url.searchParams.set('model', model);
  url.searchParams.set('encoding', 'linear16');
  url.searchParams.set('sample_rate', '24000');
  url.searchParams.set('container', 'wav');

  const response = await fetch(url, {
    method: 'POST',
    headers: {
      Authorization: `Token ${apiKey}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({ text }),
  });

  if (!response.ok) {
    throw new Error(`Deepgram TTS failed (${response.status}): ${await response.text()}`);
  }

  return Buffer.from(await response.arrayBuffer());
}

async function deepgramStt(wavAudio: Buffer, model: string, language: string, apiKey: string): Promise {
  const url = new URL('https://api.deepgram.com/v1/listen');
  url.searchParams.set('model', model);
  url.searchParams.set('language', language);
  url.searchParams.set('smart_format', 'true');

  const response = await fetch(url, {
    method: 'POST',
    headers: {
      Authorization: `Token ${apiKey}`,
      'Content-Type': 'audio/wav',
    },
    body: wavAudio,
  });

  if (!response.ok) {
    throw new Error(`Deepgram STT failed (${response.status}): ${await response.text()}`);
  }

  const payload = (await response.json()) as DeepgramListenResponse;
  return payload.results?.channels?.[0]?.alternatives?.[0]?.transcript?.trim() ?? '';
}

async function runDeepgramRoundtrip(): Promise<{ transcript: string }> {
  const voiceConfig = loadVoiceConfig();
  const apiKey = resolveApiKey('deepgram');
  if (!apiKey) {
    throw new Error('Deepgram key missing. Set DEEPGRAM_API_KEY or auth-profiles.json');
  }

  const ttsModel = voiceConfig.voice.decomposed.tts.model || 'aura-2-thalia-en';
  const sttModel = voiceConfig.voice.decomposed.stt.model || 'nova-3';
  const language = voiceConfig.voice.decomposed.stt.language || voiceConfig.voice.language;

  const sourceText = 'Hallo, das ist ein Deepgram Rundlauf Test.';
  console.log(`\n[deepgram] TTS model=${ttsModel} -> generating audio`);
  const ttsAudio = await deepgramTts(sourceText, ttsModel, apiKey);
  console.log(`[deepgram] generated ${ttsAudio.length} bytes`);

  console.log(`[deepgram] STT model=${sttModel} language=${language} -> transcribing audio`);
  const transcript = await deepgramStt(ttsAudio, sttModel, language, apiKey);
  console.log(`[deepgram] transcript: "${transcript || '(empty)'}"`);

  return { transcript };
}

async function runUltravoxHandshake(): Promise {
  const voiceConfig = loadVoiceConfig();
  const apiKey = resolveApiKey('ultravox');
  if (!apiKey) {
    throw new Error('Ultravox key missing. Set ULTRAVOX_API_KEY or auth-profiles.json');
  }

  const createResponse = await fetch('https://api.ultravox.ai/api/calls', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'X-API-Key': apiKey,
    },
    body: JSON.stringify({
      model: voiceConfig.voice.voiceToVoice.ultravoxModel,
      systemPrompt: 'You are an integration smoke test assistant. Keep replies short.',
      medium: {
        serverWebSocket: {
          inputSampleRate: 48000,
          outputSampleRate: 48000,
          clientBufferSizeMs: 60,
        },
      },
    }),
  });

  if (!createResponse.ok) {
    throw new Error(`Ultravox call creation failed (${createResponse.status}): ${await createResponse.text()}`);
  }

  const call = (await createResponse.json()) as { joinUrl?: string; websocketUrl?: string };
  const joinUrl = call.joinUrl ?? call.websocketUrl;
  if (!joinUrl) {
    throw new Error('Ultravox API did not return joinUrl/websocketUrl');
  }

  console.log('\n[ultravox] call created, connecting websocket...');

  await new Promise((resolvePromise, rejectPromise) => {
    const ws = new WebSocket(joinUrl);
    const timeout = setTimeout(() => {
      ws.terminate();
      rejectPromise(new Error('Timed out waiting for Ultravox websocket response'));
    }, 15000);

    ws.on('open', () => {
      // Wait for call_started before sending test utterance.
    });

    ws.on('message', (data, isBinary) => {
      if (isBinary) {
        const size = Buffer.isBuffer(data) ? data.length : Buffer.from(data as ArrayBuffer).length;
        console.log(`[ultravox] received audio chunk (${size} bytes)`);
        ws.send(JSON.stringify({ type: 'hang_up' }));
        ws.close();
        clearTimeout(timeout);
        resolvePromise();
        return;
      }

      const text = data.toString();
      console.log(`[ultravox] message: ${text.slice(0, 180)}`);
      try {
        const payload = JSON.parse(text) as { type?: string; text?: string };
        if (payload.type === 'call_started') {
          ws.send(JSON.stringify({ type: 'user_text_message', text: 'Say exactly: ultravox-ok' }));
          return;
        }

        if (payload.type === 'transcript') {
          ws.send(JSON.stringify({ type: 'hang_up' }));
          ws.close();
          clearTimeout(timeout);
          resolvePromise();
          return;
        }
      } catch {
        // Non-JSON data; ignore and wait for transcript/state.
      }
    });

    ws.on('error', (error) => {
      clearTimeout(timeout);
      rejectPromise(error as Error);
    });
  });
}

async function runDecomposedPipeline(): Promise {
  const voiceConfig = loadVoiceConfig();
  const openaiKey = resolveApiKey('openai');
  const deepgramKey = resolveApiKey('deepgram');

  if (!openaiKey) {
    throw new Error('OpenAI key missing. Set OPENAI_API_KEY or auth-profiles.json');
  }
  if (!deepgramKey) {
    throw new Error('Deepgram key missing. Set DEEPGRAM_API_KEY or auth-profiles.json');
  }

  const deepgramResult = await runDeepgramRoundtrip();
  const userText = deepgramResult.transcript || 'Bitte teste die Decomposed Pipeline.';

  const openai = new OpenAI({ apiKey: openaiKey });

  console.log(`\n[decomposed] LLM model=${voiceConfig.voice.decomposed.llm.model} with turn completion markers`);

  const completion = await openai.chat.completions.create({
    model: voiceConfig.voice.decomposed.llm.model,
    messages: [
      {
        role: 'system',
        content: `${TURN_COMPLETION_PROMPT}\nAntworte auf Deutsch.`,
      },
      {
        role: 'user',
        content: userText,
      },
    ],
  });

  const raw = completion.choices[0]?.message?.content?.trim() ?? '';
  const marker = raw[0] ?? '(none)';
  const assistantText = ['✓', '○', '◐'].includes(marker) ? raw.slice(1).trim() : raw;

  console.log(`[decomposed] marker=${marker} raw="${raw.slice(0, 120)}"`);

  if (marker === '○' || marker === '◐') {
    console.log('[decomposed] turn marked as incomplete, skipping TTS by design.');
    return;
  }

  const ttsModel = voiceConfig.voice.decomposed.tts.model || 'aura-2-thalia-en';
  const ttsAudio = await deepgramTts(
    assistantText || 'Die Pipeline ist verbunden.',
    ttsModel,
    deepgramKey
  );

  console.log(`[decomposed] Deepgram TTS output bytes=${ttsAudio.length}`);
}

async function main(): Promise {
  const mode = process.argv[2] ?? 'all';

  if (mode === 'auth' || mode === 'all') {
    await runAuthDiagnostics();
  }

  if (mode === 'ultravox' || mode === 'all') {
    await runUltravoxHandshake();
  }

  if (mode === 'deepgram' || mode === 'all') {
    await runDeepgramRoundtrip();
  }

  if (mode === 'decomposed' || mode === 'all') {
    await runDecomposedPipeline();
  }

  console.log('\n[scratch] done');
}

main().catch((error) => {
  console.error('\n[scratch] failed:', error);
  process.exit(1);
});



# Deepgram Provider Notes

Deepgram is used within the **decomposed adapter** for both STT (speech-to-text) and TTS (text-to-speech). It is not a standalone voice-to-voice provider.

## 1. Code Location

- Decomposed adapter: `packages/voice-runtime/src/adapters/decomposed-adapter.ts`
- STT: `transcribeWithDeepgram()` (HTTP)
- TTS: `ensureDeepgramTtsConnection()`, `speakWithDeepgramLiveSegment()`, `generateAssistantResponseStreamingWithDeepgram()` (WebSocket)

## 2. TTS: WebSocket Continuous Streaming (CRITICAL)

**Deepgram TTS uses WebSocket streaming (`wss://api.deepgram.com/v1/speak`), NOT HTTP.**

This was a real bug -- HTTP TTS does not work for streaming LLM output because it requires the full text up front. The WebSocket transport allows sending text deltas as they arrive from the LLM, producing audio in parallel.

```
LLM stream delta --> connection.sendText(delta) --> Deepgram WS --> Audio events
```

The adapter enforces this: `deepgramTtsTransport` must be `'websocket'`. Attempting HTTP Deepgram TTS throws:

```
Decomposed Deepgram TTS requires websocket transport (no HTTP fallback).
```

## 3. Connection Lifecycle

### Lazy Connect with Dedup Promise

`ensureDeepgramTtsConnection()` manages the connection:

1. If an active connection exists and `isConnected()` returns true, reuse it.
2. If a connection attempt is already in progress (`deepgramTtsConnectionReady` promise), await it (dedup).
3. Otherwise, create a new connection via the `@deepgram/sdk`:

```typescript
deepgram.speak.live({
  model,
  encoding: 'linear16',
  sample_rate: 24000,
  container: 'none',
}, endpoint);
```

4. Wait for `LiveTTSEvents.Open` (10s timeout).
5. On close, the cached reference is cleared so the next call reconnects.

### Connection Reuse

The connection persists across segments within a turn. The `deepgramTtsRequestQueue` serializes concurrent TTS requests so only one is active at a time.

### Cleanup

`closeDeepgramTtsConnection()` calls `requestClose()` then `disconnect()`, clearing both the connection reference and the ready promise.

## 4. Continuous Turn Streaming

When both LLM and TTS use streaming, `generateAssistantResponseStreamingWithDeepgram()` runs them in parallel:

1. Start LLM streaming (`generateAssistantTextStream`).
2. For each LLM text delta:
   - Emit `transcriptDelta` event (text appears in UI immediately).
   - If `deepgramTtsPunctuationChunkingEnabled` is `true` (default):
     - Buffer deltas.
     - Flush chunk packets at punctuation/threshold boundaries.
   - If `deepgramTtsPunctuationChunkingEnabled` is `false`:
     - Buffer deltas.
     - Flush chunk packets by size/whitespace thresholds (not punctuation-driven).
3. Deepgram returns audio chunks via `LiveTTSEvents.Audio`.
4. Audio chunks are enqueued into an `audioPipeline` promise chain.
5. When LLM finishes, send a final flush and wait for all audio to drain.

This achieves parallel text + audio streaming -- the user sees text and hears audio as the LLM generates.

## 5. Flush Strategy

Flushing tells Deepgram to synthesize all buffered text and return audio.

When `deepgramTtsPunctuationChunkingEnabled` is `true`, the runtime uses:

`shouldFlushDeepgramStream(delta, pendingChars, completedFlushes)` with:

| Condition | Threshold | Purpose |
|-----------|-----------|---------|
| Sentence boundary (`.!?;\n`) | 24 chars (first flush), 64 chars (subsequent) | Natural pause points |
| Minor boundary (`,`) | 96 chars | Longer clauses |
| Force flush (no boundary) | 180 chars | Prevent unbounded buffering |

The first flush uses a lower threshold (24 chars) to minimize time-to-first-audio.

When `deepgramTtsPunctuationChunkingEnabled` is `false`, punctuation-based chunking is disabled. The runtime still streams continuously by flushing on size/whitespace thresholds instead of punctuation.

Each flush increments `expectedFlushes`. The turn resolves only when `receivedFlushes >= expectedFlushes` and the audio pipeline has drained.

## 6. Audio Pipeline

### Format

- PCM16 mono, 24kHz sample rate
- `encoding: 'linear16'`, `container: 'none'`

### Chunking and Pacing

Raw audio from Deepgram is chunked into `PCM_BYTES_PER_100MS` (4800 bytes = 100ms at 24kHz mono 16-bit) segments.

Each chunk is emitted with a 20ms inter-chunk delay (`await sleep(20)`) to prevent buffer overrun on the client.

### Interruption

When the user interrupts (barge-in):
1. `interrupted` flag is set to `true`.
2. `audioInterrupted` event is emitted.
3. Audio pipeline checks `interrupted` before each chunk; if true, sets `aborted = true` and closes the connection.
4. The streaming turn resolves without waiting for remaining audio.

## 7. STT: HTTP POST

Deepgram STT uses a simple HTTP POST (not WebSocket):

```
POST https://api.deepgram.com/v1/listen?model=nova-3&language=en&smart_format=true
Authorization: Token 
Content-Type: audio/wav
Body: WAV-encoded PCM16 mono audio
```

The adapter encodes raw PCM into WAV format before sending.

## 8. Events

| Event | Source | Description |
|-------|--------|-------------|
| `LiveTTSEvents.Open` | Connection setup | Connection ready for text |
| `LiveTTSEvents.Audio` | During streaming | Raw PCM audio data |
| `LiveTTSEvents.Flushed` | After `flush()` | All buffered text has been synthesized |
| `LiveTTSEvents.Warning` | Deepgram server | Non-fatal warnings |
| `LiveTTSEvents.Error` | Deepgram server | Fatal errors, triggers connection close |
| `LiveTTSEvents.Close` | Connection teardown | Connection closed |

## 9. Configuration

| Option | Default | Description |
|--------|---------|-------------|
| `deepgramTtsTransport` | `'websocket'` | Must be `'websocket'` (HTTP not supported) |
| `deepgramTtsWsUrl` | `'wss://api.deepgram.com/v1/speak'` | WebSocket endpoint URL |
| `deepgramTtsPunctuationChunkingEnabled` | `true` | `true`: flush on punctuation/thresholds; `false`: flush on size/whitespace thresholds |
| `ttsModel` | `'aura-2-thalia-en'` | Deepgram TTS model/voice |
| `sttModel` | `'nova-3'` | Deepgram STT model (when sttProvider is deepgram) |
| `deepgramApiKey` | (required) | API key for authentication |

## 10. Timeouts

| Timeout | Duration | Scope |
|---------|----------|-------|
| Connection open | 10s | `ensureDeepgramTtsConnection` |
| Segment flush | 10s | `speakWithDeepgramLiveSegment` |
| Streaming turn | 30s | `generateAssistantResponseStreamingWithDeepgram` |

## 11. Error Handling

`toDeepgramLiveError()` normalizes Deepgram error events (which may be plain objects with `message`/`description`/`code` fields) into standard `Error` objects.

On error during streaming:
1. Connection is closed immediately.
2. The turn promise rejects.
3. The adapter emits an `error` event.



# Gemini Live Provider Notes

Google Gemini Live adapter using the `BidiGenerateContent` WebSocket API.

## 1. Code Location

- Adapter: `packages/voice-runtime/src/adapters/gemini-live-adapter.ts`
- Config parser: `parseGeminiProviderConfig()` in `provider-config.ts`

## 2. Session Flow

### WebSocket + Setup Handshake

1. Open WebSocket to the Gemini endpoint with API key as query param:
   ```
   wss://generativelanguage.googleapis.com/ws/google.ai.generativelanguage.v1beta.GenerativeService.BidiGenerateContent?key=
   ```
2. Wait for `open` event.
3. Send `setup` message with full session configuration (model, tools, voice, instructions, etc.).
4. Wait for `setupComplete` response (12s timeout).
5. Move to `listening` state and emit `connected`.

The setup message is a single JSON envelope containing everything Gemini needs:
- Model reference (auto-prefixed with `models/` if needed)
- System instruction
- Generation config (voice, temperature, max tokens, response modalities)
- Realtime input config (VAD, interruption handling)
- Tool declarations
- Transcription settings
- Session resumption handle
- Context window compression settings
- Proactivity settings

## 3. Audio Format

| Direction | Rate | Format |
|-----------|------|--------|
| Input (mic -> Gemini) | 16kHz | Base64-encoded PCM16 with `audio/pcm;rate=16000` mime |
| Output (Gemini -> speaker) | 24kHz | Base64-encoded PCM16 inline data |
| Preferred client rate | 24kHz | Adapter resamples input from 24kHz to 16kHz |

Audio is sent as JSON with base64-encoded data (not raw binary):

```typescript
{
  realtimeInput: {
    audio: {
      data: '',
      mimeType: 'audio/pcm;rate=16000',
    },
  },
}
```

Output audio arrives in `serverContent.modelTurn.parts[].inlineData` with base64 data and a mime type containing the sample rate.

## 4. Capabilities

| Capability | Supported | Notes |
|------------|-----------|-------|
| Tool calling | Yes | `functionCalls` in `toolCall` envelope |
| Tool cancellation | Yes | `toolCallCancellation` with cancelled IDs |
| Tool scheduling | Yes | `INTERRUPT` / `WHEN_IDLE` / `SILENT` |
| Non-blocking tools | Yes | `behavior: 'NON_BLOCKING'` on declaration |
| Transcript deltas | Yes | Input/output transcription |
| Interruption | Yes | `serverContent.interrupted` flag |
| Session resumption | Yes | Via `sessionResumptionUpdate.newHandle` |
| Context compression | Yes | Sliding window with target token count |
| Proactivity | Yes | `proactiveAudio: true` |
| Usage metrics | Yes | `usageMetadata` with token counts |
| Ephemeral tokens | Yes | API key passed as ephemeral-compatible value |
| VAD modes | `server`, `manual` | `automaticActivityDetection.disabled` for manual |
| Interruption modes | `barge-in`, `no-interruption` | `activityHandling` config |
| Async tools | Yes | |
| Tool timeout | No | |
| Tool reaction | No | |
| Precomputable tools | No | |
| MCP tools | No | |
| Ordered transcripts | No | |

## 5. Session Resumption

Gemini supports resuming sessions after disconnection:

1. During a session, the server sends `sessionResumptionUpdate` with a `newHandle`.
2. The adapter stores this handle in `pendingResumeHandle`.
3. On reconnect, the handle is included in the setup message:
   ```typescript
   setup.sessionResumption = { handle: resumeHandle };
   ```
4. The `resume(handle)` method allows external callers to set the handle before reconnecting.

The adapter emits latency events when a new resume handle is received, including the `resumable` flag.

## 6. Context Window Compression

Gemini supports sliding-window context compression to manage long conversations:

```typescript
setup.contextWindowCompression = {
  slidingWindow: { targetTokens: config.contextWindowCompressionTokens },
};
```

Configure via `GeminiProviderConfig.contextWindowCompressionTokens` (number of tokens to target).

## 7. Proactivity

`setup.proactivity` is currently rejected on this endpoint/model set (`1007 Unknown name "proactivity"`).

Adapter behavior: do not send `setup.proactivity` for now, even if configured, and treat proactivity as unsupported until Google adds the field for this API variant.

## 8. Transcript Handling

### Input Transcription

Arrives in `serverContent.inputTranscription.text`. The adapter:
1. Creates a user item if none is active (`ensureActiveUserItem`).
2. Computes delta from previous text using prefix matching.
3. Emits `transcriptDelta` for incremental updates.
4. Finalizes on `turnComplete` / `generationComplete`.

### Output Transcription

Arrives in `serverContent.outputTranscription.text`. Same delta computation as input.

### Model Turn Text

Text in `serverContent.modelTurn.parts[].text` is also accumulated as assistant transcript deltas.

## 9. Tool Handling

### Function Declarations

Tools are sent in the setup message as `functionDeclarations`:

```typescript
{
  name: 'tool_name',
  description: 'What the tool does',
  parameters: { type: 'object', properties: { ... } },
  behavior: 'NON_BLOCKING',  // optional
}
```

### Tool Call Protocol

```
Gemini sends:    { toolCall: { functionCalls: [{ id, name, args }] } }
Adapter calls:   toolHandler(name, args, context) for each call
Adapter sends:   { toolResponse: { functionResponses: [{ id, name, response, scheduling }] } }
```

### Tool Cancellation

```
Gemini sends:    { toolCallCancellation: { ids: ['call-1', 'call-2'] } }
Adapter emits:   'toolCancelled' event with the cancelled IDs
```

### Tool Scheduling

Tool results can specify when Gemini should process them:

| Value | Gemini Value | Description |
|-------|-------------|-------------|
| `'interrupt'` | `INTERRUPT` | Process immediately, interrupt current output |
| `'when_idle'` | `WHEN_IDLE` | Process when not speaking |
| `'silent'` | `SILENT` | Process silently without generating output |

## 10. Server Content Handling

The `serverContent` envelope contains:

| Field | Description |
|-------|-------------|
| `modelTurn.parts[]` | Audio (inlineData) and text parts |
| `turnComplete` | Model turn is complete |
| `generationComplete` | Full generation is complete |
| `interrupted` | Model was interrupted by user |
| `inputTranscription.text` | User speech transcription |
| `outputTranscription.text` | Model speech transcription |

On `turnComplete` or `generationComplete`:
1. Finalize any active user transcript.
2. Finalize any active assistant transcript.
3. Set state to `listening`.
4. Emit `turnComplete`.

## 11. GoAway Handling

The server may send `goAway` with a `timeLeft` field indicating the session will close soon. The adapter emits this as a latency event for monitoring.

## 12. Configuration

`GeminiProviderConfig` fields:

| Field | Default | Description |
|-------|---------|-------------|
| `apiKey` | (required) | Google AI API key |
| `endpoint` | Gemini Live WS endpoint | Custom WebSocket URL |
| `useEphemeralToken` | `false` | Treat apiKey as ephemeral token |
| `vadMode` / `vad.mode` | `manual` | VAD mode override (`manual` recommended, `server` available) |
| `vadSilenceDurationMs` / `vad.silenceDurationMs` | `450` | Silence threshold for local manual VAD end-of-activity |
| `vadPrefixPaddingMs` / `vad.prefixPaddingMs` | `120` | Pre-roll audio kept before manual activity start |
| `vadThreshold` / `vad.threshold` | `0.005` | RMS threshold for local manual speech detection |
| `noInterruption` | `false` | Use `NO_INTERRUPTION` activity handling |
| `enableInputTranscription` | `true` | Enable user speech transcription |
| `enableOutputTranscription` | `true` | Enable model speech transcription |
| `sessionResumptionHandle` | (none) | Resume handle from previous session |
| `contextWindowCompressionTokens` | (none) | Target token count for sliding window |
| `proactivity` | `false` | Parsed for compatibility, but currently not sent (setup field rejected) |

## 13. Known Issues & Workarounds

### Input Transcription Returns Wrong Language (Native-Audio Models)

**Symptom**: `inputTranscription.text` contains Arabic, Persian, or other random language fragments instead of actual speech content. The model's audio comprehension is unaffected — it responds correctly.

**Cause**: Auto VAD (`automaticActivityDetection: { disabled: false }`) triggers premature `interrupted` events during audio streaming, corrupting the transcription pipeline. This is a known server-side bug on `gemini-2.5-flash-native-audio` models.

**Fix**: Use manual VAD with explicit activity signals:
```typescript
// 1. Disable auto VAD in setup:
realtimeInputConfig: {
  automaticActivityDetection: { disabled: true },
}

// 2. Send activityStart before audio:
ws.send(JSON.stringify({ realtimeInput: { activityStart: {} } }));

// 3. Send audio chunks...

// 4. Send activityEnd after audio:
ws.send(JSON.stringify({ realtimeInput: { activityEnd: {} } }));
```

### languageCode Rejected on Native-Audio Models

`speechConfig.languageCode` with non-English codes (e.g., `de`) causes immediate WebSocket close with code 1007. Set language via system instruction instead.

### Only audio/pcm Accepted for realtimeInput

WAV, M4A, FLAC etc. are rejected for `realtimeInput.audio`. Only `audio/pcm` or `audio/pcm;rate=XXXXX` is accepted. Other formats may work via `clientContent` on non-native models.

### Tool Schemas With `$...` Keys and `additionalProperties` Fail Setup

Gemini rejects unsupported JSON-schema metadata in `functionDeclarations.parameters` (for example `$schema` and `additionalProperties`) and closes setup with `1007`.

Adapter workaround: sanitize tool schemas before setup and strip `$...` keys recursively.

### `proactivity` Field Rejected During Setup

`setup.proactivity` currently causes setup close `1007` (`Unknown name "proactivity" at 'setup'`).

Adapter workaround: ignore this field for now and keep proactivity disabled.

### Deprecated Model Alias Fails Setup

`models/gemini-2.5-flash-native-audio-preview` now closes setup with `1008` (model not found for `bidiGenerateContent`).

Adapter workaround: normalize this alias to `models/gemini-2.5-flash-native-audio-latest`.

### Available Models

As of 2026-02-20, only native-audio models support `bidiGenerateContent`:
- `models/gemini-2.5-flash-native-audio-latest` (recommended)
- `models/gemini-2.5-flash-native-audio-preview-12-2025`
- `models/gemini-2.5-flash-native-audio-preview-09-2025` (deprecated March 2026)

The old `gemini-2.0-flash-*` live models are no longer available.

See also: [PROVIDER_INTEGRATION_GUIDE.md Section 7](../PROVIDER_INTEGRATION_GUIDE.md#7-gemini-live-current-state--findings) for full experiment results.



# Pipecat RTVI Provider Notes

This document describes the `pipecat-rtvi` adapter integration in the extracted runtime.

Capability matrix and cross-provider comparisons live in [`../PROVIDERS.md`](../PROVIDERS.md).

## 1. Code Locations

- adapter: `packages/voice-runtime/src/adapters/pipecat-rtvi-adapter.ts`
- runtime registration: your application's factory/config files

## 2. Session Flow

1. `VoiceSession.connect()` calls adapter `connect()`.
2. Adapter opens websocket to `providerConfig.serverUrl`.
3. Adapter sends:
   - `client-ready`
   - `describe-actions`
   - `describe-config`
   - bootstrap `client-message`
4. Adapter waits for `bot-ready` (timeout default: 12s).
5. Runtime moves to `listening`.

## 3. Normalized Events

The adapter maps RTVI messages to `VoiceSessionEvents`:

- state: listening/thinking/speaking/idle
- transcripts: user + assistant delta/final
- audio: binary frames and base64 audio messages
- tools: `toolStart`/`toolEnd`/`toolCancelled`
- metrics: latency + usage

Turn lifecycle is deduplicated so `turnComplete` is emitted once per turn.

## 4. Tools

`llm-function-call*` events are normalized into one callback path:

- call -> `toolHandler(name, args, context)`
- result -> `llm-function-call-result`

`autoToolExecution` defaults to `true`. Set `false` to execute tools externally and return results with `sendToolResult`.

## 5. Reconnect + Keepalive

- unexpected close -> bounded exponential reconnect attempts
- keepalive ping (default 15s) after `bot-ready`
- keepalive config:
  - `keepAliveIntervalMs` (set `0` to disable)
  - `pingMessageType` (default: `ping`)

## 6. Provider Config Fields

`PipecatProviderConfig`:

- `serverUrl`
- `transport`
- `inputSampleRate`, `outputSampleRate`
- `audioInputEncoding`, `audioInputMessageType`
- `readyTimeoutMs`
- `reconnect`
- `clientVersion`
- `autoToolExecution`
- `bootstrapMessageType`
- `keepAliveIntervalMs`, `pingMessageType`
- `pipeline`, `botId`

## 7. Operational Checklist

1. Confirm Pipecat server is reachable from your application.
2. Start with websocket transport first (`transport: "websocket"`).
3. Validate handshake and first turn in logs.
4. Enable benchmark capture (`VOICE_BENCHMARK_ENABLED=true`) and confirm no ordering/latency violations.
5. Only then switch profile defaults/UI config to `pipecat-rtvi`.



import { streamPcmResponse } from './audio-utils.js';
import type { SegmentSynthesisInput, SegmentSynthesisResult } from './types.js';

function isQwenModel(model: string): boolean {
  const normalized = model.toLowerCase();
  return normalized.includes('qwen3') || normalized.includes('qwen-tts');
}

export async function synthesizeLocalSegment(
  input: SegmentSynthesisInput
): Promise {
  const { context, text, emitChunk, signal } = input;
  const endpoint = new URL('/v1/audio/speech', context.localEndpoint);
  const requestBody: Record = {
    model: context.model,
    voice: context.voice,
    language: context.language,
    lang_code: context.language,
    input: text,
    response_format: 'pcm',
  };
  if (context.voiceRefAudio) {
    requestBody.ref_audio = context.voiceRefAudio;
    if (context.voiceRefText) {
      requestBody.ref_text = context.voiceRefText;
    }
  }
  if (isQwenModel(context.model)) {
    const interval =
      Number.isFinite(context.localTtsStreamingIntervalSec) &&
      context.localTtsStreamingIntervalSec > 0
        ? context.localTtsStreamingIntervalSec
        : 1.0;
    requestBody.seed = 42;
    requestBody.stream = true;
    requestBody.streaming_interval = interval;
  }
  const response = await fetch(endpoint, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(requestBody),
    signal,
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`Local TTS failed (${response.status}): ${errorText}`);
  }

  await streamPcmResponse(response, emitChunk, {
    passthroughChunks: isQwenModel(context.model),
  });
  return { precision: 'segment' };
}



