      dependsOn: { field: 'turn.vadEngine', value: 'webrtc-vad' },
      description: 'Extra voiced-ratio required while assistant is speaking.',
    },
    {
      key: 'turn.assistantOutputMinRms',
      label: 'Assistant Output VAD Min RMS',
      type: 'number',
      group: 'vad',
      min: 0.001,
      max: 0.08,
      step: 0.001,
      defaultValue: 0.008,
      description: 'RMS threshold to consider assistant output actively speaking.',
    },
    {
      key: 'turn.assistantOutputSilenceMs',
      label: 'Assistant Output Silence Hold (ms)',
      type: 'number',
      group: 'vad',
      min: 100,
      max: 1200,
      step: 10,
      defaultValue: 350,
      description: 'How long output stays "speaking" after last voiced chunk.',
    },
    {
      key: 'deepgramTtsPunctuationChunkingEnabled',
      label: 'Deepgram Punctuation Chunking',
      type: 'boolean',
      group: 'advanced',
      defaultValue: true,
      description:
        'When enabled, Deepgram streaming TTS flushes on punctuation for lower latency. Disable for one continuous segment per turn.',
    },
    {
      key: 'inlineTtsChunkingEnabled',
      label: 'Inline TTS Chunking',
      type: 'boolean',
      group: 'advanced',
      defaultValue: true,
      description:
        'When enabled, inline/non-streaming TTS is synthesized in small segments while text streams in. Disable to synthesize one full utterance per response.',
    },
    {
      key: 'localEndpoint',
      label: 'Local Inference Endpoint',
      type: 'string',
      group: 'advanced',
      defaultValue: 'http://localhost:1060',
      description:
        'Base URL for local STT/TTS provider calls (for example http://localhost:1060).',
    },
    {
      key: 'localTtsStreamingIntervalSec',
      label: 'Local Qwen Streaming Interval (s)',
      type: 'number',
      group: 'advanced',
      min: 0.2,
      max: 4,
      step: 0.1,
      defaultValue: 1.0,
      description:
        'Streaming chunk interval for local Qwen TTS. Lower values reduce first audio latency but can increase chunk overhead.',
    },
    {
      key: 'localQwenAdaptiveUnderrunEnabled',
      label: 'Local Qwen Adaptive Anti-Underrun',
      type: 'boolean',
      group: 'advanced',
      defaultValue: true,
      description:
        'Dynamically increases startup buffer and streaming interval for local Qwen TTS when generation falls behind playback.',
    },
    // LLM completion fields (enabled, shortTimeoutMs, longTimeoutMs) are managed
    // by the dedicated turn.llmCompletion section in voice.config.json, not providerSettings.
  ],
};

export function resolveDecomposedOptions(input: SessionInput): DecomposedOptions {
  const providerConfig: DecomposedProviderConfig = parseDecomposedProviderConfig(input.providerConfig);
  const ttsProvider = (providerConfig.ttsProvider ?? 'openai') as DecomposedTtsProvider;
  const ttsModel = providerConfig.ttsModel ?? defaultTtsModelForProvider(ttsProvider);

  return {
    sttProvider: providerConfig.sttProvider ?? 'openai',
    sttModel: providerConfig.sttModel ?? 'gpt-4o-mini-transcribe',
    customSttMode: providerConfig.customSttMode ?? 'provider',
    llmProvider: providerConfig.llmProvider ?? 'openai',
    llmModel: providerConfig.llmModel ?? input.model,
    ttsProvider,
    ttsModel,
    ttsVoice: providerConfig.ttsVoice ?? input.voice,
    deepgramTtsTransport: providerConfig.deepgramTtsTransport ?? 'websocket',
    deepgramTtsWsUrl: providerConfig.deepgramTtsWsUrl ?? 'wss://api.deepgram.com/v1/speak',
    deepgramTtsPunctuationChunkingEnabled:
      providerConfig.deepgramTtsPunctuationChunkingEnabled ?? true,
    inlineTtsChunkingEnabled:
      providerConfig.inlineTtsChunkingEnabled ??
      defaultInlineTtsChunkingEnabled(ttsProvider, ttsModel),
    cartesiaTtsWsUrl:
      providerConfig.cartesiaTtsWsUrl ?? 'wss://api.cartesia.ai/tts/websocket',
    fishTtsWsUrl: providerConfig.fishTtsWsUrl ?? 'wss://api.fish.audio/v1/tts/live',
    rimeTtsWsUrl: providerConfig.rimeTtsWsUrl ?? 'wss://users-ws.rime.ai/ws2',
    googleChirpEndpoint:
      providerConfig.googleChirpEndpoint ??
      'https://texttospeech.googleapis.com/v1/text:synthesize',
    kokoroEndpoint:
      providerConfig.kokoroEndpoint ?? 'http://localhost:8880/v1/audio/speech',
    pocketTtsEndpoint: providerConfig.pocketTtsEndpoint ?? 'http://localhost:8000/tts',
    localEndpoint: providerConfig.localEndpoint ?? 'http://localhost:1060',
    localTtsStreamingIntervalSec: providerConfig.localTtsStreamingIntervalSec ?? 1.0,
    localQwenAdaptiveUnderrunEnabled: providerConfig.localQwenAdaptiveUnderrunEnabled ?? true,
    voiceRefAudio: providerConfig.voiceRefAudio,
    voiceRefText: providerConfig.voiceRefText,
    silenceMs: providerConfig.turn?.silenceMs ?? 700,
    minSpeechMs: providerConfig.turn?.minSpeechMs ?? 350,
    minRms: providerConfig.turn?.minRms ?? 0.015,
    bargeInEnabled: providerConfig.turn?.bargeInEnabled ?? true,
    speechStartDebounceMs: providerConfig.turn?.speechStartDebounceMs ?? 140,
    vadEngine: providerConfig.turn?.vadEngine ?? 'webrtc-vad',
    neuralFilterEnabled: providerConfig.turn?.neuralFilterEnabled ?? true,
    rnnoiseSpeechThreshold: providerConfig.turn?.rnnoiseSpeechThreshold ?? 0.62,
    rnnoiseEchoSpeechThresholdBoost: providerConfig.turn?.rnnoiseEchoSpeechThresholdBoost ?? 0.12,
    webrtcVadMode: providerConfig.turn?.webrtcVadMode ?? 3,
    webrtcVadSpeechRatioThreshold: providerConfig.turn?.webrtcVadSpeechRatioThreshold ?? 0.7,
    webrtcVadEchoSpeechRatioBoost:
      providerConfig.turn?.webrtcVadEchoSpeechRatioBoost ?? 0.15,
    assistantOutputMinRms: providerConfig.turn?.assistantOutputMinRms ?? 0.008,
    assistantOutputSilenceMs: providerConfig.turn?.assistantOutputSilenceMs ?? 350,
    spokenStreamEnabled: providerConfig.turn?.spokenStreamEnabled ?? false,
    wordAlignmentEnabled: providerConfig.turn?.wordAlignmentEnabled ?? false,
    llmCompletionEnabled: providerConfig.turn?.llmCompletionEnabled ?? false,
    llmShortTimeoutMs: providerConfig.turn?.llmShortTimeoutMs ?? 5000,
    llmLongTimeoutMs: providerConfig.turn?.llmLongTimeoutMs ?? 10000,
    llmShortReprompt:
      providerConfig.turn?.llmShortReprompt ??
      'Can you finish that thought for me?',
    llmLongReprompt:
      providerConfig.turn?.llmLongReprompt ??
      "I'm still here. Continue when you're ready.",
    language: input.language ?? 'en',
    openaiApiKey: providerConfig.openaiApiKey,
    openrouterApiKey: providerConfig.openrouterApiKey,
    anthropicApiKey: providerConfig.anthropicApiKey,
    googleApiKey: providerConfig.googleApiKey,
    deepgramApiKey: providerConfig.deepgramApiKey,
    cartesiaApiKey: providerConfig.cartesiaApiKey,
    fishAudioApiKey: providerConfig.fishAudioApiKey,
    rimeApiKey: providerConfig.rimeApiKey,
  };
}



import type { AudioFrame } from '../types.js';

export interface BenchmarkAudioChunk {
  emittedAtMs: number;
  byteLength: number;
  sampleRate: number;
}

export interface BenchmarkTranscriptEvent {
  emittedAtMs: number;
  role: 'user' | 'assistant';
  kind: 'delta' | 'final';
  text: string;
  itemId?: string;
}

export interface BenchmarkAssistantItemEvent {
  emittedAtMs: number;
  itemId: string;
}

export interface BenchmarkInterruptionSample {
  requestedAtMs: number;
  stoppedAtMs: number;
}

export interface VoiceBenchmarkInput {
  turnStartedAtMs?: number;
  audioChunks: BenchmarkAudioChunk[];
  transcripts: BenchmarkTranscriptEvent[];
  assistantItems?: BenchmarkAssistantItemEvent[];
  interruptions?: BenchmarkInterruptionSample[];
}

export interface VoiceBenchmarkThresholds {
  maxFirstAudioLatencyMs?: number;
  maxP95ChunkGapMs?: number;
  maxChunkGapMs?: number;
  minRealtimeFactor?: number;
  maxRealtimeFactor?: number;
  maxDuplicateAssistantFinals?: number;
  maxOutOfOrderConversationItems?: number;
  maxOutOfOrderAssistantItems?: number;
  maxOrphanAssistantItems?: number;
  maxInterruptionP95Ms?: number;
}

export interface VoiceBenchmarkReport {
  pass: boolean;
  violations: string[];
  firstAudioLatencyMs?: number;
  chunkCadence: {
    medianGapMs: number;
    p95GapMs: number;
    maxGapMs: number;
    p95JitterMs: number;
  };
  realtimeFactor?: number;
  transcriptOrdering: {
    duplicateAssistantFinals: number;
    outOfOrderConversationItems: number;
    outOfOrderAssistantItems: number;
    orphanAssistantItems: number;
  };
  interruption: {
    count: number;
    medianMs: number;
    p95Ms: number;
    maxMs: number;
  };
}

const DEFAULT_THRESHOLDS: Required = {
  maxFirstAudioLatencyMs: 1_500,
  maxP95ChunkGapMs: 280,
  maxChunkGapMs: 550,
  minRealtimeFactor: 0.85,
  maxRealtimeFactor: 1.35,
  maxDuplicateAssistantFinals: 0,
  maxOutOfOrderConversationItems: 0,
  maxOutOfOrderAssistantItems: 0,
  maxOrphanAssistantItems: 0,
  maxInterruptionP95Ms: 220,
};

export function evaluateVoiceBenchmark(
  input: VoiceBenchmarkInput,
  thresholds: VoiceBenchmarkThresholds = {}
): VoiceBenchmarkReport {
  const config = {
    ...DEFAULT_THRESHOLDS,
    ...thresholds,
  };
  const violations: string[] = [];

  const sortedAudio = [...input.audioChunks].sort((a, b) => a.emittedAtMs - b.emittedAtMs);
  const gaps = computeGaps(sortedAudio.map((chunk) => chunk.emittedAtMs));
  const medianGapMs = percentile(gaps, 50);
  const p95GapMs = percentile(gaps, 95);
  const maxGapMs = gaps.length > 0 ? Math.max(...gaps) : 0;
  const jitter = gaps.map((gap) => Math.abs(gap - medianGapMs));
  const p95JitterMs = percentile(jitter, 95);

  let firstAudioLatencyMs: number | undefined;
  if (typeof input.turnStartedAtMs === 'number' && sortedAudio.length > 0) {
    const firstAudio = sortedAudio[0];
    if (firstAudio) {
      firstAudioLatencyMs = Math.max(0, firstAudio.emittedAtMs - input.turnStartedAtMs);
    }
    if (
      typeof firstAudioLatencyMs === 'number' &&
      firstAudioLatencyMs > config.maxFirstAudioLatencyMs
    ) {
      violations.push(
        `First-audio latency ${firstAudioLatencyMs.toFixed(1)}ms exceeds ${config.maxFirstAudioLatencyMs}ms`
      );
    }
  }

  if (p95GapMs > config.maxP95ChunkGapMs) {
    violations.push(`Audio chunk p95 gap ${p95GapMs.toFixed(1)}ms exceeds ${config.maxP95ChunkGapMs}ms`);
  }
  if (maxGapMs > config.maxChunkGapMs) {
    violations.push(`Audio max chunk gap ${maxGapMs.toFixed(1)}ms exceeds ${config.maxChunkGapMs}ms`);
  }

  const realtimeFactor = computeRealtimeFactor(sortedAudio);
  if (typeof realtimeFactor === 'number') {
    if (realtimeFactor < config.minRealtimeFactor || realtimeFactor > config.maxRealtimeFactor) {
      violations.push(
        `Realtime factor ${realtimeFactor.toFixed(3)} outside [${config.minRealtimeFactor}, ${config.maxRealtimeFactor}]`
      );
    }
  }

  const duplicateAssistantFinals = countDuplicateAssistantFinals(input.transcripts);
  if (duplicateAssistantFinals > config.maxDuplicateAssistantFinals) {
    violations.push(
      `Duplicate assistant finals ${duplicateAssistantFinals} exceeds ${config.maxDuplicateAssistantFinals}`
    );
  }

  const outOfOrderConversationItems = countOutOfOrderConversationItems(input.transcripts);
  if (outOfOrderConversationItems > config.maxOutOfOrderConversationItems) {
    violations.push(
      `Out-of-order conversation items ${outOfOrderConversationItems} exceeds ${config.maxOutOfOrderConversationItems}`
    );
  }

  const outOfOrderAssistantItems = countOutOfOrderAssistantItems(
    input.assistantItems ?? collectAssistantItems(input.transcripts)
  );
  if (outOfOrderAssistantItems > config.maxOutOfOrderAssistantItems) {
    violations.push(
      `Out-of-order assistant items ${outOfOrderAssistantItems} exceeds ${config.maxOutOfOrderAssistantItems}`
    );
  }

  const orphanAssistantItems = countOrphanAssistantItems(
    input.assistantItems ?? collectAssistantItems(input.transcripts),
    input.transcripts
  );
  if (orphanAssistantItems > config.maxOrphanAssistantItems) {
    violations.push(
      `Orphan assistant items ${orphanAssistantItems} exceeds ${config.maxOrphanAssistantItems}`
    );
  }

  const interruptionLatencies = (input.interruptions ?? [])
    .map((sample) => sample.stoppedAtMs - sample.requestedAtMs)
    .filter((latency) => latency >= 0);
  const interruptionMedianMs = percentile(interruptionLatencies, 50);
  const interruptionP95Ms = percentile(interruptionLatencies, 95);
  const interruptionMaxMs =
    interruptionLatencies.length > 0 ? Math.max(...interruptionLatencies) : 0;
  if (
    interruptionLatencies.length > 0 &&
    interruptionP95Ms > config.maxInterruptionP95Ms
  ) {
    violations.push(
      `Interruption p95 ${interruptionP95Ms.toFixed(1)}ms exceeds ${config.maxInterruptionP95Ms}ms`
    );
  }

  return {
    pass: violations.length === 0,
    violations,
    firstAudioLatencyMs,
    chunkCadence: {
      medianGapMs,
      p95GapMs,
      maxGapMs,
      p95JitterMs,
    },
    realtimeFactor,
    transcriptOrdering: {
      duplicateAssistantFinals,
      outOfOrderConversationItems,
      outOfOrderAssistantItems,
      orphanAssistantItems,
    },
    interruption: {
      count: interruptionLatencies.length,
      medianMs: interruptionMedianMs,
      p95Ms: interruptionP95Ms,
      maxMs: interruptionMaxMs,
    },
  };
}

export class VoiceBenchmarkRecorder {
  private turnStartedAtMs?: number;
  private readonly audioChunks: BenchmarkAudioChunk[] = [];
  private readonly transcripts: BenchmarkTranscriptEvent[] = [];
  private readonly assistantItems: BenchmarkAssistantItemEvent[] = [];
  private readonly interruptionRequests: number[] = [];
  private readonly interruptions: BenchmarkInterruptionSample[] = [];
  private readonly now: () => number;

  constructor(now?: () => number) {
    this.now = now ?? (() => Date.now());
  }

  markTurnStarted(timestampMs = this.now()): void {
    this.turnStartedAtMs = timestampMs;
  }

  recordAudio(frame: AudioFrame, timestampMs = this.now()): void {
    this.audioChunks.push({
      emittedAtMs: timestampMs,
      byteLength: frame.data.byteLength,
      sampleRate: frame.sampleRate,
    });
  }

  recordTranscript(
    kind: 'delta' | 'final',
    text: string,
    role: 'user' | 'assistant',
    itemId?: string,
    timestampMs = this.now()
  ): void {
    this.transcripts.push({
      emittedAtMs: timestampMs,
      kind,
      text,
      role,
      itemId,
    });
  }

  recordAssistantItem(itemId: string, timestampMs = this.now()): void {
    this.assistantItems.push({
      emittedAtMs: timestampMs,
      itemId,
    });
  }

  markInterruptionRequested(timestampMs = this.now()): void {
    this.interruptionRequests.push(timestampMs);
  }

  markInterruptionStopped(timestampMs = this.now()): void {
    const requestedAtMs = this.interruptionRequests.shift();
    if (typeof requestedAtMs !== 'number') return;
    this.interruptions.push({
      requestedAtMs,
      stoppedAtMs: timestampMs,
    });
  }

  buildInput(): VoiceBenchmarkInput {
    return {
      turnStartedAtMs: this.turnStartedAtMs,
      audioChunks: [...this.audioChunks],
      transcripts: [...this.transcripts],
      assistantItems: [...this.assistantItems],
      interruptions: [...this.interruptions],
    };
  }

  evaluate(thresholds?: VoiceBenchmarkThresholds): VoiceBenchmarkReport {
    return evaluateVoiceBenchmark(this.buildInput(), thresholds);
  }
}

function computeRealtimeFactor(chunks: BenchmarkAudioChunk[]): number | undefined {
  if (chunks.length < 2) return undefined;
  const first = chunks[0];
  const last = chunks[chunks.length - 1];
  if (!first || !last) return undefined;

  const wallDurationMs = Math.max(1, last.emittedAtMs - first.emittedAtMs);
  const audioDurationMs = chunks.reduce((sum, chunk) => {
    if (chunk.sampleRate <= 0) return sum;
    return sum + (chunk.byteLength / 2 / chunk.sampleRate) * 1000;
  }, 0);

  return audioDurationMs / wallDurationMs;
}

function countDuplicateAssistantFinals(events: BenchmarkTranscriptEvent[]): number {
  const finals = events.filter((event) => event.role === 'assistant' && event.kind === 'final');
  const byItem = new Map();
  let duplicates = 0;

  for (const event of finals) {
    const key = event.itemId ?? `${event.text}:${event.emittedAtMs}`;
    const seen = byItem.get(key) ?? 0;
    if (seen > 0) duplicates += 1;
    byItem.set(key, seen + 1);
  }

  return duplicates;
}

function collectAssistantItems(events: BenchmarkTranscriptEvent[]): BenchmarkAssistantItemEvent[] {
  return events
    .filter((event) => event.role === 'assistant' && typeof event.itemId === 'string')
    .map((event) => ({
      itemId: event.itemId as string,
      emittedAtMs: event.emittedAtMs,
    }));
}

function countOutOfOrderConversationItems(events: BenchmarkTranscriptEvent[]): number {
  if (events.length <= 1) return 0;
  const ordered = [...events].sort((a, b) => a.emittedAtMs - b.emittedAtMs);
  const firstSeenItemIds: string[] = [];
  const seen = new Set();

  for (const event of ordered) {
    if ((event.role !== 'assistant' && event.role !== 'user') || typeof event.itemId !== 'string') {
      continue;
    }
    if (seen.has(event.itemId)) continue;
    seen.add(event.itemId);
    firstSeenItemIds.push(event.itemId);
  }

  let outOfOrder = 0;
  let lastNumeric = Number.NEGATIVE_INFINITY;
  for (const itemId of firstSeenItemIds) {
    const numeric = parseTrailingNumber(itemId);
    if (numeric === null) continue;
    if (numeric < lastNumeric) {
      outOfOrder += 1;
    }
    lastNumeric = Math.max(lastNumeric, numeric);
  }
  return outOfOrder;
}

function countOutOfOrderAssistantItems(events: BenchmarkAssistantItemEvent[]): number {
  if (events.length <= 1) return 0;
  const ordered = [...events].sort((a, b) => a.emittedAtMs - b.emittedAtMs);
  let outOfOrder = 0;
  let lastNumeric = Number.NEGATIVE_INFINITY;

  for (const event of ordered) {
    const numeric = parseTrailingNumber(event.itemId);
    if (numeric === null) continue;
    if (numeric < lastNumeric) {
      outOfOrder += 1;
    }
    lastNumeric = Math.max(lastNumeric, numeric);
  }

  return outOfOrder;
}

function countOrphanAssistantItems(
  assistantItems: BenchmarkAssistantItemEvent[],
  transcripts: BenchmarkTranscriptEvent[]
): number {
  if (assistantItems.length === 0) return 0;

  const assistantItemIds = new Set(assistantItems.map((event) => event.itemId));
  const itemIdsWithMeaningfulText = new Set();

  for (const event of transcripts) {
    if (event.role !== 'assistant') continue;
    if (typeof event.itemId !== 'string') continue;
    if (!assistantItemIds.has(event.itemId)) continue;
    if (event.text.trim().length === 0) continue;
    itemIdsWithMeaningfulText.add(event.itemId);
  }

  let orphanCount = 0;
  for (const itemId of assistantItemIds) {
    if (!itemIdsWithMeaningfulText.has(itemId)) {
      orphanCount += 1;
    }
  }
  return orphanCount;
}

function parseTrailingNumber(value: string): number | null {
  const uvxMatch = value.match(/^(?:assistant|user)-(\d+)$/);
  if (uvxMatch?.[1]) {
    const parsed = Number.parseInt(uvxMatch[1], 10);
    return Number.isFinite(parsed) ? parsed : null;
  }

  const decomposedMatch = value.match(/^decomp-(?:assistant|user|context)-(\d+)-[a-z0-9]+$/i);
  if (decomposedMatch?.[1]) {
    const parsed = Number.parseInt(decomposedMatch[1], 10);
    return Number.isFinite(parsed) ? parsed : null;
  }

  return null;
}

function computeGaps(values: number[]): number[] {
  if (values.length < 2) return [];
  const gaps: number[] = [];
  for (let i = 1; i < values.length; i += 1) {
    const previous = values[i - 1];
    const current = values[i];
    if (typeof previous !== 'number' || typeof current !== 'number') continue;
    gaps.push(Math.max(0, current - previous));
  }
  return gaps;
}

function percentile(values: number[], percentileValue: number): number {
  if (values.length === 0) return 0;
  const sorted = [...values].sort((a, b) => a - b);
  const normalized = Math.min(100, Math.max(0, percentileValue));
  const index = Math.floor((normalized / 100) * (sorted.length - 1));
  const value = sorted[index];
  return typeof value === 'number' ? value : 0;
}



import { readFileSync } from 'fs';
import { dirname, resolve } from 'path';
import { createRequire } from 'module';
import SoxrResampler from 'wasm-audio-resampler';
import { SoxrDatatype } from 'wasm-audio-resampler';
import type { AudioFrame } from '../types.js';

/**
 * Pre-load the WASM binary from disk so it works in Bun/Node
 * (Emscripten's default fetch()-based loader fails in Bun).
 */
let wasmBinaryCache: Buffer | null = null;
function getWasmBinary(): Buffer {
  if (!wasmBinaryCache) {
    const require = createRequire(import.meta.url);
    const wasmDir = dirname(require.resolve('wasm-audio-resampler/app/soxr_wasm.js'));
    wasmBinaryCache = readFileSync(resolve(wasmDir, 'soxr_wasm.wasm'));
  }
  return wasmBinaryCache;
}

/**
 * Stateful PCM16 mono stream resampler backed by libsoxr (WASM).
 *
 * Unlike the stateless `resamplePcm16Mono`, this maintains filter state
 * between processChunk() calls so chunk boundaries are seamless — no
 * click artifacts. Uses VHQ (Very High Quality) sinc interpolation
 * internally via libsoxr.
 *
 * Create one instance per audio stream (per rate pair). When the stream
 * ends, call flush() to drain the internal filter buffer.
 *
 * Usage:
 *   const resampler = new StreamResampler(24000, 16000);
 *   await resampler.init();
 *   const out = resampler.process(frame);   // returns resampled AudioFrame
 *   const tail = resampler.flush();          // drain at end of stream
 */
export class StreamResampler {
  private readonly inputRate: number;
  private readonly outputRate: number;
  private resampler: SoxrResampler | null = null;
  private initialized = false;

  constructor(inputRate: number, outputRate: number) {
    if (inputRate <= 0 || outputRate <= 0) {
      throw new Error(`Invalid sample rates: ${inputRate} -> ${outputRate}`);
    }
    this.inputRate = inputRate;
    this.outputRate = outputRate;
  }

  /** Initialize the WASM resampler. Must be called before process(). */
  async init(): Promise {
    if (this.initialized) return;
    this.resampler = new SoxrResampler(
      1, // mono
      this.inputRate,
      this.outputRate,
      SoxrDatatype.SOXR_INT16,
      SoxrDatatype.SOXR_INT16,
    );
    await this.resampler.init(undefined, { wasmBinary: getWasmBinary() });
    this.initialized = true;
  }

  /** Resample an audio frame. Returns a new frame at the output rate. */
  process(frame: AudioFrame): AudioFrame {
    if (!this.initialized || !this.resampler) {
      throw new Error('StreamResampler not initialized — call init() first');
    }
    if (frame.sampleRate !== this.inputRate) {
      throw new Error(
        `StreamResampler expected ${this.inputRate}Hz input, got ${frame.sampleRate}Hz`
      );
    }

    const input = new Uint8Array(frame.data);
    const output = this.resampler.processChunk(input);

    return {
      data: toArrayBuffer(output),
      sampleRate: this.outputRate,
      format: 'pcm16',
    };
  }

  /**
   * Flush remaining samples from the internal filter buffer.
   * Call once at end of stream. Returns null if nothing to flush.
   */
  flush(): AudioFrame | null {
    if (!this.initialized || !this.resampler) return null;
    try {
      const output = this.resampler.processChunk(new Uint8Array(0));
      if (!output || output.byteLength === 0) return null;
      return {
        data: toArrayBuffer(output),
        sampleRate: this.outputRate,
        format: 'pcm16',
      };
    } catch {
      // WASM resampler may throw on flush if internal state is already freed
      return null;
    }
  }

  /** Whether init() has been called successfully. */
  get isInitialized(): boolean {
    return this.initialized;
  }

  /** The configured input sample rate. */
  get sourceRate(): number {
    return this.inputRate;
  }

  /** The configured output sample rate. */
  get targetRate(): number {
    return this.outputRate;
  }
}

/**
 * Lazy-initialized stream resampler factory.
 *
 * Creates and caches StreamResampler instances keyed by rate pair.
 * Handles async init transparently — first call to resample() awaits
 * init, subsequent calls are synchronous.
 */
export class StreamResamplerPool {
  private readonly resamplers = new Map();
  private readonly pending = new Map<string, Promise>();

  private key(inputRate: number, outputRate: number): string {
    return `${inputRate}:${outputRate}`;
  }

  /**
   * Get or create a resampler for the given rate pair.
   * First call for a rate pair is async (WASM init). Subsequent calls
   * return the cached instance synchronously via getSync().
   */
  async get(inputRate: number, outputRate: number): Promise {
    const k = this.key(inputRate, outputRate);

    const cached = this.resamplers.get(k);
    if (cached) return cached;

    const existing = this.pending.get(k);
    if (existing) return existing;

    const promise = (async () => {
      const resampler = new StreamResampler(inputRate, outputRate);
      await resampler.init();
      this.resamplers.set(k, resampler);
      this.pending.delete(k);
      return resampler;
    })();

    this.pending.set(k, promise);
    return promise;
  }

  /**
   * Get a previously-initialized resampler synchronously.
   * Returns null if not yet initialized for this rate pair.
   */
  getSync(inputRate: number, outputRate: number): StreamResampler | null {
    return this.resamplers.get(this.key(inputRate, outputRate)) ?? null;
  }

  /** Flush and clear all cached resamplers. */
  clear(): void {
    for (const r of this.resamplers.values()) {
      r.flush();
    }
    this.resamplers.clear();
    this.pending.clear();
  }
}

/** Extract a proper ArrayBuffer from a typed array output. */
function toArrayBuffer(view: Uint8Array): ArrayBuffer {
  if (view.byteOffset === 0 && view.byteLength === view.buffer.byteLength) {
    return view.buffer as ArrayBuffer;
  }
  return view.buffer.slice(view.byteOffset, view.byteOffset + view.byteLength) as ArrayBuffer;
}



