          {selectedPrompt?.name || 'Prompt'}




          {promptDirty && (


              Unsaved

          )}

          {isActiveVersion && (


              Active

          )}


            {promptVersions.map((version) => (

                {version}
                {selectedPrompt?.activeVersion === version ? ' (active)' : ''}

            ))}



            Save as New



            Set Active




      {/* Agent Config - only for subagent prompts */}
      {isSubagent && (





              Agent Config

            {configDirty && (


                Unsaved

            )}





              Model




              Max Steps





                Save Config




      )}

      {/* Error message */}
      {promptsError && (


          {promptsError}

      )}

      {/* Content area */}


        {promptsLoading && !promptContent ? (


            Loading...

        ) : (

        )}


  );
}



