// Settings: Voice Pipeline - Mode, provider, model, voice selection
// Ported from VoiceRuntimePanel.tsx lines 603-804
// ═══════════════════════════════════════════════════════════════════════════

import { useCallback } from 'react';
import { useConfigStore, getPathValue } from '../../stores/config-store';
import { SettingsSection, SettingsField, AdvancedToggle } from './SettingsSection';
import { VoiceSelector } from '../voice-config/VoiceSelector';
import type {
  VoiceCatalog,
  RuntimeDecomposedStageManifest,
  ProviderVoiceEntry,
} from '../../lib/voice-config-api';

// ─── Helpers ───────────────────────────────────────────────────────────

function asString(value: unknown, fallback = ''): string {
  if (typeof value === 'string') return value;
  if (typeof value === 'number' || typeof value === 'boolean') return String(value);
  return fallback;
}

function withCurrent(options: string[], current: string): string[] {
  if (!current) return options;
  return options.includes(current) ? options : [current, ...options];
}

function pickMatchingOrFirst(options: string[], current: string, fallback = ''): string {
  if (options.length === 0) return fallback;
  return options.includes(current) ? current : options[0]!;
}

function asVoiceList(catalog: VoiceCatalog | null, key: string | undefined): ProviderVoiceEntry[] {
  if (!catalog || !key) return [];
  return catalog.providerCatalog[key]?.voices ?? [];
}

function asModelList(catalog: VoiceCatalog | null, key: string | undefined): string[] {
  if (!catalog || !key) return [];
  return catalog.providerCatalog[key]?.models ?? [];
}

function stageDescription(stage: RuntimeDecomposedStageManifest): string {
  if (stage.id === 'stt') return 'Transcribes user audio input before LLM routing.';
  if (stage.id === 'llm') return 'Runs reasoning and tool logic on each completed transcript turn.';
  return 'Synthesizes assistant responses back to audio.';
}

function AuthProfileSelect({
  value,
  onChange,
  profileNames,
}: {
  value: string | undefined;
  onChange: (value: string | undefined) => void;
  profileNames: string[];
}) {
  return (

       onChange(e.target.value || undefined)}
      >
        (provider default)
        {profileNames.map((name) => (
          {name}
        ))}


  );
}

// ─── Main Component ────────────────────────────────────────────────────

export function SettingsVoicePipeline() {
  const config = useConfigStore((s) => s.config);
  const catalog = useConfigStore((s) => s.catalog);
  const catalogError = useConfigStore((s) => s.catalogError);
  const updatePath = useConfigStore((s) => s.updatePath);
  const updateMany = useConfigStore((s) => s.updateMany);
  const advancedVisible = useConfigStore((s) => s.advancedVisible['voice-pipeline']);
  const toggleAdvanced = useConfigStore((s) => s.toggleAdvanced);

  const manifest = catalog?.manifest;
  const modeOptions = manifest?.modes ?? ['voice-to-voice', 'decomposed'];
  const realtimeProviderPath = manifest?.realtimeProviderPath ?? 'voice.voiceToVoice.provider';
  const realtimeProviders = manifest?.realtimeProviders ?? [];

  const selectedRealtimeProviderId = config
    ? asString(getPathValue(config, realtimeProviderPath), config.voice.voiceToVoice.provider)
    : '';
  const selectedRealtimeProvider =
    realtimeProviders.find((p) => p.id === selectedRealtimeProviderId) ??
    realtimeProviders[0];

  const isDecomposed = config?.voice.mode === 'decomposed';
  const authProfileNames = catalog?.authProfileNames ?? [];

  const handleRealtimeProviderChange = useCallback(
    (nextProviderId: string) => {
      if (!config) return;
      const provider = realtimeProviders.find((p) => p.id === nextProviderId);
      if (!provider) {
        updatePath(realtimeProviderPath, nextProviderId);
        return;
      }

      const updates: Array<{ path: string; value: unknown }> = [
        { path: realtimeProviderPath, value: nextProviderId },
      ];

      for (const field of provider.fields) {
        if (field.kind !== 'model' && field.kind !== 'voice') continue;
        const current = asString(getPathValue(config, field.path));

        if (field.kind === 'model') {
          const options = asModelList(catalog, field.catalogKey);
          const next = pickMatchingOrFirst(options, current, current);
          if (next) updates.push({ path: field.path, value: next });
        } else {
          const voiceOptions = asVoiceList(catalog, field.catalogKey).map((v) => v.id);
          const next = pickMatchingOrFirst(voiceOptions, current, current);
          if (next) updates.push({ path: field.path, value: next });
        }
      }

      updateMany(updates);
    },
    [config, catalog, realtimeProviders, realtimeProviderPath, updatePath, updateMany]
  );

  const handleDecomposedProviderChange = useCallback(
    (stage: RuntimeDecomposedStageManifest, nextProviderId: string) => {
      if (!config) return;
      const provider = stage.providers.find((p) => p.id === nextProviderId);
      const updates: Array<{ path: string; value: unknown }> = [
        { path: stage.providerPath, value: nextProviderId },
      ];

      if (provider?.modelCatalogKey) {
        const modelOptions = asModelList(catalog, provider.modelCatalogKey);
        const currentModel = asString(getPathValue(config, stage.modelPath));
        const nextModel = pickMatchingOrFirst(modelOptions, currentModel, currentModel);
        if (nextModel) updates.push({ path: stage.modelPath, value: nextModel });
      }

      if (provider?.voiceCatalogKey && stage.voicePath) {
        const voiceOptions = asVoiceList(catalog, provider.voiceCatalogKey).map((v) => v.id);
        const currentVoice = asString(getPathValue(config, stage.voicePath));
        const nextVoice = pickMatchingOrFirst(voiceOptions, currentVoice, currentVoice);
        if (nextVoice) {
          updates.push({ path: stage.voicePath, value: nextVoice });
          updates.push({ path: stage.modelPath, value: nextVoice });
        }
      }

      updateMany(updates);
    },
    [config, catalog, updateMany]
  );

  if (!config) return null;

  if (catalogError) {
    return (



          Failed to load provider catalog: {catalogError}


    );
  }

  return (
    <>
      {/* Mode & Provider */}


           updatePath('voice.mode', e.target.value)}
          >
            {modeOptions.map((mode) => (
              {mode}
            ))}



        {!isDecomposed ? (

             handleRealtimeProviderChange(e.target.value)}
            >
              {realtimeProviders.map((provider) => (
                {provider.label}
              ))}


        ) : (



        )}


           updatePath('voice.language', e.target.value)}
          />



      {/* Realtime Provider Fields */}
      {!isDecomposed && selectedRealtimeProvider && (

          {selectedRealtimeProvider.fields.map((field) => {
            const value = getPathValue(config, field.path);
            const current = asString(value);

            if (field.kind === 'model') {
              const options = withCurrent(asModelList(catalog, field.catalogKey), current);
              return (

                   updatePath(field.path, e.target.value)}>
                    {options.map((opt) => (
                      {opt}
                    ))}


              );
            }

            if (field.kind === 'voice') {
              const voices = asVoiceList(catalog, field.catalogKey);
              return (
                 updatePath(field.path, voiceId)}
                  languageFilter={config.voice.language}
                />
              );
            }

            if (field.kind === 'auth') {
              return (
                 updatePath(field.path, next)}
                  profileNames={authProfileNames}
                />
              );
            }

            if (field.kind === 'select') {
              return (

                   updatePath(field.path, e.target.value)}>
                    {(field.options ?? []).map((opt) => (
                      {opt.label}
                    ))}


              );
            }

            return (

                 updatePath(field.path, e.target.value)}
                />

            );
          })}

      )}

      {/* Decomposed Stage Cards */}
      {isDecomposed && (manifest?.decomposedStages ?? []).map((stage) => {
        const selectedProviderId = asString(getPathValue(config, stage.providerPath));
        const selectedProvider =
          stage.providers.find((p) => p.id === selectedProviderId) ??
          stage.providers[0];
        const modelOptions = selectedProvider?.modelCatalogKey
          ? withCurrent(
            asModelList(catalog, selectedProvider.modelCatalogKey),
            asString(getPathValue(config, stage.modelPath))
          )
          : [];
        const voiceOptions = selectedProvider?.voiceCatalogKey
          ? asVoiceList(catalog, selectedProvider.voiceCatalogKey)
          : [];
        const supportsVoiceCatalog = Boolean(selectedProvider?.voiceCatalogKey);
        const hasVoiceOptions = voiceOptions.length > 0;

        return (


               handleDecomposedProviderChange(stage, e.target.value)}
              >
                {stage.providers.map((provider) => (
                  {provider.label}
                ))}



            {stage.voicePath ? (
              <>
                 updatePath(stage.authPath, next)}
                  profileNames={authProfileNames}
                />
                {supportsVoiceCatalog && hasVoiceOptions ? (
                   {
                      updateMany([
                        { path: stage.modelPath, value: voiceId },
                        { path: stage.voicePath as string, value: voiceId },
                      ]);
                    }}
                    languageFilter={config.voice.language}
                  />
                ) : (
                  <>
                    {modelOptions.length > 0 ? (

                         updatePath(stage.modelPath, e.target.value)}
                        >
                          {modelOptions.map((model) => (
                            {model}
                          ))}


                    ) : (

                         updatePath(stage.modelPath, e.target.value)}
                        />

                    )}

                       updatePath(stage.voicePath as string, e.target.value)}
                      />

                  </>
                )}
              </>
            ) : (
              <>
                {modelOptions.length > 0 ? (

                     updatePath(stage.modelPath, e.target.value)}
                    >
                      {modelOptions.map((model) => (
                        {model}
                      ))}


                ) : (

                     updatePath(stage.modelPath, e.target.value)}
                    />

                )}
                 updatePath(stage.authPath, next)}
                  profileNames={authProfileNames}
                />
              </>
            )}

        );
      })}

       toggleAdvanced('voice-pipeline')}
      />

      {advancedVisible && (



            {isDecomposed
              ? `Pipeline: ${(manifest?.decomposedStages ?? []).map((s) => s.id.toUpperCase()).join(' -> ')}`
              : `Provider: ${selectedRealtimeProvider?.id ?? 'unknown'}`
            }
            {'\n'}Manifest providers: {realtimeProviders.map((p) => p.id).join(', ')}


      )}
    </>
  );
}



import { useEffect, useRef, useState, useCallback } from 'react';
import { motion } from 'framer-motion';
import { useUnifiedSessionsStore, useSessions, type SessionState } from '../../stores';
import { getTerminalClient, releaseTerminalClient } from '../../lib/terminal-client';
import type { TerminalClient, TerminalStatus } from '../../lib/terminal-client';
import type { StageItem, SessionStatus } from '../../types';

interface TerminalStageProps {
  stage: StageItem;
}

const SESSION_STATUS_CONFIG: Record = {
  pending: { label: 'Init', color: 'text-orange-500', pulse: true },
  running: { label: 'Running', color: 'text-blue-500', pulse: true },
  waiting_for_input: { label: 'Awaiting', color: 'text-purple-500', pulse: true },
  finished: { label: 'Done', color: 'text-green-500', pulse: false },
  error: { label: 'Error', color: 'text-red-500', pulse: false },
  cancelled: { label: 'Cancelled', color: 'text-muted-foreground', pulse: false },
};

const TERMINAL_STATUS_CONFIG: Record = {
  connecting: { label: 'Connecting', color: 'text-orange-500' },
  connected: { label: 'Connected', color: 'text-green-500' },
  disconnected: { label: 'Offline', color: 'text-muted-foreground' },
  error: { label: 'Error', color: 'text-red-500' },
};

export function TerminalStage({ stage }: TerminalStageProps) {
  const containerRef = useRef(null);
  const clientRef = useRef(null);
  const [terminalStatus, setTerminalStatus] = useState('disconnected');
  const [errorMessage, setErrorMessage] = useState(null);
  const [exitCode, setExitCode] = useState(null);

  const sessionId = stage.data?.sessionId;
  const sessions = useSessions();
  const minimizeTree = useUnifiedSessionsStore((s) => s.minimizeTree);

  const session = sessionId ? sessions.get(sessionId) : undefined;
  const sessionStatus = session?.status || 'pending';
  const sessionStatusConfig = SESSION_STATUS_CONFIG[sessionStatus as SessionStatus];
  const terminalStatusConfig = TERMINAL_STATUS_CONFIG[terminalStatus];

  const handleStatusChange = useCallback((status: TerminalStatus, error?: string) => {
    setTerminalStatus(status);
    setErrorMessage(error || null);
  }, []);

  const handleExit = useCallback((code: number) => {
    setExitCode(code);
  }, []);

  useEffect(() => {
    if (!sessionId || !containerRef.current) return;
    const client = getTerminalClient(sessionId, {
      fontSize: 13,
      onStatusChange: handleStatusChange,
      onExit: handleExit,
    });
    clientRef.current = client;
    client.connect(sessionId, containerRef.current).catch((error) => {
      console.error('[TerminalStage] Failed to connect:', error);
    });
    return () => {
      releaseTerminalClient(sessionId);
      clientRef.current = null;
    };
  }, [sessionId, handleStatusChange, handleExit]);

  useEffect(() => {
    if (!containerRef.current) return;
    const resizeObserver = new ResizeObserver(() => {
      if (clientRef.current && containerRef.current) {
        const charWidth = 8;
        const charHeight = 17;
        const containerWidth = containerRef.current.clientWidth;
        const containerHeight = containerRef.current.clientHeight;
        const cols = Math.floor(containerWidth / charWidth);
        const rows = Math.floor(containerHeight / charHeight);
        if (cols > 0 && rows > 0) {
          clientRef.current.resize(cols, rows);
        }
      }
    });
    resizeObserver.observe(containerRef.current);
    return () => resizeObserver.disconnect();
  }, []);

  const handleMinimize = () => {
    if (sessionId) minimizeTree();
  };

  const handleReconnect = () => {
    if (sessionId && containerRef.current) {
      const client = getTerminalClient(sessionId, {
        fontSize: 13,
        onStatusChange: handleStatusChange,
        onExit: handleExit,
      });
      clientRef.current = client;
      client.connect(sessionId, containerRef.current).catch((error) => {
        console.error('[TerminalStage] Reconnect failed:', error);
      });
    }
  };

  return (

      {/* Header */}




          ▣



              Session {sessionId?.slice(0, 8) || '--------'}


              {session?.goal || stage.title}








            {terminalStatusConfig.label}




            {sessionStatusConfig.label}


            Minimize




      {/* Terminal Container */}


        {terminalStatus === 'connecting' && (



◎

Connecting to session...

        )}

        {terminalStatus === 'error' && (



⚠

{errorMessage || 'Connection error'}

              Reconnect


        )}

        {terminalStatus === 'disconnected' && exitCode === null && (



◇

Disconnected from session

              Reconnect


        )}

        {exitCode !== null && (



{exitCode === 0 ? '✓' : '✗'}


              Session ended{exitCode !== 0 ? ` (exit code: ${exitCode})` : ''}


        )}


  );
}



import { useState, useEffect, useCallback } from 'react';

interface RecordingStatus {
  recording: boolean;
  eventCount: number;
}

interface ExportedScenario {
  id: string;
  name: string;
  description: string;
  capturedAt: string;
  events: unknown[];
}

const API_BASE = '/api/recording';

export function RecordButton() {
  const [status, setStatus] = useState({ recording: false, eventCount: 0 });
  const [isExporting, setIsExporting] = useState(false);
  const [lastExport, setLastExport] = useState(null);
  const [error, setError] = useState(null);

  useEffect(() => {
    if (!status.recording) return;
    const interval = setInterval(async () => {
      try {
        const res = await fetch(`${API_BASE}/status`);
        if (res.ok) {
          const data = await res.json();
          setStatus(data);
        }
      } catch { /* ignore */ }
    }, 1000);
    return () => clearInterval(interval);
  }, [status.recording]);

  const startRecording = useCallback(async () => {
    setError(null);
    setLastExport(null);
    try {
      const res = await fetch(`${API_BASE}/start`, { method: 'POST' });
      if (res.ok) {
        setStatus({ recording: true, eventCount: 0 });
      } else {
        setError('Failed to start recording');
      }
    } catch (err) {
      setError('Connection error');
      console.error('[RecordButton] Start error:', err);
    }
  }, []);

  const stopAndExport = useCallback(async () => {
    setIsExporting(true);
    setError(null);
    try {
      await fetch(`${API_BASE}/stop`, { method: 'POST' });
      const name = prompt('Scenario name:', 'Marvin CLI Session') || 'recorded-scenario';
      const description = prompt('Description:', 'Captured real conversation') || '';
      const res = await fetch(`${API_BASE}/export`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name, description, saveToFile: true }),
      });
      if (res.ok) {
        const scenario = await res.json();
        setLastExport(scenario);
        setStatus({ recording: false, eventCount: 0 });
        await navigator.clipboard.writeText(JSON.stringify(scenario, null, 2));
      } else {
        setError('Export failed');
      }
    } catch (err) {
      setError('Export error');
      console.error('[RecordButton] Export error:', err);
    } finally {
      setIsExporting(false);
    }
  }, []);

  const downloadJson = useCallback(() => {
    if (!lastExport) return;
    const blob = new Blob([JSON.stringify(lastExport, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${lastExport.id}.json`;
    a.click();
    URL.revokeObjectURL(url);
  }, [lastExport]);

  return (
    <>


        {status.recording ? (


            REC
            {status.eventCount}

        ) : (


            Capture

        )}

        {error && {error}}


      {lastExport && (






              Captured: {lastExport.name}



              {lastExport.events.length} events — copied to clipboard



            Download

           setLastExport(null)}
          >
            ×


      )}
    </>
  );
}



