import { createContext, useContext } from 'react';
import type { AudioController } from '../lib/audio';

/**
 * React context for the AudioController ref.
 * Allows any component to query real-time playback position
 * via audioController.getPlaybackPositionMs() without prop drilling.
 */
export const AudioControllerContext = createContext<React.RefObject>(
  { current: null }
);

export function useAudioControllerRef(): React.RefObject {
  return useContext(AudioControllerContext);
}



/**
 * Audio Session Hook - Manages voice session state and audio I/O.
 *
 * Provides:
 * - Profile selection (Jarvis / Marvin)
 * - Recording state management
 * - Audio capture/playback coordination
 * - Uses shared WebSocket from useWebSocket hook
 * - Master/Replica awareness for multi-client support
 */

import { useState, useEffect, useRef, useCallback } from 'react';
import { AudioController } from '../lib/audio';
import { useConnectionState, useVoiceState, useServiceState } from '../stores';
import { useWebSocket } from './useWebSocket';

export type ProfileId = 'jarvis' | 'marvin';

export type AudioMode = 'web' | 'local';

export interface AudioSessionState {
  /** Currently selected profile */
  activeProfile: ProfileId;
  /** Set the active profile */
  setActiveProfile: (profile: ProfileId) => void;
  /** Whether recording is active */
  isRecording: boolean;
  /** Toggle recording on/off */
  toggleSession: () => Promise;
  /** Stop the session immediately */
  stopSession: () => void;
  /** Whether audio system is initializing */
  isInitializing: boolean;
  /** Error message if any */
  error: string | null;
  /** Whether this client is the master (handles audio I/O) */
  isMaster: boolean;
  /** Request to become the master client */
  requestMaster: () => void;
  /** Whether the backend service is active (soft power) */
  serviceActive: boolean;
  /** Current audio mode (web/local) */
  audioMode: AudioMode;
  /** Toggle service on/off */
  toggleService: () => void;
  /** Set audio mode */
  setAudioMode: (mode: AudioMode) => void;
  /** AudioController ref for playback position queries */
  audioControllerRef: React.RefObject;
}

export function useAudioSession(): AudioSessionState {
  const [activeProfile, setActiveProfile] = useState('jarvis');
  const [isRecording, setIsRecording] = useState(false);
  const [isInitializing, setIsInitializing] = useState(false);
  const [error, setError] = useState(null);

  const audioControllerRef = useRef(null);
  const prevStateRef = useRef(null);
  const dropPlaybackUntilMsRef = useRef(0);
  // Track state in ref for use in audio callback (avoids stale closure)
  const stateRef = useRef('idle');

  const { voiceState } = useVoiceState();
  const { connected, isMaster } = useConnectionState();
  const { serviceActive, audioMode } = useServiceState();

  // Keep stateRef in sync with state
  useEffect(() => {
    stateRef.current = voiceState;
  }, [voiceState]);

  // Use shared WebSocket connection
  const { send, sendBinary, requestMaster } = useWebSocket();

  // Initialize audio controller
  useEffect(() => {
    audioControllerRef.current = new AudioController({
      onError: (err) => {
        console.error('[AudioSession] Error:', err);
        setError(err.message);
      },
    });

    return () => {
      if (audioControllerRef.current) {
        audioControllerRef.current.stop();
      }
    };
  }, []);

  // Listen for incoming audio from WebSocket
  useEffect(() => {
    const handleAudio = (event: CustomEvent) => {
      if (audioControllerRef.current) {
        try {
          // Drop stale chunks right after an interrupt/stop to avoid hearing
          // already-sent audio from the cancelled turn.
          if (Date.now() < dropPlaybackUntilMsRef.current) {
            return;
          }

          // Only accept incoming transport audio while the agent is speaking.
          // This prevents stale turn audio from continuing during listening/thinking.
          if (stateRef.current !== 'speaking') {
            return;
          }

          audioControllerRef.current.playAudio(event.detail);
        } catch (err) {
          console.error('[AudioSession] Error playing audio:', err);
        }
      }
    };

    window.addEventListener('ws-audio', handleAudio as EventListener);

    return () => {
      window.removeEventListener('ws-audio', handleAudio as EventListener);
    };
  }, []);

  // Listen for audio control messages (interrupt from server when user speaks over agent)
  useEffect(() => {
    const handleAudioControl = (event: CustomEvent) => {
      const action = event.detail;
      if (action === 'interrupt' || action === 'stop') {
        dropPlaybackUntilMsRef.current = Date.now() + 120;
        if (audioControllerRef.current) {
          audioControllerRef.current.interrupt();
        }
      } else if (action === 'start') {
        dropPlaybackUntilMsRef.current = 0;
      }
    };

    window.addEventListener('ws-audio-control', handleAudioControl as EventListener);

    return () => {
      window.removeEventListener('ws-audio-control', handleAudioControl as EventListener);
    };
  }, []);

  // Stop recording if WebSocket disconnects
  useEffect(() => {
    if (!connected && isRecording) {
      console.log('[AudioSession] WebSocket disconnected, stopping recording');
      if (audioControllerRef.current) {
        audioControllerRef.current.stop();
      }
      setIsRecording(false);
      setError('Connection lost');
    }
  }, [connected, isRecording]);

  // Toggle service on/off (soft power)
  const toggleService = useCallback(() => {
    if (serviceActive) {
      console.log('[AudioSession] Stopping service');
      send('client_command', { command: 'stop_service' });
    } else {
      console.log('[AudioSession] Starting service');
      send('client_command', { command: 'start_service' });
    }
  }, [serviceActive, send]);

  // Set audio mode (web/local)
  const setAudioModeCmd = useCallback((mode: AudioMode) => {
    console.log('[AudioSession] Setting audio mode:', mode);
    send('client_command', { command: 'set_audio_mode', mode });
  }, [send]);

  // Toggle session on/off
  const toggleSession = useCallback(async () => {
    console.log('[AudioSession] toggleSession called, isRecording:', isRecording, 'isMaster:', isMaster, 'serviceActive:', serviceActive);

    // Check if service is active
    if (!serviceActive && !isRecording) {
      console.log('[AudioSession] Service is not active, cannot start recording');
      setError('Service is not active');
      return;
    }

    if (isRecording) {
      // Stop recording
      console.log('[AudioSession] Stopping recording');
      if (audioControllerRef.current) {
        audioControllerRef.current.stop();
      }
      send('client_command', { command: 'stop_session' });
      setIsRecording(false);
      setError(null);
    } else {
      // Start recording
      console.log('[AudioSession] Starting recording with profile:', activeProfile);
      setIsInitializing(true);
      setError(null);

      try {
        // Send start command FIRST so backend is ready for audio
        console.log('[AudioSession] Sending start_session command');
        send('client_command', { command: 'start_session', profile: activeProfile });

        if (audioControllerRef.current) {
          // Set up audio callback to send via shared WebSocket
          let audioChunkCount = 0;
          audioControllerRef.current.setOnAudio((data) => {
            // Keep streaming microphone audio even while agent is speaking/thinking.
            // This enables fast barge-in and provider-native turn detection.
            audioChunkCount++;
            if (audioChunkCount <= 3 || audioChunkCount % 50 === 0) {
              console.log(`[AudioSession] Sending audio chunk #${audioChunkCount}, size: ${data.byteLength}`);
            }
            sendBinary(data);
          });
          await audioControllerRef.current.start();
          console.log('[AudioSession] Audio capture started');
        }

        setIsRecording(true);
      } catch (err) {
        console.error('[AudioSession] Failed to start:', err);
        setError((err as Error).message || 'Failed to start audio');
        setIsRecording(false);
      } finally {
        setIsInitializing(false);
      }
    }
  }, [isRecording, activeProfile, send, sendBinary, isMaster, serviceActive]);

  // Stop session immediately
  const stopSession = useCallback(() => {
    if (audioControllerRef.current) {
      audioControllerRef.current.stop();
    }
    send('client_command', { command: 'stop_session' });
    setIsRecording(false);
  }, [send]);

  // Auto-stop recording when agent state TRANSITIONS to idle (not on initial idle)
  useEffect(() => {
    const prevState = prevStateRef.current;
    prevStateRef.current = voiceState;

    // Only stop if we transitioned FROM a non-idle state TO idle
    // This prevents stopping immediately when starting (state is already idle)
    if (
      voiceState === 'idle' &&
      prevState !== null &&
      prevState !== 'idle' &&
      isRecording &&
      connected
    ) {
      console.log(`[AudioSession] State transitioned ${prevState} → idle, stopping`);
      if (audioControllerRef.current) {
        audioControllerRef.current.stop();
      }
      setIsRecording(false);
    }
  }, [voiceState, isRecording, connected]);

  return {
    activeProfile,
    setActiveProfile,
    isRecording,
    toggleSession,
    stopSession,
    isInitializing,
    error,
    isMaster,
    requestMaster,
    serviceActive,
    audioMode,
    toggleService,
    setAudioMode: setAudioModeCmd,
    audioControllerRef,
  };
}



// ═══════════════════════════════════════════════════════════════════════════
// WebSocket Hook - Real-time connection to voice-agent
// ═══════════════════════════════════════════════════════════════════════════

import { useEffect, useRef } from 'react';
import { useUnifiedSessionsStore, handleWebSocketMessage } from '../stores';
import type { WSMessage } from '../types';

// Determine WebSocket URL based on environment
const getWsUrl = () => {
  // If demo mode is explicitly enabled, return null
  if (process.env.PUBLIC_DEMO_MODE === 'true') return null;

  // In development mode, use the dev server proxy to avoid cross-origin issues
  // The proxy at /ws forwards to the Pi's WebSocket server
  if (process.env.NODE_ENV !== 'production') {
    const protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
    return `${protocol}//${window.location.host}/ws`;
  }

  // If explicit URL is set (production), use it
  const envUrl = process.env.PUBLIC_WS_URL;
  if (envUrl) return envUrl;

  // In production build served from Pi, use same host with port 3001
  const protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
  const host = window.location.hostname;
  return `${protocol}//${host}:3001`;
};

const WS_URL = getWsUrl();
const RECONNECT_DELAY = 3000;
const MAX_RECONNECT_ATTEMPTS = 10;
const DEMO_MODE = !WS_URL;

// Module-level singleton to prevent duplicate connections across React StrictMode remounts
let globalWs: WebSocket | null = null;
let globalWsRefCount = 0;

export function useWebSocket() {
  const wsRef = useRef(null);
  const reconnectAttemptsRef = useRef(0);
  const reconnectTimeoutRef = useRef<ReturnType | null>(null);
  const isCleaningUpRef = useRef(false);
  const isConnectingRef = useRef(false);

  // Get stable references from unified store
  const setWsError = useUnifiedSessionsStore((s) => s.setWsError);

  // Use unified message handler directly (legacy stores deleted)
  const handleMessage = handleWebSocketMessage;

  useEffect(() => {
    // Skip WebSocket connection in demo mode
    if (DEMO_MODE) {
      console.log('[WS] Demo mode - skipping WebSocket connection');
      return;
    }

    // Increment ref count for this hook instance
    globalWsRefCount++;

    // Reset cleanup flag on mount (important for React Strict Mode double-mount)
    isCleaningUpRef.current = false;

    const connect = () => {
      // Prevent multiple simultaneous connection attempts
      if (isConnectingRef.current || isCleaningUpRef.current) {
        console.log(`[WS] Skipping connect: connecting=${isConnectingRef.current}, cleaning=${isCleaningUpRef.current}`);
        return;
      }

      // Reuse existing global connection if available and open
      if (globalWs?.readyState === WebSocket.OPEN) {
        console.log('[WS] Reusing existing connection');
        wsRef.current = globalWs;
        // Connection state is tracked via clientId from 'welcome' message
        return;
      }

      // Also check if globalWs is CONNECTING (still establishing)
      if (globalWs?.readyState === WebSocket.CONNECTING) {
        console.log('[WS] Connection in progress, waiting...');
        wsRef.current = globalWs;
        // The onopen handler will set connected when ready
        return;
      }

      if (wsRef.current?.readyState === WebSocket.OPEN) {
        return;
      }

      // Close any existing connection first
      if (wsRef.current) {
        wsRef.current.close();
        wsRef.current = null;
      }
      if (globalWs) {
        globalWs.close();
        globalWs = null;
      }

      try {
        isConnectingRef.current = true;
        console.log(`[WS] Connecting to ${WS_URL}...`);
        const ws = new WebSocket(WS_URL);

        ws.onopen = () => {
          console.log('[WS] Connected, readyState:', ws.readyState);
          isConnectingRef.current = false;
          globalWs = ws; // Store in global singleton
          wsRef.current = ws; // Ensure local ref is also set
          // Connection state tracked via 'welcome' message which sets clientId
          setWsError(null);
          reconnectAttemptsRef.current = 0;
        };

        ws.binaryType = 'arraybuffer';

        ws.onmessage = (event) => {
          // Handle binary audio data
          if (event.data instanceof ArrayBuffer) {
            // Dispatch custom event for audio playback
            window.dispatchEvent(new CustomEvent('ws-audio', { detail: event.data }));
            return;
          }

          try {
            const msg: WSMessage = JSON.parse(event.data);
            handleMessage(msg);
          } catch (err) {
            console.error('[WS] Failed to parse message:', err);
          }
        };

        ws.onerror = (event) => {
          console.error('[WS] Error:', event);
          isConnectingRef.current = false;
          setWsError('WebSocket connection error');
        };

        ws.onclose = (event) => {
          console.log(`[WS] Disconnected (code: ${event.code}, reason: ${event.reason || 'none'}, wasClean: ${event.wasClean})`);
          isConnectingRef.current = false;
          // Reset connection state - clientId null means disconnected
          useUnifiedSessionsStore.getState().setClientIdentity(null, false);
          wsRef.current = null;
          globalWs = null;

          // Don't reconnect if we're cleaning up
          if (isCleaningUpRef.current) {
            return;
          }

          // Attempt reconnect for disconnections
          if (reconnectAttemptsRef.current < MAX_RECONNECT_ATTEMPTS) {
            reconnectAttemptsRef.current++;
            const delay = RECONNECT_DELAY * Math.min(reconnectAttemptsRef.current, 5);
            console.log(`[WS] Reconnecting in ${delay}ms (attempt ${reconnectAttemptsRef.current})`);
            reconnectTimeoutRef.current = setTimeout(connect, delay);
          } else {
            setWsError('Max reconnection attempts reached');
          }
        };

        wsRef.current = ws;
        globalWs = ws;
      } catch (err) {
        console.error('[WS] Connection error:', err);
        isConnectingRef.current = false;
        setWsError('Failed to connect');
      }
    };

    // Initial connection
    connect();

    // Cleanup on unmount
    return () => {
      globalWsRefCount--;
      isCleaningUpRef.current = true;
      if (reconnectTimeoutRef.current) {
        clearTimeout(reconnectTimeoutRef.current);
        reconnectTimeoutRef.current = null;
      }

      // Delay socket close to handle React StrictMode double-mount
      // StrictMode unmounts then immediately remounts, so we wait briefly
      // to see if a remount happens before actually closing the socket
      const socketToClose = wsRef.current;
      wsRef.current = null;

      setTimeout(() => {
        // Only close if still at 0 refs after delay (no remount happened)
        if (globalWsRefCount === 0 && socketToClose && socketToClose === globalWs) {
          console.log('[WS] Closing socket (no remount after 500ms)');
          socketToClose.close();
          globalWs = null;
          // Reset connection state
          useUnifiedSessionsStore.getState().setClientIdentity(null, false);
        }
      }, 500); // Increased delay for better StrictMode handling
    };
  }, []); // Empty dependency array - only run on mount/unmount

  const send = (type: string, payload: unknown) => {
    // Use globalWs as authoritative source (handles StrictMode race conditions)
    const ws = wsRef.current ?? globalWs;
    if (ws?.readyState === WebSocket.OPEN) {
      ws.send(JSON.stringify({ type, payload }));
    } else {
      console.warn('[WS] Cannot send - not connected', {
        wsRef: wsRef.current?.readyState,
        globalWs: globalWs?.readyState,
      });
    }
  };

  const sendBinary = (data: ArrayBuffer) => {
    // Use globalWs as authoritative source (handles StrictMode race conditions)
    const ws = wsRef.current ?? globalWs;
    if (ws?.readyState === WebSocket.OPEN) {
      ws.send(data);
    }
  };

  const getSocket = () => wsRef.current;

  const disconnect = () => {
    isCleaningUpRef.current = true;
    if (reconnectTimeoutRef.current) {
      clearTimeout(reconnectTimeoutRef.current);
    }
    if (wsRef.current) {
      wsRef.current.close();
      wsRef.current = null;
    }
    // Reset connection state
    useUnifiedSessionsStore.getState().setClientIdentity(null, false);
  };

  const reconnect = () => {
    isCleaningUpRef.current = false;
    reconnectAttemptsRef.current = 0;
    if (wsRef.current) {
      wsRef.current.close();
    }
  };

  /**
   * Request to become the Master client (audio I/O controller).
   * Will be denied if agent is currently thinking/speaking.
   */
  const requestMaster = () => {
    send('request_master', {});
  };

  /**
   * Notify backend which session the client is focused on.
   * Used for routing text input to the correct subagent.
   */
  const sendFocusSession = (sessionId: string | null) => {
    send('focus_session', { sessionId });
  };

  /**
   * Send text input to the currently focused session.
   * Backend routes to the appropriate subagent handler.
   */
  const sendSessionInput = (text: string) => {
    send('session_input', { text });
  };

  return { disconnect, send, sendBinary, getSocket, reconnect, requestMaster, sendFocusSession, sendSessionInput };
}



// ═══════════════════════════════════════════════════════════════════════════
// VΞRTΞX Types
// ═══════════════════════════════════════════════════════════════════════════

export type AgentState = 'idle' | 'listening' | 'thinking' | 'speaking';

export type MessageRole = 'user' | 'assistant' | 'system';

export interface TranscriptMessage {
  id: string;
  role: MessageRole;
  content: string;
  timestamp: number;
  pending?: boolean; // True when we have an ID but no transcription yet
}

export interface RealtimeEvent {
  id: string;
  type: string;
  timestamp: number;
  data: unknown;
}

// CLI Session types (matching voice-agent)
export type SessionStatus =
  | 'pending'
  | 'running'
  | 'waiting_for_input'
  | 'finished'
  | 'error'
  | 'cancelled';

export interface CliSession {
  id: string;
  goal: string;
  status: SessionStatus;
  mac_session_id: string | null;
  parent_id: string | null;
  thread_id: string | null;
  created_at: string;
  updated_at: string;
}

export interface CliEvent {
  id: number;
  session_id: string;
  event_type: 'created' | 'started' | 'input' | 'output' | 'status_change' | 'error' | 'finished';
  payload: Record | null;
  created_at: string;
}

// Agent profile
export interface AgentProfile {
  name: string;
  wakeWord: string;
  voice: string;
}

// ═══════════════════════════════════════════════════════════════════════════
// WebSocket Message Types (Phase 5: Simplified Protocol)
// ═══════════════════════════════════════════════════════════════════════════
//
// Core types (7):
// - welcome            : Client identity + service state on connect
// - stream_chunk       : All agent message events (AI SDK format)
// - session_tree_update: Session hierarchy changes
// - state_change       : Voice UI state (listening/thinking/speaking)
// - master_changed     : Multi-client coordination
// - service_state_changed: Service active/dormant + audio mode
// - audio_control      : Audio playback control (start/stop/interrupt)
//
// Lifecycle types (3):
// - session_started/ended: Voice session lifecycle
// - cli_session_deleted  : Terminal session cleanup
// - error                : Error messages
//
export type WSMessageType =
  // Core unified protocol
  | 'welcome'               // Client identity on connect
  | 'stream_chunk'          // All agent events (AI SDK format: text-delta, tool-call, etc.)
  | 'session_tree_update'   // Session hierarchy for ThreadRail
  | 'state_change'          // Voice UI state (listening/thinking/speaking/idle)
  | 'master_changed'        // Multi-client master coordination
  | 'service_state_changed' // Service active/dormant + audio mode
  | 'audio_control'         // Audio playback control (start/stop/interrupt)
  // Lifecycle events
  | 'session_started'       // Voice session activated
  | 'session_ended'         // Voice session deactivated
  | 'cli_session_deleted'   // Terminal session removed
  | 'error';                // Error messages

export interface WSMessage {
  type: WSMessageType;
  payload: unknown;
  timestamp: number;
}

// ═══════════════════════════════════════════════════════════════════════════
// WebSocket Payload Types (Phase 5: Simplified)
// ═══════════════════════════════════════════════════════════════════════════

export interface WelcomePayload {
  clientId: string;
  isMaster: boolean;
  serviceActive: boolean;
  audioMode: 'web' | 'local';
}

export interface ServiceStateChangedPayload {
  active: boolean;
  mode: 'web' | 'local';
}

export interface MasterChangedPayload {
  masterId: string;
}

export interface StateChangePayload {
  state: AgentState;
  profile: string | null;
}

export interface SessionStartedPayload {
  sessionId?: string;
  profile?: string;
}

// Activity Block types for UI rendering
export type ActivityBlockType = 'reasoning' | 'tool' | 'content' | 'error';

interface BaseBlock {
  id: string;
  timestamp: number;
  agent: string;
  /** Orchestrator session ID for per-session activity tracking */
  orchestratorId?: string;
}

export interface ReasoningBlock extends BaseBlock {
  type: 'reasoning';
  content: string; // Accumulated reasoning text
  isComplete: boolean;
  durationMs?: number;
}

export interface ToolBlock extends BaseBlock {
  type: 'tool';
  toolName: string;
  toolCallId: string;
  args: Record;
  result?: string;
  isComplete: boolean;
}

export interface ContentBlock extends BaseBlock {
  type: 'content';
  text: string;
}

export interface ErrorBlock extends BaseBlock {
  type: 'error';
  message: string;
}

export type ActivityBlock = ReasoningBlock | ToolBlock | ContentBlock | ErrorBlock;

