// ═══════════════════════════════════════════════════════════════════════════
// Dynamic Prompt Loading from Centralized Prompts Directory
// ═══════════════════════════════════════════════════════════════════════════

/**
 * Mapping from profile names to prompt IDs in the prompts directory.
 */
const PROFILE_PROMPT_MAPPING: Record = {
  jarvis: 'jarvis',
  marvin: 'marvin',
  openclaw: 'openclaw',
};

/**
 * Cache for loaded profile prompts.
 * Key: profile name (lowercase), Value: prompt content
 */
const cachedInstructions = new Map();

/**
 * Load prompts for all voice profiles from the centralized prompts directory.
 *
 * Call this at startup to pre-cache prompts, or prompts will be loaded
 * on-demand when getProfileInstructions is called.
 */
export async function loadProfilePrompts(): Promise {
  const profileNames = Object.keys(PROFILE_PROMPT_MAPPING);

  await Promise.all(
    profileNames.map(async (profileName) => {
      const promptId = PROFILE_PROMPT_MAPPING[profileName]!;
      const prompt = await getActivePrompt(promptId, { agent_name: profileName });
      if (prompt) {
        cachedInstructions.set(profileName, prompt);
        console.log(`[Profiles] Loaded prompt for ${profileName} from prompts/${promptId}`);
      }
    })
  );
}

/**
 * Reload prompts for all profiles (e.g., after editing in the UI).
 */
export async function reloadProfilePrompts(): Promise {
  cachedInstructions.clear();
  await loadProfilePrompts();
}

/**
 * Get instructions for a profile, loading from prompts directory if available.
 *
 * Falls back to inline instructions if not found in prompts directory.
 *
 * @param profileName - Profile name (e.g., "jarvis", "marvin")
 * @param context - Optional interpolation context
 * @returns The profile instructions
 */
export async function getProfileInstructions(
  profileName: string,
  context: InterpolationContext = {}
): Promise {
  const normalizedName = profileName.toLowerCase();

  // Check cache first
  if (cachedInstructions.has(normalizedName)) {
    return cachedInstructions.get(normalizedName)!;
  }

  // Try to load from prompts directory
  const promptId = PROFILE_PROMPT_MAPPING[normalizedName];
  if (promptId) {
    const prompt = await getActivePrompt(promptId, {
      agent_name: profileName,
      ...context,
    });
    if (prompt) {
      cachedInstructions.set(normalizedName, prompt);
      return prompt;
    }
  }

  // Fallback to inline instructions
  const profile = profiles[normalizedName];
  return profile?.instructions ?? '';
}

/**
 * Create a RealtimeAgent from a profile.
 * @param profile - The agent profile configuration
 * @param sessionId - The voice session ID for parent-child tracking
 * @param voiceAgent - Optional voice agent reference for tools that need completion notifications
 */
export function createAgentFromProfile(
  profile: AgentProfile,
  sessionId: string,
  voiceAgent?: VoiceAgent
): RealtimeAgent {
  const tools = getToolsForSession(profile.tools, { sessionId, voiceAgent });

  return new RealtimeAgent({
    name: profile.name,
    instructions: profile.instructions,
    tools,
  });
}

/**
 * Create a RealtimeAgent from a profile with dynamic prompt loading.
 *
 * This async version loads prompts from the centralized prompts directory.
 *
 * @param profile - The agent profile configuration
 * @param sessionId - The voice session ID for parent-child tracking
 * @param voiceAgent - Optional voice agent reference for tools that need completion notifications
 * @param context - Optional interpolation context for prompt variables
 */
export async function createAgentFromProfileAsync(
  profile: AgentProfile,
  sessionId: string,
  voiceAgent?: VoiceAgent,
  context: InterpolationContext = {}
): Promise {
  const tools = getToolsForSession(profile.tools, { sessionId, voiceAgent });

  // Get dynamic instructions (from prompts dir or fallback to inline)
  const instructions = await getProfileInstructions(profile.name, {
    session_id: sessionId,
    ...context,
  });

  return new RealtimeAgent({
    name: profile.name,
    instructions,
    tools,
  });
}

export function getProfileByWakeword(wakeword: string): AgentProfile | undefined {
  return profiles[wakeword];
}

export function getAllWakewords(): string[] {
  return Object.keys(profiles);
}



import { mkdirSync, writeFileSync } from 'fs';
import path from 'path';
import {
  VoiceBenchmarkRecorder,
  evaluateVoiceBenchmark,
  getDefaultRuntimeBenchmarkThresholds,
  type VoiceBenchmarkInput,
  type VoiceBenchmarkReport,
  type VoiceBenchmarkThresholds,
} from '@voiceclaw/voice-runtime';
import type { AgentState, VoiceProviderName, VoiceRuntimeAudio } from './types.js';

interface SessionBenchmarkMeta {
  sessionId: string;
  profile: string;
  provider: VoiceProviderName;
  startedAt: string;
  finishedAt: string;
  reason: 'disconnected' | 'deactivate' | 'connect-failed';
}

interface SessionBenchmarkPayload {
  meta: SessionBenchmarkMeta;
  thresholds: VoiceBenchmarkThresholds;
  input: VoiceBenchmarkInput;
  report: VoiceBenchmarkReport;
}

interface VoiceSessionBenchmarkParams {
  sessionId: string;
  profile: string;
  provider: VoiceProviderName;
  enabled: boolean;
  outputDir: string;
  thresholds: VoiceBenchmarkThresholds;
  now?: () => number;
}

export interface VoiceBenchmarkFinalizeResult {
  report: VoiceBenchmarkReport;
  outputPath?: string;
}

function parseNumber(value: string | undefined): number | undefined {
  if (!value) return undefined;
  const parsed = Number(value);
  if (!Number.isFinite(parsed) || parsed <= 0) return undefined;
  return parsed;
}

export function parseThresholdOverridesFromEnv(): VoiceBenchmarkThresholds {
  return {
    maxFirstAudioLatencyMs: parseNumber(process.env.VOICE_BENCH_MAX_FIRST_AUDIO_MS),
    maxP95ChunkGapMs: parseNumber(process.env.VOICE_BENCH_MAX_P95_CHUNK_GAP_MS),
    maxChunkGapMs: parseNumber(process.env.VOICE_BENCH_MAX_CHUNK_GAP_MS),
    minRealtimeFactor: parseNumber(process.env.VOICE_BENCH_MIN_RTF),
    maxRealtimeFactor: parseNumber(process.env.VOICE_BENCH_MAX_RTF),
    maxDuplicateAssistantFinals: parseNumber(process.env.VOICE_BENCH_MAX_DUP_ASSISTANT_FINALS),
    maxOutOfOrderAssistantItems: parseNumber(process.env.VOICE_BENCH_MAX_OUT_OF_ORDER_ITEMS),
    maxInterruptionP95Ms: parseNumber(process.env.VOICE_BENCH_MAX_INTERRUPT_P95_MS),
  };
}

export function mergeThresholds(
  provider: VoiceProviderName,
  overrides: VoiceBenchmarkThresholds
): VoiceBenchmarkThresholds {
  return {
    ...getDefaultRuntimeBenchmarkThresholds(provider),
    ...overrides,
  };
}

export function resolveOutputDir(): string {
  if (process.env.VOICE_BENCH_OUTPUT_DIR) {
    return path.resolve(process.cwd(), process.env.VOICE_BENCH_OUTPUT_DIR);
  }

  const cwdBase = path.basename(process.cwd());
  if (cwdBase === 'voice-agent') {
    return path.resolve(process.cwd(), '..', '..', '.benchmarks', 'voice');
  }
  return path.resolve(process.cwd(), '.benchmarks', 'voice');
}

function toTimestampFilePart(date: Date): string {
  return date.toISOString().replace(/[:.]/g, '-');
}

export function createVoiceSessionBenchmark(params: {
  sessionId: string;
  profile: string;
  provider: VoiceProviderName;
  now?: () => number;
}): VoiceSessionBenchmark | null {
  const enabled = process.env.VOICE_BENCHMARK_ENABLED === 'true';
  if (!enabled) return null;

  const thresholds = mergeThresholds(params.provider, parseThresholdOverridesFromEnv());
  return new VoiceSessionBenchmark({
    sessionId: params.sessionId,
    profile: params.profile,
    provider: params.provider,
    enabled,
    outputDir: resolveOutputDir(),
    thresholds,
    now: params.now,
  });
}

export class VoiceSessionBenchmark {
  private readonly recorder: VoiceBenchmarkRecorder;
  private readonly params: VoiceSessionBenchmarkParams;
  private readonly startedAtIso: string;
  private finalized = false;
  private turnActive = false;

  constructor(params: VoiceSessionBenchmarkParams) {
    this.params = params;
    this.recorder = new VoiceBenchmarkRecorder(params.now);
    this.startedAtIso = new Date(params.now ? params.now() : Date.now()).toISOString();
  }

  onStateChange(state: AgentState): void {
    if (!this.params.enabled) return;

    if ((state === 'thinking' || state === 'speaking') && !this.turnActive) {
      this.turnActive = true;
      this.recorder.markTurnStarted();
      return;
    }

    if (state === 'listening' || state === 'idle') {
      this.turnActive = false;
    }
  }

  onAudio(audio: VoiceRuntimeAudio): void {
    if (!this.params.enabled || !(audio.data instanceof ArrayBuffer)) return;
    this.recorder.recordAudio({
      data: audio.data,
      sampleRate: audio.sampleRate ?? 24000,
      format: audio.format ?? 'pcm16',
    });
  }

  onTranscriptFinal(text: string, role: 'user' | 'assistant', itemId?: string): void {
    if (!this.params.enabled) return;
    this.recorder.recordTranscript('final', text, role, itemId);
  }

  onTranscriptDelta(delta: string, role: 'user' | 'assistant', itemId?: string): void {
    if (!this.params.enabled) return;
    this.recorder.recordTranscript('delta', delta, role, itemId);
  }

  onAssistantItemCreated(itemId: string): void {
    if (!this.params.enabled) return;
    this.recorder.recordAssistantItem(itemId);
  }

  markInterruptionRequested(): void {
    if (!this.params.enabled) return;
    this.recorder.markInterruptionRequested();
  }

  markInterruptionStopped(): void {
    if (!this.params.enabled) return;
    this.recorder.markInterruptionStopped();
  }

  finalize(reason: SessionBenchmarkMeta['reason']): VoiceBenchmarkFinalizeResult | null {
    if (!this.params.enabled || this.finalized) return null;
    this.finalized = true;

    const input = this.recorder.buildInput();
    const report = evaluateVoiceBenchmark(input, this.params.thresholds);

    const payload: SessionBenchmarkPayload = {
      meta: {
        sessionId: this.params.sessionId,
        profile: this.params.profile,
        provider: this.params.provider,
        startedAt: this.startedAtIso,
        finishedAt: new Date(this.params.now ? this.params.now() : Date.now()).toISOString(),
        reason,
      },
      thresholds: this.params.thresholds,
      input,
      report,
    };

    let outputPath: string | undefined;
    try {
      mkdirSync(this.params.outputDir, { recursive: true });
      const timestampPart = toTimestampFilePart(new Date());
      const fileName = `${timestampPart}-${this.params.provider}-${this.params.sessionId.slice(0, 8)}.json`;
      outputPath = path.join(this.params.outputDir, fileName);
      writeFileSync(outputPath, `${JSON.stringify(payload, null, 2)}\n`, 'utf8');
    } catch (error) {
      console.error(
        `[VoiceBenchmark] failed writing report: ${(error as Error).message}`
      );
    }

    return {
      report,
      outputPath,
    };
  }
}



import { config } from '../config.js';
import type { AgentProfile } from '../agent/profiles.js';
import { resolveRuntimeConfigFromDocuments } from '@voiceclaw/voice-runtime';
import {
  ensureDefaultConfigFiles,
  loadAuthProfiles,
  loadVoiceConfig,
} from './settings.js';
import { getVoice } from './voices.js';
import type { VoiceRuntimeConfig } from './types.js';

function safeLoadConfig() {
  ensureDefaultConfigFiles();
  return {
    voice: loadVoiceConfig(),
    auth: loadAuthProfiles(),
  };
}

export function resolveVoiceRuntimeConfig(profile: AgentProfile): VoiceRuntimeConfig {
  const { voice: voiceDoc, auth: authDoc } = safeLoadConfig();
  const resolved = resolveRuntimeConfigFromDocuments({
    profileName: profile.name,
    profileVoice: profile.voice,
    fallbackModel: config.agent.model,
    voiceConfig: voiceDoc,
    authProfiles: authDoc,
    env: process.env,
  });

  // Resolve voice clone reference label → actual file paths
  if (resolved.decomposedTtsVoiceRef) {
    const entry = getVoice(resolved.decomposedTtsVoiceRef);
    if (entry) {
      resolved.providerSettings = {
        ...resolved.providerSettings,
        voiceRefAudio: entry.refAudioPath,
        voiceRefText: entry.meta.refText,
      };
    }
  }

  return resolved;
}



import type {
  EventHandler,
  VoiceSession as PackageVoiceSession,
  VoiceSessionEvents as PackageVoiceSessionEvents,
} from '@voiceclaw/voice-runtime';
import type { IAudioTransport } from '../transport/types.js';
import { LegacyAudioTransportBridge } from './transport-bridge.js';
import type {
  AgentState,
  VoiceMode,
  VoiceProviderName,
  VoiceRuntime,
  VoiceRuntimeEvents,
  VoiceRuntimeHistoryItem,
} from './types.js';

function mapHistory(items: ReturnType): VoiceRuntimeHistoryItem[] {
  return items.map((item) => ({
    id: item.id,
    type: 'message',
    role:
      item.role === 'assistant' || item.role === 'user' || item.role === 'system'
        ? item.role
        : 'system',
    content: [{ type: 'text', text: item.text }],
  }));
}

function mapLatencyStage(
  stage: string
): 'stt' | 'llm' | 'tts' | 'turn' | 'tool' | 'connection' {
  if (
    stage === 'stt' ||
    stage === 'llm' ||
    stage === 'tts' ||
    stage === 'turn' ||
    stage === 'tool' ||
    stage === 'connection'
  ) {
    return stage;
  }
  return 'turn';
}

export class PackageBackedVoiceRuntime implements VoiceRuntime {
  readonly mode: VoiceMode;
  readonly provider: VoiceProviderName;

  private readonly sessionFactory: () => Promise;
  private session: PackageVoiceSession | null = null;
  private connected = false;
  private handlers: Partial = {};
  private readonly inputSampleRateHz: number;
  private attachedBridge: LegacyAudioTransportBridge | null = null;

  constructor(params: {
    mode: VoiceMode;
    provider: VoiceProviderName;
    sessionFactory: () => Promise;
    inputSampleRateHz?: number;
  }) {
    this.mode = params.mode;
    this.provider = params.provider;
    this.sessionFactory = params.sessionFactory;
    this.inputSampleRateHz = params.inputSampleRateHz ?? 24000;
  }

  async connect(): Promise {
    const session = await this.ensureSession();
    await session.connect();
  }

  disconnect(): void {
    void this.closeInternal();
  }

  isConnected(): boolean {
    return this.connected;
  }

  sendAudio(audio: ArrayBuffer): void {
    if (!this.session) return;
    this.session.sendAudio({
      data: audio,
      sampleRate: this.inputSampleRateHz,
      format: 'pcm16',
    });
  }

  sendMessage(text: string): void {
    this.session?.sendText(text);
  }

  interrupt(): void {
    this.session?.interrupt();
  }

  getState(): AgentState {
    return this.session?.getState() ?? 'idle';
  }

  getHistory(): VoiceRuntimeHistoryItem[] {
    if (!this.session) return [];
    return mapHistory(this.session.getHistory());
  }

  async attachAudioTransport(transport: IAudioTransport): Promise {
    const session = await this.ensureSession();
    if (this.attachedBridge) {
      await session.detachClientTransport();
    }
    const bridge = new LegacyAudioTransportBridge(transport);
    await session.attachClientTransport(bridge);
    this.attachedBridge = bridge;
  }

  async detachAudioTransport(): Promise {
    if (!this.session || !this.attachedBridge) return;
    await this.session.detachClientTransport();
    this.attachedBridge = null;
  }

  usesInternalTransport(): boolean {
    return this.attachedBridge !== null;
  }

  on(event: K, handler: VoiceRuntimeEvents[K]): void {
    this.handlers[event] = handler;
  }

  private emit(
    event: K,
    ...args: Parameters
  ): void {
    const handler = this.handlers[event];
    if (!handler) return;
    (handler as (...eventArgs: Parameters) => void)(...args);
  }

  private bindSessionEvents(session: PackageVoiceSession): void {
    this.bind('connected', session, () => {
      this.connected = true;
      this.emit('connected');
    });

    this.bind('disconnected', session, () => {
      this.connected = false;
      this.emit('disconnected');
    });

    this.bind('stateChange', session, (state) => {
      this.emit('stateChange', state);
    });

    this.bind('audio', session, (frame) => {
      this.emit('audio', {
        data: frame.data,
        sampleRate: frame.sampleRate,
        format: frame.format,
      });
    });

    this.bind('audioInterrupted', session, () => {
      this.emit('audioInterrupted');
    });

    this.bind('transcript', session, (text, role, itemId, order) => {
      this.emit('transcript', text, role, itemId, order);
    });

    this.bind('transcriptDelta', session, (delta, role, itemId, order) => {
      this.emit('transcriptDelta', delta, role, itemId, order);
    });

    this.bind('spokenDelta', session, (delta, role, itemId, meta) => {
      if (this.handlers.spokenDelta) {
        this.emit('spokenDelta', delta, role, itemId, meta);
      }
    });

    this.bind('spokenProgress', session, (itemId, progress) => {
      if (this.handlers.spokenProgress) {
        this.emit('spokenProgress', itemId, progress);
      }
    });

    this.bind('spokenFinal', session, (text, role, itemId, meta) => {
      if (this.handlers.spokenFinal) {
        this.emit('spokenFinal', text, role, itemId, meta);
      }
    });

    this.bind('userItemCreated', session, (itemId, order) => {
      this.emit('userItemCreated', itemId, order);
    });

    this.bind('assistantItemCreated', session, (itemId, previousItemId, order) => {
      this.emit('assistantItemCreated', itemId, previousItemId, order);
    });

    this.bind('historyUpdated', session, (history) => {
      this.emit('historyUpdated', mapHistory(history));
    });

    this.bind('error', session, (error) => {
      this.emit('error', error);
    });

    this.bind('toolStart', session, (name, args, callId) => {
      this.emit('toolStart', name, args, callId);
    });

    this.bind('toolEnd', session, (name, result, callId) => {
      this.emit('toolEnd', name, result, callId);
    });

    this.bind('latency', session, (metric) => {
      this.emit('latency', {
        stage: mapLatencyStage(metric.stage),
        durationMs: metric.durationMs,
        provider: metric.provider,
        model: metric.model,
        details: metric.details,
      });
    });
  }

  private bind(
    event: K,
    session: PackageVoiceSession,
    handler: EventHandler
  ): void {
    session.on(event, handler);
  }

  private async closeInternal(): Promise {
    if (!this.session) return;
    await this.session.close();
    this.attachedBridge = null;
    this.connected = false;
  }

  private async ensureSession(): Promise {
    if (!this.session) {
      this.session = await this.sessionFactory();
      this.bindSessionEvents(this.session);
    }
    return this.session;
  }
}



