import type { ConfigFieldDescriptor, ProviderConfigSchema } from '../../lib/voice-config-api';
import { ConfigField, ConfigSection } from '../ui/config-dialog';

interface ProviderSettingsSectionProps {
  schema: ProviderConfigSchema;
  values: Record;
  onChange: (key: string, value: unknown) => void;
  group: 'vad' | 'advanced' | 'audio';
  title?: string;
  description?: string;
}

function isFieldVisible(
  field: ConfigFieldDescriptor,
  values: Record
): boolean {
  if (!field.dependsOn) return true;
  return values[field.dependsOn.field] === field.dependsOn.value;
}

function resolveValue(values: Record, key: string, defaultValue?: string | number | boolean): string | number | boolean {
  const val = values[key];
  if (val !== undefined && val !== null) return val as string | number | boolean;
  return defaultValue ?? '';
}

function FieldRenderer({
  field,
  values,
  onChange,
}: {
  field: ConfigFieldDescriptor;
  values: Record;
  onChange: (key: string, value: unknown) => void;
}) {
  const value = resolveValue(values, field.key, field.defaultValue);

  switch (field.type) {
    case 'select':
      return (

           onChange(field.key, e.target.value)}
          >
            {(field.options ?? []).map((opt) => (

                {opt.label}

            ))}


      );

    case 'boolean':
      return (

           onChange(field.key, e.target.value === 'true')}
          >
            disabled
            enabled


      );

    case 'number':
      return (

           {
              const num = Number(e.target.value);
              onChange(field.key, Number.isFinite(num) ? num : field.defaultValue ?? 0);
            }}
          />

      );

    case 'range':
      return (

           onChange(field.key, Number(e.target.value))}
            style={{ width: '100%' }}
          />

      );

    case 'string':
    default:
      return (

           onChange(field.key, e.target.value)}
          />

      );
  }
}

export function ProviderSettingsSection({
  schema,
  values,
