├── dev/                           # Component dev environment
│   ├── DevPage.tsx
│   ├── registry.ts
│   └── demos/
└── styles/
    └── index.css                  # Global styles + CSS vars
```

## Common Patterns

### Using the Unified Store

```typescript
import {
  useUnifiedSessionsStore,
  useFocusedSession,
  useFocusPath,
  useVoiceTimeline,
  useSessionActivities,
} from '@/stores';

function MyComponent() {
  // Get current focused session
  const focusedSession = useFocusedSession();

  // Get breadcrumb path
  const focusPath = useFocusPath();

  // Get voice timeline (for voice sessions)
  const voiceTimeline = useVoiceTimeline();

  // Get activities for a specific session
  const activities = useSessionActivities(sessionId);

  // Direct store access for actions
  const focusSession = useUnifiedSessionsStore((s) => s.focusSession);
  const minimizeTree = useUnifiedSessionsStore((s) => s.minimizeTree);

  // ...
}
```

### Handling New WebSocket Events

1. Add type to `WSMessageType` in `types/index.ts`
2. Add handler in `stores/message-handler.ts`
3. Add action/state in `stores/unified-sessions.ts` if needed
4. Update UI components to reflect new state



/**
 * Voice Agent - Main orchestrator for the voice assistant.
 *
 * Handles:
 * - Profile-based activation via wake word
 * - Session lifecycle management
 * - Event routing to consumers
 * - Agent run logging to database
 * - Audio I/O via pluggable transport layer
 */

import { randomUUID } from 'crypto';
import {
  profiles,
  getProfileByWakeword,
  type AgentProfile,
} from './profiles.js';
import { getDatabase, AgentRunsRepository, CliSessionsRepository } from '../db/index.js';
import type { VoiceProfile } from '../db/index.js';
import type { IAudioTransport } from '../transport/types.js';
import { wsBroadcast } from '../api/websocket.js';
import { createVoiceAdapter, type VoiceAdapter } from '../realtime/ai-sdk-adapter.js';
import type { ManagedProcess } from '../processes/manager.js';
import { buildHandoffPacket, type HandoffPacket, type VoiceContextEntry } from '../context/handoff.js';
import { getProcessManager } from '../processes/manager.js';
import { getSessionLogger, removeSessionLogger } from '../logging/session-logger.js';
import {
  createVoiceRuntime,
  type AgentState,
  type VoiceRuntime,
  type VoiceRuntimeAudio,
  type VoiceRuntimeHistoryItem,
} from '../voice/index.js';
import {
  createVoiceSessionBenchmark,
  type VoiceSessionBenchmark,
} from '../voice/benchmark-recorder.js';

export interface VoiceAgentEvents {
  stateChange: (state: AgentState, profile: string | null) => void;
  audio: (audio: VoiceRuntimeAudio) => void;
  transcript: (text: string, role: 'user' | 'assistant') => void;
  transcriptDelta: (delta: string, role: 'user' | 'assistant') => void;
  error: (error: Error) => void;
  toolStart: (name: string, args: Record, callId?: string) => void;
  toolEnd: (name: string, result: string, callId?: string) => void;
}

export class VoiceAgent {
  private runtime: VoiceRuntime | null = null;
  private currentProfile: AgentProfile | null = null;
  private state: AgentState = 'idle';
  private eventHandlers: Partial = {};
  private agentRunsRepo: AgentRunsRepository;
  private sessionsRepo: CliSessionsRepository;
  private transcriptBuffer: string[] = [];
  private transport: IAudioTransport | null = null;
  private currentSessionId: string | null = null; // Track current voice session ID for DB
  private adapter: VoiceAdapter | null = null; // AI SDK adapter for unified stream_chunk events
  private pendingNotifications: ManagedProcess[] = [];
  private voiceContext: VoiceContextEntry[] = []; // Accumulated voice context for HandoffPacket
  private readonly MAX_CONTEXT_ENTRIES = 30;
  private benchmark: VoiceSessionBenchmark | null = null;

  /**
   * Create a VoiceAgent.
   * @param transport - Optional audio transport. If provided, the agent manages audio I/O internally.
   *                    If not provided, use the 'audio' event and sendAudio() method for external handling.
   */
  constructor(transport?: IAudioTransport) {
    // Initialize database and repositories
    getDatabase();
    this.agentRunsRepo = new AgentRunsRepository();
    this.sessionsRepo = new CliSessionsRepository();

    // Set up transport if provided
    if (transport) {
      this.transport = transport;
      this.setupTransport();
    }
  }

  /**
   * Wire up transport events for internal audio handling.
   */
  private setupTransport(): void {
    if (!this.transport) return;

    // Route incoming audio from transport to session
    this.transport.on('audio', (chunk: ArrayBuffer) => {
      if (this.runtime?.usesInternalTransport?.()) {
        return;
      }
      if (this.runtime) {
        this.runtime.sendAudio(chunk);
      }
    });

    this.transport.on('error', (error: Error) => {
      console.error('[VoiceAgent] Transport error:', error.message);
      this.emit('error', error);
    });
  }

  on(event: K, handler: VoiceAgentEvents[K]): void {
    this.eventHandlers[event] = handler;
  }

  private emit(
    event: K,
    ...args: Parameters
  ): void {
    const handler = this.eventHandlers[event];
    if (handler) {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      (handler as (...a: any[]) => void)(...args);
    }
  }

  getState(): AgentState {
    return this.state;
  }

  getCurrentProfile(): AgentProfile | null {
    return this.currentProfile;
  }

  /**
   * Activate the agent with a specific wake word.
   * This looks up the profile and starts a conversation.
   */
  async activateWithWakeword(wakeword: string): Promise {
    const profile = getProfileByWakeword(wakeword);
    if (!profile) {
      console.error(`Unknown wakeword: ${wakeword}`);
      return false;
    }
    return this.activateProfile(profile);
  }

  /**
   * Activate with a profile name (e.g., 'jarvis', 'marvin').
   */
  async activate(profileName: string): Promise {
    // Look up by wake word first, then by profile name
    const profile =
      profiles[profileName] ?? profiles[`hey_${profileName.toLowerCase()}`];
    if (!profile) {
      console.error(`Unknown profile: ${profileName}`);
      return false;
    }
    return this.activateProfile(profile);
  }

  private async activateProfile(profile: AgentProfile): Promise {
    // Disconnect existing session if any
    if (this.runtime) {
      this.runtime.disconnect();
    }

    this.currentProfile = profile;

    // Generate session ID at the orchestrator level
    // This ID is propagated to:
    // 1. createAgentFromProfile - for factory tools (e.g., developer_session)
    // 2. VoiceSession - for lifecycle tracking and logging
    // 3. Database - for session hierarchy tracking
    const sessionId = randomUUID();
    this.currentSessionId = sessionId;
    console.log(`[Agent] Activating profile: ${profile.name} (Session: ${sessionId})`);

    // Create voice session in database - voice is now persisted in the session tree
    const voiceProfileName = profile.name.toLowerCase() as VoiceProfile;
    this.sessionsRepo.createVoice({
      id: sessionId,
      profile: voiceProfileName,
      goal: `Voice conversation (${profile.name})`,
    });
    console.log(`[Agent] Created voice session in DB: ${sessionId}`);

    // Broadcast tree update so frontend can show the new voice session
    wsBroadcast.sessionTreeUpdate(sessionId);

    // Create JSONL session logger for debugging
    getSessionLogger(sessionId, null, 'voice', null, { profile: voiceProfileName });

    // Create runtime FIRST so it can buffer/process audio during connect
    this.runtime = createVoiceRuntime(profile, sessionId, this);
    this.benchmark = createVoiceSessionBenchmark({
      sessionId,
      profile: profile.name,
      provider: this.runtime.provider,
    });

    if (this.transport && this.runtime.attachAudioTransport) {
      await this.runtime.attachAudioTransport(this.transport);
    }

    // Create AI SDK adapter for unified stream_chunk events
    // This replaces the legacy wsBroadcast.transcript/toolStart/toolEnd calls
    this.adapter = createVoiceAdapter(sessionId);

    // Start transport AFTER session exists so audio can be buffered
    // This is critical for web mode where audio capture starts immediately
    if (this.transport && !this.transport.isActive() && !this.runtime.usesInternalTransport?.()) {
      console.log('[Agent] Starting transport early for audio capture');
      this.transport.start();
    }

    // Wire up events
    this.runtime.on('stateChange', (state) => {
      this.benchmark?.onStateChange(state);
      this.state = state;
      // Emit state change for UI (listening/thinking/speaking indicator)
      this.emit('stateChange', state, this.currentProfile?.name ?? null);

      // Emit AI SDK lifecycle events via adapter (start-step on thinking, finish on idle)
      // This ensures the frontend knows when a response is complete (clears pending flag)
      this.adapter?.stateChange(state, this.currentProfile?.name ?? null);

      // Log state change to JSONL
      if (this.currentSessionId) {
        const logger = getSessionLogger(this.currentSessionId);
        logger.append({
          type: 'state-change',
          id: `sc-${Date.now()}`,
          state,
          profile: this.currentProfile?.name ?? null,
          timestamp: new Date().toISOString(),
        });
      }

      // Stop transport when going idle
      if (this.transport && state === 'idle') {
        this.transport.stop();
      }

    });

    this.runtime.on('audio', (audio) => {
      this.benchmark?.onAudio(audio);
      // Route to transport if available, otherwise emit for external handling
      if (this.transport && audio.data && !this.runtime?.usesInternalTransport?.()) {
        this.transport.play(audio.data);
      }
      this.emit('audio', audio);
    });

    // Wire up placeholder events for message ordering
    // These are emitted when conversation.item.added arrives, before transcripts
    this.runtime.on('userItemCreated', (itemId, order) => {
      this.adapter?.userPlaceholder(itemId, undefined, order);
    });

    this.runtime.on('assistantItemCreated', (itemId, previousItemId, order) => {
      this.benchmark?.onAssistantItemCreated(itemId);
      // Keep provider-native ordering edges only. Synthetic fallback links can invert
      // ordering for providers (e.g. Ultravox) where assistant starts before user transcript.
      this.adapter?.assistantPlaceholder(itemId, previousItemId, order);
    });

    this.runtime.on('transcript', (text, role, itemId, order) => {
      this.benchmark?.onTranscriptFinal(text, role, itemId);
      // Collect transcripts for logging
      this.transcriptBuffer.push(`${role}: ${text}`);
      // Accumulate voice context for HandoffPacket (anti-telephone)
      this.addVoiceContext(role, text);
      // Runtime-level transcript dedupe/normalization ensures this is canonical.
      this.adapter?.transcript(text, role, itemId, order);
    });

    this.runtime.on('transcriptDelta', (delta, role, itemId, order) => {
      this.benchmark?.onTranscriptDelta(delta, role, itemId);
      // Stream assistant transcript deltas in real-time
      // User transcripts don't have deltas (they arrive complete)
      if (role === 'assistant') {
        this.adapter?.transcript(delta, role, itemId, order);
      }
    });

    this.runtime.on('spokenDelta', (delta, role, itemId, meta) => {
      if (role !== 'assistant') return;
      this.adapter?.spokenDelta(delta, itemId, undefined, meta);
    });

    this.runtime.on('spokenProgress', (itemId, progress) => {
      this.adapter?.spokenProgress(itemId, progress);
    });

    this.runtime.on('spokenFinal', (text, role, itemId, meta) => {
      if (role !== 'assistant') return;
      this.adapter?.spokenFinal(text, itemId, undefined, meta);
    });

    this.runtime.on('latency', (metric) => {
      const latencyMetricTag =
        metric.stage === 'tts' && typeof metric.details?.metric === 'string'
          ? metric.details.metric
          : null;

      if (latencyMetricTag === 'chunk') {
        const chunkIndex =
          typeof metric.details?.chunkIndex === 'number' ? metric.details.chunkIndex : null;
        const chunkAudioMs =
          typeof metric.details?.chunkAudioMs === 'number' ? metric.details.chunkAudioMs : null;
        const producerRtf =
          typeof metric.details?.producerRtf === 'number' ? metric.details.producerRtf : null;
        const playoutLeadMs =
          typeof metric.details?.playoutLeadMs === 'number' ? metric.details.playoutLeadMs : null;
        const firstChunkTtfbMs =
          typeof metric.details?.firstChunkTtfbMs === 'number'
            ? metric.details.firstChunkTtfbMs
            : null;
        console.log(
          `[VoiceLatency] tts-chunk` +
            (chunkIndex !== null ? ` #${chunkIndex}` : '') +
            (chunkAudioMs !== null ? ` audio=${chunkAudioMs}ms` : '') +
            (firstChunkTtfbMs !== null ? ` ttfb=${firstChunkTtfbMs}ms` : '') +
            (producerRtf !== null ? ` rtf=${producerRtf.toFixed(3)}` : '') +
            (playoutLeadMs !== null ? ` lead=${playoutLeadMs}ms` : '')
        );
      }

      const firstAudioLatency =
        metric.stage === 'tts' && typeof metric.details?.firstAudioLatencyMs === 'number'
          ? ` firstAudio=${metric.details.firstAudioLatencyMs}ms`
          : '';
      const segmentIndex =
        metric.stage === 'tts' && typeof metric.details?.segmentIndex === 'number'
          ? ` segment=${metric.details.segmentIndex}`
          : '';
      const summary = `[VoiceLatency] ${metric.stage}=${metric.durationMs}ms${firstAudioLatency}${segmentIndex}` +
        (metric.provider ? ` provider=${metric.provider}` : '') +
        (metric.model ? ` model=${metric.model}` : '');
      console.log(summary);

      if (this.currentSessionId) {
        const logger = getSessionLogger(this.currentSessionId);
        logger.append({
          type: 'latency',
          id: `lat-${Date.now()}`,
          stage: metric.stage,
          durationMs: metric.durationMs,
          provider: metric.provider ?? null,
          model: metric.model ?? null,
          details: metric.details ?? {},
          timestamp: new Date().toISOString(),
        });

        wsBroadcast.streamChunk(this.currentSessionId, {
          type: 'latency',
          stage: metric.stage,
          durationMs: metric.durationMs,
          provider: metric.provider,
          model: metric.model,
          details: metric.details,
        });
      }
    });

    this.runtime.on('error', (error) => {
      // Emit stream_chunk error via adapter
      this.adapter?.error(error.message);
      this.emit('error', error);
    });

    this.runtime.on('toolStart', (name, args, callId) => {
      // Emit stream_chunk tool-call via adapter
      this.adapter?.toolStart(name, args, callId);
    });

    this.runtime.on('toolEnd', (name, result, callId) => {
      // Accumulate tool result in voice context for HandoffPacket
      this.addVoiceContext('system', `[Tool: ${name}] ${result}`, { name, result });
      // Emit stream_chunk tool-result via adapter
      this.adapter?.toolEnd(name, result, callId);
    });

    // When audio is interrupted (user speaks over agent), stop local playback
    // This is critical for WebSocket transport where we manage audio playback ourselves
    this.runtime.on('audioInterrupted', () => {
      this.benchmark?.markInterruptionStopped();
      if (this.transport && !this.runtime?.usesInternalTransport?.()) {
        this.transport.interrupt();
      }
    });

    this.runtime.on('disconnected', () => {
      this.finalizeBenchmark('disconnected');
      // Log the agent run to database before resetting state
      this.logAgentRun();

      // Clean up adapter state tracking
      this.adapter?.cleanup();

      // Mark voice session as finished in database
      if (this.currentSessionId) {
        this.sessionsRepo.finish(this.currentSessionId, 'finished');
        console.log(`[Agent] Marked voice session as finished: ${this.currentSessionId}`);
        // Broadcast tree update so frontend knows session ended
        wsBroadcast.sessionTreeUpdate(this.currentSessionId);
        // Remove JSONL logger
        removeSessionLogger(this.currentSessionId);
        this.currentSessionId = null;
      }

      this.state = 'idle';
      this.emit('stateChange', 'idle', null);
    });

    try {
      await this.runtime.connect();
      return true;
    } catch (error) {
      this.finalizeBenchmark('connect-failed');
      console.error('Failed to connect session:', error);
      this.emit('error', error as Error);
      return false;
    }
  }

  sendAudio(audio: ArrayBuffer): void {
    this.runtime?.sendAudio(audio);
  }

  sendMessage(text: string): void {
    this.runtime?.sendMessage(text);
  }

  interrupt(): void {
    this.benchmark?.markInterruptionRequested();
    this.runtime?.interrupt();
  }

  getHistory(): VoiceRuntimeHistoryItem[] {
    return this.runtime?.getHistory() ?? [];
  }

  deactivate(): void {
    if (this.runtime) {
      this.finalizeBenchmark('deactivate');
      // Log the agent run before disconnecting
      this.logAgentRun();

      // Mark voice session as finished in database (before disconnect triggers 'disconnected' event)
      // Note: disconnect() will trigger 'disconnected' event which also handles this,
      // but we do it here too in case deactivate() is called directly
      if (this.currentSessionId) {
        this.sessionsRepo.finish(this.currentSessionId, 'finished');
        console.log(`[Agent] Marked voice session as finished: ${this.currentSessionId}`);
        wsBroadcast.sessionTreeUpdate(this.currentSessionId);
        // Remove JSONL logger
        removeSessionLogger(this.currentSessionId);
        this.currentSessionId = null;
      }

      this.runtime.disconnect();
      this.runtime = null;
    }

    // Stop transport if managed internally
    if (this.transport) {
      this.transport.stop();
    }

    this.currentProfile = null;
    this.adapter = null;
    this.benchmark = null;
    this.state = 'idle';
    this.emit('stateChange', 'idle', null);
  }

  private finalizeBenchmark(reason: 'disconnected' | 'deactivate' | 'connect-failed'): void {
    const result = this.benchmark?.finalize(reason);
    if (!result) return;

    const status = result.report.pass ? 'PASS' : 'FAIL';
    const reportPath = result.outputPath ? ` report=${result.outputPath}` : '';
    console.log(`[VoiceBenchmark] ${status}${reportPath}`);
    if (!result.report.pass) {
      for (const violation of result.report.violations) {
        console.warn(`[VoiceBenchmark] violation: ${violation}`);
      }
    }
    this.benchmark = null;
  }

  /**
   * Log the current agent run to the database.
   */
  private logAgentRun(): void {
    if (this.transcriptBuffer.length === 0) {
      return; // Nothing to log
    }

    try {
      this.agentRunsRepo.create({
        profile: this.currentProfile?.name ?? undefined,
        transcript: this.transcriptBuffer.join('\n'),
      });
      console.log(`[Agent] Logged run for profile: ${this.currentProfile?.name ?? 'unknown'}`);
    } catch (error) {
      console.error('[Agent] Failed to log agent run:', error);
    }

    // Clear the buffer
    this.transcriptBuffer = [];
  }

  isActive(): boolean {
    return this.runtime?.isConnected() ?? false;
  }

  /**
   * Queue a process completion notification for the next voice session.
   * Used when a background process completes while the voice agent is idle.
   */
  addPendingNotification(process: ManagedProcess): void {
    this.pendingNotifications.push(process);
  }

  /**
   * Get and clear pending notification prompt text.
   * Called when activating a new voice session to prepend background task results.
   */
  getPendingNotificationsPrompt(): string {
    if (this.pendingNotifications.length === 0) return '';
    const notifications = this.pendingNotifications.map(p =>
      `- "${p.name}" ${p.status}: ${p.result || p.error || 'No details'}`
    ).join('\n');
    this.pendingNotifications = [];
    return `\n\nPending notifications from background tasks:\n${notifications}\nPlease inform the user about these completed tasks.`;
  }

  /**
   * Add an entry to the accumulated voice context.
   * Called on each transcript and tool result for HandoffPacket building.
   */
  private addVoiceContext(
    role: 'user' | 'assistant' | 'system',
    content: string,
    toolInfo?: { name: string; args?: unknown; result?: string }
  ): void {
    this.voiceContext.push({ role, content, timestamp: Date.now(), toolInfo });
    if (this.voiceContext.length > this.MAX_CONTEXT_ENTRIES) {
      this.voiceContext.shift();
    }
  }

  /**
   * Build a HandoffPacket for transferring context to a subagent.
   * Contains the full recent voice conversation + active process state.
   */
  createHandoffPacket(request: string): HandoffPacket {
    const pm = getProcessManager();
    return buildHandoffPacket({
      request,
      voiceContext: this.voiceContext,
      activeProcesses: [...pm.getRunning()],
      sessionId: this.currentSessionId ?? 'unknown',
      profile: this.currentProfile?.name ?? 'unknown',
    });
  }

  /**
   * Get the audio transport (if one was injected).
   */
  getTransport(): IAudioTransport | null {
    return this.transport;
  }

  /**
   * Check if the agent is managing audio internally via transport.
   */
  hasTransport(): boolean {
    return this.transport !== null;
  }

  /**
   * Hot-swap the audio transport.
   * Used for switching between local (device) and web (browser) audio sources.
   */
  setTransport(transport: IAudioTransport): void {
    // Stop and detach old transport
    if (this.transport) {
      this.transport.removeAllListeners();
      this.transport.stop();
    }

    // Set and wire new transport
    this.transport = transport;
    this.setupTransport();

    if (this.runtime?.attachAudioTransport) {
      void this.runtime.attachAudioTransport(transport);
    }

    // If agent is active, start the new transport immediately
    if (this.isActive()) {
      console.log('[VoiceAgent] Hot-swapping transport while active, starting new transport');
      if (!this.runtime?.usesInternalTransport?.()) {
        this.transport.start();
      }
    }
  }

  /**
   * Get the current voice session ID.
   * Used by subagents to establish parent-child relationships.
   */
  getCurrentSessionId(): string | null {
    return this.currentSessionId;
  }
}



/**
 * AI SDK Adapter - Converts OpenAI Realtime API events to AI SDK format.
 *
 * This adapter enables voice sessions to emit the same event format as text-based
 * subagents (CLI, web-search). The frontend receives `stream_chunk` messages for
 * all agent types, simplifying state management.
 *
 * Mapping:
 * - transcript (assistant) → text-delta (streamed token by token)
 * - transcript (user) → user-transcript (complete message)
 * - toolStart → tool-call
 * - toolEnd → tool-result
 * - stateChange (thinking) → start-step
 * - stateChange (speaking → *) → finish (marks message complete between turns)
 * - error → error
 */

import { wsBroadcast } from '../api/websocket.js';
import type {
  AISDKStreamEvent,
  SpokenWordCue,
  SpokenWordCueUpdate,
  StreamChunkMessage,
} from '../api/stream-types.js';
import { createStreamChunk } from '../api/stream-types.js';

/**
 * Voice event types from VoiceSession/VoiceAgent.
 */
export type VoiceEventType =
  | 'stateChange'
  | 'transcript'
  | 'spokenDelta'
  | 'spokenProgress'
  | 'spokenFinal'
  | 'toolStart'
  | 'toolEnd'
  | 'error';

/**
 * Payload types for voice events.
 */
export interface VoiceEventPayloads {
  stateChange: { state: 'idle' | 'listening' | 'thinking' | 'speaking'; profile: string | null };
  transcript: { text: string; role: 'user' | 'assistant'; itemId?: string; order?: number };
  spokenDelta: {
    textDelta: string;
    itemId?: string;
    order?: number;
    spokenChars?: number;
    spokenWords?: number;
    playbackMs?: number;
    precision?: 'ratio' | 'segment' | 'aligned' | 'provider-word-timestamps';
    wordTimestamps?: Array<{ word: string; startMs: number; endMs: number }>;
    wordCues?: SpokenWordCue[];
    wordCueUpdate?: SpokenWordCueUpdate;
  };
  spokenProgress: {
    itemId: string;
    spokenChars: number;
    spokenWords: number;
    playbackMs: number;
    precision: 'ratio' | 'segment' | 'aligned' | 'provider-word-timestamps';
  };
  spokenFinal: {
    text: string;
    itemId?: string;
    order?: number;
    spokenChars?: number;
    spokenWords?: number;
    playbackMs?: number;
    precision?: 'ratio' | 'segment' | 'aligned' | 'provider-word-timestamps';
    wordTimestamps?: Array<{ word: string; startMs: number; endMs: number }>;
    wordCues?: SpokenWordCue[];
    wordCueUpdate?: SpokenWordCueUpdate;
  };
  toolStart: { name: string; args: Record; callId?: string };
  toolEnd: { name: string; result: string; callId?: string };
  error: { message: string };
}

/**
 * Generate a tool call ID for tracking tool-call → tool-result pairs.
 */
let toolCallCounter = 0;
function generateToolCallId(): string {
  return `voice-tool-${++toolCallCounter}`;
}

// Track previous state per session for detecting transitions
const previousStates = new Map(); // sessionId → previous state

/**
 * Adapt a voice event to AI SDK format and broadcast as stream_chunk.
 *
 * @param sessionId - The voice session ID
 * @param eventType - The voice event type
 * @param payload - Event-specific payload
 */
export function adaptVoiceEvent(
  sessionId: string,
  eventType: T,
  payload: VoiceEventPayloads[T]
): void {
  const event = convertToAISDKEvent(eventType, payload);
  if (event) {
    const chunk = createStreamChunk(sessionId, event);
    broadcastStreamChunk(chunk);
  }
}

/**
 * Convert a voice event to an AI SDK stream event.
 */
function convertToAISDKEvent(
  eventType: T,
  payload: VoiceEventPayloads[T],
  options?: {
    consumePendingToolCall?: (toolName: string) => string | undefined;
    pushPendingToolCall?: (toolName: string, toolCallId: string) => void;
  }
): AISDKStreamEvent | null {
  switch (eventType) {
    case 'transcript': {
      const { text, role, itemId, order } = payload as VoiceEventPayloads['transcript'];
      // User messages use custom 'user-transcript' event
      // Assistant messages use standard AI SDK 'text-delta'
      if (role === 'user') {
        return { type: 'user-transcript', text, itemId, order };
      }
      return { type: 'text-delta', textDelta: text, itemId, order, channel: 'generated' };
    }

    case 'spokenDelta': {
      const {
        textDelta,
        itemId,
        order,
        spokenChars,
        spokenWords,
        playbackMs,
        precision,
        wordTimestamps,
        wordCues,
        wordCueUpdate,
      } =
        payload as VoiceEventPayloads['spokenDelta'];
      return {
        type: 'spoken-delta',
        textDelta,
        itemId,
        order,
        spokenChars,
        spokenWords,
        playbackMs,
        precision,
        wordTimestamps,
        wordCues,
        wordCueUpdate,
      };
    }

    case 'spokenFinal': {
      const {
        text,
        itemId,
        order,
        spokenChars,
        spokenWords,
        playbackMs,
        precision,
        wordTimestamps,
        wordCues,
        wordCueUpdate,
      } =
        payload as VoiceEventPayloads['spokenFinal'];
      return {
        type: 'spoken-final',
        text,
        itemId,
        order,
        spokenChars,
        spokenWords,
        playbackMs,
        precision,
        wordTimestamps,
        wordCues,
        wordCueUpdate,
      };
    }

    case 'spokenProgress': {
      const { itemId, spokenChars, spokenWords, playbackMs, precision } =
        payload as VoiceEventPayloads['spokenProgress'];
      return {
        type: 'spoken-progress',
        itemId,
        spokenChars,
        spokenWords,
        playbackMs,
        precision,
      };
    }

    case 'toolStart': {
      const { name, args, callId } = payload as VoiceEventPayloads['toolStart'];
      const toolCallId = callId ?? generateToolCallId();
      options?.pushPendingToolCall?.(name, toolCallId);
      return {
        type: 'tool-call',
        toolName: name,
        toolCallId,
        input: args,
      };
    }

    case 'toolEnd': {
      const { name, result, callId } = payload as VoiceEventPayloads['toolEnd'];
      // Use provided callId or dequeue one from pending starts for the same tool name.
      const toolCallId = callId ?? options?.consumePendingToolCall?.(name) ?? generateToolCallId();
      return {
        type: 'tool-result',
        toolName: name,
        toolCallId,
        output: result,
      };
    }

    case 'stateChange': {
      const { state } = payload as VoiceEventPayloads['stateChange'];
      // Map state transitions to AI SDK events
      if (state === 'thinking') {
        return { type: 'start-step' };
      }
      // Note: 'finish' is now emitted by the stateChange() method when leaving 'speaking'
      // state, so we don't emit it here anymore to avoid duplicates.
      // listening, speaking, and idle don't have direct AI SDK equivalents
      return null;
    }

    case 'error': {
      const { message } = payload as VoiceEventPayloads['error'];
      return { type: 'error', error: message };
    }

    default:
      return null;
  }
}

/**
 * Broadcast a stream chunk message via WebSocket.
 * Uses wsBroadcast.streamChunk which also persists the event to database.
 */
function broadcastStreamChunk(chunk: StreamChunkMessage): void {
  wsBroadcast.streamChunk(chunk.sessionId, chunk.event);
}

/**
 * Create an adapter instance for a specific voice session.
 * Provides a cleaner API for VoiceSession to use.
 */
export function createVoiceAdapter(sessionId: string) {
  // Initialize previous state tracking for this session
  previousStates.set(sessionId, 'idle');
  const pendingToolCalls = new Map();

  const pushPendingToolCall = (toolName: string, toolCallId: string): void => {
    const list = pendingToolCalls.get(toolName) ?? [];
    list.push(toolCallId);
    pendingToolCalls.set(toolName, list);
  };

  const consumePendingToolCall = (toolName: string): string | undefined => {
    const list = pendingToolCalls.get(toolName);
    if (!list || list.length === 0) {
      return undefined;
    }
    const next = list.shift();
    if (list.length === 0) {
      pendingToolCalls.delete(toolName);
    } else {
      pendingToolCalls.set(toolName, list);
    }
    return next;
  };

  return {
    /**
     * Emit a user placeholder event (reserves position before transcript arrives).
     */
    userPlaceholder(itemId: string, previousItemId?: string, order?: number): void {
      const chunk = createStreamChunk(sessionId, {
        type: 'user-placeholder',
        itemId,
        previousItemId,
        order,
      });
      broadcastStreamChunk(chunk);
    },

    /**
     * Emit an assistant placeholder event (reserves position before transcript arrives).
     */
    assistantPlaceholder(itemId: string, previousItemId?: string, order?: number): void {
      const chunk = createStreamChunk(sessionId, {
        type: 'assistant-placeholder',
        itemId,
        previousItemId,
        order,
      });
      broadcastStreamChunk(chunk);
    },

    /**
     * Emit a transcript event (user or assistant speech).
     */
    transcript(
      text: string,
      role: 'user' | 'assistant',
      itemId?: string,
      order?: number
    ): void {
      const event = convertToAISDKEvent('transcript', { text, role, itemId, order });
      if (!event) return;
      const chunk = createStreamChunk(sessionId, event);
      broadcastStreamChunk(chunk);
    },

    /**
     * Emit spoken transcript delta event (assistant audio-confirmed text).
     */
    spokenDelta(
      textDelta: string,
      itemId?: string,
      order?: number,
      meta?: {
        spokenChars?: number;
        spokenWords?: number;
        playbackMs?: number;
        precision?: 'ratio' | 'segment' | 'aligned' | 'provider-word-timestamps';
        wordTimestamps?: Array<{ word: string; startMs: number; endMs: number }>;
        wordCues?: SpokenWordCue[];
        wordCueUpdate?: SpokenWordCueUpdate;
      }
    ): void {
      const event = convertToAISDKEvent('spokenDelta', {
        textDelta,
        itemId,
        order,
        spokenChars: meta?.spokenChars,
        spokenWords: meta?.spokenWords,
        playbackMs: meta?.playbackMs,
        precision: meta?.precision,
        wordTimestamps: meta?.wordTimestamps,
        wordCues: meta?.wordCues,
        wordCueUpdate: meta?.wordCueUpdate,
      });
      if (!event) return;
      const chunk = createStreamChunk(sessionId, event);
      broadcastStreamChunk(chunk);
    },

    /**
     * Emit spoken transcript final event (assistant audio-confirmed final text).
     */
    spokenProgress(
      itemId: string,
      progress: {
        spokenChars: number;
        spokenWords: number;
        playbackMs: number;
        precision: 'ratio' | 'segment' | 'aligned' | 'provider-word-timestamps';
      }
    ): void {
      const event = convertToAISDKEvent('spokenProgress', {
        itemId,
        spokenChars: progress.spokenChars,
        spokenWords: progress.spokenWords,
        playbackMs: progress.playbackMs,
        precision: progress.precision,
      });
      if (!event) return;
      const chunk = createStreamChunk(sessionId, event);
      broadcastStreamChunk(chunk);
    },

    /**
     * Emit spoken transcript final event (assistant audio-confirmed final text).
     */
    spokenFinal(
      text: string,
      itemId?: string,
      order?: number,
      meta?: {
        spokenChars?: number;
        spokenWords?: number;
        playbackMs?: number;
        precision?: 'ratio' | 'segment' | 'aligned' | 'provider-word-timestamps';
        wordTimestamps?: Array<{ word: string; startMs: number; endMs: number }>;
        wordCues?: SpokenWordCue[];
        wordCueUpdate?: SpokenWordCueUpdate;
      }
    ): void {
      const event = convertToAISDKEvent('spokenFinal', {
        text,
        itemId,
        order,
        spokenChars: meta?.spokenChars,
        spokenWords: meta?.spokenWords,
        playbackMs: meta?.playbackMs,
        precision: meta?.precision,
        wordTimestamps: meta?.wordTimestamps,
        wordCues: meta?.wordCues,
        wordCueUpdate: meta?.wordCueUpdate,
      });
      if (!event) return;
      const chunk = createStreamChunk(sessionId, event);
      broadcastStreamChunk(chunk);
    },

    /**
     * Emit a tool start event.
     */
    toolStart(name: string, args: Record, callId?: string): void {
      const event = convertToAISDKEvent(
        'toolStart',
        { name, args, callId },
        { pushPendingToolCall, consumePendingToolCall }
      );
      if (!event) return;
      const chunk = createStreamChunk(sessionId, event);
      broadcastStreamChunk(chunk);
    },

    /**
     * Emit a tool end event.
     */
    toolEnd(name: string, result: string, callId?: string): void {
      const event = convertToAISDKEvent(
        'toolEnd',
        { name, result, callId },
        { pushPendingToolCall, consumePendingToolCall }
      );
      if (!event) return;
      const chunk = createStreamChunk(sessionId, event);
      broadcastStreamChunk(chunk);
    },

    /**
     * Emit a state change event.
     * Emits 'finish' when transitioning FROM speaking (end of assistant turn).
     * Emits 'start-step' when entering thinking state.
     */
    stateChange(state: 'idle' | 'listening' | 'thinking' | 'speaking', profile: string | null): void {
      const prevState = previousStates.get(sessionId) ?? 'idle';
      previousStates.set(sessionId, state);

      // Emit finish when leaving speaking state (marks assistant message as complete)
      // This happens between turns (speaking → listening) and at end (speaking → idle)
      if (prevState === 'speaking' && state !== 'speaking') {
        const chunk = createStreamChunk(sessionId, { type: 'finish', finishReason: 'stop' });
        broadcastStreamChunk(chunk);
      }

      // Also emit the regular state-based events
      adaptVoiceEvent(sessionId, 'stateChange', { state, profile });
    },

    /**
     * Emit an error event.
     */
    error(message: string): void {
      adaptVoiceEvent(sessionId, 'error', { message });
    },

    /**
     * Clean up tracking state when session ends.
     */
    cleanup(): void {
      previousStates.delete(sessionId);
      pendingToolCalls.clear();
    },
  };
}

