}

type SpokenWordCue = {
  word: string;
  startMs: number;
  endMs: number;
  source: 'provider' | 'synthetic';
  timeBase: 'utterance';
};

type SpokenWordCueUpdate = {
  mode: 'append' | 'replace';
  cues: SpokenWordCue[];
};

export interface VoiceRuntimeEvents {
  stateChange: (state: AgentState) => void;
  audio: (audio: VoiceRuntimeAudio) => void;
  audioInterrupted: () => void;
  transcript: (
    text: string,
    role: 'user' | 'assistant',
    itemId?: string,
    order?: number
  ) => void;
  transcriptDelta: (
    delta: string,
    role: 'user' | 'assistant',
    itemId?: string,
    order?: number
  ) => void;
  spokenDelta: (
    delta: string,
    role: 'assistant',
    itemId?: string,
    meta?: {
      spokenChars?: number;
      spokenWords?: number;
      playbackMs?: number;
      precision?: 'ratio' | 'segment' | 'aligned' | 'provider-word-timestamps';
      wordTimestamps?: Array<{ word: string; startMs: number; endMs: number }>;
      wordTimestampsTimeBase?: 'segment' | 'utterance';
      wordCues?: SpokenWordCue[];
      wordCueUpdate?: SpokenWordCueUpdate;
    }
  ) => void;
  spokenProgress: (
    itemId: string,
    progress: {
      spokenChars: number;
      spokenWords: number;
      playbackMs: number;
      precision: 'ratio' | 'segment' | 'aligned' | 'provider-word-timestamps';
    }
  ) => void;
  spokenFinal: (
    text: string,
    role: 'assistant',
    itemId?: string,
    meta?: {
      spokenChars?: number;
      spokenWords?: number;
      playbackMs?: number;
      precision?: 'ratio' | 'segment' | 'aligned' | 'provider-word-timestamps';
      wordTimestamps?: Array<{ word: string; startMs: number; endMs: number }>;
      wordTimestampsTimeBase?: 'segment' | 'utterance';
      wordCues?: SpokenWordCue[];
      wordCueUpdate?: SpokenWordCueUpdate;
    }
  ) => void;
  userItemCreated: (itemId: string, order?: number) => void;
  assistantItemCreated: (
    itemId: string,
    previousItemId?: string,
    order?: number
  ) => void;
  historyUpdated: (history: VoiceRuntimeHistoryItem[]) => void;
  error: (error: Error) => void;
  connected: () => void;
  disconnected: () => void;
  toolStart: (name: string, args: Record, callId?: string) => void;
  toolEnd: (name: string, result: string, callId?: string) => void;
  latency: (metric: {
    stage: 'stt' | 'llm' | 'tts' | 'turn' | 'tool' | 'connection';
    durationMs: number;
    provider?: string;
    model?: string;
    details?: Record;
  }) => void;
}

export interface VoiceRuntime {
