  // Pipecat voices/VAD are configured server-side
};

export class PipecatRtviAdapter extends BaseWebSocketAdapter implements ProviderAdapter {
  readonly id = 'pipecat-rtvi' as const;

  private readonly events = new TypedEventEmitter();
  private readonly options: PipecatRtviAdapterOptions;
  private readonly now: () => number;
  private socket: WebSocketLike | null = null;
  private config: PipecatProviderConfig | null = null;
  private input: SessionInput | null = null;
  private state: VoiceState = 'idle';
  private ready = false;
  private turnInProgress = false;
  private messageCounter = 0;
  private dynamicCapabilities: Partial = {};

  private history: VoiceHistoryItem[] = [];
  private readonly resamplerPool = new StreamResamplerPool();
  private pendingUserByKey = new Map();
  private pendingAssistant: PendingAssistantTranscript | null = null;
  private userSequence = 0;
  private assistantSequence = 0;
  private pendingTools = new Map();
  private toolInFlight = new Set();

  private readyPromise: Promise | null = null;
  private resolveReady: (() => void) | null = null;
  private rejectReady: ((error: Error) => void) | null = null;
  private keepAliveTimer: ReturnType | null = null;

  constructor(options?: PipecatRtviAdapterOptions) {
    super({
      maxReconnectRetries: options?.maxReconnectRetries,
      reconnectBaseDelayMs: options?.reconnectBaseDelayMs,
      reconnectMaxDelayMs: options?.reconnectMaxDelayMs,
    });
    this.options = options ?? {};
    this.now = options?.now ?? (() => Date.now());
  }

  capabilities(): ProviderCapabilities {
    const transport = this.config?.transport ?? this.options.config?.transport ?? 'websocket';
    return buildCapabilities(transport, this.dynamicCapabilities, this.options.capabilitiesOverride);
  }

  configSchema(): ProviderConfigSchema {
    return PIPECAT_CONFIG_SCHEMA;
  }

  async connect(input: SessionInput): Promise {
    this.input = input;
    this.config = this.resolveConfig(input);
    this.history = [];
    this.pendingUserByKey.clear();
    this.pendingAssistant = null;
    this.pendingTools.clear();
    this.toolInFlight.clear();
    this.dynamicCapabilities = {};
    this.ready = false;
    this.turnInProgress = false;

    await this.openAndHandshake();
    this.events.emit('connected');
    this.setState('listening');

    const providerIn = this.config.inputSampleRate ?? DEFAULT_SAMPLE_RATE;
    if (DEFAULT_SAMPLE_RATE !== providerIn) {
      await this.resamplerPool.get(DEFAULT_SAMPLE_RATE, providerIn);
    }

    return {
      providerInputRate: providerIn,
      providerOutputRate: this.config.outputSampleRate ?? DEFAULT_SAMPLE_RATE,
      preferredClientInputRate: DEFAULT_SAMPLE_RATE,
      preferredClientOutputRate: DEFAULT_SAMPLE_RATE,
      format: 'pcm16',
    };
  }

  async disconnect(): Promise {
    this.markDisconnecting(true);
    this.ready = false;
    this.turnInProgress = false;
    this.clearKeepAlive();
    this.rejectReady?.(new Error('Disconnected'));
    this.resolveReady = null;
    this.rejectReady = null;
    this.readyPromise = null;

    if (!this.socket) {
      this.setState('idle');
      this.events.emit('disconnected');
      return;
    }

    try {
      this.sendEnvelope({
        type: 'disconnect-bot',
      });
    } catch {
      // ignore
    }

    this.socket.close();
    this.socket = null;
    this.resamplerPool.clear();
    this.setState('idle');
    this.events.emit('disconnected');
  }

  sendAudio(frame: AudioFrame): void {
    if (!this.socket || this.socket.readyState !== 1 || !this.config) return;
    const inputRate = this.config.inputSampleRate ?? DEFAULT_SAMPLE_RATE;
    let normalized: AudioFrame;
    if (frame.sampleRate === inputRate) {
      normalized = frame;
    } else {
      const resampler = this.resamplerPool.getSync(frame.sampleRate, inputRate);
      normalized = resampler
        ? resampler.process(frame)
        : resamplePcm16Mono(frame, inputRate);
    }

    if (this.config.audioInputEncoding === 'client-message-base64') {
      this.sendEnvelope({
        type: 'client-message',
        data: {
          t: this.config.audioInputMessageType ?? 'audio-input',
          d: {
            data: encodeBase64(normalized.data),
            sampleRate: normalized.sampleRate,
            format: normalized.format,
          },
        },
      });
      return;
    }

    this.socket.send(normalized.data);
  }

  sendText(text: string, options?: { defer?: boolean }): void {
    const trimmed = text.trim();
    if (!trimmed) return;
    this.sendEnvelope({
      type: 'send-text',
      data: {
        text: trimmed,
        run_immediately: !(options?.defer ?? false),
        audio_response: true,
      },
    });
  }

  interrupt(): void {
    this.sendEnvelope({
      type: 'client-message',
      data: {
        t: 'interrupt-bot',
        d: {},
      },
    });
    this.events.emit('audioInterrupted');
    this.setState('listening');
  }

  truncateOutput(input: { itemId: string; audioEndMs: number }): void {
    this.sendEnvelope({
      type: 'client-message',
      data: {
        t: 'truncate-output',
        d: input,
      },
    });
  }

  sendToolResult(result: ToolCallResult): void {
    const callId = toCallId(result.invocationId);
    const name = this.pendingTools.get(callId) ?? 'tool';
    this.sendFunctionCallResult(name, callId, result);
    this.events.emit('toolEnd', name, result.result, callId);
    this.pendingTools.delete(callId);
    this.toolInFlight.delete(callId);
  }

  updateConfig(config: Partial): void {
    this.sendEnvelope({
      type: 'update-config',
      data: config,
    });
  }

  forceAgentMessage(
    text: string,
    options?: { uninterruptible?: boolean; urgency?: 'immediate' | 'soon' }
  ): void {
    this.sendEnvelope({
      type: 'client-message',
      data: {
        t: 'force-agent-message',
        d: {
          text,
          uninterruptible: options?.uninterruptible ?? false,
          urgency: options?.urgency ?? 'soon',
        },
      },
    });
  }

  setOutputMedium(medium: 'voice' | 'text'): void {
    this.sendEnvelope({
      type: 'client-message',
      data: {
        t: 'set-output-medium',
        d: { medium },
      },
    });
  }

  async resume(handle: string): Promise {
    this.sendEnvelope({
      type: 'client-message',
      data: {
        t: 'resume-session',
        d: { handle },
      },
    });
  }

  mute(muted: boolean): void {
    this.sendEnvelope({
      type: 'client-message',
      data: {
        t: 'set-mute',
        d: { muted },
      },
    });
  }

  on(
    event: K,
    handler: EventHandler
  ): void {
    this.events.on(event, handler);
  }

  off(
    event: K,
    handler: EventHandler
  ): void {
    this.events.off(event, handler);
  }

  private async openAndHandshake(): Promise {
    if (!this.config || !this.input) {
      throw new Error('Pipecat adapter missing config or input');
    }

    this.markDisconnecting(false);
    this.readyPromise = new Promise((resolve, reject) => {
      this.resolveReady = resolve;
      this.rejectReady = reject;
    });

    const serverUrl = this.config.serverUrl;
    if (!serverUrl) {
      throw new Error('Pipecat RTVI requires providerConfig.serverUrl');
    }

    await this.openSocket(serverUrl);
    this.sendClientReady();
    this.sendEnvelope({ type: 'describe-actions' });
    this.sendEnvelope({ type: 'describe-config' });
    this.sendBootstrapMessage();

    await this.waitForReady(this.config.readyTimeoutMs ?? DEFAULT_READY_TIMEOUT_MS);
  }

  private async openSocket(url: string): Promise {
    const socket = this.createSocket(url);
    this.socket = socket;
    if (typeof socket.binaryType === 'string') {
      socket.binaryType = 'arraybuffer';
    }

    await new Promise((resolve, reject) => {
      const onOpen = () => {
        socket.removeEventListener('error', onError);
        resolve();
      };
      const onError = (event: unknown) => {
        socket.removeEventListener('open', onOpen);
        reject(this.toError(event, 'Pipecat RTVI websocket open error'));
      };
      socket.addEventListener('open', onOpen, { once: true });
      socket.addEventListener('error', onError, { once: true });
    });

    this.bindSocketHandlers(socket);
  }

  private bindSocketHandlers(socket: WebSocketLike): void {
    socket.addEventListener('message', (event: unknown) => {
      void this.handleSocketMessage(event);
    });

    socket.addEventListener('close', (_event: unknown) => {
      this.clearKeepAlive();
      this.socket = null;
      if (this.disconnecting) {
        return;
      }
      const closeEvent = parseObject(_event);
      const code = typeof closeEvent?.code === 'number' ? closeEvent.code : undefined;
      const reason =
        typeof closeEvent?.reason === 'string' && closeEvent.reason
          ? closeEvent.reason
          : undefined;
      void this.handleUnexpectedClose(code, reason);
    });

    socket.addEventListener('error', (event: unknown) => {
      const error = this.toError(event, 'Pipecat RTVI websocket error');
      if (!this.ready) {
        this.rejectReady?.(error);
      }
      this.events.emit('error', error);
    });
  }

  private async handleUnexpectedClose(code?: number, reason?: string): Promise {
    this.ready = false;
    this.turnInProgress = false;
    const closeReason = [code ? `code=${code}` : null, reason ?? null]
      .filter((part): part is string => Boolean(part))
      .join(' ');
    this.events.emit(
      'error',
      new Error(
        closeReason
          ? `Pipecat RTVI websocket closed unexpectedly (${closeReason})`
          : 'Pipecat RTVI websocket closed unexpectedly'
      )
    );

    if (this.config?.reconnect === false) {
      this.setState('idle');
      this.events.emit('disconnected', closeReason ? `unexpected_close:${closeReason}` : 'unexpected_close');
      return;
    }

    const recovered = await this.tryReconnect(async () => {
      await this.openAndHandshake();
    });

    if (recovered) {
      this.events.emit('connected');
      this.setState('listening');
      return;
    }

    this.setState('idle');
    this.events.emit('disconnected', closeReason ? `reconnect_failed:${closeReason}` : 'reconnect_failed');
  }

  private async handleSocketMessage(rawEvent: unknown): Promise {
    const data = this.extractMessageData(rawEvent);
    if (typeof data === 'string') {
      this.handleJsonMessage(data);
      return;
    }

    if (data instanceof ArrayBuffer) {
      this.emitAudioFrame(data, this.config?.outputSampleRate ?? DEFAULT_SAMPLE_RATE);
      return;
    }

    if (typeof Blob !== 'undefined' && data instanceof Blob) {
      const payload = await data.arrayBuffer();
      this.emitAudioFrame(payload, this.config?.outputSampleRate ?? DEFAULT_SAMPLE_RATE);
      return;
    }

    if (data instanceof Uint8Array) {
      const copied = new Uint8Array(data.byteLength);
      copied.set(data);
      const payload = copied.buffer;
      this.emitAudioFrame(payload, this.config?.outputSampleRate ?? DEFAULT_SAMPLE_RATE);
    }
  }

  private handleJsonMessage(raw: string): void {
    const envelope = parseJsonEnvelope(raw);
    if (!envelope) return;

    switch (envelope.type) {
      case 'bot-ready':
        this.ready = true;
        this.resolveReady?.();
        this.resolveReady = null;
        this.rejectReady = null;
        this.startKeepAlive();
        return;
      case 'error':
      case 'error-response': {
        const data = parseObject(envelope.data);
        const message =
          (data && typeof data.message === 'string' && data.message) || 'Pipecat RTVI error';
        const error = new Error(message);
        if (!this.ready) {
          this.rejectReady?.(error);
        }
        this.events.emit('error', error);
        return;
      }
      case 'action-response':
        this.handleActionResponse(envelope.data);
        return;
      case 'user-started-speaking':
        this.events.emit('audioInterrupted');
        this.setState('listening');
        return;
      case 'user-stopped-speaking':
        this.setState('thinking');
        return;
      case 'bot-llm-started':
        this.startTurn('thinking');
        return;
      case 'bot-started-speaking':
        this.ensureAssistantItem();
        this.startTurn('speaking');
        return;
      case 'bot-stopped-speaking':
        this.finalizeAssistantItem();
        this.completeTurn();
        return;
      case 'bot-llm-stopped':
        if (this.state !== 'speaking') {
          this.finalizeAssistantItem();
          this.completeTurn();
        }
        return;
      case 'bot-interrupted':
        this.finalizeAssistantItem();
        this.completeTurn();
        this.events.emit('audioInterrupted');
        return;
      case 'user-transcription':
        this.handleUserTranscription(envelope.data);
        return;
      case 'bot-output':
      case 'bot-transcription':
      case 'bot-llm-text':
      case 'bot-tts-text':
        this.handleAssistantText(envelope.type, envelope.data);
        return;
      case 'llm-function-call':
      case 'llm-function-call-in-progress':
        void this.handleFunctionCall(envelope.data);
        return;
      case 'llm-function-call-stopped':
        this.handleFunctionCallStopped(envelope.data);
        return;
      case 'metrics':
        this.handleMetrics(envelope.data);
        return;
      case 'server-message':
        this.handleServerMessage(envelope.data);
        return;
      default:
        return;
    }
  }

  private handleActionResponse(rawData: unknown): void {
    const data = parseObject(rawData);
    if (!data) return;
    const actionsRaw = Array.isArray(data.actions) ? data.actions : [];
    const actions = actionsRaw
      .map((item) => {
        if (typeof item === 'string') return item;
        const object = parseObject(item);
        if (!object) return null;
        if (typeof object.action === 'string') return object.action;
        if (typeof object.service_action === 'string') return object.service_action;
        return null;
      })
      .filter((name): name is string => typeof name === 'string');

    if (actions.length === 0) return;

    this.dynamicCapabilities = {
      ...this.dynamicCapabilities,
      midSessionConfigUpdate: actions.includes('update-config'),
      sessionResumption:
        this.dynamicCapabilities.sessionResumption || actions.includes('resume-session'),
      forceAgentMessage:
        this.dynamicCapabilities.forceAgentMessage || actions.includes('force-agent-message'),
      outputMediumSwitch:
        this.dynamicCapabilities.outputMediumSwitch || actions.includes('set-output-medium'),
    };
  }

  private handleUserTranscription(rawData: unknown): void {
    const data = parseObject(rawData) as UserTranscriptionData | null;
    if (!data) return;
    const text = typeof data.text === 'string' ? data.text : '';
    if (!text) return;

    const key = typeof data.user_id === 'string' && data.user_id ? data.user_id : 'default';
    const pending = this.pendingUserByKey.get(key) ?? this.createPendingUser(key);
    const delta = computeDelta(pending.text, text);
    if (delta) {
      this.events.emit('transcriptDelta', delta, 'user', pending.itemId);
    }
    pending.text = text;
    this.pendingUserByKey.set(key, pending);

    if (data.final === true) {
      this.emitFinalUserTranscript(key, pending);
    }
  }

  private createPendingUser(key: string): PendingUserTranscript {
    this.userSequence += 1;
    const itemId = `pipecat-user-${key}-${this.userSequence}`;
    this.events.emit('userItemCreated', itemId);
    return {
      itemId,
      text: '',
    };
  }

  private emitFinalUserTranscript(key: string, pending: PendingUserTranscript): void {
    const finalText = pending.text.trim();
    if (!finalText) {
      this.pendingUserByKey.delete(key);
      return;
    }
    this.events.emit('transcript', finalText, 'user', pending.itemId);
    this.history.push({
      id: pending.itemId,
      role: 'user',
      text: finalText,
      createdAt: nowMs(this.now),
    });
    this.events.emit('historyUpdated', [...this.history]);
    this.pendingUserByKey.delete(key);
  }

  private handleAssistantText(type: string, rawData: unknown): void {
    if (type === 'bot-transcription' || type === 'bot-llm-text' || type === 'bot-tts-text') {
      const data = parseObject(rawData);
      const text = data && typeof data.text === 'string' ? data.text : '';
      if (!text) return;
      this.appendAssistantText(text);
      return;
    }

    const data = parseObject(rawData) as BotOutputData | null;
    if (!data) return;
    const text = typeof data.text === 'string' ? data.text : '';
    if (!text) return;

    this.appendAssistantText(text);
    if (data.final === true) {
      this.finalizeAssistantItem();
      if (this.state !== 'speaking') {
        this.completeTurn();
      }
    }
  }

  private appendAssistantText(text: string): void {
    const pending = this.ensureAssistantItem();
    const delta = computeDelta(pending.text, text);
    if (text.startsWith(pending.text)) {
      pending.text = text;
    } else {
      pending.text += delta;
    }
    if (delta) {
      this.events.emit('transcriptDelta', delta, 'assistant', pending.itemId);
    }
  }

  private ensureAssistantItem(): PendingAssistantTranscript {
    if (this.pendingAssistant) return this.pendingAssistant;
    if (!this.turnInProgress) {
      this.startTurn('thinking');
    }
    this.assistantSequence += 1;
    const itemId = `pipecat-assistant-${this.assistantSequence}`;
    this.pendingAssistant = {
      itemId,
      text: '',
    };
    this.events.emit('assistantItemCreated', itemId);
    return this.pendingAssistant;
  }

  private finalizeAssistantItem(): void {
    if (!this.pendingAssistant) return;
    const finalText = this.pendingAssistant.text.trim();
    if (finalText) {
      this.events.emit('transcript', finalText, 'assistant', this.pendingAssistant.itemId);
      this.history.push({
        id: this.pendingAssistant.itemId,
        role: 'assistant',
        text: finalText,
        createdAt: nowMs(this.now),
      });
      this.events.emit('historyUpdated', [...this.history]);
    }
    this.pendingAssistant = null;
  }

  private async handleFunctionCall(rawData: unknown): Promise {
    const data = parseObject(rawData) as LlmFunctionCallData | null;
    if (!data) return;

    const callId = toCallId(data.tool_call_id ?? data.call_id);
    const name =
      (typeof data.function_name === 'string' && data.function_name) ||
      (typeof data.name === 'string' && data.name) ||
      'pipecat_tool';
    const args = parseToolArguments(data.arguments ?? data.args);

    if (!this.pendingTools.has(callId)) {
      this.pendingTools.set(callId, name);
      this.events.emit('toolStart', name, args, callId);
    }

    const toolHandlerEnabled = this.config?.autoToolExecution !== false && this.input?.toolHandler;
    if (!toolHandlerEnabled || this.toolInFlight.has(callId) || !this.input?.toolHandler) {
      return;
    }

    this.toolInFlight.add(callId);
    try {
      const context: ToolCallContext = {
        providerId: this.id,
        callId,
        invocationId: callId,
        history: [...this.history],
      };
      const rawResult = await this.input.toolHandler(name, args, context);
      const normalized = normalizeToolResult(callId, rawResult);
      this.sendFunctionCallResult(name, callId, normalized);
      this.events.emit('toolEnd', name, normalized.result, callId);
    } catch (error) {
      const errorMessage = (error as Error).message;
      this.sendFunctionCallResult(name, callId, {
        invocationId: callId,
        result: errorMessage,
        isError: true,
      });
      this.events.emit('toolEnd', name, errorMessage, callId);
      this.events.emit('error', error as Error);
    } finally {
      this.toolInFlight.delete(callId);
      this.pendingTools.delete(callId);
    }
  }

  private handleFunctionCallStopped(rawData: unknown): void {
    const data = parseObject(rawData) as LlmFunctionCallStoppedData | null;
    if (!data) return;
    const callId = toCallId(data.tool_call_id ?? data.call_id);
    const knownCall = this.pendingTools.has(callId) || this.toolInFlight.has(callId);

    if (data.cancelled) {
      if (knownCall) {
        this.events.emit('toolCancelled', [callId]);
      }
      this.pendingTools.delete(callId);
      this.toolInFlight.delete(callId);
      return;
    }

    if (!knownCall || typeof data.result !== 'string') return;

    const name = this.pendingTools.get(callId) ?? data.function_name ?? 'pipecat_tool';
    this.events.emit('toolEnd', name, data.result, callId);
    this.pendingTools.delete(callId);
    this.toolInFlight.delete(callId);
  }

  private sendFunctionCallResult(
    name: string,
    callId: string,
    result: ToolCallResult
  ): void {
    const response = {
      output: maybeParseJson(result.result),
      is_error: result.isError ?? false,
      error_message: result.errorMessage,
      scheduling: result.scheduling,
      state_update: result.stateUpdate,
      stage_transition: result.stageTransition ?? false,
    };

    this.sendEnvelope({
      type: 'llm-function-call-result',
      data: {
        function_name: name,
        tool_call_id: callId,
        result: response,
        run_llm: result.agentReaction !== 'listens',
      },
    });
  }

  private handleMetrics(rawData: unknown): void {
    const data = parseObject(rawData) as MetricsData | null;
    if (!data) return;

    const processing = Array.isArray(data.processing) ? data.processing : [];
    for (const metric of processing) {
      if (!metric || typeof metric.value !== 'number') continue;
      this.events.emit('latency', {
        stage: 'turn',
        durationMs: parseMetricDurationMs(metric.value),
        provider: 'pipecat-rtvi',
        model: metric.model,
        details: {
          processor: metric.processor,
          metric: 'processing',
        },
      });
    }

    const ttfb = Array.isArray(data.ttfb) ? data.ttfb : [];
    for (const metric of ttfb) {
      if (!metric || typeof metric.value !== 'number') continue;
      this.events.emit('latency', {
        stage: 'tts',
        durationMs: parseMetricDurationMs(metric.value),
        provider: 'pipecat-rtvi',
        model: metric.model,
        details: {
          processor: metric.processor,
          metric: 'ttfb',
        },
      });
    }

    const characters = Array.isArray(data.characters) ? data.characters : [];
    if (characters.length > 0) {
      const outputChars = characters.reduce((sum, item) => {
        if (!item || typeof item.value !== 'number') return sum;
        return sum + item.value;
      }, 0);
      this.events.emit('usage', {
        outputTokenDetails: {
          textTokens: outputChars,
        },
      });
    }
  }

  private handleServerMessage(rawData: unknown): void {
    const payload = parseObject(rawData) as RtviMessageData | null;
    if (!payload || typeof payload.t !== 'string') return;
    switch (payload.t) {
      case 'bot-audio':
      case 'bot-tts-audio':
      case 'audio':
        this.handleAudioMessage(payload.d);
        return;
      case 'state': {
        const statePayload = parseObject(payload.d);
        if (!statePayload) return;
        const state = statePayload.state;
        if (isVoiceState(state)) {
          this.setState(state);
        }
        return;
      }
      case 'tool-call':
        void this.handleFunctionCall(payload.d);
        return;
      case 'user-transcription':
        this.handleUserTranscription(payload.d);
        return;
      case 'bot-output':
        this.handleAssistantText('bot-output', payload.d);
        return;
      default:
        return;
    }
  }

  private handleAudioMessage(rawData: unknown): void {
    const data = parseObject(rawData) as AudioMessageData | null;
    if (!data) return;
    const base64Audio =
      (typeof data.audio === 'string' && data.audio) ||
      (typeof data.data === 'string' && data.data) ||
      (typeof data.chunk === 'string' && data.chunk) ||
      '';
    if (!base64Audio) return;
    const sampleRate =
      (typeof data.sample_rate === 'number' && data.sample_rate > 0 && data.sample_rate) ||
      (typeof data.sampleRate === 'number' && data.sampleRate > 0 && data.sampleRate) ||
      this.config?.outputSampleRate ||
      DEFAULT_SAMPLE_RATE;
    this.emitAudioFrame(decodeBase64(base64Audio), sampleRate);
  }

  private emitAudioFrame(data: ArrayBuffer, sampleRate: number): void {
    this.events.emit('audio', {
      data,
      sampleRate,
      format: 'pcm16',
    });
  }

  private sendClientReady(): void {
    this.sendEnvelope({
      type: 'client-ready',
      data: {
        version: this.config?.clientVersion ?? '0.0.1',
        client: 'voice-runtime',
        transport: this.config?.transport ?? 'websocket',
      },
    });
  }

  private sendBootstrapMessage(): void {
    if (!this.input || !this.config) return;
    this.sendEnvelope({
      type: 'client-message',
      data: {
        t: this.config.bootstrapMessageType ?? 'voice-runtime-start',
        d: {
          instructions: this.input.instructions,
          model: this.input.model,
          voice: this.input.voice,
          language: this.input.language,
          temperature: this.input.temperature,
          maxOutputTokens: this.input.maxOutputTokens,
          tools: this.input.tools ?? [],
          pipeline: this.config.pipeline,
          botId: this.config.botId,
        },
      },
    });
  }

  private async waitForReady(timeoutMs: number): Promise {
    if (this.ready) return;
    if (!this.readyPromise) {
      throw new Error('Pipecat ready promise not initialized');
    }

    await Promise.race([
      this.readyPromise,
      new Promise((_, reject) => {
        setTimeout(() => {
          reject(new Error(`Pipecat RTVI bot-ready timeout after ${timeoutMs}ms`));
        }, timeoutMs);
      }),
    ]);
  }

  private sendEnvelope(payload: RtviEnvelope): void {
    if (!this.socket || this.socket.readyState !== 1) return;
    this.messageCounter += 1;
    const envelope: RtviEnvelope = {
      id: payload.id ?? `rtvi-${Date.now()}-${this.messageCounter}`,
      label: payload.label ?? 'rtvi-ai',
      ...payload,
    };
    this.socket.send(JSON.stringify(envelope));
  }

  private setState(next: VoiceState): void {
    if (this.state === next) return;
    this.state = next;
    this.events.emit('stateChange', next);
  }

  private startTurn(state: VoiceState): void {
    if (!this.turnInProgress) {
      this.turnInProgress = true;
      this.events.emit('turnStarted');
    }
    this.setState(state);
  }

  private completeTurn(): void {
    if (!this.turnInProgress) {
      this.setState('listening');
      return;
    }
    this.turnInProgress = false;
    this.setState('listening');
    this.events.emit('turnComplete');
  }

  private extractMessageData(rawEvent: unknown): unknown {
    const event = parseObject(rawEvent);
    if (event && 'data' in event) {
      return event.data;
    }
    return rawEvent;
  }

  private resolveConfig(input: SessionInput): PipecatProviderConfig {
    if (this.options.config) {
      const parsed = parsePipecatProviderConfig(this.options.config);
      if (!parsed.serverUrl) {
        throw new Error('Pipecat RTVI requires providerConfig.serverUrl or adapter constructor config');
      }
      return parsed;
    }

    const raw = parsePipecatProviderConfig(input.providerConfig);
    const serverUrl = raw.serverUrl;
    if (!serverUrl) {
      throw new Error('Pipecat RTVI requires providerConfig.serverUrl or adapter constructor config');
    }

    return {
      serverUrl,
      transport: raw.transport ?? 'websocket',
      inputSampleRate: raw.inputSampleRate,
      outputSampleRate: raw.outputSampleRate,
      audioInputEncoding: raw.audioInputEncoding,
      audioInputMessageType: raw.audioInputMessageType,
      readyTimeoutMs: raw.readyTimeoutMs,
      reconnect: raw.reconnect,
      clientVersion: raw.clientVersion,
      autoToolExecution: raw.autoToolExecution,
      bootstrapMessageType: raw.bootstrapMessageType,
      keepAliveIntervalMs: raw.keepAliveIntervalMs,
      pingMessageType: raw.pingMessageType,
      pipeline: raw.pipeline,
      botId: raw.botId,
    };
  }

  private createSocket(url: string): WebSocketLike {
    if (this.options.socketFactory) {
      return this.options.socketFactory(url);
    }
    return new WebSocket(url) as unknown as WebSocketLike;
  }

  private toError(raw: unknown, fallback: string): Error {
    const event = parseObject(raw);
    if (!event) return new Error(fallback);

    if (typeof event.message === 'string' && event.message) {
      return new Error(event.message);
    }

    const innerError = parseObject(event.error);
    if (innerError && typeof innerError.message === 'string' && innerError.message) {
      return new Error(innerError.message);
    }

    return new Error(fallback);
  }

  private startKeepAlive(): void {
    this.clearKeepAlive();
    const intervalMs =
      this.config?.keepAliveIntervalMs === undefined
        ? DEFAULT_KEEPALIVE_INTERVAL_MS
        : this.config.keepAliveIntervalMs;
    if (!intervalMs || intervalMs <= 0) return;
    this.keepAliveTimer = setInterval(() => {
      this.sendEnvelope({
        type: 'client-message',
        data: {
          t: this.config?.pingMessageType ?? 'ping',
          d: {
            ts: Date.now(),
          },
        },
      });
    }, intervalMs);
  }

  private clearKeepAlive(): void {
    if (!this.keepAliveTimer) return;
    clearInterval(this.keepAliveTimer);
    this.keepAliveTimer = null;
  }
}

function maybeParseJson(value: string): unknown {
  try {
    return JSON.parse(value) as unknown;
  } catch {
    return value;
  }
}



import type {
  SpokenWordCue,
  SpokenWordCueSource,
  SpokenWordCueUpdate,
  SpokenWordTimestamp,
} from '../types.js';

/**
 * Default minimum estimated ms per word for synthetic cue distribution during streaming.
 * Prevents a large batch of words (e.g. pre-audio buffer drain) from being crammed
 * into a tiny time window and highlighting all at once.
 * Conservative value — slightly slower than typical speech (~140ms/word).
 * Can be overridden via WordCueTimelineBuilder constructor.
 */
const DEFAULT_MIN_SYNTHETIC_MS_PER_WORD = 150;

interface CueIngestInput {
  spokenText: string;
  playbackMs: number;
  /** Byte-derived ms offset where audible speech starts in the audio stream. */
  speechOnsetMs?: number;
  providerWordTimestamps?: SpokenWordTimestamp[];
  providerTimeBase?: 'segment' | 'utterance';
}

interface CueIngestResult {
  update: SpokenWordCueUpdate | null;
  timeline: SpokenWordCue[];
}

export interface WordCueTimelineConfig {
  minMsPerWord?: number;
  punctuationPauseMs?: number;
  preferProviderTimestamps?: boolean;
}

/**
 * Builds a canonical utterance-relative word cue timeline.
 *
 * Runtime contract:
 * - deltas emit append-only cue updates where possible
 * - finals emit a full replacement timeline
 * - provider timestamps are normalized to utterance-relative once in runtime
 */
export class WordCueTimelineBuilder {
  private cues: SpokenWordCue[] = [];
  private readonly dedupeKeys = new Set();
  private lastSpokenText = '';
  private lastPlaybackMs = 0;
  /** Detected speech onset offset — words should not start before this. */
  private speechOnsetMs = 0;
  /** Minimum ms per word for synthetic cues — prevents batch-cramming. */
  private readonly minMsPerWord: number;
  /** Extra pause after punctuation words in synthetic cues. */
  private readonly punctuationPauseMs: number;
  /** Whether to prefer provider-supplied timestamps over synthetic ones. */
  private readonly preferProviderTimestamps: boolean;

  constructor(config?: WordCueTimelineConfig) {
    const minMsPerWord = config?.minMsPerWord;
    this.minMsPerWord =
      minMsPerWord != null && Number.isFinite(minMsPerWord) && minMsPerWord > 0
        ? minMsPerWord
        : DEFAULT_MIN_SYNTHETIC_MS_PER_WORD;
    this.punctuationPauseMs =
      config?.punctuationPauseMs != null &&
      Number.isFinite(config.punctuationPauseMs) &&
      config.punctuationPauseMs > 0
        ? config.punctuationPauseMs
        : 0;
    this.preferProviderTimestamps = config?.preferProviderTimestamps ?? true;
  }

  reset(): void {
    this.cues = [];
    this.dedupeKeys.clear();
    this.lastSpokenText = '';
    this.lastPlaybackMs = 0;
    this.speechOnsetMs = 0;
  }

  getTimeline(): SpokenWordCue[] {
    return this.cues.map((cue) => ({ ...cue }));
  }

  ingestDelta(input: CueIngestInput): CueIngestResult {
    const spokenText = normalizeText(input.spokenText);
    const playbackMs = normalizeMs(input.playbackMs, this.lastPlaybackMs);
    const providerTimeBase = input.providerTimeBase ?? 'segment';

    // Latch speech onset: once detected, never regress.
    if (
      input.speechOnsetMs != null &&
      Number.isFinite(input.speechOnsetMs) &&
      input.speechOnsetMs > this.speechOnsetMs
    ) {
      this.speechOnsetMs = input.speechOnsetMs;
    }

    let update: SpokenWordCueUpdate | null = null;
    const hasProviderTimestamps =
      this.preferProviderTimestamps &&
      input.providerWordTimestamps != null &&
      input.providerWordTimestamps.length > 0;
    if (hasProviderTimestamps) {
      const appended = this.appendProviderWordTimestamps(
        input.providerWordTimestamps!,
        providerTimeBase,
        this.lastPlaybackMs
      );
      if (appended.length > 0) {
        update = { mode: 'append', cues: appended };
      }
    } else {
      update = this.appendSyntheticCues(spokenText, playbackMs);
    }

    this.lastSpokenText = spokenText;
    this.lastPlaybackMs = playbackMs;
    return {
      update,
      timeline: this.getTimeline(),
    };
  }

  ingestFinal(input: CueIngestInput): CueIngestResult {
    const spokenText = normalizeText(input.spokenText);
    const playbackMs = normalizeMs(input.playbackMs, this.lastPlaybackMs);
    const providerTimeBase = input.providerTimeBase ?? 'utterance';

    let cues: SpokenWordCue[];
    const hasProviderTimestamps =
      this.preferProviderTimestamps &&
      input.providerWordTimestamps != null &&
      input.providerWordTimestamps.length > 0;
    if (hasProviderTimestamps) {
      cues = this.buildProviderTimeline(input.providerWordTimestamps!, providerTimeBase, 0);
    } else {
      // Preserve already-streaming synthetic timing when spoken-final arrives
      // with a smaller playbackMs (common when text was buffered before audio
      // onset). Rebuilding against the smaller final window compresses cues and
      // causes a visible mid-speech highlight jump.
      cues =
        this.maybePreserveSyntheticTimeline(spokenText, playbackMs) ??
        this.buildSyntheticTimeline(spokenText, playbackMs);
    }

    this.replaceTimeline(cues);
    this.lastSpokenText = spokenText;
    this.lastPlaybackMs = playbackMs;

    return {
      update: { mode: 'replace', cues: this.getTimeline() },
      timeline: this.getTimeline(),
    };
  }

  private maybePreserveSyntheticTimeline(
    spokenText: string,
    playbackMs: number
  ): SpokenWordCue[] | null {
    if (this.cues.length === 0) {
      return null;
    }

    if (!this.cues.every((cue) => cue.source === 'synthetic')) {
      return null;
    }

    const finalWords = tokenizeWords(spokenText);
    if (finalWords.length !== this.cues.length) {
      return null;
    }

    for (let index = 0; index < finalWords.length; index += 1) {
      if (finalWords[index] !== this.cues[index]?.word) {
        return null;
      }
    }

    const lastCueEndMs = this.cues[this.cues.length - 1]?.endMs ?? 0;
    if (playbackMs > lastCueEndMs) {
      return null;
    }

    return this.getTimeline();
  }

  private appendProviderWordTimestamps(
    timestamps: SpokenWordTimestamp[],
    timeBase: 'segment' | 'utterance',
    offsetMs: number
  ): SpokenWordCue[] {
    const appended: SpokenWordCue[] = [];
    const normalizedOffsetMs = normalizeMs(offsetMs, 0);
    let lastEndMs = this.cues[this.cues.length - 1]?.endMs ?? 0;

    for (const value of timestamps) {
      const normalized = normalizeTimestamp(value);
      if (!normalized) {
        continue;
      }

      const startMsRaw =
        timeBase === 'utterance'
          ? normalized.startMs
          : normalizedOffsetMs + normalized.startMs;
      const endMsRaw =
        timeBase === 'utterance'
          ? normalized.endMs
          : normalizedOffsetMs + normalized.endMs;
      const startMs = Math.max(lastEndMs, startMsRaw);
      const endMs = Math.max(startMs, endMsRaw);
      const key = cueKey(normalized.word, startMs, endMs);
      if (this.dedupeKeys.has(key)) {
        continue;
      }

      const cue: SpokenWordCue = {
        word: normalized.word,
        startMs,
        endMs,
        source: 'provider',
        timeBase: 'utterance',
      };
      this.cues.push(cue);
      this.dedupeKeys.add(key);
      appended.push({ ...cue });
      lastEndMs = endMs;
    }

    return appended;
  }

  private appendSyntheticCues(spokenText: string, playbackMs: number): SpokenWordCueUpdate | null {
    const words = tokenizeWords(spokenText);
    if (words.length === 0) {
      return null;
    }

    // If the spoken text regresses/corrects mid-turn, replace with a rebuilt timeline.
    if (this.lastSpokenText && !spokenText.startsWith(this.lastSpokenText)) {
      const rebuilt = this.buildSyntheticTimeline(spokenText, playbackMs);
      this.replaceTimeline(rebuilt);
      return { mode: 'replace', cues: this.getTimeline() };
    }

    const existingCount = this.cues.length;
    if (words.length <= existingCount) {
      return null;
    }

    const newWords = words.slice(existingCount);
    // Use speechOnsetMs as the floor so words don't start during TTS silence.
    const windowStartMs = Math.max(
      this.speechOnsetMs,
      this.lastPlaybackMs,
      this.cues[this.cues.length - 1]?.endMs ?? 0
    );
    // Guarantee a minimum per-word pace so a large batch (e.g. pre-audio
    // buffer drain) isn't crammed into a tiny window and highlighted instantly.
    // As more audio arrives, subsequent appends extend naturally.  The
    // spokenFinal rebuild uses actual total duration for final accuracy.
    const estimatedMinEndMs = windowStartMs + newWords.length * this.minMsPerWord;
    const windowEndMs = Math.max(windowStartMs, playbackMs, estimatedMinEndMs);
    const appended = distributeWordsIntoWindow(
      newWords, windowStartMs, windowEndMs, 'synthetic', this.punctuationPauseMs
    );
    for (const cue of appended) {
      const key = cueKey(cue.word, cue.startMs, cue.endMs);
      if (this.dedupeKeys.has(key)) {
        continue;
      }
      this.cues.push(cue);
      this.dedupeKeys.add(key);
    }

    const delta = this.cues.slice(existingCount).map((cue) => ({ ...cue }));
    if (delta.length === 0) {
      return null;
    }
    return { mode: 'append', cues: delta };
  }

  private buildProviderTimeline(
    timestamps: SpokenWordTimestamp[],
    timeBase: 'segment' | 'utterance',
    offsetMs: number
  ): SpokenWordCue[] {
    const cues: SpokenWordCue[] = [];
    const normalizedOffsetMs = normalizeMs(offsetMs, 0);
    let lastEndMs = 0;

    for (const value of timestamps) {
      const normalized = normalizeTimestamp(value);
      if (!normalized) {
        continue;
      }
      const startMsRaw =
        timeBase === 'utterance'
          ? normalized.startMs
          : normalizedOffsetMs + normalized.startMs;
      const endMsRaw =
        timeBase === 'utterance'
          ? normalized.endMs
          : normalizedOffsetMs + normalized.endMs;
      const startMs = Math.max(lastEndMs, startMsRaw);
      const endMs = Math.max(startMs, endMsRaw);
      cues.push({
        word: normalized.word,
        startMs,
        endMs,
        source: 'provider',
        timeBase: 'utterance',
      });
      lastEndMs = endMs;
    }

    return cues;
  }

  private buildSyntheticTimeline(spokenText: string, playbackMs: number): SpokenWordCue[] {
    const words = tokenizeWords(spokenText);
    if (words.length === 0) {
      return [];
    }
    const onset = this.speechOnsetMs;
    return distributeWordsIntoWindow(
      words, onset, Math.max(onset, playbackMs), 'synthetic', this.punctuationPauseMs
    );
  }

  private replaceTimeline(cues: SpokenWordCue[]): void {
    this.cues = cues.map((cue) => ({ ...cue }));
    this.dedupeKeys.clear();
    for (const cue of this.cues) {
      this.dedupeKeys.add(cueKey(cue.word, cue.startMs, cue.endMs));
    }
  }
}

export function cuesToWordTimestamps(cues: SpokenWordCue[]): SpokenWordTimestamp[] {
  return cues.map((cue) => ({
    word: cue.word,
    startMs: cue.startMs,
    endMs: cue.endMs,
  }));
}

/**
 * Resolve how many words are fully heard at a playback position.
 * Uses cue end boundaries (not start) so partially spoken words are excluded.
 */
export function resolveWordCountAtPlaybackMs(
  cues: SpokenWordCue[],
  playbackMs: number
): number {
  if (!Array.isArray(cues) || cues.length === 0) {
    return 0;
  }

  const timeMs = Number.isFinite(playbackMs) ? Math.max(0, playbackMs) : 0;
  let low = 0;
  let high = cues.length - 1;
  let count = 0;

  while (low <= high) {
    const middle = (low + high) >> 1;
    const cue = cues[middle];
    const cueEndMs = cue ? Math.max(0, cue.endMs) : 0;
    if (cueEndMs <= timeMs) {
      count = middle + 1;
      low = middle + 1;
    } else {
      high = middle - 1;
    }
  }

  return count;
}

function distributeWordsIntoWindow(
  words: string[],
  startMsInput: number,
  endMsInput: number,
  source: SpokenWordCueSource,
  punctuationPauseMs: number = 0
): SpokenWordCue[] {
  if (words.length === 0) {
    return [];
  }

  const startMs = normalizeMs(startMsInput, 0);
  const endMs = Math.max(startMs, normalizeMs(endMsInput, startMs));
  const spanMs = Math.max(words.length, endMs - startMs);

  // Count punctuation words for weighted distribution.
  const punctCount =
    punctuationPauseMs > 0
      ? words.filter((w) => hasPausePunctuation(w)).length
      : 0;

  // Solve: words.length * baseDuration + punctCount * punctuationPauseMs = spanMs
  const totalPause = punctCount * punctuationPauseMs;
  const baseDuration = Math.max(1, (spanMs - totalPause) / words.length);

  const cues: SpokenWordCue[] = [];
  let cursorMs = startMs;

  for (let index = 0; index < words.length; index += 1) {
    const word = words[index] ?? '';
    const isPunct = punctuationPauseMs > 0 && hasPausePunctuation(word);
    const wordDuration = baseDuration + (isPunct ? punctuationPauseMs : 0);
    const projectedEnd = cursorMs + wordDuration;
    const nextBoundary =
      index === words.length - 1
        ? Math.max(endMs, projectedEnd)
        : projectedEnd;
    const cueStartMs = Math.max(cursorMs, startMs);
    const cueEndMs = Math.max(cueStartMs, nextBoundary);
    cues.push({
      word,
      startMs: cueStartMs,
      endMs: cueEndMs,
      source,
      timeBase: 'utterance',
    });
    cursorMs = cueEndMs;
  }

  return cues;
}

function hasPausePunctuation(word: string): boolean {
  if (!word) return false;
  const trimmed = word.trim().replace(/[)"'\]}>»\u201D\u2019]+$/u, '');
  return /[.,!?;:\u2026]$/u.test(trimmed);
}

function tokenizeWords(text: string): string[] {
  if (!text) {
    return [];
  }
  return text.split(/\s+/).map((token) => token.trim()).filter(Boolean);
}

function normalizeTimestamp(
  value: SpokenWordTimestamp
): { word: string; startMs: number; endMs: number } | null {
  if (!value || typeof value.word !== 'string') {
    return null;
  }
  const word = value.word.trim();
  if (!word) {
    return null;
  }
  if (!Number.isFinite(value.startMs) || !Number.isFinite(value.endMs)) {
    return null;
  }
  const startMs = Math.max(0, value.startMs);
  const endMs = Math.max(startMs, value.endMs);
  return { word, startMs, endMs };
}

function normalizeText(value: string): string {
  return typeof value === 'string' ? value : '';
}

function normalizeMs(value: number, fallback: number): number {
  if (!Number.isFinite(value) || value < 0) {
    return Math.max(0, fallback);
  }
  return Math.max(0, value);
}

function cueKey(word: string, startMs: number, endMs: number): string {
  return `${word}|${Math.round(startMs * 1000)}|${Math.round(endMs * 1000)}`;
}



