/**
 * Simple Router Hook - URL-based navigation without external dependencies
 *
 * Supports:
 * - /session/:sessionId - Focus a specific session
 * - / - Home (default view)
 * - /dev - Dev page
 */

import { useState, useEffect, useRef } from 'react';

export type SettingsPage =
  | 'agents'
  | 'voice-pipeline'
  | 'voices'
  | 'audio'
  | 'credentials'
  | 'models'
  | 'system';

export interface RouteParams {
  sessionId?: string;
  settingsPage?: SettingsPage;
}

export interface RouterState {
  path: string;
  params: RouteParams;
}

/**
 * Parse the current URL path and extract route parameters.
 */
const SETTINGS_PAGES: Set = new Set([
  'agents',
  'voice-pipeline',
  'voices',
  'audio',
  'credentials',
  'models',
  'system',
]);

function parseRoute(pathname: string): RouterState {
  const params: RouteParams = {};

  // Match /session/:sessionId
  const sessionMatch = pathname.match(/^\/session\/([a-zA-Z0-9_-]+)\/?$/);
  if (sessionMatch) {
    params.sessionId = sessionMatch[1];
    return { path: '/session/:sessionId', params };
  }

  // Match /settings/:page?
  const settingsMatch = pathname.match(/^\/settings(?:\/([a-z-]+))?\/?$/);
  if (settingsMatch) {
    const page = settingsMatch[1];
    params.settingsPage = (page && SETTINGS_PAGES.has(page) ? page : 'agents') as SettingsPage;
    return { path: '/settings', params };
  }

  // Match /dev
  if (pathname === '/dev' || pathname === '/dev/') {
    return { path: '/dev', params };
  }

  // Default to home
  return { path: '/', params };
}

/**
 * Navigate to a new URL path.
 */
export function navigate(path: string, replace = false): void {
  // Skip if already at this path - prevents unnecessary state updates
  if (window.location.pathname === path) {
    console.log(`[Router] Already at ${path}, skipping navigation`);
    return;
  }

  if (replace) {
    window.history.replaceState(null, '', path);
  } else {
    window.history.pushState(null, '', path);
  }
  // Dispatch popstate event so listeners update
  window.dispatchEvent(new PopStateEvent('popstate'));
}

/**
 * Navigate to a settings page.
 */
export function navigateToSettings(page?: SettingsPage, replace = false): void {
  navigate(page ? `/settings/${page}` : '/settings/agents', replace);
}

/**
 * Navigate to a specific session.
 */
export function navigateToSession(sessionId: string | null, replace = false): void {
  if (sessionId) {
    navigate(`/session/${sessionId}`, replace);
  } else {
    navigate('/', replace);
  }
}

/**
 * Hook to get current route state and listen for changes.
 */
export function useRouter(): RouterState {
  const [state, setState] = useState(() => parseRoute(window.location.pathname));

  useEffect(() => {
    const handlePopState = () => {
      setState(parseRoute(window.location.pathname));
    };

    window.addEventListener('popstate', handlePopState);
    return () => window.removeEventListener('popstate', handlePopState);
  }, []);

  return state;
}

/**
 * Hook to get the session ID from URL (convenience wrapper).
 */
export function useSessionIdFromUrl(): string | null {
  const { params } = useRouter();
  return params.sessionId ?? null;
}

/**
 * Hook to sync focusedSessionId with URL.
 * - When URL changes → update store (primary direction)
 * - When store changes programmatically → update URL (secondary)
 */
export function useUrlSessionSync(
  focusedSessionId: string | null,
  focusSession: (id: string) => void
): void {
  const { params } = useRouter();
  const urlSessionId = params.sessionId ?? null;

  // Use ref for focusSession to avoid it being an effect dependency
  const focusSessionRef = useRef(focusSession);
  focusSessionRef.current = focusSession;

  // Track previous values to detect which one changed
  const prevUrlRef = useRef(null);
  const prevFocusRef = useRef(null);

  useEffect(() => {
    const urlChanged = urlSessionId !== prevUrlRef.current;
    const focusChanged = focusedSessionId !== prevFocusRef.current;

    // Update refs for next render
    prevUrlRef.current = urlSessionId;
    prevFocusRef.current = focusedSessionId;

    // Already in sync - nothing to do
    if (urlSessionId === focusedSessionId) {
      return;
    }

    // URL changed (user navigation) → sync to store
    if (urlChanged && urlSessionId) {
      console.log(`[Router] URL→Store: ${urlSessionId.slice(0, 8)}`);
      focusSessionRef.current(urlSessionId);
      return;
    }

    // Focus changed (programmatic) → sync to URL
    if (focusChanged) {
      if (focusedSessionId) {
        console.log(`[Router] Store→URL: ${focusedSessionId.slice(0, 8)}`);
        navigateToSession(focusedSessionId, true);
      } else if (urlSessionId) {
        console.log(`[Router] Store→URL: clearing to /`);
        navigate('/', true);
      }
      return;
    }

    // Neither changed but they differ - URL takes precedence (initial load case)
    if (urlSessionId) {
      console.log(`[Router] Initial sync URL→Store: ${urlSessionId.slice(0, 8)}`);
      focusSessionRef.current(urlSessionId);
    }
  }, [urlSessionId, focusedSessionId]);
}



/**
 * Audio Controller - Manages browser microphone capture and audio playback.
 *
 * - Captures microphone audio via AudioWorklet
 * - Resamples to 24kHz PCM16 for OpenAI Realtime API
 * - Plays back PCM16 24kHz audio from the agent
 */

export type AudioSendFn = (data: ArrayBuffer) => void;

export interface AudioControllerConfig {
  onAudio?: AudioSendFn;
  onError?: (error: Error) => void;
}

const TARGET_SAMPLE_RATE = 24000;

export class AudioController {
  private context: AudioContext | null = null;
  private mediaStream: MediaStream | null = null;
  private sourceNode: MediaStreamAudioSourceNode | null = null;
  private workletNode: AudioWorkletNode | null = null;
  private onAudio: AudioSendFn | null = null;
  private onError: ((error: Error) => void) | null = null;

  // Playback
  private playbackContext: AudioContext | null = null;
  private playbackQueue: ArrayBuffer[] = [];
  private isPlaying = false;
  private playbackStartTime = 0;
  private samplesScheduled = 0;
  private activeSources = new Set();

  constructor(config: AudioControllerConfig = {}) {
    this.onAudio = config.onAudio || null;
    this.onError = config.onError || null;
  }

  /**
   * Set the callback for sending audio data to the server.
   */
  setOnAudio(fn: AudioSendFn): void {
    this.onAudio = fn;
  }

  /**
   * Start microphone capture.
   */
  async start(): Promise {
    try {
      // Request microphone access
      this.mediaStream = await navigator.mediaDevices.getUserMedia({
        audio: {
          echoCancellation: true,
          noiseSuppression: true,
          autoGainControl: true,
          sampleRate: { ideal: 48000 },
        },
        video: false,
      });
      const micTrack = this.mediaStream.getAudioTracks()[0];
      const micSettings = micTrack?.getSettings();
      const micConstraints = micTrack?.getConstraints();
      console.log('[Audio] Mic capture settings', {
        deviceId: micSettings?.deviceId ?? 'unknown',
        sampleRate: micSettings?.sampleRate ?? 'unknown',
        channelCount: micSettings?.channelCount ?? 'unknown',
        echoCancellation: micSettings?.echoCancellation ?? 'unknown',
        noiseSuppression: micSettings?.noiseSuppression ?? 'unknown',
        autoGainControl: micSettings?.autoGainControl ?? 'unknown',
      });
      console.log('[Audio] Mic capture constraints', micConstraints ?? {});

      // Create AudioContext
      this.context = new AudioContext({
        sampleRate: 48000, // Browser typically supports 44100 or 48000
      });

      // Load AudioWorklet
      await this.context.audioWorklet.addModule('/audio-processor.js');

      // Create source node from microphone
      this.sourceNode = this.context.createMediaStreamSource(this.mediaStream);

      // Create worklet node
      this.workletNode = new AudioWorkletNode(this.context, 'audio-processor');

      // Handle processed audio from worklet
      this.workletNode.port.onmessage = (event) => {
        if (event.data.type === 'audio' && this.onAudio) {
          this.onAudio(event.data.data);
        }
      };

      // Connect: microphone -> worklet (no output, we just capture)
      this.sourceNode.connect(this.workletNode);

      // Initialize playback context
      this.playbackContext = new AudioContext({
        sampleRate: TARGET_SAMPLE_RATE,
      });

      console.log('[Audio] Capture started');
    } catch (error) {
      console.error('[Audio] Failed to start capture:', error);
      if (this.onError) {
        this.onError(error as Error);
      }
      throw error;
    }
  }

  /**
   * Stop microphone capture and clean up resources.
   */
  stop(): void {
    // Stop capture
    if (this.workletNode) {
      this.workletNode.disconnect();
      this.workletNode = null;
    }

    if (this.sourceNode) {
      this.sourceNode.disconnect();
      this.sourceNode = null;
    }

    if (this.context) {
      this.context.close();
      this.context = null;
    }

    if (this.mediaStream) {
      this.mediaStream.getTracks().forEach((track) => track.stop());
      this.mediaStream = null;
    }

    // Stop playback and reset scheduling state
    // CRITICAL: Must reset playbackStartTime and samplesScheduled so that
    // the next session doesn't schedule audio far in the future based on
    // stale values from the previous session
    this.playbackQueue = [];
    this.isPlaying = false;
    this.playbackStartTime = 0;
    this.samplesScheduled = 0;
    this.stopAllSources();

    if (this.playbackContext) {
      this.playbackContext.close();
      this.playbackContext = null;
    }

    console.log('[Audio] Stopped');
  }

  /**
   * Queue PCM16 24kHz audio for playback.
   */
  playAudio(data: ArrayBuffer): void {
    // Validate input
    if (!data || data.byteLength === 0) {
      return;
    }

    try {
      if (!this.playbackContext || this.playbackContext.state === 'closed') {
        // Lazy init playback context if capture wasn't started or context was closed
        this.playbackContext = new AudioContext({
          sampleRate: TARGET_SAMPLE_RATE,
        });
      }

      // Resume context if suspended (required for autoplay policy)
      if (this.playbackContext.state === 'suspended') {
        this.playbackContext.resume();
      }

      // Add to queue
      this.playbackQueue.push(data);

      // Start playback if not already playing
      if (!this.isPlaying) {
        this.processPlaybackQueue();
      }
    } catch (err) {
      console.error('[Audio] Error queueing playback:', err);
    }
  }

  /**
   * Process the playback queue, scheduling audio buffers.
   */
  private processPlaybackQueue(): void {
    if (!this.playbackContext || this.playbackQueue.length === 0) {
      this.isPlaying = false;
      return;
    }

    this.isPlaying = true;

    // Process all queued buffers
    while (this.playbackQueue.length > 0) {
      const data = this.playbackQueue.shift()!;
      this.scheduleAudioBuffer(data);
    }
  }

  /**
   * Schedule an audio buffer for playback.
   */
  private scheduleAudioBuffer(data: ArrayBuffer): void {
    if (!this.playbackContext || this.playbackContext.state === 'closed') return;

    try {
      if (data.byteLength < 2) return;
      if (data.byteLength % 2 !== 0) {
        // Defensive guard against malformed PCM16 payload boundaries.
        data = data.slice(0, data.byteLength - 1);
      }
      if (data.byteLength < 2) return;

      // Convert PCM16 to Float32
      const pcm16 = new Int16Array(data);
      if (pcm16.length === 0) return;

      const float32 = new Float32Array(pcm16.length);

      for (let i = 0; i < pcm16.length; i++) {
        float32[i] = pcm16[i] / 0x8000;
      }

      // Create audio buffer
      const audioBuffer = this.playbackContext.createBuffer(
        1, // mono
        float32.length,
        TARGET_SAMPLE_RATE
      );
      audioBuffer.getChannelData(0).set(float32);

      // Create buffer source
      const source = this.playbackContext.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(this.playbackContext.destination);

      // Calculate when to start this buffer
      const currentTime = this.playbackContext.currentTime;

      // Check if we've fallen behind: compare END of scheduled audio vs current time
      // This prevents resetting during rapid buffer processing in a loop
      const scheduledEndTime = this.playbackStartTime + (this.samplesScheduled / TARGET_SAMPLE_RATE);
      if (this.samplesScheduled === 0 || scheduledEndTime < currentTime) {
        // First buffer or we've actually fallen behind - start immediately
        this.playbackStartTime = currentTime;
        this.samplesScheduled = 0;
      }

      const startOffset = this.samplesScheduled / TARGET_SAMPLE_RATE;
      const startTime = this.playbackStartTime + startOffset;

      source.start(startTime);
      this.samplesScheduled += float32.length;
      this.activeSources.add(source);

      // When this buffer ends, check for more
      source.onended = () => {
        this.activeSources.delete(source);
        if (this.playbackQueue.length > 0) {
          this.processPlaybackQueue();
        } else {
          this.isPlaying = false;
        }
      };
    } catch (err) {
      console.error('[Audio] Error scheduling audio buffer:', err);
      this.isPlaying = false;
    }
  }

  /**
   * Get current playback position in milliseconds.
   * Based on AudioContext.currentTime — the real clock of what the user has heard.
   * Clamped to [0, scheduledDuration] so stale values between turns don't overshoot.
   */
  getPlaybackPositionMs(): number {
    const snapshot = this.getPlaybackSnapshot();
    return snapshot.positionMs;
  }

  /**
   * Get total scheduled audio duration in milliseconds.
   */
  getScheduledDurationMs(): number {
    const snapshot = this.getPlaybackSnapshot();
    return snapshot.scheduledMs;
  }

  /**
   * Interrupt current playback.
   */
  interrupt(): void {
    this.playbackQueue = [];
    this.samplesScheduled = 0;
    this.playbackStartTime = 0;
    this.isPlaying = false;
    this.stopAllSources();

    if (this.playbackContext) {
      const oldContext = this.playbackContext;
      this.playbackContext = null;
      void oldContext.close().catch((error) => {
        console.warn('[Audio] Failed to close interrupted playback context:', error);
      });
    }
  }

  /**
   * Check if capture is active.
   */
  isCapturing(): boolean {
    return this.context !== null && this.context.state === 'running';
  }

  /**
   * Snapshot of the current playback timeline.
   * Returns zeros once the scheduled timeline has fully elapsed.
   */
  private getPlaybackSnapshot(): { positionMs: number; scheduledMs: number } {
    if (!this.playbackContext || this.samplesScheduled === 0) {
      return { positionMs: 0, scheduledMs: 0 };
    }

    const scheduledDurationSec = this.samplesScheduled / TARGET_SAMPLE_RATE;
    const scheduledEndSec = this.playbackStartTime + scheduledDurationSec;
    const nowSec = this.playbackContext.currentTime;

    // Reset stale schedule after playback drained (between turns).
    if (scheduledEndSec <= nowSec) {
      this.samplesScheduled = 0;
      this.playbackStartTime = 0;
      return { positionMs: 0, scheduledMs: 0 };
    }

    const elapsedSec = Math.max(0, nowSec - this.playbackStartTime);
    const positionMs = Math.min(elapsedSec, scheduledDurationSec) * 1000;
    const scheduledMs = scheduledDurationSec * 1000;
    return { positionMs, scheduledMs };
  }

  /**
   * Stop and disconnect all active playback sources immediately.
   */
  private stopAllSources(): void {
    for (const source of this.activeSources) {
      try {
        source.onended = null;
        source.stop(0);
      } catch {
        // Source may already be ended/stopped.
      }
      try {
        source.disconnect();
      } catch {
        // No-op if already disconnected.
      }
    }
    this.activeSources.clear();
  }
}



/**
 * Unified Stream Types - AI SDK Protocol for all agent events.
 *
 * This module defines the unified event protocol used by all agents (voice, subagent).
 * Events follow the Vercel AI SDK Data Stream Protocol format, enabling:
 * - One handler for all agent types on the frontend
 * - Consistent message accumulation logic
 * - Compatible with AI Elements components
 *
 * See: https://ai-sdk.dev/docs/ai-sdk-ui/stream-protocol
 */

/**
 * AI SDK stream event types.
 * These match the events from `streamText().fullStream` in AI SDK v5.
 *
 * Verified against ai@5.0.108 TypeScript types:
 * - 'text-delta' with textDelta property
 * - 'tool-call' with input property
 * - 'tool-result' with output property
 */
export interface SpokenWordCue {
  word: string;
  startMs: number;
  endMs: number;
  source: 'provider' | 'synthetic';
  timeBase: 'utterance';
}

export interface SpokenWordCueUpdate {
  mode: 'append' | 'replace';
  cues: SpokenWordCue[];
}

export type AISDKStreamEvent =
  // Text streaming
  | {
      type: 'text-delta';
      textDelta: string;
      itemId?: string;
      order?: number;
      channel?: 'generated' | 'spoken';
    }

  // Spoken transcript (custom extension for voice sessions)
  | {
      type: 'spoken-delta';
      textDelta: string;
      itemId?: string;
      order?: number;
      spokenChars?: number;
      spokenWords?: number;
      playbackMs?: number;
      precision?: 'ratio' | 'segment' | 'aligned' | 'provider-word-timestamps';
      wordTimestamps?: Array<{ word: string; startMs: number; endMs: number }>;
      wordCues?: SpokenWordCue[];
      wordCueUpdate?: SpokenWordCueUpdate;
    }
  | {
      type: 'spoken-progress';
      itemId: string;
      spokenChars: number;
      spokenWords: number;
      playbackMs: number;
      precision: 'ratio' | 'segment' | 'aligned' | 'provider-word-timestamps';
    }
  | {
      type: 'spoken-final';
      text: string;
      itemId?: string;
      order?: number;
      spokenChars?: number;
      spokenWords?: number;
      playbackMs?: number;
      precision?: 'ratio' | 'segment' | 'aligned' | 'provider-word-timestamps';
      wordTimestamps?: Array<{ word: string; startMs: number; endMs: number }>;
      wordCues?: SpokenWordCue[];
      wordCueUpdate?: SpokenWordCueUpdate;
    }

  // User transcript (custom extension for voice sessions)
  | { type: 'user-transcript'; text: string; itemId?: string; order?: number }

  // Placeholders for message ordering (custom extension for voice sessions)
  // These reserve position in the timeline before transcripts arrive
  | { type: 'user-placeholder'; itemId: string; previousItemId?: string; order?: number }
  | { type: 'assistant-placeholder'; itemId: string; previousItemId?: string; order?: number }

  // Tool calls
  | { type: 'tool-call'; toolName: string; toolCallId: string; input: unknown }
  | { type: 'tool-result'; toolName: string; toolCallId: string; output: unknown }

  // Reasoning (for thinking models like Grok, DeepSeek R1)
  | { type: 'reasoning-start' }
  | { type: 'reasoning-delta'; text: string }
  | { type: 'reasoning-end'; text: string; durationMs?: number }

  // Step lifecycle
  | { type: 'start' }
  | { type: 'start-step' }
  | {
      type: 'finish-step';
      finishReason?: string;
      usage?: {
        inputTokens?: number;
        outputTokens?: number;
        totalTokens?: number;
        reasoningTokens?: number;
      };
    }
  | { type: 'finish'; finishReason: string }

  // Errors
  | { type: 'error'; error: string }

  // Latency metrics (custom extension for runtime observability)
  | {
      type: 'latency';
      stage: 'stt' | 'llm' | 'tts' | 'turn' | 'tool' | 'connection';
      durationMs: number;
      provider?: string;
      model?: string;
      details?: Record;
    }

  // Process lifecycle notifications (background tasks)
  | { type: 'process-status'; processName: string; sessionId: string; status: 'completed' | 'error'; summary?: string };

/**
 * Unified stream chunk message sent via WebSocket.
 *
 * All agents (voice, CLI, web-search) emit this format.
 * The frontend accumulates these into conversation messages.
 */
export interface StreamChunkMessage {
  type: 'stream_chunk';
  /** Session ID this event belongs to */
  sessionId: string;
  /** The AI SDK format event */
  event: AISDKStreamEvent;
  /** Timestamp when event was emitted */
  timestamp: number;
}

/**
 * Session status for stream events.
 */
export type StreamSessionStatus = 'running' | 'finished' | 'error' | 'cancelled';

/**
 * Session metadata for stream chunk context.
 */
export interface StreamSessionMeta {
  sessionId: string;
  agentName: string;
  status: StreamSessionStatus;
}

/**
 * Helper to create a stream chunk message.
 */
export function createStreamChunk(
  sessionId: string,
  event: AISDKStreamEvent
): StreamChunkMessage {
  return {
    type: 'stream_chunk',
    sessionId,
    event,
    timestamp: Date.now(),
  };
}



/**
 * Webhook API - Receives status updates from the Mac daemon.
 *
 * The Mac daemon sends POST requests to /webhooks/cli-status when:
 * - A session finishes
 * - A session encounters an error
 * - A session is waiting for input
 *
 * This allows the Pi to react to session changes proactively.
 */

import http from 'http';
import fs from 'fs';
import path from 'path';
import type { Socket } from 'net';
import {
  CliSessionsRepository,
  CliEventsRepository,
  SessionMessagesRepository,
  HandoffsRepository,
  type Session,
  type SessionStatus,
} from '../db/index.js';
import { handleDemoRequest } from '../demo/index.js';
import { eventRecorder } from './event-recorder.js';
import { wsBroadcast } from './websocket.js';
import { clearAllSessionLogs, clearSessionLogsForSessions, logWebhookStatus } from '../logging/session-logger.js';
import * as macClient from '../tools/mac-client.js';
import {
  listPrompts,
  getPromptInfo,
  getPromptConfig,
  getPromptVersion,
  listVersions,
  createPromptVersion,
  setActiveVersion,
  createPrompt,
  updatePromptConfig,
  getActivePromptRaw,
  type PromptConfig,
} from '../prompts/index.js';
import { profiles } from '../agent/profiles.js';
import { resolveVoiceRuntimeConfig } from '../voice/config.js';
import {
  loadVoiceConfig,
  saveVoiceConfig,
  loadAuthProfiles,
  saveAuthProfiles,
  redactAuthProfiles,
  resolveApiKey,
  getVoiceConfigPath,
  getAuthProfilesPath,
} from '../voice/settings.js';
import {
  listVoices,
  getVoice,
  saveVoice,
  deleteVoice,
  type VoiceMeta,
} from '../voice/voices.js';
import {
  fetchRuntimeProviderCatalogFromAuthProfiles,
  getRuntimeConfigManifest,
  runtimeAuthKeySetToProviderMap,
  testRuntimeProviderCredentials,
  type RuntimeAuthProvider,
} from '@voiceclaw/voice-runtime';

const PORT = parseInt(process.env.WEBHOOK_PORT ?? '3000', 10);
const OPEN_ROUTER_API_KEY = process.env.OPEN_ROUTER_API_KEY ?? '';

// OpenRouter models cache
let modelsCache: { data: unknown[]; timestamp: number } | null = null;
const MODELS_CACHE_TTL = 10 * 60 * 1000; // 10 minutes
let voiceCatalogCache: { data: unknown; timestamp: number } | null = null;
const VOICE_CATALOG_CACHE_TTL = 5 * 60 * 1000; // 5 minutes

interface WebhookPayload {
  sessionId: string;
  status: 'running' | 'waiting_for_input' | 'finished' | 'error';
  message?: string;
  output?: string[];
}

type WebhookHandler = (payload: WebhookPayload) => Promise;

let webhookHandler: WebhookHandler | null = null;
let server: http.Server | null = null;
const openConnections = new Set();

// Pending session completions - resolve when webhook received
const pendingCompletions = new Map<
  string,
  { resolve: (payload: WebhookPayload) => void; timeout: ReturnType }
>();

/**
 * Set a handler for webhook events.
 * This can be used to notify the agent about session changes.
 */
export function onWebhookEvent(handler: WebhookHandler): void {
  webhookHandler = handler;
}

/**
 * Wait for a session to complete via webhook (no polling).
 * Returns when the webhook is received or timeout is reached.
 */
export function waitForSessionCompletion(
  sessionId: string,
  timeoutMs = 300_000
): Promise {
  return new Promise((resolve) => {
    // Check if already completed
    const timeout = setTimeout(() => {
      pendingCompletions.delete(sessionId);
      console.log(`[Webhook] Timeout waiting for session ${sessionId}`);
      resolve(null);
    }, timeoutMs);

    pendingCompletions.set(sessionId, { resolve, timeout });
    console.log(`[Webhook] Waiting for session ${sessionId} completion via webhook`);
  });
}

/**
 * Resolve a pending session completion (called when webhook received).
 */
function resolvePendingCompletion(payload: WebhookPayload): void {
  const pending = pendingCompletions.get(payload.sessionId);
  if (pending) {
    clearTimeout(pending.timeout);
    pendingCompletions.delete(payload.sessionId);
    console.log(`[Webhook] Session ${payload.sessionId} status: ${payload.status}`);
    pending.resolve(payload);
  }
}

/**
 * Add CORS headers for browser requests.
 */
function setCorsHeaders(res: http.ServerResponse): void {
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET, POST, PUT, DELETE, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');
}

async function readJsonBody(req: http.IncomingMessage): Promise {
  return new Promise((resolve, reject) => {
    let body = '';
    req.on('data', (chunk) => {
      body += chunk.toString();
    });
    req.on('end', () => {
      try {
        resolve((body ? JSON.parse(body) : {}) as T);
      } catch (error) {
        reject(error);
      }
    });
    req.on('error', reject);
  });
}

function maskKey(value: string): string {
  if (!value) return '';
  if (value.length <= 8) return '********';
  return `${value.slice(0, 4)}...${value.slice(-4)}`;
}

function resolveLocalInferenceEndpoint(): string {
  const envEndpoint = process.env.LOCAL_INFERENCE_ENDPOINT?.trim();
  if (envEndpoint) return envEndpoint;

  try {
    const config = loadVoiceConfig();
    const providerSettings = config.voice.providerSettings;
    const decomposedSettings = providerSettings?.decomposed;
    const configuredEndpoint = decomposedSettings?.localEndpoint;
    if (typeof configuredEndpoint === 'string' && configuredEndpoint.trim().length > 0) {
      return configuredEndpoint.trim();
    }
  } catch {
    // Non-fatal: fall back to default local-inference endpoint.
  }

  return 'http://localhost:1060';
}

async function proxyLocalInferenceJson(
  req: http.IncomingMessage,
  res: http.ServerResponse,
  upstreamPath: string
): Promise {
  try {
    const endpoint = new URL(upstreamPath, resolveLocalInferenceEndpoint());
    const method = req.method ?? 'GET';
    const hasBody = method !== 'GET' && method !== 'HEAD';
    const payload = hasBody
      ? await readJsonBody<Record>(req)
      : undefined;

    const upstream = await fetch(endpoint, {
      method,
      headers: hasBody ? { 'Content-Type': 'application/json' } : undefined,
      body: hasBody ? JSON.stringify(payload ?? {}) : undefined,
    });
    const text = await upstream.text();
    res.writeHead(upstream.status, {
      'Content-Type': upstream.headers.get('content-type') ?? 'application/json',
    });
    res.end(text);
  } catch (error) {
    console.error(`[API] Local inference proxy error (${upstreamPath}):`, error);
    res.writeHead(502, { 'Content-Type': 'application/json' });
    res.end(
      JSON.stringify({
        error: `Failed to reach local inference endpoint (${resolveLocalInferenceEndpoint()})`,
      })
    );
  }
}

/**
 * Handle incoming webhook and API requests.
 */
async function handleWebhook(
  req: http.IncomingMessage,
  res: http.ServerResponse
): Promise {
  setCorsHeaders(res);

  // Handle preflight
  if (req.method === 'OPTIONS') {
    res.writeHead(204);
    res.end();
    return;
  }

  // Handle health check
  if (req.method === 'GET' && req.url === '/health') {
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ status: 'ok' }));
    return;
  }

  // Handle demo API routes
  if (req.url?.startsWith('/api/demo')) {
    const handled = await handleDemoRequest(req, res);
    if (handled) return;
  }

  // ═══════════════════════════════════════════════════════════════════════════
  // REST API for Sessions
  // ═══════════════════════════════════════════════════════════════════════════

  // GET /api/sessions - List all sessions
  if (req.method === 'GET' && req.url === '/api/sessions') {
    try {
      const sessionsRepo = new CliSessionsRepository();
      const sessions = sessionsRepo.list();
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify(sessions));
    } catch (error) {
      console.error('[API] Error fetching sessions:', error);
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Failed to fetch sessions' }));
    }
    return;
  }

  // GET /api/sessions/active - List active sessions only
  if (req.method === 'GET' && req.url === '/api/sessions/active') {
    try {
      const sessionsRepo = new CliSessionsRepository();
      const sessions = sessionsRepo.getActive();
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify(sessions));
    } catch (error) {
      console.error('[API] Error fetching active sessions:', error);
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Failed to fetch active sessions' }));
    }
    return;
  }

  // GET /api/sessions/:id - Get a single session
  const sessionMatch = req.url?.match(/^\/api\/sessions\/([a-zA-Z0-9_-]+)$/);
  if (req.method === 'GET' && sessionMatch) {
    try {
      const sessionId = sessionMatch[1]!;
      const sessionsRepo = new CliSessionsRepository();
      const session = sessionsRepo.findById(sessionId);
      if (session) {
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify(session));
      } else {
        res.writeHead(404, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Session not found' }));
      }
    } catch (error) {
      console.error('[API] Error fetching session:', error);
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Failed to fetch session' }));
    }
    return;
  }

  // GET /api/sessions/:id/events - Get session events
  const eventsMatch = req.url?.match(/^\/api\/sessions\/([a-zA-Z0-9_-]+)\/events$/);
  if (req.method === 'GET' && eventsMatch) {
    try {
      const sessionId = eventsMatch[1]!;
      const eventsRepo = new CliEventsRepository();
      const events = eventsRepo.getBySession(sessionId);
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify(events));
    } catch (error) {
      console.error('[API] Error fetching session events:', error);
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Failed to fetch session events' }));
    }
    return;
  }

  // DELETE /api/sessions - Delete all sessions
  if (req.method === 'DELETE' && req.url === '/api/sessions') {
    try {
      const sessionsRepo = new CliSessionsRepository();
      const handoffsRepo = new HandoffsRepository();

      const activeStatuses: SessionStatus[] = ['pending', 'running', 'waiting_for_input'];
      const sessions = sessionsRepo.list();
      const activeTerminalSessions = sessions.filter(
        (session) =>
          activeStatuses.includes(session.status) &&
          (session.type === 'terminal' || session.mac_session_id !== null)
      );

      let terminatedPtySessions = 0;
      const terminationErrors: string[] = [];

      // Best-effort PTY termination before DB cleanup.
      for (const session of activeTerminalSessions) {
        try {
          const result = await macClient.terminateSession(session.id);
          if (result.success) {
            terminatedPtySessions += 1;
          } else {
            terminationErrors.push(`${session.id.slice(0, 8)}: ${result.message}`);
          }
        } catch (error) {
          const message = error instanceof Error ? error.message : String(error);
          terminationErrors.push(`${session.id.slice(0, 8)}: ${message}`);
        }
      }

      // Remove handoff packets first to avoid FK violations on cli_sessions.
      const deletedHandoffs = handoffsRepo.deleteAll();
      const deleted = sessionsRepo.deleteAll();
      const deletedLogs = clearAllSessionLogs();

      if (terminationErrors.length > 0) {
        console.warn('[API] PTY termination warnings:', terminationErrors);
      }

      console.log(
        `[API] Cleared ${deleted} sessions, ${deletedHandoffs} handoffs, ${deletedLogs} session logs, terminated ${terminatedPtySessions} PTY sessions`
      );

      // Broadcast to all connected clients
      wsBroadcast.cliAllSessionsDeleted();
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({
        deleted,
        deletedHandoffs,
        deletedLogs,
        terminatedPtySessions,
        terminationErrors,
      }));
    } catch (error) {
      console.error('[API] Error deleting sessions:', error);
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Failed to delete sessions' }));
    }
    return;
  }

  // DELETE /api/sessions/:id/tree - Delete a thread tree (root + descendants)
  const deleteTreeMatch = req.url?.match(/^\/api\/sessions\/([a-zA-Z0-9_-]+)\/tree$/);
  if (req.method === 'DELETE' && deleteTreeMatch) {
    try {
      const rootId = deleteTreeMatch[1]!;
      const sessionsRepo = new CliSessionsRepository();
      const rootSession = sessionsRepo.findById(rootId);

      if (!rootSession) {
        res.writeHead(404, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Session not found' }));
        return;
      }

      const treeIds = sessionsRepo.getTreeSessionIds(rootId);
      const treeSessions: Session[] = treeIds
        .map((id) => sessionsRepo.findById(id))
        .filter((session): session is Session => session !== null);

      const activeStatuses: SessionStatus[] = ['pending', 'running', 'waiting_for_input'];
      const activeTerminalSessions = treeSessions.filter(
        (session) =>
          activeStatuses.includes(session.status) &&
          (session.type === 'terminal' || session.mac_session_id !== null)
      );

      let terminatedPtySessions = 0;
      const terminationErrors: string[] = [];

      // Best-effort PTY termination before DB cleanup.
      for (const session of activeTerminalSessions) {
        try {
          const result = await macClient.terminateSession(session.id);
          if (result.success) {
            terminatedPtySessions += 1;
          } else {
            terminationErrors.push(`${session.id.slice(0, 8)}: ${result.message}`);
          }
        } catch (error) {
          const message = error instanceof Error ? error.message : String(error);
          terminationErrors.push(`${session.id.slice(0, 8)}: ${message}`);
        }
      }

      const deletedLogs = clearSessionLogsForSessions(
        treeSessions.map((session) => ({ id: session.id, name: session.name }))
      );
      const deletedSessionIds = sessionsRepo.deleteTree(rootId);

      if (terminationErrors.length > 0) {
        console.warn('[API] PTY termination warnings (tree delete):', terminationErrors);
      }

      console.log(
        `[API] Deleted tree ${rootId}: ${deletedSessionIds.length} sessions, ${deletedLogs} logs, terminated ${terminatedPtySessions} PTY sessions`
      );

      // Remove deleted sessions from in-memory client stores.
      for (const deletedId of deletedSessionIds) {
        wsBroadcast.cliSessionDeleted(deletedId);
      }

      // Refresh tree list for all clients.
      wsBroadcast.allActiveTreesUpdate();

      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({
        deleted: deletedSessionIds.length,
        deletedSessionIds,
        deletedLogs,
        terminatedPtySessions,
        terminationErrors,
      }));
    } catch (error) {
      console.error('[API] Error deleting session tree:', error);
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Failed to delete session tree' }));
    }
    return;
  }

  // DELETE /api/sessions/:id - Delete a specific session
  const deleteSessionMatch = req.url?.match(/^\/api\/sessions\/([a-zA-Z0-9_-]+)$/);
  if (req.method === 'DELETE' && deleteSessionMatch) {
    try {
      const sessionId = deleteSessionMatch[1]!;
      const sessionsRepo = new CliSessionsRepository();
      const handoffsRepo = new HandoffsRepository();
      const session = sessionsRepo.findById(sessionId);

      if (!session) {
        res.writeHead(404, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Session not found' }));
        return;
      }

      let terminatedPtySession = false;
      let terminationError: string | null = null;
      const isActive = ['pending', 'running', 'waiting_for_input'].includes(session.status);
      const isTerminalSession = session.type === 'terminal' || session.mac_session_id !== null;

      // Best-effort PTY termination before deleting the DB row.
      if (isActive && isTerminalSession) {
        try {
          const result = await macClient.terminateSession(sessionId);
          terminatedPtySession = result.success;
          if (!result.success) {
            terminationError = result.message;
          }
        } catch (error) {
          terminationError = error instanceof Error ? error.message : String(error);
        }
      }

      const deletedHandoffs = handoffsRepo.deleteBySession(sessionId);
      const deleted = sessionsRepo.delete(sessionId);

      if (deleted) {
        console.log(
          `[API] Deleted session ${sessionId} (handoffs: ${deletedHandoffs}, terminatedPty: ${terminatedPtySession})`
        );
        wsBroadcast.cliSessionDeleted(sessionId);
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({
          deleted: true,
          deletedHandoffs,
          terminatedPtySession,
          terminationError,
        }));
      } else {
        res.writeHead(404, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Session not found' }));
      }
    } catch (error) {
      console.error('[API] Error deleting session:', error);
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Failed to delete session' }));
    }
    return;
  }

  // ═══════════════════════════════════════════════════════════════════════════
  // Event Recording API
  // ═══════════════════════════════════════════════════════════════════════════

  // POST /api/recording/start - Start recording events
  if (req.method === 'POST' && req.url === '/api/recording/start') {
    eventRecorder.start();
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ status: 'recording', message: 'Recording started' }));
    return;
  }

  // POST /api/recording/stop - Stop recording
  if (req.method === 'POST' && req.url === '/api/recording/stop') {
    const events = eventRecorder.stop();
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ status: 'stopped', eventCount: events.length }));
    return;
  }

  // GET /api/recording/status - Check recording status
  if (req.method === 'GET' && req.url === '/api/recording/status') {
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({
      recording: eventRecorder.recording,
      eventCount: eventRecorder.count,
    }));
    return;
  }

  // GET /api/recording/events - Get current events (without stopping)
  if (req.method === 'GET' && req.url === '/api/recording/events') {
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify(eventRecorder.getEvents()));
    return;
  }

  // POST /api/recording/export - Export as scenario
  if (req.method === 'POST' && req.url === '/api/recording/export') {
    let body = '';
    req.on('data', (chunk) => { body += chunk.toString(); });
    req.on('end', () => {
      try {
        const { name, description, saveToFile } = JSON.parse(body) as {
          name: string;
          description: string;
          saveToFile?: boolean;
        };

        const scenario = eventRecorder.exportScenario(
          name || 'recorded-scenario',
          description || 'Recorded session'
        );

        // Optionally save to file
        if (saveToFile) {
          const scenariosDir = path.join(process.cwd(), '..', 'web-ui', 'src', 'dev', 'demos', 'captured');
          if (!fs.existsSync(scenariosDir)) {
            fs.mkdirSync(scenariosDir, { recursive: true });
          }
          const filePath = path.join(scenariosDir, `${scenario.id}.json`);
          fs.writeFileSync(filePath, JSON.stringify(scenario, null, 2));
          console.log(`[Recording] Scenario saved to ${filePath}`);
        }

        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify(scenario));
      } catch (error) {
        console.error('[Recording] Export error:', error);
        res.writeHead(400, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Invalid request' }));
      }
    });
    return;
  }

  // POST /api/recording/clear - Clear events without stopping
  if (req.method === 'POST' && req.url === '/api/recording/clear') {
    eventRecorder.clear();
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ status: 'cleared' }));
    return;
  }

  // ═══════════════════════════════════════════════════════════════════════════
  // Sessions API - Chat History Persistence
  // ═══════════════════════════════════════════════════════════════════════════

  // GET /api/sessions/:id/messages - Get session message history
  const sessionMessagesMatch = req.url?.match(/^\/api\/sessions\/([a-zA-Z0-9_-]+)\/messages$/);
  if (req.method === 'GET' && sessionMessagesMatch) {
    try {
      const sessionId = sessionMessagesMatch[1]!;
      const messagesRepo = new SessionMessagesRepository();
      const messages = messagesRepo.getBySession(sessionId);
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ messages }));
    } catch (error) {
      console.error('[API] Error fetching session messages:', error);
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Failed to fetch session messages' }));
    }
    return;
  }

  // ═══════════════════════════════════════════════════════════════════════════
  // Models API (OpenRouter proxy with cache)
  // ═══════════════════════════════════════════════════════════════════════════

  if (req.method === 'GET' && req.url === '/api/models') {
    try {
      const now = Date.now();
      if (!modelsCache || now - modelsCache.timestamp > MODELS_CACHE_TTL) {
        const response = await fetch('https://openrouter.ai/api/v1/models', {
          headers: {
            'Authorization': `Bearer ${OPEN_ROUTER_API_KEY}`,
          },
        });
        if (!response.ok) {
          throw new Error(`OpenRouter API error: ${response.status}`);
        }
        const json = await response.json() as { data: Array<{ id: string; name: string; context_length: number; pricing: { prompt: string; completion: string } }> };
        // Trim to essential fields and sort by id
        const models = json.data
          .map((m) => ({
            id: m.id,
            name: m.name,
            context_length: m.context_length,
            pricing: m.pricing,
          }))
          .sort((a, b) => a.id.localeCompare(b.id));
        modelsCache = { data: models, timestamp: now };
      }
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify(modelsCache.data));
    } catch (error) {
      console.error('[API] Error fetching models:', error);
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Failed to fetch models' }));
    }
    return;
  }

  // ═══════════════════════════════════════════════════════════════════════════
  // Local Inference Control Plane Proxy
  // ═══════════════════════════════════════════════════════════════════════════

  if (req.method === 'GET' && req.url === '/api/local-inference/health') {
    await proxyLocalInferenceJson(req, res, '/health');
    return;
  }

  if (req.method === 'GET' && req.url === '/api/local-inference/models/catalog') {
    await proxyLocalInferenceJson(req, res, '/v1/models/catalog');
    return;
  }

  if (req.method === 'GET' && req.url === '/api/local-inference/models/state') {
    await proxyLocalInferenceJson(req, res, '/v1/models/state');
    return;
  }

  if (req.method === 'GET' && req.url === '/api/local-inference/models/suggestions') {
    await proxyLocalInferenceJson(req, res, '/v1/models/suggestions');
    return;
  }

  if (req.method === 'POST' && req.url === '/api/local-inference/models/download') {
    await proxyLocalInferenceJson(req, res, '/v1/models/download');
    return;
  }

  if (req.method === 'POST' && req.url === '/api/local-inference/models/load') {
    await proxyLocalInferenceJson(req, res, '/v1/models/load');
    return;
  }

  if (req.method === 'POST' && req.url === '/api/local-inference/playground/tts/benchmark') {
    await proxyLocalInferenceJson(req, res, '/v1/playground/tts/benchmark');
    return;
  }

  if (req.method === 'POST' && req.url === '/api/local-inference/playground/tts/speech') {
    try {
      const payload = await readJsonBody<Record>(req);
      const endpoint = new URL('/v1/audio/speech', resolveLocalInferenceEndpoint());
      const upstream = await fetch(endpoint, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });

      if (!upstream.ok) {
        const errorText = await upstream.text();
        res.writeHead(upstream.status, { 'Content-Type': 'application/json' });
        res.end(
          JSON.stringify({
            error: errorText || `Local inference speech failed (${upstream.status})`,
          })
        );
        return;
      }

      const buffer = Buffer.from(await upstream.arrayBuffer());
      res.writeHead(200, {
        'Content-Type': upstream.headers.get('content-type') ?? 'application/octet-stream',
        'Content-Length': String(buffer.byteLength),
        ...(upstream.headers.get('x-audio-sample-rate')
          ? { 'x-audio-sample-rate': upstream.headers.get('x-audio-sample-rate')! }
          : {}),
        ...(upstream.headers.get('x-audio-format')
          ? { 'x-audio-format': upstream.headers.get('x-audio-format')! }
          : {}),
      });
      res.end(buffer);
    } catch (error) {
      console.error('[API] Local inference speech proxy error:', error);
      res.writeHead(502, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Failed to synthesize local TTS sample' }));
    }
    return;
  }

  if (req.method === 'GET' && req.url === '/api/config/voice/catalog') {
    try {
      const now = Date.now();
      if (!voiceCatalogCache || now - voiceCatalogCache.timestamp > VOICE_CATALOG_CACHE_TTL) {
        const authProfiles = loadAuthProfiles();
        const runtimeCatalog = await fetchRuntimeProviderCatalogFromAuthProfiles({
          authProfiles,
          env: process.env,
        });

        const manifest = getRuntimeConfigManifest();
        // Auth profile names for dropdown selectors
        const authProfileNames = Object.keys(authProfiles.profiles);

        voiceCatalogCache = {
          data: {
            manifest,
            providerCatalog: runtimeCatalog.entries,
            providerSchemas: runtimeCatalog.providerSchemas,
            authProfileNames,
          },
          timestamp: now,
        };
      }

      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify(voiceCatalogCache.data));
    } catch (error) {
      console.error('[API] Error fetching voice catalog:', error);
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Failed to fetch voice catalog' }));
    }
    return;
  }

  // ═══════════════════════════════════════════════════════════════════════════
  // Voice Config API (JSON-backed runtime config + auth profiles)
  // ═══════════════════════════════════════════════════════════════════════════

  if (req.method === 'GET' && req.url?.startsWith('/api/config/voice/effective')) {
    try {
      const requestUrl = new URL(req.url, 'http://localhost');
      const profileName = (requestUrl.searchParams.get('profile') ?? '').toLowerCase();

      const profile = profiles[profileName] ?? profiles[`hey_${profileName}`];
      if (!profile) {
        res.writeHead(400, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Unknown profile. Use profile=jarvis|marvin|computer|hey_jarvis' }));
        return;
      }

      const runtime = resolveVoiceRuntimeConfig(profile);
      const auth = runtimeAuthKeySetToProviderMap(runtime.auth);
      const redactedAuth = Object.fromEntries(
        Object.entries(auth).map(([provider, key]) => [provider, maskKey(key)])
      );
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(
        JSON.stringify({
          profile: profile.name,
          mode: runtime.mode,
          provider: runtime.provider,
          language: runtime.language,
          voice: runtime.voice,
          model: runtime.model,
          decomposed: {
            stt: `${runtime.decomposedSttProvider}/${runtime.decomposedSttModel}`,
            llm: `${runtime.decomposedLlmProvider}/${runtime.decomposedLlmModel}`,
            tts: `${runtime.decomposedTtsProvider}/${runtime.decomposedTtsModel}`,
          },
          auth: redactedAuth,
          turn: runtime.turn,
        })
      );
    } catch (error) {
      console.error('[API] Error resolving effective voice config:', error);
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Failed to resolve effective voice config' }));
    }
    return;
  }

  if (req.method === 'GET' && req.url === '/api/config/voice') {
    try {
      const voiceConfig = loadVoiceConfig();
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ path: getVoiceConfigPath(), config: voiceConfig }));
    } catch (error) {
      console.error('[API] Error loading voice config:', error);
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Failed to load voice config' }));
    }
    return;
  }

  if (req.method === 'PUT' && req.url === '/api/config/voice') {
    try {
      const body = await readJsonBody<{ config: unknown }>(req);
      const next = saveVoiceConfig(body.config as never);
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ path: getVoiceConfigPath(), config: next }));
    } catch (error) {
      console.error('[API] Error saving voice config:', error);
      res.writeHead(400, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: (error as Error).message }));
    }
    return;
  }

  if (req.method === 'GET' && req.url?.startsWith('/api/config/auth-profiles')) {
    try {
      const requestUrl = new URL(req.url, 'http://localhost');
      const redacted = requestUrl.searchParams.get('redacted') === 'true';
      const authProfiles = loadAuthProfiles();
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(
        JSON.stringify({
          path: getAuthProfilesPath(),
          config: redacted ? redactAuthProfiles(authProfiles) : authProfiles,
        })
      );
    } catch (error) {
      console.error('[API] Error loading auth profiles:', error);
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Failed to load auth profiles' }));
    }
    return;
  }

  if (req.method === 'PUT' && req.url === '/api/config/auth-profiles') {
    try {
      const body = await readJsonBody<{ config: unknown }>(req);
      const next = saveAuthProfiles(body.config as never);
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ path: getAuthProfilesPath(), config: redactAuthProfiles(next) }));
    } catch (error) {
      console.error('[API] Error saving auth profiles:', error);
      res.writeHead(400, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: (error as Error).message }));
    }
    return;
  }

  if (req.method === 'POST' && req.url === '/api/config/auth-profiles/test') {
    try {
      const body = await readJsonBody<{
        provider?: RuntimeAuthProvider;
        authProfileId?: string;
      }>(req);

      const authProfiles = loadAuthProfiles();

      let provider = body.provider;
      if (!provider && body.authProfileId) {
        provider = authProfiles.profiles[body.authProfileId]?.provider;
      }

      if (!provider) {
        res.writeHead(400, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'provider or authProfileId is required' }));
        return;
      }

      const apiKey = resolveApiKey(provider, {
        authProfileId: body.authProfileId,
        authProfiles,
      });

      if (!apiKey) {
        res.writeHead(400, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: `No API key resolved for provider: ${provider}` }));
        return;
      }

      const result = await testRuntimeProviderCredentials(provider, apiKey);
      res.writeHead(result.ok ? 200 : 502, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ provider, ...result }));
    } catch (error) {
      console.error('[API] Error testing auth profile:', error);
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: (error as Error).message }));
    }
    return;
  }

  // ═══════════════════════════════════════════════════════════════════════════
  // Voices API — Voice Library (provider-agnostic clone references)
  // ═══════════════════════════════════════════════════════════════════════════

  // GET /api/config/voices - List all voice references
  if (req.method === 'GET' && req.url === '/api/config/voices') {
    try {
      const voices = listVoices();
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ voices }));
    } catch (error) {
      console.error('[API] Error listing voices:', error);
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: (error as Error).message }));
    }
    return;
  }

  // POST /api/config/voices - Create voice from uploaded WAV + metadata
  if (req.method === 'POST' && req.url === '/api/config/voices') {
    try {
      const body = await readJsonBody<{
        label: string;
        refText: string;
        language: string;
        instruct?: string;
        model?: string;
        seed?: number;
        wavBase64: string;
      }>(req);

      if (!body.label || !body.refText || !body.wavBase64) {
        res.writeHead(400, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'label, refText, and wavBase64 are required' }));
        return;
      }

      const wavBuffer = Buffer.from(body.wavBase64, 'base64');
      const meta = saveVoice(body.label, {
        refText: body.refText,
        language: body.language || 'English',
        instruct: body.instruct,
        model: body.model,
        seed: body.seed,
      }, wavBuffer);

      res.writeHead(201, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ voice: meta }));
    } catch (error) {
      console.error('[API] Error creating voice:', error);
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: (error as Error).message }));
    }
    return;
  }

  // DELETE /api/config/voices/:label - Delete a voice reference
  const voiceDeleteMatch = req.url?.match(/^\/api\/config\/voices\/([a-zA-Z0-9_-]+)$/);
  if (req.method === 'DELETE' && voiceDeleteMatch) {
    try {
      const label = voiceDeleteMatch[1]!;
      const deleted = deleteVoice(label);
      if (!deleted) {
        res.writeHead(404, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Voice not found' }));
        return;
      }
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ deleted: label }));
    } catch (error) {
      console.error('[API] Error deleting voice:', error);
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: (error as Error).message }));
    }
    return;
  }

  // GET /api/config/voices/:label/audio - Serve the reference WAV
  const voiceAudioMatch = req.url?.match(/^\/api\/config\/voices\/([a-zA-Z0-9_-]+)\/audio$/);
  if (req.method === 'GET' && voiceAudioMatch) {
    try {
      const label = voiceAudioMatch[1]!;
      const entry = getVoice(label);
      if (!entry) {
        res.writeHead(404, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Voice not found' }));
        return;
      }
      const wavData = fs.readFileSync(entry.refAudioPath);
      res.writeHead(200, {
        'Content-Type': 'audio/wav',
        'Content-Length': String(wavData.length),
      });
      res.end(wavData);
    } catch (error) {
      console.error('[API] Error serving voice audio:', error);
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: (error as Error).message }));
    }
    return;
  }

  // POST /api/config/voices/design - Generate voice via VoiceDesign model
  if (req.method === 'POST' && req.url === '/api/config/voices/design') {
    try {
      const body = await readJsonBody<{
        label: string;
        instruct: string;
        text: string;
        language?: string;
        seed?: number;
        temperature?: number;
        model?: string;
        localEndpoint?: string;
      }>(req);

      if (!body.label || !body.instruct || !body.text) {
        res.writeHead(400, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'label, instruct, and text are required' }));
        return;
      }

      const endpoint = body.localEndpoint || process.env.LOCAL_INFERENCE_URL || 'http://localhost:1060';
      const designResponse = await fetch(`${endpoint}/v1/voice/design`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          instruct: body.instruct,
          text: body.text,
          language: body.language || 'English',
          seed: body.seed ?? 42,
          temperature: body.temperature ?? 0.7,
          model: body.model,
        }),
      });

      if (!designResponse.ok) {
        const errText = await designResponse.text();
        res.writeHead(502, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: `Voice design failed: ${errText}` }));
        return;
      }

      const wavBuffer = Buffer.from(await designResponse.arrayBuffer());
      const meta = saveVoice(body.label, {
        refText: body.text,
        language: body.language || 'English',
        instruct: body.instruct,
        model: body.model || 'qwen3-1.7b-vd-4bit',
        seed: body.seed ?? 42,
      }, wavBuffer);

      res.writeHead(201, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ voice: meta }));
    } catch (error) {
      console.error('[API] Error designing voice:', error);
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: (error as Error).message }));
    }
    return;
  }

  // ═══════════════════════════════════════════════════════════════════════════
  // Prompts API
  // ═══════════════════════════════════════════════════════════════════════════

  // GET /api/prompts - List all prompts
  if (req.method === 'GET' && req.url === '/api/prompts') {
    try {
      const prompts = await listPrompts();
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify(prompts));
    } catch (error) {
      console.error('[API] Error fetching prompts:', error);
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Failed to fetch prompts' }));
    }
    return;
  }

  // GET /api/prompts/:id - Get prompt config + active version content
  const promptMatch = req.url?.match(/^\/api\/prompts\/([a-zA-Z0-9_-]+)$/);
  if (req.method === 'GET' && promptMatch) {
    try {
      const promptId = promptMatch[1]!;
      const info = await getPromptInfo(promptId);
      if (!info) {
        res.writeHead(404, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Prompt not found' }));
        return;
      }
      const content = await getActivePromptRaw(promptId);
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ ...info, content }));
    } catch (error) {
      console.error('[API] Error fetching prompt:', error);
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Failed to fetch prompt' }));
    }
    return;
  }

  // GET /api/prompts/:id/versions - List all versions
  const promptVersionsMatch = req.url?.match(/^\/api\/prompts\/([a-zA-Z0-9_-]+)\/versions$/);
  if (req.method === 'GET' && promptVersionsMatch) {
    try {
      const promptId = promptVersionsMatch[1]!;
      const versions = await listVersions(promptId);
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify(versions));
    } catch (error) {
      console.error('[API] Error fetching versions:', error);
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Failed to fetch versions' }));
    }
    return;
  }

  // GET /api/prompts/:id/versions/:version - Get specific version content
  const promptVersionMatch = req.url?.match(/^\/api\/prompts\/([a-zA-Z0-9_-]+)\/versions\/(v\d+)$/);
  if (req.method === 'GET' && promptVersionMatch) {
    try {
      const promptId = promptVersionMatch[1]!;
      const version = promptVersionMatch[2]!;
      const versionData = await getPromptVersion(promptId, version);
      if (!versionData) {
        res.writeHead(404, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Version not found' }));
        return;
      }
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify(versionData));
    } catch (error) {
      console.error('[API] Error fetching version:', error);
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Failed to fetch version' }));
    }
    return;
  }

  // POST /api/prompts/:id - Create new version
  const createVersionMatch = req.url?.match(/^\/api\/prompts\/([a-zA-Z0-9_-]+)$/);
  if (req.method === 'POST' && createVersionMatch) {
    const promptId = createVersionMatch[1]!;
    let body = '';
    req.on('data', (chunk) => { body += chunk.toString(); });
    req.on('end', async () => {
      try {
        const { content } = JSON.parse(body) as { content: string };
        if (!content) {
          res.writeHead(400, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ error: 'Content is required' }));
          return;
        }
        const version = await createPromptVersion(promptId, content);
        console.log(`[API] Created prompt version ${version} for ${promptId}`);
        res.writeHead(201, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ version, promptId }));
      } catch (error) {
        console.error('[API] Error creating version:', error);
        res.writeHead(400, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Failed to create version' }));
      }
    });
    return;
  }

  // PUT /api/prompts/:id/active - Set active version
  const setActiveMatch = req.url?.match(/^\/api\/prompts\/([a-zA-Z0-9_-]+)\/active$/);
  if (req.method === 'PUT' && setActiveMatch) {
    const promptId = setActiveMatch[1]!;
    let body = '';
    req.on('data', (chunk) => { body += chunk.toString(); });
    req.on('end', async () => {
      try {
        const { version } = JSON.parse(body) as { version: string };
        if (!version) {
          res.writeHead(400, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ error: 'Version is required' }));
          return;
        }
        await setActiveVersion(promptId, version);
        console.log(`[API] Set active version for ${promptId} to ${version}`);
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ success: true, promptId, activeVersion: version }));
      } catch (error) {
        console.error('[API] Error setting active version:', error);
        res.writeHead(400, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Failed to set active version' }));
      }
    });
    return;
  }

  // PUT /api/prompts/:id/metadata - Update prompt metadata (model, maxSteps, etc.)
  const metadataMatch = req.url?.match(/^\/api\/prompts\/([a-zA-Z0-9_-]+)\/metadata$/);
  if (req.method === 'PUT' && metadataMatch) {
    const promptId = metadataMatch[1]!;
    let body = '';
    req.on('data', (chunk) => { body += chunk.toString(); });
    req.on('end', async () => {
      try {
        const { metadata } = JSON.parse(body) as { metadata: PromptConfig['metadata'] };
        if (!metadata) {
          res.writeHead(400, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ error: 'metadata is required' }));
          return;
        }
        // Merge with existing metadata
        const existing = await getPromptConfig(promptId);
        if (!existing) {
          res.writeHead(404, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ error: 'Prompt not found' }));
          return;
        }
        const mergedMetadata = { ...existing.metadata, ...metadata };
        await updatePromptConfig(promptId, { metadata: mergedMetadata });
        console.log(`[API] Updated metadata for ${promptId}:`, mergedMetadata);
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ success: true, promptId, metadata: mergedMetadata }));
      } catch (error) {
        console.error('[API] Error updating metadata:', error);
        res.writeHead(400, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Failed to update metadata' }));
      }
    });
    return;
  }

  // POST /api/prompts - Create new prompt
  if (req.method === 'POST' && req.url === '/api/prompts') {
    let body = '';
    req.on('data', (chunk) => { body += chunk.toString(); });
    req.on('end', async () => {
      try {
        const { id, name, description, type, content, metadata } = JSON.parse(body) as {
          id: string;
          name: string;
          description: string;
          type: 'voice' | 'subagent';
          content: string;
          metadata?: PromptConfig['metadata'];
        };

        if (!id || !name || !type || !content) {
          res.writeHead(400, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ error: 'id, name, type, and content are required' }));
          return;
        }

        await createPrompt(id, { name, description: description || '', type, metadata }, content);
        console.log(`[API] Created new prompt: ${id}`);
        res.writeHead(201, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ success: true, id }));
      } catch (error) {
        console.error('[API] Error creating prompt:', error);
        res.writeHead(400, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Failed to create prompt' }));
      }
    });
    return;
  }

  // ═══════════════════════════════════════════════════════════════════════════
  // Webhooks
  // ═══════════════════════════════════════════════════════════════════════════

  // Handle CLI status webhook
  if (req.method === 'POST' && req.url === '/webhooks/cli-status') {
    let body = '';

    req.on('data', (chunk) => {
      body += chunk.toString();
    });

    req.on('end', async () => {
      try {
        const payload = JSON.parse(body) as WebhookPayload;

        console.log('[Webhook] Received CLI status update:');
        console.log(`  Session: ${payload.sessionId}`);
        console.log(`  Status: ${payload.status}`);
        if (payload.message) {
          console.log(`  Message: ${payload.message}`);
        }

        // Mirror webhook status into session JSONL logs for replay/debugging.
        logWebhookStatus(payload.sessionId, payload.status, payload.message, payload.output);

        // Update database
        const sessionsRepo = new CliSessionsRepository();
        const eventsRepo = new CliEventsRepository();

        // Map daemon status to our status
        const statusMap: Record = {
          running: 'running',
          waiting_for_input: 'waiting_for_input',
          finished: 'finished',
          error: 'error',
        };

        const dbStatus = statusMap[payload.status] ?? 'running';
        sessionsRepo.updateStatus(payload.sessionId, dbStatus);

        eventsRepo.create({
          session_id: payload.sessionId,
          event_type: 'status_change',
          payload: {
            status: payload.status,
            message: payload.message,
          },
        });

        // Resolve any pending completion waiters
        if (payload.status === 'finished' || payload.status === 'error') {
          resolvePendingCompletion(payload);
        }

        // Notify handler if registered
        if (webhookHandler) {
          await webhookHandler(payload);
        }

        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ received: true }));
      } catch (error) {
        console.error('[Webhook] Error processing request:', error);
        res.writeHead(400, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Invalid request' }));
      }
    });

    return;
  }

  // 404 for unknown routes
  res.writeHead(404, { 'Content-Type': 'application/json' });
  res.end(JSON.stringify({ error: 'Not found' }));
}

/**
 * Start the webhook server.
 */
export function startWebhookServer(): Promise {
  return new Promise((resolve, reject) => {
    if (server) {
      console.log('[Webhook] Server already running');
      resolve();
      return;
    }

    server = http.createServer(handleWebhook);
    openConnections.clear();

    server.on('connection', (socket) => {
      openConnections.add(socket);
      socket.on('close', () => {
        openConnections.delete(socket);
      });
    });

    server.on('error', (err) => {
      console.error('[Webhook] Server error:', err);
      server = null;
      openConnections.clear();
      reject(err);
    });

    server.listen(PORT, '0.0.0.0', () => {
      console.log(`[Webhook] Server listening on port ${PORT}`);
      console.log(`[Webhook] Endpoint: POST http://0.0.0.0:${PORT}/webhooks/cli-status`);
      resolve();
    });
  });
}

/**
 * Stop the webhook server.
 */
export function stopWebhookServer(): Promise {
  return new Promise((resolve) => {
    if (!server) {
      resolve();
      return;
    }

    const currentServer = server;
    server = null;

    let settled = false;
    const finish = () => {
      if (settled) return;
      settled = true;
      openConnections.clear();
      resolve();
    };

    const timeout = setTimeout(() => {
      for (const socket of openConnections) {
        socket.destroy();
      }
      openConnections.clear();
      console.warn('[Webhook] Force shutdown after close timeout');
      finish();
    }, 2000);

    try {
      currentServer.close(() => {
        clearTimeout(timeout);
        console.log('[Webhook] Server stopped');
        finish();
      });
    } catch (error) {
      clearTimeout(timeout);
      console.warn('[Webhook] Error while closing server:', error);
      finish();
    }
  });
}

/**
 * Get the webhook URL for the Mac daemon to call.
 */
export function getWebhookUrl(): string {
  // Get the Pi's hostname or IP
  const hostname = process.env.PI_HOSTNAME ?? 'marlon.local';
  return `http://${hostname}:${PORT}/webhooks/cli-status`;
}



import { resamplePcm16Mono } from '../media/resample-pcm16.js';
import { StreamResamplerPool } from '../media/stream-resampler.js';
import { parseUltravoxProviderConfig } from '../provider-config.js';
import { TypedEventEmitter } from '../runtime/typed-emitter.js';
import type {
  AudioFrame,
  AudioNegotiation,
  EventHandler,
  ProviderAdapter,
  ProviderCapabilities,
  ProviderConfigSchema,
  SessionInput,
  ToolCallContext,
  ToolCallResult,
  ToolDefinition,
  ToolReaction,
  UltravoxProviderConfig,
  VoiceHistoryItem,
  VoiceSessionEvents,
  VoiceState,
} from '../types.js';

interface UltravoxCallResponse {
  joinUrl?: string;
  websocketUrl?: string;
  medium?: {
    serverWebSocket?: {
      inputSampleRate?: number;
      outputSampleRate?: number;
      clientBufferSizeMs?: number;
    };
  };
}

interface UltravoxMessage {
  type?: string;
  state?: string;
  text?: string | null;
  delta?: string | null;
  role?: 'user' | 'assistant' | 'agent';
  speaker?: 'user' | 'assistant' | 'agent';
  final?: boolean;
  ordinal?: number;
  toolName?: string;
  invocationId?: string;
  parameters?: unknown;
  result?: unknown;
  [key: string]: unknown;
}

interface TranscriptAccumulator {
  text: string;
  role: 'user' | 'assistant';
  final: boolean;
  announced: boolean;
}

interface UltravoxSelectedTool {
  temporaryTool: {
    modelToolName: string;
    description: string;
    dynamicParameters: Array<{
      name: string;
      location: 'PARAMETER_LOCATION_BODY';
      schema: Record;
      required: boolean;
    }>;
    client: Record;
    precomputable?: boolean;
    timeout?: string;
    defaultReaction?: 'SPEAKS' | 'LISTENS' | 'SPEAKS_ONCE';
  };
}

const DEFAULT_API_BASE = 'https://api.ultravox.ai';
const DEFAULT_BUFFER_MS = 60;
const DEFAULT_INPUT_RATE = 24000;
const DEFAULT_OUTPUT_RATE = 24000;

const ULTRAVOX_CAPABILITIES: ProviderCapabilities = {
  toolCalling: true,
  transcriptDeltas: true,
  interruption: true,

  providerTransportKinds: ['websocket'],
  audioNegotiation: true,
  vadModes: ['server'],
  interruptionModes: ['barge-in'],

  toolTimeout: true,
  asyncTools: false,
  toolCancellation: false,
  toolScheduling: false,
  toolReaction: true,
  precomputableTools: true,
  toolApproval: false,
  mcpTools: false,
  serverSideTools: true,

  sessionResumption: true,
  midSessionConfigUpdate: false,
  contextCompression: false,

  forceAgentMessage: true,
  outputMediumSwitch: true,
  callState: true,
  deferredText: true,
  callStages: true,
  proactivity: false,
  usageMetrics: false,
  orderedTranscripts: true,
  ephemeralTokens: false,
  nativeTruncation: false,
  wordLevelTimestamps: false,
};

const ULTRAVOX_CONFIG_SCHEMA: ProviderConfigSchema = {
  providerId: 'ultravox-ws',
  displayName: 'Ultravox Realtime',
  fields: [
    {
      key: 'vad.turnEndpointDelay',
      label: 'Turn Endpoint Delay',
      type: 'string',
      group: 'vad',
      defaultValue: '0.384s',
      description: 'Time agent waits after user stops speaking before responding. Multiples of 32ms.',
    },
    {
      key: 'vad.minimumTurnDuration',
      label: 'Minimum Turn Duration',
      type: 'string',
      group: 'vad',
      defaultValue: '0s',
      description: 'Minimum speech duration to count as a valid turn. Longer values filter brief noise.',
    },
    {
      key: 'vad.minimumInterruptionDuration',
      label: 'Minimum Interruption Duration',
      type: 'string',
      group: 'vad',
      defaultValue: '0.09s',
      description: 'Minimum speech to interrupt the agent while speaking.',
    },
    {
      key: 'vad.frameActivationThreshold',
      label: 'Frame Activation Threshold',
      type: 'range',
      group: 'vad',
      min: 0.1,
      max: 1.0,
      step: 0.05,
      defaultValue: 0.1,
      description: 'Threshold for considering a 32ms frame as speech. Higher = less sensitive.',
    },
  ],
  // Ultravox voices are fetched dynamically from the API — no static list here
};

export class UltravoxWsAdapter implements ProviderAdapter {
  readonly id = 'ultravox-ws' as const;

  private readonly events = new TypedEventEmitter();
  private socket: WebSocket | null = null;
  private connected = false;
  private state: VoiceState = 'idle';
  private input: SessionInput | null = null;
  private history: VoiceHistoryItem[] = [];
  private toolByName = new Map();
  private transcriptsByOrdinal = new Map();

  private providerInputRateHz = DEFAULT_INPUT_RATE;
  private providerOutputRateHz = DEFAULT_OUTPUT_RATE;
  private preferredInputRateHz = 24000;
  private preferredOutputRateHz = 24000;
  private readonly resamplerPool = new StreamResamplerPool();

  capabilities(): ProviderCapabilities {
    return ULTRAVOX_CAPABILITIES;
  }

  configSchema(): ProviderConfigSchema {
    return ULTRAVOX_CONFIG_SCHEMA;
  }

  async connect(input: SessionInput): Promise {
    if (this.connected) {
      return {
        providerInputRate: this.providerInputRateHz,
        providerOutputRate: this.providerOutputRateHz,
        preferredClientInputRate: this.preferredInputRateHz,
        preferredClientOutputRate: this.preferredOutputRateHz,
        format: 'pcm16',
      };
    }

    this.input = input;
    this.toolByName.clear();
    this.history = [];
    this.transcriptsByOrdinal.clear();
    for (const tool of input.tools ?? []) {
      this.toolByName.set(tool.name, tool);
    }

    const providerConfig = this.getProviderConfig(input);
    const apiKey = providerConfig.apiKey;
    if (!apiKey) {
      throw new Error('Ultravox adapter requires providerConfig.apiKey');
    }

    this.providerInputRateHz = providerConfig.inputSampleRate ?? DEFAULT_INPUT_RATE;
    this.providerOutputRateHz = providerConfig.outputSampleRate ?? DEFAULT_OUTPUT_RATE;
    const clientBufferSizeMs = providerConfig.clientBufferSizeMs ?? DEFAULT_BUFFER_MS;

    const payload: Record = {
      model: providerConfig.model ?? input.model,
      systemPrompt: input.instructions,
      voice: providerConfig.voice ?? input.voice,
      medium: {
        serverWebSocket: {
          inputSampleRate: this.providerInputRateHz,
          outputSampleRate: this.providerOutputRateHz,
          clientBufferSizeMs,
        },
      },
    };

    // Ultravox VAD settings from providerConfig (pass-through from providerSettings)
    const vadKeys = ['turnEndpointDelay', 'minimumTurnDuration', 'minimumInterruptionDuration', 'frameActivationThreshold'] as const;
    const vadSettings: Record = {};
    for (const key of vadKeys) {
      const cfgKey = `vad.${key}`;
      const val = (providerConfig as Record)[cfgKey] ?? (providerConfig as Record)[key];
      if (val != null) vadSettings[key] = val;
    }
    if (Object.keys(vadSettings).length > 0) {
      payload.vadSettings = vadSettings;
    }

    const selectedTools = this.toSelectedTools(input.tools ?? []);
    if (selectedTools.length > 0) {
      payload.selectedTools = selectedTools;
    }

    const createUrl = `${providerConfig.apiBaseUrl ?? DEFAULT_API_BASE}/api/calls`;
    const createResponse = await fetch(createUrl, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'X-API-Key': apiKey,
      },
      body: JSON.stringify(payload),
    });

    if (!createResponse.ok) {
      const errorText = await createResponse.text();
      throw new Error(`Ultravox call creation failed (${createResponse.status}): ${errorText}`);
    }

    const call = (await createResponse.json()) as UltravoxCallResponse;
    const negotiatedInputRate = call.medium?.serverWebSocket?.inputSampleRate;
    const negotiatedOutputRate = call.medium?.serverWebSocket?.outputSampleRate;
    if (typeof negotiatedInputRate === 'number' && negotiatedInputRate > 0) {
      this.providerInputRateHz = negotiatedInputRate;
    }
    if (typeof negotiatedOutputRate === 'number' && negotiatedOutputRate > 0) {
      this.providerOutputRateHz = negotiatedOutputRate;
    }

    const joinUrl = call.joinUrl ?? call.websocketUrl;
    if (!joinUrl) {
      throw new Error('Ultravox API response did not include joinUrl/websocketUrl');
    }

    const wsUrl = new URL(joinUrl);
    wsUrl.searchParams.set('apiVersion', '1');

    this.socket = new WebSocket(wsUrl.toString());
    this.socket.binaryType = 'arraybuffer';

    await new Promise((resolve, reject) => {
      if (!this.socket) {
        reject(new Error('Ultravox websocket not created'));
        return;
      }

      const onOpen = () => {
        this.socket?.removeEventListener('error', onError);
        resolve();
      };
      const onError = (event: Event) => {
        this.socket?.removeEventListener('open', onOpen);
        reject(
          new Error(`Ultravox websocket connection error: ${String((event as ErrorEvent).message ?? '')}`)
        );
      };

      this.socket.addEventListener('open', onOpen, { once: true });
      this.socket.addEventListener('error', onError, { once: true });
    });

    this.bindSocketHandlers();
    this.connected = true;
    this.setState('listening');
    this.events.emit('connected');

    // Pre-warm stream resamplers for any rate mismatches
    const inits: Promise[] = [];
    if (this.preferredInputRateHz !== this.providerInputRateHz) {
      inits.push(this.resamplerPool.get(this.preferredInputRateHz, this.providerInputRateHz));
    }
    if (this.providerOutputRateHz !== this.preferredOutputRateHz) {
      inits.push(this.resamplerPool.get(this.providerOutputRateHz, this.preferredOutputRateHz));
    }
    if (inits.length > 0) await Promise.all(inits);

    return {
      providerInputRate: this.providerInputRateHz,
      providerOutputRate: this.providerOutputRateHz,
      preferredClientInputRate: this.preferredInputRateHz,
      preferredClientOutputRate: this.preferredOutputRateHz,
      format: 'pcm16',
    };
  }

  async disconnect(): Promise {
    if (!this.socket) {
      this.connected = false;
      this.setState('idle');
      this.events.emit('disconnected');
      return;
    }

    try {
      this.socket.send(JSON.stringify({ type: 'hang_up' }));
    } catch {
      // ignore
    }

    this.socket.close();
    this.socket = null;
    this.connected = false;
    this.transcriptsByOrdinal.clear();
    this.resamplerPool.clear();
    this.setState('idle');
    this.events.emit('disconnected');
  }

  sendAudio(frame: AudioFrame): void {
    if (!this.socket || this.socket.readyState !== WebSocket.OPEN) return;
    if (frame.sampleRate === this.providerInputRateHz) {
      this.socket.send(frame.data);
      return;
    }
    const resampler = this.resamplerPool.getSync(frame.sampleRate, this.providerInputRateHz);
    const pcm = resampler
      ? resampler.process(frame)
      : resamplePcm16Mono(frame, this.providerInputRateHz);
    this.socket.send(pcm.data);
  }

  sendText(text: string, options?: { defer?: boolean }): void {
    if (!this.socket || this.socket.readyState !== WebSocket.OPEN) return;
    if (options?.defer) {
      this.socket.send(
        JSON.stringify({
          type: 'deferred_text_message',
          text,
        })
      );
      return;
    }

    this.socket.send(
      JSON.stringify({
        type: 'input_text_message',
        text,
      })
    );
  }

  interrupt(): void {
    this.events.emit('audioInterrupted');
  }

  sendToolResult(result: ToolCallResult): void {
    if (!this.socket || this.socket.readyState !== WebSocket.OPEN) return;
    const payload: Record = {
      type: 'client_tool_result',
      invocationId: result.invocationId,
      result: result.result,
      responseType: result.isError ? 'tool-error' : result.stageTransition ? 'new-stage' : 'tool-response',
    };
    if (result.stateUpdate) {
      payload.updateCallState = result.stateUpdate;
    }
    if (result.errorMessage) {
      payload.errorMessage = result.errorMessage;
    }
    if (result.agentReaction) {
      payload.agentReaction = toUltravoxReaction(result.agentReaction);
    }
    this.socket.send(JSON.stringify(payload));
  }

  on(
    event: K,
    handler: EventHandler
  ): void {
    this.events.on(event, handler);
  }

  off(
    event: K,
    handler: EventHandler
  ): void {
    this.events.off(event, handler);
  }

  setOutputMedium(medium: 'voice' | 'text'): void {
    if (!this.socket || this.socket.readyState !== WebSocket.OPEN) return;
    this.socket.send(
      JSON.stringify({
        type: 'set_output_medium',
        medium,
      })
    );
  }

  forceAgentMessage(
    text: string,
    options?: { uninterruptible?: boolean; urgency?: 'immediate' | 'soon' }
  ): void {
    if (!this.socket || this.socket.readyState !== WebSocket.OPEN) return;
    this.socket.send(
      JSON.stringify({
        type: 'forced_agent_message',
        text,
        uninterruptible: options?.uninterruptible ?? false,
        urgency: options?.urgency === 'immediate' ? 'IMMEDIATE' : 'SOON',
      })
    );
  }

  resume(handle: string): Promise {
    throw new Error(`Ultravox resume is not implemented in this adapter yet (${handle})`);
  }

  private bindSocketHandlers(): void {
    if (!this.socket) return;

    this.socket.addEventListener('message', (event: MessageEvent) => {
      void this.handleSocketMessage(event.data);
    });

    this.socket.addEventListener('close', () => {
      this.connected = false;
      this.setState('idle');
      this.events.emit('disconnected');
    });

    this.socket.addEventListener('error', (event: Event) => {
      const message = (event as ErrorEvent).message ?? 'Ultravox websocket error';
      this.events.emit('error', new Error(message));
    });
  }

  private async handleSocketMessage(data: unknown): Promise {
    if (typeof data === 'string') {
      this.handleDataMessage(data);
      return;
    }

    if (data instanceof ArrayBuffer) {
      this.emitAudioFrame(data);
      return;
    }

    if (data instanceof Uint8Array) {
      this.emitAudioFrame(data.buffer.slice(data.byteOffset, data.byteOffset + data.byteLength));
      return;
    }

    if (typeof Blob !== 'undefined' && data instanceof Blob) {
      const audio = await data.arrayBuffer();
      this.emitAudioFrame(audio);
      return;
    }
  }

  private emitAudioFrame(raw: ArrayBufferLike): void {
    const normalizedRaw = toArrayBuffer(raw);
    const frame: AudioFrame = {
      data: normalizedRaw,
      sampleRate: this.providerOutputRateHz,
      format: 'pcm16',
    };
    if (frame.sampleRate === this.preferredOutputRateHz) {
      this.events.emit('audio', frame);
      return;
    }
    const resampler = this.resamplerPool.getSync(frame.sampleRate, this.preferredOutputRateHz);
    const frameForSession = resampler
      ? resampler.process(frame)
      : resamplePcm16Mono(frame, this.preferredOutputRateHz);
    this.events.emit('audio', frameForSession);
  }

  private handleDataMessage(raw: string): void {
    let message: UltravoxMessage;
    try {
      message = JSON.parse(raw) as UltravoxMessage;
    } catch {
      return;
    }

    const type = message.type ?? '';

    if (type === 'state') {
      this.mapState(message.state);
      return;
    }

    if (type === 'transcript') {
      this.handleTranscript(message);
      return;
    }

    if (type === 'playback_clear_buffer') {
      this.events.emit('audioInterrupted');
      return;
    }

    if (type === 'client_tool_invocation') {
      void this.handleToolInvocation(message);
      return;
    }
  }

  private handleTranscript(message: UltravoxMessage): void {
    const role = this.mapRole(message);
    if (!role) return;

    const ordinal = typeof message.ordinal === 'number' ? message.ordinal : -1;
    const itemId = ordinal >= 0 ? `${role}-${ordinal}` : `${role}-${Date.now()}`;
    const order = ordinal >= 0 ? ordinal + 1 : undefined;
    const delta = typeof message.delta === 'string' ? message.delta : '';
    const text = typeof message.text === 'string' ? message.text : '';

    let accumulator = ordinal >= 0 ? this.transcriptsByOrdinal.get(ordinal) : undefined;
    if (!accumulator && ordinal >= 0) {
      accumulator = {
        text: '',
        role,
        final: false,
        announced: false,
      };
      this.transcriptsByOrdinal.set(ordinal, accumulator);
    }

    const previousText = accumulator?.text ?? '';
    const wasAnnounced = accumulator?.announced ?? false;

    let nextText = previousText;
    if (delta) {
      nextText = previousText + delta;
    } else if (text) {
      nextText = text;
    }
    if (accumulator) {
      accumulator.text = nextText;
      accumulator.role = role;
    }

    // Ultravox can emit scaffold ordinals that carry only whitespace/newlines.
    // Keep assistant placeholder gating strict (only with meaningful text) to avoid
    // empty assistant bubbles, but announce user placeholder immediately so UI can
    // show "You: ..." while recognition is still in progress.
    const hasMeaningfulText = nextText.trim().length > 0;
    if (accumulator && !accumulator.announced) {
      if (role === 'user') {
        this.events.emit('userItemCreated', itemId, order);
        accumulator.announced = true;
      } else if (hasMeaningfulText) {
        this.events.emit(
          'assistantItemCreated',
          itemId,
          this.resolveAssistantPreviousItemId(ordinal),
          order
        );
        accumulator.announced = true;
      }
    }

    if (role === 'assistant') {
      if (delta && accumulator?.announced) {
        let emittedDelta = delta;
        if (!wasAnnounced && previousText.trim().length === 0 && hasMeaningfulText) {
          emittedDelta = nextText.replace(/^\s+/, '');
        }
        if (emittedDelta) {
          this.events.emit('transcriptDelta', emittedDelta, role, itemId, order);
        }
      } else if (text && message.final !== true && accumulator?.announced) {
        let computedDelta =
          text.length > previousText.length ? text.slice(previousText.length) : text;
        if (!wasAnnounced && previousText.trim().length === 0 && text.trim().length > 0) {
          computedDelta = text.replace(/^\s+/, '');
        }
        if (computedDelta) {
          this.events.emit('transcriptDelta', computedDelta, role, itemId, order);
        }
      }
    }

    if (message.final === true) {
      if (accumulator) {
        accumulator.final = true;
      }

      const finalText = (accumulator?.text || text).trim();
      if (!finalText) return;

      if (accumulator && !accumulator.announced) {
        if (role === 'user') {
          this.events.emit('userItemCreated', itemId, order);
        } else {
          this.events.emit(
            'assistantItemCreated',
            itemId,
            this.resolveAssistantPreviousItemId(ordinal),
            order
          );
        }
        accumulator.announced = true;
      }

      const historyItem: VoiceHistoryItem = {
        id: itemId,
        role,
        text: finalText,
        createdAt: Date.now(),
      };
      this.history.push(historyItem);
      this.events.emit('historyUpdated', [...this.history]);
      this.events.emit('transcript', finalText, role, itemId, order);
    }
  }

  private async handleToolInvocation(message: UltravoxMessage): Promise {
    const invocationId =
      typeof message.invocationId === 'string' ? message.invocationId : `uvx-${Date.now()}`;
    const toolName = typeof message.toolName === 'string' ? message.toolName : 'ultravox_tool';
    const args = this.parseToolParameters(message.parameters);
    this.events.emit('toolStart', toolName, args, invocationId);

    if (!this.input?.toolHandler) {
      const errorResult: ToolCallResult = {
        invocationId,
        result: `No toolHandler registered for tool ${toolName}`,
        isError: true,
      };
      this.sendToolResult(errorResult);
      this.events.emit('toolEnd', toolName, errorResult.result, invocationId);
      return;
    }

    try {
      const context: ToolCallContext = {
        providerId: this.id,
        callId: invocationId,
        invocationId,
        history: [...this.history],
      };
      const rawResult = await this.input.toolHandler(toolName, args, context);
      const normalized = this.normalizeToolResult(invocationId, rawResult);
      this.sendToolResult(normalized);
      this.events.emit('toolEnd', toolName, normalized.result, invocationId);
    } catch (error) {
      const result = `Tool ${toolName} failed: ${(error as Error).message}`;
      this.sendToolResult({
        invocationId,
        result,
        isError: true,
      });
      this.events.emit('toolEnd', toolName, result, invocationId);
      this.events.emit('error', error as Error);
    }
  }

  private mapState(state?: string): void {
    switch (state) {
      case 'listening':
        this.setState('listening');
        break;
      case 'thinking':
        this.setState('thinking');
        break;
      case 'speaking':
        this.setState('speaking');
        break;
      default:
        this.setState('idle');
        break;
    }
  }

  private mapRole(message: UltravoxMessage): 'user' | 'assistant' | null {
    if (message.role === 'user' || message.speaker === 'user') return 'user';
    if (
      message.role === 'assistant' ||
      message.role === 'agent' ||
      message.speaker === 'assistant' ||
      message.speaker === 'agent'
    ) {
      return 'assistant';
    }
    return null;
  }

  private resolveAssistantPreviousItemId(ordinal: number): string | undefined {
    if (!Number.isFinite(ordinal) || ordinal <= 0) {
      return undefined;
    }

    const previousOrdinal = ordinal - 1;
    const previous = this.transcriptsByOrdinal.get(previousOrdinal);
    if (previous) {
      if (previous.role === 'user') {
        return `user-${previousOrdinal}`;
      }
      // Ignore assistant scaffold ordinals (whitespace/newline only) as chain anchors.
      // They are protocol artifacts and can invert conversation ordering.
      if (previous.announced && previous.text.trim().length > 0) {
        return `assistant-${previousOrdinal}`;
      }
    }

    // Ultravox can emit assistant transcript activity before user transcript finalization.
    // Anchor to the expected preceding user ordinal.
    return `user-${previousOrdinal}`;
  }

  private setState(next: VoiceState): void {
    if (this.state === next) return;
    this.state = next;
    this.events.emit('stateChange', next);
  }

  private parseToolParameters(parameters: unknown): Record {
    if (!parameters) return {};
    if (typeof parameters === 'object' && !Array.isArray(parameters)) {
      return parameters as Record;
    }
    if (typeof parameters === 'string') {
      try {
        const parsed = JSON.parse(parameters) as unknown;
        if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
          return parsed as Record;
        }
      } catch {
        // fall through
      }
      return { raw: parameters };
    }
    return { raw: parameters };
  }

  private normalizeToolResult(
    invocationId: string,
    value: ToolCallResult | string
  ): ToolCallResult {
    if (typeof value === 'string') {
      return {
        invocationId,
        result: value,
      };
    }
    return {
      ...value,
      invocationId,
      result: this.stringifyToolOutput(value.result),
    };
  }

  private stringifyToolOutput(output: unknown): string {
    if (typeof output === 'string') return output;
    if (typeof output === 'number' || typeof output === 'boolean') return String(output);
    try {
      return JSON.stringify(output);
    } catch {
      return String(output);
    }
  }

  private getProviderConfig(input: SessionInput): UltravoxProviderConfig {
    return parseUltravoxProviderConfig(input.providerConfig);
  }

  private toSelectedTools(tools: ToolDefinition[]): UltravoxSelectedTool[] {
    return tools.map((tool) => {
      const parameters = tool.parameters ?? {};
      const properties =
        parameters.properties &&
        typeof parameters.properties === 'object' &&
        !Array.isArray(parameters.properties)
          ? (parameters.properties as Record)
          : {};
      const requiredNames = Array.isArray(parameters.required)
        ? new Set(parameters.required.filter((name): name is string => typeof name === 'string'))
        : new Set();

      return {
        temporaryTool: {
          modelToolName: tool.name,
          description: tool.description,
          dynamicParameters: Object.entries(properties).map(([name, schema]) => ({
            name,
            location: 'PARAMETER_LOCATION_BODY' as const,
            schema:
              schema && typeof schema === 'object' && !Array.isArray(schema)
                ? (schema as Record)
                : { type: 'string' },
            required: requiredNames.has(name),
          })),
          client: {},
          precomputable: tool.precomputable,
          timeout: typeof tool.timeout === 'number' ? `${tool.timeout}ms` : undefined,
          defaultReaction: tool.defaultReaction
            ? toUltravoxReaction(tool.defaultReaction)
            : undefined,
        },
      };
    });
  }
}

function toUltravoxReaction(reaction: ToolReaction): 'SPEAKS' | 'LISTENS' | 'SPEAKS_ONCE' {
  if (reaction === 'listens') return 'LISTENS';
  if (reaction === 'speaks-once') return 'SPEAKS_ONCE';
  return 'SPEAKS';
}

function toArrayBuffer(input: ArrayBufferLike): ArrayBuffer {
  if (input instanceof ArrayBuffer) return input;
  const copied = new Uint8Array(input.byteLength);
  copied.set(new Uint8Array(input));
  return copied.buffer;
}



import type {
  AudioFrame,
  InterruptionContext,
  SpokenWordTimestamp,
} from '../types.js';
import { WordTimeline } from './word-timeline.js';

interface SpokenSegment {
  id: string;
  text: string;
  audioStartMs: number;
  audioEndMs: number;
}

/**
 * Tracks assistant text/audio alignment at session level so interruptions can
 * resolve "what the user actually heard" even for providers without native
 * truncation support.
 */
export class InterruptionTracker {
  private currentItemId: string | null = null;
  private fullText = '';
  private pendingText = '';
  private segments: SpokenSegment[] = [];
  private cumulativeAudioMs = 0;
  private explicitSpokenText = '';
  private explicitSpokenWordCount = 0;
  private explicitPlaybackMs = 0;
  private explicitPrecision:
    | 'ratio'
    | 'segment'
    | 'aligned'
    | 'provider-word-timestamps'
    | null = null;
  private explicitSegments: SpokenSegment[] = [];
  private readonly wordTimeline = new WordTimeline();
  private segmentCounter = 0;

  beginAssistantItem(itemId?: string): void {
    if (!itemId) return;
    if (this.currentItemId && this.currentItemId !== itemId) {
      this.reset();
    }
    this.currentItemId = itemId;
  }

  trackAssistantDelta(delta: string, itemId?: string): void {
    if (!delta) return;
    this.beginAssistantItem(itemId);
    this.pendingText += delta;
    this.fullText += delta;
  }

  trackAssistantTranscript(text: string, itemId?: string): void {
    if (!text) return;
    this.beginAssistantItem(itemId);
    this.fullText = text;
  }

  trackAssistantSpokenDelta(
    delta: string,
    itemId?: string,
    meta?: {
      spokenChars?: number;
      spokenWords?: number;
      playbackMs?: number;
      precision?: 'ratio' | 'segment' | 'aligned' | 'provider-word-timestamps';
      wordTimestamps?: SpokenWordTimestamp[];
      wordTimestampsTimeBase?: 'segment' | 'utterance';
    }
  ): void {
    this.beginAssistantItem(itemId);
    const playbackMs = this.normalizeMs(meta?.playbackMs, this.explicitPlaybackMs);
    const previousText = this.explicitSpokenText;
    let nextText = previousText;
    if (delta) {
      nextText = previousText + delta;
    }
    if (typeof meta?.spokenChars === 'number' && meta.spokenChars >= 0 && this.fullText) {
      nextText = this.fullText.slice(0, Math.min(this.fullText.length, meta.spokenChars));
    }

    if (nextText.length > previousText.length) {
      const appended = nextText.slice(previousText.length);
      this.explicitSegments.push({
        id: this.nextSegmentId(),
        text: appended,
        audioStartMs: this.explicitPlaybackMs,
        audioEndMs: Math.max(this.explicitPlaybackMs, playbackMs),
      });
    }

    this.explicitSpokenText = nextText;
    this.ingestWordTimestamps(
      meta?.wordTimestamps,
      this.explicitPlaybackMs,
      meta?.wordTimestampsTimeBase ?? 'segment'
    );
    this.explicitPlaybackMs = playbackMs;
    this.explicitPrecision = this.wordTimeline.hasWords()
      ? 'provider-word-timestamps'
      : meta?.precision ?? this.explicitPrecision ?? 'segment';
    this.explicitSpokenWordCount =
      typeof meta?.spokenWords === 'number' && meta.spokenWords >= 0
        ? meta.spokenWords
        : countWords(nextText);
  }

  trackAssistantSpokenProgress(
    itemId: string,
    progress: {
      spokenChars: number;
      spokenWords: number;
      playbackMs: number;
      precision: 'ratio' | 'segment' | 'aligned' | 'provider-word-timestamps';
    }
  ): void {
    this.beginAssistantItem(itemId);
    const playbackMs = this.normalizeMs(progress.playbackMs, this.explicitPlaybackMs);
    const previousText = this.explicitSpokenText;
    let nextText = previousText;
    if (this.fullText) {
      nextText = this.fullText.slice(0, Math.min(this.fullText.length, progress.spokenChars));
    } else if (progress.spokenChars < previousText.length) {
      nextText = previousText.slice(0, progress.spokenChars);
    }

    if (nextText.length > previousText.length) {
      this.explicitSegments.push({
        id: this.nextSegmentId(),
        text: nextText.slice(previousText.length),
        audioStartMs: this.explicitPlaybackMs,
        audioEndMs: Math.max(this.explicitPlaybackMs, playbackMs),
      });
    } else if (nextText.length < previousText.length) {
      this.explicitSegments = trimSegmentsToChars(this.explicitSegments, nextText.length);
    }

    this.explicitSpokenText = nextText;
    this.explicitPlaybackMs = playbackMs;
    this.explicitPrecision = this.wordTimeline.hasWords()
      ? 'provider-word-timestamps'
      : progress.precision;
    this.explicitSpokenWordCount = Math.max(0, progress.spokenWords);
  }

  trackAssistantSpokenFinal(
    text: string,
    itemId?: string,
    meta?: {
      spokenChars?: number;
      spokenWords?: number;
      playbackMs?: number;
      precision?: 'ratio' | 'segment' | 'aligned' | 'provider-word-timestamps';
      wordTimestamps?: SpokenWordTimestamp[];
      wordTimestampsTimeBase?: 'segment' | 'utterance';
    }
  ): void {
    this.beginAssistantItem(itemId);
    const playbackMs = this.normalizeMs(meta?.playbackMs, this.explicitPlaybackMs);
    const finalText = text ?? '';
    this.explicitSpokenText = finalText;
    // spokenFinal can always replace the word timeline — it carries the
    // authoritative final timestamps, correcting any partial/inaccurate
    // data from earlier deltas.
    if (meta?.wordTimestamps && meta.wordTimestamps.length > 0) {
      this.wordTimeline.reset();
      this.ingestWordTimestamps(
        meta.wordTimestamps,
        0,
        meta.wordTimestampsTimeBase ?? 'utterance'
      );
    }
    this.explicitPlaybackMs = playbackMs;
    this.explicitPrecision = this.wordTimeline.hasWords()
      ? 'provider-word-timestamps'
      : meta?.precision ?? this.explicitPrecision ?? 'segment';
    this.explicitSpokenWordCount =
      typeof meta?.spokenWords === 'number' && meta.spokenWords >= 0
        ? meta.spokenWords
        : countWords(finalText);

    if (this.explicitSegments.length === 0 && finalText) {
      this.explicitSegments.push({
        id: this.nextSegmentId(),
        text: finalText,
        audioStartMs: 0,
        audioEndMs: playbackMs,
      });
    } else if (this.explicitSegments.length > 0) {
      const segmentText = this.explicitSegments.map((segment) => segment.text).join('');
      if (segmentText !== finalText) {
        this.explicitSegments = [
          {
            id: this.nextSegmentId(),
            text: finalText,
            audioStartMs: 0,
            audioEndMs: playbackMs,
          },
        ];
      }
    }
  }

  trackAssistantAudio(frame: AudioFrame): void {
    const chunkDurationMs = this.computeAudioDurationMs(frame);
    if (this.pendingText) {
      this.segments.push({
        id: this.nextSegmentId(),
        text: this.pendingText,
        audioStartMs: this.cumulativeAudioMs,
        audioEndMs: this.cumulativeAudioMs + chunkDurationMs,
      });
      this.pendingText = '';
    }
    this.cumulativeAudioMs += chunkDurationMs;
  }

  hasActiveAssistantOutput(): boolean {
    return (
      this.currentItemId !== null ||
      this.fullText.length > 0 ||
      this.pendingText.length > 0 ||
      this.cumulativeAudioMs > 0 ||
      this.explicitSpokenText.length > 0 ||
      this.explicitPlaybackMs > 0
    );
  }

  resolve(playbackPositionMs?: number): InterruptionContext | null {
    if (!this.currentItemId && !this.fullText && this.cumulativeAudioMs === 0) {
      return null;
    }

    const rawPlaybackMs = playbackPositionMs ?? this.cumulativeAudioMs;
    const upperBoundMs = Math.max(this.cumulativeAudioMs, this.explicitPlaybackMs, rawPlaybackMs);
    const clampedPlaybackMs = Math.max(
      0,
      Math.min(rawPlaybackMs, upperBoundMs || rawPlaybackMs)
    );

    let precision: InterruptionContext['precision'] = this.explicitPrecision ?? 'segment';
    let spokenText = '';
    let spans: InterruptionContext['spans'] | undefined;
    let explicitInterpolated = false;
    let resolvedSpokenWordCount: number | undefined;
    let resolvedSpokenWordIndex: number | undefined;

    const hasExplicitSpokenData =
      this.explicitSpokenText.length > 0 ||
      this.explicitSegments.length > 0 ||
      this.explicitPlaybackMs > 0;

    if (this.wordTimeline.hasWords()) {
      const timelineResolution = this.wordTimeline.getSpokenTextAt(clampedPlaybackMs);
      precision = 'provider-word-timestamps';
      spans = this.wordTimeline.getWordSpans();
      spokenText =
        playbackPositionMs === undefined && hasExplicitSpokenData
          ? this.explicitSpokenText
          : timelineResolution.text;
      resolvedSpokenWordCount =
        playbackPositionMs === undefined &&
        hasExplicitSpokenData &&
        this.explicitSpokenWordCount > 0
          ? this.explicitSpokenWordCount
          : timelineResolution.wordCount;
      resolvedSpokenWordIndex =
        playbackPositionMs === undefined && hasExplicitSpokenData
          ? undefined
          : timelineResolution.wordIndex;
    } else if (hasExplicitSpokenData) {
      const shouldInterpolateExplicitSegments =
        playbackPositionMs !== undefined &&
        clampedPlaybackMs > 0 &&
        clampedPlaybackMs < this.explicitPlaybackMs &&
        this.explicitSegments.length > 0;
      spokenText = shouldInterpolateExplicitSegments
        ? interpolateSegmentsToPlayback(this.explicitSegments, clampedPlaybackMs)
        : this.explicitSpokenText;
      explicitInterpolated = shouldInterpolateExplicitSegments;
      spans = this.explicitSegments.map((segment) => ({
        id: segment.id,
        text: segment.text,
        startMs: segment.audioStartMs,
        endMs: segment.audioEndMs,
        type: 'segment' as const,
      }));
    } else {
      spokenText = this.segments
        .filter((segment) => segment.audioStartMs < clampedPlaybackMs)
        .map((segment) => segment.text)
        .join('');
      spans = this.segments.map((segment) => ({
        id: segment.id,
        text: segment.text,
        startMs: segment.audioStartMs,
        endMs: segment.audioEndMs,
        type: 'segment' as const,
      }));
    }

    // Fallback for providers that do not align deltas tightly to audio chunks.
    if (!spokenText && this.fullText && clampedPlaybackMs > 0) {
      precision = 'ratio';
      const ratio =
        this.cumulativeAudioMs > 0 ? clampedPlaybackMs / this.cumulativeAudioMs : 0;
      const chars = Math.max(
        0,
        Math.min(this.fullText.length, Math.floor(this.fullText.length * ratio))
      );
      spokenText = this.fullText.slice(0, chars);
    }

    if (spokenText.length > this.fullText.length && this.fullText) {
      spokenText = spokenText.slice(0, this.fullText.length);
    }

    const spokenWordCount =
      typeof resolvedSpokenWordCount === 'number'
        ? resolvedSpokenWordCount
        : hasExplicitSpokenData && this.explicitSpokenWordCount > 0 && !explicitInterpolated
        ? this.explicitSpokenWordCount
        : countWords(spokenText);
    const spokenWordIndex =
      typeof resolvedSpokenWordIndex === 'number'
        ? resolvedSpokenWordIndex
        : spokenWordCount > 0
          ? Math.max(0, spokenWordCount - 1)
          : undefined;

    return {
      itemId: this.currentItemId ?? undefined,
      fullText: this.fullText,
      spokenText,
      playbackPositionMs: clampedPlaybackMs,
      truncated: spokenText !== this.fullText,
      spokenWordCount: spokenWordCount > 0 ? spokenWordCount : undefined,
      spokenWordIndex,
      precision,
      spans:
        precision === 'segment' || precision === 'provider-word-timestamps'
          ? spans
          : undefined,
    };
  }

  reset(): void {
    this.currentItemId = null;
    this.fullText = '';
    this.pendingText = '';
    this.segments = [];
    this.cumulativeAudioMs = 0;
    this.explicitSpokenText = '';
    this.explicitSpokenWordCount = 0;
    this.explicitPlaybackMs = 0;
    this.explicitPrecision = null;
    this.explicitSegments = [];
    this.wordTimeline.reset();
    this.segmentCounter = 0;
  }

  private computeAudioDurationMs(frame: AudioFrame): number {
    if (frame.sampleRate <= 0) return 0;
    const sampleCount = frame.data.byteLength / 2;
    return (sampleCount / frame.sampleRate) * 1000;
  }

  private normalizeMs(value: number | undefined, fallback: number): number {
    if (!Number.isFinite(value) || value === undefined || value < 0) {
      return Math.max(0, fallback);
    }
    return Math.max(0, value);
  }

  private nextSegmentId(): string {
    this.segmentCounter += 1;
    return `seg-${this.segmentCounter}`;
  }

  private ingestWordTimestamps(
    wordTimestamps: SpokenWordTimestamp[] | undefined,
    offsetMs: number,
    timeBase: 'segment' | 'utterance'
  ): void {
    if (!wordTimestamps || wordTimestamps.length === 0) {
      return;
    }
    const effectiveOffset = timeBase === 'utterance' ? 0 : offsetMs;
    this.wordTimeline.beginSegment(effectiveOffset);
    this.wordTimeline.addWords(wordTimestamps);
  }
}

function countWords(text: string): number {
  const trimmed = text.trim();
  if (!trimmed) return 0;
  return trimmed.split(/\s+/).length;
}

function trimSegmentsToChars(segments: SpokenSegment[], maxChars: number): SpokenSegment[] {
  if (maxChars <= 0) return [];
  const trimmed: SpokenSegment[] = [];
  let remaining = maxChars;
  for (const segment of segments) {
    if (remaining <= 0) break;
    if (segment.text.length <= remaining) {
      trimmed.push(segment);
      remaining -= segment.text.length;
      continue;
    }
    trimmed.push({
      ...segment,
      text: segment.text.slice(0, remaining),
    });
    remaining = 0;
  }
  return trimmed;
}

function interpolateSegmentsToPlayback(
  segments: SpokenSegment[],
  playbackPositionMs: number
): string {
  if (segments.length === 0 || playbackPositionMs <= 0) {
    return '';
  }

  let text = '';
  for (const segment of segments) {
    if (segment.audioStartMs >= playbackPositionMs) {
      break;
    }

    const segmentDuration = Math.max(0, segment.audioEndMs - segment.audioStartMs);
    if (segmentDuration <= 0 || segment.audioEndMs <= playbackPositionMs) {
      text += segment.text;
      continue;
    }

    const ratio = (playbackPositionMs - segment.audioStartMs) / segmentDuration;
    const interpolatedChars = Math.max(
      0,
      Math.min(segment.text.length, Math.floor(segment.text.length * ratio))
    );
    const snappedChars = snapToWordBoundary(segment.text, interpolatedChars);
    text += segment.text.slice(0, snappedChars);
    break;
  }
  return text;
}

function snapToWordBoundary(text: string, chars: number): number {
  if (chars <= 0) {
    return 0;
  }
  if (chars >= text.length) {
    return text.length;
  }
  if (text[chars] === ' ') {
    return chars;
  }
  const lastSpace = text.lastIndexOf(' ', chars);
  return lastSpace > 0 ? lastSpace : chars;
}



