interface GlassHUDProps {
  forceShow?: boolean;
}

export function GlassHUD({ forceShow = false }: GlassHUDProps) {
  const { voiceState: state, voiceProfile: profile } = useVoiceState();
  const timeline = useVoiceTimeline();
  const focusedSession = useFocusedSession();

  const isAgentActive = state === 'speaking' || state === 'thinking';
  const isTerminalStage = focusedSession?.type === 'terminal';
  const shouldShow = isAgentActive && (isTerminalStage || forceShow);

  const latestMessage = useMemo(() => {
    const assistantTranscripts = timeline.filter(
      (item): item is TranscriptItem =>
        item.type === 'transcript' && item.role === 'assistant'
    );
    return assistantTranscripts[assistantTranscripts.length - 1] || null;
  }, [timeline]);

  const generatedText = latestMessage?.generatedContent ?? latestMessage?.content ?? '';
  const spokenText = latestMessage?.spokenContent ?? '';

  const words = useMemo(() => {
    if (!generatedText) return [];
    return generatedText.split(/\s+/).filter(Boolean);
  }, [generatedText]);

  const spokenWordCount = useMemo(() => {
    if (!latestMessage) return 0;
    if (typeof latestMessage.spokenWords === 'number') {
      return Math.max(0, Math.min(latestMessage.spokenWords, words.length));
    }
    if (!spokenText.trim()) return 0;
    return Math.max(0, Math.min(spokenText.trim().split(/\s+/).length, words.length));
  }, [latestMessage, spokenText, words.length]);

  const stateDotColor = state === 'speaking'
    ? 'bg-green-500'
    : 'bg-purple-500';

  return (

      {shouldShow && (

          {/* Header */}



              {profile || 'Agent'}




              {state === 'speaking' ? 'Speaking' : 'Thinking'}



          {/* Transcript */}


            {words.length === 0 ? (
              Preparing response...
            ) : (
              words.map((word, index) => {
                const isSpoken = index < spokenWordCount;
                const isCurrent = index === spokenWordCount;
                return (

                    {word}{' '}

                );
              })
            )}


          {/* Voice indicator */}





      )}

  );
}



import { useState, useEffect, useRef } from 'react';
import type { AudioController } from '../lib/audio';
import { countCuesForPlayback } from '../lib/spoken-cues';

interface UseSpokenHighlightOptions {
  /** Total number of words in the generated text */
  totalWords: number;
  /** Whether the spoken stream is finalized (all audio emitted) */
  isFinalized: boolean;
  /** Whether the agent is currently speaking */
  isSpeaking: boolean;
  /** AudioController instance for querying real playback position */
  audioController: AudioController | null;
  /** Unique key for the currently highlighted turn/message */
  turnKey?: string | number | null;
  /** Optional cumulative word cue endpoints in milliseconds */
  wordCueEndMs?: number[];
  /** Fallback pace in ms/word when no cue timeline is provided */
  fallbackMsPerWord?: number;
}

const DEFAULT_MS_PER_WORD = 340;

/**
 * Drives word-by-word highlighting from the client's AudioContext clock.
 * The cursor is monotonic inside each turn and resets only on turnKey change.
 */
export function useSpokenHighlight({
  totalWords,
  isFinalized,
  isSpeaking,
  audioController,
  turnKey = null,
  wordCueEndMs,
  fallbackMsPerWord = DEFAULT_MS_PER_WORD,
}: UseSpokenHighlightOptions): number {
  const [highlightedCount, setHighlightedCount] = useState(0);
  const highlightedRef = useRef(0);
  const rafRef = useRef(0);
  const previousTurnKeyRef = useRef(turnKey);

  // Cumulative playback offset — bridges AudioController position resets
  // between TTS segments.  AudioController resets playbackPositionMs to 0
  // when all scheduled audio drains, but word cues use utterance-relative
  // timestamps that accumulate across segments.  This offset keeps the
  // two aligned so highlighting progresses continuously.
  const playbackOffsetRef = useRef(0);
  const prevRawPlaybackRef = useRef(0);
  const prevRawScheduledRef = useRef(0);

  useEffect(() => {
    if (turnKey !== previousTurnKeyRef.current) {
      previousTurnKeyRef.current = turnKey;
      highlightedRef.current = 0;
      playbackOffsetRef.current = 0;
      prevRawPlaybackRef.current = 0;
      prevRawScheduledRef.current = 0;
      setHighlightedCount(0);
    }
  }, [turnKey]);

  useEffect(() => {
    if (!audioController || totalWords <= 0) {
      if (rafRef.current) {
        cancelAnimationFrame(rafRef.current);
        rafRef.current = 0;
      }
      if (totalWords === 0 && highlightedRef.current !== 0) {
        highlightedRef.current = 0;
        setHighlightedCount(0);
      }
      return;
    }

    if (highlightedRef.current > totalWords) {
      highlightedRef.current = totalWords;
      setHighlightedCount(totalWords);
    }

    const cueTimeline =
      Array.isArray(wordCueEndMs) && wordCueEndMs.length > 0 ? wordCueEndMs : undefined;
    const msPerWord = normalizePositive(fallbackMsPerWord, DEFAULT_MS_PER_WORD);

    const tick = () => {
      const rawPlaybackMs = audioController.getPlaybackPositionMs();
      const rawScheduledMs = audioController.getScheduledDurationMs();
      const hasPendingAudio = rawScheduledMs > 0;

      // Detect AudioController position reset: the raw position dropped while
      // there was previously scheduled audio.  This happens between TTS
      // segments when all scheduled audio finishes before the next segment
      // arrives.  Accumulate the previous segment's total duration so that
      // the cumulative position keeps advancing.
      if (
        rawPlaybackMs < prevRawPlaybackRef.current &&
        prevRawScheduledRef.current > 0
      ) {
        playbackOffsetRef.current += prevRawScheduledRef.current;
      }
      prevRawPlaybackRef.current = rawPlaybackMs;
      prevRawScheduledRef.current = rawScheduledMs;

      const playbackMs = playbackOffsetRef.current + rawPlaybackMs;

      let nextWordCount = cueTimeline
        ? countCuesForPlayback(cueTimeline, playbackMs)
        : Math.floor(playbackMs / msPerWord);

      if (isFinalized && !hasPendingAudio) {
        // Audio fully drained — force-complete regardless of cue mode.
        // The last cue's endMs may exceed the real playback clock by a few ms,
        // but once the AudioContext has nothing left to play, all words should
        // be marked spoken.
        nextWordCount = totalWords;
      }

      nextWordCount = clamp(nextWordCount, 0, totalWords);
      if (nextWordCount < highlightedRef.current) {
        nextWordCount = highlightedRef.current;
      }

      if (nextWordCount !== highlightedRef.current) {
        highlightedRef.current = nextWordCount;
        setHighlightedCount(nextWordCount);
      }

      if (isSpeaking || hasPendingAudio) {
        rafRef.current = requestAnimationFrame(tick);
      } else {
        rafRef.current = 0;
      }
    };

    rafRef.current = requestAnimationFrame(tick);

    return () => {
      if (rafRef.current) {
        cancelAnimationFrame(rafRef.current);
        rafRef.current = 0;
      }
    };
  }, [totalWords, isFinalized, isSpeaking, audioController, turnKey, wordCueEndMs, fallbackMsPerWord]);

  return highlightedCount;
}

function normalizePositive(value: number, fallback: number): number {
  if (!Number.isFinite(value) || value <= 0) return fallback;
  return value;
}

function clamp(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(value, max));
}



// ═══════════════════════════════════════════════════════════════════════════
// Message Handler - Routes WebSocket events to unified sessions store
// ═══════════════════════════════════════════════════════════════════════════
//
// Phase 5: Simplified Protocol
// - Core events: welcome, stream_chunk, session_tree_update, state_change, master_changed
// - Lifecycle: session_started, session_ended, cli_session_deleted, error
//
// stream_chunk handles ALL agent content (voice + subagent) in AI SDK format.
// Voice sessions also populate voiceTimeline for AgentStage compatibility.

import {
  useUnifiedSessionsStore,
  type TimelineItem,
  type TranscriptItem,
  type ToolItem,
} from './unified-sessions';
import type { WSMessage } from '../types';
import { applyWordCueUpdate } from '../lib/spoken-cues';

// ═══════════════════════════════════════════════════════════════════════════
// Types (Phase 5: Simplified Protocol)
// ═══════════════════════════════════════════════════════════════════════════

interface StateChangePayload {
  state: 'idle' | 'listening' | 'thinking' | 'speaking';
  profile: string | null;
}

interface WelcomePayload {
  clientId: string;
  isMaster: boolean;
  serviceActive: boolean;
  audioMode: 'web' | 'local';
}

interface ServiceStateChangedPayload {
  active: boolean;
  mode: 'web' | 'local';
}

interface MasterChangedPayload {
  masterId: string;
}

interface SessionTreeUpdatePayload {
  tree?: {
    id: string;
    type: 'voice' | 'orchestrator' | 'terminal';
    status: string;
    goal: string;
    agent_name: string | null;
    tool_call_id: string | null;
    created_at: string;
    children: SessionTreeUpdatePayload['tree'][];
  };
  trees?: SessionTreeUpdatePayload['tree'][];
}

interface CliSessionDeletedPayload {
  sessionId?: string;
  all?: boolean;
}

// ═══════════════════════════════════════════════════════════════════════════
// ID Generator
// ═══════════════════════════════════════════════════════════════════════════

const generateId = () => `msg_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;

// ═══════════════════════════════════════════════════════════════════════════
// Helper Functions
// ═══════════════════════════════════════════════════════════════════════════

/**
 * Find timeline item index by provider itemId, preferring the most recent match.
 * Using the latest match avoids attaching new deltas to stale placeholders.
 */
function findTimelineItemByItemId(
  timeline: TranscriptItem[],
  itemId: string,
  role?: 'user' | 'assistant'
): number {
  for (let idx = timeline.length - 1; idx >= 0; idx -= 1) {
    const item = timeline[idx];
    if (item.type !== 'transcript') continue;
    if (item.itemId !== itemId) continue;
    if (role && item.role !== role) continue;
    return idx;
  }
  return -1;
}

function toOrderValue(order?: number): number | null {
  return typeof order === 'number' && Number.isFinite(order) ? order : null;
}

function findVoiceTimelineInsertIndex(
  timeline: TimelineItem[],
  order?: number,
  previousItemId?: string
): number | undefined {
  const targetOrder = toOrderValue(order);

  if (previousItemId) {
    for (let idx = timeline.length - 1; idx >= 0; idx -= 1) {
      const item = timeline[idx];
      if (item.type !== 'transcript') continue;
      if (item.itemId !== previousItemId) continue;

      // Use previousItemId as an anchor, but never insert ahead of earlier-order
      // transcript items.
      let insertIdx = idx + 1;
      if (targetOrder !== null) {
        while (insertIdx < timeline.length) {
          const current = timeline[insertIdx];
          if (!current || current.type !== 'transcript') {
            insertIdx += 1;
            continue;
          }
          const currentOrder = toOrderValue(current.order);
          if (currentOrder === null) {
            insertIdx += 1;
            continue;
          }
          if (currentOrder >= targetOrder) break;
          insertIdx += 1;
        }
      }
      return insertIdx;
    }
  }

  if (targetOrder === null) return undefined;

  for (let idx = 0; idx < timeline.length; idx += 1) {
    const item = timeline[idx];
    if (item.type !== 'transcript') continue;
    const currentOrder = toOrderValue(item.order);
    if (currentOrder === null) continue;
    if (currentOrder > targetOrder) {
      return idx;
    }
  }

  return timeline.length;
}

// ═══════════════════════════════════════════════════════════════════════════
// Message Handler
// ═══════════════════════════════════════════════════════════════════════════

/**
 * Handle incoming WebSocket message and route to unified store.
 * This provides backward compatibility with existing events while
 * preparing for the new stream_chunk protocol.
 */
export function handleWebSocketMessage(msg: WSMessage): void {
  const store = useUnifiedSessionsStore.getState();
  const { type, payload, timestamp } = msg;

  // Log event for debugging
  store.addEvent(type, payload);

  switch (type) {
    // ─────────────────────────────────────────────────────────────────────────
    // Connection Events
    // ─────────────────────────────────────────────────────────────────────────

    case 'welcome': {
      const { clientId, isMaster, serviceActive, audioMode } = payload as WelcomePayload;
      console.log(`[WS] Welcome: clientId=${clientId.slice(0, 8)}, isMaster=${isMaster}, serviceActive=${serviceActive}, audioMode=${audioMode}`);
      store.setClientIdentity(clientId, isMaster, serviceActive, audioMode);
      break;
    }

    case 'service_state_changed': {
      const { active, mode } = payload as ServiceStateChangedPayload;
      console.log(`[WS] Service state changed: active=${active}, mode=${mode}`);
      store.setServiceState(active, mode);
      break;
    }

    case 'audio_control': {
      const { action } = payload as { action: 'start' | 'stop' | 'interrupt' };
      // Dispatch custom event for useAudioSession to handle
      window.dispatchEvent(new CustomEvent('ws-audio-control', { detail: action }));
      break;
    }

    case 'master_changed': {
      const { masterId } = payload as MasterChangedPayload;
      const { clientId } = store;
      const newIsMaster = clientId === masterId;
      console.log(`[WS] Master changed to ${masterId.slice(0, 8)}, isMaster=${newIsMaster}`);
      store.setIsMaster(newIsMaster);
      break;
    }

    // ─────────────────────────────────────────────────────────────────────────
    // Voice Session Events
    // ─────────────────────────────────────────────────────────────────────────

    case 'state_change': {
      const { state, profile } = payload as StateChangePayload;
      store.setVoiceState(state, profile);
      break;
    }

    case 'session_started': {
      store.clearVoiceTimeline();
      store.setVoiceActive(true);
      break;
    }

    case 'session_ended': {
      store.setVoiceState('idle');
      store.setVoiceActive(false);
      store.setCurrentTool(null);
      break;
    }

    // NOTE: transcript, item_pending, item_completed, tool_start, tool_end
    // are now handled via stream_chunk for voice sessions (Phase 5 simplification)

    // ─────────────────────────────────────────────────────────────────────────
    // Session Tree Events (v2 Architecture)
    // ─────────────────────────────────────────────────────────────────────────

    case 'session_tree_update': {
      const treePayload = payload as SessionTreeUpdatePayload;
      store.handleSessionTreeUpdate(treePayload as Parameters[0]);
      break;
    }

    // NOTE: subagent_activity is replaced by stream_chunk (Phase 5)
    // NOTE: cli_session_created/update are handled via session_tree_update

    case 'cli_session_deleted': {
      const deletePayload = payload as CliSessionDeletedPayload;
      if (deletePayload.all) {
        store.clearSessions();
      } else if (deletePayload.sessionId) {
        store.removeSession(deletePayload.sessionId);
      }
      break;
    }

    // ─────────────────────────────────────────────────────────────────────────
    // New Protocol Events (Phase 1)
    // ─────────────────────────────────────────────────────────────────────────

    case 'stream_chunk': {
      // Unified AI SDK protocol for all agents (voice + subagent)
      const { sessionId, event } = payload as { sessionId: string; event: Parameters[1] };

      // Update session messages (works for all session types)
      store.handleStreamChunk(sessionId, event);

      // Handle process-status events (toast notifications for completed/errored processes)
      if (event.type === 'process-status') {
        store.addToast({
          id: `toast-${Date.now()}`,
          sessionName: event.processName,
          sessionId: event.sessionId || sessionId,
          status: event.status,
          summary: event.summary || (event.status === 'completed' ? 'Task finished' : 'Task failed'),
          timestamp: Date.now(),
        });
      }

      if (event.type === 'latency' && event.stage === 'tts') {
        const details = (event.details ?? {}) as Record;
        const metric = typeof details.metric === 'string' ? details.metric : null;
        if (metric === 'chunk') {
          const chunkIndex =
            typeof details.chunkIndex === 'number' ? details.chunkIndex : null;
          const ttfb =
            typeof details.firstChunkTtfbMs === 'number'
              ? `${Math.round(details.firstChunkTtfbMs)}ms`
              : 'n/a';
          const rtf =
            typeof details.producerRtf === 'number'
              ? details.producerRtf.toFixed(3)
              : 'n/a';
          const lead =
            typeof details.playoutLeadMs === 'number'
              ? `${Math.round(details.playoutLeadMs)}ms`
              : 'n/a';
          console.debug(
            `[TTS Debug] chunk${chunkIndex ? ` #${chunkIndex}` : ''} ttfb=${ttfb} rtf=${rtf} lead=${lead}`
          );
        } else if (metric === 'adaptive-update' || metric === 'startup-release') {
          console.debug('[TTS Debug]', metric, details);
        }
      }

      // For voice sessions, also populate voiceTimeline for AgentStage compatibility
      // Detect voice session: it's the root of the current tree with type='voice'
      const { sessionTree, voiceActive } = store;
      const isVoiceSession =
        voiceActive &&
        sessionTree?.id === sessionId &&
        sessionTree?.type === 'voice';

      if (isVoiceSession) {
        // Convert AI SDK events to voiceTimeline format
        switch (event.type) {
          case 'user-placeholder': {
            const { voiceTimeline } = store;
            const transcriptItems = voiceTimeline.filter(
              (item): item is TranscriptItem => item.type === 'transcript'
            );
            const existingIdx = findTimelineItemByItemId(transcriptItems, event.itemId, 'user');
            if (existingIdx >= 0) {
              break;
            }

            // Create placeholder for user message (reserves position before transcript arrives)
            const newItem: TranscriptItem = {
              id: generateId(),
              type: 'transcript',
              role: 'user',
              content: '',
              timestamp,
              pending: true,
              itemId: event.itemId,
              order: event.order,
            };
            const insertIndex = findVoiceTimelineInsertIndex(
              voiceTimeline,
              event.order,
              event.previousItemId
            );
            store.addVoiceTimelineItem(newItem, insertIndex);
            break;
          }

          case 'assistant-placeholder': {
            const { voiceTimeline } = store;
            const transcriptItems = voiceTimeline.filter(
              (item): item is TranscriptItem => item.type === 'transcript'
            );
            const existingIdx = findTimelineItemByItemId(transcriptItems, event.itemId, 'assistant');
            if (existingIdx >= 0) {
              break;
            }

            // Create placeholder for assistant message (reserves position before transcript arrives)
            const newItem: TranscriptItem = {
              id: generateId(),
              type: 'transcript',
              role: 'assistant',
              content: '',
              generatedContent: '',
              spokenContent: '',
              spokenFinalized: false,
              timestamp,
              pending: true,
              itemId: event.itemId,
              order: event.order,
            };
            const insertIndex = findVoiceTimelineInsertIndex(
              voiceTimeline,
              event.order,
              event.previousItemId
            );
            store.addVoiceTimelineItem(newItem, insertIndex);
            break;
          }

          case 'text-delta': {
            // Add/update assistant transcript in voice timeline
            const { voiceTimeline } = store;
            const deltaText = event.textDelta ?? '';
            const channel = event.channel ?? 'generated';

            if (channel === 'spoken') {
              let targetItem: TranscriptItem | undefined;
              if (event.itemId) {
                const transcriptItems = voiceTimeline.filter(
                  (item): item is TranscriptItem => item.type === 'transcript'
                );
                const idx = findTimelineItemByItemId(transcriptItems, event.itemId, 'assistant');
                targetItem = idx >= 0 ? transcriptItems[idx] : undefined;
              }

              if (!targetItem) {
                targetItem = [...voiceTimeline].reverse().find(
                  (item): item is TranscriptItem =>
                    item.type === 'transcript' && item.role === 'assistant' && !!item.pending
                );
              }

              if (targetItem) {
                const nextSpoken = `${targetItem.spokenContent ?? ''}${deltaText}`;
                const nextContent = nextSpoken || targetItem.content;
                store.updateVoiceTimelineItem(targetItem.id, {
                  content: nextContent,
                  spokenContent: nextSpoken,
                  spokenChars: nextSpoken.length,
                  spokenFinalized: false,
                  order: event.order ?? targetItem.order,
                } as Partial);
                break;
              }

              if (deltaText.trim().length === 0) {
                break;
              }

              const spokenSeed: TranscriptItem = {
                id: generateId(),
                type: 'transcript',
                role: 'assistant',
                content: deltaText,
                generatedContent: '',
                spokenContent: deltaText,
                spokenChars: deltaText.length,
                spokenFinalized: false,
                timestamp,
                pending: true,
                itemId: event.itemId,
                order: event.order,
              };
              const insertIndex = findVoiceTimelineInsertIndex(voiceTimeline, event.order);
              store.addVoiceTimelineItem(spokenSeed, insertIndex);
              break;
            }

            // Try to find existing placeholder by itemId first
            if (event.itemId) {
              const transcriptItems = voiceTimeline.filter(
                (item): item is TranscriptItem => item.type === 'transcript'
              );
              const idx = findTimelineItemByItemId(transcriptItems, event.itemId, 'assistant');
              if (idx >= 0) {
                const item = transcriptItems[idx];
                const nextGenerated = `${item.generatedContent ?? item.content}${deltaText}`;
                store.updateVoiceTimelineItem(item.id, {
                  content: item.spokenContent ?? item.content,
                  generatedContent: nextGenerated,
                  spokenFinalized: false,
                  order: event.order ?? item.order,
                } as Partial);
                break;
              }

              // Ignore scaffold-only deltas when no matching placeholder exists.
              if (deltaText.trim().length === 0) {
                break;
              }
            }

            if (event.itemId) {
              const newItem: TranscriptItem = {
                id: generateId(),
                type: 'transcript',
                role: 'assistant',
                content: '',
                generatedContent: deltaText,
                spokenContent: '',
                spokenFinalized: false,
                timestamp,
                pending: true,
                itemId: event.itemId,
                order: event.order,
              };
              const insertIndex = findVoiceTimelineInsertIndex(
                voiceTimeline,
                event.order
              );
              store.addVoiceTimelineItem(newItem, insertIndex);
              break;
            }

            // Fallback for providers that do not send stable item IDs.
            const lastPendingAssistant = [...voiceTimeline].reverse().find(
              (item): item is TranscriptItem =>
                item.type === 'transcript' && item.role === 'assistant' && !!item.pending
            );

            if (lastPendingAssistant) {
              const nextGenerated = `${lastPendingAssistant.generatedContent ?? lastPendingAssistant.content}${deltaText}`;
              store.updateVoiceTimelineItem(lastPendingAssistant.id, {
                content: lastPendingAssistant.spokenContent ?? lastPendingAssistant.content,
                generatedContent: nextGenerated,
                spokenFinalized: false,
                order: event.order ?? lastPendingAssistant.order,
              } as Partial);
            } else {
              if (deltaText.trim().length === 0) {
                break;
              }
              const newItem: TranscriptItem = {
                id: generateId(),
                type: 'transcript',
                role: 'assistant',
                content: '',
                generatedContent: deltaText,
                spokenContent: '',
                spokenFinalized: false,
                timestamp,
                pending: true,
                order: event.order,
              };
              store.addVoiceTimelineItem(newItem);
            }
            break;
          }

          case 'spoken-delta': {
            const { voiceTimeline } = store;
            const deltaText = event.textDelta ?? '';

            let targetItem: TranscriptItem | undefined;
            if (event.itemId) {
              const transcriptItems = voiceTimeline.filter(
                (item): item is TranscriptItem => item.type === 'transcript'
              );
              const idx = findTimelineItemByItemId(transcriptItems, event.itemId, 'assistant');
              targetItem = idx >= 0 ? transcriptItems[idx] : undefined;
            }

            if (!targetItem) {
              targetItem = [...voiceTimeline].reverse().find(
                (item): item is TranscriptItem =>
                  item.type === 'transcript' && item.role === 'assistant' && !!item.pending
              );
            }

            if (targetItem) {
              const nextSpoken = `${targetItem.spokenContent ?? ''}${deltaText}`;
              const nextContent = nextSpoken || targetItem.content;
              const nextWordCues = applyWordCueUpdate(
                event.wordCues ?? targetItem.wordCues,
                event.wordCueUpdate
              );
              store.updateVoiceTimelineItem(targetItem.id, {
                content: nextContent,
                spokenContent: nextSpoken,
                spokenChars: event.spokenChars ?? nextSpoken.length,
                spokenWords: event.spokenWords,
                playbackMs: event.playbackMs,
                precision: event.precision,
                wordCues: nextWordCues,
                spokenFinalized: false,
                order: event.order ?? targetItem.order,
              } as Partial);
              break;
            }

            if (deltaText.trim().length === 0) {
              break;
            }

            const newItem: TranscriptItem = {
              id: generateId(),
              type: 'transcript',
              role: 'assistant',
              content: deltaText,
              generatedContent: '',
              spokenContent: deltaText,
              spokenChars: event.spokenChars ?? deltaText.length,
              spokenWords: event.spokenWords,
              playbackMs: event.playbackMs,
              precision: event.precision,
              wordCues: applyWordCueUpdate(event.wordCues, event.wordCueUpdate),
              spokenFinalized: false,
              timestamp,
              pending: true,
              itemId: event.itemId,
              order: event.order,
            };
            const insertIndex = findVoiceTimelineInsertIndex(voiceTimeline, event.order);
            store.addVoiceTimelineItem(newItem, insertIndex);
            break;
          }

          case 'spoken-progress': {
            const { voiceTimeline } = store;
            const transcriptItems = voiceTimeline.filter(
              (item): item is TranscriptItem => item.type === 'transcript'
            );
            const idx = findTimelineItemByItemId(transcriptItems, event.itemId, 'assistant');
            if (idx < 0) {
              const fallbackItem: TranscriptItem = {
                id: generateId(),
                type: 'transcript',
                role: 'assistant',
                content: '',
                generatedContent: '',
                spokenContent: '',
                spokenChars: event.spokenChars,
                spokenWords: event.spokenWords,
                playbackMs: event.playbackMs,
                precision: event.precision,
                spokenFinalized: false,
                timestamp,
                pending: true,
                itemId: event.itemId,
              };
              store.addVoiceTimelineItem(fallbackItem);
              break;
            }
            const item = transcriptItems[idx];
            const generatedText = item.generatedContent ?? item.content;
            const spokenChars = Math.max(0, Math.min(generatedText.length, event.spokenChars));
            const spokenContent = generatedText
              ? generatedText.slice(0, spokenChars)
              : (item.spokenContent ?? '').slice(0, event.spokenChars);
            const content = spokenContent || item.content;
            store.updateVoiceTimelineItem(item.id, {
              content,
              spokenContent,
              spokenChars: event.spokenChars,
              spokenWords: event.spokenWords,
              playbackMs: event.playbackMs,
              precision: event.precision,
              spokenFinalized: false,
            } as Partial);
            break;
          }

          case 'spoken-final': {
            const { voiceTimeline } = store;
            let targetItem: TranscriptItem | undefined;

            if (event.itemId) {
              const transcriptItems = voiceTimeline.filter(
                (item): item is TranscriptItem => item.type === 'transcript'
              );
              const idx = findTimelineItemByItemId(transcriptItems, event.itemId, 'assistant');
              targetItem = idx >= 0 ? transcriptItems[idx] : undefined;
            }

            if (!targetItem) {
              targetItem = [...voiceTimeline].reverse().find(
                (item): item is TranscriptItem =>
                  item.type === 'transcript' && item.role === 'assistant'
              );
            }

            if (targetItem) {
              const nextWordCues = applyWordCueUpdate(
                event.wordCues ?? targetItem.wordCues,
                event.wordCueUpdate
              );
              // `spoken-final` is the authoritative spoken output (possibly
              // truncated by interruption). Keep generated content aligned with
              // spoken text so overlays/highlighting stop at the spoken boundary.
              const generatedContent = event.text;
              store.updateVoiceTimelineItem(targetItem.id, {
                content: event.text,
                generatedContent,
                spokenContent: event.text,
                spokenChars: event.spokenChars ?? event.text.length,
                spokenWords: event.spokenWords,
                playbackMs: event.playbackMs,
                precision: event.precision,
                wordCues: nextWordCues,
                spokenFinalized: true,
                pending: false,
                order: event.order ?? targetItem.order,
              } as Partial);
              break;
            }

            const newItem: TranscriptItem = {
              id: generateId(),
              type: 'transcript',
              role: 'assistant',
              content: event.text,
              generatedContent: event.text,
              spokenContent: event.text,
              spokenChars: event.spokenChars ?? event.text.length,
              spokenWords: event.spokenWords,
              playbackMs: event.playbackMs,
              precision: event.precision,
              wordCues: applyWordCueUpdate(event.wordCues, event.wordCueUpdate),
              spokenFinalized: true,
              timestamp,
              pending: false,
              itemId: event.itemId,
              order: event.order,
            };
            const insertIndex = findVoiceTimelineInsertIndex(voiceTimeline, event.order);
            store.addVoiceTimelineItem(newItem, insertIndex);
            break;
          }

          case 'user-transcript': {
            // Try to find and fill placeholder by itemId
            if (event.itemId) {
              const { voiceTimeline } = store;
              const transcriptItems = voiceTimeline.filter(
                (item): item is TranscriptItem => item.type === 'transcript'
              );
              const idx = findTimelineItemByItemId(transcriptItems, event.itemId, 'user');
              if (idx >= 0) {
                const item = transcriptItems[idx];
                store.updateVoiceTimelineItem(item.id, {
                  content: event.text,
                  pending: false,
                  order: event.order ?? item.order,
                } as Partial);
                break;
              }
            }

            // Fallback: create new timeline item
            const newItem: TranscriptItem = {
              id: generateId(),
              type: 'transcript',
              role: 'user',
              content: event.text,
              timestamp,
              pending: false,
              itemId: event.itemId,
              order: event.order,
            };
            const { voiceTimeline } = store;
            const insertIndex = findVoiceTimelineInsertIndex(
              voiceTimeline,
              event.order
            );
            store.addVoiceTimelineItem(newItem, insertIndex);
            break;
          }

          case 'tool-call': {
            const toolItem: ToolItem = {
              id: event.toolCallId,
              type: 'tool',
              name: event.toolName,
              args: event.input as Record,
              status: 'running',
              timestamp,
            };
            store.addVoiceTimelineItem(toolItem);
            store.setCurrentTool({ name: event.toolName, args: event.input as Record });
            break;
          }

          case 'tool-result': {
            const { voiceTimeline } = store;
            // Match by toolCallId first (reliable even with repeated same tool names).
            // Fall back to the latest running tool with same name for older events.
            let toolIdx = voiceTimeline.findIndex(
              (item) => item.type === 'tool' && item.id === event.toolCallId
            );
            if (toolIdx < 0) {
              toolIdx = [...voiceTimeline]
                .map((item, idx) => ({ item, idx }))
                .reverse()
                .find(
                  ({ item }) =>
                    item.type === 'tool' &&
                    (item as ToolItem).name === event.toolName &&
                    (item as ToolItem).status === 'running'
                )?.idx ?? -1;
            }
            if (toolIdx >= 0) {
              const resultText =
                typeof event.output === 'string'
                  ? event.output
                  : JSON.stringify(event.output, null, 2);
              store.updateVoiceTimelineItem(voiceTimeline[toolIdx].id, {
                status: 'completed',
                result: resultText,
              } as Partial);
            } else {
              // Keep result visible even when call/result ordering or IDs drift.
              const resultText =
                typeof event.output === 'string'
                  ? event.output
                  : JSON.stringify(event.output, null, 2);
              const fallbackTool: ToolItem = {
                id: event.toolCallId,
                type: 'tool',
                name: event.toolName,
                args: {},
                status: 'completed',
                result: resultText,
                timestamp,
              };
              store.addVoiceTimelineItem(fallbackTool);
            }
            store.setCurrentTool(null);
            break;
          }

          case 'latency': {
            if (event.stage !== 'tts') {
              break;
            }
            const firstAudioLatencyMs = event.details?.firstAudioLatencyMs;
            if (typeof firstAudioLatencyMs !== 'number' || !Number.isFinite(firstAudioLatencyMs)) {
              break;
            }
            const segmentIndex = event.details?.segmentIndex;
            if (typeof segmentIndex === 'number' && segmentIndex > 1) {
              break;
            }

            const { voiceTimeline } = store;
            const assistantIdx = [...voiceTimeline]
              .map((item, idx) => ({ item, idx }))
              .reverse()
              .find(
                ({ item }) =>
                  item.type === 'transcript' &&
                  item.role === 'assistant'
              )?.idx;

            if (assistantIdx !== undefined && assistantIdx >= 0) {
              const target = voiceTimeline[assistantIdx];
              if (target?.type === 'transcript' && typeof target.ttfbMs !== 'number') {
                store.updateVoiceTimelineItem(target.id, {
                  ttfbMs: Math.max(0, Math.round(firstAudioLatencyMs)),
                } as Partial);
              }
            }
            break;
          }

          case 'finish': {
            // Mark all pending assistant transcripts as complete.
            // This prevents stale "typing" indicators from orphan placeholders.
            const { voiceTimeline } = store;
            const pendingAssistantItems = voiceTimeline.filter(
              (item): item is TranscriptItem =>
                item.type === 'transcript' && item.role === 'assistant' && !!item.pending
            );
            for (const item of pendingAssistantItems) {
              const spokenText = item.spokenContent || '';
              const generatedText = item.generatedContent || item.content || '';
              // Voice UI must prefer audio-confirmed spoken text on finish.
              // If interruption happens before spokenFinal arrives, generated text
              // may already contain tokens the user never heard.
              const content = spokenText || generatedText;
              store.updateVoiceTimelineItem(item.id, {
                content,
                pending: false,
              } as Partial);
            }
            break;
          }
        }
      }
      break;
    }

    // ─────────────────────────────────────────────────────────────────────────
    // Error Events
    // ─────────────────────────────────────────────────────────────────────────

    case 'error': {
      const errorPayload = payload as { message: string };
      console.error('[WS] Error:', errorPayload.message);
      break;
    }
  }
}



