interface VoiceRuntimePanelProps {
  config: VoiceConfigDocument | null;
  setConfig: (config: VoiceConfigDocument) => void;
  save: () => Promise;
  loading: boolean;
  saving: boolean;
  error: string | null;
}

function withCurrent(options: string[], current: string): string[] {
  if (!current) return options;
  return options.includes(current) ? options : [current, ...options];
}

function parseNumeric(value: string, fallback: number, min?: number): number {
  const parsed = Number(value);
  if (!Number.isFinite(parsed)) return fallback;
  if (typeof min === 'number') return Math.max(min, parsed);
  return parsed;
}

function pickMatchingOrFirst(options: string[], current: string, fallback = ''): string {
  if (options.length === 0) return fallback;
  return options.includes(current) ? current : options[0]!;
}

function getPathValue(obj: unknown, path: string): unknown {
  if (!path) return undefined;
  const segments = path.split('.');
  let cursor: unknown = obj;
  for (const segment of segments) {
    if (!cursor || typeof cursor !== 'object') return undefined;
    cursor = (cursor as Record)[segment];
  }
  return cursor;
}

function setPathValue(obj: T, path: string, value: unknown): T {
  const segments = path.split('.');
  if (segments.length === 0) return obj;

  const root = { ...(obj as Record) };
  let cursor: Record = root;
  let source: unknown = obj;

  for (let i = 0; i < segments.length - 1; i += 1) {
    const segment = segments[i]!;
    const sourceObj = source && typeof source === 'object'
      ? (source as Record)
      : undefined;
    const sourceNext = sourceObj?.[segment];

    const next = sourceNext && typeof sourceNext === 'object' && !Array.isArray(sourceNext)
      ? { ...(sourceNext as Record) }
      : {};

    cursor[segment] = next;
    cursor = next;
    source = sourceNext;
  }

  cursor[segments[segments.length - 1]!] = value;
  return root as T;
}

function asString(value: unknown, fallback = ''): string {
  if (typeof value === 'string') return value;
  if (typeof value === 'number' || typeof value === 'boolean') return String(value);
  return fallback;
}

function asVoiceList(catalog: VoiceCatalog | null, key: string | undefined): ProviderVoiceEntry[] {
  if (!catalog || !key) return [];
  return catalog.providerCatalog[key]?.voices ?? [];
}

function asModelList(catalog: VoiceCatalog | null, key: string | undefined): string[] {
  if (!catalog || !key) return [];
  return catalog.providerCatalog[key]?.models ?? [];
}

function AuthProfileSelect({
  value,
  onChange,
  profileNames,
  placeholder,
}: {
  value: string | undefined;
  onChange: (value: string | undefined) => void;
  profileNames: string[];
  placeholder?: string;
}) {
  return (

       onChange(e.target.value || undefined)}
      >
        {placeholder ?? '(provider default)'}
        {profileNames.map((name) => (

            {name}

        ))}


  );
}

function renderRuntimeField(args: {
  field: RuntimeFieldBinding;
  value: unknown;
  language: string;
  catalog: VoiceCatalog | null;
  authProfileNames: string[];
  onChange: (value: unknown) => void;
}) {
  const { field, value, language, catalog, authProfileNames, onChange } = args;
  const current = asString(value);

  if (field.kind === 'model') {
    const options = withCurrent(asModelList(catalog, field.catalogKey), current);
    return (

         onChange(event.target.value)}>
          {options.map((option) => (

              {option}

          ))}


    );
  }

  if (field.kind === 'voice') {
    const voices = asVoiceList(catalog, field.catalogKey);
    return (
       onChange(voiceId)}
        languageFilter={language}
      />
    );
  }

  if (field.kind === 'auth') {
    return (
       onChange(next)}
        profileNames={authProfileNames}
      />
    );
  }

  if (field.kind === 'select') {
    return (

         onChange(event.target.value)}>
          {(field.options ?? []).map((opt) => (

              {opt.label}

          ))}


    );
  }

  return (

       onChange(event.target.value)}
      />

  );
}

function stageDescription(stage: RuntimeDecomposedStageManifest): string {
  if (stage.id === 'stt') return 'Transcribes user audio input before LLM routing.';
  if (stage.id === 'llm') return 'Runs reasoning and tool logic on each completed transcript turn.';
  return 'Synthesizes assistant responses back to audio.';
}

export function VoiceRuntimePanel({
  config,
  setConfig,
  save,
  loading,
  saving,
  error,
}: VoiceRuntimePanelProps) {
  const [open, setOpen] = useState(false);
  const [catalog, setCatalog] = useState(null);
  const [catalogError, setCatalogError] = useState(null);
  const [effectiveSummary, setEffectiveSummary] = useState<Record>({});

  useEffect(() => {
    let cancelled = false;
    void (async () => {
      try {
        const next = await fetchVoiceCatalog();
        if (!cancelled) {
          setCatalog(next);
          setCatalogError(null);
        }
      } catch (err) {
        if (!cancelled) {
          setCatalogError((err as Error).message);
        }
      }
    })();

    return () => {
      cancelled = true;
    };
  }, []);

  useEffect(() => {
    if (!open) return;
    let cancelled = false;

    void (async () => {
      try {
        const [jarvis, marvin] = await Promise.all([
          fetchEffectiveVoiceConfig('jarvis'),
          fetchEffectiveVoiceConfig('marvin'),
        ]);
        if (cancelled) return;
        setEffectiveSummary({
          jarvis: `${jarvis.mode} | ${jarvis.provider} | voice=${jarvis.voice}`,
          marvin: `${marvin.mode} | ${marvin.provider} | voice=${marvin.voice}`,
        });
      } catch {
        if (cancelled) return;
        setEffectiveSummary({});
      }
    })();

    return () => {
      cancelled = true;
    };
  }, [open]);

  const manifest = catalog?.manifest;
  const modeOptions = manifest?.modes ?? ['voice-to-voice', 'decomposed'];
  const realtimeProviderPath = manifest?.realtimeProviderPath ?? 'voice.voiceToVoice.provider';
  const realtimeProviders = manifest?.realtimeProviders ?? [];

  const selectedRealtimeProviderId = config
    ? asString(getPathValue(config, realtimeProviderPath), config.voice.voiceToVoice.provider)
    : '';
  const selectedRealtimeProvider =
    realtimeProviders.find((provider) => provider.id === selectedRealtimeProviderId) ??
    realtimeProviders[0];

  const isDecomposed = config?.voice.mode === 'decomposed';
  const activeProviderKey = isDecomposed
    ? 'decomposed'
    : selectedRealtimeProvider?.id ?? selectedRealtimeProviderId;

  const providerSettings = config?.voice.providerSettings?.[activeProviderKey] ?? {};
  const activeSchema = catalog?.providerSchemas?.[activeProviderKey] as ProviderConfigSchema | undefined;
  const authProfileNames = catalog?.authProfileNames ?? [];

  const updatePath = useCallback(
    (path: string, value: unknown) => {
      if (!config) return;
      setConfig(setPathValue(config, path, value));
    },
    [config, setConfig]
  );

  const updateMany = useCallback(
    (updates: Array<{ path: string; value: unknown }>) => {
      if (!config) return;
      let next = config;
      for (const update of updates) {
        next = setPathValue(next, update.path, update.value);
      }
      setConfig(next);
    },
    [config, setConfig]
  );

  const updateTurn = (patch: Partial) => {
    if (!config) return;
    setConfig({
      ...config,
      voice: {
        ...config.voice,
        turn: {
          ...config.voice.turn,
          ...patch,
        },
      },
    });
  };

  const updateLlmCompletion = (
    patch: Partial
  ) => {
    if (!config) return;
    setConfig({
      ...config,
      voice: {
        ...config.voice,
        turn: {
          ...config.voice.turn,
          llmCompletion: {
            ...config.voice.turn.llmCompletion,
            ...patch,
          },
        },
      },
    });
  };

  const updateProviderSetting = useCallback(
    (key: string, value: unknown) => {
      if (!config) return;
      const currentSettings = config.voice.providerSettings ?? {};
      const currentProvider = currentSettings[activeProviderKey] ?? {};
      setConfig({
        ...config,
        voice: {
          ...config.voice,
          providerSettings: {
            ...currentSettings,
            [activeProviderKey]: {
              ...currentProvider,
              [key]: value,
            },
          },
        },
      });
    },
    [activeProviderKey, config, setConfig]
  );

  const runtimeSummary = useMemo(() => {
    if (!config) {
      return loading
        ? 'Loading voice runtime configuration...'
        : error || 'Voice runtime configuration unavailable.';
    }

    if (isDecomposed) {
      const parts = (manifest?.decomposedStages ?? []).map((stage) => {
        const provider = asString(getPathValue(config, stage.providerPath), 'n/a');
        const model = asString(getPathValue(config, stage.modelPath), 'n/a');
        return `${stage.id.toUpperCase()} ${provider}:${model}`;
      });
      return `Decomposed • ${parts.join(' -> ')}`;
    }

    if (!selectedRealtimeProvider) {
      return `Realtime • ${selectedRealtimeProviderId}`;
    }

    const fieldSummary = selectedRealtimeProvider.fields
      .filter((field) => field.kind === 'model' || field.kind === 'voice' || field.kind === 'string' || field.kind === 'select')
      .slice(0, 2)
      .map((field) => `${field.label} ${asString(getPathValue(config, field.path), 'n/a')}`)
      .join(' • ');

    return fieldSummary
      ? `Realtime • ${selectedRealtimeProvider.id} • ${fieldSummary}`
      : `Realtime • ${selectedRealtimeProvider.id}`;
  }, [
    config,
    error,
    isDecomposed,
    loading,
    manifest?.decomposedStages,
    selectedRealtimeProvider,
    selectedRealtimeProviderId,
  ]);

  const overridesText = config
    ? Object.entries(config.voice.profileOverrides)
        .map(([name, override]) => {
          const parts = [override.mode, override.provider, override.voice].filter(Boolean);
          return parts.length ? `${name}: ${parts.join(' / ')}` : null;
        })
        .filter(Boolean)
        .join(' | ')
    : '';

  const handleRealtimeProviderChange = (nextProviderId: string) => {
    if (!config) return;
    const provider = realtimeProviders.find((entry) => entry.id === nextProviderId);
    if (!provider) {
      updatePath(realtimeProviderPath, nextProviderId);
      return;
    }

    const updates: Array<{ path: string; value: unknown }> = [
      { path: realtimeProviderPath, value: nextProviderId },
    ];

    for (const field of provider.fields) {
      if (field.kind !== 'model' && field.kind !== 'voice') continue;
      const current = asString(getPathValue(config, field.path));

      if (field.kind === 'model') {
        const options = asModelList(catalog, field.catalogKey);
        const next = pickMatchingOrFirst(options, current, current);
        if (next) updates.push({ path: field.path, value: next });
        continue;
      }

      const voiceOptions = asVoiceList(catalog, field.catalogKey).map((voice) => voice.id);
      const next = pickMatchingOrFirst(voiceOptions, current, current);
      if (next) updates.push({ path: field.path, value: next });
    }

    updateMany(updates);
  };

  const handleDecomposedProviderChange = (stage: RuntimeDecomposedStageManifest, nextProviderId: string) => {
    if (!config) return;
    const provider = stage.providers.find((entry) => entry.id === nextProviderId);
    const updates: Array<{ path: string; value: unknown }> = [
      { path: stage.providerPath, value: nextProviderId },
    ];

    if (provider?.modelCatalogKey) {
      const modelOptions = asModelList(catalog, provider.modelCatalogKey);
      const currentModel = asString(getPathValue(config, stage.modelPath));
      const nextModel = pickMatchingOrFirst(modelOptions, currentModel, currentModel);
      if (nextModel) updates.push({ path: stage.modelPath, value: nextModel });
    }

    if (provider?.voiceCatalogKey && stage.voicePath) {
      const voiceOptions = asVoiceList(catalog, provider.voiceCatalogKey).map((voice) => voice.id);
      const currentVoice = asString(getPathValue(config, stage.voicePath));
      const nextVoice = pickMatchingOrFirst(voiceOptions, currentVoice, currentVoice);
      if (nextVoice) {
        updates.push({ path: stage.voicePath, value: nextVoice });
        updates.push({ path: stage.modelPath, value: nextVoice });
      }
    }

    updateMany(updates);
  };

  const handleSave = () => {
    void (async () => {
      try {
        await save();
        setOpen(false);
      } catch {
        // Save errors are surfaced through the existing error state.
      }
    })();
  };

  const statusMessage = error || catalogError || 'Saved settings apply when you start the next voice session.';

  if (!config) {
    return (


        {loading ? 'Loading voice runtime configuration...' : error || 'Voice runtime configuration unavailable.'}

    );
  }

  return (
    <>





Voice Runtime

{runtimeSummary}

         setOpen(true)}
        >
          Configure Runtime



       setOpen(false)}
        onSave={handleSave}
      >


             {
                updatePath('voice.mode', event.target.value);
              }}
            >
              {modeOptions.map((mode) => (

                  {mode}

              ))}



          {!isDecomposed ? (

               {
                  handleRealtimeProviderChange(event.target.value);
                }}
              >
                {realtimeProviders.map((provider) => (

                    {provider.label}

                ))}


          ) : (



          )}


             {
                updatePath('voice.language', event.target.value);
              }}
            />



        {!isDecomposed && selectedRealtimeProvider && (

            {selectedRealtimeProvider.fields.map((field) => {
              const value = getPathValue(config, field.path);
              return (


                  {renderRuntimeField({
                    field,
                    value,
                    language: config.voice.language,
                    catalog,
                    authProfileNames,
                    onChange: (nextValue) => updatePath(field.path, nextValue),
                  })}

              );
            })}

        )}

        {isDecomposed && (manifest?.decomposedStages ?? []).map((stage) => {
          const selectedProviderId = asString(getPathValue(config, stage.providerPath));
          const selectedProvider =
            stage.providers.find((provider) => provider.id === selectedProviderId) ??
            stage.providers[0];
          const modelOptions = selectedProvider?.modelCatalogKey
            ? withCurrent(
                asModelList(catalog, selectedProvider.modelCatalogKey),
                asString(getPathValue(config, stage.modelPath))
              )
            : [];
          const voiceOptions = selectedProvider?.voiceCatalogKey
            ? asVoiceList(catalog, selectedProvider.voiceCatalogKey)
            : [];

          return (


                 {
                    handleDecomposedProviderChange(stage, event.target.value);
                  }}
                >
                  {stage.providers.map((provider) => (

                      {provider.label}

                  ))}



              {stage.voicePath ? (
                <>
                   updatePath(stage.authPath, next)}
                    profileNames={authProfileNames}
                  />
                   {
                      const voicePath = stage.voicePath as string;
                      updateMany([
                        { path: stage.modelPath, value: voiceId },
                        { path: voicePath, value: voiceId },
                      ]);
                    }}
                    languageFilter={config.voice.language}
                  />
                </>
              ) : (
                <>

                     updatePath(stage.modelPath, event.target.value)}
                    >
                      {modelOptions.map((model) => (

                          {model}

                      ))}


                   updatePath(stage.authPath, next)}
                    profileNames={authProfileNames}
                  />
                </>
              )}

          );
        })}

        {activeSchema && (

        )}

        {isDecomposed && (


               {
                  updateTurn({
                    strategy: event.target.value as VoiceConfigDocument['voice']['turn']['strategy'],
                  });
                }}
              >
                provider-native
                layered




               {
                  updateTurn({
                    silenceMs: parseNumeric(event.target.value, config.voice.turn.silenceMs, 0),
                  });
                }}
              />



               {
                  updateTurn({
                    minSpeechMs: parseNumeric(event.target.value, config.voice.turn.minSpeechMs, 0),
                  });
                }}
              />



               {
                  updateTurn({
                    minRms: parseNumeric(event.target.value, config.voice.turn.minRms),
                  });
                }}
              />



               {
                  updateLlmCompletion({
                    enabled: event.target.value === 'enabled',
                  });
                }}
              >
                disabled
                enabled




               {
                  updateLlmCompletion({
                    shortTimeoutMs: parseNumeric(
                      event.target.value,
                      config.voice.turn.llmCompletion.shortTimeoutMs,
                      0
                    ),
                  });
                }}
              />



               {
                  updateLlmCompletion({
                    longTimeoutMs: parseNumeric(
                      event.target.value,
                      config.voice.turn.llmCompletion.longTimeoutMs,
                      0
                    ),
                  });
                }}
              />



               {
                  updateLlmCompletion({
                    shortReprompt: event.target.value,
                  });
                }}
              />



               {
                  updateLlmCompletion({
                    longReprompt: event.target.value,
                  });
                }}
              />


        )}

        {activeSchema && (

        )}




            Jarvis: {effectiveSummary.jarvis || 'loading...'}
            {'\n'}
            Marvin: {effectiveSummary.marvin || 'loading...'}



            {overridesText ? `Profile overrides: ${overridesText}` : 'Profile overrides: none'}



            Runtime config UI is rendered from runtime manifest/catalog metadata. Provider protocol logic stays in voice-runtime.



    </>
  );
}



// ═══════════════════════════════════════════════════════════════════════════
// Unified Sessions Store - Single source of truth for all session state
// ═══════════════════════════════════════════════════════════════════════════
//
// This store consolidates agent.ts + stage.ts + sessions.ts into one unified store.
// All agents emit AI SDK format events via stream_chunk, enabling:
// - One handler for all agent types
// - Consistent message accumulation
// - Simplified debugging (one path instead of 4)
//
// See: docs/SESSION_CENTRIC_REFACTOR_PLAN.md

import { useMemo } from 'react';
import { create } from 'zustand';
import { useShallow } from 'zustand/shallow';
import type {
  AgentState,
  RealtimeEvent,
  SessionTreeNode,
  SessionStatus,
  ActivityBlock,
  ReasoningBlock,
  ToolBlock,
  ContentBlock,
  ErrorBlock,
  OverlayType,
  SpokenWordCue,
  SpokenWordCueUpdate,
} from '../types';
import type { TimelineItem, TranscriptItem, ToolItem } from '../types/timeline';
import type { ToastItem } from '../components/overlays/Toast';
import type { PromptInfo } from '../lib/prompts-api';
import { applyWordCueUpdate } from '../lib/spoken-cues';
import * as promptsApi from '../lib/prompts-api';
import * as sessionsApi from '../lib/sessions-api';

// ═══════════════════════════════════════════════════════════════════════════
// Types
// ═══════════════════════════════════════════════════════════════════════════

/** Session types in the unified model */
export type SessionType = 'voice' | 'subagent' | 'terminal';

/** Re-export for convenience */
export type { SessionStatus, AgentState, ActivityBlock, ReasoningBlock, ToolBlock, ContentBlock, ErrorBlock };

/** Message role in AI SDK format */
export type MessageRole = 'user' | 'assistant' | 'system';
export type SpokenPrecision = 'ratio' | 'segment' | 'aligned' | 'provider-word-timestamps';

/** Message part types following AI SDK format */
export type MessagePart =
  | { type: 'text'; text: string }
  | { type: 'tool-call'; toolName: string; toolCallId: string; args: unknown }
  | { type: 'tool-result'; toolName: string; toolCallId: string; result: unknown }
  | { type: 'reasoning'; text: string };

/** Message in AI SDK format */
export interface Message {
  id: string;
  role: MessageRole;
  parts: MessagePart[];
  createdAt: number;
  ttfbMs?: number;
  itemId?: string;
  order?: number;
  generatedText?: string;
  spokenText?: string;
  spokenChars?: number;
  spokenWords?: number;
  playbackMs?: number;
  precision?: SpokenPrecision;
  wordCues?: SpokenWordCue[];
  spokenFinalized?: boolean;
  pending?: boolean;
}

/** Session state in the unified model */
export interface SessionState {
  id: string;
  type: SessionType;
  status: SessionStatus;
  parentId: string | null;
  agentName?: string;
  goal?: string;
  profile?: string;
  messages: Message[];
  children: string[];
}

/** AI SDK stream event types */
export type AISDKStreamEvent =
  | {
      type: 'text-delta';
      textDelta: string;
      itemId?: string;
      order?: number;
      channel?: 'generated' | 'spoken';
    }
  | {
      type: 'spoken-delta';
      textDelta: string;
      itemId?: string;
      order?: number;
      spokenChars?: number;
      spokenWords?: number;
      playbackMs?: number;
      precision?: SpokenPrecision;
      wordCues?: SpokenWordCue[];
      wordCueUpdate?: SpokenWordCueUpdate;
    }
  | {
      type: 'spoken-progress';
      itemId: string;
      spokenChars: number;
      spokenWords: number;
      playbackMs: number;
      precision: SpokenPrecision;
    }
  | {
      type: 'spoken-final';
      text: string;
      itemId?: string;
      order?: number;
      spokenChars?: number;
      spokenWords?: number;
      playbackMs?: number;
      precision?: SpokenPrecision;
      wordCues?: SpokenWordCue[];
      wordCueUpdate?: SpokenWordCueUpdate;
    }
  | { type: 'user-transcript'; text: string; itemId?: string; order?: number } // Custom extension for voice user messages
  // Placeholders for message ordering (custom extension for voice sessions)
  | { type: 'user-placeholder'; itemId: string; previousItemId?: string; order?: number }
  | { type: 'assistant-placeholder'; itemId: string; previousItemId?: string; order?: number }
  | { type: 'tool-call'; toolName: string; toolCallId: string; input: unknown }
  | { type: 'tool-result'; toolName: string; toolCallId: string; output: unknown }
  | { type: 'reasoning-start' }
  | { type: 'reasoning-delta'; text: string }
  | { type: 'reasoning-end'; text: string; durationMs?: number }
  | { type: 'start' }
  | { type: 'start-step' }
  | { type: 'finish-step'; finishReason?: string; usage?: Record }
  | { type: 'finish'; finishReason: string }
  | { type: 'error'; error: string }
  | {
      type: 'latency';
      stage: 'stt' | 'llm' | 'tts' | 'turn' | 'tool' | 'connection';
      durationMs: number;
      provider?: string;
      model?: string;
      details?: Record;
    }
  | { type: 'process-status'; processName: string; sessionId: string; status: 'completed' | 'error'; summary?: string };

/** Re-export timeline types for message-handler compatibility */
export type { TimelineItem, TranscriptItem, ToolItem };
export type { SessionTreeNode, OverlayType };
export type { ToastItem };

// ═══════════════════════════════════════════════════════════════════════════
// Store Interface
// ═══════════════════════════════════════════════════════════════════════════

interface UnifiedSessionsStore {
  // ─────────────────────────────────────────────────────────────────────────
  // Connection State
  // ─────────────────────────────────────────────────────────────────────────
  clientId: string | null;
  isMaster: boolean;
  wsError: string | null;

  // ─────────────────────────────────────────────────────────────────────────
  // Service State (Soft Power)
  // ─────────────────────────────────────────────────────────────────────────
  serviceActive: boolean;
  audioMode: 'web' | 'local';

  // ─────────────────────────────────────────────────────────────────────────
  // Voice State (for ChatStage compatibility)
  // ─────────────────────────────────────────────────────────────────────────
  voiceState: AgentState;
  voiceProfile: string | null;
  voiceActive: boolean;
  voiceTimeline: TimelineItem[];
  currentTool: { name: string; args?: Record } | null;

  // ─────────────────────────────────────────────────────────────────────────
  // Session Tree (from backend)
  // ─────────────────────────────────────────────────────────────────────────
  sessionTree: SessionTreeNode | null;
  allTrees: Map;
  focusedSessionId: string | null;
  backgroundTreeIds: string[];
  focusTimeout: ReturnType | null;

  // ─────────────────────────────────────────────────────────────────────────
  // Sessions (by ID for O(1) lookup)
  // ─────────────────────────────────────────────────────────────────────────
  sessions: Map;
  loadingSessionIds: Set; // Sessions currently loading history

  // ─────────────────────────────────────────────────────────────────────────
  // Subagent Activities
  // ─────────────────────────────────────────────────────────────────────────
  activitiesBySession: Record;
  activeOrchestratorId: string | null;
  subagentActive: boolean;

  // ─────────────────────────────────────────────────────────────────────────
  // Events Log
  // ─────────────────────────────────────────────────────────────────────────
  events: RealtimeEvent[];

  // ─────────────────────────────────────────────────────────────────────────
  // Overlay State
  // ─────────────────────────────────────────────────────────────────────────
  activeOverlay: OverlayType;

  // ─────────────────────────────────────────────────────────────────────────
  // View State (Sessions / Prompts / Settings)
  // ─────────────────────────────────────────────────────────────────────────
  activeView: 'sessions' | 'prompts' | 'settings';
  historyPanelOpen: boolean;

  // ─────────────────────────────────────────────────────────────────────────
  // Toast Notifications
  // ─────────────────────────────────────────────────────────────────────────
  toasts: ToastItem[];

  // ─────────────────────────────────────────────────────────────────────────
  // Prompts State
  // ─────────────────────────────────────────────────────────────────────────
  prompts: PromptInfo[];
  selectedPromptId: string | null;
  selectedVersion: string | null;
  promptContent: string;
  promptVersions: string[];
  promptsLoading: boolean;
  promptsError: string | null;
  promptDirty: boolean;

  // ─────────────────────────────────────────────────────────────────────────
  // Connection Actions
  // ─────────────────────────────────────────────────────────────────────────
  setClientIdentity: (clientId: string | null, isMaster: boolean, serviceActive?: boolean, audioMode?: 'web' | 'local') => void;
  setIsMaster: (isMaster: boolean) => void;
  setWsError: (error: string | null) => void;

  // ─────────────────────────────────────────────────────────────────────────
  // Service State Actions
  // ─────────────────────────────────────────────────────────────────────────
  setServiceState: (active: boolean, mode: 'web' | 'local') => void;

  // ─────────────────────────────────────────────────────────────────────────
  // Voice Actions
  // ─────────────────────────────────────────────────────────────────────────
  setVoiceState: (state: AgentState, profile?: string | null) => void;
  setVoiceActive: (active: boolean) => void;
  clearVoiceTimeline: () => void;
  addVoiceTimelineItem: (item: TimelineItem, index?: number) => void;
  updateVoiceTimelineItem: (id: string, updates: Partial) => void;
  setCurrentTool: (tool: { name: string; args?: Record } | null) => void;

  // ─────────────────────────────────────────────────────────────────────────
  // Session Tree Actions
  // ─────────────────────────────────────────────────────────────────────────
  handleSessionTreeUpdate: (payload: { tree?: SessionTreeNode; trees?: SessionTreeNode[] }) => void;
  focusSession: (sessionId: string) => void;
  minimizeTree: () => void;
  restoreTree: (rootId: string) => void;
  clearFocusedSession: () => void;

  // ─────────────────────────────────────────────────────────────────────────
  // Session Actions
  // ─────────────────────────────────────────────────────────────────────────
  upsertSession: (session: Partial & { id: string }) => void;
  removeSession: (id: string) => void;
  clearSessions: () => void;

  // ─────────────────────────────────────────────────────────────────────────
  // Activity Actions
  // ─────────────────────────────────────────────────────────────────────────
  handleSubagentActivity: (
    agent: string,
    eventType: string,
    payload: unknown,
    timestamp: number,
    orchestratorId?: string
  ) => void;
  clearActivities: (orchestratorId?: string) => void;

  // ─────────────────────────────────────────────────────────────────────────
  // Stream Chunk Handler (AI SDK Protocol)
  // ─────────────────────────────────────────────────────────────────────────
  handleStreamChunk: (sessionId: string, event: AISDKStreamEvent) => void;

  // ─────────────────────────────────────────────────────────────────────────
  // History Loading (Chat Persistence)
  // ─────────────────────────────────────────────────────────────────────────
  loadSessionHistory: (sessionId: string, sessionType?: SessionType) => Promise;

  // ─────────────────────────────────────────────────────────────────────────
  // Events & Overlay
  // ─────────────────────────────────────────────────────────────────────────
  addEvent: (type: string, payload: unknown) => void;
  clearEvents: () => void;
  setActiveOverlay: (overlay: OverlayType) => void;

  // ─────────────────────────────────────────────────────────────────────────
  // Toast Actions
  // ─────────────────────────────────────────────────────────────────────────
  addToast: (toast: ToastItem) => void;
  dismissToast: (id: string) => void;

  // ─────────────────────────────────────────────────────────────────────────
  // View & Prompts Actions
  // ─────────────────────────────────────────────────────────────────────────
  setActiveView: (view: 'sessions' | 'prompts' | 'settings') => void;
  toggleHistoryPanel: () => void;
  loadPrompts: () => Promise;
  selectPrompt: (id: string) => Promise;
  selectVersion: (version: string) => Promise;
  setPromptContent: (content: string) => void;
  savePromptVersion: () => Promise;
  setPromptActiveVersion: (version: string) => Promise;
  updatePromptMetadata: (id: string, metadata: PromptInfo['metadata']) => Promise;

  // ─────────────────────────────────────────────────────────────────────────
  // Reset
  // ─────────────────────────────────────────────────────────────────────────
  reset: () => void;
}

// ═══════════════════════════════════════════════════════════════════════════
// Helper Functions
// ═══════════════════════════════════════════════════════════════════════════

const generateId = () => `msg_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;
const GLOBAL_KEY = '__global__';

/** Find session by ID in tree */
function findSessionById(node: SessionTreeNode | null, id: string | null): SessionTreeNode | null {
  if (!node || !id) return null;
  if (node.id === id) return node;
  for (const child of node.children) {
    const found = findSessionById(child, id);
    if (found) return found;
  }
  return null;
}

/** Get path from root to target session */
function getPathToSession(tree: SessionTreeNode | null, targetId: string | null): SessionTreeNode[] {
  if (!tree || !targetId) return [];
  const path: SessionTreeNode[] = [];
  function traverse(node: SessionTreeNode): boolean {
    path.push(node);
    if (node.id === targetId) return true;
    for (const child of node.children) {
      if (traverse(child)) return true;
    }
    path.pop();
    return false;
  }
  traverse(tree);
  return path;
}

/** Get children of target session */
function getChildrenOfSession(tree: SessionTreeNode | null, targetId: string | null): SessionTreeNode[] {
  if (!tree || !targetId) return [];
  const session = findSessionById(tree, targetId);
  return session?.children ?? [];
}

/** Flattened tree node with depth info for consistent rail display */
export interface FlattenedTreeNode {
  node: SessionTreeNode;
  depth: number;
}

/** Flatten tree into linear list with depth info (DFS pre-order) */
function flattenTree(node: SessionTreeNode | null, depth = 0): FlattenedTreeNode[] {
  if (!node) return [];
  const result: FlattenedTreeNode[] = [{ node, depth }];
  for (const child of node.children) {
    result.push(...flattenTree(child, depth + 1));
  }
  return result;
}

/** Find deepest running session in tree */
function findDeepestRunning(node: SessionTreeNode): SessionTreeNode | null {
  for (const child of node.children) {
    const found = findDeepestRunning(child);
    if (found) return found;
  }
  if (['pending', 'running', 'waiting_for_input'].includes(node.status)) {
    return node;
  }
  return null;
}

/** Get all IDs in a tree */
function getAllTreeIds(node: SessionTreeNode): Set {
  const ids = new Set([node.id]);
  node.children.forEach((child) => getAllTreeIds(child).forEach((id) => ids.add(id)));
  return ids;
}

function getSessionIdFromPath(pathname: string): string | null {
  const sessionMatch = pathname.match(/^\/session\/([a-zA-Z0-9_-]+)\/?$/);
  return sessionMatch?.[1] ?? null;
}

function replacePath(path: string): void {
  if (window.location.pathname === path) return;
  window.history.replaceState(null, '', path);
  window.dispatchEvent(new PopStateEvent('popstate'));
}

function toOrderValue(order?: number): number | null {
  return typeof order === 'number' && Number.isFinite(order) ? order : null;
}

function buildVoiceTimelineFromMessages(messages: Message[]): TimelineItem[] {
  const timeline: TimelineItem[] = [];
  const toolIndexByCallId = new Map();
  const orderedMessages = messages
    .map((message, index) => ({
      message,
      index,
      order: toOrderValue(message.order),
    }))
    .sort((a, b) => {
      if (a.order === null || b.order === null) {
        return a.index - b.index;
      }
      if (a.order !== b.order) {
        return a.order - b.order;
      }
      return a.index - b.index;
    })
    .map((entry) => entry.message);

  for (const message of orderedMessages) {
    for (const part of message.parts) {
      if (part.type === 'text') {
        const isAssistant = message.role === 'assistant';
        const generatedContent = isAssistant ? message.generatedText ?? part.text : undefined;
        const spokenContent = isAssistant ? message.spokenText : undefined;
        const content = spokenContent ?? generatedContent ?? part.text;
        timeline.push({
          id: generateId(),
          type: 'transcript',
          role: message.role as 'user' | 'assistant',
          content,
          ttfbMs: message.ttfbMs,
          generatedContent,
          spokenContent,
          spokenChars: message.spokenChars,
          spokenWords: message.spokenWords,
          playbackMs: message.playbackMs,
          precision: message.precision,
          wordCues: message.wordCues,
          spokenFinalized: message.spokenFinalized,
          timestamp: message.createdAt,
          pending: false,
          itemId: message.itemId,
          order: message.order,
        });
        continue;
      }

      if (part.type === 'tool-call') {
        const toolItem: ToolItem = {
          id: part.toolCallId,
          type: 'tool',
          name: part.toolName,
          args: part.args as Record,
          status: 'running',
          timestamp: message.createdAt,
        };
        toolIndexByCallId.set(part.toolCallId, timeline.length);
        timeline.push(toolItem);
        continue;
      }

      if (part.type === 'tool-result') {
        const resultText =
          typeof part.result === 'string'
            ? part.result
            : JSON.stringify(part.result, null, 2);
        const existingIdx = toolIndexByCallId.get(part.toolCallId);

        if (existingIdx !== undefined) {
          const existing = timeline[existingIdx];
          if (existing?.type === 'tool') {
            timeline[existingIdx] = {
              ...existing,
              status: 'completed',
              result: resultText,
            };
          }
        } else {
          // Keep result visible even when persisted history misses the call event.
          const fallbackTool: ToolItem = {
            id: part.toolCallId,
            type: 'tool',
            name: part.toolName,
            args: {},
            status: 'completed',
            result: resultText,
            timestamp: message.createdAt,
          };
          toolIndexByCallId.set(part.toolCallId, timeline.length);
          timeline.push(fallbackTool);
        }
      }
    }
  }

  return timeline;
}

// ═══════════════════════════════════════════════════════════════════════════
// Store Implementation
// ═══════════════════════════════════════════════════════════════════════════

export const useUnifiedSessionsStore = create((set, get) => ({
  // ─────────────────────────────────────────────────────────────────────────
  // Initial State
  // ─────────────────────────────────────────────────────────────────────────

  // Connection
  clientId: null,
  isMaster: false,
  wsError: null,

  // Service state (soft power)
  serviceActive: false,
  audioMode: 'web',

  // Voice
  voiceState: 'idle',
  voiceProfile: null,
  voiceActive: false,
  voiceTimeline: [],
  currentTool: null,

  // Session tree
  sessionTree: null,
  allTrees: new Map(),
  focusedSessionId: null,
  backgroundTreeIds: [],
  focusTimeout: null,

  // Sessions
  sessions: new Map(),
  loadingSessionIds: new Set(),

  // Activities
  activitiesBySession: {},
  activeOrchestratorId: null,
  subagentActive: false,

  // Events
  events: [],

  // Overlay
  activeOverlay: null,

  // View
  activeView: 'sessions',
  historyPanelOpen: false,

  // Toasts
  toasts: [],

  // Prompts
  prompts: [],
  selectedPromptId: null,
  selectedVersion: null,
  promptContent: '',
  promptVersions: [],
  promptsLoading: false,
  promptsError: null,
  promptDirty: false,

  // ─────────────────────────────────────────────────────────────────────────
  // Connection Actions
  // ─────────────────────────────────────────────────────────────────────────

  setClientIdentity: (clientId, isMaster, serviceActive, audioMode) =>
    set({
      clientId,
      isMaster,
      ...(serviceActive !== undefined && { serviceActive }),
      ...(audioMode !== undefined && { audioMode }),
    }),
  setIsMaster: (isMaster) => set({ isMaster }),
  setWsError: (wsError) => set({ wsError }),

  // ─────────────────────────────────────────────────────────────────────────
  // Service State Actions
  // ─────────────────────────────────────────────────────────────────────────
  setServiceState: (serviceActive, audioMode) => set({ serviceActive, audioMode }),

  // ─────────────────────────────────────────────────────────────────────────
  // Voice Actions
  // ─────────────────────────────────────────────────────────────────────────

  setVoiceState: (state, profile) =>
    set((s) => ({
      voiceState: state,
      voiceProfile: profile !== undefined ? profile : s.voiceProfile,
    })),

  setVoiceActive: (active) => set({ voiceActive: active }),

  clearVoiceTimeline: () => set({ voiceTimeline: [], currentTool: null }),

  addVoiceTimelineItem: (item, index) =>
    set((s) => {
      if (
        typeof index !== 'number' ||
        Number.isNaN(index) ||
        index < 0 ||
        index >= s.voiceTimeline.length
      ) {
        return { voiceTimeline: [...s.voiceTimeline, item] };
      }
      const voiceTimeline = [...s.voiceTimeline];
      voiceTimeline.splice(index, 0, item);
      return { voiceTimeline };
    }),

  updateVoiceTimelineItem: (id, updates) =>
    set((s) => ({
      voiceTimeline: s.voiceTimeline.map((item) =>
        item.id === id ? ({ ...item, ...updates } as TimelineItem) : item
      ),
    })),

  setCurrentTool: (tool) => set({ currentTool: tool }),

  // ─────────────────────────────────────────────────────────────────────────
  // Session Tree Actions
  // ─────────────────────────────────────────────────────────────────────────

  handleSessionTreeUpdate: (payload) => {
    const { tree, trees } = payload;

    // URL is source of truth when a session is present.
    const urlSessionId = getSessionIdFromPath(window.location.pathname);
    const urlHasSession = urlSessionId !== null;

    if (trees) {
      // Batch update - initial load / reconnect
      const newAllTrees = new Map();
      for (const t of trees) {
        newAllTrees.set(t.id, t);
      }

      // Default to first tree, then override if URL points at a different tree.
      const firstTree = trees[0] ?? null;
      let activeTree = firstTree;
      let focusId: string | null = null;

      if (urlSessionId) {
        const matchingRoot = trees.find((candidate) => findSessionById(candidate, urlSessionId));
        if (matchingRoot) {
          activeTree = matchingRoot;
          focusId = urlSessionId;
        } else {
          // Stale /session/:id URL (common after backend restart): reset to home.
          console.log(`[Router] URL session ${urlSessionId.slice(0, 8)} not found, resetting to /`);
          replacePath('/');
          const deepest = firstTree ? findDeepestRunning(firstTree) : null;
          focusId = deepest?.id ?? firstTree?.id ?? null;
        }
      } else {
        const deepest = firstTree ? findDeepestRunning(firstTree) : null;
        focusId = deepest?.id ?? firstTree?.id ?? null;
      }

      const backgroundIds = activeTree
        ? trees.filter((candidate) => candidate.id !== activeTree.id).map((candidate) => candidate.id)
        : [];

      set({
        allTrees: newAllTrees,
        sessionTree: activeTree,
        focusedSessionId: focusId,
        backgroundTreeIds: backgroundIds,
      });

      if (focusId && activeTree) {
        const node = findSessionById(activeTree, focusId);
        if (node) {
          get().loadSessionHistory(focusId, node.type as SessionType);
        }
      }
      return;
    }

    if (!tree) return;

    const current = get();

    // Detect new running sessions
    let newRunningId: string | null = null;
    if (current.sessionTree) {
      const oldIds = getAllTreeIds(current.sessionTree);
      const findNewRunning = (node: SessionTreeNode): string | null => {
        if (!oldIds.has(node.id) && ['running', 'waiting_for_input'].includes(node.status)) {
          return node.id;
        }
        for (const child of node.children) {
          const found = findNewRunning(child);
          if (found) return found;
        }
        return null;
      };
      newRunningId = findNewRunning(tree);
    } else if (!urlHasSession) {
      // Initial load without URL session - focus deepest running immediately
      const deepest = findDeepestRunning(tree);
      if (deepest && deepest.id !== tree.id) {
        set({ sessionTree: tree, focusedSessionId: deepest.id });
        return;
      }
    }

    // Validate existing focus - only clear if session no longer exists
    let focusedId = current.focusedSessionId;
    if (focusedId && !findSessionById(tree, focusedId)) {
      focusedId = null;
    }

    // Update tree
    const newAllTrees = new Map(current.allTrees);
    newAllTrees.set(tree.id, tree);
    set({ sessionTree: tree, allTrees: newAllTrees });

    // Handle auto-focus for NEW running sessions (user just started a session)
    // This should always focus regardless of URL - user explicitly started it
    if (newRunningId) {
      if (current.focusTimeout) clearTimeout(current.focusTimeout);
      const timeout = setTimeout(() => {
        const currentTree = get().sessionTree;
        const currentFocus = get().focusedSessionId;
        if (currentTree && findSessionById(currentTree, newRunningId)) {
          // Focus new session and update URL
          console.log(`[TreeUpdate] Auto-focusing new session ${newRunningId.slice(0, 8)}`);
          get().focusSession(newRunningId);
        }
        set({ focusTimeout: null });
      }, 500); // Reduced delay for better UX
      set({ focusTimeout: timeout });
    } else if (!focusedId && !current.focusTimeout && !urlHasSession) {
      // Only auto-focus deepest if no focus exists and URL doesn't specify one
      const deepest = findDeepestRunning(tree);
      set({ focusedSessionId: deepest?.id ?? null });
    }
  },

  focusSession: (sessionId) => {
    const { sessionTree, allTrees, backgroundTreeIds } = get();

    console.log(`[Focus] Focusing session ${sessionId.slice(0, 8)}`);

    // Helper to find session and trigger history load
    const focusAndLoadHistory = (node: SessionTreeNode | null) => {
      if (node) {
        console.log(`[Focus] Found node type=${node.type}, triggering history load`);
        // Trigger history loading in background (async, don't await)
        get().loadSessionHistory(sessionId, node.type as SessionType);
      }
    };

    // Check current tree first
    if (sessionTree) {
      const node = findSessionById(sessionTree, sessionId);
      if (node) {
        set({ focusedSessionId: sessionId });
        focusAndLoadHistory(node);
        return;
      }
    }

    // Search all trees
    for (const [rootId, tree] of allTrees) {
      const node = findSessionById(tree, sessionId);
      if (node) {
        let newBackgroundIds = [...backgroundTreeIds];
        if (sessionTree && !newBackgroundIds.includes(sessionTree.id)) {
          newBackgroundIds.push(sessionTree.id);
        }
        newBackgroundIds = newBackgroundIds.filter((id) => id !== rootId);
        set({
          sessionTree: tree,
          focusedSessionId: sessionId,
          backgroundTreeIds: newBackgroundIds,
        });
        focusAndLoadHistory(node);
        return;
      }
    }
  },

  minimizeTree: () => {
    const { sessionTree, backgroundTreeIds } = get();
    if (sessionTree) {
      set({
        backgroundTreeIds: [...backgroundTreeIds, sessionTree.id],
        sessionTree: null,
        focusedSessionId: null,
      });
    }
  },

  restoreTree: (rootId) => {
    const { backgroundTreeIds, allTrees } = get();
    const tree = allTrees.get(rootId);
    const deepestNode = tree ? findDeepestRunning(tree) : null;
    const focusedId = deepestNode?.id ?? null;
    set({
      backgroundTreeIds: backgroundTreeIds.filter((id) => id !== rootId),
      sessionTree: tree ?? null,
      focusedSessionId: focusedId,
    });
    // Load history for the focused session
    if (focusedId && deepestNode) {
      get().loadSessionHistory(focusedId, deepestNode.type as SessionType);
    }
  },

  clearFocusedSession: () => set({ focusedSessionId: null }),

  // ─────────────────────────────────────────────────────────────────────────
  // Session Actions
  // ─────────────────────────────────────────────────────────────────────────

  upsertSession: (session) => {
    set((s) => {
      const newSessions = new Map(s.sessions);
      const existing = newSessions.get(session.id);
      const updated: SessionState = existing
        ? { ...existing, ...session }
        : {
            id: session.id,
            type: session.type ?? 'subagent',
            status: session.status ?? 'running',
            parentId: session.parentId ?? null,
            agentName: session.agentName,
            goal: session.goal,
            profile: session.profile,
            messages: session.messages ?? [],
            children: session.children ?? [],
          };
      newSessions.set(session.id, updated);
      return { sessions: newSessions };
    });
  },

  removeSession: (id) => {
    set((s) => {
      const newSessions = new Map(s.sessions);
      newSessions.delete(id);
      return { sessions: newSessions };
    });
  },

  clearSessions: () => {
    const { focusTimeout } = get();
    if (focusTimeout) clearTimeout(focusTimeout);
    // Clear all session-related state but keep connection state
    set({
      // Keep: clientId, isMaster, wsError (connection state)
      // Clear session state:
      voiceState: 'idle',
      voiceProfile: null,
      voiceActive: false,
      voiceTimeline: [],
      currentTool: null,
      sessionTree: null,
      allTrees: new Map(),
      focusedSessionId: null,
      backgroundTreeIds: [],
      focusTimeout: null,
      sessions: new Map(),
      activitiesBySession: {},
      activeOrchestratorId: null,
      subagentActive: false,
      events: [],
      activeOverlay: null,
    });
  },

  // ─────────────────────────────────────────────────────────────────────────
  // Activity Actions
  // ─────────────────────────────────────────────────────────────────────────

  handleSubagentActivity: (agent, eventType, payload, timestamp, orchestratorId) => {
    const sessionKey = orchestratorId || GLOBAL_KEY;

    set((s) => {
      const activities = [...(s.activitiesBySession[sessionKey] || [])];

      switch (eventType) {
        case 'reasoning_start': {
          const block: ReasoningBlock = {
            id: generateId(),
            type: 'reasoning',
            agent,
            orchestratorId,
            timestamp,
            content: '',
            isComplete: false,
          };
          activities.push(block);
          return {
            activitiesBySession: { ...s.activitiesBySession, [sessionKey]: activities },
            subagentActive: true,
            activeOrchestratorId: orchestratorId ?? s.activeOrchestratorId,
          };
        }

        case 'reasoning_delta': {
          const lastReasoning = [...activities].reverse().find(
            (b) => b.type === 'reasoning' && !b.isComplete
          ) as ReasoningBlock | undefined;
          if (lastReasoning) {
            const idx = activities.findIndex((b) => b.id === lastReasoning.id);
            activities[idx] = {
              ...lastReasoning,
              content: lastReasoning.content + ((payload as { text?: string })?.text || ''),
            };
          }
          return { activitiesBySession: { ...s.activitiesBySession, [sessionKey]: activities } };
        }

        case 'reasoning_end': {
          const lastReasoning = [...activities].reverse().find(
            (b) => b.type === 'reasoning' && !b.isComplete
          ) as ReasoningBlock | undefined;
          if (lastReasoning) {
            const idx = activities.findIndex((b) => b.id === lastReasoning.id);
            const endPayload = payload as { text?: string; durationMs?: number };
            activities[idx] = {
              ...lastReasoning,
              content: endPayload?.text || lastReasoning.content,
              isComplete: true,
              durationMs: endPayload?.durationMs,
            };
          }
          return { activitiesBySession: { ...s.activitiesBySession, [sessionKey]: activities } };
        }

        case 'tool_call': {
          const toolPayload = payload as { toolName: string; toolCallId: string; args: Record };
          const block: ToolBlock = {
            id: generateId(),
            type: 'tool',
            agent,
            orchestratorId,
            timestamp,
            toolName: toolPayload.toolName,
            toolCallId: toolPayload.toolCallId,
            args: toolPayload.args || {},
            isComplete: false,
          };
          activities.push(block);
          return { activitiesBySession: { ...s.activitiesBySession, [sessionKey]: activities } };
        }

        case 'tool_result': {
          const resultPayload = payload as { toolCallId: string; result: string };
          const toolBlock = [...activities].reverse().find(
            (b) => b.type === 'tool' && (b as ToolBlock).toolCallId === resultPayload.toolCallId
          ) as ToolBlock | undefined;
          if (toolBlock) {
            const idx = activities.findIndex((b) => b.id === toolBlock.id);
            activities[idx] = {
              ...toolBlock,
              result: resultPayload.result,
              isComplete: true,
            };
          }
          return { activitiesBySession: { ...s.activitiesBySession, [sessionKey]: activities } };
        }

        case 'response': {
          const responsePayload = payload as { text: string };
          const block: ContentBlock = {
            id: generateId(),
            type: 'content',
            agent,
            orchestratorId,
            timestamp,
            text: responsePayload.text,
          };
          activities.push(block);
          return { activitiesBySession: { ...s.activitiesBySession, [sessionKey]: activities } };
        }

        case 'error': {
          const errorPayload = payload as { message: string };
          const block: ErrorBlock = {
            id: generateId(),
            type: 'error',
            agent,
            orchestratorId,
            timestamp,
            message: errorPayload.message,
          };
          activities.push(block);
          return { activitiesBySession: { ...s.activitiesBySession, [sessionKey]: activities } };
        }

        case 'complete':
          return { subagentActive: false };

        default:
          return {};
      }
    });
  },

  clearActivities: (orchestratorId) => {
    if (orchestratorId) {
      set((s) => {
        const newActivities = { ...s.activitiesBySession };
        delete newActivities[orchestratorId];
        return { activitiesBySession: newActivities };
      });
    } else {
      set({ activitiesBySession: {}, subagentActive: false, activeOrchestratorId: null });
    }
  },

  // ─────────────────────────────────────────────────────────────────────────
  // Stream Chunk Handler (AI SDK Protocol)
  // ─────────────────────────────────────────────────────────────────────────

  handleStreamChunk: (sessionId, event) => {
    set((s) => {
      const newSessions = new Map(s.sessions);
      let session = newSessions.get(sessionId);

      // Create session if doesn't exist
      if (!session) {
        session = {
          id: sessionId,
          type: 'subagent',
          status: 'running',
          parentId: null,
          messages: [],
          children: [],
        };
        newSessions.set(sessionId, session);
      }

      const messages = [...session.messages];
      const spokenFirstVoiceSession =
        session.type === 'voice' ||
        (s.sessionTree?.id === sessionId && s.sessionTree?.type === 'voice');
      const lastMessage = messages[messages.length - 1];
      const isAssistantMessage = lastMessage?.role === 'assistant';
      const findMessageInsertIndexByOrder = (order?: number): number | null => {
        const targetOrder = toOrderValue(order);
        if (targetOrder === null) return null;
        for (let idx = 0; idx < messages.length; idx += 1) {
          const current = messages[idx];
          if (!current) continue;
          const currentOrder = toOrderValue(current.order);
          if (currentOrder === null) continue;
          if (currentOrder > targetOrder) {
            return idx;
          }
        }
        return messages.length;
      };
      const insertMessage = (message: Message, insertIndex: number | null): void => {
        if (typeof insertIndex === 'number' && insertIndex >= 0 && insertIndex < messages.length) {
          messages.splice(insertIndex, 0, message);
          return;
        }
        messages.push(message);
      };
      const findMessageIndexByItemId = (
        role: MessageRole,
        itemId: string
      ): number => {
        for (let idx = messages.length - 1; idx >= 0; idx -= 1) {
          const message = messages[idx];
          if (message?.role !== role) continue;
          if (message.itemId !== itemId) continue;
          return idx;
        }
        return -1;
      };
      const readTextFromMessage = (index: number): string => {
        const target = messages[index];
        if (!target) return '';
        for (let partIndex = target.parts.length - 1; partIndex >= 0; partIndex -= 1) {
          const part = target.parts[partIndex];
          if (part?.type === 'text') {
            return part.text;
          }
        }
        return '';
      };
      const setTextForMessage = (index: number, text: string): void => {
        const target = messages[index];
        if (!target) return;
        const targetParts = [...target.parts];
        const textPartIndex = targetParts.findIndex((part) => part.type === 'text');
        if (textPartIndex >= 0) {
          targetParts[textPartIndex] = { type: 'text', text };
        } else {
          targetParts.push({ type: 'text', text });
        }
        messages[index] = { ...target, parts: targetParts };
      };
      const resolveDisplayText = (
        spokenText: string | undefined,
        generatedText: string,
        currentText: string
      ): string => {
        if (spokenFirstVoiceSession) {
          return spokenText ?? currentText;
        }
        return spokenText ?? generatedText;
      };

      switch (event.type) {
        case 'text-delta': {
          const deltaText = event.textDelta ?? '';
          const channel = event.channel ?? 'generated';

          if (channel === 'spoken') {
            let messageIdx = -1;
            if (event.itemId) {
              messageIdx = findMessageIndexByItemId('assistant', event.itemId);
            } else if (isAssistantMessage) {
              messageIdx = messages.length - 1;
            }

            if (messageIdx < 0) {
              const created: Message = {
                id: generateId(),
                role: 'assistant',
                parts: [{ type: 'text', text: deltaText }],
                createdAt: Date.now(),
                itemId: event.itemId,
                order: event.order,
                generatedText: '',
                spokenText: deltaText,
                spokenFinalized: false,
              };
              insertMessage(created, findMessageInsertIndexByOrder(event.order));
              break;
            }

            const target = messages[messageIdx]!;
            const nextSpoken = `${target.spokenText ?? ''}${deltaText}`;
            const generatedText =
              target.generatedText ??
              readTextFromMessage(messageIdx);
            const currentText = readTextFromMessage(messageIdx);
            const displayText = resolveDisplayText(nextSpoken, generatedText, currentText);
            messages[messageIdx] = {
              ...target,
              order: event.order ?? target.order,
              spokenText: nextSpoken,
              spokenChars: nextSpoken.length,
              spokenFinalized: false,
            };
            setTextForMessage(messageIdx, displayText);
            break;
          }

          if (event.itemId) {
            const messageIdx = findMessageIndexByItemId('assistant', event.itemId);
            if (messageIdx >= 0) {
              const target = messages[messageIdx]!;
              const fallbackGenerated =
                target.generatedText ??
                target.spokenText ??
                readTextFromMessage(messageIdx);
              const generatedText = fallbackGenerated + deltaText;
              messages[messageIdx] = {
                ...target,
                generatedText,
                order: event.order ?? target.order,
              };
              const currentText = readTextFromMessage(messageIdx);
              const displayText = resolveDisplayText(
                messages[messageIdx]?.spokenText,
                generatedText,
                currentText
              );
              setTextForMessage(messageIdx, displayText);
              if (event.order != null && messages[messageIdx]?.order == null) {
                messages[messageIdx] = { ...messages[messageIdx]!, order: event.order };
              }
              break;
            }

            // Ignore scaffold-only deltas that do not yet map to a concrete assistant item.
            if (deltaText.trim().length === 0) {
              break;
            }

            const created: Message = {
              id: generateId(),
              role: 'assistant',
              parts: [{ type: 'text', text: spokenFirstVoiceSession ? '' : deltaText }],
              createdAt: Date.now(),
              itemId: event.itemId,
              order: event.order,
              generatedText: deltaText,
              spokenFinalized: false,
            };
            insertMessage(created, findMessageInsertIndexByOrder(event.order));
            break;
          }

          if (isAssistantMessage) {
            const target = messages[messages.length - 1]!;
            const fallbackGenerated =
              target.generatedText ??
              target.spokenText ??
              readTextFromMessage(messages.length - 1);
            const generatedText = fallbackGenerated + deltaText;
            messages[messages.length - 1] = {
              ...target,
              generatedText,
              order: event.order ?? target.order,
            };
            const currentText = readTextFromMessage(messages.length - 1);
            const displayText = resolveDisplayText(
              messages[messages.length - 1]?.spokenText,
              generatedText,
              currentText
            );
            setTextForMessage(messages.length - 1, displayText);
          } else {
            // Create new assistant message
            messages.push({
              id: generateId(),
              role: 'assistant',
              parts: [{ type: 'text', text: spokenFirstVoiceSession ? '' : deltaText }],
              createdAt: Date.now(),
              order: event.order,
              generatedText: deltaText,
              spokenFinalized: false,
            });
          }
          break;
        }

        case 'spoken-delta': {
          const spokenDelta = event.textDelta ?? '';
          const incomingWordCues = event.wordCues;
          const incomingWordCueUpdate = event.wordCueUpdate;
          const metadata = {
            spokenChars: event.spokenChars,
            spokenWords: event.spokenWords,
            playbackMs: event.playbackMs,
            precision: event.precision,
            wordCues: incomingWordCues,
            wordCueUpdate: incomingWordCueUpdate,
          };

          let messageIdx = -1;
          if (event.itemId) {
            messageIdx = findMessageIndexByItemId('assistant', event.itemId);
          } else if (isAssistantMessage) {
            messageIdx = messages.length - 1;
          }

          if (messageIdx < 0) {
            const created: Message = {
              id: generateId(),
              role: 'assistant',
              parts: [{ type: 'text', text: spokenDelta }],
              createdAt: Date.now(),
              itemId: event.itemId,
              order: event.order,
              generatedText: '',
              spokenText: spokenDelta,
              spokenChars: metadata.spokenChars ?? spokenDelta.length,
              spokenWords: metadata.spokenWords,
              playbackMs: metadata.playbackMs,
              precision: metadata.precision,
              wordCues: applyWordCueUpdate(
                metadata.wordCues,
                metadata.wordCueUpdate
              ),
              spokenFinalized: false,
            };
            insertMessage(created, findMessageInsertIndexByOrder(event.order));
            break;
          }

          const target = messages[messageIdx]!;
          const nextSpoken = `${target.spokenText ?? ''}${spokenDelta}`;
          const generatedText =
            target.generatedText ??
            readTextFromMessage(messageIdx);
          const currentText = readTextFromMessage(messageIdx);
          const displayText = resolveDisplayText(nextSpoken, generatedText, currentText);
          const nextWordCues = applyWordCueUpdate(
            metadata.wordCues ?? target.wordCues,
            metadata.wordCueUpdate
          );
          messages[messageIdx] = {
            ...target,
            order: event.order ?? target.order,
            spokenText: nextSpoken,
            spokenChars: metadata.spokenChars ?? nextSpoken.length,
            spokenWords: metadata.spokenWords ?? target.spokenWords,
            playbackMs: metadata.playbackMs ?? target.playbackMs,
            precision: metadata.precision ?? target.precision,
            wordCues: nextWordCues,
            spokenFinalized: false,
          };
          setTextForMessage(messageIdx, displayText);
          break;
        }

        case 'spoken-progress': {
          const messageIdx = findMessageIndexByItemId('assistant', event.itemId);
          if (messageIdx < 0) {
            // Spoken progress may arrive before any assistant text delta (for example
            // initial zero-cursor signal). Create a stub so generated deltas that
            // follow can stay hidden until spoken text is available.
            const created: Message = {
              id: generateId(),
              role: 'assistant',
              parts: [{ type: 'text', text: '' }],
              createdAt: Date.now(),
              itemId: event.itemId,
              generatedText: '',
              spokenText: '',
              spokenChars: event.spokenChars,
              spokenWords: event.spokenWords,
              playbackMs: event.playbackMs,
              precision: event.precision,
              spokenFinalized: false,
            };
            messages.push(created);
            break;
          }

          const target = messages[messageIdx]!;
          const generatedText = target.generatedText ?? readTextFromMessage(messageIdx);
          const previousSpoken = target.spokenText ?? '';
          let spokenText = previousSpoken;
          if (generatedText) {
            const spokenChars = Math.max(0, Math.min(generatedText.length, event.spokenChars));
            spokenText = generatedText.slice(0, spokenChars);
          } else if (event.spokenChars < previousSpoken.length) {
            spokenText = previousSpoken.slice(0, event.spokenChars);
          }
          const currentText = readTextFromMessage(messageIdx);
          const displayText = resolveDisplayText(spokenText, generatedText, currentText);
          messages[messageIdx] = {
            ...target,
            spokenText,
            spokenChars: event.spokenChars,
            spokenWords: event.spokenWords,
            playbackMs: event.playbackMs,
            precision: event.precision,
            spokenFinalized: false,
          };
          setTextForMessage(messageIdx, displayText);
          break;
        }

        case 'spoken-final': {
          let messageIdx = -1;
          if (event.itemId) {
            messageIdx = findMessageIndexByItemId('assistant', event.itemId);
          } else if (isAssistantMessage) {
            messageIdx = messages.length - 1;
          }

          if (messageIdx < 0) {
            const created: Message = {
              id: generateId(),
              role: 'assistant',
              parts: [{ type: 'text', text: event.text }],
              createdAt: Date.now(),
              itemId: event.itemId,
              order: event.order,
              generatedText: event.text,
              spokenText: event.text,
              spokenChars: event.spokenChars ?? event.text.length,
              spokenWords: event.spokenWords,
              playbackMs: event.playbackMs,
              precision: event.precision,
              wordCues: applyWordCueUpdate(event.wordCues, event.wordCueUpdate),
              spokenFinalized: true,
              pending: false,
            };
            insertMessage(created, findMessageInsertIndexByOrder(event.order));
            break;
          }

          const target = messages[messageIdx]!;
          const generatedText =
            target.generatedText ??
            readTextFromMessage(messageIdx);
          const spokenText = event.text;
          const currentText = readTextFromMessage(messageIdx);
          const displayText = resolveDisplayText(spokenText, generatedText, currentText);
          const nextWordCues = applyWordCueUpdate(
            event.wordCues ?? target.wordCues,
            event.wordCueUpdate
          );
          messages[messageIdx] = {
            ...target,
            order: event.order ?? target.order,
            generatedText: spokenText,
            spokenText,
            spokenChars: event.spokenChars ?? spokenText.length,
            spokenWords: event.spokenWords ?? target.spokenWords,
            playbackMs: event.playbackMs ?? target.playbackMs,
            precision: event.precision ?? target.precision,
            wordCues: nextWordCues,
            spokenFinalized: true,
            pending: false,
          };
          setTextForMessage(messageIdx, displayText);
          break;
        }

        case 'user-transcript': {
          if (event.itemId) {
            const messageIdx = findMessageIndexByItemId('user', event.itemId);
            if (messageIdx >= 0) {
              messages[messageIdx] = {
                ...messages[messageIdx]!,
                parts: [{ type: 'text', text: event.text }],
                order: event.order ?? messages[messageIdx]?.order,
              };
              break;
            }
          }

          // User transcripts create a dedicated user message.
          const created: Message = {
            id: generateId(),
            role: 'user',
            parts: [{ type: 'text', text: event.text }],
            createdAt: Date.now(),
            itemId: event.itemId,
            order: event.order,
          };
          insertMessage(created, findMessageInsertIndexByOrder(event.order));
          break;
        }

        case 'tool-call': {
          const toolPart: MessagePart = {
            type: 'tool-call',
            toolName: event.toolName,
            toolCallId: event.toolCallId,
            args: event.input,
          };
          if (isAssistantMessage) {
            lastMessage.parts.push(toolPart);
            messages[messages.length - 1] = { ...lastMessage };
          } else {
            messages.push({
              id: generateId(),
              role: 'assistant',
              parts: [toolPart],
              createdAt: Date.now(),
            });
          }
          break;
        }

        case 'tool-result': {
          const resultPart: MessagePart = {
            type: 'tool-result',
            toolName: event.toolName,
            toolCallId: event.toolCallId,
            result: event.output,
          };
          if (isAssistantMessage) {
            lastMessage.parts.push(resultPart);
            messages[messages.length - 1] = { ...lastMessage };
          } else {
            messages.push({
              id: generateId(),
              role: 'assistant',
              parts: [resultPart],
              createdAt: Date.now(),
            });
          }
          break;
        }

        case 'reasoning-delta': {
          const reasoningPart: MessagePart = { type: 'reasoning', text: event.text };
          if (isAssistantMessage) {
            const lastPart = lastMessage.parts[lastMessage.parts.length - 1];
            if (lastPart?.type === 'reasoning') {
              lastMessage.parts[lastMessage.parts.length - 1] = {
                type: 'reasoning',
                text: lastPart.text + event.text,
              };
            } else {
              lastMessage.parts.push(reasoningPart);
            }
            messages[messages.length - 1] = { ...lastMessage };
          } else {
            messages.push({
              id: generateId(),
              role: 'assistant',
              parts: [reasoningPart],
              createdAt: Date.now(),
            });
          }
          break;
        }

        case 'finish':
          if (spokenFirstVoiceSession) {
            for (let idx = 0; idx < messages.length; idx += 1) {
              const message = messages[idx];
              if (!message || message.role !== 'assistant') {
                continue;
              }
              if (message.spokenFinalized) {
                continue;
              }
              const spokenText = message.spokenText ?? '';
              if (spokenText) {
                setTextForMessage(idx, spokenText);
                continue;
              }
              const generatedText = message.generatedText ?? '';
              if (generatedText) {
                setTextForMessage(idx, generatedText);
              }
            }
          }
          session = { ...session, status: 'finished' };
          break;

        case 'error':
          session = { ...session, status: 'error' };
          break;

        case 'latency': {
          if (event.stage !== 'tts') break;
          const firstAudioLatencyMs = event.details?.firstAudioLatencyMs;
          if (typeof firstAudioLatencyMs !== 'number' || !Number.isFinite(firstAudioLatencyMs)) {
            break;
          }
          const segmentIndex = event.details?.segmentIndex;
          if (typeof segmentIndex === 'number' && segmentIndex > 1) {
            break;
          }

          let targetIndex = -1;
          for (let idx = messages.length - 1; idx >= 0; idx -= 1) {
            if (messages[idx]?.role === 'assistant') {
              targetIndex = idx;
              break;
            }
          }

          if (targetIndex >= 0) {
            const target = messages[targetIndex]!;
            if (typeof target.ttfbMs !== 'number') {
              messages[targetIndex] = {
                ...target,
                ttfbMs: Math.max(0, Math.round(firstAudioLatencyMs)),
              };
            }
          }
          break;
        }

        // Ignore lifecycle events
        case 'start':
        case 'start-step':
        case 'finish-step':
        case 'reasoning-start':
        case 'reasoning-end':
        case 'process-status':
          break;
      }

      newSessions.set(sessionId, { ...session, messages });
      return { sessions: newSessions };
    });
  },

  // ─────────────────────────────────────────────────────────────────────────
  // History Loading (Chat Persistence)
  // ─────────────────────────────────────────────────────────────────────────

  loadSessionHistory: async (sessionId, sessionType) => {
    const { loadingSessionIds, sessions } = get();

    console.log(`[History] Loading history for ${sessionId.slice(0, 8)}, type=${sessionType}`);

    // Skip if already loading
    if (loadingSessionIds.has(sessionId)) {
      console.log(`[History] Already loading ${sessionId.slice(0, 8)}, skipping`);
      return;
    }

    // Check if session already has messages (cached from previous load)
    const existing = sessions.get(sessionId);
    if (existing?.messages && existing.messages.length > 0) {
      console.log(`[History] Session ${sessionId.slice(0, 8)} already has ${existing.messages.length} messages (cached)`);

      // For voice sessions, still need to repopulate voiceTimeline from cached messages
      if (sessionType === 'voice') {
        console.log(`[History] Repopulating voiceTimeline from cached messages`);
        set({ voiceTimeline: buildVoiceTimelineFromMessages(existing.messages) });
      }
      return;
    }

    // Mark as loading
    set((s) => ({
      loadingSessionIds: new Set([...s.loadingSessionIds, sessionId]),
    }));

    try {
      console.log(`[History] Fetching messages from API for ${sessionId.slice(0, 8)}`);
      const rawMessages = await sessionsApi.fetchSessionMessages(sessionId);
      console.log(`[History] Got ${rawMessages.length} messages from API`);

      // Replay events through handleStreamChunk to reconstruct messages
      for (const msg of rawMessages) {
        const event = JSON.parse(msg.payload);
        get().handleStreamChunk(sessionId, event);
      }

      // For voice sessions, also populate voiceTimeline
      if (sessionType === 'voice') {
        set((s) => {
          const session = s.sessions.get(sessionId);
          return { voiceTimeline: buildVoiceTimelineFromMessages(session?.messages ?? []) };
        });
      }

      // Check what we actually got
      const finalSession = get().sessions.get(sessionId);
      console.log(`[History] After replay: session has ${finalSession?.messages?.length ?? 0} messages`);
      if (sessionType === 'voice') {
        console.log(`[History] voiceTimeline has ${get().voiceTimeline.length} items`);
      }
    } catch (error) {
      console.error(`[History] Failed to load history for session ${sessionId}:`, error);
    } finally {
      // Remove from loading set
      set((s) => {
        const newLoading = new Set(s.loadingSessionIds);
        newLoading.delete(sessionId);
        return { loadingSessionIds: newLoading };
      });
    }
  },

  // ─────────────────────────────────────────────────────────────────────────
  // Events & Overlay
  // ─────────────────────────────────────────────────────────────────────────

  addEvent: (type, payload) => {
    set((s) => ({
      events: [
        ...s.events.slice(-99), // Keep last 100 events
        { id: generateId(), type, timestamp: Date.now(), data: payload },
      ],
    }));
  },

  clearEvents: () => {
    set({ events: [] });
  },

  setActiveOverlay: (overlay) => set({ activeOverlay: overlay }),

  // ─────────────────────────────────────────────────────────────────────────
  // Toast Actions
  // ─────────────────────────────────────────────────────────────────────────

  addToast: (toast) => set((s) => ({ toasts: [...s.toasts, toast] })),

  dismissToast: (id) => set((s) => ({ toasts: s.toasts.filter((t) => t.id !== id) })),

  // ─────────────────────────────────────────────────────────────────────────
  // View & Prompts Actions
  // ─────────────────────────────────────────────────────────────────────────

  setActiveView: (view) => set({ activeView: view }),
  toggleHistoryPanel: () => set((s) => ({ historyPanelOpen: !s.historyPanelOpen })),

  loadPrompts: async () => {
    set({ promptsLoading: true, promptsError: null });
    try {
      const prompts = await promptsApi.fetchPrompts();
      set({ prompts, promptsLoading: false });
    } catch (error) {
      set({
        promptsError: error instanceof Error ? error.message : 'Failed to load prompts',
        promptsLoading: false,
      });
    }
  },

  selectPrompt: async (id) => {
    set({ promptsLoading: true, promptsError: null });
    try {
      const data = await promptsApi.fetchPrompt(id);
      set({
        selectedPromptId: id,
        selectedVersion: data.activeVersion,
        promptContent: data.content ?? '',
        promptVersions: data.versions,
        promptDirty: false,
        promptsLoading: false,
      });
    } catch (error) {
      set({
        promptsError: error instanceof Error ? error.message : 'Failed to load prompt',
        promptsLoading: false,
      });
    }
  },

  selectVersion: async (version) => {
    const { selectedPromptId } = get();
    if (!selectedPromptId) return;

    set({ promptsLoading: true, promptsError: null });
    try {
      const data = await promptsApi.fetchVersion(selectedPromptId, version);
      set({
        selectedVersion: version,
        promptContent: data.content,
        promptDirty: false,
        promptsLoading: false,
      });
    } catch (error) {
      set({
        promptsError: error instanceof Error ? error.message : 'Failed to load version',
        promptsLoading: false,
      });
    }
  },

  setPromptContent: (content) => set({ promptContent: content, promptDirty: true }),

  savePromptVersion: async () => {
    const { selectedPromptId, promptContent } = get();
    if (!selectedPromptId) return;

    set({ promptsLoading: true, promptsError: null });
    try {
      const result = await promptsApi.saveNewVersion(selectedPromptId, promptContent);
      // Reload prompt to get updated versions list
      const data = await promptsApi.fetchPrompt(selectedPromptId);
      set({
        selectedVersion: result.version,
        promptVersions: data.versions,
        promptDirty: false,
        promptsLoading: false,
      });
    } catch (error) {
      set({
        promptsError: error instanceof Error ? error.message : 'Failed to save version',
        promptsLoading: false,
      });
    }
  },

  setPromptActiveVersion: async (version) => {
    const { selectedPromptId, prompts } = get();
    if (!selectedPromptId) return;

    set({ promptsLoading: true, promptsError: null });
    try {
      await promptsApi.setActiveVersion(selectedPromptId, version);
      // Update the prompts list with new active version
      const updatedPrompts = prompts.map((p) =>
        p.id === selectedPromptId ? { ...p, activeVersion: version } : p
      );
      set({ prompts: updatedPrompts, promptsLoading: false });
    } catch (error) {
      set({
        promptsError: error instanceof Error ? error.message : 'Failed to set active version',
        promptsLoading: false,
      });
    }
  },

  updatePromptMetadata: async (id, metadata) => {
    const { prompts } = get();
    set({ promptsLoading: true, promptsError: null });
    try {
      await promptsApi.updateMetadata(id, metadata);
      const updatedPrompts = prompts.map((p) =>
        p.id === id ? { ...p, metadata: { ...p.metadata, ...metadata } } : p
      );
      set({ prompts: updatedPrompts, promptsLoading: false });
    } catch (error) {
      set({
        promptsError: error instanceof Error ? error.message : 'Failed to update metadata',
        promptsLoading: false,
      });
    }
  },

  // ─────────────────────────────────────────────────────────────────────────
  // Reset
  // ─────────────────────────────────────────────────────────────────────────

  reset: () => {
    const { focusTimeout } = get();
    if (focusTimeout) clearTimeout(focusTimeout);
    set({
      clientId: null,
      isMaster: false,
      wsError: null,
      voiceState: 'idle',
      voiceProfile: null,
      voiceActive: false,
      voiceTimeline: [],
      currentTool: null,
      sessionTree: null,
      allTrees: new Map(),
      focusedSessionId: null,
      backgroundTreeIds: [],
      focusTimeout: null,
      sessions: new Map(),
      activitiesBySession: {},
      activeOrchestratorId: null,
      subagentActive: false,
      events: [],
      activeOverlay: null,
      toasts: [],
      activeView: 'sessions',
      historyPanelOpen: false,
      prompts: [],
      selectedPromptId: null,
      selectedVersion: null,
      promptContent: '',
      promptVersions: [],
      promptsLoading: false,
      promptsError: null,
      promptDirty: false,
    });
  },
}));

// ═══════════════════════════════════════════════════════════════════════════
// Selectors
// ═══════════════════════════════════════════════════════════════════════════

/** Get the focused session from the tree */
export function useFocusedSession(): SessionTreeNode | null {
  return useUnifiedSessionsStore((s) => findSessionById(s.sessionTree, s.focusedSessionId));
}

/** Get path from root to focused session */
export function useFocusPath(): SessionTreeNode[] {
  return useUnifiedSessionsStore(
    useShallow((s) => getPathToSession(s.sessionTree, s.focusedSessionId))
  );
}

/** Get children of focused session */
export function useFocusedSessionChildren(): SessionTreeNode[] {
  return useUnifiedSessionsStore(
    useShallow((s) => {
      const { sessionTree, focusedSessionId } = s;
      if (focusedSessionId === null && sessionTree) {
        return [sessionTree];
      }
      return getChildrenOfSession(sessionTree, focusedSessionId);
    })
  );
}

/** Get session tree for flattening (use useMemo in component to flatten) */
export function useSessionTree(): SessionTreeNode | null {
  return useUnifiedSessionsStore((s) => s.sessionTree);
}

/** Get flattened session tree - memoized to avoid infinite loops */
export function useFlattenedSessionTree(): FlattenedTreeNode[] {
  const sessionTree = useUnifiedSessionsStore((s) => s.sessionTree);
  return useMemo(() => flattenTree(sessionTree), [sessionTree]);
}

/** Flatten tree helper - export for use with useMemo in components */
export { flattenTree };

/** Get activities for a specific session */
export function useSessionActivities(sessionId: string | null): ActivityBlock[] {
  return useUnifiedSessionsStore(
    useShallow((s) => (sessionId ? s.activitiesBySession[sessionId] ?? [] : []))
  );
}

/** Get all activities flattened and sorted */
export function useAllActivities(): ActivityBlock[] {
  return useUnifiedSessionsStore(
    useShallow((s) =>
      Object.values(s.activitiesBySession)
        .flat()
        .sort((a, b) => a.timestamp - b.timestamp)
    )
  );
}

/** Check if any session is active */
export function useHasActiveSession(): boolean {
  return useUnifiedSessionsStore((s) => {
    if (!s.sessionTree) return false;
    const checkRunning = (node: SessionTreeNode): boolean => {
      if (['pending', 'running', 'waiting_for_input'].includes(node.status)) return true;
      return node.children.some(checkRunning);
    };
    return checkRunning(s.sessionTree);
  });
}

/** Get voice timeline for ChatStage */
export function useVoiceTimeline(): TimelineItem[] {
  return useUnifiedSessionsStore(useShallow((s) => s.voiceTimeline));
}

/** Get connection state */
export function useConnectionState() {
  return useUnifiedSessionsStore(
    useShallow((s) => ({
      connected: s.clientId !== null,
      wsError: s.wsError,
      clientId: s.clientId,
      isMaster: s.isMaster,
    }))
  );
}

/** Get voice state */
export function useVoiceState() {
  return useUnifiedSessionsStore(
    useShallow((s) => ({
      voiceState: s.voiceState,
      voiceProfile: s.voiceProfile,
      voiceActive: s.voiceActive,
      currentTool: s.currentTool,
    }))
  );
}

/** Get service state (soft power) */
export function useServiceState() {
  return useUnifiedSessionsStore(
    useShallow((s) => ({
      serviceActive: s.serviceActive,
      audioMode: s.audioMode,
    }))
  );
}

/** Get active view */
export function useActiveView() {
  return useUnifiedSessionsStore((s) => s.activeView);
}

/** Get prompts state */
export function usePromptsState() {
  return useUnifiedSessionsStore(
    useShallow((s) => ({
      prompts: s.prompts,
      selectedPromptId: s.selectedPromptId,
      selectedVersion: s.selectedVersion,
      promptContent: s.promptContent,
      promptVersions: s.promptVersions,
      promptsLoading: s.promptsLoading,
      promptsError: s.promptsError,
      promptDirty: s.promptDirty,
    }))
  );
}

/** Get toast notifications */
export function useToasts() {
  return useUnifiedSessionsStore(useShallow((s) => s.toasts));
}

